      averageAgeMinutes: evaluated.length ? Math.round(totalAge / evaluated.filter(({ freshness }) => Number.isFinite(Number(freshness?.ageMinutes))).length || 0) : 0,
      oldestSamples: byAgeAsc.slice(-6).reverse().map(formatSample),
