  const lngRaw = Number(incident?.lng ?? incident?.lon ?? incident?.longitude ?? incident?.location?.lng);
  const lat = Number.isFinite(latRaw) ? latRaw.toFixed(4) : "na";
  const lng = Number.isFinite(lngRaw) ? lngRaw.toFixed(4) : "na";
