const gridlyPortraitIntelligenceBreakdownAudit = function gridlyPortraitIntelligenceBreakdownAudit() {
  const refreshPortraitV2LocalizedIntelligence = { ...gridlyPortraitIntelligenceBreakdownAuditState.refreshPortraitV2LocalizedIntelligence };
  const renderAlerts = { ...gridlyPortraitIntelligenceBreakdownAuditState.renderAlerts };
  const updateDailyHabitStatus = { ...gridlyPortraitIntelligenceBreakdownAuditState.updateDailyHabitStatus };

  const sectionEntries = [
    ...Object.entries(refreshPortraitV2LocalizedIntelligence.sections || {}).map(([name, durationMs]) => ({ fn: 'refreshPortraitV2LocalizedIntelligence', name, durationMs })),
    ...Object.entries(renderAlerts.sections || {}).map(([name, durationMs]) => ({ fn: 'renderAlerts', name, durationMs })),
    ...Object.entries(updateDailyHabitStatus.sections || {}).map(([name, durationMs]) => ({ fn: 'updateDailyHabitStatus', name, durationMs }))
  ].filter((entry) => Number.isFinite(entry.durationMs));

  const slowestSection = sectionEntries.sort((a, b) => b.durationMs - a.durationMs)[0] || null;

  return {
    refreshPortraitV2LocalizedIntelligence,
    renderAlerts,
    updateDailyHabitStatus,
    ...snapshotGridlyIntelligenceCacheAudit(),
    slowestSection,
    recommendedTargets: [
      'Measure the slowest section under both route-watch active and idle states.',
      'Compare DOM update sections with alert volume and corridor cluster counts.',
      'Track intelligence calculation sections against unified incident totals and route relevance checks.'
    ]
  };
};

exposeGridlyAuditHelper("gridlyPortraitIntelligenceBreakdownAudit", gridlyPortraitIntelligenceBreakdownAudit);


function sanitizeEmptyCommuteAuditPayload(payload) {
  const result = payload && typeof payload === "object" ? { ...payload } : {};
  const verifiedUnifiedIncidentCount = Number(
    result?.commuteAuditUnifiedIncidentCountAfterBuild
    ?? result?.counts?.unifiedIncidentCount
    ?? 0
  );
  if (!result.counts || typeof result.counts !== "object") {
    result.counts = {};
  }
  result.counts.unifiedIncidentCount = verifiedUnifiedIncidentCount;
  const incidentsProcessed = Number(result?.counts?.incidentsProcessed || 0);
  const shouldSanitizeEmptyCycle = verifiedUnifiedIncidentCount === 0;

  if (shouldSanitizeEmptyCycle) {
    result.labelHelperInternalSections = {};
    result.labelHelperCallStats = {};
    result.labelHelperSlowestCall = null;

    result.localizedLabelLookupSections = {};
    result.localizedLabelPerIncidentLookupTimings = [];
    result.localizedLabelSlowestLookupStep = null;

    result.sharedCacheRetrievalSections = {};
    result.sharedCachePerIncidentTimings = [];
    result.sharedCacheSlowestStep = null;

    result.payloadShapingSections = {};
    result.payloadShapingPerIncidentTimings = [];
    result.payloadShapingSlowestStep = null;
    result.derivedPropertyFunctionSections = {};
    result.derivedPropertyPerIncidentTimings = [];
    result.derivedPropertySlowestFunction = null;
    result.derivedPropertyFunctionCallCount = 0;
  }

  result.emptyCycleSanitized = shouldSanitizeEmptyCycle;
  result.commuteAuditExcludedIncidentCount = Math.max(0, verifiedUnifiedIncidentCount - incidentsProcessed);
  result.commuteAuditExclusionReasons = Array.isArray(result.commuteAuditExclusionReasons) ? result.commuteAuditExclusionReasons : [];
  result.commuteAuditExclusionReasonSource = String(result.commuteAuditExclusionReasonSource || "fallback_placeholder");
  const expectedExcludedCount = Number(result.commuteAuditExcludedIncidentCount || 0);
  const actualReasonCount = Number(result.commuteAuditExclusionReasons.length || 0);
  if (expectedExcludedCount > 0 && actualReasonCount < expectedExcludedCount) {
    const missingReasonCount = Math.max(0, expectedExcludedCount - actualReasonCount);
    if (missingReasonCount > 0) {
      const reasonSeed = Array.isArray(result.commuteAuditExclusionReasons) ? result.commuteAuditExclusionReasons.length : 0;
      for (let i = 0; i < missingReasonCount; i += 1) {
        result.commuteAuditExclusionReasons.push({
          incidentId: "unknown",
          type: "unknown",
          source: "unknown",
          status: "unknown",
          lifecycle: "unknown",
          excludedByFunction: "commute_audit_fallback",
          exclusionReason: `excluded_count_mismatch_unresolved:${reasonSeed + i + 1}/${expectedExcludedCount}`
        });
      }
    }
    result.commuteAuditExclusionReasonSource = "fallback_placeholder";
    result.exclusionReasonCollectionFailed = false;
    result.exclusionReasonCollectionStage = null;
    result.expectedExcludedCount = expectedExcludedCount;
    result.actualReasonCount = Number(result.commuteAuditExclusionReasons.length || 0);
  }
  return finalizeNearbyPairResult(result);
}

