function gridlyCloneCoordinate(coordinate) {
  const resolved = gridlyCoordinateFromRecord(coordinate);
  return resolved ? { lat: resolved.lat, lng: resolved.lng } : null;
}

function gridlyReadMapCenterCoordinate() {
  if (!map || typeof map.getCenter !== "function") return null;
  return gridlyCloneCoordinate(map.getCenter());
}

function gridlyNowMs() {
  return (typeof performance !== "undefined" && typeof performance.now === "function") ? performance.now() : Date.now();
}

function gridlyReadMapContainerSnapshot() {
  try {
    const container = map && typeof map.getContainer === "function" ? map.getContainer() : null;
    if (!container || typeof container.getBoundingClientRect !== "function") return null;
    const rect = container.getBoundingClientRect();
    return {
      width: Math.round(rect.width * 10) / 10,
      height: Math.round(rect.height * 10) / 10,
      top: Math.round(rect.top * 10) / 10,
      left: Math.round(rect.left * 10) / 10,
      right: Math.round(rect.right * 10) / 10,
      bottom: Math.round(rect.bottom * 10) / 10,
      clientWidth: container.clientWidth || 0,
      clientHeight: container.clientHeight || 0
    };
  } catch (error) {
    return null;
  }
}

function gridlySummarizeTapMapSheetState() {
  const summarize = (selector) => {
    const el = document.querySelector(selector);
    if (!el) return null;
    let rect = null;
    let style = null;
    try {
      const bounds = el.getBoundingClientRect();
      rect = {
        top: Math.round(bounds.top * 10) / 10,
        left: Math.round(bounds.left * 10) / 10,
        width: Math.round(bounds.width * 10) / 10,
        height: Math.round(bounds.height * 10) / 10,
        bottom: Math.round(bounds.bottom * 10) / 10
      };
      const computed = getComputedStyle(el);
      style = {
        display: computed.display,
        visibility: computed.visibility,
        opacity: computed.opacity,
        pointerEvents: computed.pointerEvents,
        transform: computed.transform,
        translate: computed.translate
      };
    } catch (error) {
      rect = null;
      style = null;
    }
    return {
      selector,
      hidden: Boolean(el.hidden),
      className: typeof el.className === "string" ? el.className : "",
      activeSheet: el.dataset?.activeSheet || null,
      rect,
      style
    };
  };
  return {
    portraitV2Sheet: summarize("#gridlyPortraitV2Sheet"),
    portraitV2Backdrop: summarize("#gridlyPortraitV2SheetBackdrop"),
    legacyHazardPanel: summarize("#gridlyHazardPanel"),
    bodyClasses: document.body?.className || ""
  };
}

function gridlyTapMapSnapshotsDiffer(before, after) {
  if (!before || !after) return false;
  return ["width", "height", "top", "left", "right", "bottom"].some((key) => Math.abs(Number(before[key]) - Number(after[key])) > 0.5);
}

function gridlySheetSnapshotsDiffer(before, after) {
  if (!before || !after) return false;
  const fields = ["hidden", "className", "activeSheet"];
  const compareNode = (a, b) => {
    if (!a && !b) return false;
    if (!a || !b) return true;
    if (fields.some((field) => String(a[field] ?? "") !== String(b[field] ?? ""))) return true;
    const aRect = a.rect || {};
    const bRect = b.rect || {};
    return ["top", "left", "width", "height", "bottom"].some((key) => Math.abs(Number(aRect[key]) - Number(bRect[key])) > 0.5);
  };
  return compareNode(before.portraitV2Sheet, after.portraitV2Sheet)
    || compareNode(before.portraitV2Backdrop, after.portraitV2Backdrop)
    || compareNode(before.legacyHazardPanel, after.legacyHazardPanel)
    || String(before.bodyClasses || "") !== String(after.bodyClasses || "");
}

function gridlyReadPointerClientFromEvent(event) {
  const source = event?.touches?.[0] || event?.changedTouches?.[0] || event?.originalEvent?.touches?.[0] || event?.originalEvent?.changedTouches?.[0] || event?.originalEvent || event;
  const clientX = Number(source?.clientX);
  const clientY = Number(source?.clientY);
  if (!Number.isFinite(clientX) || !Number.isFinite(clientY)) return null;
  return {
    clientX,
    clientY,
    timestamp: Date.now(),
    performanceTimestamp: gridlyNowMs(),
    eventType: event?.type || event?.originalEvent?.type || "unknown",
    pointerType: source?.pointerType || event?.pointerType || ""
  };
}

function gridlyConvertClientPointToMapLatLng(rawPointerClient) {
  try {
    if (!map || typeof map.getContainer !== "function" || typeof map.containerPointToLatLng !== "function" || !rawPointerClient) return null;
    const container = map.getContainer();
    const rect = container.getBoundingClientRect();
    const x = rawPointerClient.clientX - rect.left;
    const y = rawPointerClient.clientY - rect.top;
    const point = typeof L !== "undefined" && typeof L.point === "function" ? L.point(x, y) : { x, y };
    const latLng = map.containerPointToLatLng(point);
    const coordinate = gridlyCloneCoordinate(latLng);
    return coordinate ? {
      lat: coordinate.lat,
      lng: coordinate.lng,
      containerPoint: {
        x: Math.round(x * 10) / 10,
        y: Math.round(y * 10) / 10
      }
    } : null;
  } catch (error) {
    return null;
  }
}

function gridlyCaptureTapMapPointer(event, source = "map_pointer_event") {
  if (!reportingState?.placementModeActive) return null;
  if (!pendingHazardPlacement && !reportingState.selectedHazardType) return null;
  const rawPointerClient = gridlyReadPointerClientFromEvent(event);
  if (!rawPointerClient) return null;
  const converted = gridlyConvertClientPointToMapLatLng(rawPointerClient);
  if (!converted) return null;
  const coordinate = { lat: converted.lat, lng: converted.lng };
  latestTapMapPointerCapture = {
    source,
    rawPointerClient,
    containerPointLatLng: coordinate,
    containerPoint: converted.containerPoint,
    capturedAt: Date.now(),
    capturedAtPerformance: rawPointerClient.performanceTimestamp,
    mapCenterAtTap: gridlyReadMapCenterCoordinate(),
    mapZoomAtTap: typeof map?.getZoom === "function" ? map.getZoom() : null,
    mapContainerSizeAtTap: gridlyReadMapContainerSnapshot(),
    sheetStateAtTap: gridlySummarizeTapMapSheetState()
  };
  return latestTapMapPointerCapture;
}

function installTapMapImmediatePointerCapture() {
  try {
    const container = map && typeof map.getContainer === "function" ? map.getContainer() : null;
    if (!container || container.dataset.gridlyTapMapPointerCapture === "1") return;
    container.dataset.gridlyTapMapPointerCapture = "1";
    const capture = (event) => gridlyCaptureTapMapPointer(event, `map_container_${event.type}`);
    container.addEventListener("pointerdown", capture, { capture: true, passive: true });
    container.addEventListener("touchstart", capture, { capture: true, passive: true });
    container.addEventListener("mousedown", capture, { capture: true, passive: true });
  } catch (error) {
    console.warn("Gridly tap-map pointer capture install failed", error);
  }
}

function gridlyRecordTapMapMovementCheckpoint(source = "unknown") {
  if (!tapMapPlacementAccuracyState.rawTapCapturedAt || tapMapPlacementAccuracyState.mapMovementMonitoringActive === false) return;
  const center = gridlyReadMapCenterCoordinate();
  if (!center) return;
  const previousCenter = tapMapPlacementAccuracyState.mapCenterAtTap;
  const deltaMeters = gridlyCoordinateDeltaMeters(previousCenter, center);
  const zoom = typeof map?.getZoom === "function" ? map.getZoom() : null;
  tapMapPlacementAccuracyState.latestMapCenterAfterTap = center;
  tapMapPlacementAccuracyState.latestMapZoomAfterTap = zoom;
  tapMapPlacementAccuracyState.mapMovementDeltaMeters = Number.isFinite(deltaMeters) ? deltaMeters : 0;
  if ((Number.isFinite(deltaMeters) && deltaMeters > 0.5) || zoom !== tapMapPlacementAccuracyState.mapZoomAtTap) {
    tapMapPlacementAccuracyState.mapMovementDetectedAfterTap = true;
    if (tapMapPlacementAccuracyState.coordinateAndMarkerLocked) {
      tapMapPlacementAccuracyState.movementAfterCoordinateAndMarkerLock = true;
    } else {
      tapMapPlacementAccuracyState.movementAfterPointerCaptureBeforeSubmit = true;
    }
    const finding = `map_movement_after_tap_detected:${source}`;
    if (!tapMapPlacementAccuracyState.findings.includes(finding)) tapMapPlacementAccuracyState.findings.push(finding);
  }
}

function gridlyStartTapMapPlacementAccuracyCapture(rawTapCoordinate, hazardType = "", options = {}) {
  const captured = gridlyCloneCoordinate(rawTapCoordinate);
  if (!captured) return null;
  const pointerCapture = options.pointerCapture || null;
  const center = pointerCapture?.mapCenterAtTap || gridlyReadMapCenterCoordinate();
  const mapContainerSizeAtTap = pointerCapture?.mapContainerSizeAtTap || gridlyReadMapContainerSnapshot();
  const sheetStateAtTap = pointerCapture?.sheetStateAtTap || gridlySummarizeTapMapSheetState();
  const rawPointerClient = pointerCapture?.rawPointerClient || options.rawPointerClient || null;
  const containerPointLatLng = gridlyCloneCoordinate(pointerCapture?.containerPointLatLng || options.containerPointLatLng) || captured;
  const rawLeafletLatLng = gridlyCloneCoordinate(options.rawLeafletLatLng) || null;
  const pointerCapturedBeforeLeafletClick = Boolean(pointerCapture?.capturedAtPerformance && options.clickReceivedAtPerformance && pointerCapture.capturedAtPerformance <= options.clickReceivedAtPerformance);
  const pointerCaptureAgeMs = pointerCapture?.capturedAtPerformance && options.clickReceivedAtPerformance
    ? Math.round((options.clickReceivedAtPerformance - pointerCapture.capturedAtPerformance) * 10) / 10
    : null;
  const captureWasImmediate = Boolean(rawPointerClient && containerPointLatLng && pointerCapturedBeforeLeafletClick);
  tapMapPlacementAccuracyState = {
    auditVersion: "GRIDLY_V236_2B_TAP_MAP_AUDIT_CONFIDENCE",
    tapMapModeActive: Boolean(reportingState?.placementModeActive),
    lastRawTapCoordinate: captured,
    lastSubmittedReportCoordinate: null,
    lastRenderedMarkerCoordinate: null,
    lastResolvedRoadCoordinate: null,
    resolverAttemptedCoordinateReplacement: false,
    resolverAttemptedReplacementDeltaMeters: null,
    rawPointerClient,
    rawLeafletLatLng,
    containerPointLatLng,
    finalSubmittedCoordinate: null,
    markerCoordinate: null,
    visualDeltaWarning: "",
    coordinateSourceUsed: captureWasImmediate ? "immediate_pointer_container_point" : "leaflet_click_latlng_fallback",
    rawTapCapturedAt: Date.now(),
    rawTapCapturedIso: new Date().toISOString(),
    mapCenterAtTap: center,
    mapZoomAtTap: pointerCapture?.mapZoomAtTap ?? (typeof map?.getZoom === "function" ? map.getZoom() : null),
    mapContainerSizeAtTap,
    mapContainerSizeAfterSubmit: null,
    sheetStateAtTap,
    sheetStateAfterSubmit: null,
    latestMapCenterAfterTap: center,
    latestMapZoomAfterTap: pointerCapture?.mapZoomAtTap ?? (typeof map?.getZoom === "function" ? map.getZoom() : null),
    mapMovementDetectedAfterTap: false,
    mapMovementDeltaMeters: 0,
    mapMovementMonitoringActive: true,
    pointerCapturedBeforeLeafletClick,
    pointerCaptureAgeMs,
    layoutChangedAfterTap: false,
    dangerousMovementBeforePointerCapture: false,
    movementAfterPointerCaptureBeforeSubmit: false,
    movementAfterCoordinateAndMarkerLock: false,
    movementAfterCleanup: false,
    layoutChangedAfterCoordinateLock: false,
    mapContainerSizeAfterCleanup: null,
    sheetStateAfterCleanup: null,
    coordinateAndMarkerLocked: false,
    coordinateLockedAt: null,
    coordinateLockedIso: null,
    visualAccuracyConfidence: captureWasImmediate ? "high" : "low",
    findings: [
      captureWasImmediate
        ? "pointer client coordinates and containerPointToLatLng were captured synchronously before Leaflet click handling or UI teardown"
        : "tap coordinate fell back to Leaflet click latlng; immediate pointer capture was unavailable, so visual confidence is low",
      hazardType ? `hazard_type:${hazardType}` : "hazard_type:unknown"
    ]
  };
  return captured;
}

function gridlyFinishTapMapPlacementAccuracyCapture({ submittedReportCoordinate = null, renderedMarkerCoordinate = null, resolvedRoadCoordinate = null, finding = "", monitoringComplete = false, afterCoordinateLockCleanup = false, coordinateRendered = true } = {}) {
  const submitted = gridlyCloneCoordinate(submittedReportCoordinate);
  const rendered = gridlyCloneCoordinate(renderedMarkerCoordinate) || submitted;
  const resolvedRoad = gridlyCloneCoordinate(resolvedRoadCoordinate);
  if (submitted) {
    tapMapPlacementAccuracyState.lastSubmittedReportCoordinate = submitted;
    tapMapPlacementAccuracyState.finalSubmittedCoordinate = submitted;
  }
  if (rendered) {
    tapMapPlacementAccuracyState.lastRenderedMarkerCoordinate = rendered;
    tapMapPlacementAccuracyState.markerCoordinate = rendered;
  }
  tapMapPlacementAccuracyState.lastResolvedRoadCoordinate = resolvedRoad;
  const resolverReplacementDeltaMeters = gridlyCoordinateDeltaMeters(submitted, resolvedRoad);
  const resolverAttemptedCoordinateReplacement = Boolean(submitted && resolvedRoad && Number.isFinite(resolverReplacementDeltaMeters) && resolverReplacementDeltaMeters > 0.5);
  tapMapPlacementAccuracyState.resolverAttemptedCoordinateReplacement = Boolean(tapMapPlacementAccuracyState.resolverAttemptedCoordinateReplacement || resolverAttemptedCoordinateReplacement);
  tapMapPlacementAccuracyState.resolverAttemptedReplacementDeltaMeters = Number.isFinite(resolverReplacementDeltaMeters) ? resolverReplacementDeltaMeters : tapMapPlacementAccuracyState.resolverAttemptedReplacementDeltaMeters;
  tapMapPlacementAccuracyState.coordinateSourceUsed = tapMapPlacementAccuracyState.pointerCapturedBeforeLeafletClick === true ? "immediate_pointer_container_point" : "leaflet_click_latlng_fallback";
  tapMapPlacementAccuracyState.tapMapModeActive = Boolean(reportingState?.placementModeActive);
  const snapshotNow = gridlyReadMapContainerSnapshot();
  const sheetNow = gridlySummarizeTapMapSheetState();
  if (afterCoordinateLockCleanup) {
    tapMapPlacementAccuracyState.mapContainerSizeAfterCleanup = snapshotNow;
    tapMapPlacementAccuracyState.sheetStateAfterCleanup = sheetNow;
  } else {
    tapMapPlacementAccuracyState.mapContainerSizeAfterSubmit = snapshotNow;
    tapMapPlacementAccuracyState.sheetStateAfterSubmit = sheetNow;
  }
  const comparisonMapSnapshot = afterCoordinateLockCleanup
    ? (tapMapPlacementAccuracyState.mapContainerSizeAfterSubmit || tapMapPlacementAccuracyState.mapContainerSizeAtTap)
    : tapMapPlacementAccuracyState.mapContainerSizeAtTap;
  const comparisonSheetSnapshot = afterCoordinateLockCleanup
    ? (tapMapPlacementAccuracyState.sheetStateAfterSubmit || tapMapPlacementAccuracyState.sheetStateAtTap)
    : tapMapPlacementAccuracyState.sheetStateAtTap;
  const mapContainerChanged = gridlyTapMapSnapshotsDiffer(comparisonMapSnapshot, snapshotNow);
  const sheetChanged = gridlySheetSnapshotsDiffer(comparisonSheetSnapshot, sheetNow);
  const layoutChangedNow = Boolean(mapContainerChanged || sheetChanged);
  if (afterCoordinateLockCleanup) {
    tapMapPlacementAccuracyState.layoutChangedAfterCoordinateLock = Boolean(tapMapPlacementAccuracyState.layoutChangedAfterCoordinateLock || layoutChangedNow);
    tapMapPlacementAccuracyState.movementAfterCoordinateAndMarkerLock = Boolean(tapMapPlacementAccuracyState.movementAfterCoordinateAndMarkerLock || layoutChangedNow);
    tapMapPlacementAccuracyState.movementAfterCleanup = Boolean(tapMapPlacementAccuracyState.movementAfterCleanup || layoutChangedNow);
  } else {
    tapMapPlacementAccuracyState.layoutChangedAfterTap = Boolean(tapMapPlacementAccuracyState.layoutChangedAfterTap || layoutChangedNow);
    tapMapPlacementAccuracyState.movementAfterPointerCaptureBeforeSubmit = Boolean(tapMapPlacementAccuracyState.movementAfterPointerCaptureBeforeSubmit || layoutChangedNow);
  }
  const captureDeltaMeters = gridlyCoordinateDeltaMeters(tapMapPlacementAccuracyState.containerPointLatLng, submitted);
  const markerDeltaMeters = gridlyCoordinateDeltaMeters(submitted, rendered);
  const coordinateLocked = Boolean(
    coordinateRendered
      && tapMapPlacementAccuracyState.pointerCapturedBeforeLeafletClick === true
      && tapMapPlacementAccuracyState.coordinateSourceUsed === "immediate_pointer_container_point"
      && Number.isFinite(captureDeltaMeters)
      && captureDeltaMeters <= 0.5
      && Number.isFinite(markerDeltaMeters)
      && markerDeltaMeters <= 0.5
  );
  if (!afterCoordinateLockCleanup && coordinateLocked) {
    tapMapPlacementAccuracyState.coordinateAndMarkerLocked = true;
    tapMapPlacementAccuracyState.coordinateLockedAt = Date.now();
    tapMapPlacementAccuracyState.coordinateLockedIso = new Date().toISOString();
  }
  if (Number.isFinite(captureDeltaMeters) && captureDeltaMeters > 0.5) {
    tapMapPlacementAccuracyState.visualDeltaWarning = `submitted coordinate differs from immediate container-point coordinate by ${Math.round(captureDeltaMeters * 10) / 10}m`;
  } else if (!tapMapPlacementAccuracyState.rawPointerClient) {
    tapMapPlacementAccuracyState.visualDeltaWarning = "immediate pointer coordinate was not captured before Leaflet click conversion";
  } else if (tapMapPlacementAccuracyState.dangerousMovementBeforePointerCapture) {
    tapMapPlacementAccuracyState.visualDeltaWarning = "map or sheet layout changed before immediate pointer/container coordinate conversion";
  } else if (tapMapPlacementAccuracyState.layoutChangedAfterTap || tapMapPlacementAccuracyState.layoutChangedAfterCoordinateLock) {
    tapMapPlacementAccuracyState.visualDeltaWarning = "layout movement detected after immediate pointer/container capture; marker coordinate remained locked when submitted and rendered coordinates match";
  } else {
    tapMapPlacementAccuracyState.visualDeltaWarning = "";
  }
  if (!tapMapPlacementAccuracyState.rawPointerClient || tapMapPlacementAccuracyState.pointerCapturedBeforeLeafletClick !== true || tapMapPlacementAccuracyState.coordinateSourceUsed !== "immediate_pointer_container_point") {
    tapMapPlacementAccuracyState.visualAccuracyConfidence = "low";
  } else if (tapMapPlacementAccuracyState.dangerousMovementBeforePointerCapture || !tapMapPlacementAccuracyState.coordinateAndMarkerLocked) {
    tapMapPlacementAccuracyState.visualAccuracyConfidence = "medium";
  } else {
    tapMapPlacementAccuracyState.visualAccuracyConfidence = "high";
  }
  if (finding && !tapMapPlacementAccuracyState.findings.includes(finding)) tapMapPlacementAccuracyState.findings.push(finding);
  const mapContainerFinding = afterCoordinateLockCleanup ? "map_container_changed_after_coordinate_lock" : "map_container_changed_after_tap";
  const sheetFinding = afterCoordinateLockCleanup ? "sheet_state_changed_after_coordinate_lock" : "sheet_state_changed_after_tap";
  if (mapContainerChanged && !tapMapPlacementAccuracyState.findings.includes(mapContainerFinding)) tapMapPlacementAccuracyState.findings.push(mapContainerFinding);
  if (sheetChanged && !tapMapPlacementAccuracyState.findings.includes(sheetFinding)) tapMapPlacementAccuracyState.findings.push(sheetFinding);
  if (resolverAttemptedCoordinateReplacement) {
    const resolverFinding = `road_resolver_coordinate_replacement_attempt_blocked:${Math.round(resolverReplacementDeltaMeters * 10) / 10}m`;
    if (!tapMapPlacementAccuracyState.findings.includes(resolverFinding)) tapMapPlacementAccuracyState.findings.push(resolverFinding);
  }
  if (tapMapPlacementAccuracyState.visualDeltaWarning && !tapMapPlacementAccuracyState.findings.includes(tapMapPlacementAccuracyState.visualDeltaWarning)) {
    tapMapPlacementAccuracyState.findings.push(tapMapPlacementAccuracyState.visualDeltaWarning);
  }
  gridlyRecordTapMapMovementCheckpoint("finish_capture");
  if (monitoringComplete) tapMapPlacementAccuracyState.mapMovementMonitoringActive = false;
}


const DEFAULT_REPORT_HAZARD_TYPE = "other_hazard";
let reportActionCompletionAudit = {
  reportHazardTypeResolved: false,
  reportUseLocationAttempted: false,
  reportUseLocationSubmitted: false,
  reportUseLocationCompleted: false,
  reportUseLocationError: "",
  reportTapMapAttempted: false,
  reportTapMapPlacementArmed: false,
  reportTapMapSubmitted: false,
  reportTapMapCompleted: false,
  reportTapMapError: "",
  lastReportAction: "",
  lastReportActionCompleted: false,
  lastReportCompletedAt: null,
  lastReportCompletionState: "idle",
  lastResolvedHazardType: ""
};

function markReportActionCompletionAudit(patch = {}) {
  const normalizedPatch = { ...patch };
  if (normalizedPatch.lastReportActionCompleted === true) {
    normalizedPatch.lastReportCompletedAt = normalizedPatch.lastReportCompletedAt || Date.now();
    normalizedPatch.lastReportCompletionState = normalizedPatch.lastReportCompletionState || "completed";
  } else if (normalizedPatch.lastReportActionCompleted === false && !normalizedPatch.lastReportCompletionState) {
    normalizedPatch.lastReportCompletionState = normalizedPatch.reportUseLocationError || normalizedPatch.reportTapMapError ? "error" : "pending";
  }
  reportActionCompletionAudit = {
    ...reportActionCompletionAudit,
    ...normalizedPatch
  };
  window.gridlyReportActionCompletionAudit = { ...reportActionCompletionAudit };
}

function resolveRoadHazardReportTypeForAction(hazardType, options = {}) {
  const rawType = String(hazardType || "").trim();
  if (rawType && HAZARD_TYPES[rawType]) {
    markReportActionCompletionAudit({
      reportHazardTypeResolved: true,
      lastResolvedHazardType: rawType
    });
    return { type: rawType, defaulted: false };
  }
  const fallbackType = DEFAULT_REPORT_HAZARD_TYPE;
  markReportActionCompletionAudit({
    reportHazardTypeResolved: true,
    lastResolvedHazardType: fallbackType
  });
  if (options.announceDefault !== false) {
    updateReportingState({
      selectedHazardType: fallbackType,
      lastReportError: "",
      lastReportMessage: "No hazard type selected. Reporting as Other Hazard."
    });
    setConfirmation("No hazard type selected. Reporting as Other Hazard.", "info", { persist: true });
  }
  return { type: fallbackType, defaulted: true };
}

