const GRIDLY_SEARCH_RENDER_LIMIT = 5;
const GRIDLY_SEARCH_NOISY_META_TOKENS = new Set(["administrative", "unknown", "boundary", "place", "node", "hamlet", "village", "city", "town"]);

function normalizeGridlySearchDisplayLabel(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .replace(/\s+/g, " ");
}

function getGridlySearchQueryTokens(query = "") {
  return normalizeGridlySearchDisplayLabel(query)
    .replace(/[’']/g, "")
    .split(/[^a-z0-9]+/i)
    .map((token) => token.trim())
    .filter(Boolean);
}

function normalizeGridlyBrandSearchText(value = "") {
  let normalized = normalizeGridlySearchDisplayLabel(value)
    .replace(/[’']/g, "")
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  for (const entry of GRIDLY_SEARCH_BRAND_ALIASES) {
    for (const alias of entry.aliases) {
      const aliasPattern = normalizeGridlySearchDisplayLabel(alias).replace(/[’']/g, "").replace(/[^a-z0-9]+/g, " ").trim();
      if (!aliasPattern) continue;
      normalized = normalized.replace(new RegExp(`(^|\\s)${aliasPattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}(?=\\s|$)`, "g"), `$1${entry.canonical}`);
    }
  }
  return normalized.replace(/\s+/g, " ").trim();
}

function getGridlyCanonicalSearchTerms(value = "") {
  const normalized = normalizeGridlyBrandSearchText(value);
  const tokens = getGridlySearchQueryTokens(normalized);
  return { normalized, tokens };
}

function gridlySearchQueryHasAddressIndicator(query = "") {
  const normalized = normalizeGridlySearchDisplayLabel(query);
  if (!normalized) return false;
  const tokens = getGridlySearchQueryTokens(normalized);
  if (/^\d{1,6}\s+[a-z0-9]/i.test(normalized)) return true;
  if (/\b\d{5}(?:-\d{4})?\b/.test(normalized)) return true;
  return tokens.some((token) => GRIDLY_SEARCH_ADDRESS_WORDS.has(token));
}

function gridlySearchQueryHasDestinationIndicator(query = "") {
  const normalized = normalizeGridlySearchDisplayLabel(query);
  if (!normalized) return false;
  if (/[,@]/.test(normalized)) return true;
  if (/\b(?:near|in)\s+[a-z0-9]/i.test(normalized)) return true;
  const tokens = getGridlySearchQueryTokens(normalized);
  if (tokens.some((token) => GRIDLY_SEARCH_DESTINATION_LOCATION_WORDS.has(token))) return true;
  return tokens.some((token) => Boolean(LOCAL_PLACE_LOOKUP[token]));
}

function classifyGridlyDestinationSearchIntent(query = "") {
  const normalized = normalizeGridlySearchDisplayLabel(query);
  if (!normalized) return { type: GRIDLY_DESTINATION_INTENTS.GENERIC_LOCAL, reason: "empty" };
  if (gridlySearchQueryHasAddressIndicator(normalized)) {
    return { type: GRIDLY_DESTINATION_INTENTS.ADDRESS, reason: "address_indicator" };
  }
  if (gridlySearchQueryHasDestinationIndicator(normalized)) {
    return { type: GRIDLY_DESTINATION_INTENTS.EXPLICIT_DESTINATION, reason: "destination_indicator" };
  }
  return { type: GRIDLY_DESTINATION_INTENTS.GENERIC_LOCAL, reason: "no_destination_indicator" };
}

function getGridlySelectedHomeTownAnchor() {
  const area = typeof getGridlySelectedAwarenessArea === "function" ? getGridlySelectedAwarenessArea() : null;
  if (!area) return null;
  return { label: area.label, lat: area.lat, lng: area.lng, source: area.countyWide ? "awareness_county" : (area.fallback ? "awareness_fallback" : "awareness_area"), countyWide: area.countyWide === true, fallback: area.fallback === true, radiusMiles: area.radiusMiles ?? null };
}

function getGridlySearchAnchorContext(searchContext = null) {
  const homeTownAnchor = getGridlySelectedHomeTownAnchor();
  if (homeTownAnchor) return homeTownAnchor;
  const center = searchContext?.center || getGridlySearchMapContext()?.center || null;
  if (center && Number.isFinite(center.lat) && Number.isFinite(center.lng)) {
    return { label: "Map center", lat: center.lat, lng: center.lng, source: "map_center" };
  }
  return { label: "Liberty County", lat: defaultCenter[0], lng: defaultCenter[1], source: "default_center" };
}

function buildGridlySearchDisplayLines(result) {
  const raw = result?.raw && typeof result.raw === "object" ? result.raw : {};
  const rawAddress = raw?.address && typeof raw.address === "object" ? raw.address : {};
  const conciseAddressName = String(
    rawAddress.road ||
    rawAddress.city ||
    rawAddress.town ||
    rawAddress.village ||
    rawAddress.hamlet ||
    ""
  ).trim();
  const baseTitle = String(result.label || result.title || conciseAddressName || result.address || "Destination").trim();
  const title = isGridlyUsefulMetaValue(baseTitle) ? baseTitle : (conciseAddressName || "Destination");
  const titleNorm = normalizeGridlySearchDisplayLabel(title);
  const provider = String(result.provider || "").trim();
  const type = String(result.type || "").trim();
  const metaParts = [type, provider]
    .map((entry) => String(entry || "").trim())
    .filter(Boolean)
    .filter((entry) => !GRIDLY_SEARCH_NOISY_META_TOKENS.has(entry.toLowerCase()));
  const meta = metaParts.find((entry) => normalizeGridlySearchDisplayLabel(entry) !== titleNorm) || "";
  return { title, meta };
}

function toGridlyTitleCase(value) {
  const normalized = String(value || "").trim();
  if (!normalized) return "";
  return normalized
    .split(/\s+/)
    .filter(Boolean)
    .map((part) => {
      if (part.length <= 3 && part.toUpperCase() === part) return part;
      if (/^\d/.test(part)) return part;
      return part.charAt(0).toUpperCase() + part.slice(1).toLowerCase();
    })
    .join(" ");
}

function isGridlyUsefulMetaValue(value) {
  const normalized = normalizeGridlySearchDisplayLabel(value);
  if (!normalized) return false;
  return !GRIDLY_SEARCH_NOISY_META_TOKENS.has(normalized);
}

function cleanGridlyDisplayNameContext(displayName, fallbackTitle = "") {
  const normalizedTitle = normalizeGridlySearchDisplayLabel(fallbackTitle);
  const noisyDisplayParts = new Set(["united states", "usa", "us"]);
  const parts = String(displayName || "")
    .split(",")
    .map((part) => toGridlyTitleCase(part))
    .map((part) => String(part || "").trim())
    .filter((part) => isGridlyUsefulMetaValue(part))
    .filter((part) => normalizeGridlySearchDisplayLabel(part) !== normalizedTitle)
    .filter((part) => !noisyDisplayParts.has(normalizeGridlySearchDisplayLabel(part)));
  if (!parts.length) return "";
  const stateMatcher = /^(alabama|alaska|arizona|arkansas|california|colorado|connecticut|delaware|florida|georgia|hawaii|idaho|illinois|indiana|iowa|kansas|kentucky|louisiana|maine|maryland|massachusetts|michigan|minnesota|mississippi|missouri|montana|nebraska|nevada|new hampshire|new jersey|new mexico|new york|north carolina|north dakota|ohio|oklahoma|oregon|pennsylvania|rhode island|south carolina|south dakota|tennessee|texas|utah|vermont|virginia|washington|west virginia|wisconsin|wyoming|district of columbia)$/i;
  const countyIndex = parts.findIndex((part) => /\bcounty\b/i.test(part));
  if (countyIndex >= 0) {
    const nextPart = parts[countyIndex + 1] || "";
    if (stateMatcher.test(nextPart)) return `${parts[countyIndex]}, ${nextPart}`;
  }
  const county = parts.find((part) => /\bcounty\b/i.test(part)) || "";
  const state = parts.find((part) => stateMatcher.test(part)) || "";
  if (county && state) return `${county}, ${state}`;
  if (parts.length >= 2) return `${parts[0]}, ${parts[1]}`;
  return parts[0];
}

function cleanGridlyNormalizedContext(contextValue, fallbackTitle = "") {
  const normalizedTitle = normalizeGridlySearchDisplayLabel(fallbackTitle);
  const noisyTokens = new Set(["administrative", "unknown", "boundary", "place", "node", "city", "town", "village", "hamlet"]);
  const sanitizePart = (value) => toGridlyTitleCase(String(value || "").replace(/\s+/g, " ").trim());
  const cleanParts = (parts) => {
    const cleaned = parts
      .map((part) => sanitizePart(part))
      .filter(Boolean)
      .filter((part) => {
        const normalized = normalizeGridlySearchDisplayLabel(part);
        return normalized && normalized !== normalizedTitle && !noisyTokens.has(normalized) && normalized !== "[object object]" && normalized !== "object object";
      });
    while (cleaned.length && normalizeGridlySearchDisplayLabel(cleaned[cleaned.length - 1]) === "united states") cleaned.pop();
    return cleaned;
  };

  if (contextValue && typeof contextValue === "object" && !Array.isArray(contextValue)) {
    const location = contextValue;
    const take = (...keys) => keys.map((key) => sanitizePart(location?.[key])).find(Boolean) || "";
    const county = take("county");
    const state = take("state");
    const locality = take("city", "town", "village", "hamlet", "municipality");
    const suburb = take("suburb", "neighbourhood", "neighborhood");
    const road = take("road");
    const country = take("country");

    const objectCandidates = [];
    if (road && locality && state) objectCandidates.push([`Near ${road} · ${locality}`, state]);
    if (suburb && locality && state) objectCandidates.push([suburb, locality, state]);
    if (locality && state) objectCandidates.push([locality, state]);
    if (county && state) objectCandidates.push([county, state]);
    if (state && country) objectCandidates.push([state, country]);

    const objectEntries = Object.entries(location)
      .map(([, value]) => sanitizePart(value))
      .filter(Boolean)
      .slice(0, 2);
    if (objectEntries.length) objectCandidates.push(objectEntries);

    for (const candidate of objectCandidates) {
      const cleaned = cleanParts(candidate);
      if (cleaned.length) return cleaned.slice(0, 2).join(", ");
    }
    return "";
  }

  const normalizedRaw = normalizeGridlySearchDisplayLabel(contextValue);
  if (normalizedRaw === "[object object]" || normalizedRaw === "object object") return "";

  const parts = cleanParts(String(contextValue || "").split(","));
  return parts.join(", ").replace(/,\s*,+/g, ", ").replace(/\s{2,}/g, " ").trim().replace(/,\s*$/, "");
}

function buildGridlyLocationContext(result) {
  try {
    const raw = result?.raw && typeof result.raw === "object" ? result.raw : {};
    const resolve = (...values) => values.map((value) => String(value || "").trim()).find(Boolean) || "";
    const sourceTitle = resolve(result?.label, result?.title, result?.display_name, raw?.display_name, "");
    const subtitleContext = cleanGridlyNormalizedContext(result?.subtitle, sourceTitle);
    if (subtitleContext) {
      gridlySearchUiState.lastContextDiagnostics = { strategy: "subtitle", hasNormalizedSubtitle: true };
      return subtitleContext;
    }
    const addressContext = cleanGridlyNormalizedContext(result?.address, sourceTitle);
    if (addressContext) {
      gridlySearchUiState.lastContextDiagnostics = { strategy: "address", hasNormalizedAddress: true };
      return addressContext;
    }
    const rawAddressContext = cleanGridlyNormalizedContext(raw?.address, sourceTitle);
    if (rawAddressContext) {
      gridlySearchUiState.lastContextDiagnostics = { strategy: "raw_address", hasRawAddress: true };
      return rawAddressContext;
    }
    const displayNameValue = resolve(raw?.display_name, result?.display_name, "");
    const displayNameContext = cleanGridlyDisplayNameContext(displayNameValue, sourceTitle);
    if (displayNameContext) {
      gridlySearchUiState.lastContextDiagnostics = {
        strategy: "display_name_fallback",
        hasAddressFields: Boolean(raw?.address && typeof raw.address === "object" && Object.keys(raw.address).length),
        contextSourcePreview: {
          hasRawDisplayName: Boolean(resolve(raw?.display_name, "")),
          hasRawAddress: Boolean(raw?.address && typeof raw.address === "object"),
          rawDisplayNameSample: String(resolve(raw?.display_name, result?.display_name, "")).slice(0, 120),
          addressKeys: raw?.address && typeof raw.address === "object" ? Object.keys(raw.address).slice(0, 6) : []
        }
      };
      return displayNameContext;
    }
    gridlySearchUiState.lastContextDiagnostics = {
      strategy: "empty",
      hasAddressFields: Boolean(raw?.address && typeof raw.address === "object" && Object.keys(raw.address).length),
      hasDisplayName: Boolean(resolve(raw?.display_name, result?.display_name, ""))
    };
    return "";
  } catch (_error) {
    return "";
  }
}

function getGridlySearchMapContext() {
  const mapInstance = typeof getGridlyMapInstance === "function" ? getGridlyMapInstance() : (typeof map !== "undefined" ? map : null);
  const centerCandidate = mapInstance && typeof mapInstance.getCenter === "function" ? mapInstance.getCenter() : null;
  const center = normalizeCoordinatePair(
    centerCandidate?.lat ?? userLocation?.lat ?? defaultCenter[0],
    centerCandidate?.lng ?? userLocation?.lng ?? defaultCenter[1]
  );
  const bounds = mapInstance && typeof mapInstance.getBounds === "function" ? mapInstance.getBounds() : null;
  const south = Number(bounds?.getSouth?.());
  const north = Number(bounds?.getNorth?.());
  const west = Number(bounds?.getWest?.());
  const east = Number(bounds?.getEast?.());
  const hasBounds = Number.isFinite(south) && Number.isFinite(north) && Number.isFinite(west) && Number.isFinite(east);
  return {
    center: center || { lat: defaultCenter[0], lng: defaultCenter[1] },
    bounds: hasBounds ? bounds : null,
    viewbox: hasBounds ? `${west},${north},${east},${south}` : ""
  };
}

function gridlySearchResultContainsTexas(haystack) {
  return /(^|[\s,])(texas|tx)([\s,]|$)/i.test(String(haystack || ""));
}

function gridlySearchResultContainsLocality(haystack, anchor = null) {
  const normalized = normalizeGridlySearchDisplayLabel(haystack);
  if (!normalized) return false;
  if (/\b(liberty county|liberty, texas|liberty, tx)\b/i.test(normalized)) return true;
  const anchorLabel = normalizeGridlySearchDisplayLabel(anchor?.label || "");
  if (anchorLabel && anchorLabel !== "map center" && new RegExp(`\\b${anchorLabel.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i").test(normalized)) return true;
  return Object.keys(LOCAL_PLACE_LOOKUP).some((town) => new RegExp(`\\b${town.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i").test(normalized));
}

function getGridlySearchResultHaystack(result, context = "") {
  return normalizeGridlySearchDisplayLabel(
    `${result?.label || ""} ${result?.title || ""} ${result?.address || ""} ${result?.subtitle || ""} ${context} ${result?.raw?.display_name || ""}`
  );
}

function getGridlySearchResultTitleMatchScore(result, rawQuery = "") {
  const query = normalizeGridlyBrandSearchText(rawQuery).replace(/\b(near|in)\b.*$/i, "").trim();
  const title = normalizeGridlyBrandSearchText(result?.title || result?.label || "");
  if (!query || !title) return 0;
  if (title === query) return 28;
  if (title.startsWith(query)) return 20;
  if (title.includes(query)) return 10;
  return 0;
}

function prioritizeGridlySearchResults(results = [], options = {}) {
  if (!Array.isArray(results) || !results.length) return [];
  const searchContext = getGridlySearchMapContext();
  const intent = options.intent || classifyGridlyDestinationSearchIntent(options.query || ensureGridlySearchState().activeQuery || "");
  const isGenericLocalSearch = intent.type === GRIDLY_DESTINATION_INTENTS.GENERIC_LOCAL;
  const anchor = getGridlySearchAnchorContext(searchContext);
  const scored = results.map((result, index) => {
    const context = buildGridlyLocationContext(result);
    const haystack = getGridlySearchResultHaystack(result, context);
    const hasCoordinates = Number.isFinite(result?.lat) && Number.isFinite(result?.lng);
    const inBounds = Boolean(searchContext.bounds && hasCoordinates && searchContext.bounds.contains([result.lat, result.lng]));
    const isTexas = gridlySearchResultContainsTexas(haystack);
    const isLibertyCounty = /\bliberty county\b/i.test(haystack);
    const isLocality = gridlySearchResultContainsLocality(haystack, anchor);
    const distanceMiles = hasCoordinates && searchContext.center
      ? haversineDistance(searchContext.center.lat, searchContext.center.lng, result.lat, result.lng)
      : null;
    const anchorDistanceMiles = hasCoordinates && anchor
      ? haversineDistance(anchor.lat, anchor.lng, result.lat, result.lng)
      : distanceMiles;
    let score = Math.max(0, GRIDLY_SEARCH_RENDER_LIMIT - index) * 0.25;
    if (isGenericLocalSearch) {
      if (result?.provider === "local_poi_seed" || result?.localPoiSeed) score += 18;
      if (Number.isFinite(anchorDistanceMiles)) {
        if (anchorDistanceMiles <= 10) score += 135;
        else if (anchorDistanceMiles <= 25) score += 115;
        else if (anchorDistanceMiles <= 50) score += 95;
        else if (anchorDistanceMiles <= 75) score += 40;
        else if (anchorDistanceMiles <= 150) score += 12;
      }
      if (inBounds) score += 70;
      if (isLibertyCounty) score += 55;
      if (isLocality) score += 40;
      if (isTexas) score += 25;
      if (Number.isFinite(anchorDistanceMiles) && anchorDistanceMiles > 250) score -= 40;
    } else {
      if ((result?.provider === "local_poi_seed" || result?.localPoiSeed) && isLocality) score += 8;
      if (inBounds) score += 25;
      if (isTexas) score += 12;
      if (isLocality) score += 8;
      if (Number.isFinite(distanceMiles) && distanceMiles <= 75) score += 6;
    }
    score += getGridlySearchResultTitleMatchScore(result, options.query || ensureGridlySearchState().activeQuery || "");
    const resultBucket = isGenericLocalSearch && Number.isFinite(anchorDistanceMiles) && anchorDistanceMiles <= 50
      ? "nearby_your_town"
      : isTexas
        ? "other_texas_results"
        : "farther_away";
    const rankedResult = {
      ...result,
      searchIntent: intent.type,
      searchRank: {
        score,
        bucket: resultBucket,
        inBounds,
        isTexas,
        isLibertyCounty,
        isLocality,
        distanceMiles,
        anchorDistanceMiles,
        anchor: anchor ? { label: anchor.label, source: anchor.source } : null
      }
    };
    return { result: rankedResult, score, index, inBounds, isTexas, isLibertyCounty, isLocality, distanceMiles, anchorDistanceMiles };
  });
  if (isGenericLocalSearch) {
    const hasNearbyMatch = scored.some((entry) => Number.isFinite(entry.anchorDistanceMiles) && entry.anchorDistanceMiles <= 50);
    if (hasNearbyMatch) {
      scored.forEach((entry) => {
        if (!Number.isFinite(entry.anchorDistanceMiles) || entry.anchorDistanceMiles > 50) entry.score -= 60;
      });
    }
  } else {
    const hasLocalOrTexasMatch = scored.some((entry) => entry.inBounds || entry.isLocality || entry.isTexas);
    if (hasLocalOrTexasMatch) {
      scored.forEach((entry) => {
        if (!entry.inBounds && !entry.isLocality && !entry.isTexas) entry.score -= 20;
      });
    }
  }
  const prioritized = scored.sort((a, b) => (b.score - a.score) || (a.index - b.index));
  prioritized.forEach((entry, sortedIndex) => {
    if (entry.result?.searchRank) {
      entry.result.searchRank.score = entry.score;
      entry.result.searchRank.rank = sortedIndex + 1;
    }
  });
  gridlySearchUiState.prioritizedLocalResultsCount = prioritized.filter((entry) => entry.inBounds || entry.isLocality || entry.isTexas || (Number.isFinite(entry.anchorDistanceMiles) && entry.anchorDistanceMiles <= 50)).length;
  return prioritized.map((entry) => entry.result);
}

function dedupeGridlySearchResults(results, options = {}) {
  if (!Array.isArray(results) || !results.length) return [];
  const parsedLimit = Number(options.limit);
  const maxResults = Number.isFinite(parsedLimit)
    ? Math.min(Math.max(Math.floor(parsedLimit), 1), 25)
    : GRIDLY_SEARCH_RENDER_LIMIT;
  const seen = new Set();
  const deduped = [];
  for (const result of results) {
    const display = buildGridlySearchDisplayLines(result);
    const labelKey = normalizeGridlySearchDisplayLabel(display.title);
    const hasCoords = Number.isFinite(result?.lat) && Number.isFinite(result?.lng);
    const coordKey = hasCoords ? `${result.lat.toFixed(3)},${result.lng.toFixed(3)}` : "no-coords";
    const dedupeKey = `${labelKey}|${coordKey}`;
    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);
    deduped.push(result);
    if (deduped.length >= maxResults) break;
  }
  return deduped;
}

function isGridlyLocalQualitySearchResult(result) {
  if (!result || typeof result !== "object") return false;
  const rank = result.searchRank && typeof result.searchRank === "object" ? result.searchRank : {};
  const anchorDistanceMiles = Number(rank.anchorDistanceMiles);
  return Boolean(
    result.provider === "local_poi_seed"
      || result.localPoiSeed
      || rank.inBounds
      || rank.isLibertyCounty
      || rank.isLocality
      || (Number.isFinite(anchorDistanceMiles) && anchorDistanceMiles <= 150)
      || (rank.isTexas && Number.isFinite(anchorDistanceMiles) && anchorDistanceMiles <= 250)
  );
}

function isGridlyCountyOnlyProviderDuplicate(result, localSeedTitles = new Set()) {
  if (!result || result.provider === "local_poi_seed" || result.localPoiSeed) return false;
  const display = buildGridlySearchDisplayLines(result);
  const titleKey = normalizeGridlySearchDisplayLabel(display.title);
  if (!titleKey || !localSeedTitles.has(titleKey)) return false;
  const context = buildGridlyLocationContext(result);
  const haystack = getGridlySearchResultHaystack(result, context);
  const hasPreciseAddress = /\b(near|road|rd|street|st|avenue|ave|drive|dr|highway|hwy|fm|i-?\d+|us\s*\d+|tx\s*\d+)\b/i.test(haystack);
  const countyOnlyContext = /\bcounty\b/i.test(context) && !/\b(city|town|village|hamlet|road|street|highway)\b/i.test(haystack);
  return countyOnlyContext && !hasPreciseAddress;
}

function filterGridlyGenericLocalQualityResults(results = [], options = {}) {
  const intent = options.intent || classifyGridlyDestinationSearchIntent(options.query || ensureGridlySearchState().activeQuery || "");
  const diagnostics = options.diagnostics && typeof options.diagnostics === "object" ? options.diagnostics : null;
  if (!Array.isArray(results) || !results.length || intent.type !== GRIDLY_DESTINATION_INTENTS.GENERIC_LOCAL) {
    if (diagnostics) {
      diagnostics.suppressedFarAwayCount = Number(diagnostics.suppressedFarAwayCount) || 0;
      diagnostics.visibleQualityFiltered = Boolean(diagnostics.visibleQualityFiltered);
      diagnostics.localQualityResultCount = Number(diagnostics.localQualityResultCount) || 0;
      diagnostics.genericLocalProviderFillerSuppressed = Boolean(diagnostics.genericLocalProviderFillerSuppressed);
    }
    return results;
  }

  const localQualityResultCount = results.filter((result) => isGridlyLocalQualitySearchResult(result)).length;
  const localSeedTitles = new Set(results
    .filter((result) => result.provider === "local_poi_seed" || result.localPoiSeed)
    .map((result) => normalizeGridlySearchDisplayLabel(buildGridlySearchDisplayLines(result).title))
    .filter(Boolean));

  let suppressedFarAwayCount = 0;
  const filtered = localQualityResultCount > 0
    ? results.filter((result) => {
        const rank = result.searchRank && typeof result.searchRank === "object" ? result.searchRank : {};
        const anchorDistanceMiles = Number(rank.anchorDistanceMiles);
        const providerResult = result.provider !== "local_poi_seed" && !result.localPoiSeed;
        const farAwayProvider = providerResult
          && !rank.inBounds
          && !rank.isLibertyCounty
          && !rank.isLocality
          && !rank.isTexas
          && (!Number.isFinite(anchorDistanceMiles) || anchorDistanceMiles > 150);
        const countyOnlyProviderDuplicate = isGridlyCountyOnlyProviderDuplicate(result, localSeedTitles);
        if (farAwayProvider || countyOnlyProviderDuplicate) {
          suppressedFarAwayCount += 1;
          return false;
        }
        return true;
      })
    : results;

  if (diagnostics) {
    diagnostics.suppressedFarAwayCount = suppressedFarAwayCount;
    diagnostics.visibleQualityFiltered = suppressedFarAwayCount > 0 && filtered.length < results.length;
    diagnostics.localQualityResultCount = localQualityResultCount;
    diagnostics.genericLocalProviderFillerSuppressed = suppressedFarAwayCount > 0;
  }
  return filtered;
}

function clearGridlySearchResults(options = {}) {
  const state = ensureGridlySearchState();
  const resultsContainer = gridlySearchUiRefs.results || document.getElementById("gridlySearchResults");
  if (resultsContainer) resultsContainer.textContent = "";
  gridlySearchUiState.lastRenderedResults = [];
  gridlySearchUiState.lastResultShapePreview = [];
  if (options?.clearActiveResult === true) state.activeResult = null;
  if (options?.clearSelectedDestination === true) {
    state.selectedDestination = null;
    clearGridlyDestinationRoutePreview({ silent: true });
  }
  if (options?.clearDestinationMarker === true) clearGridlyDestinationMarker({ silent: true });
  return true;
}

function getGridlySearchActiveInputQuery() {
  const input = gridlySearchUiRefs.input || document.getElementById("gridlyAddressSearchInput");
  return String(input?.value || ensureGridlySearchState().activeQuery || "").trim();
}

function isGridlyLiveSearchRenderCurrent(options = {}) {
  const requestId = Number(options.requestId);
  if (Number.isFinite(requestId) && requestId !== gridlySearchUiState.activeSearchRequestId) return false;
  const renderQuery = String(options.query || "").trim();
  if (!renderQuery) return true;
  return normalizeGridlySearchDisplayLabel(renderQuery) === normalizeGridlySearchDisplayLabel(getGridlySearchActiveInputQuery());
}

function renderGridlySearchResults(results = [], options = {}) {
  if (!isGridlyLiveSearchRenderCurrent(options)) return false;
  const resultsContainer = gridlySearchUiRefs.results || document.getElementById("gridlySearchResults");
  if (!resultsContainer) return false;
  resultsContainer.textContent = "";

  if (options?.state === "searching") {
    const status = document.createElement("div");
    status.className = "gridly-search-results-status";
    status.textContent = "Searching nearby places…";
    resultsContainer.appendChild(status);
    return true;
  }

  if (options?.state === "error") {
    const status = document.createElement("div");
    status.className = "gridly-search-results-status";
    status.textContent = "Search is unavailable right now.";
    resultsContainer.appendChild(status);
    return true;
  }

  const normalizedResults = Array.isArray(results)
    ? results.map((result) => normalizeGridlySearchResult(result)).filter(Boolean)
    : [];
  if (normalizedResults.length && !gridlySearchUiState.debugWarningsSeen.has("normalized-results-preview")) {
    const preview = normalizedResults.slice(0, 3).map((result) => {
      const display = buildGridlySearchDisplayLines(result);
      return {
        title: display.title,
        lat: Number.isFinite(result?.lat) ? Number(result.lat.toFixed(6)) : null,
        lng: Number.isFinite(result?.lng) ? Number(result.lng.toFixed(6)) : null,
        selectable: Boolean(Number.isFinite(result?.lat) && Number.isFinite(result?.lng))
      };
    });
    console.info("Gridly search normalized preview", preview);
    gridlySearchUiState.debugWarningsSeen.add("normalized-results-preview");
  }
  const prioritizedResults = prioritizeGridlySearchResults(normalizedResults, { query: options?.query || ensureGridlySearchState().activeQuery || "" });
  const renderedResults = dedupeGridlySearchResults(prioritizedResults);
  gridlySearchUiState.lastRenderedResults = renderedResults;
  gridlySearchUiState.lastRenderedResultsPreview = renderedResults.map((result) => summarizeGridlyDestinationSearchResult(result)).filter(Boolean);

  if (!renderedResults.length) {
    if (options?.state === "done" && options?.allowEmptyMessage === true) {
      const status = document.createElement("div");
      status.className = "gridly-search-results-status";
      status.textContent = "No matching places found.";
      resultsContainer.appendChild(status);
    }
    return true;
  }

  const list = document.createElement("div");
  list.className = "gridly-search-results-list";
  const preview = [];
  renderedResults.forEach((result, index) => {
    const itemBtn = document.createElement("button");
    itemBtn.type = "button";
    itemBtn.className = "gridly-search-result-item";
    itemBtn.dataset.resultIndex = String(index);

    const display = buildGridlySearchDisplayLines(result);
    const locationContext = buildGridlyLocationContext(result);
    const label = document.createElement("span");
    label.className = "gridly-search-result-title";
    label.textContent = display.title;
    itemBtn.appendChild(label);

    const secondaryLine = [locationContext, display.meta]
      .map((entry) => String(entry || "").trim())
      .find((entry) => isGridlyUsefulMetaValue(entry));
    preview.push({
      title: display.title,
      context: secondaryLine || "",
      lat: Number.isFinite(result?.lat) ? Number(result.lat.toFixed(6)) : null,
      lng: Number.isFinite(result?.lng) ? Number(result.lng.toFixed(6)) : null,
      selectable: Boolean(Number.isFinite(result?.lat) && Number.isFinite(result?.lng))
    });
    if (secondaryLine) {
      const meta = document.createElement("span");
      meta.className = "gridly-search-result-meta";
      meta.textContent = secondaryLine;
      itemBtn.appendChild(meta);
    }

    itemBtn.addEventListener("click", () => {
      const resolvedIndex = Number.parseInt(itemBtn.dataset.resultIndex || "", 10);
      const picked = Number.isInteger(resolvedIndex) ? gridlySearchUiState.lastRenderedResults[resolvedIndex] : null;
      if (!picked) {
        if (!gridlySearchUiState.debugWarningsSeen.has("selection-missing-result")) {
          console.warn("Gridly selection skipped: missing rendered result.", { resolvedIndex });
          gridlySearchUiState.debugWarningsSeen.add("selection-missing-result");
        }
        return;
      }
      if (!Number.isFinite(picked?.lat) || !Number.isFinite(picked?.lng)) {
        if (!gridlySearchUiState.debugWarningsSeen.has("selection-invalid-coordinates")) {
          console.warn("Gridly selection skipped: invalid coordinates.", { resolvedIndex });
          gridlySearchUiState.debugWarningsSeen.add("selection-invalid-coordinates");
        }
        return;
      }
      selectGridlySearchResult(picked);
    });
    list.appendChild(itemBtn);
  });
  gridlySearchUiState.lastRenderedResultsPreview = preview.slice(0, 3);
  gridlySearchUiState.lastResultShapePreview = renderedResults.slice(0, 3).map((result) => buildGridlyResultShapePreviewItem(result));

  resultsContainer.appendChild(list);
  return true;
}

function collapseGridlySearchResults() {
  const resultsContainer = gridlySearchUiRefs.results || document.getElementById("gridlySearchResults");
  if (resultsContainer) resultsContainer.textContent = "";
  gridlySearchUiState.lastRenderedResults = [];
  gridlySearchUiState.lastRenderedResultsPreview = [];
  gridlySearchUiState.lastResultShapePreview = [];
  gridlySearchUiState.isSearching = false;
}


function getSelectedDestinationLabel() {
  const state = ensureGridlySearchState();
  const normalized = normalizeGridlySearchResult(state?.selectedDestination);
  if (!normalized) return "";
  return normalized.title || normalized.displayName || normalized.context || normalized.address || "";
}

const GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE = {
  viewportAdjusted: false,
  bottomInsetApplied: false,
  destinationCardDetected: false,
  lastAppliedKey: "",
  lastReason: "not_applied",
  destinationLat: null,
  destinationLng: null
};

function isGridlyElementVisible(element) {
  if (!element || typeof window === "undefined") return false;
  const style = window.getComputedStyle(element);
  if (!style || style.display === "none" || style.visibility === "hidden" || Number(style.opacity || "1") <= 0) return false;
  const rect = typeof element.getBoundingClientRect === "function" ? element.getBoundingClientRect() : null;
  return Boolean(rect && rect.width > 0 && rect.height > 0);
}

function getGridlyDestinationVisibilityLayout(mapInstance = getGridlyMapInstance()) {
  const mapContainer = typeof mapInstance?.getContainer === "function" ? mapInstance.getContainer() : document.getElementById("map");
  const mapRect = typeof mapContainer?.getBoundingClientRect === "function" ? mapContainer.getBoundingClientRect() : null;
  const destinationCard = document.getElementById("mobileDestinationCommandTitle")?.closest?.(".mobile-destination-command")
    || document.querySelector(".mobile-destination-command");
  const bottomNav = document.querySelector(".mobile-bottom-nav");
  const destinationCardDetected = isGridlyElementVisible(destinationCard);
  const bottomNavDetected = isGridlyElementVisible(bottomNav);
  const cardRect = destinationCardDetected ? destinationCard.getBoundingClientRect() : null;
  const navRect = bottomNavDetected ? bottomNav.getBoundingClientRect() : null;
  const viewportHeight = Number(window.visualViewport?.height || window.innerHeight || 0);
  const viewportOffsetTop = Number(window.visualViewport?.offsetTop || 0);
  const safeAreaInset = Math.max(0, Math.round(Number(window.innerHeight || 0) - viewportHeight - viewportOffsetTop));

  if (!mapRect || !mapRect.width || !mapRect.height) {
    return {
      mapRect: null,
      destinationCardDetected,
      bottomNavDetected,
      bottomInsetApplied: false,
      bottomInsetPx: 0,
      safeAreaInset
    };
  }

  let obstructionTop = mapRect.bottom;
  if (cardRect && cardRect.bottom > mapRect.top && cardRect.top < mapRect.bottom) obstructionTop = Math.min(obstructionTop, cardRect.top);
  if (navRect && navRect.bottom > mapRect.top && navRect.top < mapRect.bottom) obstructionTop = Math.min(obstructionTop, navRect.top);
  const stackedOverlayHeight = Math.max(0, mapRect.bottom - obstructionTop);
  const cappedInset = Math.min(Math.max(stackedOverlayHeight + safeAreaInset + 28, 0), Math.max(96, mapRect.height * 0.46));

  return {
    mapRect,
    destinationCardDetected,
    bottomNavDetected,
    bottomInsetApplied: cappedInset > 0,
    bottomInsetPx: Math.round(cappedInset),
    safeAreaInset
  };
}

function isGridlyDestinationVisibilityCardPresent() {
  return Boolean(getGridlyDestinationVisibilityLayout().destinationCardDetected);
}

function applyGridlyDestinationVisibilityOffset(destinationInput, options = {}) {
  const destination = normalizeGridlySearchResult(destinationInput) || normalizeCoordinatePair(destinationInput?.lat, destinationInput?.lng);
  const coordinates = normalizeCoordinatePair(destination?.lat, destination?.lng);
  const preview = getGridlyDestinationRoutePreviewState();
  const mapInstance = getGridlyMapInstance();
  const layout = getGridlyDestinationVisibilityLayout(mapInstance);
  const routePreviewActive = Boolean(preview.active);
  const destinationSelected = Boolean(normalizeGridlySearchResult(ensureGridlySearchState()?.selectedDestination));

  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.destinationCardDetected = Boolean(layout.destinationCardDetected);
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.bottomInsetApplied = Boolean(layout.bottomInsetApplied && layout.destinationCardDetected);
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.destinationLat = coordinates?.lat ?? null;
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.destinationLng = coordinates?.lng ?? null;

  if (!destinationSelected || !routePreviewActive || !layout.destinationCardDetected || !coordinates || !mapInstance) {
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted = false;
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastReason = !destinationSelected
      ? "destination_not_selected"
      : !routePreviewActive
        ? "route_preview_inactive"
        : !layout.destinationCardDetected
          ? "destination_card_not_detected"
          : !coordinates
            ? "invalid_destination"
            : "map_not_ready";
    return false;
  }

  const requestId = Number(preview.requestId || 0);
  const applyKey = [
    requestId,
    coordinates.lat.toFixed(6),
    coordinates.lng.toFixed(6),
    Math.round(layout.bottomInsetPx || 0),
    options?.reason || "destination_visibility"
  ].join("|");
  if (GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastAppliedKey === applyKey) {
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted = true;
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastReason = "already_adjusted";
    return true;
  }

  const currentZoom = typeof mapInstance.getZoom === "function" ? Number(mapInstance.getZoom()) : null;
  const minFocusZoom = Number.isFinite(options?.minZoom) ? options.minZoom : 12;
  const maxFocusZoom = Number.isFinite(options?.maxZoom) ? options.maxZoom : 14;
  const targetZoom = Number.isFinite(currentZoom)
    ? Math.min(maxFocusZoom, Math.max(currentZoom, minFocusZoom))
    : maxFocusZoom;
  const offsetPx = Math.min(Math.max((layout.bottomInsetPx || 0) / 2, 54), Math.max(72, (layout.mapRect?.height || 0) * 0.24));

  try {
    if (typeof mapInstance.project === "function" && typeof mapInstance.unproject === "function" && typeof mapInstance.setView === "function") {
      const destinationPoint = mapInstance.project([coordinates.lat, coordinates.lng], targetZoom);
      const adjustedCenterPoint = destinationPoint.add([0, offsetPx]);
      const adjustedCenter = mapInstance.unproject(adjustedCenterPoint, targetZoom);
      mapInstance.setView(adjustedCenter, targetZoom, { animate: false });
    } else if (typeof mapInstance.setView === "function") {
      mapInstance.setView([coordinates.lat, coordinates.lng], targetZoom, { animate: false });
      if (typeof mapInstance.panBy === "function") mapInstance.panBy([0, offsetPx], { animate: false });
    } else {
      GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted = false;
      GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastReason = "camera_unavailable";
      return false;
    }
  } catch (_error) {
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted = false;
    GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastReason = "camera_adjust_failed";
    return false;
  }

  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted = true;
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.bottomInsetApplied = true;
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastAppliedKey = applyKey;
  GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.lastReason = options?.reason || "destination_visibility_offset_applied";
  setGridlyMarkerDiagnostics({
    lastMapFocusSuccess: true,
    lastMapFocusLat: coordinates.lat,
    lastMapFocusLng: coordinates.lng,
    lastMapFocusZoom: targetZoom,
    destinationVisibilityOffsetApplied: true,
    destinationVisibilityBottomInsetPx: layout.bottomInsetPx
  });
  return true;
}

window.gridlyDestinationVisibilityAudit = function gridlyDestinationVisibilityAudit() {
  const state = ensureGridlySearchState();
  const destination = normalizeGridlySearchResult(state?.selectedDestination);
  const preview = getGridlyDestinationRoutePreviewState();
  const layout = getGridlyDestinationVisibilityLayout();
  return {
    destinationSelected: Boolean(destination),
    routePreviewActive: Boolean(preview.active),
    viewportAdjusted: Boolean(GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.viewportAdjusted),
    bottomInsetApplied: Boolean(GRIDLY_DESTINATION_VISIBILITY_OFFSET_STATE.bottomInsetApplied || (layout.bottomInsetApplied && layout.destinationCardDetected)),
    destinationCardDetected: Boolean(layout.destinationCardDetected),
    destinationLat: Number.isFinite(Number(destination?.lat)) ? Number(destination.lat) : null,
    destinationLng: Number.isFinite(Number(destination?.lng)) ? Number(destination.lng) : null
  };
};

function getGridlyDestinationRoutePreviewState() {
  const existingState = window.GridlyDestinationRoutePreview;
  const nextState = {
    active: false,
    status: "idle",
    requestId: 0,
    routeLayer: null,
    source: null,
    destination: null,
    distanceMeters: null,
    distanceMiles: null,
    etaMinutes: null,
    durationSeconds: null,
    geometry: [],
    routeProvider: "osrm",
    error: ""
  };
  if (existingState && typeof existingState === "object") {
    Object.keys(nextState).forEach((key) => {
      if (Object.hasOwn(existingState, key)) nextState[key] = existingState[key];
    });
  }
  window.GridlyDestinationRoutePreview = nextState;
  return window.GridlyDestinationRoutePreview;
}

function formatGridlyDestinationPreviewDistance(miles) {
  const value = Number(miles);
  if (!Number.isFinite(value) || value <= 0) return "";
  return value >= 10 ? `${value.toFixed(1)} mi` : `${Math.max(0.1, value).toFixed(1)} mi`;
}

function formatGridlyDestinationPreviewEta(minutes) {
  const value = Number(minutes);
  if (!Number.isFinite(value) || value <= 0) return "";
  return `${Math.max(1, Math.round(value))} min`;
}

function getGridlyDestinationPreviewMetaText() {
  const preview = getGridlyDestinationRoutePreviewState();
  if (preview.status === "loading") return "Calculating route…";
  if (preview.status === "unavailable") return "Route unavailable";
  if (preview.status === "ready") {
    const distanceText = formatGridlyDestinationPreviewDistance(preview.distanceMiles);
    const etaText = formatGridlyDestinationPreviewEta(preview.etaMinutes);
    if (distanceText && etaText) return `${distanceText} • ${etaText}`;
    if (distanceText) return distanceText;
    if (etaText) return etaText;
    return "Route unavailable";
  }
  return "";
}

const GRIDLY_DESTINATION_ROUTE_IMPACT_LABELS = {
  none: "None",
  low: "Low",
  moderate: "Moderate",
  high: "High"
};

function getGridlyDestinationRouteImpactLabel(level = "none") {
  return GRIDLY_DESTINATION_ROUTE_IMPACT_LABELS[String(level || "none").toLowerCase()] || GRIDLY_DESTINATION_ROUTE_IMPACT_LABELS.none;
}

function getGridlyDestinationRouteImpactCopy(level = "none") {
  const normalizedLevel = String(level || "none").toLowerCase();
  if (normalizedLevel === "high") return "Train blocking crossing near your route";
  if (normalizedLevel === "moderate") return "Road closure reported nearby";
  if (normalizedLevel === "low") return "Construction activity reported nearby";
  return "No active hazards reported nearby";
}

function getGridlyDestinationRouteImpactCardText() {
  const preview = window.GridlyDestinationRoutePreview && typeof window.GridlyDestinationRoutePreview === "object"
    ? window.GridlyDestinationRoutePreview
    : {};
  if (preview.status === "loading") return "";
  if (preview.status !== "ready") return "";
  try {
    const audit = typeof window.gridlyDestinationRouteImpactAudit === "function"
      ? window.gridlyDestinationRouteImpactAudit()
      : null;
    const impactLevel = audit?.impactLevel || "none";
    const reason = audit?.primaryImpactReason || getGridlyDestinationRouteImpactCopy(impactLevel);
    const locationLine = String(audit?.primaryImpactLocation || "").trim();
    const proximityLine = String(audit?.primaryImpactProximityLabel || "").trim();
    return normalizeGridlyUserFacingRoadText([
      `Potential Impact: ${getGridlyDestinationRouteImpactLabel(impactLevel)}`,
      reason,
      locationLine,
      proximityLine
    ].filter((line) => String(line || "").trim()).join("\n"));
  } catch (_) {
    return "";
  }
}

function getGridlyDestinationRouteReasonInspectionText(item = {}) {
  return [
    item?.type,
    item?.category,
    item?.title,
    item?.severity,
    item?.status,
    item?.sourceType,
    item?.impactText
  ].map((value) => String(value || "").toLowerCase()).join(" ");
}

function isGridlyDestinationRouteActiveRailReason(item = {}) {
  const text = getGridlyDestinationRouteReasonInspectionText(item);
  const railRelated = /rail|train|crossing/.test(text);
  if (!railRelated) return false;
  return /rail[_\s-]*(blockage|delay|issue)|blocked[_\s-]*crossing|train[_\s-]*(blocking|blocked|stopped|delay)|\b(blocked|blocking|active|issue|problem|delay|stopped)\b/.test(text);
}

function getGridlyDestinationRouteActiveRailReasonCopy(matches = []) {
  const text = (Array.isArray(matches) ? matches : [])
    .map((item) => getGridlyDestinationRouteReasonInspectionText(item))
    .join(" ");
  if (/train[_\s-]*(blocking|blocked|stopped)|\b(blocked|blocking)\b/.test(text)) return "Train blocking crossing near your route";
  if (/rail[_\s-]*(blockage|delay)|blocked[_\s-]*crossing/.test(text)) return "Blocked rail crossing reported nearby";
  return "Rail issue reported nearby";
}

const GRIDLY_DESTINATION_IMPACT_PANE_STATE = {
  paneOpen: false,
  impactLevel: "none",
  displayedReasons: []
};

function pluralizeGridlyDestinationImpactReason(count, singular, plural = `${singular}s`) {
  const value = Math.max(0, Number(count) || 0);
  return `${value} ${value === 1 ? singular : plural}`;
}

function getGridlyDestinationImpactPaneElements() {
  return {
    pane: document.getElementById("gridlyDestinationImpactPane"),
    backdrop: document.getElementById("gridlyDestinationImpactPaneBackdrop"),
    close: document.getElementById("gridlyDestinationImpactPaneClose"),
    done: document.getElementById("gridlyDestinationImpactPaneDone"),
    summary: document.getElementById("gridlyDestinationImpactPaneSummary"),
    reasons: document.getElementById("gridlyDestinationImpactPaneReasons"),
    quietNote: document.getElementById("gridlyDestinationImpactPaneQuietNote"),
    why: document.getElementById("gridlyDestinationImpactPaneWhy"),
    severity: document.getElementById("gridlyDestinationImpactPaneSeverity"),
    confidence: document.getElementById("gridlyDestinationImpactPaneConfidence"),
    trigger: document.getElementById("mobileDestinationCommandImpact")
  };
}

function getGridlyDestinationImpactPaneReasonModel() {
  const paneModelStartedAt = getGridlyDestinationPerfNow();
  const audit = typeof window.gridlyDestinationRouteImpactAudit === "function"
    ? window.gridlyDestinationRouteImpactAudit()
    : null;
  const intelligence = typeof window.gridlyDestinationRouteIntelligenceAudit === "function"
    ? window.gridlyDestinationRouteIntelligenceAudit()
    : null;
  const routeFound = Boolean(audit?.routeFound);
  const impactLevel = String(audit?.impactLevel || "none").toLowerCase();
  const matchedHazards = routeFound && Array.isArray(intelligence?.matchedHazards) ? intelligence.matchedHazards : [];
  const matchedAlerts = routeFound && Array.isArray(intelligence?.matchedAlerts) ? intelligence.matchedAlerts : [];
  const matchedReports = routeFound && Array.isArray(intelligence?.matchedReports) ? intelligence.matchedReports : [];
  const activeRailMatches = [...matchedHazards, ...matchedAlerts, ...matchedReports]
    .filter((item) => isGridlyDestinationRouteActiveRailReason(item));
  const displayHazards = matchedHazards.filter((item) => !isGridlyDestinationRouteActiveRailReason(item));
  const displayAlerts = matchedAlerts.filter((item) => !isGridlyDestinationRouteActiveRailReason(item));
  const highImpactNearby = displayHazards.some((item) => isGridlyDestinationRouteHighImpactMatch(item))
    || displayAlerts.some((item) => isGridlyDestinationRouteHighImpactMatch(item));
  const hazards = displayHazards.length;
  const alerts = displayAlerts.length;
  const reports = Math.max(0, Number(audit?.reportsConsidered || 0));
  const activeRail = activeRailMatches.length;
  const reasons = [];

  if (activeRail > 0) {
    reasons.push(getGridlyDestinationRouteActiveRailReasonCopy(activeRailMatches));
  }

  if (highImpactNearby) {
    reasons.push("Road closure reported nearby");
  } else if (hazards > 0) {
    reasons.push(`${pluralizeGridlyDestinationImpactReason(hazards, "active hazard")} reported near your route`);
  }

  if (alerts > 0) {
    reasons.push(`${pluralizeGridlyDestinationImpactReason(alerts, "hazard report")} nearby`);
  }

  if (reports > 0) {
    reasons.push(`${pluralizeGridlyDestinationImpactReason(reports, "community report")} nearby`);
  }

  const primaryImpactLocation = String(audit?.primaryImpactLocation || "").trim();
  const primaryImpactProximityLabel = String(audit?.primaryImpactProximityLabel || "").trim();

  const quiet = !routeFound || (hazards === 0 && alerts === 0 && reports === 0 && activeRail === 0);
  const detailReasons = quiet ? [] : [
    primaryImpactLocation,
    primaryImpactProximityLabel,
    ...reasons
  ].filter((line) => String(line || "").trim());

  const impactLabel = audit?.impactLabel || getGridlyDestinationRouteImpactLabel(impactLevel);
  const confidenceLabel = audit?.confidenceLabel || getGridlyDestinationRouteConfidenceLabel({
    routeFound,
    impactLevel,
    hazardsConsidered: hazards,
    alertsConsidered: alerts,
    reportsConsidered: reports
  });

  const model = {
    impactLevel,
    impactLabel,
    confidenceLabel,
    summary: normalizeGridlyUserFacingRoadText(routeFound ? (audit?.primaryImpactReason || getGridlyDestinationRouteImpactCopy(impactLevel)) : "No active hazards reported nearby"),
    primaryImpactLocation: normalizeGridlyUserFacingRoadText(primaryImpactLocation),
    primaryImpactProximityLabel: normalizeGridlyUserFacingRoadText(primaryImpactProximityLabel),
    reasons: detailReasons.slice(0, 6).map((reason) => normalizeGridlyUserFacingRoadText(reason)),
    quiet
  };
  setGridlyDestinationPerformanceTiming("routeAwarenessPaneModelMs", getGridlyDestinationPerfNow() - paneModelStartedAt);
  return model;
}

function renderGridlyDestinationImpactPane() {
  const paneEls = getGridlyDestinationImpactPaneElements();
  const model = getGridlyDestinationImpactPaneReasonModel();
  GRIDLY_DESTINATION_IMPACT_PANE_STATE.impactLevel = model.impactLevel;
  GRIDLY_DESTINATION_IMPACT_PANE_STATE.displayedReasons = [...model.reasons];

  if (paneEls.severity) paneEls.severity.textContent = normalizeGridlyUserFacingRoadText(model.impactLabel || getGridlyDestinationRouteImpactLabel(model.impactLevel));
  if (paneEls.confidence) paneEls.confidence.textContent = normalizeGridlyUserFacingRoadText(model.confidenceLabel || "Low confidence");
  if (paneEls.summary) paneEls.summary.textContent = normalizeGridlyUserFacingRoadText(model.summary || "No active hazards reported nearby");
  if (paneEls.reasons) {
    paneEls.reasons.innerHTML = "";
    model.reasons.forEach((reason) => {
      const item = document.createElement("li");
      item.textContent = normalizeGridlyUserFacingRoadText(reason);
      paneEls.reasons.appendChild(item);
    });
  }
  if (paneEls.quietNote) paneEls.quietNote.hidden = !model.quiet;
  if (paneEls.why) paneEls.why.hidden = Boolean(model.quiet);
  if (paneEls.reasons) paneEls.reasons.hidden = Boolean(model.quiet);
  return model;
}

function openGridlyDestinationImpactPane() {
  const paneEls = getGridlyDestinationImpactPaneElements();
  if (!paneEls.pane) return false;
  renderGridlyDestinationImpactPane();
  paneEls.pane.hidden = false;
  paneEls.pane.setAttribute("aria-hidden", "false");
  paneEls.trigger?.setAttribute("aria-expanded", "true");
  GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen = true;
  requestAnimationFrame(() => paneEls.close?.focus?.());
  return true;
}

function closeGridlyDestinationImpactPane() {
  const paneEls = getGridlyDestinationImpactPaneElements();
  if (!paneEls.pane) return false;
  paneEls.pane.hidden = true;
  paneEls.pane.setAttribute("aria-hidden", "true");
  paneEls.trigger?.setAttribute("aria-expanded", "false");
  GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen = false;
  paneEls.trigger?.focus?.();
  return true;
}

function bindGridlyDestinationImpactPane() {
  const paneEls = getGridlyDestinationImpactPaneElements();
  if (paneEls.trigger && paneEls.trigger.dataset.impactPaneBound !== "true") {
    paneEls.trigger.dataset.impactPaneBound = "true";
    paneEls.trigger.addEventListener("click", () => {
      if (!String(paneEls.trigger.textContent || "").trim()) return;
      openGridlyDestinationImpactPane();
    });
    paneEls.trigger.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") return;
      if (!String(paneEls.trigger.textContent || "").trim()) return;
      event.preventDefault();
      openGridlyDestinationImpactPane();
    });
  }
  [paneEls.backdrop, paneEls.close, paneEls.done].forEach((node) => {
    if (!node || node.dataset.impactPaneBound === "true") return;
    node.dataset.impactPaneBound = "true";
    node.addEventListener("click", closeGridlyDestinationImpactPane);
  });
  if (paneEls.pane && paneEls.pane.dataset.escapeBound !== "true") {
    paneEls.pane.dataset.escapeBound = "true";
    paneEls.pane.addEventListener("keydown", (event) => {
      if (event.key === "Escape") closeGridlyDestinationImpactPane();
    });
  }
}

function isGridlyDestinationImpactLineVisible(node) {
  if (!node || !String(node.textContent || "").trim()) return false;
  const style = window.getComputedStyle ? window.getComputedStyle(node) : null;
  if (style) {
    const hiddenByStyle = style.display === "none"
      || style.visibility === "hidden"
      || Number(style.opacity || 1) <= 0;
    if (hiddenByStyle) return false;
  }

  const rect = typeof node.getBoundingClientRect === "function" ? node.getBoundingClientRect() : null;
  if (!rect || rect.width <= 0 || rect.height <= 0) return false;
  const viewportWidth = window.innerWidth || document.documentElement?.clientWidth || 0;
  const viewportHeight = window.innerHeight || document.documentElement?.clientHeight || 0;
  if (viewportWidth <= 0 || viewportHeight <= 0) return true;

  let visibleLeft = Math.max(rect.left, 0);
  let visibleTop = Math.max(rect.top, 0);
  let visibleRight = Math.min(rect.right, viewportWidth);
  let visibleBottom = Math.min(rect.bottom, viewportHeight);
  for (let ancestor = node.parentElement; ancestor && ancestor !== document.body; ancestor = ancestor.parentElement) {
    const ancestorStyle = window.getComputedStyle ? window.getComputedStyle(ancestor) : null;
    const clipsOverflow = ancestorStyle && /(hidden|clip|auto|scroll)/.test(`${ancestorStyle.overflow} ${ancestorStyle.overflowX} ${ancestorStyle.overflowY}`);
    if (!clipsOverflow || typeof ancestor.getBoundingClientRect !== "function") continue;
    const ancestorRect = ancestor.getBoundingClientRect();
    visibleLeft = Math.max(visibleLeft, ancestorRect.left);
    visibleTop = Math.max(visibleTop, ancestorRect.top);
    visibleRight = Math.min(visibleRight, ancestorRect.right);
    visibleBottom = Math.min(visibleBottom, ancestorRect.bottom);
  }
  if (visibleRight - visibleLeft <= 1 || visibleBottom - visibleTop <= 1) return false;

  if (typeof document.elementFromPoint !== "function") return true;
  const paneEls = getGridlyDestinationImpactPaneElements();
  const samples = [
    [visibleLeft + ((visibleRight - visibleLeft) / 2), visibleTop + ((visibleBottom - visibleTop) / 2)],
    [visibleLeft + 2, visibleTop + 2],
    [visibleRight - 2, visibleTop + 2],
    [visibleLeft + 2, visibleBottom - 2],
    [visibleRight - 2, visibleBottom - 2]
  ];
  return samples.some(([x, y]) => {
    const sampleX = Math.min(Math.max(x, 0), Math.max(viewportWidth - 1, 0));
    const sampleY = Math.min(Math.max(y, 0), Math.max(viewportHeight - 1, 0));
    const sampledNode = document.elementFromPoint(sampleX, sampleY);
    if (!sampledNode) return false;
    if (sampledNode === node || Boolean(node.contains(sampledNode))) return true;
    if (GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen && (paneEls.pane === sampledNode || paneEls.pane?.contains(sampledNode))) return true;
    return false;
  });
}

window.gridlyDestinationImpactPaneAudit = function gridlyDestinationImpactPaneAudit() {
  const paneEls = getGridlyDestinationImpactPaneElements();
  if (paneEls.pane && !GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen) {
    renderGridlyDestinationImpactPane();
  }
  const impactLineText = String(paneEls.trigger?.textContent || "").trim();
  const routeAudit = typeof window.gridlyDestinationRouteImpactAudit === "function"
    ? window.gridlyDestinationRouteImpactAudit()
    : null;
  const paneAvailable = Boolean(paneEls.pane);
  return {
    available: paneAvailable,
    paneAvailable,
    paneOpen: Boolean(GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen),
    impactLineVisible: isGridlyDestinationImpactLineVisible(paneEls.trigger),
    impactLineText,
    impactLevel: String(GRIDLY_DESTINATION_IMPACT_PANE_STATE.impactLevel || ""),
    impactLabel: getGridlyDestinationRouteImpactLabel(GRIDLY_DESTINATION_IMPACT_PANE_STATE.impactLevel || "none"),
    displayedReasonCount: GRIDLY_DESTINATION_IMPACT_PANE_STATE.displayedReasons.length,
    displayedReasons: [...GRIDLY_DESTINATION_IMPACT_PANE_STATE.displayedReasons],
    primaryImpactProximityLabel: String(routeAudit?.primaryImpactProximityLabel || ""),
    selectedImpactSourceDistanceFeet: routeAudit?.selectedImpactSourceDistanceFeet ?? null,
    selectedImpactRoutePointIndex: routeAudit?.selectedImpactRoutePointIndex ?? null,
    selectedImpactRouteProgressRatio: routeAudit?.selectedImpactRouteProgressRatio ?? null,
    selectedImpactDistanceFromStartMiles: routeAudit?.selectedImpactDistanceFromStartMiles ?? null,
    selectedImpactDistanceToDestinationMiles: routeAudit?.selectedImpactDistanceToDestinationMiles ?? null,
    primaryImpactProximityEmptyReason: String(routeAudit?.primaryImpactProximityEmptyReason || "")
  };
};

function getGridlyMobileAwarenessPanelSummary() {
  const summary = typeof buildGridlyCommunityAwarenessIntelligenceSummary === "function"
    ? buildGridlyCommunityAwarenessIntelligenceSummary()
    : {};
  const areaName = safeDisplayText(summary.awarenessAreaName, "Liberty County");
  const crossingsCount = Array.isArray(summary.crossingsInArea) ? summary.crossingsInArea.length : Number(summary.crossingsInArea || 0);
  const hazardCount = Array.isArray(summary.activeHazardsInArea) ? summary.activeHazardsInArea.length : Number(summary.activeHazardsInArea || 0);
  const reportCount = Array.isArray(summary.activeReportsInArea) ? summary.activeReportsInArea.length : Number(summary.activeReportsInArea || 0);
  const activeIssueCount = hazardCount + reportCount;
  const selectedArea = summary.selectedAwarenessArea || {};
  const countyMode = Boolean(selectedArea.countyWide || selectedArea.fallback || normalizeGridlyAwarenessAreaLookupText(areaName) === "liberty county");
  const quietStatus = countyMode ? "No active countywide issues reported" : "No active local issues reported";
  const activeStatus = hazardCount > 0
    ? "Active hazards reported nearby"
    : "Active reports posted nearby";
  return {
    ...summary,
    areaName,
    panelTitle: `${areaName} Awareness`,
    status: activeIssueCount > 0 ? activeStatus : quietStatus,
    crossingsLine: `${crossingsCount} crossing${crossingsCount === 1 ? "" : "s"} watched · ${hazardCount} hazard${hazardCount === 1 ? "" : "s"} · ${reportCount} report${reportCount === 1 ? "" : "s"}`,
    activeIssueCount,
    activeIssuesLine: ""
  };
}

function isGridlyAwarenessPanelModeActive() {
  const routeIsMonitoring = Boolean(routeWatchActivated || window.__gridlyRouteWatchActive);
  return !routeIsMonitoring && !getSelectedDestinationLabel();
}

let gridlyAwarenessAreaImmediateSyncState = {
  lastReason: "",
  lastSyncedAt: null,
  awarenessAreaName: "",
  panelSynced: false,
  communityPulseSynced: false
};

function syncGridlyAwarenessAreaSurfacesImmediately(reason = "awareness-area-change", options = {}) {
  const syncStartedAt = typeof performance !== "undefined" && typeof performance.now === "function" ? performance.now() : Date.now();
  const summary = typeof buildGridlyCommunityAwarenessIntelligenceSummary === "function"
    ? buildGridlyCommunityAwarenessIntelligenceSummary(options?.summaryOptions || {})
    : null;
  const awarenessAreaName = safeDisplayText(summary?.awarenessAreaName, "Liberty County");

  if (typeof syncMobileDestinationCommandCard === "function") {
    syncMobileDestinationCommandCard();
  }

  const communityPulseState = typeof renderGridlyCommunityPulse === "function"
    ? renderGridlyCommunityPulse({ ...(options?.pulseOptions || {}), reason })
    : null;

  if (typeof refreshPortraitV2LocalizedIntelligence === "function" && options?.refreshPortrait !== false) {
    refreshPortraitV2LocalizedIntelligence();
  }
  if (typeof renderUnifiedIncidents === "function" && options?.refreshMapMarkers !== false) {
    renderUnifiedIncidents(`awareness-area-sync:${reason}`);
  }

  gridlyAwarenessAreaImmediateSyncState = {
    lastReason: reason,
    lastSyncedAt: new Date().toISOString(),
    awarenessAreaName,
    panelSynced: true,
    communityPulseSynced: Boolean(communityPulseState),
    durationMs: Number((((typeof performance !== "undefined" && typeof performance.now === "function") ? performance.now() : Date.now()) - syncStartedAt).toFixed(2)),
    crossingsInArea: Array.isArray(summary?.crossingsInArea) ? summary.crossingsInArea.length : 0,
    activeHazardsInArea: Array.isArray(summary?.activeHazardsInArea) ? summary.activeHazardsInArea.length : 0,
    activeReportsInArea: Array.isArray(summary?.activeReportsInArea) ? summary.activeReportsInArea.length : 0,
    pulseVisible: Boolean(communityPulseState?.pulseVisible)
  };

  if (typeof recordGridlyActiveLocationLifecycleEvent === "function") {
    recordGridlyActiveLocationLifecycleEvent("syncGridlyAwarenessAreaSurfacesImmediately", {
      reason,
      awarenessAreaName,
      panelSynced: true,
      communityPulseSynced: Boolean(communityPulseState),
      durationMs: gridlyAwarenessAreaImmediateSyncState.durationMs
    });
  }

  return {
    summary,
    communityPulseState,
    syncState: { ...gridlyAwarenessAreaImmediateSyncState }
  };
}

window.gridlyAwarenessAreaImmediateSyncDebug = function gridlyAwarenessAreaImmediateSyncDebug() {
  return { ...gridlyAwarenessAreaImmediateSyncState };
};

function syncMobileDestinationCommandCard() {
  const cardRenderStartedAt = getGridlyDestinationPerfNow();
  const routeIsMonitoring = Boolean(routeWatchActivated || window.__gridlyRouteWatchActive);
  const selectedLabel = getSelectedDestinationLabel();
  const previewMeta = selectedLabel ? getGridlyDestinationPreviewMetaText() : "";
  const destinationSupportText = selectedLabel
    ? `Destination: ${selectedLabel}${previewMeta ? ` · ${previewMeta}` : " · Route preview loading"}`
    : "";
  const routeImpactText = routeIsMonitoring && selectedLabel ? getGridlyDestinationRouteImpactCardText() : "";
  const routeMonitoringSupportText = routeIsMonitoring
    ? [
        "Route Watch Active",
        destinationSupportText || "Monitoring saved destination",
        routeImpactText
      ].filter((line) => String(line || "").trim()).join("\n")
    : destinationSupportText;
  const awarenessPanelMode = true;
  const card = document.getElementById("mobileDestinationCommandTitle")?.closest?.(".mobile-destination-command");
  card?.classList.toggle("is-awareness-panel", awarenessPanelMode);
  card?.classList.toggle("is-destination-panel", !awarenessPanelMode);
  document.body?.classList.toggle("gridly-mobile-awareness-panel-present", awarenessPanelMode);
  window.__gridlySyncAwarenessPanelDockContract?.();

  if (awarenessPanelMode) {
    const awarenessSummary = getGridlyMobileAwarenessPanelSummary();
    safeText("mobileAwarenessPanelKicker", "Awareness Area");
    safeText("mobileDestinationCommandTitle", awarenessSummary.panelTitle);
    safeText("mobileDestinationCommandMeta", awarenessSummary.status);
    safeText("mobileAwarenessPanelCrossings", awarenessSummary.crossingsLine);
    safeText("mobileAwarenessPanelIssues", "");
    document.getElementById("mobileAwarenessPanelCrossings")?.toggleAttribute("hidden", false);
    document.getElementById("mobileAwarenessPanelIssues")?.toggleAttribute("hidden", true);
    safeText("mobileDestinationCommandImpact", routeMonitoringSupportText);
    safeText("mobileDestinationCommandBtn", selectedLabel ? "Change" : (routeIsMonitoring ? "View Route" : "Route"));
  } else {
    const impactText = selectedLabel ? getGridlyDestinationRouteImpactCardText() : "";
    safeText("mobileAwarenessPanelKicker", "Route");
    safeText("mobileDestinationCommandTitle", selectedLabel || (routeIsMonitoring ? "Destination selected" : "Destination"));
    safeText(
      "mobileDestinationCommandMeta",
      selectedLabel
        ? (previewMeta || "Calculating route…")
        : routeIsMonitoring
          ? "Selected: Saved destination"
          : "Choose where you're going"
    );
    safeText("mobileAwarenessPanelCrossings", "");
    safeText("mobileAwarenessPanelIssues", "");
    document.getElementById("mobileAwarenessPanelCrossings")?.toggleAttribute("hidden", true);
    document.getElementById("mobileAwarenessPanelIssues")?.toggleAttribute("hidden", true);
    safeText("mobileDestinationCommandImpact", impactText);
    safeText("mobileDestinationCommandBtn", selectedLabel ? "Change" : "Choose Route");
  }

  const impactLine = document.getElementById("mobileDestinationCommandImpact");
  if (impactLine) {
    const hasImpactText = Boolean(String(impactLine.textContent || "").trim());
    impactLine.setAttribute("aria-disabled", hasImpactText ? "false" : "true");
    impactLine.title = hasImpactText ? "Open route awareness details" : "";
  }
  if (GRIDLY_DESTINATION_IMPACT_PANE_STATE.paneOpen) renderGridlyDestinationImpactPane();
  setGridlyDestinationPerformanceTiming("renderMs", getGridlyDestinationPerfNow() - cardRenderStartedAt);
}

function clearGridlyDestinationRoutePreview(options = {}) {
  if (options?.preservePerformanceAudit !== true) resetGridlyDestinationPerformanceAudit("idle");
  else invalidateGridlyDestinationRouteIntelligenceCache();
  const preview = getGridlyDestinationRoutePreviewState();
  preview.requestId = Number(preview.requestId || 0) + 1;
  preview.active = false;
  preview.status = "idle";
  preview.source = null;
  preview.destination = null;
  preview.distanceMeters = null;
  preview.distanceMiles = null;
  preview.etaMinutes = null;
  preview.durationSeconds = null;
  preview.geometry = [];
  preview.error = "";
  try {
    destinationRoutePreviewLayer?.clearLayers?.();
  } catch (error) {
    if (options?.silent !== true) console.warn("Failed to clear destination route preview:", error);
  }
  preview.routeLayer = null;
  window.GridlyDestinationRoutePreview = preview;
  if (options?.syncCard !== false) syncMobileDestinationCommandCard();
  return true;
}

function getGridlyDestinationRouteOrigin() {
  const gpsCoords = normalizeCoordinatePair(userLocation?.lat, userLocation?.lng);
  if (gpsCoords) return { ...gpsCoords, label: "Current location", source: "gps" };

  const savedHome = typeof getSavedPlacesState === "function" ? getSavedPlacesState()?.home : null;
  const homeCoords = normalizeCoordinatePair(savedHome?.lat, savedHome?.lng);
  if (homeCoords) return { ...homeCoords, label: savedHome?.label || savedHome?.name || "Home", source: "home" };

  const mapCenter = typeof map?.getCenter === "function" ? map.getCenter() : null;
  const centerCoords = normalizeCoordinatePair(mapCenter?.lat ?? defaultCenter[0], mapCenter?.lng ?? defaultCenter[1]);
  return centerCoords ? { ...centerCoords, label: "Map center", source: "map_center" } : null;
}

function drawGridlyDestinationRoutePreviewLine(latLngs = []) {
  const leaflet = window.L;
  if (!map || !Array.isArray(latLngs) || latLngs.length < 2 || typeof leaflet?.polyline !== "function") return null;
  if (!destinationRoutePreviewLayer && typeof leaflet?.layerGroup === "function") destinationRoutePreviewLayer = leaflet.layerGroup().addTo(map);
  if (!destinationRoutePreviewLayer) return null;
  destinationRoutePreviewLayer.clearLayers();
  const halo = leaflet.polyline(latLngs, {
    pane: "routePane",
    color: "#e8fbff",
    weight: 24,
    opacity: 0.18,
    lineCap: "round",
    lineJoin: "round",
    interactive: false,
    className: "gridly-route-signature-halo gridly-destination-route-hero-halo"
  });
  const shoulder = leaflet.polyline(latLngs, {
    pane: "routePane",
    color: "#0b5f92",
    weight: 15,
    opacity: 0.62,
    lineCap: "round",
    lineJoin: "round",
    interactive: false,
    className: "gridly-route-signature-shoulder gridly-destination-route-hero-shoulder"
  });
  const core = leaflet.polyline(latLngs, {
    pane: "routePane",
    color: "#8ff1ff",
    weight: 8,
    opacity: 0.98,
    lineCap: "round",
    lineJoin: "round",
    interactive: false,
    className: "gridly-route-signature-core gridly-destination-route-hero-core"
  });
  destinationRoutePreviewLayer.addLayer(halo);
  destinationRoutePreviewLayer.addLayer(shoulder);
  destinationRoutePreviewLayer.addLayer(core);
  return destinationRoutePreviewLayer;
}

async function buildGridlyDestinationRoutePreview(options = {}) {
  const state = ensureGridlySearchState();
  const destination = normalizeGridlySearchResult(state?.selectedDestination);
  clearGridlyDestinationRoutePreview({ silent: true, syncCard: false, preservePerformanceAudit: true });
  const flowStartedAt = Number.isFinite(Number(gridlyDestinationPerformanceAuditState.destinationFlowStartedAt))
    ? Number(gridlyDestinationPerformanceAuditState.destinationFlowStartedAt)
    : getGridlyDestinationPerfNow();
  const routePreviewStartedAt = getGridlyDestinationPerfNow();
  gridlyDestinationPerformanceAuditState.routePreviewRequestStartedAt = routePreviewStartedAt;
  gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt = null;
  gridlyDestinationPerformanceAuditState.routePreviewStatus = "preparing";
  gridlyDestinationPerformanceAuditState.lastUpdatedAt = Date.now();
  const preview = getGridlyDestinationRoutePreviewState();
  const requestId = Number(preview.requestId || 0) + 1;
  preview.requestId = requestId;
  preview.destination = destination ? {
    label: destination.title || destination.displayName || destination.address || "Destination",
    lat: destination.lat,
    lng: destination.lng,
    id: destination.id || null
  } : null;

  if (!destination || !Number.isFinite(destination.lat) || !Number.isFinite(destination.lng)) {
    preview.status = destination ? "unavailable" : "idle";
    preview.error = destination ? "invalid_destination" : "";
    window.GridlyDestinationRoutePreview = preview;
    gridlyDestinationPerformanceAuditState.routePreviewStatus = preview.status;
    gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt = getGridlyDestinationPerfNow();
    setGridlyDestinationPerformanceTiming("totalDestinationRouteMs", gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt - flowStartedAt);
    addGridlyDestinationPerformanceNote(preview.error || "destination route preview did not start");
    syncMobileDestinationCommandCard();
    return preview;
  }

  const origin = getGridlyDestinationRouteOrigin();
  if (!origin) {
    preview.status = "unavailable";
    preview.error = "origin_unavailable";
    window.GridlyDestinationRoutePreview = preview;
    gridlyDestinationPerformanceAuditState.routePreviewStatus = preview.status;
    gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt = getGridlyDestinationPerfNow();
    setGridlyDestinationPerformanceTiming("totalDestinationRouteMs", gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt - flowStartedAt);
    addGridlyDestinationPerformanceNote(preview.error || "destination route origin unavailable");
    syncMobileDestinationCommandCard();
    return preview;
  }

  preview.active = true;
  preview.status = "loading";
  gridlyDestinationPerformanceAuditState.routePreviewStatus = "loading";
  preview.source = origin;
  preview.error = "";
  window.GridlyDestinationRoutePreview = preview;
  syncMobileDestinationCommandCard();
  applyGridlyDestinationVisibilityOffset(destination, { reason: "destination-preview-loading" });

  const routeRequestStartedAt = getGridlyDestinationPerfNow();
  const routeData = await fetchRoadRoutePreviewData([origin.lat, origin.lng], [destination.lat, destination.lng], { auditSource: "destination_route_preview" });
  setGridlyDestinationPerformanceTiming("routeRequestMs", getGridlyDestinationPerfNow() - routeRequestStartedAt);
  const latestPreview = getGridlyDestinationRoutePreviewState();
  if (latestPreview.requestId !== requestId) {
    addGridlyDestinationPerformanceNote("stale destination route preview request ignored");
    return latestPreview;
  }

  if (!routeData?.geometry?.length || routeData.geometry.length < 2) {
    destinationRoutePreviewLayer?.clearLayers?.();
    latestPreview.active = true;
    latestPreview.status = "unavailable";
    latestPreview.geometry = [];
    latestPreview.distanceMeters = null;
    latestPreview.distanceMiles = null;
    latestPreview.durationSeconds = null;
    latestPreview.etaMinutes = null;
    latestPreview.error = "route_unavailable";
    latestPreview.routeLayer = null;
    window.GridlyDestinationRoutePreview = latestPreview;
    gridlyDestinationPerformanceAuditState.routePreviewStatus = latestPreview.status;
    gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt = getGridlyDestinationPerfNow();
    setGridlyDestinationPerformanceTiming("totalDestinationRouteMs", gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt - flowStartedAt);
    addGridlyDestinationPerformanceNote(latestPreview.error || "route preview unavailable");
    syncMobileDestinationCommandCard();
    return latestPreview;
  }

  const renderStartedAt = getGridlyDestinationPerfNow();
  const renderedLayer = drawGridlyDestinationRoutePreviewLine(routeData.geometry);
  setGridlyDestinationPerformanceTiming("renderMs", getGridlyDestinationPerfNow() - renderStartedAt);
  latestPreview.active = true;
  latestPreview.status = renderedLayer ? "ready" : "unavailable";
  latestPreview.routeLayer = renderedLayer;
  latestPreview.geometry = routeData.geometry;
  latestPreview.distanceMeters = routeData.distanceMeters;
  latestPreview.distanceMiles = routeData.distanceMiles;
  latestPreview.durationSeconds = routeData.durationSeconds;
  latestPreview.etaMinutes = routeData.etaMinutes;
  latestPreview.routeProvider = routeData.provider || "osrm";
  latestPreview.error = renderedLayer ? "" : "render_unavailable";
  gridlyDestinationPerformanceAuditState.routePreviewStatus = latestPreview.status;
  gridlyDestinationPerformanceAuditState.routeGeometryPointCount = Array.isArray(latestPreview.geometry) ? latestPreview.geometry.length : 0;
  if (!renderedLayer) addGridlyDestinationPerformanceNote(latestPreview.error);
  window.GridlyDestinationRoutePreview = latestPreview;
  if (latestPreview.status === "ready") primeGridlyDestinationRouteImpactCache();
  syncMobileDestinationCommandCard();
  gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt = getGridlyDestinationPerfNow();
  setGridlyDestinationPerformanceTiming("totalDestinationRouteMs", gridlyDestinationPerformanceAuditState.routePreviewRequestEndedAt - flowStartedAt);
  return latestPreview;
}

window.gridlyDestinationRoutePreviewDebug = function gridlyDestinationRoutePreviewDebug() {
  const preview = getGridlyDestinationRoutePreviewState();
  return {
    active: Boolean(preview.active),
    status: preview.status,
    source: preview.source,
    destination: preview.destination,
    distanceMiles: preview.distanceMiles,
    etaMinutes: preview.etaMinutes,
    geometryPointCount: Array.isArray(preview.geometry) ? preview.geometry.length : 0,
    layerOwnsRenderedRoute: Boolean(destinationRoutePreviewLayer && preview.routeLayer === destinationRoutePreviewLayer),
    routeWatchLayerUntouched: Boolean(savedRouteLayer && destinationRoutePreviewLayer !== savedRouteLayer),
    routeProvider: preview.routeProvider,
    error: preview.error
  };
};

window.gridlyDestinationPerformanceAudit = function gridlyDestinationPerformanceAudit() {
  return buildGridlyDestinationPerformanceAuditReport();
};

const GRIDLY_DESTINATION_ROUTE_INTELLIGENCE_CORRIDOR_FEET = 750;
const GRIDLY_FEET_PER_MILE = 5280;

function normalizeGridlyDestinationRoutePoint(point) {
  if (Array.isArray(point)) return normalizeCoordinatePair(point[0], point[1]);
  if (point && typeof point === "object") return normalizeCoordinatePair(point.lat ?? point.latitude, point.lng ?? point.lon ?? point.longitude);
  return null;
}

function getGridlyDestinationRoutePreviewPoints() {
  const preview = window.GridlyDestinationRoutePreview && typeof window.GridlyDestinationRoutePreview === "object"
    ? window.GridlyDestinationRoutePreview
    : {};
  return (Array.isArray(preview.geometry) ? preview.geometry : [])
    .map((point) => normalizeGridlyDestinationRoutePoint(point))
    .filter(Boolean);
}

function getGridlyDestinationRouteObjectCoordinate(record = {}) {
  return gridlyCoordinateFromRecord(record)
    || gridlyCoordinateFromRecord(record?.raw)
    || gridlyCoordinateFromRecord(record?.source)
    || gridlyCoordinateFromRecord(record?.incident)
    || gridlyCoordinateFromRecord(record?.latestReport)
    || gridlyCoordinateFromRecord(record?.finalPlacementCoordinate)
    || gridlyCoordinateFromRecord(record?.storedReportCoordinate)
    || gridlyCoordinateFromRecord(record?.activeHazardCoordinate)
    || gridlyCoordinateFromRecord(record?.representativeCoordinate)
    || null;
}

function pickGridlyDestinationRouteFirstText() {
  for (let index = 0; index < arguments.length; index += 1) {
    const value = arguments[index];
    if (typeof value === "string" && value.trim()) return value.trim();
  }
  return "";
}

function getGridlyDestinationRouteObjectTitle(record = {}, fallback = "Route intelligence") {
  return pickGridlyDestinationRouteFirstText(
    record?.title,
    record?.headline,
    record?.resolvedHeadline,
    record?.localizedSummary,
    record?.finalHeadline,
    record?.segmentHeadline,
    record?.label,
    record?.crossingName,
    record?.roadName,
    record?.nearestRoad,
    record?.locationName,
    record?.location,
    record?.raw?.title,
    record?.latestReport?.title,
    fallback
  );
}

function getGridlyDestinationRouteObjectType(record = {}, fallback = "intelligence") {
  return String(
    record?.type
      || record?.reportType
      || record?.report_type
      || record?.reportKind
      || record?.category
      || record?.status
      || record?.raw?.type
      || record?.latestReport?.type
      || fallback
  ).trim() || fallback;
}

function getGridlyDestinationRouteObjectId(record = {}, fallback = "") {
  return String(
    record?.id
      || record?.report_id
      || record?.reportId
      || record?.incidentId
      || record?.crossingId
      || record?.crossing_id
      || record?.objectid
      || record?.objectId
      || record?.raw?.id
      || record?.latestReport?.id
      || fallback
  ).trim() || fallback;
}

function readGridlyDestinationRoutePath(record = {}, path = "") {
  if (!record || typeof record !== "object" || !path) return undefined;
  return String(path).split(".").reduce((current, key) => current?.[key], record);
}

function getGridlyDestinationRouteFirstUsefulPath(record = {}, paths = []) {
  for (const path of Array.isArray(paths) ? paths : []) {
    const value = readGridlyDestinationRoutePath(record, path);
    if (typeof value === "string" && value.trim()) return value.trim();
    if (typeof value === "number" && Number.isFinite(value)) return String(value);
  }
  return "";
}

function normalizeGridlyDestinationLocationToken(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/\b(street|st)\b/g, "st")
    .replace(/\b(road|rd)\b/g, "rd")
    .replace(/\b(avenue|ave)\b/g, "ave")
    .replace(/\b(highway|hwy)\b/g, "hwy")
    .replace(/\s+/g, " ")
    .replace(/[^a-z0-9 ]+/g, "")
    .trim();
}

function formatGridlyDestinationRouteLocationLabel(value = "") {
  const cleaned = String(value || "")
    .replace(/\s+/g, " ")
    .replace(/\bnear\s+near\b/ig, "near")
    .replace(/^\s*(at|near|between|on)\s+/i, "")
    .trim();
  if (!cleaned) return "";
  if (typeof gridlyNormalizeAnalyticsRoadLabel === "function") {
    const normalized = gridlyNormalizeAnalyticsRoadLabel(cleaned);
    if (normalized) return normalized;
  }
  if (typeof normalizeRoadDisplayCase === "function") return normalizeRoadDisplayCase(cleaned);
  return cleaned;
}

function isGridlyDestinationRouteUsefulLocationLabel(value = "", primaryRoad = "") {
  const label = formatGridlyDestinationRouteLocationLabel(value);
  if (!label) return false;
  const normalized = normalizeGridlyDestinationLocationToken(label);
  if (!normalized) return false;
  if (primaryRoad && normalized === normalizeGridlyDestinationLocationToken(primaryRoad)) return false;
  if (/^(unknown|unknown road|active hazard|active alert|route intelligence|road closure|road closed|closure|construction|flooding|hazard|report|nearby|community report)$/i.test(label)) return false;
  if (/reported nearby|near your route|potential impact|active hazards reported/i.test(label)) return false;
  return true;
}

function formatGridlyDestinationRouteDelimitedIntersection(value = "") {
  const parts = String(value || "")
    .split(/\s*[;|]\s*/g)
    .map((part) => formatGridlyDestinationRouteLocationLabel(part))
    .filter((part) => isGridlyDestinationRouteUsefulLocationLabel(part));
  if (parts.length !== 2) return "";
  const [primaryRoad, referenceRoad] = parts;
  if (!isGridlyDestinationRouteUsefulLocationLabel(referenceRoad, primaryRoad)) return "";
  return `${primaryRoad} at ${referenceRoad}`;
}

function getGridlyDestinationRouteRoadName(record = {}) {
  const directRoad = getGridlyDestinationRouteFirstUsefulPath(record, GRIDLY_DESTINATION_ROUTE_LOCATION_FIELD_PATHS.roadName);
  const resolvedRoad = directRoad || (typeof gridlyResolveHazardHistoryRoadName === "function" ? gridlyResolveHazardHistoryRoadName(record) : "");
  const label = formatGridlyDestinationRouteLocationLabel(resolvedRoad);
  if (!isGridlyDestinationRouteUsefulLocationLabel(label)) return "";
  if (typeof gridlyIsHazardTypeRoadName === "function" && gridlyIsHazardTypeRoadName(label, record)) return "";
  return label;
}

