function selectGridlySearchResult(result, options = {}) {
  resetGridlyDestinationPerformanceAudit("selecting");
  const destinationSelectStartedAt = getGridlyDestinationPerfNow();
  gridlyDestinationPerformanceAuditState.destinationFlowStartedAt = destinationSelectStartedAt;
  const normalized = normalizeGridlySearchResult(result);
  if (!normalized) return null;
  if (!Number.isFinite(normalized?.lat) || !Number.isFinite(normalized?.lng)) {
    if (!gridlySearchUiState.debugWarningsSeen.has("select-invalid-normalized-result")) {
      console.warn("Gridly selection aborted: normalized result missing coordinates.");
      gridlySearchUiState.debugWarningsSeen.add("select-invalid-normalized-result");
    }
    return null;
  }
  const state = ensureGridlySearchState();
  state.activeResult = normalized;
  state.selectedDestination = normalized;

  if (options?.addToRecentSearches !== false) {
    const existing = Array.isArray(state.recentSearches) ? state.recentSearches : [];
    const deduped = [normalized, ...existing.filter((entry) => normalizeGridlySearchResult(entry)?.id !== normalized.id)];
    state.recentSearches = deduped.slice(0, 5);
  }

  const selectedLabel = normalized.title || normalized.displayName || normalized.context || normalized.address || "";
  const input = gridlySearchUiRefs.input || document.getElementById("gridlyAddressSearchInput");
  if (input) input.value = selectedLabel;
  state.activeQuery = selectedLabel;
  const destinationHabitCopy = document.getElementById("destinationHabitCopy");
  if (destinationHabitCopy && selectedLabel) destinationHabitCopy.textContent = `Selected: ${selectedLabel}`;

  const marker = setGridlyDestinationMarker(normalized, { preserveSelectedDestination: true });
  if (!marker && !gridlySearchUiState.debugWarningsSeen.has("select-marker-failed")) {
    console.warn("Gridly selection warning: destination marker was not created.");
    gridlySearchUiState.debugWarningsSeen.add("select-marker-failed");
  }
  collapseGridlySearchResults();
  hideGridlySearchShell({ clear: false });
  syncMobileDestinationCommandCard();
  if (marker && !isGridlyDestinationVisibilityCardPresent()) focusGridlyDestinationOnMap(normalized.lat, normalized.lng);
  setGridlyDestinationPerformanceTiming("destinationSelectMs", getGridlyDestinationPerfNow() - destinationSelectStartedAt);
  buildGridlyDestinationRoutePreview({ reason: options?.reason || "destination-selected" });
  return normalized;
}

function getGridlyLiveDestinationSearchOptions() {
  return { limit: GRIDLY_SEARCH_RENDER_LIMIT };
}

function beginGridlyLiveDestinationSearch(query = "") {
  const state = ensureGridlySearchState();
  const normalizedQuery = String(query || "").trim();
  state.activeQuery = normalizedQuery;
  const requestId = gridlySearchUiState.activeSearchRequestId + 1;
  gridlySearchUiState.activeSearchRequestId = requestId;
  gridlySearchUiState.isSearching = Boolean(normalizedQuery.length >= 3);
  return requestId;
}

function buildGridlyLiveSearchAuditReport(query, results = [], metadata = {}) {
  const normalizedResults = Array.isArray(results)
    ? results.map((result) => normalizeGridlySearchResult(result)).filter(Boolean)
    : [];
  const first = summarizeGridlyDestinationSearchResult(normalizedResults[0]) || {};
  const providerDiagnostics = metadata.providerDiagnostics
    || results?.gridlyProviderDiagnostics
    || gridlyDestinationProviderState.lastDiagnostics
    || createGridlyDestinationProviderDiagnostics(query, classifyGridlyDestinationSearchIntent(query), 0);
  const localSeedCount = Number(providerDiagnostics.localSeedCount) || normalizedResults.filter((result) => result.provider === "local_poi_seed" || result.localPoiSeed).length;
  const finalResultCount = normalizedResults.length;
  return {
    query: String(query || "").trim(),
    intent: providerDiagnostics.intent || classifyGridlyDestinationSearchIntent(query).type,
    detectedIntent: classifyGridlyDestinationSearchIntent(query),
    localSeedCount,
    providerAttempted: Boolean(providerDiagnostics.providerAttempted),
    providerSkippedReason: providerDiagnostics.providerSkippedReason || "",
    providerError: providerDiagnostics.providerError || "",
    providerStatus: providerDiagnostics.providerStatus || "not_attempted",
    providerResultCount: Number(providerDiagnostics.providerResultCount) || 0,
    cacheHit: Boolean(providerDiagnostics.cacheHit),
    cooldownActive: Boolean(providerDiagnostics.cooldownActive),
    duplicateSuppressed: Boolean(providerDiagnostics.duplicateSuppressed),
    throttled: Boolean(providerDiagnostics.throttled),
    suppressedFarAwayCount: Number(providerDiagnostics.suppressedFarAwayCount) || 0,
    visibleQualityFiltered: Boolean(providerDiagnostics.visibleQualityFiltered),
    localQualityResultCount: Number(providerDiagnostics.localQualityResultCount) || normalizedResults.filter((result) => isGridlyLocalQualitySearchResult(result)).length,
    genericLocalProviderFillerSuppressed: Boolean(providerDiagnostics.genericLocalProviderFillerSuppressed),
    finalResultCount,
    resultCount: finalResultCount,
    firstResult: {
      title: first.title || "",
      subtitle: first.subtitle || "",
      provider: first.provider || ""
    },
    seedResultsRenderImmediately: localSeedCount > 0,
    emptyStateWouldRender: finalResultCount === 0 && localSeedCount === 0,
    seedResultsIncluded: normalizedResults.some((result) => result.provider === "local_poi_seed" || result.localPoiSeed),
    providerVariants: Array.isArray(providerDiagnostics.variants) ? providerDiagnostics.variants : [],
    futureArchitecture: providerDiagnostics.futureArchitecture || gridlyDestinationProviderState.futureArchitecture,
    laterAsyncResponseOverwroteResults: Boolean(metadata.laterAsyncResponseOverwroteResults),
    requestId: metadata.requestId ?? null,
    rendered: Boolean(metadata.rendered),
    seedRenderedImmediately: Boolean(metadata.seedRenderedImmediately),
    staleRequestBlocked: Boolean(metadata.staleRequestBlocked)
  };
}

async function runGridlyLiveDestinationSearch(query = "", options = {}) {
  const normalizedQuery = String(query || "").trim();
  const state = ensureGridlySearchState();
  const requestId = Number.isFinite(Number(options.requestId)) ? Number(options.requestId) : beginGridlyLiveDestinationSearch(normalizedQuery);
  const shouldRender = options.render !== false;
  const auditOnly = options.auditOnly === true;
  let staleRequestBlocked = false;
  let rendered = false;
  let seedRenderedImmediately = false;
  let results = [];

  state.activeQuery = normalizedQuery;

  try {
    const intent = classifyGridlyDestinationSearchIntent(normalizedQuery);
    const immediateSeedResults = normalizedQuery.length >= 3
      ? dedupeGridlySearchResults(prioritizeGridlySearchResults(searchGridlyLocalPoiSeeds(normalizedQuery, { intent }), { query: normalizedQuery, intent })).slice(0, GRIDLY_SEARCH_RENDER_LIMIT)
      : [];
    const seedRenderCurrent = requestId === gridlySearchUiState.activeSearchRequestId
      && normalizeGridlySearchDisplayLabel(normalizedQuery) === normalizeGridlySearchDisplayLabel(getGridlySearchActiveInputQuery());
    if (shouldRender && !auditOnly && seedRenderCurrent && immediateSeedResults.length) {
      seedRenderedImmediately = renderGridlySearchResults(immediateSeedResults, { state: "done", allowEmptyMessage: false, query: normalizedQuery, requestId });
    }

    results = await gridlySearchAddress(normalizedQuery, getGridlyLiveDestinationSearchOptions());
    const isCurrent = requestId === gridlySearchUiState.activeSearchRequestId
      && normalizeGridlySearchDisplayLabel(normalizedQuery) === normalizeGridlySearchDisplayLabel(getGridlySearchActiveInputQuery());
    staleRequestBlocked = !isCurrent;
    if (shouldRender && !auditOnly && isCurrent) {
      gridlySearchUiState.isSearching = false;
      rendered = renderGridlySearchResults(results, { state: "done", allowEmptyMessage: true, query: normalizedQuery, requestId });
    }
  } catch (_error) {
    const isCurrent = requestId === gridlySearchUiState.activeSearchRequestId
      && normalizeGridlySearchDisplayLabel(normalizedQuery) === normalizeGridlySearchDisplayLabel(getGridlySearchActiveInputQuery());
    staleRequestBlocked = !isCurrent;
    if (shouldRender && !auditOnly && isCurrent) {
      gridlySearchUiState.isSearching = false;
      rendered = renderGridlySearchResults([], { state: "error", query: normalizedQuery, requestId });
    }
    results = [];
  }

  const audit = buildGridlyLiveSearchAuditReport(normalizedQuery, results, {
    requestId,
    rendered,
    seedRenderedImmediately,
    providerDiagnostics: results?.gridlyProviderDiagnostics,
    staleRequestBlocked,
    laterAsyncResponseOverwroteResults: false
  });
  gridlySearchUiState.lastLiveSearchAudit = audit;
  return auditOnly ? audit : results;
}

async function gridlyDestinationLiveSearchAudit(query = "") {
  const normalizedQuery = String(query || "").trim();
  const input = gridlySearchUiRefs.input || document.getElementById("gridlyAddressSearchInput");
  if (input) input.value = normalizedQuery;
  const requestId = beginGridlyLiveDestinationSearch(normalizedQuery);
  return runGridlyLiveDestinationSearch(normalizedQuery, { requestId, render: false, auditOnly: true });
}

function initGridlySearchUI() {
  const shell = document.getElementById("gridlySearchShell");
  const input = document.getElementById("gridlyAddressSearchInput");
  const clearBtn = document.getElementById("gridlySearchClearBtn");
  const results = document.getElementById("gridlySearchResults");

  gridlySearchUiRefs.shell = shell || null;
  gridlySearchUiRefs.input = input || null;
  gridlySearchUiRefs.clearBtn = clearBtn || null;
  gridlySearchUiRefs.results = results || null;

  if (shell) {
    shell.hidden = true;
    shell.dataset.searchUi = "dormant";
  }

  if (clearBtn && !clearBtn.dataset.gridlySearchClearBound) {
    clearBtn.addEventListener("click", () => {
      const state = ensureGridlySearchState();
      if (gridlySearchUiState.pendingSearchTimer) {
        clearTimeout(gridlySearchUiState.pendingSearchTimer);
        gridlySearchUiState.pendingSearchTimer = null;
      }
      if (gridlySearchUiRefs.input) gridlySearchUiRefs.input.value = "";
      state.activeQuery = "";
      gridlySearchUiState.activeSearchRequestId += 1;
      clearGridlySearchResults();
    });
    clearBtn.dataset.gridlySearchClearBound = "true";
  }

  if (input && !input.dataset.gridlySearchInputBound) {
    input.addEventListener("input", () => {
      const state = ensureGridlySearchState();
      const query = String(input.value || "").trim();
      state.activeQuery = query;

      if (gridlySearchUiState.pendingSearchTimer) {
        clearTimeout(gridlySearchUiState.pendingSearchTimer);
        gridlySearchUiState.pendingSearchTimer = null;
      }

      if (query.length < 3) {
        gridlySearchUiState.isSearching = false;
        gridlySearchUiState.activeSearchRequestId += 1;
        clearGridlySearchResults();
        return;
      }

      const requestId = beginGridlyLiveDestinationSearch(query);
      renderGridlySearchResults([], { state: "searching", query, requestId });

      gridlySearchUiState.pendingSearchTimer = setTimeout(() => {
        gridlySearchUiState.pendingSearchTimer = null;
        runGridlyLiveDestinationSearch(query, { requestId });
      }, 350);
    });
    const reopenResults = () => {
      const state = ensureGridlySearchState();
      const query = String(input.value || state.activeQuery || "").trim();
      state.activeQuery = query;
      if (query.length >= 3) {
        const requestId = beginGridlyLiveDestinationSearch(query);
        renderGridlySearchResults([], { state: "searching", query, requestId });
        runGridlyLiveDestinationSearch(query, { requestId });
      } else if (Array.isArray(state.recentSearches) && state.recentSearches.length) {
        renderGridlySearchResults(state.recentSearches, { state: "done", allowEmptyMessage: false, query });
      }
    };
    input.addEventListener("focus", reopenResults);
    input.addEventListener("click", reopenResults);
    input.dataset.gridlySearchInputBound = "true";
  }

  window.GridlySearchUI = {
    hasSearchShell: Boolean(shell),
    hasSearchInput: Boolean(input),
    hasSearchClearButton: Boolean(clearBtn),
    hasSearchResults: Boolean(results)
  };
}

function showGridlySearchShell(options = {}) {
  const shell = gridlySearchUiRefs.shell || document.getElementById("gridlySearchShell");
  if (options?.source) gridlySearchUiState.lastSearchShellOpenSource = String(options.source);
  if (!shell) return false;
  shell.hidden = false;
  shell.removeAttribute("hidden");
  shell.dataset.searchUi = "active";
  if (options?.focusInput === true) {
    const input = gridlySearchUiRefs.input || document.getElementById("gridlyAddressSearchInput");
    if (input && typeof input.focus === "function") input.focus();
  }
  return true;
}

function openGridlyDestinationSearchSurface(options = {}) {
  const openSearch = () => showGridlySearchShell({ focusInput: true, ...options });
  if (typeof openGridlySurface === "function") {
    openGridlySurface("search", openSearch);
    return true;
  }
  return openSearch();
}

function hideGridlySearchShell(options = {}) {
  const shell = gridlySearchUiRefs.shell || document.getElementById("gridlySearchShell");
  if (!shell) return false;
  shell.hidden = true;
  shell.setAttribute("hidden", "");
  shell.dataset.searchUi = "dormant";
  if (options?.clear === true) {
    const input = gridlySearchUiRefs.input || document.getElementById("gridlyAddressSearchInput");
    const results = gridlySearchUiRefs.results || document.getElementById("gridlySearchResults");
    if (input) input.value = "";
    if (results) results.textContent = "";
  }
  return true;
}

