if (typeof window !== "undefined") {
  window.gridlyTxdotDirectionalReadinessAudit = gridlyTxdotDirectionalReadinessAudit;
  window.gridlyLastTxdotDirectionalReadinessAudit = window.gridlyLastTxdotDirectionalReadinessAudit || null;
}
exposeGridlyAuditHelper("gridlyTxdotDirectionalReadinessAudit", gridlyTxdotDirectionalReadinessAudit);

function gridlyRefreshAfterTxdotFetch(reason = "txdot-fetch") {
  if (typeof refreshReportHazardViews === "function") {
    refreshReportHazardViews(reason);
    return "refreshReportHazardViews";
  }
  if (typeof renderUnifiedIncidents === "function") {
    renderUnifiedIncidents(reason);
    return "renderUnifiedIncidents";
  }
  if (typeof renderUnifiedIncidentMarkers === "function") {
    renderUnifiedIncidentMarkers(reason);
    return "renderUnifiedIncidentMarkers";
  }
  return "none";
}

async function gridlyRunTxdotFetchAndRefresh(options = {}) {
  const force = Boolean(options.force);
  const reason = String(options.reason || (force ? "txdot-manual-validation" : "txdot-startup"));
  const txdotService = window.gridlyTxdot || null;
  const txdotState = window.gridlyTxdotState || {};
  const cachedRows = typeof txdotService?.getRoadConditions === "function" ? txdotService.getRoadConditions() : gridlyReadCachedTxdotRows();
  const cachedRowCount = Array.isArray(cachedRows) ? cachedRows.length : 0;

  if (!force && !gridlyIsTxdotStartupFetchEnabled()) {
    return {
      attempted: false,
      skipped: true,
      skipReason: "txdot_startup_fetch_disabled",
      refreshMethod: "none",
      fetchedRows: cachedRowCount
    };
  }

  if (!gridlyIsTxdotFetchAvailable()) {
    return {
      attempted: false,
      skipped: true,
      skipReason: "txdot_fetch_not_configured",
      refreshMethod: "none",
      fetchedRows: 0
    };
  }

  if (!force && cachedRowCount > 0) {
    const refreshMethod = gridlyRefreshAfterTxdotFetch(`${reason}:cached`);
    return {
      attempted: false,
      skipped: true,
      skipReason: "cached_rows_available",
      refreshMethod,
      fetchedRows: cachedRowCount
    };
  }

  if (!force && (txdotState.hasFetched || txdotState.lastFetchTime)) {
    return {
      attempted: false,
      skipped: true,
      skipReason: "startup_fetch_already_attempted",
      refreshMethod: "none",
      fetchedRows: cachedRowCount
    };
  }

  if (!force && gridlyTxdotStartupFetchPromise) {
    return gridlyTxdotStartupFetchPromise;
  }

  const runFetch = (async () => {
    let rows = [];
    let fetchError = "";
    let refreshMethod = "none";
    try {
      rows = await txdotService.fetchRoadConditions();
    } catch (error) {
      fetchError = error instanceof Error ? error.message : String(error);
    }
    try {
      refreshMethod = gridlyRefreshAfterTxdotFetch(reason);
    } catch (error) {
      fetchError = [fetchError, error instanceof Error ? error.message : String(error)].filter(Boolean).join("; ");
    }
    const fetchedRows = Array.isArray(rows) ? rows.length : 0;
    return {
      attempted: true,
      skipped: false,
      skipReason: "",
      refreshMethod,
      fetchedRows,
      error: fetchError
    };
  })();

  if (!force) {
    gridlyTxdotStartupFetchPromise = runFetch;
    runFetch.then(
      () => { gridlyTxdotStartupFetchPromise = null; },
      () => { gridlyTxdotStartupFetchPromise = null; }
    );
  }

  return runFetch;
}

function gridlyBuildTxdotValidationResult(fetchSummary = {}) {
  const txdotAudit = typeof gridlyTxDotSourceAudit === "function" ? gridlyTxDotSourceAudit() : {};
  const incidentAudit = typeof gridlyIncidentSourceAudit === "function" ? gridlyIncidentSourceAudit({ sampleLimit: 5 }) : {};
  const normalizedRows = Number(txdotAudit.txdotNormalizedCount || 0);
  const rawRows = Number(txdotAudit.txdotRawConditionCount || 0);
  const txdotUnifiedIncidents = Number(txdotAudit.txdotUnifiedIncidents || 0);
  const txdotMapEligibleCount = Number(txdotAudit.txdotMapEligibleCount || 0);
  const txdotAlertEligibleCount = Number(txdotAudit.txdotAlertEligibleCount || 0);
  const txdotRenderedMarkerCount = Number(txdotAudit.trace?.mapMarkers || 0);
  const checks = {
    txdotFetchSuccess: txdotAudit.txdotLastFetchSuccess === true,
    rawRows: rawRows > 0,
    normalizedRows: normalizedRows > 0,
    futureTxdotIncidents: Number(txdotAudit.futureTxdotIncidents || 0) > 0,
    futureTxdotConstruction: Number(txdotAudit.futureTxdotConstruction || 0) > 0,
    txdotUnifiedIncidents: txdotUnifiedIncidents > 0,
    txdotMapEligibleCount: txdotMapEligibleCount > 0,
    txdotMarkersOrAlertsEligible: (txdotMapEligibleCount + txdotAlertEligibleCount + txdotRenderedMarkerCount) > 0
  };
  const failedChecks = Object.entries(checks)
    .filter(([, passed]) => !passed)
    .map(([name]) => name);

  return {
    result: failedChecks.length ? "FAIL" : "PASS",
    txdotFetchSuccess: checks.txdotFetchSuccess,
    rawRows,
    normalizedRows,
    futureTxdotIncidents: Number(txdotAudit.futureTxdotIncidents || 0),
    futureTxdotConstruction: Number(txdotAudit.futureTxdotConstruction || 0),
    txdotUnifiedIncidents,
    txdotMapEligibleCount,
    txdotAlertEligibleCount,
    txdotRenderedMarkerCount,
    txdotRowsSkippedNoCoordinates: Number(txdotAudit.txdotRowsSkippedNoCoordinates || 0),
    fetchSummary,
    refreshMethod: fetchSummary.refreshMethod || "none",
    checks,
    failedChecks,
    blockers: Array.isArray(txdotAudit.blockers) ? txdotAudit.blockers : [],
    txdotSourceAudit: txdotAudit,
    incidentSourceAudit: incidentAudit
  };
}

async function gridlyTxdotFullValidation() {
  const fetchSummary = await gridlyRunTxdotFetchAndRefresh({ force: true, reason: "txdot-full-validation" });
  const result = gridlyBuildTxdotValidationResult(fetchSummary);
  console.info("gridlyTxdotFullValidation", result);
  return result;
}

function gridlyScheduleStartupTxdotFetch() {
  if (gridlyTxdotStartupFetchAttempted) return;
  if (!gridlyIsTxdotStartupFetchEnabled()) return;
  gridlyTxdotStartupFetchAttempted = true;
  const start = () => {
    gridlyRunTxdotFetchAndRefresh({ force: false, reason: "txdot-startup-once" })
      .then((summary) => {
        if (summary?.attempted) console.info("gridlyTxdotStartupFetch", summary);
      })
      .catch((error) => {
        console.warn("gridlyTxdotStartupFetch failed", error);
      });
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", start, { once: true });
  } else {
    setTimeout(start, 0);
  }
}

window.gridlyTxdotFullValidation = gridlyTxdotFullValidation;
exposeGridlyAuditHelper("gridlyTxdotFullValidation", gridlyTxdotFullValidation);
gridlyScheduleStartupTxdotFetch();

function gridlyAuditHelperExposureAudit() {
  const target = typeof window !== "undefined" ? window : globalThis;
  const helperNames = Object.keys(target || {}).filter((name) => typeof name === "string");
  const helperNamesContainingTxdot = helperNames
    .filter((name) => name.toLowerCase().includes("txdot"))
    .sort();
  const helperNamesContainingIncident = helperNames
    .filter((name) => name.toLowerCase().includes("incident"))
    .sort();
  const appVersionParts = [
    typeof GRIDLY_APP_VERSION_LABEL === "string" ? GRIDLY_APP_VERSION_LABEL : null,
    typeof GRIDLY_APP_BUILD_LABEL === "string" ? GRIDLY_APP_BUILD_LABEL : null,
    typeof APP_BUILD === "string" ? `APP_BUILD ${APP_BUILD}` : null,
    "V203.4B"
  ].filter(Boolean);

  return {
    gridlyTxDotSourceAudit: typeof target?.gridlyTxDotSourceAudit,
    gridlyTxdotLayerAudit: typeof target?.gridlyTxdotLayerAudit,
    gridlyRunTxdotLayerAudit: typeof target?.gridlyRunTxdotLayerAudit,
    gridlyLastTxdotLayerAudit: target?.gridlyLastTxdotLayerAudit || null,
    gridlyIncidentSourceAudit: typeof target?.gridlyIncidentSourceAudit,
    gridlyTxdotFetch: typeof target?.gridlyTxdot?.fetchRoadConditions,
    helperNamesContainingTxdot,
    helperNamesContainingIncident,
    appVersionTag: appVersionParts.join(" / ")
  };
}

window.gridlyAuditHelperExposureAudit = gridlyAuditHelperExposureAudit;
exposeGridlyAuditHelper("gridlyAuditHelperExposureAudit", gridlyAuditHelperExposureAudit);


const GRIDLY_CORE_ROAD_HAZARD_CLEANUP_TYPES = Object.freeze(["flooding", "ice", "debris", "crash", "construction", "road_closed", "disabled_vehicle", "traffic_backup", "other_hazard"]);
const GRIDLY_SHARED_ROAD_HAZARD_REPORT_TYPES = Object.freeze([...GRIDLY_CORE_ROAD_HAZARD_CLEANUP_TYPES, "hazard_cleared", "wreck"]);
const GRIDLY_SUPABASE_TEST_HAZARD_CONFIRMATION = "CLEAR_SUPABASE_TEST_HAZARDS";

function gridlyGetSharedRoadHazardReportTypes() {
  return [...GRIDLY_SHARED_ROAD_HAZARD_REPORT_TYPES];
}

function gridlyNormalizeSharedRoadHazardType(type = "") {
  const normalized = String(type || "").trim().toLowerCase();
  return normalized === "wreck" ? "crash" : normalized;
}

function gridlyIsSharedRoadHazardReportRow(row = {}) {
  const rawType = String(row?.report_type || row?.type || "").trim().toLowerCase();
  return GRIDLY_SHARED_ROAD_HAZARD_REPORT_TYPES.includes(rawType);
}

function gridlyIsTxDotReportSource(row = {}) {
  const sourceText = [row?.source, row?.provider, row?.external_source]
    .map((value) => String(value || "").toLowerCase())
    .join(" ");
  return /\btx\s*dot\b|\btxdot\b|texas department of transportation/.test(sourceText);
}

function gridlySupabaseHazardRoadName(row = {}) {
  return gridlyNormalizeAnalyticsRoadLabel(
    row?.road_name
      || row?.roadName
      || row?.primary_road
      || row?.primaryRoad
      || row?.nearest_road
      || row?.nearestRoad
      || row?.location_name
      || row?.locationName
      || row?.crossing_name
      || row?.crossingName
      || ""
  ) || "Unknown road";
}

async function gridlyFetchActiveSupabaseRoadHazardRows(limit = 1000) {
  if (!supabaseClient) {
    return { ok: false, rows: [], error: "Supabase client not initialized." };
  }

  const nowIso = new Date().toISOString();
  const maxRows = Math.max(1, Math.min(1000, Number(limit) || 1000));
  const { data, error } = await supabaseClient
    .from("reports")
    .select("id,report_type,source,created_at,expires_at,crossing_id,crossing_name,railroad,detail,lat,lng")
    .gt("expires_at", nowIso)
    .in("report_type", gridlyGetSharedRoadHazardReportTypes())
    .order("created_at", { ascending: true })
    .limit(maxRows);

  if (error) {
    return { ok: false, rows: [], error: error.message || "query_failed" };
  }

  return { ok: true, rows: (Array.isArray(data) ? data : []).filter(gridlyIsSharedRoadHazardReportRow), error: "" };
}

function gridlyBuildSupabaseHazardInventory(rows = []) {
  const activeRows = Array.isArray(rows) ? rows.filter(gridlyIsSharedRoadHazardReportRow) : [];
  const byType = activeRows.reduce((acc, row) => {
    const type = gridlyNormalizeSharedRoadHazardType(row?.report_type || row?.type || "unknown") || "unknown";
    acc[type] = (acc[type] || 0) + 1;
    return acc;
  }, {});
  const createdTimes = activeRows
    .map((row) => ({ iso: row?.created_at || row?.createdAt || null, time: new Date(row?.created_at || row?.createdAt || 0).getTime() }))
    .filter((entry) => entry.iso && Number.isFinite(entry.time));

  return {
    activeHazardRows: activeRows.length,
    byType,
    cleanupTypeCoverage: {
      requiredTypes: [...GRIDLY_CORE_ROAD_HAZARD_CLEANUP_TYPES],
      sharedReportTypes: gridlyGetSharedRoadHazardReportTypes(),
      includesIce: GRIDLY_SHARED_ROAD_HAZARD_REPORT_TYPES.includes("ice")
    },
    oldestCreatedAt: createdTimes.length ? createdTimes.reduce((oldest, entry) => entry.time < oldest.time ? entry : oldest).iso : null,
    newestCreatedAt: createdTimes.length ? createdTimes.reduce((newest, entry) => entry.time > newest.time ? entry : newest).iso : null,
    sampleRows: activeRows.slice(0, 10).map((row) => ({
      id: row?.id || null,
      type: gridlyNormalizeSharedRoadHazardType(row?.report_type || row?.type || "unknown") || "unknown",
      source: row?.source || "user",
      createdAt: row?.created_at || row?.createdAt || null,
      roadName: gridlySupabaseHazardRoadName(row)
    }))
  };
}

window.gridlySupabaseHazardInventoryAudit = async function gridlySupabaseHazardInventoryAudit(options = {}) {
  const fetchResult = await gridlyFetchActiveSupabaseRoadHazardRows(options?.limit || 1000);
  if (!fetchResult.ok) {
    const failed = { activeHazardRows: 0, byType: {}, oldestCreatedAt: null, newestCreatedAt: null, sampleRows: [], ok: false, error: fetchResult.error };
    console.warn("gridlySupabaseHazardInventoryAudit failed", failed);
    return failed;
  }
  const audit = gridlyBuildSupabaseHazardInventory(fetchResult.rows);
  console.info("gridlySupabaseHazardInventoryAudit", audit);
  return audit;
};

window.gridlySupabaseHazardPurgeAudit = async function gridlySupabaseHazardPurgeAudit(options = {}) {
  const fetchResult = await gridlyFetchActiveSupabaseRoadHazardRows(options?.limit || 1000);
  if (!fetchResult.ok) {
    const failed = { supabaseActiveHazardsFound: 0, supabaseActiveHazardsWouldDelete: 0, purgeScope: "shared road hazard reports only", preservedRailReports: true, preservedTxDot: true, ok: false, error: fetchResult.error };
    console.warn("gridlySupabaseHazardPurgeAudit failed", failed);
    return failed;
  }

  const rows = fetchResult.rows;
  const deleteCandidates = rows.filter((row) => gridlyIsSharedRoadHazardReportRow(row) && !gridlyIsTxDotReportSource(row));
  const txdotRows = rows.filter(gridlyIsTxDotReportSource);
  const audit = {
    supabaseActiveHazardsFound: rows.length,
    supabaseActiveHazardsWouldDelete: deleteCandidates.length,
    purgeScope: "active Supabase reports where report_type is a shared road hazard type; excludes TxDOT-tagged rows and never targets rail crossing report types or other storage",
    cleanupTypeCoverage: {
      requiredTypes: [...GRIDLY_CORE_ROAD_HAZARD_CLEANUP_TYPES],
      sharedReportTypes: gridlyGetSharedRoadHazardReportTypes(),
      includesIce: GRIDLY_SHARED_ROAD_HAZARD_REPORT_TYPES.includes("ice")
    },
    preservedRailReports: true,
    preservedTxDot: txdotRows.length
  };
  console.info("gridlySupabaseHazardPurgeAudit", audit);
  return audit;
};

function gridlyNormalizeSupabaseMutationError(error = null) {
  if (!error) return null;
  return {
    message: error.message || "",
    code: error.code || "",
    details: error.details || "",
    hint: error.hint || "",
    name: error.name || ""
  };
}

function gridlyLooksLikeSupabaseRlsError(error = null) {
  const normalized = gridlyNormalizeSupabaseMutationError(error);
  if (!normalized) return false;
  const text = [normalized.message, normalized.code, normalized.details, normalized.hint, normalized.name].join(" ").toLowerCase();
  return text.includes("row-level security")
    || text.includes("rls")
    || text.includes("policy")
    || text.includes("permission denied")
    || text.includes("42501")
    || text.includes("insufficient privilege");
}

function gridlyBuildNonMatchingIdProbeValue(candidateIds = []) {
  const sample = candidateIds.find((id) => id !== null && typeof id !== "undefined");
  const sampleText = String(sample || "").trim();
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(sampleText)) {
    return "00000000-0000-0000-0000-000000000000";
  }
  if (typeof sample === "number" || (/^-?\d+$/.test(sampleText) && sampleText !== "")) return -1;
  return "gridly-dev-purge-failure-audit-non-matching-id";
}

window.gridlyClearSupabaseTestHazards = async function gridlyClearSupabaseTestHazards(options = {}) {
  if (options?.confirm !== GRIDLY_SUPABASE_TEST_HAZARD_CONFIRMATION) {
    const blocked = { deleted: 0, failed: 0, ok: false, reason: "confirm_CLEAR_SUPABASE_TEST_HAZARDS_required" };
    console.warn("gridlyClearSupabaseTestHazards blocked", blocked);
    return blocked;
  }
  if (!supabaseClient) {
    const missing = { deleted: 0, failed: 0, ok: false, reason: "Supabase client not initialized." };
    console.warn("gridlyClearSupabaseTestHazards unavailable", missing);
    return missing;
  }

  const fetchResult = await gridlyFetchActiveSupabaseRoadHazardRows(options?.limit || 1000);
  if (!fetchResult.ok) {
    const failed = { deleted: 0, failed: 0, ok: false, error: fetchResult.error };
    console.warn("gridlyClearSupabaseTestHazards query failed", failed);
    return failed;
  }
  const idsToDelete = fetchResult.rows
    .filter((row) => gridlyIsSharedRoadHazardReportRow(row) && !gridlyIsTxDotReportSource(row))
    .map((row) => row.id)
    .filter(Boolean);
  if (!idsToDelete.length) {
    await loadSharedReports("clear_supabase_test_hazards_noop_validation");
    const trace = typeof gridlyBuildIncidentSourceTrace === "function" ? gridlyBuildIncidentSourceTrace({ sampleLimit: 5 }) : null;
    return { deleted: 0, failed: 0, ok: true, validation: trace };
  }

  const { error } = await supabaseClient.from("reports").delete().in("id", idsToDelete);
  if (error) {
    const failed = { deleted: 0, failed: idsToDelete.length, ok: false, error: error.message || "delete_failed" };
    console.error("gridlyClearSupabaseTestHazards delete failed", failed);
    return failed;
  }

  await loadSharedReports("clear_supabase_test_hazards_validation");
  const validation = typeof gridlyBuildIncidentSourceTrace === "function" ? gridlyBuildIncidentSourceTrace({ sampleLimit: 5 }) : null;
  const result = { deleted: idsToDelete.length, failed: 0, ok: true, validation };
  console.info("gridlyClearSupabaseTestHazards completed", result);
  return result;
};

window.gridlyDevPurgeFailureAudit = async function gridlyDevPurgeFailureAudit(options = {}) {
  const deleteTargetTable = "reports";
  const emptyAudit = {
    deleteAttempted: false,
    deleteCandidateCount: 0,
    deleteTargetTable,
    deleteError: null,
    deleteResponse: null,
    rlsSuspected: false,
    candidateIdsSample: [],
    dryRunCount: 0,
    actualDeleteCount: 0
  };

  if (!supabaseClient) {
    const missing = { ...emptyAudit, deleteError: { message: "Supabase client not initialized." }, deleteResponse: { ok: false, reason: "supabase_client_missing" } };
    console.warn("gridlyDevPurgeFailureAudit unavailable", missing);
    return missing;
  }

  const ROAD_HAZARD_TYPES = gridlyGetSharedRoadHazardReportTypes();
  const {
    hours = 24,
    radiusMiles = DEFAULT_NEARBY_RADIUS_MILES,
    nearLocation = null,
    sourceFilter = ["user"],
    typeFilter = [],
    deviceIdFilter = [deviceId],
    limit = 50
  } = options || {};

  const normalizedTypeFilter = Array.isArray(typeFilter)
    ? typeFilter.map((v) => String(v || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedSourceFilter = Array.isArray(sourceFilter)
    ? sourceFilter.map((v) => String(v || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedDeviceIdFilter = Array.isArray(deviceIdFilter)
    ? deviceIdFilter.map((v) => String(v || "").trim()).filter(Boolean)
    : [];
  const explicitTypeFilter = normalizedTypeFilter.length > 0;
  const maxRows = Math.max(1, Math.min(500, Number(limit) || 50));
  const radius = Number(radiusMiles) > 0 ? Number(radiusMiles) : 0;
  const cutoffIso = new Date(Date.now() - (Math.max(1, Number(hours) || 24) * 60 * 60 * 1000)).toISOString();
  const centerCandidate = nearLocation && Number.isFinite(Number(nearLocation.lat)) && Number.isFinite(Number(nearLocation.lng))
    ? { lat: Number(nearLocation.lat), lng: Number(nearLocation.lng), source: "nearLocation" }
    : userLocation && Number.isFinite(Number(userLocation.lat)) && Number.isFinite(Number(userLocation.lng))
    ? { lat: Number(userLocation.lat), lng: Number(userLocation.lng), source: "userLocation" }
    : map?.getCenter
    ? { lat: Number(map.getCenter().lat), lng: Number(map.getCenter().lng), source: "mapCenter" }
    : null;

  const { data, error } = await supabaseClient
    .from(deleteTargetTable)
    .select("id,report_type,source,created_at,lat,lng,crossing_id,crossing_name,detail,device_id")
    .gte("created_at", cutoffIso)
    .in("report_type", ROAD_HAZARD_TYPES)
    .order("created_at", { ascending: false })
    .limit(1000);

  if (error) {
    const queryError = gridlyNormalizeSupabaseMutationError(error) || { message: error.message || "query_failed" };
    const failed = {
      ...emptyAudit,
      deleteError: queryError,
      deleteResponse: { ok: false, stage: "candidate_query", error: queryError },
      rlsSuspected: gridlyLooksLikeSupabaseRlsError(error)
    };
    console.warn("gridlyDevPurgeFailureAudit query failed", failed);
    return failed;
  }

  const matches = (Array.isArray(data) ? data : []).filter((row) => {
    const type = String(row?.report_type || "").toLowerCase();
    const effectiveSource = String(row?.source || "user").toLowerCase();
    const isRail = String(row?.crossing_id || "").trim().length > 0;

    if (!ROAD_HAZARD_TYPES.includes(type)) return false;
    if (!explicitTypeFilter && type === "hazard_cleared") return false;
    if (!explicitTypeFilter && isRail) return false;
    if (explicitTypeFilter && !normalizedTypeFilter.includes(type)) return false;
    if (normalizedSourceFilter.length && !normalizedSourceFilter.includes(effectiveSource)) return false;
    if (normalizedDeviceIdFilter.length && !normalizedDeviceIdFilter.includes(String(row?.device_id || "").trim())) return false;
    if (!radius || !centerCandidate) return true;

    return getDistanceMiles(centerCandidate.lat, centerCandidate.lng, Number(row?.lat), Number(row?.lng)) <= radius;
  }).slice(0, maxRows);

  const candidateIds = matches.map((row) => row?.id).filter(Boolean);
  const impossibleId = gridlyBuildNonMatchingIdProbeValue(candidateIds);
  const deleteProbe = candidateIds.length
    ? await supabaseClient
      .from(deleteTargetTable)
      .delete({ count: "exact" })
      .eq("id", impossibleId)
      .select("id")
    : { data: null, error: null, count: 0, status: null, statusText: "Skipped: no delete candidates." };
  const normalizedDeleteError = gridlyNormalizeSupabaseMutationError(deleteProbe?.error);
  const deleteResponse = {
    ok: !deleteProbe?.error,
    nonMutatingProbe: Boolean(candidateIds.length),
    probeFilter: candidateIds.length ? { id: impossibleId } : null,
    data: Array.isArray(deleteProbe?.data) ? deleteProbe.data : deleteProbe?.data ?? null,
    count: Number.isFinite(Number(deleteProbe?.count)) ? Number(deleteProbe.count) : null,
    status: deleteProbe?.status ?? null,
    statusText: deleteProbe?.statusText ?? null,
    error: normalizedDeleteError,
    filterComparison: {
      dryRunFilters: {
        table: deleteTargetTable,
        createdAtGte: cutoffIso,
        reportTypeIn: ROAD_HAZARD_TYPES,
        sourceFilter: normalizedSourceFilter,
        typeFilter: normalizedTypeFilter,
        deviceIdFilter: normalizedDeviceIdFilter,
        excludesHazardClearedUnlessExplicit: !explicitTypeFilter,
        excludesRailUnlessExplicit: !explicitTypeFilter,
        radiusMiles: radius,
        center: centerCandidate,
        limit: maxRows
      },
      actualDeleteFiltersInPurgeHelper: {
        table: deleteTargetTable,
        idInCandidateIdsOnly: true
      },
      filtersDiffer: true,
      note: "gridlyDevPurgeRecentRoadHazards builds candidates with the dry-run filters, then deletes by candidate id only; this audit probes delete permissions with an impossible id and does not delete candidate rows."
    }
  };
  const audit = {
    deleteAttempted: Boolean(candidateIds.length),
    deleteCandidateCount: candidateIds.length,
    deleteTargetTable,
    deleteError: normalizedDeleteError,
    deleteResponse,
    rlsSuspected: gridlyLooksLikeSupabaseRlsError(deleteProbe?.error),
    candidateIdsSample: candidateIds.slice(0, 10),
    dryRunCount: matches.length,
    actualDeleteCount: Number.isFinite(Number(deleteProbe?.count)) ? Number(deleteProbe.count) : 0
  };

  console.info("gridlyDevPurgeFailureAudit", audit);
  return audit;
};

const gridlyDevPurgeRecentRoadHazards = async function gridlyDevPurgeRecentRoadHazards(options = {}) {
  const host = String(window?.location?.hostname || "").toLowerCase();
  const isDevHost = host === "localhost" || host === "127.0.0.1" || host.endsWith(".local") || host === "";
  if (!isDevHost) {
    const blocked = { ok: false, deleted: 0, reason: `Blocked outside dev host (${host || "unknown"}).` };
    console.warn("gridlyDevPurgeRecentRoadHazards blocked", blocked);
    return blocked;
  }
  if (!supabaseClient) {
    const missing = { ok: false, deleted: 0, reason: "Supabase client not initialized." };
    console.warn("gridlyDevPurgeRecentRoadHazards unavailable", missing);
    return missing;
  }

  const ROAD_HAZARD_TYPES = gridlyGetSharedRoadHazardReportTypes();
  const {
    dryRun = true,
    hours = 24,
    radiusMiles = DEFAULT_NEARBY_RADIUS_MILES,
    nearLocation = null,
    sourceFilter = ["user"],
    typeFilter = [],
    deviceIdFilter = [deviceId],
    limit = 50,
    confirm = false
  } = options || {};

  const normalizedTypeFilter = Array.isArray(typeFilter)
    ? typeFilter.map((v) => String(v || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedSourceFilter = Array.isArray(sourceFilter)
    ? sourceFilter.map((v) => String(v || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedDeviceIdFilter = Array.isArray(deviceIdFilter)
    ? deviceIdFilter.map((v) => String(v || "").trim()).filter(Boolean)
    : [];
  const explicitTypeFilter = normalizedTypeFilter.length > 0;
  const maxRows = Math.max(1, Math.min(500, Number(limit) || 50));
  const radius = Number(radiusMiles) > 0 ? Number(radiusMiles) : 0;
  const cutoffIso = new Date(Date.now() - (Math.max(1, Number(hours) || 24) * 60 * 60 * 1000)).toISOString();
  const centerCandidate = nearLocation && Number.isFinite(Number(nearLocation.lat)) && Number.isFinite(Number(nearLocation.lng))
    ? { lat: Number(nearLocation.lat), lng: Number(nearLocation.lng), source: "nearLocation" }
    : userLocation && Number.isFinite(Number(userLocation.lat)) && Number.isFinite(Number(userLocation.lng))
    ? { lat: Number(userLocation.lat), lng: Number(userLocation.lng), source: "userLocation" }
    : map?.getCenter
    ? { lat: Number(map.getCenter().lat), lng: Number(map.getCenter().lng), source: "mapCenter" }
    : null;

  console.warn("⚠️ gridlyDevPurgeRecentRoadHazards: This helper targets Supabase report SOURCE rows. Generated road-* incidents are derived output and are not directly persisted. Always review dryRun output before running confirm delete.");

  const { data, error } = await supabaseClient
    .from("reports")
    .select("id,report_type,source,created_at,lat,lng,crossing_id,crossing_name,detail,device_id")
    .gte("created_at", cutoffIso)
    .in("report_type", ROAD_HAZARD_TYPES)
    .order("created_at", { ascending: false })
    .limit(1000);

  if (error) {
    console.error("gridlyDevPurgeRecentRoadHazards query failed", error);
    return { ok: false, deleted: 0, error: error.message || "query_failed" };
  }

  const matches = (Array.isArray(data) ? data : []).filter((row) => {
    const type = String(row?.report_type || "").toLowerCase();
    const effectiveSource = String(row?.source || "user").toLowerCase();
    const isRail = String(row?.crossing_id || "").trim().length > 0;

    if (!ROAD_HAZARD_TYPES.includes(type)) return false;
    if (!explicitTypeFilter && type === "hazard_cleared") return false;
    if (!explicitTypeFilter && isRail) return false;
    if (explicitTypeFilter && !normalizedTypeFilter.includes(type)) return false;
    if (normalizedSourceFilter.length && !normalizedSourceFilter.includes(effectiveSource)) return false;
    if (normalizedDeviceIdFilter.length && !normalizedDeviceIdFilter.includes(String(row?.device_id || "").trim())) return false;
    if (!radius || !centerCandidate) return true;

    return getDistanceMiles(centerCandidate.lat, centerCandidate.lng, Number(row?.lat), Number(row?.lng)) <= radius;
  }).slice(0, maxRows);

  const groupedClusterKeys = [...new Set(matches.map((row) => getHazardClusterKey({ type: row.report_type, lat: row.lat, lng: row.lng })))];
  const predictedRoadIncidentIds = groupedClusterKeys.map((clusterKey) => `road-${clusterKey}`);
  const candidates = matches.map((row) => ({
    id: row.id,
    type: row.report_type,
    source: row.source || "user",
    created_at: row.created_at,
    lat: row.lat,
    lng: row.lng,
    crossing_id: row.crossing_id || "",
    crossing_name: row.crossing_name || "",
    detail: row.detail || "",
    device_id: row.device_id || ""
  }));

  if (candidates.length) console.table(candidates);

  const summary = {
    ok: true,
    dryRun: Boolean(dryRun),
    cutoffIso,
    radiusMiles: radius,
    hours: Math.max(1, Number(hours) || 24),
    limit: maxRows,
    sourceFilter: normalizedSourceFilter,
    typeFilter: normalizedTypeFilter,
    deviceIdFilter: normalizedDeviceIdFilter,
    safeDeleteScope: "dev host only; report rows must be recent, user-sourced by default, from the current device by default, non-rail road hazard types, and within the dev radius when a center is available",
    center: centerCandidate,
    candidateCount: candidates.length,
    candidates,
    groupedClusterKeys,
    predictedRoadIncidentIds,
    currentLiveHazardIncidentCount: getLiveHazardIncidents().length,
    currentGeneratedRoadIncidentCount: getUnifiedIncidents().filter((item) => String(item?.id || "").startsWith("road-")).length,
    deleted: 0
  };

  if (dryRun !== false) {
    console.info("gridlyDevPurgeRecentRoadHazards dry run", summary);
    return summary;
  }

  if (confirm !== true) {
    return { ...summary, ok: false, reason: "confirm_true_required_for_delete" };
  }

  const idsToDelete = candidates.map((row) => row.id).filter(Boolean);
  if (!idsToDelete.length) {
    console.info("gridlyDevPurgeRecentRoadHazards no matches to delete", summary);
    return summary;
  }

  const { error: deleteError } = await supabaseClient.from("reports").delete().in("id", idsToDelete);
  if (deleteError) {
    console.error("gridlyDevPurgeRecentRoadHazards delete failed", deleteError);
    return { ...summary, ok: false, error: deleteError.message || "delete_failed" };
  }

  await loadSharedReports("dev_purge_recent_road_hazards");

  summary.deleted = idsToDelete.length;
  console.info("gridlyDevPurgeRecentRoadHazards completed", summary);
  return summary;
};



const gridlyDevPurgeRecentCrossingReports = async function gridlyDevPurgeRecentCrossingReports(options = {}) {
  const host = String(window?.location?.hostname || "").toLowerCase();
  const isDevHost = host === "localhost" || host === "127.0.0.1" || host.endsWith(".local") || host === "";
  if (!isDevHost) {
    const blocked = { ok: false, deleted: 0, reason: `Blocked outside dev host (${host || "unknown"}).` };
    console.warn("gridlyDevPurgeRecentCrossingReports blocked", blocked);
    return blocked;
  }
  if (!supabaseClient) {
    const missing = { ok: false, deleted: 0, reason: "Supabase client not initialized." };
    console.warn("gridlyDevPurgeRecentCrossingReports unavailable", missing);
    return missing;
  }

  const {
    dryRun = true,
    hours = 24,
    radiusMiles = DEFAULT_NEARBY_RADIUS_MILES,
    nearLocation = null,
    sourceFilter = ["user"],
    deviceIdFilter = [deviceId],
    limit = 50,
    confirm = false
  } = options || {};

  const roadHazardTypes = gridlyGetSharedRoadHazardReportTypes();
  const normalizedSourceFilter = Array.isArray(sourceFilter)
    ? sourceFilter.map((v) => String(v || "").trim().toLowerCase()).filter(Boolean)
    : [];
  const normalizedDeviceIdFilter = Array.isArray(deviceIdFilter)
    ? deviceIdFilter.map((v) => String(v || "").trim()).filter(Boolean)
    : [];
  const maxRows = Math.max(1, Math.min(500, Number(limit) || 50));
  const radius = Number(radiusMiles) > 0 ? Number(radiusMiles) : 0;
  const cutoffIso = new Date(Date.now() - (Math.max(1, Number(hours) || 24) * 60 * 60 * 1000)).toISOString();
  const centerCandidate = nearLocation && Number.isFinite(Number(nearLocation.lat)) && Number.isFinite(Number(nearLocation.lng))
    ? { lat: Number(nearLocation.lat), lng: Number(nearLocation.lng), source: "nearLocation" }
    : userLocation && Number.isFinite(Number(userLocation.lat)) && Number.isFinite(Number(userLocation.lng))
    ? { lat: Number(userLocation.lat), lng: Number(userLocation.lng), source: "userLocation" }
    : map?.getCenter
    ? { lat: Number(map.getCenter().lat), lng: Number(map.getCenter().lng), source: "mapCenter" }
    : null;

  const { data, error } = await supabaseClient
    .from("reports")
    .select("id,report_type,source,created_at,lat,lng,crossing_id,crossing_name,detail,device_id")
    .gte("created_at", cutoffIso)
    .order("created_at", { ascending: false })
    .limit(1000);

  if (error) {
    console.error("gridlyDevPurgeRecentCrossingReports query failed", error);
    return { ok: false, deleted: 0, error: error.message || "query_failed" };
  }

  const matches = (Array.isArray(data) ? data : []).filter((row) => {
    const type = String(row?.report_type || "").toLowerCase();
    const effectiveSource = String(row?.source || "user").toLowerCase();
    const crossingId = String(row?.crossing_id || "").trim();
    if (roadHazardTypes.includes(type)) return false;
    if (!crossingId || crossingId.startsWith("hazard-")) return false;
    if (normalizedSourceFilter.length && !normalizedSourceFilter.includes(effectiveSource)) return false;
    if (normalizedDeviceIdFilter.length && !normalizedDeviceIdFilter.includes(String(row?.device_id || "").trim())) return false;
    if (!radius || !centerCandidate) return true;
    return getDistanceMiles(centerCandidate.lat, centerCandidate.lng, Number(row?.lat), Number(row?.lng)) <= radius;
  }).slice(0, maxRows);

  const candidates = matches.map((row) => ({
    id: row.id,
    type: row.report_type,
    source: row.source || "user",
    created_at: row.created_at,
    lat: row.lat,
    lng: row.lng,
    crossing_id: row.crossing_id || "",
    crossing_name: row.crossing_name || "",
    detail: row.detail || "",
    device_id: row.device_id || ""
  }));

  const summary = {
    ok: true,
    dryRun: Boolean(dryRun),
    cutoffIso,
    radiusMiles: radius,
    hours: Math.max(1, Number(hours) || 24),
    limit: maxRows,
    sourceFilter: normalizedSourceFilter,
    deviceIdFilter: normalizedDeviceIdFilter,
    safeDeleteScope: "dev host only; recent crossing rows from the current device by default, user-sourced by default, non-road-hazard report types, and within the dev radius when a center is available",
    center: centerCandidate,
    candidateCount: candidates.length,
    candidates,
    deleted: 0
  };

  if (dryRun !== false) {
    console.info("gridlyDevPurgeRecentCrossingReports dry run", summary);
    return summary;
  }
  if (confirm !== true) return { ...summary, ok: false, reason: "confirm_true_required_for_delete" };

  const idsToDelete = candidates.map((row) => row.id).filter(Boolean);
  if (!idsToDelete.length) {
    console.info("gridlyDevPurgeRecentCrossingReports no matches to delete", summary);
    return summary;
  }

  const { error: deleteError } = await supabaseClient.from("reports").delete().in("id", idsToDelete);
  if (deleteError) {
    console.error("gridlyDevPurgeRecentCrossingReports delete failed", deleteError);
    return { ...summary, ok: false, error: deleteError.message || "delete_failed" };
  }

  summary.deleted = idsToDelete.length;
  console.info("gridlyDevPurgeRecentCrossingReports completed", summary);
  return summary;
};


