function resolveGridlyLightweightLocationLabel(item = {}, sourceKind = "activeHazard", activeCategory = "") {
  const direct = getGridlyLightweightFirstField(item, getGridlyLightweightFieldDefsForSource(GRIDLY_LIGHTWEIGHT_LOCATION_FIELD_DEFS, sourceKind));
  if (direct.value) {
    return {
      value: normalizeGridlyLightweightLocationLabelText(direct.value),
      source: direct.source,
      specificity: /road|route|corridor|highway|reference/i.test(direct.source) ? "road" : "location_label",
      reusedAlertSummary: false,
      reusedAlertText: ""
    };
  }

  const rendered = getGridlyLightweightFirstField(item, [
    ["renderedAlertRowLabel", `${sourceKind}.renderedAlertRowLabel`],
    ["alertRowLabel", `${sourceKind}.alertRowLabel`],
    ["lightweightAlertSummary", `${sourceKind}.lightweightAlertSummary`],
    ["lightweightSummary", `${sourceKind}.lightweightSummary`],
    ["summary", `${sourceKind}.summary`],
    ["headline", `${sourceKind}.headline`],
    ["resolvedHeadline", `${sourceKind}.resolvedHeadline`],
    ["localizedSummary", `${sourceKind}.localizedSummary`],
    ["title", `${sourceKind}.title`],
    ["renderedMarkerSummary", `${sourceKind}.renderedMarkerSummary`],
    ["markerSummary", `${sourceKind}.markerSummary`],
    ["finalHeadline", `${sourceKind}.finalHeadline`],
    ["raw.renderedAlertRowLabel", `${sourceKind}.raw.renderedAlertRowLabel`],
    ["raw.alertRowLabel", `${sourceKind}.raw.alertRowLabel`],
    ["raw.lightweightAlertSummary", `${sourceKind}.raw.lightweightAlertSummary`],
    ["raw.lightweightSummary", `${sourceKind}.raw.lightweightSummary`],
    ["raw.summary", `${sourceKind}.raw.summary`],
    ["raw.headline", `${sourceKind}.raw.headline`],
    ["raw.resolvedHeadline", `${sourceKind}.raw.resolvedHeadline`],
    ["raw.localizedSummary", `${sourceKind}.raw.localizedSummary`],
    ["raw.title", `${sourceKind}.raw.title`],
    ["raw.renderedMarkerSummary", `${sourceKind}.raw.renderedMarkerSummary`],
    ["raw.markerSummary", `${sourceKind}.raw.markerSummary`],
    ["raw.finalHeadline", `${sourceKind}.raw.finalHeadline`]
  ]);
  const renderedLocation = getGridlyLightweightLocationFromHeadline(rendered.value);
  if (renderedLocation && !getGridlyHeaderRailTextRejectionReason(rendered.value, activeCategory)) {
    return {
      value: renderedLocation,
      source: `${rendered.source}:parsed_location`,
      specificity: /\bnear\b|\bbetween\b/i.test(renderedLocation) ? "rendered_alert_reference" : "rendered_alert_location",
      reusedAlertSummary: isGridlyLightweightReusableAlertSummary(rendered.value),
      reusedAlertText: isGridlyLightweightReusableAlertSummary(rendered.value) ? normalizeGridlyLightweightAlertSummaryText(rendered.value) : ""
    };
  }

  if (typeof document !== "undefined") {
    const domSample = getGridlyRenderedAlertTextSamples(4, { includeMetadata: true, activeCategory })
      .find((sample) => getGridlyLightweightLocationFromHeadline(sample?.text) && !getGridlyHeaderRailTextRejectionReason(sample?.text, activeCategory));
    const domLocation = getGridlyLightweightLocationFromHeadline(domSample?.text || "");
    if (domLocation) {
      return {
        value: domLocation,
        source: `${domSample.source || "dom.gridlyAlertRows.textContent"}:parsed_location`,
        specificity: /\bnear\b|\bbetween\b/i.test(domLocation) ? "rendered_alert_dom_reference" : "rendered_alert_dom_location",
        reusedAlertSummary: true,
        reusedAlertText: normalizeGridlyLightweightAlertSummaryText(domSample.text)
      };
    }
  }

  return { value: "", source: "", specificity: "nearby", reusedAlertSummary: false, reusedAlertText: "" };
}

function resolveGridlyLightweightActiveLocation(item = {}, sourceKind = "activeHazard", activeCategory = "") {
  const pick = (fieldDefs) => getGridlyLightweightFirstField(item, getGridlyLightweightFieldDefsForSource(fieldDefs, sourceKind));
  const label = resolveGridlyLightweightLocationLabel(item, sourceKind, activeCategory);
  const roadFieldCandidate = pick([
    ["primaryRoad", "activeHazard.primaryRoad"], ["roadName", "activeHazard.roadName"], ["road", "activeHazard.road"], ["routeName", "activeHazard.routeName"], ["route", "activeHazard.route"], ["corridor", "activeHazard.corridor"], ["highway", "activeHazard.highway"], ["nearestRoad", "activeHazard.nearestRoad"],
    ["raw.primaryRoad", "activeHazard.raw.primaryRoad"], ["raw.roadName", "activeHazard.raw.roadName"], ["raw.road", "activeHazard.raw.road"], ["raw.routeName", "activeHazard.raw.routeName"], ["raw.route", "activeHazard.raw.route"], ["raw.corridor", "activeHazard.raw.corridor"], ["raw.highway", "activeHazard.raw.highway"], ["raw.nearestRoad", "activeHazard.raw.nearestRoad"],
    ["source.primaryRoad", "activeHazard.source.primaryRoad"], ["source.roadName", "activeHazard.source.roadName"], ["source.road", "activeHazard.source.road"], ["source.routeName", "activeHazard.source.routeName"], ["source.route", "activeHazard.source.route"], ["source.corridor", "activeHazard.source.corridor"], ["source.highway", "activeHazard.source.highway"], ["source.nearestRoad", "activeHazard.source.nearestRoad"]
  ]);
  const labelIsSpecificLocation = label.value && hasGridlyTopAwarenessUsableLocationIntelligence(label.value);
  const primary = label.value && (labelIsSpecificLocation || !roadFieldCandidate.value) ? { value: label.value, source: label.source } : roadFieldCandidate;
  const refA = pick([["referenceRoadA", "activeHazard.referenceRoadA"], ["crossStreet", "activeHazard.crossStreet"], ["crossStreetA", "activeHazard.crossStreetA"], ["raw.referenceRoadA", "activeHazard.raw.referenceRoadA"], ["raw.crossStreet", "activeHazard.raw.crossStreet"], ["raw.crossStreetA", "activeHazard.raw.crossStreetA"], ["source.referenceRoadA", "activeHazard.source.referenceRoadA"], ["source.crossStreet", "activeHazard.source.crossStreet"], ["source.crossStreetA", "activeHazard.source.crossStreetA"]]);
  const refB = pick([["referenceRoadB", "activeHazard.referenceRoadB"], ["crossStreetB", "activeHazard.crossStreetB"], ["raw.referenceRoadB", "activeHazard.raw.referenceRoadB"], ["raw.crossStreetB", "activeHazard.raw.crossStreetB"], ["source.referenceRoadB", "activeHazard.source.referenceRoadB"], ["source.crossStreetB", "activeHazard.source.crossStreetB"]]);
  const direction = pick([["travelDirection", "activeHazard.travelDirection"], ["direction", "activeHazard.direction"], ["laneDirection", "activeHazard.laneDirection"], ["raw.travelDirection", "activeHazard.raw.travelDirection"], ["raw.direction", "activeHazard.raw.direction"], ["raw.laneDirection", "activeHazard.raw.laneDirection"]]);
  const distance = pick([["relativeDistance", "activeHazard.relativeDistance"], ["distanceMiles", "activeHazard.distanceMiles"], ["raw.relativeDistance", "activeHazard.raw.relativeDistance"], ["raw.distanceMiles", "activeHazard.raw.distanceMiles"]]);
  const directional = pick([["directionalLocation", "activeHazard.directionalLocation"], ["raw.directionalLocation", "activeHazard.raw.directionalLocation"]]);
  const nearby = pick([["nearbyLocationPhrase", "activeHazard.nearbyLocationPhrase"], ["localizedLocation", "activeHazard.localizedLocation"], ["localizedSpot", "activeHazard.localizedSpot"], ["locationLabel", "activeHazard.locationLabel"], ["localizedSummary", "activeHazard.localizedSummary"], ["raw.nearbyLocationPhrase", "activeHazard.raw.nearbyLocationPhrase"], ["raw.localizedLocation", "activeHazard.raw.localizedLocation"], ["raw.localizedSpot", "activeHazard.raw.localizedSpot"], ["raw.locationLabel", "activeHazard.raw.locationLabel"], ["raw.localizedSummary", "activeHazard.raw.localizedSummary"]]);

  const directionLabel = normalizeGridlyLightweightDirection(direction.value);
  const hasDistance = Boolean(distance.value);
  const distanceLabel = /^\d+(?:\.\d+)?$/.test(distance.value) ? `${Number(distance.value).toFixed(Number(distance.value) % 1 === 0 ? 0 : 1)} miles` : distance.value;
  let resolvedLocationLabel = "";
  let locationSpecificityLevel = label.specificity || "nearby";
  let lightweightLocationSourcesUsed = [];
  const useSources = (...sources) => { lightweightLocationSourcesUsed = [...new Set(sources.filter(Boolean))]; };
  if (primary.value && refA.value && refB.value && !/parsed_location/.test(primary.source)) {
    resolvedLocationLabel = `${primary.value} between ${refA.value} and ${refB.value}`;
    locationSpecificityLevel = "road_reference";
    useSources(primary.source, refA.source, refB.source);
  } else if (primary.value && refA.value && !/parsed_location/.test(primary.source)) {
    resolvedLocationLabel = `${primary.value} near ${refA.value}`;
    locationSpecificityLevel = "road_reference";
    useSources(primary.source, refA.source);
  } else if (primary.value && directionLabel && !/parsed_location/.test(primary.source)) {
    resolvedLocationLabel = `${primary.value} ${directionLabel}`;
    locationSpecificityLevel = "road_direction";
    useSources(primary.source, direction.source);
  } else if (primary.value) {
    resolvedLocationLabel = primary.value;
    locationSpecificityLevel = label.specificity || "road";
    useSources(primary.source);
  } else if (directional.value) {
    resolvedLocationLabel = directional.value;
    locationSpecificityLevel = "directional_location";
    useSources(directional.source);
  } else if (hasDistance && nearby.value) {
    resolvedLocationLabel = `${distanceLabel} from ${nearby.value}`;
    locationSpecificityLevel = "distance_place";
    useSources(distance.source, nearby.source);
  } else if (nearby.value) {
    resolvedLocationLabel = nearby.value;
    locationSpecificityLevel = "nearby_phrase";
    useSources(nearby.source);
  }

  return {
    resolvedLocationLabel,
    locationSpecificityLevel,
    directionUsed: Boolean(directionLabel && resolvedLocationLabel.includes(directionLabel)),
    distanceUsed: Boolean(hasDistance && resolvedLocationLabel.includes(distanceLabel)),
    referenceRoadUsed: Boolean((lightweightLocationSourcesUsed.includes(refA.source) && refA.value) || (lightweightLocationSourcesUsed.includes(refB.source) && refB.value) || /\bnear\b|\bbetween\b/i.test(resolvedLocationLabel)),
    lightweightLocationSourcesUsed,
    lightweightLocationSourceField: lightweightLocationSourcesUsed[0] || "",
    locationReusedAlertSummary: Boolean(label.reusedAlertSummary),
    locationReusedAlertText: label.reusedAlertText || ""
  };
}


function getGridlyActiveAwarenessTruthLayers(item = {}, detail = {}) {
  const layers = [];
  const add = (name, found, evidence = "") => {
    if (found && !layers.some((layer) => layer.name === name)) layers.push({ name, evidence });
  };
  const sourceText = normalizeGridlyLightweightCategoryValue([item?.source, item?.provider, item?.externalSource, item?.raw?.source, item?.raw?.provider, item?.reportKind].join(" "));
  const hasLocationField = Boolean(detail?.resolvedLocationLabel || detail?.lightweightLocationSourceField);
  add("gridlyNaturalState", Boolean(item?.id || item?.reportId || item?.report_id || item?.type || item?.report_type || item?.category), detail?.categorySource || "active item fields");
  add("txdotMaterialized", /txdot|texas department|roadway|highway/.test(sourceText) || Boolean(item?.txdotId || item?.raw?.txdotId || item?.eventId || item?.raw?.eventId), detail?.lightweightLocationSourceField || "materialized roadway fields");
  add("fraMaterialized", /fra|rail|crossing|train/.test(sourceText) || Boolean(item?.crossingId || item?.crossing_id || item?.raw?.crossingId), "materialized rail/crossing fields");
  add("renderedAlertDom", /dom\.|renderedAlert|alertRow|parsed_location/.test(String(detail?.lightweightLocationSourceField || detail?.reusedAlertSource || "")), detail?.lightweightLocationSourceField || detail?.reusedAlertSource || "rendered alert text");
  add("routeConsequence", Boolean(item?.routeRelevant || item?.routeImpact || item?.etaImpact || item?.routeConsequence || item?.raw?.routeRelevant), "route/commute consequence fields");
  add("materializedLocationField", hasLocationField, detail?.lightweightLocationSourceField || "location label");
  return layers;
}

function buildGridlyLightweightActiveHeadline(category = "unknown", location = {}) {
  const locationLabel = getGridlyLightweightSafeDisplayText(location?.resolvedLocationLabel);
  const hasLocation = Boolean(locationLabel);
  const preposition = hasLocation
    ? (/^(?:\d|north|south|east|west|near\b|on\b|at\b|between\b)/i.test(locationLabel) ? "" : (location?.locationSpecificityLevel === "nearby_phrase" ? "near" : "on"))
    : "nearby";
  const locationPhrase = hasLocation ? `${preposition ? ` ${preposition} ` : " "}${locationLabel}` : " nearby";
  if (category === "flooding") return `Flooding${hasLocation ? locationPhrase : " nearby"}`;
  if (category === "road closure") return `Road closure reported${locationPhrase}`;
  if (category === "debris") return `Debris in Road reported${locationPhrase}`;
  if (category === "traffic_backup") return `Traffic Backup reported${locationPhrase}`;
  if (category === "rail") return `Rail report visible${hasLocation ? ` near ${locationLabel}` : " nearby"}`;
  if (category === "crash") return `Crash reported${locationPhrase}`;
  if (category === "road work") return `Road work reported${locationPhrase}`;
  if (category === "ice") return `Ice reported${locationPhrase}`;
  if (category === "disabled vehicle") return `Disabled vehicle reported${locationPhrase}`;
  return `Active report visible${hasLocation ? ` near ${locationLabel}` : " nearby"}`;
}

function normalizeGridlyLightweightRenderedAlertText(value = "") {
  let text = getGridlyLightweightSafeDisplayText(value)
    .replace(/\s+·\s+.*$/g, " ")
    .replace(/\b\d+\s+active\s+(?:community\s+)?reports?\b.*$/gi, " ")
    .replace(/\b\d+\s+active\s+alerts?\b.*$/gi, " ")
    .replace(/\bactive\s+(?:community\s+)?reports?\b.*$/gi, " ")
    .replace(/\bactive\s+alerts?\b.*$/gi, " ")
    .replace(/\b(?:high|moderate|low|minor)\s+impact\b.*$/gi, " ")
    .replace(/\b\d+\s+(?:minutes?|hours?)\s+ago\b.*$/gi, " ")
    .replace(/\b(?:just\s+)?now\b/gi, " ")
    .replace(/\b\d+\s*[mh]\s+ago\b/gi, " ")
    .replace(/\b(?:alert|alerts|card|row|community report|active community report|movement summary|active alerts?)\b/gi, " ")
    .replace(/\s+/g, " ")
    .replace(/[.。]+$/g, "")
    .trim();
  const categoryTail = /(?:\s+|,)+(?:flooding|flood|high water|road closed|road closure|closure|closed|accident|crash|collision|wreck|debris|hazard|road hazard|construction|road work|ice|disabled vehicle|stalled vehicle)\s*$/i;
  for (let index = 0; index < 3 && categoryTail.test(text); index += 1) {
    text = text.replace(categoryTail, "").replace(/\s+/g, " ").trim();
  }
  return normalizeGridlyUserFacingRoadText(text);
}

function normalizeGridlyLightweightLocationLabelText(value = "") {
  return normalizeGridlyLightweightRenderedAlertText(value)
    .replace(/^(?:flooding|flood|high water|road closed|road closure|closure|closed|accident|crash|collision|wreck|debris|hazard|road hazard|construction|road work|ice|disabled vehicle|stalled vehicle)(?:\s+(?:reported|visible))?\s+(?:on|near|at|along|from|over|under)\s+/i, "")
    .replace(/^(?:on|near|at|along|from|over|under)\s+/i, "")
    .replace(/\s+/g, " ")
    .trim();
}

function isGridlyTopAwarenessBroadAreaLocation(value = "") {
  const text = normalizeGridlyLightweightLocationLabelText(value).toLowerCase();
  if (!text) return true;
  if (/^(?:nearby|local area|the area|across\s+[a-z .'-]+|around\s+[a-z .'-]+|near\s+[a-z .'-]+)$/i.test(text) && !/\b(?:road|rd|street|st|avenue|ave|drive|dr|lane|ln|blvd|boulevard|pkwy|parkway|hwy|highway|fm|rm|rr|sh|tx|us|ih|i-|loop|spur|cr|county road|crossing)\b/i.test(text)) return true;
  return /^(?:dayton|liberty county|ames|kenefick|plum grove|devers|cleveland|liberty)$/i.test(text);
}

function hasGridlyTopAwarenessUsableLocationIntelligence(value = "") {
  const text = normalizeGridlyLightweightLocationLabelText(value);
  if (!text || isGridlyTopAwarenessBroadAreaLocation(text)) return false;
  return /\b(?:between|at|near|on)\b.+\b(?:road|rd|street|st|avenue|ave|drive|dr|lane|ln|blvd|boulevard|pkwy|parkway|hwy|highway|fm|rm|rr|sh|tx|us|ih|i-|loop|spur|cr|county road|crossing)\b/i.test(text)
    || /\b(?:road|rd|street|st|avenue|ave|drive|dr|lane|ln|blvd|boulevard|pkwy|parkway|hwy|highway|fm|rm|rr|sh|tx|us|ih|i-|loop|spur|cr|county road|crossing)\b/i.test(text)
    || /\b(?:fm|rm|rr|sh|tx|us|ih|i-)\s*-?\d+\b/i.test(text)
    || /\b\d{2,4}\b/.test(text);
}

function classifyGridlyTopAwarenessLocationIntelligence(detail = {}) {
  const label = normalizeGridlyLightweightLocationLabelText(detail?.resolvedLocationLabel || "");
  const sources = Array.isArray(detail?.lightweightLocationSourcesUsed) ? detail.lightweightLocationSourcesUsed.slice(0, 6) : [];
  const sourceText = [detail?.lightweightLocationSourceField, ...sources].filter(Boolean).join("+");
  const hasTwoReferences = /\bbetween\b.+\band\b/i.test(label) || (sources.filter((source) => /referenceRoad|crossStreet/i.test(source)).length >= 2);
  const hasReference = Boolean(detail?.referenceRoadUsed) || /\b(?:near|at)\b/i.test(label) || /referenceRoad|crossStreet|nearestRoad/i.test(sourceText);
  let hierarchy = "generic_fallback";
  if (hasGridlyTopAwarenessUsableLocationIntelligence(label)) {
    hierarchy = hasTwoReferences ? "road_plus_two_references" : (hasReference ? "road_plus_reference" : "road_only");
  }
  return {
    label,
    usable: hierarchy !== "generic_fallback",
    hierarchy,
    specificityLevel: detail?.locationSpecificityLevel || "nearby",
    sourceField: detail?.lightweightLocationSourceField || "",
    sourcesUsed: sources
  };
}

function getGridlyTopAwarenessHeadlineLocationIntelligence(text = "", detail = {}) {
  const parsedLocation = getGridlyLightweightLocationFromHeadline(text);
  if (hasGridlyTopAwarenessUsableLocationIntelligence(parsedLocation)) {
    return {
      label: parsedLocation,
      usable: true,
      hierarchy: /\bbetween\b.+\band\b/i.test(parsedLocation) ? "road_plus_two_references" : (/\b(?:near|at)\b/i.test(parsedLocation) ? "road_plus_reference" : "road_only"),
      sourceField: "headline.parsed_location",
      sourcesUsed: []
    };
  }
  return classifyGridlyTopAwarenessLocationIntelligence(detail);
}

function buildGridlyTopAwarenessSpecificHeadlineSelection(detail = {}) {
  const empty = {
    headline: "",
    source: "",
    type: "generic_fallback",
    locationIntelligence: classifyGridlyTopAwarenessLocationIntelligence(detail),
    fallbackReason: "no_selected_awareness_detail"
  };
  if (!detail || typeof detail !== "object") return empty;
  const candidates = [];
  const addCandidate = (headline, source, type) => {
    const text = normalizeGridlyLightweightAlertSummaryText(headline);
    if (!text) return;
    const locationIntelligence = getGridlyTopAwarenessHeadlineLocationIntelligence(text, detail);
    candidates.push({ headline: text, source, type, locationIntelligence });
  };
  if (typeof buildGridlyRoadHazardTxDotStyleCandidate === "function") {
    const roadHazard = buildGridlyRoadHazardTxDotStyleCandidate(detail.item || detail);
    const roadHazardLocation = roadHazard.referenceRoadA && roadHazard.referenceRoadB
      ? `${roadHazard.road} between ${roadHazard.referenceRoadA} and ${roadHazard.referenceRoadB}`
      : (roadHazard.nearestRoadName ? `${roadHazard.road} near ${roadHazard.nearestRoadName}` : roadHazard.road);
    const resolvedRoadHazardSummary = roadHazard.hazard === "Other Hazard" && roadHazardLocation
      ? buildGridlyLightweightSummaryFromResolvedDetail({ ...detail, resolvedLocationLabel: roadHazardLocation })
      : { value: roadHazard.text, source: roadHazard.source };
    addCandidate(resolvedRoadHazardSummary.value, resolvedRoadHazardSummary.source || roadHazard.source || "roadHazard.txdotStyle", "road_hazard_location_headline");
  }
  if (typeof buildGridlyCrossingAlertCandidate === "function") {
    const crossing = buildGridlyCrossingAlertCandidate(detail.item || detail);
    addCandidate(crossing.text, crossing.source || "crossing.locationFields", "crossing_location_headline");
  }
  addCandidate(detail.reusedAlertText || detail.locationReusedAlertText, detail.reusedAlertSource || detail.lightweightLocationSourceField || "lightweightActiveAwareness.reusedAlertText", "reused_alert_location_headline");
  const resolvedSummary = buildGridlyLightweightSummaryFromResolvedDetail(detail);
  addCandidate(resolvedSummary.value, resolvedSummary.source, "resolved_location_headline");

  const selected = candidates.find((candidate) => candidate.locationIntelligence?.usable && isGridlyLightweightReusableAlertSummary(candidate.headline));
  if (selected) {
    return { ...selected, fallbackReason: "" };
  }
  return {
    ...empty,
    locationIntelligence: classifyGridlyTopAwarenessLocationIntelligence(detail),
    fallbackReason: candidates.length ? "candidate_headlines_lacked_usable_location_intelligence" : "no_location_headline_candidates_available"
  };
}

function normalizeGridlyLightweightAlertSummaryText(value = "") {
  return normalizeGridlyLightweightRenderedAlertText(value);
}

function isGridlyLightweightReusableAlertSummary(value = "") {
  const text = normalizeGridlyLightweightAlertSummaryText(value);
  if (!text || text.length < 5 || text.length > 140) return false;
  if (/^(active|reported|watch|live|cleared|route relevant|location pending|nearby|just now)$/i.test(text)) return false;
  if (/^(road hazard|hazard|alert|mobility\s+report|active report)(?:\s+reported|\s+visible)?$/i.test(text)) return false;
  if (/\b(?:report active|reported|visible)\s+nearby$/i.test(text)) return false;
  if (/^(?:no active|local movement looks quiet|community pulse is quiet|town moving normally)/i.test(text)) return false;
  if (/^(?:near|on|at|between|along|from|over|under)\b/i.test(text) && !/\b(?:flood|high water|closure|closed|debris|crash|wreck|collision|rail|crossing|work|construction|ice|disabled|stalled|hazard|report)\b/i.test(text)) return false;
  return /\b(?:on|near|at|between|along|from|over|under|nb|sb|eb|wb|fm|tx|sh|us|ih|i-\d|road|street|st|avenue|ave|drive|dr|lane|ln|county|corridor)\b/i.test(text)
    || /\b\d{2,4}\b/.test(text);
}

function getGridlyLightweightTitleCaseCategory(category = "") {
  const label = getGridlyLightweightCategoryLabel(category);
  if (!label || label === "unknown") return "";
  return label.charAt(0).toUpperCase() + label.slice(1);
}

function buildGridlyLightweightSummaryFromResolvedDetail(detail = {}) {
  const category = getGridlyLightweightTitleCaseCategory(detail.resolvedCategory);
  const locationLabel = normalizeGridlyLightweightLocationLabelText(detail.resolvedLocationLabel);
  if (!category || !locationLabel) return { value: "", source: "" };
  const preposition = /^(?:near|on|at|between|along|from|over|under)\b/i.test(locationLabel) ? "" : "on ";
  const value = isGridlyRailOrCrossingCategory(detail.resolvedCategory)
    ? `Train blocking crossing ${preposition}${locationLabel}`
    : `${category} ${preposition}${locationLabel}`;
  return { value, source: "lightweightActiveAwareness.resolvedCategory+resolvedLocationLabel" };
}

function isGridlyRailOrCrossingCategory(category = "") {
  return /(?:^|\b)(rail|crossing|train)(?:\b|$)/i.test(normalizeGridlyLightweightCategoryValue(category));
}

function isGridlyRoadHazardCategory(category = "") {
  const normalized = normalizeGridlyLightweightCategoryValue(category);
  return /flood|standing water|high water|closure|closed|road closure|crash|wreck|collision|accident|hazard|debris|tree|obstruction|ice|slick|disabled|stalled|construction|road work|utility|maintenance/.test(normalized)
    && !isGridlyRailOrCrossingCategory(normalized);
}

function getGridlyHeaderRailTextRejectionReason(text = "", activeCategory = "") {
  if (!isGridlyRoadHazardCategory(activeCategory)) return "";
  const normalized = normalizeGridlyLightweightAlertSummaryText(text).toLowerCase();
  if (/\btrain blocking\b/.test(normalized)) return "rail_text_for_road_hazard_train_blocking";
  if (/\bcrossing blocked\b|\bblocked crossing\b/.test(normalized)) return "rail_text_for_road_hazard_crossing_blocked";
  if (/\brail(?:road)?\b/.test(normalized)) return "rail_text_for_road_hazard_rail";
  return "";
}


function isGridlyAlertRailOrCrossingRelated(alert = {}) {
  const reportKind = normalizeGridlyLightweightCategoryValue(alert?.reportKind || alert?.report_kind || alert?.kind || "");
  const categoryText = normalizeGridlyLightweightCategoryValue([
    alert?.normalizedCategory,
    alert?.category,
    alert?.reportCategory,
    alert?.type,
    alert?.reportType,
    alert?.report_type,
    alert?.incidentType,
    alert?.hazardTypeLabel,
    alert?.typeLabel,
    alert?.title,
    alert?.headline,
    alert?.resolvedHeadline,
    alert?.localizedSummary
  ].filter(Boolean).join(" "));
  if (reportKind === "crossing" || reportKind === "rail") return true;
  if (String(alert?.crossingId || alert?.crossing_id || "").trim()) return true;
  const explicitRoadCategory = normalizeGridlyLightweightCategoryValue([
    alert?.normalizedCategory,
    alert?.category,
    alert?.reportCategory,
    alert?.type,
    alert?.reportType,
    alert?.report_type,
    alert?.incidentType,
    alert?.hazardTypeLabel,
    alert?.typeLabel
  ].filter(Boolean).join(" "));
  if (isGridlyRoadHazardCategory(explicitRoadCategory)) return false;
  return /\b(?:rail|railroad|train|crossing)\b/.test(categoryText);
}

function resolveGridlyLightweightReusableAlertSummary(detail = {}) {
  const item = detail?.item || {};
  const sourceKind = detail?.sourceKind || "activeItem";
  const candidates = [
    ["summary", `${sourceKind}.summary`],
    ["raw.summary", `${sourceKind}.raw.summary`],
    ["headline", `${sourceKind}.headline`],
    ["resolvedHeadline", `${sourceKind}.resolvedHeadline`],
    ["localizedSummary", `${sourceKind}.localizedSummary`],
    ["title", `${sourceKind}.title`],
    ["raw.headline", `${sourceKind}.raw.headline`],
    ["raw.resolvedHeadline", `${sourceKind}.raw.resolvedHeadline`],
    ["raw.localizedSummary", `${sourceKind}.raw.localizedSummary`],
    ["raw.title", `${sourceKind}.raw.title`],
    ["lightweightAlertSummary", `${sourceKind}.lightweightAlertSummary`],
    ["lightweightSummary", `${sourceKind}.lightweightSummary`],
    ["subtitle", `${sourceKind}.subtitle`],
    ["renderedAlertRowLabel", `${sourceKind}.renderedAlertRowLabel`],
    ["alertRowLabel", `${sourceKind}.alertRowLabel`],
    ["renderedMarkerSummary", `${sourceKind}.renderedMarkerSummary`],
    ["markerSummary", `${sourceKind}.markerSummary`],
    ["finalHeadline", `${sourceKind}.finalHeadline`],
    ["raw.lightweightAlertSummary", `${sourceKind}.raw.lightweightAlertSummary`],
    ["raw.lightweightSummary", `${sourceKind}.raw.lightweightSummary`],
    ["raw.subtitle", `${sourceKind}.raw.subtitle`],
    ["raw.renderedAlertRowLabel", `${sourceKind}.raw.renderedAlertRowLabel`],
    ["raw.finalHeadline", `${sourceKind}.raw.finalHeadline`]
  ];
  for (const [path, source] of candidates) {
    const text = normalizeGridlyLightweightAlertSummaryText(getGridlyLightweightNestedValue(item, path));
    if (!isGridlyLightweightReusableAlertSummary(text)) continue;
    if (getGridlyHeaderRailTextRejectionReason(text, detail?.resolvedCategory)) continue;
    return { value: text, source };
  }
  const resolved = buildGridlyLightweightSummaryFromResolvedDetail(detail);
  if (isGridlyLightweightReusableAlertSummary(resolved.value)) return resolved;
  return { value: "", source: "" };
}

function classifyGridlyRenderedAlertTextNode(node, text = "", activeContext = {}) {
  const tag = String(node?.tagName || "").toLowerCase();
  const className = String(node?.className || "");
  const role = String(node?.getAttribute?.("role") || "").toLowerCase();
  const hasAlertDataset = Boolean(node?.dataset?.gridlyAlertRow !== undefined || node?.dataset?.gridlyAlertSummary || node?.dataset?.gridlyAlertTitle || node?.dataset?.gridlyAlertHeadline);
  const isHeading = /^(h1|h2|h3|h4|h5|h6)$/.test(tag) || role === "heading" || /(?:^|\s)(?:section|group|panel|card)?-?(?:heading|header|title)(?:\s|$)/i.test(className);
  const containsMultipleRows = typeof node?.querySelectorAll === "function" && node.querySelectorAll(".gridly-alert-row,[data-gridly-alert-row]").length > 1;
  const railReject = getGridlyHeaderRailTextRejectionReason(text, activeContext?.activeCategory);
  if (railReject) return { type: "stale_rail_summary", rejectionReason: railReject };
  if (isHeading && !hasAlertDataset) return { type: "group_heading", rejectionReason: "heading_or_section_title" };
  if (containsMultipleRows || normalizeGridlyLightweightAlertSummaryText(text).length > 180) return { type: "generic_container", rejectionReason: "container_or_overlong_text" };
  return { type: hasAlertDataset || /(?:^|\s)gridly-alert-row(?:\s|$)/i.test(className) ? "actual_alert_item" : "generic_container", rejectionReason: hasAlertDataset ? "" : "generic_dom_text" };
}

function getGridlyRenderedAlertTextSamples(limit = 8, options = {}) {
  if (typeof document === "undefined") return [];
  const includeMetadata = Boolean(options?.includeMetadata);
  const selectors = [
    ".gridly-alert-row",
    "[data-gridly-alert-row]",
    "[data-gridly-alert-summary]",
    "[data-gridly-alert-title]",
    "[data-gridly-alert-headline]"
  ];
  const activeContext = {
    activeCategory: options?.activeCategory || options?.activeAwareness?.resolvedCategory || options?.activeAwareness?.topCategory || "",
    activeLocationLabel: options?.activeLocationLabel || options?.activeAwareness?.resolvedLocationLabel || ""
  };
  const seen = new Set();
  const samples = [];
  selectors.flatMap((selector) => Array.from(document.querySelectorAll(selector))).forEach((node) => {
    const rawText = safeDisplayText(node?.dataset?.gridlyAlertSummary || node?.dataset?.gridlyAlertTitle || node?.dataset?.gridlyAlertHeadline || node?.textContent, "");
    const text = normalizeGridlyLightweightAlertSummaryText(rawText);
    const key = text.toLowerCase();
    if (!text || seen.has(key)) return;
    seen.add(key);
    const classification = classifyGridlyRenderedAlertTextNode(node, text, activeContext);
    samples.push({
      text,
      source: node?.dataset?.gridlyAlertSummary ? "dom.data-gridly-alert-summary"
        : node?.dataset?.gridlyAlertTitle ? "dom.data-gridly-alert-title"
          : node?.dataset?.gridlyAlertHeadline ? "dom.data-gridly-alert-headline"
            : "dom.gridlyAlertRows.textContent",
      type: classification.type,
      classification: classification.type,
      rejectionReason: classification.rejectionReason || "",
      tagName: String(node?.tagName || "").toLowerCase(),
      className: String(node?.className || "").slice(0, 120)
    });
  });
  const limited = samples.slice(0, limit);
  return includeMetadata ? limited : limited.map((sample) => sample.text);
}


function isGridlyCleanRoadHazardHeadingText(value = "") {
  const text = normalizeGridlyLightweightAlertSummaryText(value);
  if (!isGridlyLightweightReusableAlertSummary(text)) return false;
  if (/\b(?:crossing blocked|blocked crossing|rail(?:road)?|train blocking)\b/i.test(text)) return false;
  if (!/\b(?:crash|collision|wreck|accident|flood|flooding|high water|road closed|closure|closed|debris|hazard|construction|road work|ice|disabled|stalled)\b/i.test(text)) return false;
  return /\b(?:on|near|at|between|along|from|over|under)\b\s+.+\b(?:tx|sh|us|ih|i-|fm|road|rd|street|st|avenue|ave|drive|dr|lane|ln|loop|spur|county|cr)\b/i.test(text)
    || /\b(?:tx|sh|us|ih|i-|fm|loop|spur)\s*-?\d+\b/i.test(text);
}

function buildGridlyRenderedRoadHazardHeadingRecord(text = "", source = "") {
  const normalizedText = normalizeGridlyLightweightAlertSummaryText(text);
  if (!isGridlyCleanRoadHazardHeadingText(normalizedText)) return null;
  const parsed = parseGridlyRoadHazardRoadsFromText(normalizedText);
  return {
    text: normalizedText,
    source: source || "dom.renderedAlertsPanelHeading",
    hazard: getGridlyRoadHazardLabel({ title: normalizedText }),
    road: parsed.road || "",
    referenceRoadA: parsed.referenceRoadA || "",
    referenceRoadB: parsed.referenceRoadB || "",
    nearestRoadName: parsed.referenceRoadA && !parsed.referenceRoadB ? parsed.referenceRoadA : ""
  };
}

function getGridlyRenderedAlertsPanelHeadingCandidate(options = {}) {
  if (typeof document === "undefined") {
    return {
      renderedAlertsPanelHeadingText: "",
      renderedRoadHazardHeadingCandidate: "",
      renderedRoadHazardHeadingSource: "",
      roadHazardTxDotStyleCandidate: null,
      rejectedCrossingCandidates: []
    };
  }
  const panel = document.querySelector("#alertsPanel, #gridlyAlertsPanel, #alertsSection:not([hidden]), .alerts-panel, [data-gridly-alerts-panel], .gridly-alerts-active") || document;
  const headingNode = panel?.querySelector?.("[data-gridly-alerts-panel-heading], .gridly-alert-headline") || null;
  const renderedAlertsPanelHeadingText = normalizeGridlyLightweightAlertSummaryText(headingNode?.textContent || "");
  const rejectedCrossingCandidates = [];
  const inspectCandidate = (text, source) => {
    const normalizedText = normalizeGridlyLightweightAlertSummaryText(text);
    if (!normalizedText) return null;
    const crossingReject = /\b(?:crossing blocked|blocked crossing|rail(?:road)?|train blocking)\b/i.test(normalizedText);
    if (crossingReject) {
      rejectedCrossingCandidates.push({ text: normalizedText, source, rejectionReason: "crossing_candidate_preserved_but_lower_priority_than_road_hazard" });
      return null;
    }
    return buildGridlyRenderedRoadHazardHeadingRecord(normalizedText, source);
  };
  const headingSource = headingNode?.dataset?.gridlyAlertsPanelHeadingSource || "dom.renderedAlertsPanelHeading.textContent";
  const headingRecord = inspectCandidate(renderedAlertsPanelHeadingText, headingSource);
  if (headingRecord) {
    return {
      renderedAlertsPanelHeadingText,
      renderedRoadHazardHeadingCandidate: headingRecord.text,
      renderedRoadHazardHeadingSource: headingRecord.source,
      roadHazardTxDotStyleCandidate: headingRecord,
      rejectedCrossingCandidates
    };
  }
  const rowSamples = getGridlyRenderedAlertTextSamples(Number(options?.limit || 8), { ...options, includeMetadata: true });
  for (const sample of rowSamples) {
    const record = inspectCandidate(sample?.text, sample?.source || "dom.renderedAlertRow.textContent");
    if (record) {
      return {
        renderedAlertsPanelHeadingText,
        renderedRoadHazardHeadingCandidate: record.text,
        renderedRoadHazardHeadingSource: record.source,
        roadHazardTxDotStyleCandidate: record,
        rejectedCrossingCandidates
      };
    }
  }
  return {
    renderedAlertsPanelHeadingText,
    renderedRoadHazardHeadingCandidate: "",
    renderedRoadHazardHeadingSource: "",
    roadHazardTxDotStyleCandidate: null,
    rejectedCrossingCandidates
  };
}

function getGridlyLightweightAlertSummarySourceFields() {
  return [
    "summary",
    "headline",
    "resolvedHeadline",
    "localizedSummary",
    "title",
    "finalHeadline",
    "subtitle",
    "lightweightAlertSummary",
    "lightweightSummary",
    "renderedAlertRowLabel",
    "alertRowLabel",
    "renderedMarkerSummary",
    "markerSummary",
    "raw.summary",
    "raw.headline",
    "raw.resolvedHeadline",
    "raw.localizedSummary",
    "raw.title",
    "raw.finalHeadline",
    "raw.subtitle",
    "raw.lightweightAlertSummary",
    "raw.lightweightSummary",
    "raw.renderedAlertRowLabel",
    "dom.gridlyAlertRows.textContent"
  ];
}

function buildGridlyHeaderCandidateFromCategoryLocation(category = "", locationLabel = "") {
  const normalizedCategory = getGridlyLightweightTitleCaseCategory(category);
  const normalizedLocation = normalizeGridlyLightweightLocationLabelText(locationLabel);
  if (!normalizedCategory || !normalizedLocation) return "";
  const preposition = /^(?:near|on|at|between|along|from|over|under)\b/i.test(normalizedLocation) ? "" : "on ";
  if (isGridlyRailOrCrossingCategory(category)) return `Train blocking crossing ${preposition}${normalizedLocation}`;
  return `${normalizedCategory} ${preposition}${normalizedLocation}`;
}

function classifyGridlyHeaderCandidate(candidate = {}, activeContext = {}) {
  const text = normalizeGridlyLightweightAlertSummaryText(candidate.text);
  if (!text) return { ...candidate, text: "", type: candidate.type || "empty", accepted: false, rejectionReason: "empty" };
  if (!isGridlyLightweightReusableAlertSummary(text)) {
    return { ...candidate, text, type: candidate.type || "generic_container", accepted: false, rejectionReason: "not_reusable_alert_summary" };
  }
  const railReject = getGridlyHeaderRailTextRejectionReason(text, activeContext.activeCategory);
  if (railReject) {
    return { ...candidate, text, type: "stale_rail_summary", accepted: false, rejectionReason: railReject };
  }
  if (candidate.type === "group_heading" || candidate.type === "generic_container") {
    return { ...candidate, text, accepted: false, rejectionReason: candidate.rejectionReason || candidate.type };
  }
  return { ...candidate, text, type: candidate.type || "actual_alert_item", accepted: true, rejectionReason: "" };
}

function resolveGridlyExistingAlertWording(options = {}) {
  let awareness = options?.activeAwareness || null;
  if (!awareness) {
    try {
      awareness = gridlyCommunityPulseAuditState?.activeAwareness || null;
    } catch (_error) {
      awareness = null;
    }
  }
  if (!awareness && typeof buildGridlyLightweightActiveAwareness === "function") {
    awareness = buildGridlyLightweightActiveAwareness(options);
  }

  const activeCategory = awareness?.resolvedCategory || awareness?.topCategory || "";
  const activeLocationLabel = safeDisplayText(awareness?.resolvedLocationLabel, "");
  const activeContext = { activeCategory, activeLocationLabel };
  const candidates = [];
  const addCandidate = (text, source, type = "actual_alert_item", metadata = {}) => {
    const normalizedText = normalizeGridlyLightweightAlertSummaryText(text);
    if (!normalizedText) return;
    candidates.push({ text: normalizedText, source, type, ...metadata });
  };

  const renderedHeadingBridge = getGridlyRenderedAlertsPanelHeadingCandidate(options);
  if (renderedHeadingBridge.renderedRoadHazardHeadingCandidate) {
    addCandidate(
      renderedHeadingBridge.renderedRoadHazardHeadingCandidate,
      renderedHeadingBridge.renderedRoadHazardHeadingSource || "dom.renderedAlertsPanelHeading",
      "road_hazard_txdot_style_candidate",
      {
        priorityReason: "already-rendered alerts panel road hazard heading outranks generic active report title",
        roadHazardTxDotStyleCandidate: renderedHeadingBridge.roadHazardTxDotStyleCandidate,
        renderedAlertsPanelHeadingText: renderedHeadingBridge.renderedAlertsPanelHeadingText
      }
    );
  }

  const activeRoadHazardItems = [
    ...(Array.isArray(options?.activeHazards) ? options.activeHazards : (Array.isArray(typeof activeHazards !== "undefined" ? activeHazards : null) ? activeHazards : [])),
    ...(Array.isArray(options?.activeReports) ? options.activeReports : (Array.isArray(typeof activeReports !== "undefined" ? activeReports : null) ? activeReports : []))
  ].filter((item) => item && typeof item === "object" && isGridlyRoadHazardCategory(resolveGridlyLightweightActiveCategory(item, "activeHazard")?.resolvedCategory || item?.category || item?.type || item?.reportType));
  activeRoadHazardItems.slice(0, 6).forEach((item, index) => {
    const roadHazardCandidate = buildGridlyRoadHazardTxDotStyleCandidate(item);
    addCandidate(roadHazardCandidate.text, roadHazardCandidate.source || `activeRoadHazards.${index}.txdotStyle`, "road_hazard_txdot_style_candidate");
  });

  const activeSamples = Array.isArray(awareness?.activeAwarenessSamples) ? awareness.activeAwarenessSamples : [];
  activeSamples.forEach((sample, index) => {
    addCandidate(sample?.reusedAlertText, sample?.reusedAlertSource || `lightweightActiveAwareness.activeAwarenessSamples.${index}.reusedAlertText`, "actual_alert_item");
    addCandidate(
      buildGridlyHeaderCandidateFromCategoryLocation(sample?.resolvedCategory, sample?.resolvedLocationLabel),
      `lightweightActiveAwareness.activeAwarenessSamples.${index}.resolvedCategory+resolvedLocationLabel`,
      "actual_alert_item"
    );
  });
  addCandidate(awareness?.reusedAlertText, awareness?.reusedAlertSource || "lightweightActiveAwareness.reusedAlertText", "actual_alert_item");
  addCandidate(awareness?.headline, "lightweightActiveAwareness.headline", "actual_alert_item");
  addCandidate(
    buildGridlyHeaderCandidateFromCategoryLocation(activeCategory, activeLocationLabel),
    "lightweightActiveAwareness.resolvedCategory+resolvedLocationLabel",
    "actual_alert_item"
  );

  getGridlyRenderedAlertTextSamples(Number(options?.limit || 6), { includeMetadata: true, activeAwareness: awareness, activeCategory, activeLocationLabel })
    .forEach((sample) => {
      candidates.push({
        text: sample.text,
        source: sample.source || "dom.gridlyAlertRows.textContent",
        type: sample.type || sample.classification || "generic_container",
        rejectionReason: sample.rejectionReason || ""
      });
    });

  const seen = new Set();
  const rejectedHeaderCandidates = [];
  for (const rawCandidate of candidates) {
    const classified = classifyGridlyHeaderCandidate(rawCandidate, activeContext);
    const key = `${classified.source}:${classified.text}`.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    if (classified.accepted) {
      return {
        available: true,
        text: classified.text,
        source: classified.source || "lightweightActiveAwareness",
        type: classified.type || "actual_alert_item",
        selectedHeaderCandidate: classified.text,
        selectedHeaderCandidateSource: classified.source || "lightweightActiveAwareness",
        selectedHeaderCandidateType: classified.type || "actual_alert_item",
        rejectedHeaderCandidates,
        rejectedCrossingCandidates: renderedHeadingBridge.rejectedCrossingCandidates || [],
        rejectedRailFallbackReason: (rejectedHeaderCandidates.find((candidate) => /rail_text_for_road_hazard|stale_rail/i.test(candidate.rejectionReason || candidate.type || "")) || {}).rejectionReason || "",
        renderedAlertsPanelHeadingText: renderedHeadingBridge.renderedAlertsPanelHeadingText || "",
        renderedRoadHazardHeadingCandidate: renderedHeadingBridge.renderedRoadHazardHeadingCandidate || "",
        renderedRoadHazardHeadingSource: renderedHeadingBridge.renderedRoadHazardHeadingSource || "",
        roadHazardTxDotStyleCandidate: classified.roadHazardTxDotStyleCandidate || renderedHeadingBridge.roadHazardTxDotStyleCandidate || null,
        alertsPanelHeadingPriorityReason: classified.priorityReason || "first accepted header candidate",
        activeCategory,
        activeLocationLabel,
        activeAwareness: awareness
      };
    }
    rejectedHeaderCandidates.push({
      text: classified.text,
      source: classified.source || "",
      type: classified.type || "",
      rejectionReason: classified.rejectionReason || "rejected"
    });
  }
  return {
    available: false,
    text: "",
    source: "",
    type: "",
    selectedHeaderCandidate: "",
    selectedHeaderCandidateSource: "",
    selectedHeaderCandidateType: "",
    rejectedHeaderCandidates,
    rejectedCrossingCandidates: renderedHeadingBridge.rejectedCrossingCandidates || [],
    rejectedRailFallbackReason: (rejectedHeaderCandidates.find((candidate) => /rail_text_for_road_hazard|stale_rail/i.test(candidate.rejectionReason || candidate.type || "")) || {}).rejectionReason || "",
    renderedAlertsPanelHeadingText: renderedHeadingBridge.renderedAlertsPanelHeadingText || "",
    renderedRoadHazardHeadingCandidate: renderedHeadingBridge.renderedRoadHazardHeadingCandidate || "",
    renderedRoadHazardHeadingSource: renderedHeadingBridge.renderedRoadHazardHeadingSource || "",
    roadHazardTxDotStyleCandidate: renderedHeadingBridge.roadHazardTxDotStyleCandidate || null,
    alertsPanelHeadingPriorityReason: renderedHeadingBridge.renderedRoadHazardHeadingCandidate ? "rendered road hazard heading available but no header candidate accepted" : "no accepted header candidate",
    activeCategory,
    activeLocationLabel,
    activeAwareness: awareness
  };
}

function getGridlyAlertNestedTextValue(source = {}, path = "") {
  if (!source || typeof source !== "object") return "";
  const value = path.split(".").reduce((acc, key) => (acc && typeof acc === "object" ? acc[key] : undefined), source);
  return normalizeGridlyLightweightAlertSummaryText(value);
}

function getGridlyAlertFirstTextValue(alert = {}, paths = []) {
  for (const path of paths) {
    const text = getGridlyAlertNestedTextValue(alert, path);
    if (text) return text;
  }
  return "";
}

function getGridlyRoadHazardLabel(alert = {}) {
  const otherHazardSubtype = resolveOtherHazardSubtypeFromRecord(alert);
  if (otherHazardSubtype) return getOtherHazardSubtypeLabel(otherHazardSubtype);
  const text = normalizeGridlyLightweightCategoryValue([
    alert?.hazardTypeLabel,
    alert?.typeLabel,
    alert?.type,
    alert?.reportType,
    alert?.report_type,
    alert?.category,
    alert?.title,
    alert?.headline,
    alert?.resolvedHeadline,
    alert?.localizedSummary,
    alert?.finalHeadline,
    alert?.raw?.hazardTypeLabel,
    alert?.raw?.typeLabel,
    alert?.raw?.type,
    alert?.raw?.reportType,
    alert?.raw?.report_type,
    alert?.raw?.title
  ].filter(Boolean).join(" "));
  if (/flood|standing water|high water/.test(text)) return "Flooding";
  if (/crash|collision|wreck|accident/.test(text)) return "Crash / Wreck";
  if (/road[_\s-]*closed|closure|closed/.test(text)) return "Road closed";
  if (/construction|work ?zone|road work|lane ?work/.test(text)) return "Construction";
  if (/debris|object|tree|obstruction/.test(text)) return "Debris in Road";
  if (/traffic|backup|congestion|heavy delay/.test(text)) return "Traffic Backup";
  if (/ice|slick/.test(text)) return "Ice";
  if (/disabled|stalled/.test(text)) return "Disabled vehicle";
  return "Other Hazard";
}

function stripGridlyRoadHazardLocationMetadata(value = "") {
  return normalizeGridlyLightweightAlertSummaryText(value)
    .replace(/\b\d+\s+active\s+(?:community\s+)?reports?\b.*$/i, "")
    .replace(/\b\d+\s+active\s+alerts?\b.*$/i, "")
    .replace(/\bactive\s+(?:community\s+)?reports?\b.*$/i, "")
    .replace(/\bactive\s+alerts?\b.*$/i, "")
    .replace(/\b(?:high|moderate|low|minor)\s+impact\b.*$/i, "")
    .replace(/\b\d+\s+(?:minutes?|hours?)\s+ago\b.*$/i, "")
    .replace(/\b(?:flooding|flood|high water|road closed|road closure|closure|closed|accident|crash|collision|wreck|debris|hazard|road hazard|construction|road work|ice|disabled vehicle|stalled vehicle)\b\s*$/i, "")
    .replace(/[|•·].*$/g, "")
    .replace(/[.,;:]+$/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeGridlyRoadHazardRoadComponent(value = "") {
  const cleaned = stripGridlyRoadHazardLocationMetadata(value)
    .replace(/^(?:on|near|at|between)\s+/i, "")
    .replace(/\s+\b(?:between|near|at)\b.*$/i, "")
    .trim();
  const evaluated = evaluateRoadNameCandidate(cleaned);
  return evaluated.valid ? normalizeRoadDisplayCase(evaluated.normalized) : "";
}

function isGridlyBroadHighwayReference(value = "") {
  return /^(?:US|SH|TX|I-|IH|FM|Loop|Spur)\s*-?\d+/i.test(normalizeRoadDisplayCase(value));
}

function areGridlyRoadHazardRoadsEquivalent(left = "", right = "") {
  const a = normalizeRoadComparison(left);
  const b = normalizeRoadComparison(right);
  if (!a || !b) return false;
  if (a === b) return true;
  return a.includes(b) || b.includes(a);
}

function pushGridlyRoadHazardReferenceRoad(refs, value = "", primaryRoad = "", source = "") {
  const road = normalizeGridlyRoadHazardRoadComponent(value);
  if (!road || areGridlyRoadHazardRoadsEquivalent(road, primaryRoad)) return;
  if (refs.some((entry) => areGridlyRoadHazardRoadsEquivalent(entry.road, road))) return;
  refs.push({ road, source, broad: isGridlyBroadHighwayReference(road) });
}

function parseGridlyRoadHazardRoadsFromText(value = "") {
  const text = stripGridlyRoadHazardLocationMetadata(value);
  const betweenMatch = text.match(/\bon\s+(.+?)\s+between\s+(.+?)\s+and\s+(.+?)(?:$|[.,;:])/i);
  if (betweenMatch) {
    return {
      road: normalizeGridlyRoadHazardRoadComponent(betweenMatch[1]),
      referenceRoadA: normalizeGridlyRoadHazardRoadComponent(betweenMatch[2]),
      referenceRoadB: normalizeGridlyRoadHazardRoadComponent(betweenMatch[3])
    };
  }
  const nearMatch = text.match(/\bon\s+(.+?)\s+near\s+(.+?)(?:$|[.,;:])/i);
  if (nearMatch) {
    return {
      road: normalizeGridlyRoadHazardRoadComponent(nearMatch[1]),
      referenceRoadA: normalizeGridlyRoadHazardRoadComponent(nearMatch[2]),
      referenceRoadB: ""
    };
  }
  const roadMatch = text.match(/\bon\s+(.+?)(?:$|[.,;:])/i);
  return { road: roadMatch ? normalizeGridlyRoadHazardRoadComponent(roadMatch[1]) : "", referenceRoadA: "", referenceRoadB: "" };
}

function buildGridlyRoadHazardTxDotStyleCandidate(alert = {}) {
  const empty = { text: "", source: "", hazard: "", road: "", referenceRoadA: "", referenceRoadB: "", nearestRoadName: "" };
  if (!alert || typeof alert !== "object") return empty;
  if (isGridlyAlertRailOrCrossingRelated(alert)) return { ...empty, source: "rail_or_crossing" };
  const hazard = getGridlyRoadHazardLabel(alert);
  const renderedText = getGridlyAlertFirstTextValue(alert, [
    "resolvedHeadline",
    "finalHeadline",
    "segmentHeadline",
    "localizedSummary",
    "summary",
    "title",
    "raw.resolvedHeadline",
    "raw.finalHeadline",
    "raw.segmentHeadline",
    "raw.localizedSummary",
    "raw.summary",
    "raw.title",
    "source.resolvedHeadline",
    "source.finalHeadline",
    "source.segmentHeadline",
    "source.localizedSummary",
    "source.summary",
    "source.title"
  ]);
  const parsedRendered = parseGridlyRoadHazardRoadsFromText(renderedText);
  const road = normalizeGridlyRoadHazardRoadComponent(getGridlyAlertFirstTextValue(alert, [
    "primaryRoad",
    "parsedPrimaryRoad",
    "roadName",
    "corridorLabel",
    "displayRoadName",
    "corridor",
    "route",
    "titleRoad",
    "raw.primaryRoad",
    "raw.parsedPrimaryRoad",
    "raw.roadName",
    "raw.corridorLabel",
    "raw.displayRoadName",
    "raw.corridor",
    "raw.route",
    "source.primaryRoad",
    "source.parsedPrimaryRoad",
    "source.roadName",
    "source.corridorLabel",
    "source.displayRoadName",
    "source.corridor",
    "source.route"
  ]) || parsedRendered.road);
  if (!road) return { ...empty, source: "missing_road", hazard };

  const refs = [];
  pushGridlyRoadHazardReferenceRoad(refs, getGridlyAlertFirstTextValue(alert, [
    "referenceRoadA",
    "crossStreetA",
    "crossStreet1",
    "fromStreet",
    "startStreet",
    "parsedCrossRoad",
    "raw.referenceRoadA",
    "raw.crossStreetA",
    "raw.crossStreet1",
    "raw.fromStreet",
    "raw.startStreet",
    "raw.parsedCrossRoad",
    "source.referenceRoadA",
    "source.crossStreetA",
    "source.crossStreet1",
    "source.fromStreet",
    "source.startStreet",
    "source.parsedCrossRoad"
  ]), road, "referenceRoadA");
  pushGridlyRoadHazardReferenceRoad(refs, getGridlyAlertFirstTextValue(alert, [
    "referenceRoadB",
    "crossStreetB",
    "crossStreet2",
    "toStreet",
    "endStreet",
    "raw.referenceRoadB",
    "raw.crossStreetB",
    "raw.crossStreet2",
    "raw.toStreet",
    "raw.endStreet",
    "source.referenceRoadB",
    "source.crossStreetB",
    "source.crossStreet2",
    "source.toStreet",
    "source.endStreet"
  ]), road, "referenceRoadB");
  pushGridlyRoadHazardReferenceRoad(refs, getGridlyAlertFirstTextValue(alert, [
    "nearestRoadName",
    "nearestRoad",
    "knownLocation",
    "nearbyRoad",
    "nearbyCrossStreet",
    "locationName",
    "location",
    "raw.nearestRoadName",
    "raw.nearestRoad",
    "raw.knownLocation",
    "raw.nearbyRoad",
    "raw.nearbyCrossStreet",
    "raw.locationName",
    "raw.location",
    "source.nearestRoadName",
    "source.nearestRoad",
    "source.knownLocation",
    "source.nearbyRoad",
    "source.nearbyCrossStreet",
    "source.locationName",
    "source.location"
  ]), road, "nearestRoadName");
  if (parsedRendered.referenceRoadA && parsedRendered.referenceRoadB) {
    pushGridlyRoadHazardReferenceRoad(refs, parsedRendered.referenceRoadA, road, "renderedBetween.referenceRoadA");
    pushGridlyRoadHazardReferenceRoad(refs, parsedRendered.referenceRoadB, road, "renderedBetween.referenceRoadB");
  } else if (!refs.length && parsedRendered.referenceRoadA) {
    pushGridlyRoadHazardReferenceRoad(refs, parsedRendered.referenceRoadA, road, "renderedNear.referenceRoadA");
  }

  const referenceRoadA = refs[0]?.road || "";
  const referenceRoadB = refs[1]?.road || "";
  const nearestRoadName = (refs.find((entry) => !entry.broad) || refs[0])?.road || "";
  let text = `${hazard} on ${road}`;
  let source = "roadHazard.primaryRoad";
  if (referenceRoadA && referenceRoadB) {
    text = `${hazard} on ${road} between ${referenceRoadA} and ${referenceRoadB}`;
    source = "roadHazard.primaryRoad+referenceRoadA+referenceRoadB";
  } else if (nearestRoadName) {
    text = `${hazard} on ${road} near ${nearestRoadName}`;
    source = refs.find((entry) => entry.road === nearestRoadName)?.source === "nearestRoadName" ? "roadHazard.primaryRoad+nearestRoadName" : "roadHazard.primaryRoad+referenceRoad";
  }
  return { text: normalizeGridlyLightweightAlertSummaryText(text), source, hazard, road, referenceRoadA, referenceRoadB, nearestRoadName };
}

function buildGridlyCrossingAlertCandidate(alert = {}) {
  if (!alert || typeof alert !== "object" || !isGridlyAlertRailOrCrossingRelated(alert)) return { text: "", source: "" };
  const text = getGridlyAlertFirstTextValue(alert, ["resolvedHeadline", "finalHeadline", "localizedSummary", "summary", "title", "raw.resolvedHeadline", "raw.finalHeadline", "raw.localizedSummary", "raw.summary", "raw.title"]);
  if (text) return { text, source: "crossing.alreadyRenderedCleanAlertText" };
  const road = getGridlyAlertFirstTextValue(alert, ["roadName", "primaryRoad", "crossingRoad", "raw.roadName", "raw.primaryRoad", "raw.crossingRoad"]);
  const crossing = getGridlyAlertFirstTextValue(alert, ["crossingName", "nearestRoadName", "nearestRoad", "referenceRoadA", "raw.crossingName", "raw.nearestRoadName", "raw.nearestRoad", "raw.referenceRoadA"]);
  return { text: road && crossing ? `Crossing blocked at ${road} and ${crossing}` : (road ? `Crossing blocked at ${road}` : "Rail crossing blocked"), source: "crossing.locationFields" };
}

function getGridlyAlertsPanelHeadingSeverityScore(alert = {}) {
  const severity = String(alert?.severity || alert?.severityLevel || alert?.raw?.severity || alert?.raw?.severityLevel || "moderate").toLowerCase();
  if (/critical|severe|high/.test(severity)) return 300;
  if (/moderate|medium/.test(severity)) return 200;
  if (/low|minor|watch/.test(severity)) return 100;
  return 150;
}

function getGridlyAlertsPanelHeadingPriority(alert = {}, index = 0, candidate = {}) {
  const explicit = Number(alert?.priorityScore ?? alert?.priority_score ?? alert?.priority ?? alert?.raw?.priorityScore ?? alert?.raw?.priority_score ?? alert?.__rank);
  const explicitScore = Number.isFinite(explicit) ? explicit : 0;
  const isCrossing = isGridlyAlertRailOrCrossingRelated(alert);
  const hasBetween = /\sbetween\s.+\sand\s/i.test(candidate?.text || "");
  const hasNear = /\snear\s/i.test(candidate?.text || "");
  return getGridlyAlertsPanelHeadingSeverityScore(alert) + explicitScore + (isCrossing ? 0 : 15) + (hasBetween ? 8 : hasNear ? 4 : 0) - (index * 0.001);
}

function getGridlyRankedAlertsPanelHeadingCandidates(snapshot = {}) {
  const alerts = Array.isArray(snapshot?.alerts) ? snapshot.alerts : [];
  const ranked = alerts.map((alert, index) => {
    const roadCandidate = buildGridlyRoadHazardTxDotStyleCandidate(alert);
    const crossingCandidate = buildGridlyCrossingAlertCandidate(alert);
    const isCrossing = isGridlyAlertRailOrCrossingRelated(alert);
    const candidate = roadCandidate.text ? roadCandidate : crossingCandidate;
    const priority = candidate.text ? getGridlyAlertsPanelHeadingPriority(alert, index, candidate) : -Infinity;
    return {
      index,
      text: candidate.text || "",
      source: candidate.source || "",
      type: isCrossing ? "crossing_alert_candidate" : "road_hazard_txdot_style_candidate",
      priority,
      priorityReason: `${isCrossing ? "crossing" : "road/community hazard"}; severity=${String(alert?.severity || "moderate")}; txdot=${Boolean(roadCandidate.text)}`,
      roadHazardTxDotStyleCandidate: roadCandidate.text ? roadCandidate : null,
      crossingAlertCandidate: crossingCandidate.text ? crossingCandidate : null
    };
  }).filter((entry) => entry.text);
  return ranked.sort((a, b) => Number(b.priority || 0) - Number(a.priority || 0));
}


function resolveGridlyAlertsPanelHeadingCandidate(options = {}) {
  const snapshot = options?.snapshot || null;
  const activeAwareness = options?.activeAwareness || buildGridlyLightweightActiveAwareness(options);
  const existingAlertWording = options?.existingAlertWording || resolveGridlyExistingAlertWording({ ...options, activeAwareness });
  const activeCategory = existingAlertWording?.activeCategory || activeAwareness?.resolvedCategory || activeAwareness?.topCategory || "";
  const activeLocationLabel = existingAlertWording?.activeLocationLabel || activeAwareness?.resolvedLocationLabel || "";
  const rankedActiveAlertCandidates = getGridlyRankedAlertsPanelHeadingCandidates(snapshot);
  const renderedHeadingBridge = getGridlyRenderedAlertsPanelHeadingCandidate({ ...options, activeAwareness, activeCategory, activeLocationLabel });
  if (renderedHeadingBridge.renderedRoadHazardHeadingCandidate) {
    rankedActiveAlertCandidates.unshift({
      index: -1,
      text: renderedHeadingBridge.renderedRoadHazardHeadingCandidate,
      source: renderedHeadingBridge.renderedRoadHazardHeadingSource || "dom.renderedAlertsPanelHeading",
      type: "road_hazard_txdot_style_candidate",
      priority: 10000,
      priorityReason: "already-rendered alerts panel road hazard heading bridges into active awareness/header priority",
      roadHazardTxDotStyleCandidate: renderedHeadingBridge.roadHazardTxDotStyleCandidate,
      crossingAlertCandidate: null
    });
  }
  const topRankedAlert = rankedActiveAlertCandidates[0] || null;
  const topRoadHazardCandidate = rankedActiveAlertCandidates.find((candidate) => candidate.type === "road_hazard_txdot_style_candidate") || null;
  const topCrossingCandidate = rankedActiveAlertCandidates.find((candidate) => candidate.type === "crossing_alert_candidate") || null;
  const roadHazardIsActiveTopConcern = Boolean(topRoadHazardCandidate && (Number(activeAwareness?.activeHazardCount || 0) > 0 || !topRankedAlert || topRankedAlert === topRoadHazardCandidate || Number(topRoadHazardCandidate.priority || 0) >= Number(topRankedAlert.priority || 0)));
  const candidates = [];
  const addCandidate = (text, source, type = "actual_alert_item", metadata = {}) => {
    const normalizedText = normalizeGridlyLightweightAlertSummaryText(text);
    if (normalizedText) candidates.push({ text: normalizedText, source, type, ...metadata });
  };

  if (roadHazardIsActiveTopConcern && topRoadHazardCandidate) {
    addCandidate(topRoadHazardCandidate.text, topRoadHazardCandidate.source, "road_hazard_txdot_style_candidate", topRoadHazardCandidate);
  }
  rankedActiveAlertCandidates
    .filter((candidate) => candidate !== topRoadHazardCandidate || !roadHazardIsActiveTopConcern)
    .forEach((candidate) => addCandidate(candidate.text, candidate.source, candidate.type, candidate));
  addCandidate(existingAlertWording?.selectedHeaderCandidate || existingAlertWording?.text, existingAlertWording?.selectedHeaderCandidateSource || existingAlertWording?.source || "resolveGridlyExistingAlertWording", existingAlertWording?.type || "actual_alert_item", { priorityReason: "existing reusable header wording after ranked active alert candidates" });
  addCandidate(buildGridlyHeaderCandidateFromCategoryLocation(activeCategory, activeLocationLabel), "lightweightActiveAwareness.resolvedCategory+resolvedLocationLabel", "actual_alert_item", { priorityReason: "lightweight active awareness fallback" });
  addCandidate(activeAwareness?.headline, "lightweightActiveAwareness.headline", "actual_alert_item", { priorityReason: "lightweight active awareness headline fallback" });
  addCandidate(snapshot?.commuteImpactHeadline, "alertsSurfaceSnapshot.commuteImpactHeadline", "group_heading", { priorityReason: "group heading fallback" });
  addCandidate(snapshot?.topStatus, "alertsSurfaceSnapshot.topStatus", "group_heading", { priorityReason: "snapshot top status fallback" });

  const rejectedAlertsPanelHeadingCandidates = [];
  const seen = new Set();
  for (const candidate of candidates) {
    const classified = classifyGridlyHeaderCandidate(candidate, { activeCategory, activeLocationLabel });
    const railReject = getGridlyHeaderRailTextRejectionReason(classified.text, activeCategory);
    const key = `${classified.source}:${classified.text}`.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    if (classified.accepted && !railReject) {
      return {
        text: classified.text,
        source: classified.source || "lightweightActiveAwareness",
        selectedAlertsPanelHeadingCandidate: classified.text,
        selectedAlertsPanelHeadingSource: classified.source || "lightweightActiveAwareness",
        alertsPanelHeadingPriorityReason: candidate.priorityReason || (candidate.type === "road_hazard_txdot_style_candidate" ? "highest-priority active road/community hazard selected before generic fallback" : "first accepted heading candidate"),
        activeAlertRankingSamples: rankedActiveAlertCandidates.slice(0, 6).map(({ index, text, source, type, priority, priorityReason }) => ({ index, text, source, type, priority, priorityReason })),
        renderedAlertsPanelHeadingText: renderedHeadingBridge.renderedAlertsPanelHeadingText || "",
        renderedRoadHazardHeadingCandidate: renderedHeadingBridge.renderedRoadHazardHeadingCandidate || "",
        renderedRoadHazardHeadingSource: renderedHeadingBridge.renderedRoadHazardHeadingSource || "",
        roadHazardTxDotStyleCandidate: topRoadHazardCandidate?.roadHazardTxDotStyleCandidate || renderedHeadingBridge.roadHazardTxDotStyleCandidate || null,
        crossingAlertCandidate: topCrossingCandidate?.crossingAlertCandidate || null,
        rejectedCrossingCandidates: renderedHeadingBridge.rejectedCrossingCandidates || [],
        rejectedAlertsPanelHeadingCandidates,
        rejectedRailFallbackReason: "",
        activeAwareness,
        existingAlertWording
      };
    }
    rejectedAlertsPanelHeadingCandidates.push({
      text: classified.text,
      source: classified.source || "",
      type: classified.type || candidate.type || "",
      rejectionReason: railReject || classified.rejectionReason || "rejected",
      priorityReason: candidate.priorityReason || ""
    });
  }
  const fallbackText = topRoadHazardCandidate?.text || buildGridlyHeaderCandidateFromCategoryLocation(activeCategory, activeLocationLabel) || "Active Alerts";
  const railRejection = rejectedAlertsPanelHeadingCandidates.find((candidate) => /rail_text_for_road_hazard|stale_rail/i.test(candidate.rejectionReason || candidate.type || ""));
  return {
    text: fallbackText,
    source: topRoadHazardCandidate?.source || (fallbackText === "Active Alerts" ? "alertsPanel.default" : "lightweightActiveAwareness.resolvedCategory+resolvedLocationLabel:fallback"),
    selectedAlertsPanelHeadingCandidate: fallbackText,
    selectedAlertsPanelHeadingSource: topRoadHazardCandidate?.source || "fallback",
    alertsPanelHeadingPriorityReason: topRoadHazardCandidate ? "fallback preserved highest-ranked road/community hazard wording" : "fallback after no accepted candidate",
    activeAlertRankingSamples: rankedActiveAlertCandidates.slice(0, 6).map(({ index, text, source, type, priority, priorityReason }) => ({ index, text, source, type, priority, priorityReason })),
    renderedAlertsPanelHeadingText: renderedHeadingBridge.renderedAlertsPanelHeadingText || "",
    renderedRoadHazardHeadingCandidate: renderedHeadingBridge.renderedRoadHazardHeadingCandidate || "",
    renderedRoadHazardHeadingSource: renderedHeadingBridge.renderedRoadHazardHeadingSource || "",
    roadHazardTxDotStyleCandidate: topRoadHazardCandidate?.roadHazardTxDotStyleCandidate || renderedHeadingBridge.roadHazardTxDotStyleCandidate || null,
    crossingAlertCandidate: topCrossingCandidate?.crossingAlertCandidate || null,
    rejectedCrossingCandidates: renderedHeadingBridge.rejectedCrossingCandidates || [],
    rejectedAlertsPanelHeadingCandidates,
    rejectedRailFallbackReason: railRejection?.rejectionReason || "",
    activeAwareness,
    existingAlertWording
  };
}

function getGridlyAlertsPanelAuditSnapshot(options = {}) {
  const snapshot = options?.snapshot || (typeof window !== "undefined" && typeof window.getAlertsSurfaceSnapshot === "function" ? window.getAlertsSurfaceSnapshot() : null);
  const headingCandidate = resolveGridlyAlertsPanelHeadingCandidate({ ...options, snapshot });
  const panel = typeof document !== "undefined"
    ? document.querySelector("#alertsPanel, #gridlyAlertsPanel, #alertsSection:not([hidden]), .alerts-panel, [data-gridly-alerts-panel], .gridly-alerts-active")
    : null;
  const headingNode = panel?.querySelector?.("[data-gridly-alerts-panel-heading], .gridly-alert-headline") || null;
  const itemNodes = panel ? Array.from(panel.querySelectorAll(".gridly-alert-title, [data-gridly-alert-summary], [data-gridly-alert-title], [data-gridly-alert-headline]")) : [];
  const alertsPanelItemTexts = itemNodes
    .map((node) => normalizeGridlyLightweightAlertSummaryText(node?.dataset?.gridlyAlertSummary || node?.dataset?.gridlyAlertTitle || node?.dataset?.gridlyAlertHeadline || node?.textContent || ""))
    .filter(Boolean)
    .slice(0, 12);
  return {
    alertsPanelHeadingText: normalizeGridlyLightweightAlertSummaryText(headingNode?.textContent || headingCandidate.text || ""),
    renderedAlertsPanelHeadingText: headingCandidate.renderedAlertsPanelHeadingText || normalizeGridlyLightweightAlertSummaryText(headingNode?.textContent || ""),
    renderedRoadHazardHeadingCandidate: headingCandidate.renderedRoadHazardHeadingCandidate || "",
    renderedRoadHazardHeadingSource: headingCandidate.renderedRoadHazardHeadingSource || "",
    alertsPanelItemTexts,
    selectedAlertsPanelHeadingCandidate: headingCandidate.selectedAlertsPanelHeadingCandidate || headingCandidate.text || "",
    selectedAlertsPanelHeadingSource: headingCandidate.selectedAlertsPanelHeadingSource || headingCandidate.source || "",
    alertsPanelHeadingPriorityReason: headingCandidate.alertsPanelHeadingPriorityReason || "",
    activeAlertRankingSamples: Array.isArray(headingCandidate.activeAlertRankingSamples) ? headingCandidate.activeAlertRankingSamples.slice(0, 8) : [],
    roadHazardTxDotStyleCandidate: headingCandidate.roadHazardTxDotStyleCandidate || null,
    crossingAlertCandidate: headingCandidate.crossingAlertCandidate || null,
    rejectedCrossingCandidates: Array.isArray(headingCandidate.rejectedCrossingCandidates) ? headingCandidate.rejectedCrossingCandidates.slice(0, 12) : [],
    rejectedAlertsPanelHeadingCandidates: Array.isArray(headingCandidate.rejectedAlertsPanelHeadingCandidates) ? headingCandidate.rejectedAlertsPanelHeadingCandidates.slice(0, 12) : [],
    rejectedRailFallbackReason: headingCandidate.rejectedRailFallbackReason || ""
  };
}

function getGridlyLightweightActivePriorityScore(detail = {}, index = 0) {
  const item = detail?.item || {};
  const explicitPriority = Number(item?.priorityScore ?? item?.priority_score ?? item?.priority ?? item?.raw?.priorityScore ?? item?.raw?.priority_score ?? item?.raw?.priority);
  const severity = normalizeGridlyLightweightCategoryValue(item?.severity || item?.severityLevel || item?.raw?.severity || item?.raw?.severityLevel);
  const severityScore = ({ critical: 50, high: 40, severe: 40, moderate: 30, medium: 30, low: 20, watch: 10 })[severity] || 0;
  const sourceScore = detail?.sourceKind === "activeHazard" ? 4 : 2;
  const categoryScore = detail?.resolvedCategory && detail.resolvedCategory !== "unknown" ? 1 : 0;
  const explicitScore = Number.isFinite(explicitPriority) ? Math.max(0, explicitPriority) : 0;
  return explicitScore + severityScore + sourceScore + categoryScore - (index * 0.001);
}


function normalizeGridlyTopAwarenessCountToken(value = "") {
  return normalizeGridlyLightweightAlertSummaryText(value)
    .toLowerCase()
    .replace(/\b(dayton|liberty county|community|nearby|local corridors)\b/g, " ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\b(?:at|on|near|between|and|of|the|a|an|reported|active|report|reports|hazard|issue|issues)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getGridlyTopAwarenessPolishedHeadline(value = "") {
  const text = normalizeGridlyLightweightAlertSummaryText(value);
  if (!text) return "";
  return text
    .replace(/\b([^;]{2,80}?)\s*;\s*([^;]{2,80}?)(?=$|[.,•-])/g, (match, left, right) => {
      const leftText = String(left || "").trim();
      const rightText = String(right || "").trim();
      const roadLike = /\b(?:i-?\d+|ih\s*\d+|us\s*\d+|sh\s*\d+|tx\s*\d+|fm\s*\d+|cr\s*\d+|county road|road|rd|street|st|avenue|ave|drive|dr|lane|ln|crossing)\b/i;
      return roadLike.test(leftText) && roadLike.test(rightText) ? `${leftText} at ${rightText}` : match;
    })
    .replace(/\s+/g, " ")
    .trim();
}

function isGridlyTopAwarenessMeaningfulMobilityDetail(detail = {}) {
  if (!detail || typeof detail !== "object") return false;
  if (detail.lifecycleClassification?.lifecycleStage === "expired_candidate") return false;
  const item = detail.item && typeof detail.item === "object" ? detail.item : detail;
  const state = getGridlyLightweightLifecycleState(item);
  if (state !== "active") return false;
  const text = normalizeGridlyLightweightAlertSummaryText([
    detail.resolvedCategory, detail.rawCategoryValue, detail.resolvedLocationLabel, detail.reusedAlertText,
    item?.title, item?.headline, item?.summary, item?.description, item?.detail, item?.details, item?.type, item?.report_type,
    item?.status, item?.raw?.title, item?.raw?.headline, item?.raw?.summary, item?.raw?.description, item?.raw?.type, item?.raw?.report_type
  ].filter(Boolean).join(" ")).toLowerCase();
  if (!text) return false;
  if (/\b(?:cleared|resolved|expired|historical|history|sample|audit|route intelligence|destination|eta|osrm|community pulse|conditions normal)\b/i.test(text)) return false;
  if (/\b(?:road closure|closed|closure|blocked crossing|crossing blocked|train blocking|blocked by train|flood|high water|standing water|crash|wreck|collision|accident|construction|road work|utility work|disabled vehicle|stalled vehicle|debris|tree down|obstruction|road hazard|hazard)\b/i.test(text)) return true;
  if (detail.resolvedCategory && detail.resolvedCategory !== "unknown" && detail.resolvedCategory !== "rail") return true;
  return detail.resolvedCategory === "rail" && /\b(?:blocked|blocking|stopped|train|closure|closed)\b/i.test(text);
}

function getGridlyTopAwarenessIncidentStableKey(detail = {}) {
  const item = detail?.item && typeof detail.item === "object" ? detail.item : (detail || {});
  const idFields = [
    item?.incidentId, item?.incident_id, item?.reportId, item?.report_id, item?.id, item?.uuid, item?.key,
    item?.raw?.incidentId, item?.raw?.incident_id, item?.raw?.reportId, item?.raw?.report_id, item?.raw?.id, item?.raw?.uuid
  ];
  const explicitId = idFields.find((value) => value !== undefined && value !== null && String(value).trim());
  if (explicitId !== undefined) return `id:${String(explicitId).trim().toLowerCase()}`;
  const crossingId = item?.crossingId ?? item?.crossing_id ?? item?.raw?.crossingId ?? item?.raw?.crossing_id;
  if (crossingId !== undefined && crossingId !== null && String(crossingId).trim()) {
    const type = normalizeGridlyTopAwarenessCountToken(detail.resolvedCategory || item?.type || item?.report_type || "crossing");
    return `crossing:${String(crossingId).trim().toLowerCase()}:${type || "blocked"}`;
  }
  const category = normalizeGridlyTopAwarenessCountToken(detail.resolvedCategory || item?.type || item?.report_type || item?.category || "mobility");
  const location = normalizeGridlyTopAwarenessCountToken(detail.resolvedLocationLabel || item?.locationName || item?.location || item?.roadName || item?.nearestRoadName || item?.raw?.locationName || item?.raw?.location || item?.raw?.roadName || "");
  if (category && location) return `type-location:${category}:${location}`;
  const headline = normalizeGridlyTopAwarenessCountToken(detail.reusedAlertText || item?.headline || item?.title || item?.summary || item?.description || "");
  if (headline && location) return `headline-location:${headline}:${location}`;
  if (headline) return `headline:${headline}`;
  const coords = typeof getGridlyIncidentCoordinate === "function" ? getGridlyIncidentCoordinate(item) : null;
  const fallbackText = normalizeGridlyTopAwarenessCountToken([item?.type, item?.report_type, item?.category, item?.title, item?.summary, item?.description].filter(Boolean).join(" "));
  return `fallback:${category || "mobility"}:${coords ? `${coords.lat.toFixed(4)},${coords.lng.toFixed(4)}` : (fallbackText || "unknown")}`;
}

function buildGridlyTopAwarenessDedupedMobilityCount(activeItemDetails = [], counts = {}) {
  const accepted = [];
  const suppressed = [];
  const seen = new Map();
  activeItemDetails.forEach((detail, index) => {
    const key = getGridlyTopAwarenessIncidentStableKey(detail);
    const meaningful = isGridlyTopAwarenessMeaningfulMobilityDetail(detail);
    const sample = {
      key,
      sourceKind: detail?.sourceKind || "activeItem",
      sourceIndex: Number(detail?.sourceIndex ?? index),
      resolvedCategory: detail?.resolvedCategory || "unknown",
      resolvedLocationLabel: safeDisplayText(detail?.resolvedLocationLabel, ""),
      reusedAlertText: safeDisplayText(detail?.reusedAlertText, "")
    };
    if (!meaningful) {
      suppressed.push({ ...sample, reason: "not_user_meaningful_active_mobility" });
      return;
    }
    if (seen.has(key)) {
      suppressed.push({ ...sample, reason: "duplicate_active_mobility_issue", duplicateOf: seen.get(key) });
      return;
    }
    seen.set(key, accepted.length);
    accepted.push(sample);
  });
  const count = accepted.length;
  const rawActiveAwarenessCount = Number(counts.rawActiveAwarenessCount ?? activeItemDetails.length) || 0;
  const fallbackReason = count > 0 ? "" : (rawActiveAwarenessCount > 0 ? "active_items_present_but_none_user_meaningful_after_lifecycle_and_category_filters" : "no_active_awareness_items");
  return {
    count,
    source: "deduped_user_meaningful_active_mobility",
    displayedCount: count,
    rawActiveAwarenessCount,
    activeHazardCount: Number(counts.activeHazardCount || 0),
    activeReportCount: Number(counts.activeReportCount || 0),
    alertCount: Number(counts.alertCount || 0),
    duplicateSuppressionCount: suppressed.filter((entry) => entry.reason === "duplicate_active_mobility_issue").length,
    fallbackReason,
    breakdown: {
      acceptedCount: accepted.length,
      suppressedCount: suppressed.length,
      acceptedSamples: accepted.slice(0, 12),
      suppressedSamples: suppressed.slice(0, 12)
    }
  };
}

function getGridlyLightweightItemKey(item = {}, index = 0, prefix = "item") {
  const explicit = item?.id ?? item?.reportId ?? item?.report_id ?? item?.key ?? item?.crossingId ?? item?.crossing_id;
  if (explicit !== undefined && explicit !== null && String(explicit).trim()) return `${prefix}:${String(explicit).trim()}`;
  const coords = typeof getGridlyIncidentCoordinate === "function" ? getGridlyIncidentCoordinate(item) : null;
  const type = String(item?.type || item?.report_type || item?.category || "activity").toLowerCase();
  return `${prefix}:${coords ? `${coords.lat.toFixed(4)},${coords.lng.toFixed(4)}` : "no-coords"}:${type}:${index}`;
}

function getGridlyLightweightRenderedMarkerCount() {
  const rendered = Number(lastMarkerAuditDebug?.lastMarkerRenderResult?.renderedMarkerCount);
  if (Number.isFinite(rendered)) return Math.max(0, rendered);
  const activeRendered = Number(lastMarkerAuditDebug?.activeRenderedCount);
  if (Number.isFinite(activeRendered)) return Math.max(0, activeRendered);
  const markerLayerCount = Number(lastMarkerAuditDebug?.markerLayerCount);
  return Number.isFinite(markerLayerCount) ? Math.max(0, markerLayerCount) : 0;
}

function buildGridlyLightweightActiveAwareness(options = {}) {
  const startedAt = typeof performance !== "undefined" && typeof performance.now === "function" ? performance.now() : Date.now();
  const sourceLimit = Math.max(1, Math.min(Number(options?.limit || GRIDLY_LIGHTWEIGHT_ACTIVE_AWARENESS_SOURCE_LIMIT), GRIDLY_LIGHTWEIGHT_ACTIVE_AWARENESS_SOURCE_LIMIT));
  const reportItems = Array.isArray(options?.activeReports)
    ? options.activeReports
    : (Array.isArray(typeof activeReports !== "undefined" ? activeReports : null) ? activeReports : []);
  const hazardItems = Array.isArray(options?.activeHazards)
    ? options.activeHazards
    : (Array.isArray(typeof activeHazards !== "undefined" ? activeHazards : null) ? activeHazards : []);
  const rawActiveReportItems = reportItems.slice(0, sourceLimit).filter(isGridlyLightweightActiveItem);
  const crossingAreaFilter = typeof gridlyGetCrossingReportAreaFilter === "function"
    ? gridlyGetCrossingReportAreaFilter(rawActiveReportItems, "lightweightActiveAwareness.activeReports")
    : { applied: false, pass: true, filteredOutCount: 0, filteredOutRecords: [], inSelectedArea: rawActiveReportItems, outsideSelectedArea: [], selectedMode: "unknown", selectedLabel: "" };
  const activeReportItems = rawActiveReportItems.filter((report) => !isGridlyCrossingReportRecord(report) || crossingAreaFilter.inSelectedArea.includes(report));
  const activeHazardItems = hazardItems.slice(0, sourceLimit).filter(isGridlyLightweightActiveItem);
  const seen = new Set();
  const activeItems = [];
  [
    ...activeHazardItems.map((item, index) => ({ item, index, prefix: "hazard" })),
    ...activeReportItems.map((item, index) => ({ item, index, prefix: "report" }))
  ].forEach(({ item, index, prefix }) => {
    const key = getGridlyLightweightItemKey(item, index, prefix);
    if (seen.has(key)) return;
    seen.add(key);
    activeItems.push(item);
  });

  const activeItemDetails = activeItems.map((item, index) => {
    const sourceKind = activeHazardItems.includes(item) ? "activeHazard" : "activeReport";
    const category = resolveGridlyLightweightActiveCategory(item, sourceKind);
    const location = resolveGridlyLightweightActiveLocation(item, sourceKind, category.resolvedCategory);
    const detail = { item, sourceKind, sourceIndex: index, ...category, ...location };
    const alertSummary = resolveGridlyLightweightReusableAlertSummary(detail);
    const lifecycleClassification = typeof gridlyClassifyHazardLifecycle === "function" ? gridlyClassifyHazardLifecycle(item) : null;
    const basePriorityScore = getGridlyLightweightActivePriorityScore(detail, index);
    const lifecyclePriorityAdjustment = lifecycleClassification?.lifecycleStage === "expired_candidate"
      ? -1000
      : (lifecycleClassification?.lifecycleStage === "aging" ? -18 : 0);
    return {
      ...detail,
      priorityScore: basePriorityScore + lifecyclePriorityAdjustment,
      basePriorityScore,
      lifecyclePriorityAdjustment,
      lifecycleClassification,
      lifecycleInfluencedTopAwareness: Boolean(lifecyclePriorityAdjustment),
      activeSourceTruthLayers: getGridlyActiveAwarenessTruthLayers(item, detail),
      reusedAlertSummary: Boolean(alertSummary.value || detail.locationReusedAlertSummary),
      reusedAlertSource: alertSummary.source || (detail.locationReusedAlertSummary ? detail.lightweightLocationSourceField : ""),
      reusedAlertText: alertSummary.value || detail.locationReusedAlertText || ""
    };
  });
  const topAwarenessEligibleDetails = activeItemDetails.filter((detail) => detail.lifecycleClassification?.lifecycleStage !== "expired_candidate");
  const topAwarenessMeaningfulDetails = topAwarenessEligibleDetails.filter(isGridlyTopAwarenessMeaningfulMobilityDetail);
  const topAwarenessCategoryDetails = topAwarenessMeaningfulDetails.length ? topAwarenessMeaningfulDetails : (topAwarenessEligibleDetails.length ? topAwarenessEligibleDetails : activeItemDetails);
  const categoryCounts = topAwarenessCategoryDetails.reduce((acc, detail) => {
    const category = detail.resolvedCategory || "unknown";
    acc[category] = (acc[category] || 0) + 1;
    return acc;
  }, {});
  const activeCategories = Object.entries(categoryCounts)
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .map(([category]) => category)
    .slice(0, 6);
  const topCategory = activeCategories[0] || null;
  const priorityOrderedDetails = (topAwarenessMeaningfulDetails.length ? topAwarenessMeaningfulDetails : activeItemDetails).slice().sort((a, b) => Number(b.priorityScore || 0) - Number(a.priorityScore || 0));
  const selectedActiveDetail = priorityOrderedDetails[0] || null;
  const lifecycleSuppressedDetails = activeItemDetails
    .filter((detail) => detail.lifecycleClassification?.lifecycleStage === "expired_candidate" || Number(detail.lifecyclePriorityAdjustment || 0) < 0)
    .sort((a, b) => Number(a.priorityScore || 0) - Number(b.priorityScore || 0));
  const staleCandidatesSuppressedFromTopAwareness = lifecycleSuppressedDetails.filter((detail) => detail.lifecycleClassification?.lifecycleStage === "expired_candidate").length;
  const lifecycleInfluencedTopAwareness = activeItemDetails.some((detail) => Boolean(detail.lifecycleInfluencedTopAwareness));
  const lifecycleSuppressionReason = lifecycleInfluencedTopAwareness
    ? "Read-only lifecycle scoring reduces aging and expired_candidate hazards during top-awareness selection only; map, alert panel, and Supabase records are unchanged."
    : "No aging or expired_candidate hazards influenced top-awareness selection.";
  const corridorCounts = topAwarenessCategoryDetails.reduce((acc, detail) => {
    const corridor = typeof detectGridlyCommunityCorridor === "function" ? detectGridlyCommunityCorridor(detail.item) : "Local corridors";
    if (corridor && corridor !== "Local corridors") acc[corridor] = (acc[corridor] || 0) + 1;
    return acc;
  }, {});
  const topCorridorLabel = Object.entries(corridorCounts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))[0]?.[0] || null;
  const activeHazardCount = activeHazardItems.length;
  const activeReportCount = activeReportItems.length;
  const renderedMarkerCount = getGridlyLightweightRenderedMarkerCount();
  const activeAwarenessCount = activeItems.length;
  const topAwarenessAlertCount = Array.isArray(options?.alerts)
    ? options.alerts.length
    : (Array.isArray(typeof window !== "undefined" ? window.__gridlyLatestAlertsForRender : null) ? window.__gridlyLatestAlertsForRender.length : 0);
  const topAwarenessCountAudit = buildGridlyTopAwarenessDedupedMobilityCount(activeItemDetails, {
    rawActiveAwarenessCount: activeAwarenessCount,
    activeHazardCount,
    activeReportCount,
    alertCount: topAwarenessAlertCount
  });
  const topAwarenessDedupedMobilityCount = topAwarenessCountAudit.count;
  const selectedLocation = selectedActiveDetail ? {
    resolvedLocationLabel: selectedActiveDetail.resolvedLocationLabel,
    locationSpecificityLevel: selectedActiveDetail.locationSpecificityLevel
  } : null;
  const placePhrase = selectedLocation?.resolvedLocationLabel
    ? ` near ${selectedLocation.resolvedLocationLabel}`
    : (topCorridorLabel ? ` near ${topCorridorLabel}` : " nearby");
  const reusedAlertSummary = Boolean(selectedActiveDetail?.reusedAlertSummary);
  const reusedAlertSource = selectedActiveDetail?.reusedAlertSource || "";
  const reusedAlertText = safeDisplayText(selectedActiveDetail?.reusedAlertText, "");
  const topAwarenessHeadlineSelection = buildGridlyTopAwarenessSpecificHeadlineSelection(selectedActiveDetail || {});
  const topAwarenessLocationIntelligence = topAwarenessHeadlineSelection.locationIntelligence || classifyGridlyTopAwarenessLocationIntelligence(selectedActiveDetail || {});
  const topAwarenessSpecificLocationApplied = Boolean(topAwarenessHeadlineSelection.headline && topAwarenessLocationIntelligence.usable);
  const lightweightSummaryReuseApplied = Boolean(!topAwarenessSpecificLocationApplied && reusedAlertSummary && reusedAlertText);
  const activeAwarenessSamples = priorityOrderedDetails.slice(0, 6).map((detail) => {
    const sampleLocationIntelligence = classifyGridlyTopAwarenessLocationIntelligence(detail);
    return {
      sourceKind: detail.sourceKind || "activeItem",
      sourceIndex: Number(detail.sourceIndex || 0),
      resolvedCategory: detail.resolvedCategory || "unknown",
      resolvedLocationLabel: safeDisplayText(detail.resolvedLocationLabel, ""),
      selectedLocationIntelligence: sampleLocationIntelligence,
      reusedAlertSummary: Boolean(detail.reusedAlertSummary),
      reusedAlertSource: detail.reusedAlertSource || "",
      reusedAlertText: safeDisplayText(detail.reusedAlertText, ""),
      categorySource: detail.categorySource || "none",
      locationSources: Array.isArray(detail.lightweightLocationSourcesUsed) ? detail.lightweightLocationSourcesUsed.slice(0, 6) : [],
      lightweightLocationSourceField: detail.lightweightLocationSourceField || "",
      activeSourceTruthLayers: Array.isArray(detail.activeSourceTruthLayers) ? detail.activeSourceTruthLayers.slice(0, 6) : [],
      lifecycleStage: detail.lifecycleClassification?.lifecycleStage || "unknown",
      lifecycleAgeMinutes: detail.lifecycleClassification?.lifecycleAgeMinutes ?? null,
      lifecycleRecommendedAction: detail.lifecycleClassification?.lifecycleRecommendedAction || "",
      lifecyclePriorityAdjustment: Number(detail.lifecyclePriorityAdjustment || 0)
    };
  });
  let headline = "Community Conditions Normal";
  let topAwarenessHeadlineSource = "default.noActiveAlerts";
  let topAwarenessFallbackReason = topAwarenessDedupedMobilityCount > 0 ? "generic_fallback_pending" : (topAwarenessCountAudit.fallbackReason || "no_active_awareness_items");
  if (topAwarenessDedupedMobilityCount > 0 && topAwarenessSpecificLocationApplied) {
    headline = topAwarenessHeadlineSelection.headline;
    topAwarenessHeadlineSource = topAwarenessHeadlineSelection.source || "topAwareness.locationIntelligence";
    topAwarenessFallbackReason = "";
  } else if (topAwarenessDedupedMobilityCount > 0 && lightweightSummaryReuseApplied) {
    headline = reusedAlertText;
    topAwarenessHeadlineSource = reusedAlertSource || "lightweightActiveAwareness.reusedAlertText";
    topAwarenessFallbackReason = topAwarenessHeadlineSelection.fallbackReason || "reused_alert_summary_without_specific_location";
  } else if (topAwarenessDedupedMobilityCount > 0 && selectedActiveDetail) {
    headline = buildGridlyLightweightActiveHeadline(selectedActiveDetail.resolvedCategory, selectedLocation);
    topAwarenessHeadlineSource = "lightweightActiveAwareness.category+locationFallback";
    topAwarenessFallbackReason = topAwarenessHeadlineSelection.fallbackReason || (topAwarenessLocationIntelligence.usable ? "specific_location_candidate_unavailable" : "no_usable_location_intelligence");
  } else if (topAwarenessDedupedMobilityCount > 1 && topCategory) {
    headline = `${topAwarenessDedupedMobilityCount} active mobility issues${placePhrase}`;
    topAwarenessHeadlineSource = "lightweightActiveAwareness.dedupedMobilityCountFallback";
    topAwarenessFallbackReason = topAwarenessHeadlineSelection.fallbackReason || (topAwarenessLocationIntelligence.usable ? "specific_location_candidate_unavailable" : "multiple_deduped_mobility_issues_without_single_specific_location_headline");
  }
  const subline = activeAwarenessCount > 0
    ? (topCorridorLabel ? `Community activity remains visible near ${topCorridorLabel}.` : "Active reports are limited nearby.")
    : "Community activity is quiet.";
  const dataSourceSummary = {
    activeReports: activeReportCount,
    activeHazards: activeHazardCount,
    renderedMarkerSummary: renderedMarkerCount,
    communityPulseCached: Number(gridlyCommunityPulseAuditState?.selectedCommunityCount || 0),
    routeIntelligenceSummary: Number(lastMarkerAuditDebug?.routeRelevantRenderedCount || 0),
    sourceLimit
  };
  const endedAt = typeof performance !== "undefined" && typeof performance.now === "function" ? performance.now() : Date.now();
  if (!options?.lifecycleAuditReadOnly) {
    recordGridlyActiveLocationLifecycleEvent("buildGridlyLightweightActiveAwareness", {
      resolvedCategory: selectedActiveDetail?.resolvedCategory || null,
      resolvedLocationLabel: selectedActiveDetail?.resolvedLocationLabel || "",
      lightweightLocationSourcesUsed: selectedActiveDetail?.lightweightLocationSourcesUsed || [],
      activeAwarenessCount,
      sourceLimit
    });
  }
  return {
    loaded: true,
    version: GRIDLY_COMMUNITY_ACTIVE_AWARENESS_VERSION,
    runtimeMode: "lightweight_only",
    activeAwarenessCount,
    topAwarenessCountSource: topAwarenessCountAudit.source,
    topAwarenessDisplayedCount: topAwarenessDedupedMobilityCount,
    topAwarenessRawActiveAwarenessCount: topAwarenessCountAudit.rawActiveAwarenessCount,
    topAwarenessActiveHazardCount: topAwarenessCountAudit.activeHazardCount,
    topAwarenessActiveReportCount: topAwarenessCountAudit.activeReportCount,
    topAwarenessAlertCount: topAwarenessCountAudit.alertCount,
    topAwarenessDedupedMobilityCount,
    topAwarenessCountBreakdown: topAwarenessCountAudit.breakdown,
    topAwarenessDuplicateSuppressionCount: topAwarenessCountAudit.duplicateSuppressionCount,
    topAwarenessCountFallbackReason: topAwarenessCountAudit.fallbackReason,
    activeHazardCount,
    activeReportCount,
    crossingAreaFilterApplied: Boolean(crossingAreaFilter.applied),
    crossingAreaFilterPass: Boolean(crossingAreaFilter.pass),
    crossingAreaFilteredOutCount: Number(crossingAreaFilter.filteredOutCount || 0),
    crossingAreaFilteredOutRecords: crossingAreaFilter.filteredOutRecords || [],
    activeCrossingReportsInSelectedArea: Number(crossingAreaFilter.inSelectedArea?.length || 0),
    activeCrossingReportsOutsideSelectedArea: Number(crossingAreaFilter.outsideSelectedArea?.length || 0),
    renderedMarkerCount,
    activeCategories,
    topCategory,
    topCorridorLabel,
    resolvedCategory: selectedActiveDetail?.resolvedCategory || null,
    categorySource: selectedActiveDetail?.categorySource || "none",
    resolvedLocationLabel: selectedActiveDetail?.resolvedLocationLabel || "",
    locationSpecificityLevel: selectedActiveDetail?.locationSpecificityLevel || "nearby",
    directionUsed: Boolean(selectedActiveDetail?.directionUsed),
    distanceUsed: Boolean(selectedActiveDetail?.distanceUsed),
    referenceRoadUsed: Boolean(selectedActiveDetail?.referenceRoadUsed),
    lightweightLocationSourcesUsed: selectedActiveDetail?.lightweightLocationSourcesUsed || [],
    lightweightLocationSourceField: selectedActiveDetail?.lightweightLocationSourceField || "",
    activeSourceTruthLayers: Array.isArray(selectedActiveDetail?.activeSourceTruthLayers) ? selectedActiveDetail.activeSourceTruthLayers : [],
    activeAwarenessSamples,
    alertSourceCandidates: getGridlyLightweightAlertSummarySourceFields(),
    reusedAlertSummary,
    reusedAlertSource,
    reusedAlertText,
    lightweightSummaryReuseApplied,
    headline,
    topAwarenessHeadlineSource,
    topAwarenessSpecificLocationApplied,
    topAwarenessSelectedLocationIntelligence: topAwarenessLocationIntelligence,
    topAwarenessFallbackReason,
    subline,
    lifecycleInfluencedTopAwareness,
    staleCandidatesSuppressedFromTopAwareness,
    lifecycleSuppressionReason,
    lifecycleSuppressionSamples: lifecycleSuppressedDetails.slice(0, 6).map((detail) => ({
      sourceKind: detail.sourceKind || "activeItem",
      sourceIndex: Number(detail.sourceIndex || 0),
      resolvedCategory: detail.resolvedCategory || "unknown",
      resolvedLocationLabel: safeDisplayText(detail.resolvedLocationLabel, ""),
      lifecycleStage: detail.lifecycleClassification?.lifecycleStage || "unknown",
      lifecycleReason: detail.lifecycleClassification?.lifecycleReason || "",
      lifecycleRecommendedAction: detail.lifecycleClassification?.lifecycleRecommendedAction || "",
      basePriorityScore: Number(detail.basePriorityScore || 0),
      priorityScore: Number(detail.priorityScore || 0),
      lifecyclePriorityAdjustment: Number(detail.lifecyclePriorityAdjustment || 0)
    })),
    dataSourceSummary,
    crossingRuntimeUsed: false,
    sourceJoinRuntimeUsed: false,
    heavyRuntimeUsed: false,
    auditDurationMs: Number(Math.max(0, endedAt - startedAt).toFixed(2))
  };
}

function detectGridlyCommunityCorridor(incident = {}) {
  const text = normalizeGridlyCommunityPresenceToken([
    incident?.corridor, incident?.roadName, incident?.road_name, incident?.street_name, incident?.nearest_road,
    incident?.location_name, incident?.area, incident?.title, incident?.description, incident?.detail, incident?.details,
    incident?.route, incident?.highway, incident?.crossingName
  ].join(" "));
  const detected = GRIDLY_COMMUNITY_CORRIDORS.find((corridor) => corridor.aliases.some((alias) => text.includes(alias)));
  return detected?.name || "Local corridors";
}

function getGridlyCommunitySeverityScore(severity = "low") {
  const level = String(severity || "low").toLowerCase();
  if (level === "critical") return 30;
  if (level === "high") return 24;
  if (level === "medium" || level === "moderate") return 16;
  if (level === "low") return 8;
  return 6;
}

function scoreCommunityPresenceIncident(incident = {}, options = {}) {
  const candidates = Array.isArray(options?.allCandidates) ? options.allCandidates : getGridlyCommunityPresenceCandidates(options);
  const coords = getGridlyIncidentCoordinate(incident);
  const anchor = getGridlyCommunityPresenceAnchor(options);
  const category = normalizeGridlyIncidentCategory(incident);
  const severity = getGridlyIncidentSeverity(incident, category);
  const freshness = typeof evaluateGridlyIncidentFreshness === "function" ? evaluateGridlyIncidentFreshness(incident, options?.freshnessOptions || {}) : { freshnessLevel: "unknown", freshnessScore: 24 };
  const corridor = detectGridlyCommunityCorridor(incident);
  const distanceMiles = coords ? getDistanceMiles(anchor.lat, anchor.lng, coords.lat, coords.lng) : null;
  const proximityScore = !Number.isFinite(distanceMiles) ? 6
    : distanceMiles <= 1 ? 30
      : distanceMiles <= 3 ? 24
        : distanceMiles <= 7 ? 16
          : distanceMiles <= 14 ? 8
            : 3;
  const freshnessScore = Math.round((Number(freshness?.freshnessScore || 24) / 100) * 22);
  const severityScore = getGridlyCommunitySeverityScore(severity);
  const densityRadiusMiles = Number(options?.densityRadiusMiles || 1.75);
  const nearbyCount = coords ? candidates.filter((candidate) => {
    if (candidate === incident) return false;
    const candidateCoords = getGridlyIncidentCoordinate(candidate);
    return candidateCoords && getDistanceMiles(coords.lat, coords.lng, candidateCoords.lat, candidateCoords.lng) <= densityRadiusMiles;
  }).length : 0;
  const densityScore = Math.min(20, nearbyCount * 5);
  const corridorCount = candidates.filter((candidate) => detectGridlyCommunityCorridor(candidate) === corridor).length;
  const corridorWeight = corridor === "Local corridors" ? Math.min(8, Math.max(0, corridorCount - 1) * 2) : Math.min(18, 6 + Math.max(0, corridorCount - 1) * 4);
  const communityPresenceScore = Math.round(proximityScore + freshnessScore + severityScore + densityScore + corridorWeight);
  return {
    id: getGridlyCommunityIncidentId(incident),
    incident,
    communityPresenceScore,
    proximityScore,
    freshnessScore,
    severityScore,
    densityScore,
    corridorWeight,
    corridor,
    nearbyCount,
    distanceMiles: Number.isFinite(distanceMiles) ? Number(distanceMiles.toFixed(2)) : null,
    category,
    severity,
    freshnessLevel: freshness?.freshnessLevel || "unknown",
    awarenessMode: "community"
  };
}

function buildCommunityPresencePhrases(scoredItems = []) {
  const selected = Array.isArray(scoredItems) ? scoredItems : [];
  const corridorCounts = selected.reduce((acc, item) => {
    const key = item?.corridor || "Local corridors";
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  return selected.slice(0, 8).map((item) => {
    const typeText = String(item?.category || item?.incident?.type || "activity").replace(/_/g, " ");
    const corridor = item?.corridor || "Local corridors";
    const count = Number(corridorCounts[corridor] || 0);
    if (/flood|standing water/.test(typeText) && corridor !== "Local corridors") return `Flooding activity increasing along ${corridor}`;
    if (/rail|blocked|train/.test(typeText) && count > 1) return corridor === "Local corridors" ? "Train blocking crossing reports across nearby corridors" : `Train blocking crossing reports continuing near ${corridor}`;
    if (corridor !== "Local corridors" && count > 1) return `Movement pressure building along ${corridor}`;
    return corridor === "Local corridors" ? "Light activity across nearby corridors" : `Mobility activity under watch near ${corridor}`;
  });
}

function buildCommunityPresenceDataset(options = {}) {
  // V178-RECOVERY.1 guardrail: Community Pulse must stay lightweight unless an
  // explicit future debug/feature flag re-enables heavier analysis. Keep this
  // model free of full crossing scans, boot/interaction crossing enrichment,
  // and source joins inside pulse render.
  const sourceDiagnostics = resolveGridlyCommunityPresenceSources(options);
  const candidates = sourceDiagnostics.candidates;
  const scored = candidates.map((incident) => scoreCommunityPresenceIncident(incident, { ...options, allCandidates: candidates }))
    .sort((a, b) => b.communityPresenceScore - a.communityPresenceScore);
  const selected = scored.filter((item, index) => item.communityPresenceScore >= 34 || index < Math.min(5, scored.length)).slice(0, Number(options?.limit || 12));
  const corridorIncidentCounts = scored.reduce((acc, item) => {
    const key = item?.corridor || "Local corridors";
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  const corridorSeveritySummary = scored.reduce((acc, item) => {
    const corridor = item?.corridor || "Local corridors";
    if (!acc[corridor]) acc[corridor] = { low: 0, moderate: 0, high: 0, critical: 0 };
    const severity = String(item?.severity || "low").toLowerCase() === "medium" ? "moderate" : String(item?.severity || "low").toLowerCase();
    acc[corridor][acc[corridor][severity] === undefined ? "low" : severity] += 1;
    return acc;
  }, {});
  const detectedCorridors = Object.keys(corridorIncidentCounts).filter((name) => name !== "Local corridors" || corridorIncidentCounts[name] > 0);
  const dominantCorridor = Object.entries(corridorIncidentCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || null;
  const phrases = buildCommunityPresencePhrases(selected);
  return {
    version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
    awarenessMode: "community",
    evaluatedCount: scored.length,
    selectedCommunityCount: selected.length,
    highestPresenceScore: scored.length ? scored[0].communityPresenceScore : 0,
    corridorClusterCount: Object.values(corridorIncidentCounts).filter((count) => count >= 2).length,
    nearbyIncidentCount: scored.filter((item) => Number(item.nearbyCount || 0) > 0 || (Number.isFinite(item.distanceMiles) && item.distanceMiles <= 7)).length,
    selected,
    scored,
    phrases,
    communityPhraseCount: phrases.length,
    detectedCorridors,
    corridorIncidentCounts,
    dominantCorridor,
    corridorSeveritySummary,
    candidateSourceNames: sourceDiagnostics.candidateSourceNames,
    candidateSourceCounts: sourceDiagnostics.candidateSourceCounts,
    rawCandidateSourceCounts: sourceDiagnostics.rawCandidateSourceCounts,
    rawCandidateCount: sourceDiagnostics.rawCandidateCount,
    normalizedCandidateCount: sourceDiagnostics.normalizedCandidateCount,
    skippedCandidateReasons: sourceDiagnostics.skippedCandidateReasons,
    sourceErrors: sourceDiagnostics.sourceErrors
  };
}

function getGridlyCommunityBridgeTargets() {
  if (typeof document === "undefined") return [];
  const markerPane = document.querySelector("#map .leaflet-marker-pane");
  if (!markerPane) return [];
  const selector = ".gridly-hazard-marker, [data-visual-style], [data-category], [data-incident-id]";
  return Array.from(new Set(Array.from(markerPane.querySelectorAll(selector))));
}

function gridlyApplyCommunityAwarenessDomBridge(options = {}) {
  const dataset = buildCommunityPresenceDataset(options);
  const targets = getGridlyCommunityBridgeTargets();
  const selectedById = new Map(dataset.selected.map((item) => [String(item.id), item]));
  const selectedByRoundedCoords = new Map(dataset.selected.map((item) => {
    const coords = getGridlyIncidentCoordinate(item.incident);
    return coords ? [`${coords.lat.toFixed(4)},${coords.lng.toFixed(4)}`, item] : [null, item];
  }).filter(([key]) => key));
  const matchedSelectedIds = new Set();
  let selectedDomCount = 0;
  const sampleBridgeEntries = [];
  targets.forEach((target) => {
    const datasetId = String(target?.dataset?.incidentId || target?.dataset?.id || target?.dataset?.crossingId || "");
    const lat = Number(target?.dataset?.lat || target?.getAttribute?.("data-lat"));
    const lng = Number(target?.dataset?.lng || target?.getAttribute?.("data-lng"));
    const coordKey = Number.isFinite(lat) && Number.isFinite(lng) ? `${lat.toFixed(4)},${lng.toFixed(4)}` : "";
    const selected = selectedById.get(datasetId) || selectedByRoundedCoords.get(coordKey) || null;
    if (!selected) return;
    selectedDomCount += 1;
    matchedSelectedIds.add(String(selected.id));
    target.dataset.gridlyCommunityAwareness = "true";
    target.dataset.gridlyCommunityScore = String(selected.communityPresenceScore);
    target.dataset.gridlyCommunityCorridor = selected.corridor || "Local corridors";
    target.dataset.gridlyCommunitySeverity = String(selected.severity || "low");
    target.dataset.gridlyCommunityFreshness = String(selected.freshnessLevel || "unknown");
    target.dataset.gridlyCommunityBridgeSource = GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE;
    if (sampleBridgeEntries.length < 8) {
      sampleBridgeEntries.push({
        id: selected.id,
        score: selected.communityPresenceScore,
        corridor: selected.corridor,
        severity: selected.severity,
        freshness: selected.freshnessLevel,
        bridgeSource: GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE
      });
    }
  });
  const unmatchedSelected = dataset.selected.filter((item) => !matchedSelectedIds.has(String(item.id)));
  const unmatchedSelectedSamples = unmatchedSelected.slice(0, 8).map((item) => ({
    id: item.id,
    score: item.communityPresenceScore,
    corridor: item.corridor,
    severity: item.severity,
    freshness: item.freshnessLevel
  }));
  return {
    dataset,
    targets,
    selectedDomCount,
    extractedDomCount: selectedDomCount,
    bridgeSource: GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE,
    unmatchedSelectedCount: unmatchedSelected.length,
    unmatchedSelectedSamples,
    sampleBridgeEntries
  };
}

function getGridlyAwarenessCommunityActivityItems(options = {}) {
  const optionItems = Array.isArray(options?.communityActivityItems) ? options.communityActivityItems : null;
  const sourceItems = optionItems || [
    ...(Array.isArray(activeReports) ? activeReports : []),
    ...(Array.isArray(activeHazards) ? activeHazards : [])
  ];
  const seen = new Set();
  return sourceItems.filter((item) => {
    if (!item || typeof item !== "object") return false;
    const lifecycleState = typeof getIncidentLifecycleState === "function"
      ? getIncidentLifecycleState(item)
      : String(item?.status || item?.lifecycleState || "active").toLowerCase();
    if (lifecycleState !== "active") return false;
    const key = String(item?.id || item?.reportId || item?.crossingId || item?.submittedAt || `${item?.lat || ""},${item?.lng || ""},${item?.type || ""}`);
    if (key && seen.has(key)) return false;
    if (key) seen.add(key);
    return true;
  });
}

function getGridlyAwarenessModeDiagnostics(options = {}) {
  const notes = [
    "V177.4 community presence foundation; passive awareness scoring runs independently from route overlap and Route Watch.",
    "No popup, bottom-sheet, route consequence, route DOM bridge, route-impact rendering, freshness, confidence, or TxDOT ownership paths are modified."
  ];
  const routeLatLngs = Array.isArray(options?.routeLatLngs)
    ? options.routeLatLngs
    : (typeof getRoutePolylineLatLngs === "function" ? getRoutePolylineLatLngs() : []);
  const activeRouteCoordinateCount = Array.isArray(routeLatLngs)
    ? routeLatLngs.filter((pt) => Number.isFinite(Number(pt?.lat)) && Number.isFinite(Number(pt?.lng))).length
    : 0;
  const activeRoutePresent = activeRouteCoordinateCount > 1;
  const routeHazard = activeRoutePresent
    ? (options?.routeHazardAssessment || (typeof getRouteHazardAssessmentForPath === "function"
      ? getRouteHazardAssessmentForPath(routeLatLngs)
      : (typeof getRouteHazardAssessment === "function" ? getRouteHazardAssessment() : null)))
    : null;
  const nearbyReports = Array.isArray(routeHazard?.nearbyReports) ? routeHazard.nearbyReports : [];
  const nearbyIncidentCount = nearbyReports.filter((report) => String(report?.lifecycleState || "active").toLowerCase() === "active").length;
  const activeIncidents = Array.isArray(options?.activeIncidents)
    ? options.activeIncidents
    : (typeof getActiveUnifiedIncidents === "function" ? getActiveUnifiedIncidents() : []);
  let routeRelevantIncidentCount = 0;
  if (activeRoutePresent && Array.isArray(activeIncidents)) {
    routeRelevantIncidentCount = activeIncidents.filter((incident) => {
      if (!incident || typeof incident !== "object") return false;
      if (typeof isIncidentRouteRelevant === "function" && isIncidentRouteRelevant(incident, routeHazard)) return true;
      return typeof doesGridlyIncidentImpactActiveRoute === "function" ? doesGridlyIncidentImpactActiveRoute(incident) : false;
    }).length;
  }
  const communityActivityCount = getGridlyAwarenessCommunityActivityItems(options).length;
  const communityPresence = buildCommunityPresenceDataset(options);
  const communityBridge = gridlyApplyCommunityAwarenessDomBridge(options);
  const highDensityCommunityThreshold = Number.isFinite(Number(options?.highDensityCommunityThreshold))
    ? Math.max(1, Number(options.highDensityCommunityThreshold))
    : 3;
  const nearbyCommunityActivityPresent = activeRoutePresent && nearbyIncidentCount > 0;
  const highDensityCommunityActivityPresent = activeRoutePresent && communityActivityCount >= highDensityCommunityThreshold;

  let awarenessMode = "community";
  let modeReason = "No active route coordinates detected; community awareness mode selected.";
  const communityActivityWouldElevate = Boolean(activeRoutePresent && (nearbyCommunityActivityPresent || highDensityCommunityActivityPresent));
  if (activeRoutePresent) {
    awarenessMode = "route";
    modeReason = communityActivityWouldElevate
      ? "Active route coordinates detected; route intelligence owns the active awareness mode while community presence remains available internally."
      : "Active route detected with more than one route coordinate.";
  }

  return {
    awarenessMode,
    modeReason,
    activeRoutePresent,
    activeRouteCoordinateCount,
    nearbyIncidentCount,
    routeRelevantIncidentCount,
    communityActivityCount,
    communityActivityWouldElevate,
    routeModePriorityApplied: activeRoutePresent && awarenessMode === "route",
    evaluatedCount: communityPresence.evaluatedCount,
    selectedCommunityCount: communityPresence.selectedCommunityCount,
    selectedDomCount: communityBridge.selectedDomCount,
    communityPhraseCount: communityPresence.communityPhraseCount,
    highestPresenceScore: communityPresence.highestPresenceScore,
    dominantCommunityCorridor: communityPresence.dominantCorridor,
    notes
  };
}

function getGridlyAwarenessMode(options = {}) {
  return getGridlyAwarenessModeDiagnostics(options).awarenessMode;
}

window.getGridlyAwarenessMode = getGridlyAwarenessMode;
window.getGridlyAwarenessModeDiagnostics = getGridlyAwarenessModeDiagnostics;
window.gridlyAwarenessModeAudit = function gridlyAwarenessModeAudit(options = {}) {
  const diagnostics = getGridlyAwarenessModeDiagnostics(options);
  return {
    loaded: true,
    version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
    awarenessMode: diagnostics.awarenessMode,
    selectedDomCount: diagnostics.selectedDomCount,
    evaluatedCount: diagnostics.evaluatedCount,
    communityPhraseCount: diagnostics.communityPhraseCount,
    diagnostics
  };
};
window.gridlyCommunityPresenceAudit = function gridlyCommunityPresenceAudit(options = {}) {
  try {
    const dataset = buildCommunityPresenceDataset(options);
    return {
      loaded: true,
      version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
      evaluatedCount: dataset.evaluatedCount,
      selectedCommunityCount: dataset.selectedCommunityCount,
      highestPresenceScore: dataset.highestPresenceScore,
      candidateSourceNames: dataset.candidateSourceNames,
      candidateSourceCounts: dataset.candidateSourceCounts,
      rawCandidateSourceCounts: dataset.rawCandidateSourceCounts,
      rawCandidateCount: dataset.rawCandidateCount,
      normalizedCandidateCount: dataset.normalizedCandidateCount,
      skippedCandidateReasons: dataset.skippedCandidateReasons,
      sourceErrors: dataset.sourceErrors,
      corridorClusterCount: dataset.corridorClusterCount,
      nearbyIncidentCount: dataset.nearbyIncidentCount,
      samplePresenceItems: dataset.selected.slice(0, 8).map((item) => ({
        id: item.id,
        communityPresenceScore: item.communityPresenceScore,
        corridor: item.corridor,
        severity: item.severity,
        freshnessLevel: item.freshnessLevel,
        nearbyCount: item.nearbyCount,
        distanceMiles: item.distanceMiles,
        phrase: dataset.phrases[dataset.selected.indexOf(item)] || ""
      })),
      awarenessMode: dataset.awarenessMode
    };
  } catch (error) {
    return { loaded: false, version: GRIDLY_COMMUNITY_PRESENCE_VERSION, evaluatedCount: 0, selectedCommunityCount: 0, highestPresenceScore: 0, candidateSourceNames: [], candidateSourceCounts: {}, rawCandidateCount: 0, normalizedCandidateCount: 0, skippedCandidateReasons: {}, corridorClusterCount: 0, nearbyIncidentCount: 0, samplePresenceItems: [], awarenessMode: "community", notes: [`Community presence audit fallback: ${error?.message || "unknown error"}`] };
  }
};
window.gridlyCommunityCorridorAudit = function gridlyCommunityCorridorAudit(options = {}) {
  try {
    const dataset = buildCommunityPresenceDataset(options);
    return {
      loaded: true,
      version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
      detectedCorridors: dataset.detectedCorridors,
      corridorIncidentCounts: dataset.corridorIncidentCounts,
      dominantCorridor: dataset.dominantCorridor,
      corridorSeveritySummary: dataset.corridorSeveritySummary
    };
  } catch (error) {
    return { loaded: false, version: GRIDLY_COMMUNITY_PRESENCE_VERSION, detectedCorridors: [], corridorIncidentCounts: {}, dominantCorridor: null, corridorSeveritySummary: {}, notes: [`Community corridor audit fallback: ${error?.message || "unknown error"}`] };
  }
};

const GRIDLY_COMMUNITY_PULSE_RENDER_TARGET = "#gridlyCommunityPulseSurface";
let gridlyCommunityPulseAuditState = {
  awarenessMode: "community",
  pulseVisible: false,
  renderedPulseHeadline: "",
  renderedPulseSubline: "",
  dominantCorridor: null,
  selectedCommunityCount: 0,
  communityPhraseCount: 0,
  pulseRenderTarget: GRIDLY_COMMUNITY_PULSE_RENDER_TARGET,
  pulseSuppressedReason: "not_rendered_yet",
  selectedHeadlineTemplate: "",
  selectedSublineTemplate: "",
  dominantCorridorScore: 0,
  mobilityPressureCategory: "quiet",
  blendedSignalTypes: [],
  pulseSummaryReuseApplied: false,
  pulseSummarySource: "",
  pulseSummaryText: "",
  phraseGenerationMode: "not_rendered_yet",
  repetitionAvoidanceApplied: false
};
let gridlyCommunityPulseTemplateMemory = {
  lastHeadlineTemplate: "",
  lastSublineTemplate: ""
};

function formatGridlyCommunityCount(count, singular, plural = `${singular}s`) {
  const safeCount = Math.max(0, Number(count || 0));
  return `${safeCount} ${safeCount === 1 ? singular : plural}`;
}

function getGridlyCommunityPulseCategoryLabel(category = "activity") {
  const normalized = String(category || "activity").toLowerCase().replace(/[_-]+/g, " ");
  if (/flood|standing water|high water/.test(normalized)) return "flooding";
  if (/rail|crossing|train/.test(normalized)) return "rail activity";
  if (/crash|wreck|collision/.test(normalized)) return "crash reports";
  if (/construction|utility|work/.test(normalized)) return "road work";
  if (/closure|closed/.test(normalized)) return "closure reports";
  if (/debris|tree|obstruction/.test(normalized)) return "road debris";
  return "community reports";
}

function getGridlyCommunityPulseTypeSummary(selected = []) {
  const labels = (Array.isArray(selected) ? selected : [])
    .map((item) => getGridlyCommunityPulseCategoryLabel(item?.category || item?.incident?.type || item?.incident?.report_type))
    .filter(Boolean);
  const unique = Array.from(new Set(labels));
  if (!unique.length) return "community reports";
  if (unique.length === 1) return unique[0];
  return `${unique[0]} and ${unique[1]}`;
}


function getGridlyCommunityPulseSignalType(item = {}) {
  const categoryText = String(item?.category || item?.incident?.type || item?.incident?.report_type || item?.incident?.category || "activity")
    .toLowerCase()
    .replace(/[_-]+/g, " ");
  const detailText = String([item?.incident?.title, item?.incident?.description, item?.incident?.detail, item?.incident?.details, item?.incident?.status]
    .filter(Boolean)
    .join(" "))
    .toLowerCase();
  const text = `${categoryText} ${detailText}`;
  if (/flood|standing water|high water/.test(text)) return "flooding";
  if (/rail|crossing|train|blocked crossing|stopped train/.test(text)) return "rail";
  if (/closure|closed|blocked road|road block/.test(text)) return "closure";
  if (/crash|wreck|collision|accident/.test(text)) return "crash";
  if (/construction|utility|work zone|road work/.test(text)) return "road_work";
  if (/debris|tree|obstruction/.test(text)) return "debris";
  return "mobility";
}

function getGridlyCommunityPulseSignalLabel(signalType = "mobility") {
  const labels = {
    flooding: "flooding",
    rail: "rail activity",
    closure: "closures",
    crash: "crash reports",
    road_work: "road work",
    debris: "road debris",
    mobility: "community reports"
  };
  return labels[signalType] || labels.mobility;
}

function scoreGridlyDominantCorridor(dataset = {}) {
  const scopedItems = Array.isArray(dataset.selected) && dataset.selected.length
    ? dataset.selected
    : (Array.isArray(dataset.scored) ? dataset.scored : []);
  const corridorScores = new Map();
  const ensureCorridor = (corridor) => {
    const key = corridor || "Local corridors";
    if (!corridorScores.has(key)) {
      corridorScores.set(key, {
        corridor: key,
        score: 0,
        count: 0,
        severityScore: 0,
        freshnessScore: 0,
        densityScore: 0,
        repeatActivityScore: 0,
        multiCategoryScore: 0,
        signalTypes: new Set(),
        signalCounts: {}
      });
    }
    return corridorScores.get(key);
  };
  scopedItems.forEach((item) => {
    const corridor = item?.corridor || "Local corridors";
    const bucket = ensureCorridor(corridor);
    const severity = String(item?.severity || "low").toLowerCase();
    const freshness = String(item?.freshnessLevel || "unknown").toLowerCase();
    const signalType = getGridlyCommunityPulseSignalType(item);
    const severityWeights = { critical: 34, high: 26, moderate: 17, medium: 17, low: 8 };
    const freshnessWeights = { fresh: 16, recent: 10, aging: 4, stale: -4, unknown: 2 };
    const signalWeights = { flooding: 18, rail: 14, closure: 12, crash: 10, road_work: 6, debris: 5, mobility: 4 };
    const nearbyCount = Math.max(0, Number(item?.nearbyCount || 0));
    bucket.count += 1;
    bucket.severityScore += Number(severityWeights[severity] ?? 6);
    bucket.freshnessScore += Number(freshnessWeights[freshness] ?? 2);
    bucket.densityScore += Math.min(12, nearbyCount * 3);
    bucket.signalTypes.add(signalType);
    bucket.signalCounts[signalType] = (bucket.signalCounts[signalType] || 0) + 1;
    bucket.score += Number(signalWeights[signalType] || 4);
  });
  corridorScores.forEach((bucket) => {
    const densityFromCount = Math.min(28, bucket.count * 7);
    const repeatedRail = Number(bucket.signalCounts.rail || 0) > 1 ? 12 : 0;
    const repeatedFlooding = Number(bucket.signalCounts.flooding || 0) > 1 ? 10 : 0;
    const repeatedSameSignal = Object.values(bucket.signalCounts).some((count) => Number(count || 0) > 1) ? 6 : 0;
    bucket.repeatActivityScore = repeatedRail + repeatedFlooding + repeatedSameSignal;
    bucket.multiCategoryScore = bucket.signalTypes.size > 1 ? Math.min(14, bucket.signalTypes.size * 5) : 0;
    bucket.densityScore += densityFromCount;
    bucket.score += bucket.severityScore + bucket.freshnessScore + bucket.densityScore + bucket.repeatActivityScore + bucket.multiCategoryScore;
    if (bucket.corridor === "Local corridors" && corridorScores.size > 1) bucket.score -= 6;
    bucket.score = Math.max(0, Math.round(bucket.score));
  });
  const sorted = Array.from(corridorScores.values()).sort((a, b) => b.score - a.score || b.count - a.count || String(a.corridor).localeCompare(String(b.corridor)));
  const winner = sorted[0] || { corridor: null, score: 0, count: 0, signalTypes: new Set(), signalCounts: {} };
  return {
    dominantCorridor: winner.corridor,
    dominantCorridorScore: Number(winner.score || 0),
    dominantCorridorCount: Number(winner.count || 0),
    blendedSignalTypes: Array.from(winner.signalTypes || []).filter(Boolean),
    signalCounts: { ...(winner.signalCounts || {}) },
    corridorPriorityBreakdown: sorted.map((bucket) => ({
      corridor: bucket.corridor,
      score: Number(bucket.score || 0),
      count: Number(bucket.count || 0),
      severityScore: Number(bucket.severityScore || 0),
      freshnessScore: Number(bucket.freshnessScore || 0),
      densityScore: Number(bucket.densityScore || 0),
      repeatActivityScore: Number(bucket.repeatActivityScore || 0),
      multiCategoryScore: Number(bucket.multiCategoryScore || 0),
      signalTypes: Array.from(bucket.signalTypes || [])
    }))
  };
}

function getGridlyMobilityPressureCategory({ selectedCommunityCount = 0, dominantCorridorScore = 0, activeCorridorCount = 0 } = {}) {
  const count = Number(selectedCommunityCount || 0);
  const score = Number(dominantCorridorScore || 0);
  const activeCorridors = Number(activeCorridorCount || 0);
  if (count <= 0 || score <= 0) return "quiet";
  if (score >= 125 || count >= 6 || activeCorridors >= 4) return "building";
  if (score >= 78 || count >= 3 || activeCorridors >= 2) return "elevated";
  return "light";
}

function selectGridlyCommunityPulseTemplate(templates = [], seed = 0, previousTemplateId = "") {
  const safeTemplates = Array.isArray(templates) ? templates.filter((template) => template && template.id) : [];
  if (!safeTemplates.length) return { template: null, repetitionAvoidanceApplied: false };
  const baseIndex = Math.abs(Number(seed || 0)) % safeTemplates.length;
  let selected = safeTemplates[baseIndex];
  let repetitionAvoidanceApplied = false;
  if (safeTemplates.length > 1 && selected.id === previousTemplateId) {
    selected = safeTemplates[(baseIndex + 1) % safeTemplates.length];
    repetitionAvoidanceApplied = true;
  }
  return { template: selected, repetitionAvoidanceApplied };
}

function formatGridlyCommunityPulsePlace(corridor = null, mode = "near") {
  const safeCorridor = String(corridor || "").trim();
  if (!safeCorridor || safeCorridor === "Local corridors") {
    return mode === "across" ? "across nearby corridors" : "nearby";
  }
  if (mode === "across") return `across ${safeCorridor}`;
  if (mode === "along") return `along ${safeCorridor}`;
  return `near ${safeCorridor}`;
}

function buildGridlyCommunityBlendPhrase(context = {}) {
  const signalTypes = Array.isArray(context.blendedSignalTypes) ? context.blendedSignalTypes : [];
  const corridor = context.dominantCorridor || null;
  const pressure = context.mobilityPressureCategory || "light";
  const hasMultipleSignals = signalTypes.length > 1;
  if (!hasMultipleSignals && Number(context.activeCorridorCount || 0) <= 1) return null;
  const verb = pressure === "building" ? "building" : pressure === "elevated" ? "showing" : "present";
  const templates = [
    { id: "blend_movement_slowing", text: `Movement slowing ${formatGridlyCommunityPulsePlace(corridor, corridor && corridor !== "Local corridors" ? "along" : "across")}` },
    { id: "blend_travel_pressure", text: `Travel pressure ${verb} ${formatGridlyCommunityPulsePlace(corridor, corridor && corridor !== "Local corridors" ? "along" : "across")}` },
    { id: "blend_mobility_slowdowns", text: corridor && corridor !== "Local corridors" ? `Multiple mobility slowdowns near ${corridor}` : "Multiple mobility slowdowns reported nearby" }
  ];
  return { templates, mode: hasMultipleSignals ? "blended_signals" : "corridor_density" };
}

function buildGridlyMobilityPressurePhrase(context = {}) {
  const signalTypes = Array.isArray(context.blendedSignalTypes) ? context.blendedSignalTypes : [];
  const primarySignal = signalTypes[0] || "mobility";
  const corridor = context.dominantCorridor || null;
  const corridorIsLocal = !corridor || corridor === "Local corridors";
  const count = Number(context.selectedCommunityCount || 0);
  const pressure = context.mobilityPressureCategory || "light";
  const phraseGenerationMode = signalTypes.length > 1 ? "blended_signals" : `category_${primarySignal}`;
  const blend = buildGridlyCommunityBlendPhrase(context);
  if (blend) return { templates: blend.templates, phraseGenerationMode: blend.mode };
  if (primarySignal === "flooding") {
    return { phraseGenerationMode, templates: [
      { id: "flood_increasing_along", text: `Flooding activity increasing ${formatGridlyCommunityPulsePlace(corridor, corridorIsLocal ? "across" : "along")}` },
      { id: "flood_pressure_near", text: `High-water reports shaping travel ${formatGridlyCommunityPulsePlace(corridor)}` }
    ] };
  }
  if (primarySignal === "rail") {
    return { phraseGenerationMode, templates: [
      { id: "rail_delays_continuing", text: `Train blocking crossing reports continuing ${formatGridlyCommunityPulsePlace(corridor)}` },
      { id: "rail_activity_across", text: corridorIsLocal ? "Rail activity reported across nearby corridors" : `Rail activity reported across ${corridor}` }
    ] };
  }
  if (primarySignal === "closure") {
    return { phraseGenerationMode, templates: [
      { id: "closure_movement", text: `Closures affecting movement ${formatGridlyCommunityPulsePlace(corridor)}` },
      { id: "closure_pressure", text: `Travel pressure near closure reports ${formatGridlyCommunityPulsePlace(corridor)}` }
    ] };
  }
  if (primarySignal === "crash") {
    return { phraseGenerationMode, templates: [
      { id: "crash_slowing", text: `Traffic slowing ${formatGridlyCommunityPulsePlace(corridor)}` },
      { id: "crash_pressure", text: `Traffic pressure ${pressure === "building" ? "building" : "showing"} ${formatGridlyCommunityPulsePlace(corridor, corridorIsLocal ? "across" : "near")}` }
    ] };
  }
  return { phraseGenerationMode, templates: [
    { id: "mobility_slowdowns", text: count > 1 ? "Multiple mobility slowdowns reported nearby" : `Mobility slowdown reported ${formatGridlyCommunityPulsePlace(corridor)}` },
    { id: "movement_pressure", text: `Movement pressure ${pressure === "building" ? "building" : "present"} ${formatGridlyCommunityPulsePlace(corridor, corridorIsLocal ? "across" : "near")}` }
  ] };
}

function buildGridlyCommunityPulseHeadline(context = {}) {
  const seed = Number(context.selectedCommunityCount || 0) + Number(context.dominantCorridorScore || 0) + Number(context.activeCorridorCount || 0);
  const phraseSet = buildGridlyMobilityPressurePhrase(context);
  const selected = selectGridlyCommunityPulseTemplate(phraseSet.templates, seed, gridlyCommunityPulseTemplateMemory.lastHeadlineTemplate);
  const text = selected.template?.text || "Light activity across nearby corridors";
  return {
    text,
    selectedHeadlineTemplate: selected.template?.id || "headline_fallback",
    phraseGenerationMode: phraseSet.phraseGenerationMode || "category_mobility",
    repetitionAvoidanceApplied: selected.repetitionAvoidanceApplied
  };
}

function buildGridlyCommunityPulseSubline(context = {}) {
  const signalLabels = (Array.isArray(context.blendedSignalTypes) ? context.blendedSignalTypes : [])
    .map((signalType) => getGridlyCommunityPulseSignalLabel(signalType));
  const activeCorridorCount = Number(context.activeCorridorCount || 0);
  const pressure = context.mobilityPressureCategory || "light";
  const corridor = context.dominantCorridor || null;
  const templates = [
    { id: "subline_watchful", text: pressure === "light" ? "No major mobility slowdowns nearby" : "Local signals remain active but contained" },
    { id: "subline_corridors", text: activeCorridorCount > 1 ? `${formatGridlyCommunityCount(activeCorridorCount, "active corridor")} under light watch` : `Watching ${formatGridlyCommunityPulsePlace(corridor)}` },
    { id: "subline_signals", text: signalLabels.length > 1 ? `${signalLabels.slice(0, 2).join(" + ")} blending into travel pressure` : `${signalLabels[0] || "community reports"} under local watch` }
  ];
  const seed = Number(context.dominantCorridorScore || 0) + activeCorridorCount + signalLabels.length;
  const selected = selectGridlyCommunityPulseTemplate(templates, seed, gridlyCommunityPulseTemplateMemory.lastSublineTemplate);
  return {
    text: selected.template?.text || "Light activity across nearby corridors",
    selectedSublineTemplate: selected.template?.id || "subline_fallback",
    repetitionAvoidanceApplied: selected.repetitionAvoidanceApplied
  };
}

function buildGridlyCommunityPulseModel(options = {}) {
  const awarenessDiagnostics = typeof getGridlyAwarenessModeDiagnostics === "function"
    ? getGridlyAwarenessModeDiagnostics(options)
    : { awarenessMode: "community" };
  const awarenessMode = String(awarenessDiagnostics?.awarenessMode || "community").toLowerCase();
  const dataset = buildCommunityPresenceDataset(options);
  const activeAwareness = buildGridlyLightweightActiveAwareness(options);
  const selectedCommunityCount = Number(dataset.selectedCommunityCount || 0);
  const communityAwarenessSummary = buildGridlyCommunityAwarenessIntelligenceSummary({
    ...options,
    communityActivityCount: selectedCommunityCount,
    communityActivitySource: "community_presence_dataset.selectedCommunityCount"
  });
  const communityPhraseCount = Number(dataset.communityPhraseCount || 0);
  const corridorPriority = scoreGridlyDominantCorridor(dataset);
  const dominantCorridor = corridorPriority.dominantCorridor || dataset.dominantCorridor || null;
  const pulseRenderTarget = GRIDLY_COMMUNITY_PULSE_RENDER_TARGET;
  const dominantCorridorCount = Number(corridorPriority.dominantCorridorCount || (dominantCorridor ? dataset.corridorIncidentCounts?.[dominantCorridor] : 0) || 0);
  const activeCorridorCount = Object.entries(dataset.corridorIncidentCounts || {})
    .filter(([, count]) => Number(count || 0) > 0).length;
  const fallbackTypeSummary = getGridlyCommunityPulseTypeSummary(dataset.selected);
  const blendedSignalTypes = Array.isArray(corridorPriority.blendedSignalTypes) && corridorPriority.blendedSignalTypes.length
    ? corridorPriority.blendedSignalTypes
    : (fallbackTypeSummary ? [fallbackTypeSummary] : []);
  const mobilityPressureCategory = getGridlyMobilityPressureCategory({
    selectedCommunityCount,
    dominantCorridorScore: corridorPriority.dominantCorridorScore,
    activeCorridorCount
  });
  const phraseContext = {
    dataset,
    selectedCommunityCount,
    communityPhraseCount,
    dominantCorridor,
    dominantCorridorCount,
    dominantCorridorScore: corridorPriority.dominantCorridorScore,
    activeCorridorCount,
    blendedSignalTypes,
    mobilityPressureCategory
  };
  const headlinePhrase = selectedCommunityCount > 0
    ? buildGridlyCommunityPulseHeadline(phraseContext)
    : {
        text: "Community activity is quiet",
        selectedHeadlineTemplate: "headline_quiet",
        phraseGenerationMode: "quiet",
        repetitionAvoidanceApplied: false
      };
  const sublinePhrase = selectedCommunityCount > 0
    ? buildGridlyCommunityPulseSubline(phraseContext)
    : {
        text: "No major mobility issues reported nearby.",
        selectedSublineTemplate: "subline_quiet",
        repetitionAvoidanceApplied: false
      };

  const communityAwarenessDisplay = summarizeGridlyAwarenessIntelligenceForDisplay(communityAwarenessSummary);
  let renderedPulseHeadline = safeDisplayText(communityAwarenessDisplay.headline || activeAwareness.headline || headlinePhrase.text, "Community activity is quiet");
  let renderedPulseSubline = safeDisplayText(communityAwarenessDisplay.subline || activeAwareness.subline || sublinePhrase.text, "No major disruptions nearby");
  const pulseSummaryReuseApplied = Boolean(activeAwareness.lightweightSummaryReuseApplied && activeAwareness.reusedAlertText && renderedPulseHeadline === activeAwareness.reusedAlertText);
  const pulseSummarySource = pulseSummaryReuseApplied ? activeAwareness.reusedAlertSource : "";
  const pulseSummaryText = pulseSummaryReuseApplied ? activeAwareness.reusedAlertText : "";
  const selectedHeadlineTemplate = activeAwareness.headline ? "headline_lightweight_active_awareness" : headlinePhrase.selectedHeadlineTemplate;
  const selectedSublineTemplate = activeAwareness.subline ? "subline_lightweight_active_awareness" : sublinePhrase.selectedSublineTemplate;
  const phraseGenerationMode = activeAwareness.headline ? "lightweight_active_awareness" : (headlinePhrase.phraseGenerationMode || "category_mobility");
  const repetitionAvoidanceApplied = Boolean(headlinePhrase.repetitionAvoidanceApplied || sublinePhrase.repetitionAvoidanceApplied);

  let pulseVisible = awarenessMode === "community" && Boolean(activeAwareness.loaded);
  let pulseSuppressedReason = "";
  if (awarenessMode === "route") {
    pulseVisible = false;
    pulseSuppressedReason = "route-priority suppression: active route intelligence is primary";
  } else if (awarenessMode !== "community") {
    pulseVisible = false;
    pulseSuppressedReason = `awareness mode ${awarenessMode || "unknown"} does not show Community Pulse`;
  } else if (selectedCommunityCount <= 0 && activeAwareness.activeAwarenessCount <= 0) {
    pulseSuppressedReason = "quiet lightweight active awareness state";
  }

  if (pulseVisible) {
    gridlyCommunityPulseTemplateMemory = {
      lastHeadlineTemplate: selectedHeadlineTemplate,
      lastSublineTemplate: selectedSublineTemplate
    };
  }

  return {
    awarenessMode,
    pulseVisible,
    renderedPulseHeadline,
    renderedPulseSubline,
    dominantCorridor,
    selectedCommunityCount,
    communityPhraseCount,
    pulseRenderTarget,
    pulseSuppressedReason,
    corridorIncidentCounts: dataset.corridorIncidentCounts || {},
    highestPresenceScore: Number(dataset.highestPresenceScore || 0),
    selectedHeadlineTemplate,
    selectedSublineTemplate,
    dominantCorridorScore: Number(corridorPriority.dominantCorridorScore || 0),
    mobilityPressureCategory,
    blendedSignalTypes,
    activeAwareness,
    communityAwarenessSummary,
    pulseSummaryReuseApplied,
    pulseSummarySource,
    pulseSummaryText,
    phraseGenerationMode,
    repetitionAvoidanceApplied,
    corridorPriorityBreakdown: corridorPriority.corridorPriorityBreakdown || []
  };
}

function renderGridlyCommunityPulse(options = {}) {
  // Recovery baseline guard: rendering the pulse must consume the lightweight
  // Community Presence model only. Do not run source joins inside pulse render.
  let model;
  try {
    model = buildGridlyCommunityPulseModel(options);
  } catch (error) {
    model = {
      awarenessMode: "community",
      pulseVisible: false,
      renderedPulseHeadline: "",
      renderedPulseSubline: "",
      dominantCorridor: null,
      selectedCommunityCount: 0,
      communityPhraseCount: 0,
      pulseRenderTarget: GRIDLY_COMMUNITY_PULSE_RENDER_TARGET,
      pulseSuppressedReason: `render error: ${error?.message || "unknown error"}`,
      selectedHeadlineTemplate: "render_error",
      selectedSublineTemplate: "render_error",
      dominantCorridorScore: 0,
      mobilityPressureCategory: "quiet",
      blendedSignalTypes: [],
      activeAwareness: null,
      pulseSummaryReuseApplied: false,
      pulseSummarySource: "",
      pulseSummaryText: "",
      phraseGenerationMode: "render_error",
      repetitionAvoidanceApplied: false
    };
  }

  const surface = document.getElementById("gridlyCommunityPulseSurface");
  const headline = document.getElementById("gridlyCommunityPulseHeadline");
  const subline = document.getElementById("gridlyCommunityPulseSubline");
  if (!surface) {
    gridlyCommunityPulseAuditState = { ...model, pulseVisible: false, pulseSuppressedReason: "pulse render target missing" };
    return gridlyCommunityPulseAuditState;
  }

  surface.hidden = !model.pulseVisible;
  surface.dataset.awarenessMode = model.awarenessMode;
  surface.dataset.gridlyPulseVisible = model.pulseVisible ? "true" : "false";
  surface.dataset.gridlyPulseRenderTarget = GRIDLY_COMMUNITY_PULSE_RENDER_TARGET;
  const renderedPulseHeadlineText = safeDisplayText(model.renderedPulseHeadline, "Community activity is quiet");
  const renderedPulseSublineText = safeDisplayText(model.renderedPulseSubline, "No major disruptions nearby");
  if (headline) headline.textContent = renderedPulseHeadlineText;
  if (subline) subline.textContent = renderedPulseSublineText;

  gridlyCommunityPulseAuditState = {
    ...model,
    pulseVisible: model.pulseVisible && !surface.hidden,
    renderedPulseHeadline: model.pulseVisible ? renderedPulseHeadlineText : "",
    renderedPulseSubline: model.pulseVisible ? renderedPulseSublineText : ""
  };
  recordGridlyActiveLocationLifecycleEvent("renderGridlyCommunityPulse", {
    reason: options?.reason || "unspecified",
    pulseVisible: Boolean(gridlyCommunityPulseAuditState.pulseVisible),
    renderedPulseHeadline: gridlyCommunityPulseAuditState.renderedPulseHeadline || "",
    renderedPulseSubline: gridlyCommunityPulseAuditState.renderedPulseSubline || "",
    resolvedLocationLabel: gridlyCommunityPulseAuditState.activeAwareness?.resolvedLocationLabel || "",
    resolvedCategory: gridlyCommunityPulseAuditState.activeAwareness?.resolvedCategory || null
  });
  return gridlyCommunityPulseAuditState;
}



const GRIDLY_AWARENESS_INTELLIGENCE_AUDIT_VERSION = "V227.0";

function getGridlyV227SafeCall(fn, fallback = null) {
  try {
    return typeof fn === "function" ? fn() : fallback;
  } catch (error) {
    return fallback;
  }
}

function getGridlyV227SafeText(selectorOrId = "") {
  try {
    const selector = String(selectorOrId || "");
    const node = selector.startsWith("#") || selector.startsWith(".") || selector.startsWith("[")
      ? document.querySelector(selector)
      : document.getElementById(selector);
    return safeDisplayText(node?.textContent, "");
  } catch (error) {
    return "";
  }
}

function getGridlyV227Visibility(selectorOrId = "") {
  try {
    const selector = String(selectorOrId || "");
    const node = selector.startsWith("#") || selector.startsWith(".") || selector.startsWith("[")
      ? document.querySelector(selector)
      : document.getElementById(selector);
    if (!node) return false;
    const style = typeof getComputedStyle === "function" ? getComputedStyle(node) : null;
    const rect = typeof node.getBoundingClientRect === "function" ? node.getBoundingClientRect() : null;
    return !node.hidden && style?.display !== "none" && style?.visibility !== "hidden" && style?.opacity !== "0" && (!rect || rect.width > 0 || rect.height > 0);
  } catch (error) {
    return false;
  }
}

function getGridlyV227PulseModelSnapshot(options = {}) {
  const existingState = typeof gridlyCommunityPulseAuditState === "object" && gridlyCommunityPulseAuditState ? { ...gridlyCommunityPulseAuditState } : {};
  if (existingState.pulseSuppressedReason !== "not_rendered_yet" || existingState.activeAwareness || existingState.communityAwarenessSummary) return existingState;
  try {
    if (typeof buildGridlyCommunityPulseModel === "function") return buildGridlyCommunityPulseModel({ ...options, auditOnly: true });
  } catch (error) {
    return { ...existingState, error: error?.message || "pulse model unavailable" };
  }
  return existingState;
}

function getGridlyV227AwarenessSnapshot(options = {}) {
  const pulseModel = getGridlyV227PulseModelSnapshot(options);
  const activeAwareness = pulseModel?.activeAwareness || gridlyCommunityPulseAuditState?.activeAwareness || {};
  const communityAwarenessSummary = pulseModel?.communityAwarenessSummary || getGridlyV227SafeCall(() => (
    typeof buildGridlyCommunityAwarenessIntelligenceSummary === "function"
      ? buildGridlyCommunityAwarenessIntelligenceSummary({ ...options, auditOnly: true })
      : null
  ), null) || {};
  const mobileSummary = getGridlyV227SafeCall(() => (typeof getGridlyMobileAwarenessPanelSummary === "function" ? getGridlyMobileAwarenessPanelSummary() : null), null) || {};
  const topPrimary = getGridlyV227SafeText("gridlyV2TopStatusPrimary");
  const topSecondary = getGridlyV227SafeText("gridlyV2TopStatusSecondary");
  const topMicroline = getGridlyV227SafeText("gridlyTopAwarenessMicroline");
  const pulseHeadline = getGridlyV227SafeText("gridlyCommunityPulseHeadline") || safeDisplayText(pulseModel?.renderedPulseHeadline, "");
  const pulseSubline = getGridlyV227SafeText("gridlyCommunityPulseSubline") || safeDisplayText(pulseModel?.renderedPulseSubline, "");
  const commandCard = {
    kicker: getGridlyV227SafeText("mobileAwarenessPanelKicker"),
    title: getGridlyV227SafeText("mobileDestinationCommandTitle"),
    meta: getGridlyV227SafeText("mobileDestinationCommandMeta"),
    crossings: getGridlyV227SafeText("mobileAwarenessPanelCrossings"),
    issues: getGridlyV227SafeText("mobileAwarenessPanelIssues"),
    impact: getGridlyV227SafeText("mobileDestinationCommandImpact"),
    button: getGridlyV227SafeText("mobileDestinationCommandBtn")
  };
  const activeHazardCount = Number(activeAwareness?.activeHazardCount ?? (Array.isArray(typeof activeHazards !== "undefined" ? activeHazards : null) ? activeHazards.length : 0) ?? 0);
  const activeReportCount = Number(activeAwareness?.activeReportCount ?? (Array.isArray(typeof activeReports !== "undefined" ? activeReports : null) ? activeReports.length : 0) ?? 0);
  const activeAwarenessCount = Number(activeAwareness?.activeAwarenessCount ?? (activeHazardCount + activeReportCount) ?? 0);
  const selectedCommunityCount = Number(pulseModel?.selectedCommunityCount || 0);
  const textBundle = [topPrimary, topSecondary, topMicroline, pulseHeadline, pulseSubline, commandCard.title, commandCard.meta, commandCard.crossings, commandCard.issues, commandCard.impact].filter(Boolean).join(" ");
  return {
    version: GRIDLY_AWARENESS_INTELLIGENCE_AUDIT_VERSION,
    generatedAt: new Date().toISOString(),
    pulseModel,
    activeAwareness,
    communityAwarenessSummary,
    mobileSummary,
    crossingAreaFilterApplied: Boolean(activeAwareness?.crossingAreaFilterApplied || communityAwarenessSummary?.crossingAreaFilterApplied),
    crossingAreaFilterPass: Boolean((activeAwareness?.crossingAreaFilterPass ?? true) && (communityAwarenessSummary?.crossingAreaFilterPass ?? true)),
    crossingAreaFilteredOutCount: Number(activeAwareness?.crossingAreaFilteredOutCount ?? communityAwarenessSummary?.crossingAreaFilteredOutCount ?? 0),
    crossingAreaFilteredOutRecords: activeAwareness?.crossingAreaFilteredOutRecords || communityAwarenessSummary?.crossingAreaFilteredOutRecords || [],
    activeCrossingReportsInSelectedArea: activeAwareness?.activeCrossingReportsInSelectedArea ?? communityAwarenessSummary?.activeCrossingReportsInSelectedArea ?? 0,
    activeCrossingReportsOutsideSelectedArea: activeAwareness?.activeCrossingReportsOutsideSelectedArea ?? communityAwarenessSummary?.activeCrossingReportsOutsideSelectedArea ?? 0,
    visibleText: { topPrimary, topSecondary, topMicroline, pulseHeadline, pulseSubline, commandCard },
    visibility: {
      topStatusPrimaryVisible: getGridlyV227Visibility("gridlyV2TopStatusPrimary"),
      topStatusSecondaryVisible: getGridlyV227Visibility("gridlyV2TopStatusSecondary"),
      communityPulseVisible: getGridlyV227Visibility("gridlyCommunityPulseSurface"),
      commandCardVisible: getGridlyV227Visibility(".mobile-destination-command")
    },
    counts: {
      activeHazardCount,
      activeReportCount,
      activeAwarenessCount,
      selectedCommunityCount,
      communityPhraseCount: Number(pulseModel?.communityPhraseCount || 0),
      dominantCorridorScore: Number(pulseModel?.dominantCorridorScore || 0),
      highestPresenceScore: Number(pulseModel?.highestPresenceScore || 0),
      crossingsInArea: Array.isArray(mobileSummary?.crossingsInArea) ? mobileSummary.crossingsInArea.length : Number(mobileSummary?.crossingsInArea || 0)
    },
    locations: {
      awarenessAreaName: safeDisplayText(mobileSummary?.areaName || communityAwarenessSummary?.awarenessAreaName, ""),
      resolvedLocationLabel: safeDisplayText(activeAwareness?.resolvedLocationLabel, ""),
      dominantCorridor: safeDisplayText(pulseModel?.dominantCorridor, "")
    },
    categories: {
      resolvedCategory: activeAwareness?.resolvedCategory || null,
      topCategory: activeAwareness?.topCategory || null,
      mobilityPressureCategory: pulseModel?.mobilityPressureCategory || "quiet",
      blendedSignalTypes: Array.isArray(pulseModel?.blendedSignalTypes) ? pulseModel.blendedSignalTypes : []
    },
    samples: Array.isArray(activeAwareness?.activeAwarenessSamples) ? activeAwareness.activeAwarenessSamples : [],
    textBundle
  };
}

function gridlyV227TextHasCounts(text = "") {
  return /\b\d+\b|\b(no|zero|one|two|three|four|five|six|seven|eight|nine|ten)\b/i.test(String(text || ""));
}

function gridlyV227TextHasObservation(text = "") {
  return /reported|seeing|active|quiet|clear|normal|building|elevated|impacted|hazard|flood|water|crash|closure|debris|rail|train|crossing|issue|mobility|activity|disruption/i.test(String(text || ""));
}

function gridlyV227TextHasLocation(text = "") {
  return /nearby|county|area|town|corridor|road|route|crossing|on\s+[A-Z]{1,4}\s*\d+|TX\s*\d+|US\s*\d+|I-\d+|Dayton|Liberty/i.test(String(text || ""));
}

function gridlyV227TextHasWhy(text = "") {
  return /because|due to|caused|reported|active|quiet|no major|\d+\s+(hazard|report|issue|crossing|disruption|mobility)/i.test(String(text || ""));
}

function inferGridlyV227DisplayedAwarenessStatus(snapshot) {
  const topState = safeDisplayText(window.gridlyTopAwarenessMicrolineState?.state, "");
  if (topState) return topState;
  const { activeHazardCount, activeReportCount, activeAwarenessCount, selectedCommunityCount } = snapshot.counts;
  const pressure = safeDisplayText(snapshot.categories.mobilityPressureCategory, "quiet");
  if (activeHazardCount > 0 || /high|elevated|impacted/i.test(pressure)) return "impacted";
  if (activeAwarenessCount > 0 || selectedCommunityCount >= 3 || /moderate|building/i.test(pressure)) return "building";
  return "quiet";
}

function gridlyAwarenessStatusAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const awarenessStatus = inferGridlyV227DisplayedAwarenessStatus(snapshot);
  const explanationText = [snapshot.visibleText.topPrimary, snapshot.visibleText.topSecondary, snapshot.visibleText.topMicroline].filter(Boolean).join(" ");
  const countDriven = gridlyV227TextHasCounts(explanationText) || Object.values(snapshot.counts).some((value) => Number(value || 0) > 0);
  const observationDriven = gridlyV227TextHasObservation(explanationText) || snapshot.samples.length > 0 || Boolean(snapshot.categories.resolvedCategory);
  const explainsConditions = gridlyV227TextHasObservation(explanationText);
  return {
    awarenessStatus,
    statusReasoning: {
      displayedPrimary: snapshot.visibleText.topPrimary,
      displayedSecondary: snapshot.visibleText.topSecondary,
      displayedMicroline: snapshot.visibleText.topMicroline,
      inferredFrom: window.gridlyTopAwarenessMicrolineState?.state ? "gridlyTopAwarenessMicrolineState.state" : "active awareness, community count, and mobility pressure signals",
      quietState: awarenessStatus === "quiet",
      findings: explainsConditions
        ? "Top awareness copy communicates a condition in addition to raw counts."
        : "Top awareness copy leans on status/count language and does not strongly explain observed conditions."
    },
    underlyingSignals: {
      counts: snapshot.counts,
      locations: snapshot.locations,
      categories: snapshot.categories,
      activeAwarenessLoaded: Boolean(snapshot.activeAwareness?.loaded),
      pulseSuppressedReason: snapshot.pulseModel?.pulseSuppressedReason || ""
    },
    userVisibleExplanation: explanationText,
    explanationQuality: explainsConditions && gridlyV227TextHasLocation(explanationText)
      ? "condition_and_place_explained"
      : (explainsConditions ? "condition_explained_location_light" : "counts_or_status_label_heavy"),
    countDriven,
    observationDriven
  };
}

function gridlyCommunityPulseIntelligenceAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const pulseText = [snapshot.visibleText.pulseHeadline, snapshot.visibleText.pulseSubline].filter(Boolean).join(" ");
  const containsTrendInformation = /trend|building|increasing|rising|easing|fresh|recent|last|again|repeat|multiple|across|pressure/i.test(pulseText)
    || Number(snapshot.counts.dominantCorridorScore || 0) > 0
    || (Array.isArray(snapshot.pulseModel?.corridorPriorityBreakdown) && snapshot.pulseModel.corridorPriorityBreakdown.length > 0);
  const containsObservationInformation = gridlyV227TextHasObservation(pulseText) || snapshot.samples.length > 0 || Boolean(snapshot.categories.resolvedCategory);
  const containsLocationContext = gridlyV227TextHasLocation(pulseText) || Boolean(snapshot.locations.resolvedLocationLabel || snapshot.locations.dominantCorridor || snapshot.locations.awarenessAreaName);
  const containsActionableContext = /review|avoid|before you go|heading|expect|delay|blocked|active|nearby|reported/i.test(pulseText);
  const visibleTextAvailable = Boolean(pulseText.trim());
  const intelligenceScore = [containsTrendInformation, containsObservationInformation, containsLocationContext, containsActionableContext]
    .reduce((score, passed) => score + (passed ? 25 : 0), visibleTextAvailable ? 0 : -10);
  const findings = [];
  findings.push(snapshot.visibility.communityPulseVisible ? "Community Pulse is visible." : `Community Pulse is not visible (${snapshot.pulseModel?.pulseSuppressedReason || "no rendered pulse copy"}).`);
  findings.push(containsObservationInformation ? "Pulse includes condition/observation language." : "Pulse is mostly label/count oriented and lacks observation detail.");
  findings.push(containsTrendInformation ? "Pulse exposes trend/pressure/freshness signals." : "Pulse does not expose clear trend information in the visible summary.");
  findings.push(containsLocationContext ? "Pulse model has location context available." : "Pulse lacks visible where/context language.");
  return {
    pulseState: {
      awarenessMode: snapshot.pulseModel?.awarenessMode || "unknown",
      pulseVisible: Boolean(snapshot.visibility.communityPulseVisible),
      mobilityPressureCategory: snapshot.categories.mobilityPressureCategory,
      pulseSuppressedReason: snapshot.pulseModel?.pulseSuppressedReason || ""
    },
    pulseInputs: {
      counts: snapshot.counts,
      locations: snapshot.locations,
      categories: snapshot.categories,
      selectedHeadlineTemplate: snapshot.pulseModel?.selectedHeadlineTemplate || "",
      selectedSublineTemplate: snapshot.pulseModel?.selectedSublineTemplate || "",
      phraseGenerationMode: snapshot.pulseModel?.phraseGenerationMode || ""
    },
    userVisibleSummary: pulseText,
    containsTrendInformation,
    containsObservationInformation,
    containsLocationContext,
    containsActionableContext,
    intelligenceScore: Math.max(0, Math.min(100, intelligenceScore)),
    findings
  };
}

function gridlyAwarenessStoryAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const visibleNarrative = [
    snapshot.visibleText.topPrimary,
    snapshot.visibleText.topSecondary,
    snapshot.visibleText.topMicroline,
    snapshot.visibleText.commandCard.title,
    snapshot.visibleText.commandCard.meta,
    snapshot.visibleText.commandCard.crossings,
    snapshot.visibleText.pulseHeadline,
    snapshot.visibleText.pulseSubline
  ].filter(Boolean).join(" | ");
  const explainsWhat = gridlyV227TextHasObservation(visibleNarrative);
  const explainsWhere = gridlyV227TextHasLocation(visibleNarrative) || Boolean(snapshot.locations.awarenessAreaName || snapshot.locations.resolvedLocationLabel || snapshot.locations.dominantCorridor);
  const explainsWhy = gridlyV227TextHasWhy(visibleNarrative) || Number(snapshot.counts.activeAwarenessCount || 0) > 0;
  const storyCompleteness = Math.round(([explainsWhat, explainsWhere, explainsWhy].filter(Boolean).length / 3) * 100);
  return {
    awarenessArea: snapshot.locations.awarenessAreaName || snapshot.visibleText.commandCard.title || "",
    visibleNarrative,
    explainsWhat,
    explainsWhere,
    explainsWhy,
    storyCompleteness,
    findings: [
      explainsWhat ? "The glanceable story says what condition is present." : "The glanceable story does not clearly say what is happening.",
      explainsWhere ? "The story provides area/location context." : "The story lacks specific where context.",
      explainsWhy ? "The status has a visible reason or signal basis." : "The status reason is not obvious from a single glance."
    ]
  };
}

function gridlyDestinationAwarenessAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const selectedLabel = getGridlyV227SafeCall(() => (typeof getSelectedDestinationLabel === "function" ? getSelectedDestinationLabel() : ""), "");
  const destinationPresent = Boolean(selectedLabel || snapshot.visibleText.commandCard.title || snapshot.visibleText.commandCard.impact);
  const destinationContextText = [snapshot.visibleText.commandCard.title, snapshot.visibleText.commandCard.meta, snapshot.visibleText.commandCard.impact].filter(Boolean).join(" ");
  const awarenessContextText = [snapshot.visibleText.commandCard.kicker, snapshot.visibleText.commandCard.title, snapshot.visibleText.commandCard.meta, snapshot.visibleText.commandCard.crossings, snapshot.visibleText.commandCard.issues].filter(Boolean).join(" ");
  const routeOnlyInformation = /route|navigate|preview|calculating|monitoring|destination selected|choose route|view route/i.test(destinationContextText)
    && !/awareness|hazard|report|issue|quiet|county|area|crossing|community/i.test(awarenessContextText);
  const awarenessEnhancedInformation = /awareness|hazard|report|issue|quiet|county|area|crossing|community/i.test(awarenessContextText);
  return {
    destinationPresent,
    destinationContextPresent: Boolean(destinationContextText),
    awarenessContextPresent: awarenessEnhancedInformation,
    routeOnlyInformation,
    awarenessEnhancedInformation,
    findings: [
      awarenessEnhancedInformation ? "Destination/command card context inherits awareness-area language without changing ownership." : "Destination context currently reads as route-only or destination-only.",
      snapshot.visibleText.commandCard.crossings ? "The card includes watched crossings/hazards/reports counts as awareness context." : "No supporting awareness details are visible on the destination card.",
      snapshot.visibleText.commandCard.impact ? "Route support text exists separately from awareness context." : "No route impact support text is visible."
    ]
  };
}

function gridlyKnowBeforeYouGoAudit(options = {}) {
  const statusAudit = gridlyAwarenessStatusAudit(options);
  const pulseAudit = gridlyCommunityPulseIntelligenceAudit(options);
  const storyAudit = gridlyAwarenessStoryAudit(options);
  const destinationAudit = gridlyDestinationAwarenessAudit(options);
  const explainsConditions = Boolean(statusAudit.observationDriven || storyAudit.explainsWhat);
  const explainsLocation = Boolean(storyAudit.explainsWhere || pulseAudit.containsLocationContext);
  const explainsImpact = /impact|delay|blocked|avoid|review|before you go|active|hazard|issue|clear|quiet|no major/i.test([
    statusAudit.userVisibleExplanation,
    pulseAudit.userVisibleSummary,
    destinationAudit.findings.join(" ")
  ].join(" "));
  const requiresAdditionalPanels = !(explainsConditions && explainsLocation && explainsImpact && storyAudit.storyCompleteness >= 67);
  const decisionUseful = Boolean(explainsConditions && explainsLocation && explainsImpact && !requiresAdditionalPanels);
  const missionScore = Math.round(([
    explainsConditions,
    explainsLocation,
    explainsImpact,
    !requiresAdditionalPanels,
    pulseAudit.intelligenceScore >= 50
  ].filter(Boolean).length / 5) * 100);
  return {
    decisionUseful,
    explainsConditions,
    explainsLocation,
    explainsImpact,
    requiresAdditionalPanels,
    missionScore,
    findings: [
      decisionUseful ? "Visible awareness information can improve a travel decision." : "Visible awareness information is not yet complete enough to reliably improve a travel decision at a glance.",
      explainsConditions ? "Conditions are communicated." : "Conditions are not clearly communicated.",
      explainsLocation ? "Location/area context is present." : "Location/area context is missing or too weak.",
      explainsImpact ? "Impact language is present or inferable." : "Impact on travel is not explicit.",
      requiresAdditionalPanels ? "A user likely needs additional panels for full Know Before You Go context." : "The primary visible surfaces carry enough context without additional panels."
    ]
  };
}



const GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION = "V228.0";

function gridlyV228ActiveConditionTextBundle(snapshot) {
  const commandCard = snapshot?.visibleText?.commandCard || {};
  return [
    snapshot?.visibleText?.topPrimary,
    snapshot?.visibleText?.topSecondary,
    snapshot?.visibleText?.topMicroline,
    commandCard.title,
    commandCard.meta,
    commandCard.crossings,
    commandCard.issues,
    commandCard.impact,
    snapshot?.visibleText?.pulseHeadline,
    snapshot?.visibleText?.pulseSubline
  ].filter(Boolean).join(" | ");
}

function gridlyV228ActiveConditionSamples(snapshot) {
  const activeSamples = Array.isArray(snapshot?.samples) ? snapshot.samples : [];
  const pulseBreakdown = Array.isArray(snapshot?.pulseModel?.corridorPriorityBreakdown)
    ? snapshot.pulseModel.corridorPriorityBreakdown
    : [];
  return { activeSamples, pulseBreakdown };
}

function gridlyV228TextHasImpact(text = "") {
  return /impact|delay|blocked|closure|closed|avoid|detour|flood|water|construction|rail|train|crossing|slow|disruption|before you go|use caution|expect|review|travel/i.test(String(text || ""));
}

function gridlyV228TextHasExplanation(text = "") {
  return /because|due to|caused|from|reported|near|along|on|around|activity|conditions|flood|water|construction|closure|rail|train|corridor/i.test(String(text || ""));
}

function gridlyV228GetSignalTypes(snapshot) {
  const categories = snapshot?.categories || {};
  const blended = Array.isArray(categories.blendedSignalTypes) ? categories.blendedSignalTypes : [];
  const samples = Array.isArray(snapshot?.samples) ? snapshot.samples : [];
  const sampleTypes = samples.map((sample) => sample?.type || sample?.reportType || sample?.hazardType || sample?.category || sample?.resolvedCategory).filter(Boolean);
  return Array.from(new Set([categories.resolvedCategory, categories.topCategory, ...blended, ...sampleTypes].filter(Boolean).map((value) => String(value).trim()).filter(Boolean)));
}

function gridlyV228BuildConditionNarrative(snapshot) {
  const text = gridlyV228ActiveConditionTextBundle(snapshot);
  if (text.trim()) return text;
  const signalTypes = gridlyV228GetSignalTypes(snapshot);
  const locations = [snapshot?.locations?.dominantCorridor, snapshot?.locations?.resolvedLocationLabel, snapshot?.locations?.awarenessAreaName].filter(Boolean);
  if (signalTypes.length && locations.length) return `${signalTypes.slice(0, 2).join(" and ")} activity reported near ${locations[0]}.`;
  if (signalTypes.length) return `${signalTypes.slice(0, 2).join(" and ")} activity reported in the awareness area.`;
  return "";
}

function gridlyActiveConditionIntelligenceAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const visibleConditionSummary = gridlyV228BuildConditionNarrative(snapshot);
  const activeConditionCount = Number(snapshot?.counts?.activeAwarenessCount || 0);
  const { activeSamples } = gridlyV228ActiveConditionSamples(snapshot);
  const signalTypes = gridlyV228GetSignalTypes(snapshot);
  const explainsWhat = gridlyV227TextHasObservation(visibleConditionSummary) || signalTypes.length > 0 || activeSamples.length > 0;
  const explainsWhere = gridlyV227TextHasLocation(visibleConditionSummary) || Boolean(snapshot?.locations?.awarenessAreaName || snapshot?.locations?.resolvedLocationLabel || snapshot?.locations?.dominantCorridor);
  const explainsWhy = gridlyV227TextHasWhy(visibleConditionSummary) || gridlyV228TextHasExplanation(visibleConditionSummary) || activeSamples.length > 0;
  const explainsImpact = gridlyV228TextHasImpact(visibleConditionSummary);
  const textHasCounts = gridlyV227TextHasCounts(visibleConditionSummary);
  const countDriven = textHasCounts && !(explainsWhat && (explainsWhere || explainsImpact));
  const observationDriven = Boolean(explainsWhat && (explainsWhere || explainsWhy || explainsImpact));
  return {
    auditVersion: GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION,
    activeConditionCount,
    visibleConditionSummary,
    explainsWhat,
    explainsWhere,
    explainsWhy,
    explainsImpact,
    countDriven,
    observationDriven,
    findings: [
      activeConditionCount > 0 ? `${activeConditionCount} active mobility condition signal(s) are available to audit.` : "No live active condition count is currently present; readiness is inferred from visible copy and model fields.",
      explainsWhat ? "Active conditions can be described as observations rather than only categories." : "Active conditions are not clearly described as observations.",
      explainsWhere ? "Location or corridor context is available for active condition language." : "Active condition language lacks where/corridor context.",
      explainsWhy ? "The summary has an explanatory signal basis." : "The summary does not clearly explain why the user should pay attention.",
      explainsImpact ? "Travel-impact language is present or inferable." : "Travel impact is not explicit in the active condition summary.",
      countDriven ? "The current summary is count-driven." : "The current summary is not merely count-driven.",
      observationDriven ? "The current summary supports awareness intelligence framing." : "The current summary needs stronger observation framing for active conditions."
    ]
  };
}

function gridlyAwarenessNarrativeAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const conditionAudit = gridlyActiveConditionIntelligenceAudit(options);
  const signalTypes = gridlyV228GetSignalTypes(snapshot);
  const { activeSamples, pulseBreakdown } = gridlyV228ActiveConditionSamples(snapshot);
  const narrativeText = gridlyV228BuildConditionNarrative(snapshot);
  const signalCount = Math.max(
    Number(snapshot?.counts?.activeAwarenessCount || 0),
    signalTypes.length,
    activeSamples.length,
    Number(snapshot?.counts?.selectedCommunityCount || 0)
  );
  const combinesMultipleSignals = Boolean(
    signalTypes.length >= 2
    || activeSamples.length >= 2
    || pulseBreakdown.length >= 2
    || Number(snapshot?.counts?.activeHazardCount || 0) > 0 && Number(snapshot?.counts?.activeReportCount || 0) > 0
    || Number(snapshot?.counts?.selectedCommunityCount || 0) >= 2
  );
  const explainsConditions = Boolean(conditionAudit.explainsWhat && conditionAudit.explainsWhy);
  const locationContextPresent = Boolean(conditionAudit.explainsWhere);
  const impactContextPresent = Boolean(conditionAudit.explainsImpact);
  const narrativeAvailable = Boolean(narrativeText.trim() && explainsConditions && locationContextPresent && (combinesMultipleSignals || signalCount <= 1));
  return {
    auditVersion: GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION,
    narrativeAvailable,
    narrativeText,
    combinesMultipleSignals,
    explainsConditions,
    locationContextPresent,
    impactContextPresent,
    findings: [
      narrativeAvailable ? "A coherent awareness narrative is available from current surfaces/model fields." : "A coherent active-state narrative is not fully available from current surfaces/model fields.",
      combinesMultipleSignals ? "Multiple mobility signals can be blended into one narrative." : "Multiple-signal blending is not demonstrated by the current model state.",
      explainsConditions ? "The narrative explains conditions." : "The narrative does not yet explain conditions strongly enough.",
      locationContextPresent ? "The narrative includes area/corridor context." : "The narrative lacks area/corridor context.",
      impactContextPresent ? "The narrative includes travel-impact context." : "The narrative lacks explicit travel-impact context."
    ]
  };
}


const GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION = "V229.0";

function gridlyV229NormalizeNarrativeText(value = "") {
  return safeDisplayText(value, "").replace(/\s+/g, " ").trim();
}

function gridlyV229GetPathValue(record = {}, path = "") {
  try {
    return String(path || "").split(".").reduce((current, part) => (current && typeof current === "object" ? current[part] : undefined), record);
  } catch (error) {
    return undefined;
  }
}

function gridlyV229FirstNarrativeText(record = {}, paths = []) {
  for (const path of paths) {
    const value = gridlyV229NormalizeNarrativeText(gridlyV229GetPathValue(record, path));
    if (value) return { text: value, path };
  }
  return { text: "", path: "" };
}

function gridlyV229NarrativeHasCondition(text = "") {
  return /construction|closure|closed|flood|water|crash|wreck|debris|disabled|traffic|backup|delay|rail|train|blocked|hazard|incident|report|work zone|utility|ice|damage|slow/i.test(String(text || ""));
}

function gridlyV229NarrativeHasLocation(text = "") {
  return gridlyV227TextHasLocation(text) || /\b(FM|CR|US|TX|SH|IH|I)[-\s]?\d+\b|farm-to-market|county road|road|street|highway|between|near|at|on|along|around|across|Liberty|Dayton|Hull|Cleveland|Ames|Devers|Daisetta|Tarkington|Hardin/i.test(String(text || ""));
}

function gridlyV229ConditionStrength(text = "") {
  const value = String(text || "");
  let score = 0;
  if (gridlyV229NarrativeHasCondition(value)) score += 3;
  if (gridlyV229NarrativeHasLocation(value)) score += 3;
  if (/between|near|at|on|along|around|across/i.test(value)) score += 1;
  if (/construction|closure|closed|flood|crash|wreck|blocked|debris|disabled|traffic|delay/i.test(value)) score += 2;
  if (value.length >= 18) score += 1;
  if (gridlyV227TextHasCounts(value) && value.length < 40) score -= 1;
  return score;
}

function gridlyV229BuildNarrativeSourceCandidates(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const candidates = [];
  const addCandidate = (text, source, sourceType, extra = {}) => {
    const narrative = gridlyV229NormalizeNarrativeText(text);
    if (!narrative || narrative.toLowerCase() === "[object object]") return;
    const conditionContextPresent = gridlyV229NarrativeHasCondition(narrative);
    const locationContextPresent = gridlyV229NarrativeHasLocation(narrative);
    candidates.push({
      narrative,
      source,
      sourceType,
      promotable: Boolean(conditionContextPresent && locationContextPresent),
      conditionContextPresent,
      locationContextPresent,
      strength: gridlyV229ConditionStrength(narrative),
      ...extra
    });
  };

  const alertPaths = [
    "headline", "title", "detail", "description", "summary", "message", "subline",
    "localizedSummary", "resolvedHeadline", "finalHeadline", "segmentHeadline",
    "raw.headline", "raw.title", "raw.detail", "raw.description", "raw.summary", "raw.message",
    "source.headline", "source.title", "source.detail", "source.description", "source.summary", "source.message"
  ];
  const alertItems = getGridlyV227SafeCall(() => getGridlyDestinationRouteAlertSource(), []) || [];
  (Array.isArray(alertItems) ? alertItems : []).forEach((alert, index) => {
    const picked = gridlyV229FirstNarrativeText(alert, alertPaths);
    addCandidate(picked.text, `alert.${picked.path || "text"}`, "alert", { index, recordId: alert?.id || alert?.reportId || alert?.incidentId || "", visible: true });
  });

  const activeAwarenessSamples = Array.isArray(snapshot?.samples) ? snapshot.samples : [];
  activeAwarenessSamples.forEach((sample, index) => {
    const picked = gridlyV229FirstNarrativeText(sample, ["headline", "title", "description", "summary", "detail", "message", "roadName", "corridor", "resolvedLocationLabel"]);
    addCandidate(picked.text, `activeAwarenessSamples.${picked.path || "text"}`, "active_awareness_sample", { index, recordId: sample?.id || sample?.reportId || "" });
  });

  (Array.isArray(snapshot?.communityAwarenessSummary?.activeHazardsInArea) ? snapshot.communityAwarenessSummary.activeHazardsInArea : []).forEach((hazard, index) => {
    const picked = gridlyV229FirstNarrativeText(hazard, ["headline", "title", "description", "summary", "detail", "message", "roadName", "corridor", "raw.headline", "raw.title", "raw.description"]);
    addCandidate(picked.text, `communityAwarenessSummary.activeHazardsInArea.${picked.path || "text"}`, "active_hazard", { index, recordId: hazard?.id || hazard?.reportId || "" });
  });

  (Array.isArray(snapshot?.communityAwarenessSummary?.activeReportsInArea) ? snapshot.communityAwarenessSummary.activeReportsInArea : []).forEach((report, index) => {
    const picked = gridlyV229FirstNarrativeText(report, ["headline", "title", "description", "summary", "detail", "message", "roadName", "corridor", "raw.headline", "raw.title", "raw.description"]);
    addCandidate(picked.text, `communityAwarenessSummary.activeReportsInArea.${picked.path || "text"}`, "active_report", { index, recordId: report?.id || report?.reportId || "" });
  });

  addCandidate(snapshot?.visibleText?.pulseHeadline, "Community Pulse headline", "community_pulse", { visible: Boolean(snapshot?.visibility?.communityPulseVisible) });
  addCandidate(snapshot?.visibleText?.pulseSubline, "Community Pulse subline", "community_pulse", { visible: Boolean(snapshot?.visibility?.communityPulseVisible) });
  addCandidate(snapshot?.visibleText?.topPrimary, "awareness summary primary", "awareness_summary", { visible: Boolean(snapshot?.visibility?.topStatusPrimaryVisible) });
  addCandidate(snapshot?.visibleText?.topSecondary, "awareness summary secondary", "awareness_summary", { visible: Boolean(snapshot?.visibility?.topStatusSecondaryVisible) });
  addCandidate(snapshot?.visibleText?.topMicroline, "awareness summary microline", "awareness_summary", { visible: true });
  addCandidate(snapshot?.visibleText?.commandCard?.title, "destination context title", "destination_context", { visible: Boolean(snapshot?.visibility?.commandCardVisible) });
  addCandidate(snapshot?.visibleText?.commandCard?.meta, "destination context meta", "destination_context", { visible: Boolean(snapshot?.visibility?.commandCardVisible) });
  addCandidate(snapshot?.visibleText?.commandCard?.issues, "destination context issues", "destination_context", { visible: Boolean(snapshot?.visibility?.commandCardVisible) });
  addCandidate(snapshot?.visibleText?.commandCard?.impact, "destination context impact", "destination_context", { visible: Boolean(snapshot?.visibility?.commandCardVisible) });
  addCandidate(gridlyV228BuildConditionNarrative(snapshot), "derived active-condition narrative", "derived_awareness", { derived: true });

  const displaySummary = getGridlyV227SafeCall(() => summarizeGridlyAwarenessIntelligenceForDisplay(snapshot?.communityAwarenessSummary || {}), null) || {};
  addCandidate(displaySummary.headline, "current awareness display headline", "awareness_summary", { derived: true });
  addCandidate(displaySummary.subline, "current awareness display subline", "awareness_summary", { derived: true });

  const visibleBundle = gridlyV229NormalizeNarrativeText([
    snapshot?.textBundle,
    snapshot?.visibleText?.pulseHeadline,
    snapshot?.visibleText?.pulseSubline,
    snapshot?.visibleText?.commandCard?.title,
    snapshot?.visibleText?.commandCard?.meta,
    snapshot?.visibleText?.commandCard?.issues,
    snapshot?.visibleText?.commandCard?.impact
  ].filter(Boolean).join(" "));
  const ranked = candidates
    .map((candidate) => ({
      ...candidate,
      sourceAlreadyVisible: Boolean(candidate.visible || (candidate.narrative && visibleBundle.toLowerCase().includes(candidate.narrative.toLowerCase())))
    }))
    .sort((a, b) => (Number(b.promotable) - Number(a.promotable)) || (b.strength - a.strength) || (b.narrative.length - a.narrative.length));
  return { snapshot, candidates: ranked, visibleBundle };
}

function gridlyV229BestCandidate(options = {}) {
  const sourceState = gridlyV229BuildNarrativeSourceCandidates(options);
  const candidate = sourceState.candidates.find((entry) => entry.promotable) || sourceState.candidates[0] || null;
  return { ...sourceState, candidate };
}

function gridlyAwarenessNarrativePromotionAudit(options = {}) {
  const { candidate, candidates } = gridlyV229BestCandidate(options);
  const promotionAvailable = Boolean(candidate?.promotable);
  return {
    auditVersion: GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION,
    promotionAvailable,
    candidateNarrative: candidate?.narrative || "",
    candidateSource: candidate?.source || "none",
    sourceAlreadyVisible: Boolean(candidate?.sourceAlreadyVisible),
    hierarchyRisk: promotionAvailable ? "low_if_summary_only" : "not_applicable",
    ownershipRisk: promotionAvailable ? "low_read_only_existing_source" : "not_applicable",
    findings: [
      promotionAvailable ? "A promotable awareness narrative already exists in current Gridly intelligence." : "No condition-plus-location narrative is currently promotable from audited sources.",
      candidate ? `Strongest source audited: ${candidate.sourceType} (${candidate.source}).` : "No narrative source candidates were found.",
      candidate?.sourceAlreadyVisible ? "The strongest narrative is already visible on an existing surface." : "The strongest narrative is available in existing state but is not clearly visible in the current awareness text bundle.",
      "Promotion would be safest as read-only summary wording because this audit does not alter command card, awareness, destination, route, Community Pulse, alert, hazard, map, or Supabase ownership."
    ],
    candidateCount: candidates.length
  };
}

function gridlyBestAvailableObservationAudit(options = {}) {
  const { candidate } = gridlyV229BestCandidate(options);
  const observationAvailable = Boolean(candidate?.narrative);
  return {
    auditVersion: GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION,
    observationAvailable,
    observationText: candidate?.narrative || "",
    observationSource: candidate?.source || "none",
    locationContextPresent: Boolean(candidate?.locationContextPresent),
    conditionContextPresent: Boolean(candidate?.conditionContextPresent),
    findings: [
      observationAvailable ? "A best available observation was identified without creating new intelligence." : "No existing observation was available to rank.",
      candidate?.conditionContextPresent ? "The observation includes condition context." : "Condition context is missing or weak.",
      candidate?.locationContextPresent ? "The observation includes location context." : "Location context is missing or weak.",
      candidate ? `Observation source type: ${candidate.sourceType}.` : "No source type could be assigned."
    ]
  };
}

function gridlyNarrativeSourceTraceAudit(options = {}) {
  const { candidate, candidates } = gridlyV229BestCandidate(options);
  const traceResults = candidates.slice(0, 12).map((entry) => ({
    source: entry.source,
    sourceType: entry.sourceType,
    narrative: entry.narrative,
    promotable: entry.promotable,
    sourceAlreadyVisible: entry.sourceAlreadyVisible,
    locationContextPresent: entry.locationContextPresent,
    conditionContextPresent: entry.conditionContextPresent,
    strength: entry.strength
  }));
  const sourcesFound = Array.from(new Set(candidates.map((entry) => entry.sourceType))).filter(Boolean);
  return {
    auditVersion: GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION,
    sourcesFound,
    strongestSource: candidate?.source || "none",
    strongestNarrative: candidate?.narrative || "",
    traceResults,
    findings: [
      sourcesFound.length ? `Narrative sources found: ${sourcesFound.join(", ")}.` : "No narrative sources were found.",
      candidate ? `Strongest narrative traces to ${candidate.source}.` : "No strongest narrative could be selected.",
      "Trace audit only reads existing alert, Community Pulse, awareness summary, destination/visible text, and active awareness model fields."
    ]
  };
}

function gridlyPromotionSafetyAudit(options = {}) {
  const promotionAudit = gridlyAwarenessNarrativePromotionAudit(options);
  const ownershipSafe = promotionAudit.ownershipRisk !== "high";
  const routeSafe = true;
  const destinationSafe = true;
  const communityPulseSafe = true;
  const alertSafe = true;
  const safe = Boolean(ownershipSafe && routeSafe && destinationSafe && communityPulseSafe && alertSafe);
  return {
    auditVersion: GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION,
    ownershipSafe,
    routeSafe,
    destinationSafe,
    communityPulseSafe,
    alertSafe,
    overallSafetyAssessment: safe ? "safe_for_future_read_only_summary_promotion" : "promotion_requires_additional_guardrails",
    findings: [
      ownershipSafe ? "Ownership remains safe because audited promotion would read existing intelligence and would not transfer source ownership." : "Ownership risk requires review.",
      "Route behavior is safe because no route state, route preview, route ownership, or route rendering is modified.",
      "Destination behavior is safe because no destination selection, command card ownership, or destination route preview behavior is modified.",
      "Community Pulse behavior is safe because pulse model/render logic is not changed.",
      "Alert behavior is safe because alert generation and rendering are not changed."
    ]
  };
}

function gridlyNarrativeValueAudit(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const currentSummary = gridlyV229NormalizeNarrativeText([
    snapshot?.visibleText?.topPrimary,
    snapshot?.visibleText?.topSecondary,
    snapshot?.visibleText?.topMicroline
  ].filter(Boolean).join(" "));
  const observationAudit = gridlyBestAvailableObservationAudit(options);
  const bestAvailableObservation = observationAudit.observationText || "";
  const currentHasCondition = gridlyV229NarrativeHasCondition(currentSummary);
  const currentHasLocation = gridlyV229NarrativeHasLocation(currentSummary);
  const observationHasCondition = gridlyV229NarrativeHasCondition(bestAvailableObservation);
  const observationHasLocation = gridlyV229NarrativeHasLocation(bestAvailableObservation);
  const improvementInConditionAwareness = Boolean(observationHasCondition && (!currentHasCondition || gridlyV229ConditionStrength(bestAvailableObservation) > gridlyV229ConditionStrength(currentSummary)));
  const improvementInLocationAwareness = Boolean(observationHasLocation && (!currentHasLocation || gridlyV229ConditionStrength(bestAvailableObservation) > gridlyV229ConditionStrength(currentSummary)));
  const improvementInDecisionUsefulness = Boolean(bestAvailableObservation && observationHasCondition && observationHasLocation && (improvementInConditionAwareness || improvementInLocationAwareness));
  return {
    auditVersion: GRIDLY_AWARENESS_NARRATIVE_PROMOTION_AUDIT_VERSION,
    currentSummary,
    bestAvailableObservation,
    improvementInConditionAwareness,
    improvementInLocationAwareness,
    improvementInDecisionUsefulness,
    recommendation: improvementInDecisionUsefulness ? "consider_future_read_only_awareness_summary_promotion" : "do_not_promote_without_stronger_existing_observation",
    findings: [
      currentSummary ? "Current awareness summary was captured from existing top awareness text." : "Current awareness summary is not visible in the audited state.",
      bestAvailableObservation ? "Best available observation was captured from existing Gridly intelligence." : "No best available observation was found.",
      improvementInConditionAwareness ? "Promoting the observation would improve condition understanding." : "Condition understanding would not clearly improve.",
      improvementInLocationAwareness ? "Promoting the observation would improve location understanding." : "Location understanding would not clearly improve.",
      improvementInDecisionUsefulness ? "Promotion appears valuable for Know Before You Go decision usefulness." : "Promotion value is limited in the current state."
    ]
  };
}


const GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION = "V229.1";

function gridlyV2291UniqueTexts(values = []) {
  const seen = new Set();
  return values.map((value) => gridlyV229NormalizeNarrativeText(value)).filter((value) => {
    const key = value.toLowerCase();
    if (!value || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function gridlyV2291ExtractRoadReferences(text = "") {
  const normalized = gridlyV229NormalizeNarrativeText(text);
  if (!normalized) return [];
  const roads = [];
  const pushRoad = (value = "") => {
    const road = normalizeRoadDisplayCase(gridlyV229NormalizeNarrativeText(value).replace(/^[,;:.\s]+|[,;:.\s]+$/g, ""));
    if (!road || road.length < 2) return;
    if (/^(?:in|near|at|on|between|and|reported|affecting)$/i.test(road)) return;
    if (!gridlyV229NarrativeHasLocation(road)) return;
    if (roads.some((entry) => normalizeRoadComparison(entry) === normalizeRoadComparison(road))) return;
    roads.push(road);
  };
  (normalized.match(/\b(?:FM|RM|RR|CR|US|TX|SH|IH|I|Loop|Spur)\s*-?\s*\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\b(?:County Road|Road|Rd|Street|St|Avenue|Ave|Drive|Dr|Lane|Ln|Highway|Hwy)\s+[A-Za-z0-9 .'-]{1,36}\b/gi) || []).forEach(pushRoad);
  const onMatch = normalized.match(/\b(?:on|along|affecting)\s+(.+?)(?:\s+in\s+|\s+near\s+|\s+between\s+|[.;,]|$)/i);
  if (onMatch?.[1]) pushRoad(onMatch[1]);
  return roads;
}

function gridlyV2291ConditionLabelFromText(text = "", fallback = "") {
  const value = gridlyV229NormalizeNarrativeText(text);
  const normalized = value.toLowerCase();
  if (/construction|work\s*zone|road\s*work|utility\s*work|maintenance/.test(normalized)) return "Construction";
  if (/flood|standing water|high water/.test(normalized)) return "Flooding";
  if (/road\s*closed|closure|closed/.test(normalized)) return "Road closed";
  if (/crash|collision|wreck|accident/.test(normalized)) return "Crash / Wreck";
  if (/debris|tree down|obstruction|object/.test(normalized)) return "Debris in Road";
  if (/disabled|stalled/.test(normalized)) return "Disabled vehicle";
  if (/rail|train|crossing|blocked/.test(normalized)) return "Train blocking crossing";
  if (/traffic|backup|congestion|delay/.test(normalized)) return "Traffic Backup";
  return getGridlyLightweightTitleCaseCategory(fallback) || (gridlyV229NarrativeHasCondition(value) ? "Active condition" : "");
}

function gridlyV2291GetAwarenessAreaName(options = {}) {
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const selectedArea = getGridlyV227SafeCall(() => (typeof getGridlySelectedAwarenessArea === "function" ? getGridlySelectedAwarenessArea() : null), null) || {};
  const name = gridlyV229NormalizeNarrativeText(
    options?.awarenessAreaName
      || snapshot?.communityAwarenessSummary?.awarenessAreaName
      || selectedArea.label
      || selectedArea.storageValue
      || snapshot?.mobileSummary?.selectedAwarenessArea?.label
      || ""
  );
  return {
    name,
    source: name === options?.awarenessAreaName ? "options.awarenessAreaName"
      : snapshot?.communityAwarenessSummary?.awarenessAreaName ? "communityAwarenessSummary.awarenessAreaName"
        : selectedArea.label ? "selectedAwarenessArea.label"
          : selectedArea.storageValue ? "selectedAwarenessArea.storageValue"
            : "none",
    selectedArea,
    snapshot
  };
}

function gridlyV2291NarrativeContainsAwarenessArea(text = "", areaName = "") {
  const narrative = gridlyV229NormalizeNarrativeText(text).toLowerCase();
  const area = gridlyV229NormalizeNarrativeText(areaName).toLowerCase();
  if (!narrative) return false;
  if (area && narrative.includes(area)) return true;
  return /\b(?:hull|dayton|liberty|cleveland|ames|devers|daisetta|tarkington|hardin|kenefick|plum grove|raywood|moss bluff)\b/i.test(narrative);
}

function gridlyV2291ScoreNarrative(narrative = "", context = {}) {
  const text = gridlyV229NormalizeNarrativeText(narrative);
  const conditionLabel = gridlyV2291ConditionLabelFromText(text, context.condition || "");
  const roads = gridlyV2291ExtractRoadReferences(text);
  const containsCondition = Boolean(conditionLabel || gridlyV229NarrativeHasCondition(text));
  const containsRoad = roads.length > 0;
  const containsAwarenessArea = gridlyV2291NarrativeContainsAwarenessArea(text, context.awarenessAreaName || "");
  const conditionSpecificity = containsCondition ? (/reported|hazard|incident/i.test(text) && !/construction|flood|closure|closed|crash|wreck|debris|disabled|traffic|rail|train|blocked/i.test(text) ? 12 : 25) : 0;
  const roadwaySpecificity = containsRoad ? (roads.some((road) => /\d/.test(road)) ? 30 : 22) : 0;
  const locationSpecificity = containsAwarenessArea ? 25 : (gridlyV229NarrativeHasLocation(text) ? 12 : 0);
  const awarenessUsefulness = Math.min(20, (containsCondition ? 6 : 0) + (containsRoad ? 7 : 0) + (containsAwarenessArea ? 7 : 0));
  const specificityScore = Math.max(0, Math.min(100, conditionSpecificity + roadwaySpecificity + locationSpecificity + awarenessUsefulness));
  return {
    narrative: text,
    conditionSpecificity,
    roadwaySpecificity,
    locationSpecificity,
    awarenessUsefulness,
    specificityScore,
    containsCondition,
    containsRoad,
    containsAwarenessArea,
    conditionLabel,
    roadNames: roads
  };
}

function gridlyV2291BuildNarrativeAuditCandidates(options = {}) {
  const sourceState = gridlyV229BuildNarrativeSourceCandidates(options);
  const snapshot = sourceState.snapshot || getGridlyV227AwarenessSnapshot(options);
  const area = gridlyV2291GetAwarenessAreaName(options);
  const base = [];
  sourceState.candidates.forEach((candidate) => base.push({ narrative: candidate.narrative, source: candidate.source, sourceType: candidate.sourceType, derived: Boolean(candidate.derived) }));
  const activeAwareness = snapshot?.activeAwareness || {};
  (Array.isArray(activeAwareness?.activeAwarenessSamples) ? activeAwareness.activeAwarenessSamples : []).forEach((sample, index) => {
    base.push({ narrative: sample?.reusedAlertText, source: `activeAwareness.activeAwarenessSamples.${index}.reusedAlertText`, sourceType: "active_awareness_sample", derived: false });
    base.push({ narrative: buildGridlyLightweightSummaryFromResolvedDetail({ resolvedCategory: sample?.resolvedCategory, resolvedLocationLabel: sample?.resolvedLocationLabel }).value, source: `activeAwareness.activeAwarenessSamples.${index}.resolvedCategory+resolvedLocationLabel`, sourceType: "active_awareness_sample", derived: true });
  });
  base.push({ narrative: activeAwareness?.headline, source: "activeAwareness.headline", sourceType: "active_awareness", derived: false });
  base.push({ narrative: activeAwareness?.reusedAlertText, source: activeAwareness?.reusedAlertSource || "activeAwareness.reusedAlertText", sourceType: "active_awareness", derived: false });
  base.push({ narrative: buildGridlyLightweightSummaryFromResolvedDetail({ resolvedCategory: activeAwareness?.resolvedCategory || activeAwareness?.topCategory, resolvedLocationLabel: activeAwareness?.resolvedLocationLabel }).value, source: "activeAwareness.resolvedCategory+resolvedLocationLabel", sourceType: "active_awareness", derived: true });

  const normalized = [];
  const seen = new Set();
  base.forEach((candidate) => {
    const narrative = gridlyV229NormalizeNarrativeText(candidate.narrative);
    const key = narrative.toLowerCase();
    if (!narrative || seen.has(key)) return;
    seen.add(key);
    normalized.push({ ...candidate, narrative });
  });

  const strongestCondition = normalized.map((candidate) => gridlyV2291ConditionLabelFromText(candidate.narrative, activeAwareness?.resolvedCategory || activeAwareness?.topCategory || "")).find(Boolean) || "";
  const roads = [];
  normalized.forEach((candidate) => gridlyV2291ExtractRoadReferences(candidate.narrative).forEach((road) => {
    if (!roads.some((entry) => normalizeRoadComparison(entry) === normalizeRoadComparison(road))) roads.push(road);
  }));
  const strongestRoadReference = roads[0] || "";
  if (strongestCondition && strongestRoadReference) {
    normalized.push({ narrative: `${strongestCondition} on ${strongestRoadReference}`, source: "readOnly.condition+roadCandidate", sourceType: "read_only_derived_candidate", derived: true });
  }
  if (strongestCondition && strongestRoadReference && area.name) {
    normalized.push({ narrative: gridlyV238FormatNarrativePromotionCopy(strongestCondition, strongestRoadReference, area.name, "impact"), source: "readOnly.condition+road+awarenessAreaCandidate", sourceType: "read_only_derived_candidate", derived: true });
  }

  return { candidates: normalized, sourceState, snapshot, awarenessAreaName: area.name, awarenessAreaSource: area.source, strongestCondition, roadNamesFound: roads, strongestRoadReference };
}

function gridlyNarrativeSpecificityAudit(options = {}) {
  const context = gridlyV2291BuildNarrativeAuditCandidates(options);
  const scored = context.candidates.map((candidate) => ({ ...candidate, ...gridlyV2291ScoreNarrative(candidate.narrative, context) }))
    .sort((a, b) => b.specificityScore - a.specificityScore || b.narrative.length - a.narrative.length);
  const highest = scored[0] || null;
  return {
    auditVersion: GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION,
    candidatesEvaluated: scored.length,
    highestSpecificityNarrative: highest?.narrative || "",
    specificityScore: highest?.specificityScore || 0,
    containsCondition: Boolean(highest?.containsCondition),
    containsRoad: Boolean(highest?.containsRoad),
    containsAwarenessArea: Boolean(highest?.containsAwarenessArea),
    findings: [
      highest ? `Highest specificity narrative scored ${highest.specificityScore}/100 from ${highest.source}.` : "No narrative candidates were available to score.",
      highest?.containsCondition ? "The strongest narrative includes condition context." : "The strongest narrative does not include condition context.",
      highest?.containsRoad ? `The strongest narrative includes roadway context (${highest.roadNames.join(", ")}).` : "The strongest narrative does not include roadway context.",
      highest?.containsAwarenessArea ? "The strongest narrative includes awareness-area/community context." : "The strongest narrative does not include awareness-area/community context.",
      "Specificity audit is read-only and does not promote or render any candidate."
    ]
  };
}

function gridlyNarrativeRankingAudit(options = {}) {
  const context = gridlyV2291BuildNarrativeAuditCandidates(options);
  const rankedCandidates = context.candidates.map((candidate) => {
    const score = gridlyV2291ScoreNarrative(candidate.narrative, context);
    const knowBeforeYouGoScore = score.specificityScore + (candidate.derived ? -1 : 0);
    return { narrative: candidate.narrative, source: candidate.source, sourceType: candidate.sourceType, score: score.specificityScore, knowBeforeYouGoScore, containsCondition: score.containsCondition, containsRoad: score.containsRoad, containsAwarenessArea: score.containsAwarenessArea, derived: Boolean(candidate.derived) };
  }).sort((a, b) => b.knowBeforeYouGoScore - a.knowBeforeYouGoScore || b.narrative.length - a.narrative.length);
  const best = rankedCandidates[0] || null;
  return {
    auditVersion: GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION,
    rankedCandidates,
    bestCandidate: best?.narrative || "",
    bestCandidateSource: best?.source || "none",
    rankingReason: best ? "Ranked by condition specificity, roadway specificity, awareness-area specificity, and Know Before You Go usefulness using existing read-only candidates." : "No candidates were available to rank.",
    findings: [
      best ? `Best candidate is ${best.sourceType} from ${best.source}.` : "No best candidate could be selected.",
      best?.containsCondition ? "Best candidate communicates what condition is active." : "Best candidate lacks condition context.",
      best?.containsRoad ? "Best candidate communicates the affected roadway." : "Best candidate lacks roadway context.",
      best?.containsAwarenessArea ? "Best candidate communicates the awareness area/community." : "Best candidate lacks awareness-area context.",
      "Ranking audit is read-only and does not modify awareness summaries or UI copy."
    ]
  };
}

function gridlyRoadContextAvailabilityAudit(options = {}) {
  const context = gridlyV2291BuildNarrativeAuditCandidates(options);
  return {
    auditVersion: GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION,
    roadContextAvailable: context.roadNamesFound.length > 0,
    roadNamesFound: context.roadNamesFound,
    strongestRoadReference: context.strongestRoadReference || "",
    findings: [
      context.roadNamesFound.length ? `Road context is available from existing narrative/intelligence candidates: ${context.roadNamesFound.join(", ")}.` : "No road names, roadway references, or corridor references were found in existing candidates.",
      context.strongestRoadReference ? `Strongest road reference selected for audit-only synthesis: ${context.strongestRoadReference}.` : "No strongest road reference could be selected.",
      "Road context audit reads existing active-condition and narrative candidates only."
    ]
  };
}

function gridlyAwarenessAreaContextAudit(options = {}) {
  const area = gridlyV2291GetAwarenessAreaName(options);
  const broad = /liberty county|countywide|entire/i.test(area.name);
  const communityContextAvailable = Boolean(area.name && !broad);
  return {
    auditVersion: GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION,
    awarenessAreaAvailable: Boolean(area.name),
    awarenessAreaName: area.name || "",
    communityContextAvailable,
    findings: [
      area.name ? `Awareness area context is available from ${area.source}.` : "No awareness area name was found in the audited state.",
      communityContextAvailable ? "The available awareness area is specific enough to support community wording such as an in-town phrase." : "Awareness area context is countywide or missing, so community-specific wording is limited.",
      "Awareness area audit reads selected awareness-area state and community awareness summary only."
    ]
  };
}

function gridlyIdealNarrativeReadinessAudit(options = {}) {
  const context = gridlyV2291BuildNarrativeAuditCandidates(options);
  const condition = context.strongestCondition || "";
  const road = context.strongestRoadReference || "";
  const area = context.awarenessAreaName || "";
  const missingElements = [];
  if (!condition) missingElements.push("condition");
  if (!road) missingElements.push("road");
  if (!area) missingElements.push("awareness_area");
  const idealNarrativePossible = missingElements.length === 0;
  const idealNarrativeCandidate = idealNarrativePossible ? `${condition} affecting ${road} in ${area}` : "";
  return {
    auditVersion: GRIDLY_NARRATIVE_SPECIFICITY_AUDIT_VERSION,
    idealNarrativePossible,
    idealNarrativeCandidate,
    missingElements,
    readinessAssessment: idealNarrativePossible ? "ready_with_existing_read_only_intelligence" : "not_ready_missing_existing_context",
    findings: [
      condition ? `Condition context available: ${condition}.` : "Condition context is missing.",
      road ? `Road context available: ${road}.` : "Road context is missing.",
      area ? `Awareness area context available: ${area}.` : "Awareness area context is missing.",
      idealNarrativePossible ? "Gridly can derive the ideal condition-road-awareness-area structure using existing intelligence only." : `Gridly cannot derive the ideal structure until missing elements are present: ${missingElements.join(", ") || "none"}.`,
      "Ideal narrative readiness audit does not promote the candidate or change ownership/UI/rendering."
    ]
  };
}

function gridlyCommunityPulseActiveAudit(options = {}) {
  const pulseAudit = gridlyCommunityPulseIntelligenceAudit(options);
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const pulseText = pulseAudit.userVisibleSummary || gridlyV228BuildConditionNarrative(snapshot);
  const supportsTrendNarratives = Boolean(pulseAudit.containsTrendInformation || /increasing|rising|building|elevated|fresh|recent|repeat|multiple|pressure/i.test(pulseText));
  const supportsLocationNarratives = Boolean(pulseAudit.containsLocationContext || /concentrated|corridor|near|around|along|area|county|crossing/i.test(pulseText) || snapshot?.locations?.dominantCorridor);
  const supportsImpactNarratives = Boolean(pulseAudit.containsActionableContext || gridlyV228TextHasImpact(pulseText));
  const readinessScore = Math.round(([supportsTrendNarratives, supportsLocationNarratives, supportsImpactNarratives, pulseAudit.containsObservationInformation].filter(Boolean).length / 4) * 100);
  const intelligenceReadiness = readinessScore >= 75 ? "ready" : (readinessScore >= 50 ? "partial" : "limited");
  return {
    auditVersion: GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION,
    supportsTrendNarratives,
    supportsLocationNarratives,
    supportsImpactNarratives,
    intelligenceReadiness,
    findings: [
      supportsTrendNarratives ? "Community Pulse supports increasing/building activity narratives." : "Community Pulse does not clearly support trend narratives yet.",
      supportsLocationNarratives ? "Community Pulse supports concentrated/corridor activity narratives." : "Community Pulse location/corridor narrative support is weak.",
      supportsImpactNarratives ? "Community Pulse supports travel-impact activity narratives." : "Community Pulse impact narrative support is weak.",
      `Active-state intelligence readiness is ${intelligenceReadiness} (${readinessScore}/100).`
    ]
  };
}

function gridlyDestinationImpactIntelligenceAudit(options = {}) {
  const destinationAudit = gridlyDestinationAwarenessAudit(options);
  const conditionAudit = gridlyActiveConditionIntelligenceAudit(options);
  const snapshot = getGridlyV227AwarenessSnapshot(options);
  const destinationText = [
    snapshot?.visibleText?.commandCard?.kicker,
    snapshot?.visibleText?.commandCard?.title,
    snapshot?.visibleText?.commandCard?.meta,
    snapshot?.visibleText?.commandCard?.crossings,
    snapshot?.visibleText?.commandCard?.impact
  ].filter(Boolean).join(" | ");
  const destinationAware = Boolean(destinationAudit.destinationPresent || destinationAudit.destinationContextPresent);
  const awarenessInherited = Boolean(destinationAudit.awarenessContextPresent || /awareness|community|hazard|report|issue|condition|area|county|crossing/i.test(destinationText));
  const routeDominanceDetected = Boolean(destinationAudit.routeOnlyInformation || (/route|navigate|preview|choose route|view route/i.test(destinationText) && !awarenessInherited));
  const destinationImpactNarrativeAvailable = Boolean(destinationAware && awarenessInherited && !routeDominanceDetected && (conditionAudit.explainsImpact || conditionAudit.explainsWhat));
  return {
    auditVersion: GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION,
    destinationAware,
    awarenessInherited,
    routeDominanceDetected,
    destinationImpactNarrativeAvailable,
    findings: [
      destinationAware ? "Destination context is present without requiring a redesign." : "Destination context is not present in the current audit state.",
      awarenessInherited ? "Destination context can inherit awareness intelligence." : "Destination context does not clearly inherit awareness intelligence.",
      routeDominanceDetected ? "Route-first language is dominant in the destination context." : "Route dominance was not detected in the destination context.",
      destinationImpactNarrativeAvailable ? "Destination impact intelligence is available while preserving awareness-first ownership." : "Destination impact intelligence is incomplete or too route-first."
    ]
  };
}

function gridlyKnowBeforeYouGoStressAudit(options = {}) {
  const conditionAudit = gridlyActiveConditionIntelligenceAudit(options);
  const narrativeAudit = gridlyAwarenessNarrativeAudit(options);
  const pulseActiveAudit = gridlyCommunityPulseActiveAudit(options);
  const destinationImpactAudit = gridlyDestinationImpactIntelligenceAudit(options);
  const stressTerms = ["road closures", "flooding", "construction", "blocked crossings", "multiple reports"];
  const combinedText = [conditionAudit.visibleConditionSummary, narrativeAudit.narrativeText, ...conditionAudit.findings, ...narrativeAudit.findings, ...pulseActiveAudit.findings, ...destinationImpactAudit.findings].join(" ");
  const supportsConditionAwareness = Boolean(conditionAudit.explainsWhat || narrativeAudit.explainsConditions);
  const supportsImpactAwareness = Boolean(conditionAudit.explainsImpact || narrativeAudit.impactContextPresent || pulseActiveAudit.supportsImpactNarratives || destinationImpactAudit.destinationImpactNarrativeAvailable);
  const supportsLocationAwareness = Boolean(conditionAudit.explainsWhere || narrativeAudit.locationContextPresent || pulseActiveAudit.supportsLocationNarratives);
  const stressCoverage = stressTerms.filter((term) => {
    if (term === "road closures") return /closure|closed|blocked|road/i.test(combinedText);
    if (term === "flooding") return /flood|water/i.test(combinedText);
    if (term === "construction") return /construction|work zone|workzone/i.test(combinedText);
    if (term === "blocked crossings") return /rail|train|crossing|blocked|delay/i.test(combinedText);
    if (term === "multiple reports") return /multiple|reports|signals|activity|hazards/i.test(combinedText) || narrativeAudit.combinesMultipleSignals;
    return false;
  });
  const supportsDecisionMaking = Boolean(supportsConditionAwareness && supportsImpactAwareness && supportsLocationAwareness && (narrativeAudit.narrativeAvailable || conditionAudit.observationDriven));
  const readinessScore = Math.round(([
    supportsDecisionMaking,
    supportsConditionAwareness,
    supportsImpactAwareness,
    supportsLocationAwareness,
    pulseActiveAudit.intelligenceReadiness === "ready" || pulseActiveAudit.intelligenceReadiness === "partial",
    destinationImpactAudit.awarenessInherited,
    stressCoverage.length >= 3
  ].filter(Boolean).length / 7) * 100);
  return {
    auditVersion: GRIDLY_ACTIVE_CONDITION_INTELLIGENCE_AUDIT_VERSION,
    supportsDecisionMaking,
    supportsConditionAwareness,
    supportsImpactAwareness,
    supportsLocationAwareness,
    readinessScore,
    findings: [
      supportsDecisionMaking ? "Gridly can support a better travel decision before departure." : "Gridly is not yet fully ready to support better travel decisions during active conditions.",
      supportsConditionAwareness ? "Condition awareness is supported." : "Condition awareness is weak.",
      supportsImpactAwareness ? "Impact awareness is supported." : "Impact awareness is weak.",
      supportsLocationAwareness ? "Location awareness is supported." : "Location awareness is weak.",
      `Stress condition language coverage: ${stressCoverage.length ? stressCoverage.join(", ") : "none detected"}.`,
      `Know Before You Go readiness score is ${readinessScore}/100.`
    ]
  };
}

const GRIDLY_NARRATIVE_PROMOTION_PROTOTYPE_VERSION = "V232.0";
const GRIDLY_NARRATIVE_LANGUAGE_STANDARD_AUDIT_VERSION = "V232.0";

const GRIDLY_V232_IMPACT_CONDITION_MATCHERS = [
  { matcher: /construction|road\s*work|work\s*zone|utility\s*work|maintenance/i, label: "Construction", reason: "Construction is a validated V231 impact condition." },
  { matcher: /flood|standing\s*water|high\s*water/i, label: "Flooding", reason: "Flooding is a validated V231 impact condition." },
  { matcher: /road\s*closure|road\s*closed|closure|closed/i, label: "Road closure", reason: "Road closure is a validated V231 impact condition." },
  { matcher: /rail|train|crossing|blocked/i, label: "Train blocking crossing", reason: "Blocked crossing is a validated impact condition." }
];

const GRIDLY_V232_OBSERVATION_CONDITION_MATCHERS = [
  { matcher: /crash|wreck|collision|accident/i, label: "Crash", reason: "Crash / wreck is a validated V231 observation condition." },
  { matcher: /disabled|stalled/i, label: "Disabled vehicle", reason: "Disabled vehicle is a validated V231 observation condition." },
  { matcher: /debris|tree\s*down|obstruction|object/i, label: "Debris", reason: "Debris is a validated V231 observation condition." },
  { matcher: /hazard|active\s*condition|unknown|ice|slick/i, label: "Hazard", reason: "General hazard is a validated V231 observation condition when exact impact is unknown." }
];

function gridlyV232ResolveNarrativeCondition(value = "") {
  const label = gridlyV229NormalizeNarrativeText(value);
  if (!label) return { label: "", conditionType: "", selectedPattern: "", patternReason: "No condition label was available." };
  const impactMatch = GRIDLY_V232_IMPACT_CONDITION_MATCHERS.find((definition) => definition.matcher.test(label));
  if (impactMatch) {
    return {
      label: impactMatch.label,
      conditionType: "impact",
      selectedPattern: impactMatch.label === "Train blocking crossing" ? "Train blocking crossing on <road> in <area>" : "<condition> affecting <road> in <area>",
      fallbackPattern: impactMatch.label === "Train blocking crossing" ? "Blocked crossing reported in <area>" : "<condition> affecting travel in <area>",
      patternReason: impactMatch.reason
    };
  }
  const observationMatch = GRIDLY_V232_OBSERVATION_CONDITION_MATCHERS.find((definition) => definition.matcher.test(label));
  if (observationMatch) {
    return {
      label: observationMatch.label,
      conditionType: "observation",
      selectedPattern: "<condition> reported on <road> in <area>",
      fallbackPattern: "<condition> reported in <area>",
      patternReason: observationMatch.reason
    };
  }
  return {
    label: "Hazard",
    conditionType: "observation",
    selectedPattern: "<condition> reported on <road> in <area>",
    fallbackPattern: "<condition> reported in <area>",
    patternReason: "Unmapped active mobility conditions default to the V231 general hazard observation pattern."
  };
}

function gridlyV238IsBlockedCrossingCondition(condition = "") {
  return /rail|train|crossing|blocked/i.test(gridlyV229NormalizeNarrativeText(condition));
}

function gridlyV238FormatNarrativePromotionCopy(condition = "", road = "", area = "", conditionType = "") {
  const selectedCondition = gridlyV229NormalizeNarrativeText(condition);
  const selectedRoad = gridlyV229NormalizeNarrativeText(road);
  const selectedArea = gridlyV229NormalizeNarrativeText(area);
  const areaSuffix = selectedArea ? ` in ${selectedArea}` : "";
  if (gridlyV238IsBlockedCrossingCondition(selectedCondition)) {
    return selectedRoad
      ? `Train blocking crossing on ${selectedRoad}${areaSuffix}`
      : `Blocked crossing reported${areaSuffix}`;
  }
  if (conditionType === "impact") {
    return selectedRoad
      ? `${selectedCondition} affecting ${selectedRoad}${areaSuffix}`
      : `${selectedCondition} affecting travel${areaSuffix}`;
  }
  return selectedRoad
    ? `${selectedCondition} reported on ${selectedRoad}${areaSuffix}`
    : `${selectedCondition} reported${areaSuffix}`;
}

function gridlyV230NormalizeConditionLabel(value = "") {
  return gridlyV232ResolveNarrativeCondition(value).label;
}

function gridlyV230NormalizeRoadReference(value = "") {
  let road = gridlyV229NormalizeNarrativeText(value)
    .replace(/^[,;:.\s]+|[,;:.\s]+$/g, "")
    .replace(/\b(?:reported nearby|active\s+mobility\s+report|mobility\s+report|affecting|travel|nearby)$/ig, "")
    .trim();
  if (!road) return "";
  road = road.replace(/\bFarm[\s\u2010-\u2015-]*to[\s\u2010-\u2015-]*Market\s+(?:Road\s+)?(\d+)\b/i, "FM $1");
  road = road.replace(/\bFarm\s+Road\s+(\d+)\b/i, "FM $1");
  road = road.replace(/\bCounty\s+Road\s+(\d+)\b/i, "CR $1");
  road = road.replace(/\b(?:U\.?S\.?|United\s+States)\s+(?:Highway\s+|Hwy\s+|Route\s+)?(\d+)\b/i, "US $1");
  road = road.replace(/\b(?:Texas|State)\s+(?:Highway\s+|Hwy\s+|Route\s+)?(\d+)\b/i, "TX $1");
  road = road.replace(/\bInterstate\s+(\d+)\b/i, "I-$1");
  road = road.replace(/\b(FM|RM|RR|CR|US|TX|SH|IH|I|Loop|Spur)\s*-?\s*(\d+)\b/i, (_match, prefix, number) => {
    const upper = String(prefix || "").toUpperCase();
    if (upper === "I") return `I-${number}`;
    return `${upper} ${number}`;
  });
  road = normalizeRoadDisplayCase(road);
  const genericRoadLabel = /^(?:road\s*work\s*reported\s*nearby|active\s*mobility\s*report|reported\s*nearby|road|street|highway|travel)$/i.test(road);
  if (genericRoadLabel) return "";
  if (/\b(?:reported nearby|active\s+mobility\s+report|mobility\s+report)\b/i.test(road)) return "";
  const roadReference = road.match(/\b(?:FM|RM|RR|CR|US|TX|SH|IH|I-|Loop|Spur)\s*\d+\b/i)?.[0] || "";
  return roadReference ? normalizeRoadDisplayCase(roadReference) : "";
}

function gridlyV230ExtractRoadReferences(text = "") {
  const normalized = gridlyV229NormalizeNarrativeText(text);
  if (!normalized) return [];
  const roads = [];
  const pushRoad = (value = "") => {
    const road = gridlyV230NormalizeRoadReference(value);
    if (!road) return;
    if (roads.some((entry) => normalizeRoadComparison(entry) === normalizeRoadComparison(road))) return;
    roads.push(road);
  };
  (normalized.match(/\bFarm[\s\u2010-\u2015-]*to[\s\u2010-\u2015-]*Market\s+(?:Road\s+)?\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\bFarm\s+Road\s+\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\bCounty\s+Road\s+\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\b(?:U\.?S\.?|United\s+States)\s+(?:Highway\s+|Hwy\s+|Route\s+)?\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\b(?:Texas|State)\s+(?:Highway\s+|Hwy\s+|Route\s+)?\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\bInterstate\s+\d+\b/gi) || []).forEach(pushRoad);
  (normalized.match(/\b(?:FM|RM|RR|CR|US|TX|SH|IH|I|Loop|Spur)\s*-?\s*\d+\b/gi) || []).forEach(pushRoad);
  return roads;
}

function gridlyV230VisibleAlertTextCandidates() {
  if (typeof document === "undefined" || !document?.querySelectorAll) return [];
  const alertRowSelector = [
    typeof GRIDLY_ALERT_ROW_SELECTOR === "string" ? GRIDLY_ALERT_ROW_SELECTOR : "[data-gridly-alert-id]",
    "[data-gridly-alert-row='true']",
    "[data-gridly-alert-summary]",
    "[data-gridly-alert-title]",
    "[data-gridly-alert-headline]",
    "[data-gridly-alert-location]",
    ".gridly-alert-row",
    "[data-alert-id]",
    "[data-alert-summary]",
    "[data-alert-title]",
    "[aria-label*='alert' i]",
    "[class*='alert' i]",
    "[class*='incident' i]",
    "[class*='hazard' i]",
    "article",
    "li",
    "[role='listitem']"
  ].join(",");
  const rows = Array.from(document.querySelectorAll(alertRowSelector));
  const candidates = [];
  const seen = new Set();
  const isElementVisible = (element) => {
    if (!element || element.hidden) return false;
    if (typeof element.getAttribute === "function" && element.getAttribute("data-gridly-alert-hidden") === "true") return false;
    const style = typeof window !== "undefined" && typeof window.getComputedStyle === "function" ? window.getComputedStyle(element) : null;
    if (style && (style.display === "none" || style.visibility === "hidden" || Number(style.opacity) === 0)) return false;
    const rect = typeof element.getBoundingClientRect === "function" ? element.getBoundingClientRect() : null;
    return !rect || rect.width > 0 || rect.height > 0;
  };
  const addVisibleAlertText = (text, source, index) => {
    const narrative = gridlyV229NormalizeNarrativeText(text);
    const key = `${source}|${narrative}`.toLowerCase();
    if (!narrative || seen.has(key)) return;
    seen.add(key);
    candidates.push({
      narrative,
      source,
      sourceType: "visible_alert_card",
      index,
      visible: true,
      derived: false
    });
  };
  rows.forEach((row, index) => {
    if (!row || typeof row.getAttribute !== "function") return;
    if (!isElementVisible(row)) return;
    if (typeof row.hasAttribute === "function" && row.hasAttribute("data-gridly-alert-expand")) return;
    addVisibleAlertText(row.getAttribute("data-gridly-alert-summary"), "visibleAlertCard.data-gridly-alert-summary", index);
    addVisibleAlertText(row.getAttribute("data-gridly-alert-title"), "visibleAlertCard.data-gridly-alert-title", index);
    addVisibleAlertText(row.getAttribute("data-gridly-alert-headline"), "visibleAlertCard.data-gridly-alert-headline", index);
    addVisibleAlertText(row.getAttribute("data-gridly-alert-location"), "visibleAlertCard.data-gridly-alert-location", index);
    addVisibleAlertText(row.getAttribute("data-alert-summary"), "visibleAlertCard.data-alert-summary", index);
    addVisibleAlertText(row.getAttribute("data-alert-title"), "visibleAlertCard.data-alert-title", index);
    addVisibleAlertText(row.getAttribute("aria-label"), "visibleAlertCard.aria-label", index);
    const textContent = gridlyV229NormalizeNarrativeText(row.textContent);
    if (gridlyV229NarrativeHasCondition(textContent) && gridlyV230ExtractRoadReferences(textContent).length) {
      addVisibleAlertText(textContent, "visibleAlertCard.textContent", index);
    }
  });
  if (!candidates.length && document.body) {
    const bodyText = gridlyV229NormalizeNarrativeText(document.body.textContent);
    const roadSentences = bodyText.split(/(?<=[.!?])\s+|\s+[•|]\s+/).filter((part) => gridlyV229NarrativeHasCondition(part) && gridlyV230ExtractRoadReferences(part).length).slice(0, 8);
    roadSentences.forEach((text, index) => addVisibleAlertText(text, "visibleAlertCard.bodyTextRoadSentence", index));
  }
  return candidates;
}

function gridlyV232CandidateSample(text = "") {
  return gridlyV229NormalizeNarrativeText(text).slice(0, 220);
}

function gridlyV232AddRoadCandidateSource(collection, rejected, candidate = {}, priority = 99, priorityLabel = "unknown") {
  const narrative = gridlyV229NormalizeNarrativeText(candidate?.narrative);
  if (!narrative) return;
  const roads = gridlyV230ExtractRoadReferences(narrative);
  const entry = {
    priority,
    priorityLabel,
    source: candidate?.source || "unknown",
    sourceType: candidate?.sourceType || "unknown",
    derived: Boolean(candidate?.derived),
    visible: Boolean(candidate?.visible),
    roads,
    narrativeSample: gridlyV232CandidateSample(narrative)
  };
  collection.push(entry);
  if (!roads.length) {
    rejected.push({
      source: entry.source,
      sourceType: entry.sourceType,
      priorityLabel,
      reason: "no_valid_road_reference_extracted",
      narrativeSample: entry.narrativeSample
    });
  }
}

function gridlyV232CollectDirectRoadFieldCandidates(options = {}, snapshot = {}) {
  const candidates = [];
  const addRoadField = (value, source, sourceType) => {
    const road = gridlyV230NormalizeRoadReference(value);
    const narrative = road || gridlyV229NormalizeNarrativeText(value);
    if (!narrative) return;
    candidates.push({ narrative, source, sourceType, derived: false, roadField: true });
  };
  const roadFieldNames = ["roadName", "primaryRoad", "resolvedRoadName", "nearestRoad", "nearestRoadName", "selectedRoadName", "displayRoadName", "routeNameDisplay", "routeName", "road", "route", "corridor", "highway", "locationName", "resolvedLocationLabel"];
  const inspectRecord = (record, sourcePrefix, sourceType) => {
    if (!record || typeof record !== "object") return;
    roadFieldNames.forEach((field) => addRoadField(record?.[field], `${sourcePrefix}.${field}`, sourceType));
    if (record.raw && typeof record.raw === "object") roadFieldNames.forEach((field) => addRoadField(record.raw?.[field], `${sourcePrefix}.raw.${field}`, sourceType));
    if (record.source && typeof record.source === "object") roadFieldNames.forEach((field) => addRoadField(record.source?.[field], `${sourcePrefix}.source.${field}`, sourceType));
  };
  (Array.isArray(snapshot?.communityAwarenessSummary?.activeHazardsInArea) ? snapshot.communityAwarenessSummary.activeHazardsInArea : []).forEach((hazard, index) => inspectRecord(hazard, `communityAwarenessSummary.activeHazardsInArea.${index}`, "active_hazard_road_field"));
  (Array.isArray(snapshot?.communityAwarenessSummary?.activeReportsInArea) ? snapshot.communityAwarenessSummary.activeReportsInArea : []).forEach((report, index) => inspectRecord(report, `communityAwarenessSummary.activeReportsInArea.${index}`, "active_report_road_field"));
  (Array.isArray(snapshot?.samples) ? snapshot.samples : []).forEach((sample, index) => inspectRecord(sample, `activeAwarenessSamples.${index}`, "active_awareness_road_field"));
  inspectRecord(options?.activeHazard, "options.activeHazard", "active_hazard_road_field");
  inspectRecord(options?.activeReport, "options.activeReport", "active_report_road_field");
  inspectRecord(options?.activeAwareness, "options.activeAwareness", "active_awareness_road_field");
  (Array.isArray(options?.activeHazards) ? options.activeHazards : []).forEach((hazard, index) => inspectRecord(hazard, `options.activeHazards.${index}`, "active_hazard_road_field"));
  (Array.isArray(options?.activeReports) ? options.activeReports : []).forEach((report, index) => inspectRecord(report, `options.activeReports.${index}`, "active_report_road_field"));
  return candidates;
}

function gridlyV232SelectRoadBySourcePriority({ visibleAlertCandidates = [], allCandidates = [], directRoadFieldCandidates = [] } = {}) {
  const roadCandidateSources = [];
  const rejectedRoadCandidates = [];
  const addBucket = (candidates, priority, priorityLabel) => (Array.isArray(candidates) ? candidates : []).forEach((candidate) => gridlyV232AddRoadCandidateSource(roadCandidateSources, rejectedRoadCandidates, candidate, priority, priorityLabel));
  const alertTextCandidates = allCandidates.filter((candidate) => {
    const sourceText = `${candidate?.source || ""} ${candidate?.sourceType || ""}`;
    return !candidate?.derived && /alert|headline|title|support|subline|summary|description|detail|message|reusedAlertText/i.test(sourceText) && candidate?.sourceType !== "visible_alert_card";
  });
  const activeHazardReportCandidates = allCandidates.filter((candidate) => /active_(?:hazard|report|awareness)/i.test(`${candidate?.sourceType || ""}`) && !candidate?.derived);
  const derivedCandidates = allCandidates.filter((candidate) => candidate?.derived || /derived|read_only_derived_candidate|readOnly\.condition\+road/i.test(`${candidate?.source || ""} ${candidate?.sourceType || ""}`));
  addBucket(visibleAlertCandidates, 1, "visible_alert_card_roadway_reference");
  addBucket(alertTextCandidates, 2, "alert_title_support_text_roadway_reference");
  addBucket([...directRoadFieldCandidates, ...activeHazardReportCandidates], 3, "active_hazard_report_roadway_field");
  addBucket(derivedCandidates, 4, "derived_candidate_roadway_reference");
  addBucket(allCandidates.filter((candidate) => !roadCandidateSources.some((entry) => entry.source === (candidate?.source || "unknown") && entry.narrativeSample === gridlyV232CandidateSample(candidate?.narrative))), 5, "other_existing_text_roadway_reference");
  const extractedRoadCandidates = [];
  roadCandidateSources
    .sort((a, b) => a.priority - b.priority)
    .forEach((entry) => entry.roads.forEach((road) => {
      if (extractedRoadCandidates.some((candidate) => normalizeRoadComparison(candidate.road) === normalizeRoadComparison(road))) return;
      extractedRoadCandidates.push({ road, source: entry.source, sourceType: entry.sourceType, priority: entry.priority, priorityLabel: entry.priorityLabel, narrativeSample: entry.narrativeSample });
    }));
  const selected = extractedRoadCandidates.find((candidate) => candidate.road) || null;
  return {
    selectedRoad: selected?.road || "",
    selectedRoadSource: selected ? `${selected.priorityLabel}:${selected.source}` : "fallback_travel_wording_no_road",
    roadCandidateSources,
    visibleAlertTextSamples: visibleAlertCandidates.map((candidate) => ({ source: candidate.source, index: candidate.index, text: gridlyV232CandidateSample(candidate.narrative), roads: gridlyV230ExtractRoadReferences(candidate.narrative) })).slice(0, 12),
    extractedRoadCandidates,
    rejectedRoadCandidates: rejectedRoadCandidates.slice(0, 24)
  };
}

function buildGridlyNarrativePromotionPrototype(options = {}) {
  const intel = options?.intel || {};
  const pulseModel = options?.pulseModel || {};
  const activeState = getGridlyAwarenessBriefActiveState({ intel, pulseModel });
  const context = gridlyV2291BuildNarrativeAuditCandidates(options);
  const activeConditionPresent = Boolean(
    !activeState.activeCountsAreClear
    || Number(context?.snapshot?.counts?.activeAwarenessCount || 0) > 0
    || Number(context?.snapshot?.counts?.activeHazardCount || 0) > 0
    || Number(context?.snapshot?.counts?.activeReportCount || 0) > 0
  );
  const area = gridlyV2291GetAwarenessAreaName(options);
  const selectedAwarenessArea = gridlyV229NormalizeNarrativeText(options?.awarenessAreaName || area.name || getGridlyAwarenessBriefTownLabel());
  const optionActiveAwareness = options?.activeAwareness || {};
  const optionCandidates = [];
  const addOptionCandidate = (narrative, source, sourceType = "active_awareness") => {
    const text = gridlyV229NormalizeNarrativeText(narrative);
    if (!text) return;
    optionCandidates.push({ narrative: text, source, sourceType, derived: false });
  };
  (Array.isArray(optionActiveAwareness?.activeAwarenessSamples) ? optionActiveAwareness.activeAwarenessSamples : []).forEach((sample, index) => {
    addOptionCandidate(sample?.reusedAlertText, `options.activeAwareness.activeAwarenessSamples.${index}.reusedAlertText`, "active_awareness_sample");
    addOptionCandidate(sample?.headline || sample?.title || sample?.description || sample?.summary || sample?.detail || sample?.message, `options.activeAwareness.activeAwarenessSamples.${index}.narrative`, "active_awareness_sample");
    addOptionCandidate(buildGridlyLightweightSummaryFromResolvedDetail({ resolvedCategory: sample?.resolvedCategory, resolvedLocationLabel: sample?.resolvedLocationLabel }).value, `options.activeAwareness.activeAwarenessSamples.${index}.resolvedCategory+resolvedLocationLabel`, "active_awareness_sample");
  });
  addOptionCandidate(optionActiveAwareness?.headline, "options.activeAwareness.headline");
  addOptionCandidate(optionActiveAwareness?.reusedAlertText, optionActiveAwareness?.reusedAlertSource || "options.activeAwareness.reusedAlertText");
  addOptionCandidate(buildGridlyLightweightSummaryFromResolvedDetail({ resolvedCategory: optionActiveAwareness?.resolvedCategory || optionActiveAwareness?.topCategory, resolvedLocationLabel: optionActiveAwareness?.resolvedLocationLabel }).value, "options.activeAwareness.resolvedCategory+resolvedLocationLabel");
  const visibleAlertCandidates = gridlyV230VisibleAlertTextCandidates();
  const allCandidates = gridlyV2291UniqueTexts([...(context.candidates || []).map((candidate) => candidate.narrative), ...optionCandidates.map((candidate) => candidate.narrative), ...visibleAlertCandidates.map((candidate) => candidate.narrative)])
    .map((narrative) => visibleAlertCandidates.find((candidate) => candidate.narrative === narrative) || optionCandidates.find((candidate) => candidate.narrative === narrative) || (context.candidates || []).find((candidate) => candidate.narrative === narrative) || { narrative, source: "unknown", sourceType: "unknown" });
  const directRoadFieldCandidates = gridlyV232CollectDirectRoadFieldCandidates(options, context.snapshot || {});
  const scoredCandidates = allCandidates.map((candidate) => {
    const score = gridlyV2291ScoreNarrative(candidate.narrative, context);
    const roadNames = gridlyV230ExtractRoadReferences(candidate.narrative);
    return {
      ...candidate,
      ...score,
      roadNames,
      v230Score: Number(score.specificityScore || 0) + (roadNames.length ? 18 : 0) + (candidate.derived ? -1 : 0)
    };
  }).sort((a, b) => b.v230Score - a.v230Score || b.narrative.length - a.narrative.length);
  const selectedCandidate = scoredCandidates.find((candidate) => candidate.conditionLabel || candidate.roadNames.length) || scoredCandidates[0] || null;
  const selectedRawCondition = selectedCandidate?.conditionLabel
    || context.strongestCondition
    || gridlyV2291ConditionLabelFromText(selectedCandidate?.narrative || "", context?.snapshot?.activeAwareness?.resolvedCategory || context?.snapshot?.activeAwareness?.topCategory || "");
  const standardizedCondition = gridlyV232ResolveNarrativeCondition(selectedRawCondition);
  const selectedCondition = standardizedCondition.label;
  const roadSelection = gridlyV232SelectRoadBySourcePriority({ visibleAlertCandidates, allCandidates, directRoadFieldCandidates });
  const selectedRoad = roadSelection.selectedRoad || "";
  const conditionType = activeConditionPresent && selectedCondition ? standardizedCondition.conditionType : "";
  const selectedPattern = activeConditionPresent && selectedCondition
    ? (selectedRoad ? standardizedCondition.selectedPattern : standardizedCondition.fallbackPattern)
    : "";
  const fallbackUsed = Boolean(activeConditionPresent && selectedCondition && !selectedRoad);
  let promotedNarrative = "";
  if (activeConditionPresent && selectedCondition) {
    promotedNarrative = gridlyV238FormatNarrativePromotionCopy(selectedCondition, selectedRoad, selectedAwarenessArea, conditionType);
  }
  return {
    activeConditionPresent,
    selectedCondition: activeConditionPresent ? selectedCondition : "",
    conditionType,
    selectedPattern,
    selectedRoad: activeConditionPresent ? selectedRoad : "",
    selectedAwarenessArea,
    promotedNarrative,
    fallbackUsed,
    patternReason: activeConditionPresent && selectedCondition ? standardizedCondition.patternReason : "No active condition was available for narrative promotion.",
    sourceUsed: promotedNarrative ? (selectedRoad ? roadSelection.selectedRoadSource : (selectedCandidate?.source && selectedCandidate.source !== "readOnly.condition+road+awarenessAreaCandidate" ? selectedCandidate.source : "fallback_travel_wording")) : "none",
    selectedRoadSource: activeConditionPresent && selectedRoad ? roadSelection.selectedRoadSource : "fallback_travel_wording_no_road",
    roadCandidateSources: roadSelection.roadCandidateSources,
    visibleAlertTextSamples: roadSelection.visibleAlertTextSamples,
    extractedRoadCandidates: roadSelection.extractedRoadCandidates,
    rejectedRoadCandidates: roadSelection.rejectedRoadCandidates,
    auditVersion: GRIDLY_NARRATIVE_PROMOTION_PROTOTYPE_VERSION
  };
}

function gridlyNarrativePromotionPrototypeAudit(options = {}) {
  const audit = buildGridlyNarrativePromotionPrototype(options);
  return {
    activeConditionPresent: audit.activeConditionPresent,
    selectedCondition: audit.selectedCondition,
    conditionType: audit.conditionType,
    selectedPattern: audit.selectedPattern,
    selectedRoad: audit.selectedRoad,
    selectedAwarenessArea: audit.selectedAwarenessArea,
    promotedNarrative: audit.promotedNarrative,
    fallbackUsed: audit.fallbackUsed,
    patternReason: audit.patternReason,
    sourceUsed: audit.sourceUsed,
    roadCandidateSources: audit.roadCandidateSources || [],
    visibleAlertTextSamples: audit.visibleAlertTextSamples || [],
    extractedRoadCandidates: audit.extractedRoadCandidates || [],
    rejectedRoadCandidates: audit.rejectedRoadCandidates || [],
    selectedRoadSource: audit.selectedRoadSource || ""
  };
}

function gridlyNarrativeLanguageStandardAudit(options = {}) {
  const audit = buildGridlyNarrativePromotionPrototype(options);
  return {
    auditVersion: GRIDLY_NARRATIVE_LANGUAGE_STANDARD_AUDIT_VERSION,
    conditionType: audit.conditionType || "",
    selectedPattern: audit.selectedPattern || "",
    selectedRoad: audit.selectedRoad || "",
    selectedAwarenessArea: audit.selectedAwarenessArea || "",
    promotedNarrative: audit.promotedNarrative || "",
    fallbackUsed: Boolean(audit.fallbackUsed),
    patternReason: audit.patternReason || "",
    roadCandidateSources: audit.roadCandidateSources || [],
    visibleAlertTextSamples: audit.visibleAlertTextSamples || [],
    extractedRoadCandidates: audit.extractedRoadCandidates || [],
    rejectedRoadCandidates: audit.rejectedRoadCandidates || [],
    selectedRoadSource: audit.selectedRoadSource || ""
  };
}


const GRIDLY_NARRATIVE_LANGUAGE_VALIDATION_AUDIT_VERSION = "V231.0";

function gridlyV231NarrativeScore({ pattern = "", conditionVerb = "", impactStrength = "" } = {}) {
  const awarenessUseful = pattern === "affectingRoadInArea" || impactStrength === "high" ? "strong" : "good";
  const decisionUseful = impactStrength === "high" ? "strong" : (pattern === "reportedOnRoadInArea" ? "good" : "moderate");
  return {
    naturalReadability: conditionVerb === "reported on" && pattern === "affectingRoadInArea" ? "awkward" : "natural",
    awarenessUsefulness: awarenessUseful,
    locationClarity: "strong",
    decisionUsefulness: decisionUseful
  };
}

