function buildGridlyOwnershipStateAudit(options = {}) {
  const auditVersion = "V226.4";
  const safeNow = () => {
    try {
      return new Date().toISOString();
    } catch (error) {
      return "";
    }
  };
  const safeTextById = (id) => {
    try {
      if (typeof document === "undefined") return null;
      const element = document.getElementById(id);
      if (!element) return null;
      return String(element.textContent || "").replace(/\s+/g, " ").trim();
    } catch (error) {
      return null;
    }
  };
  const safeCall = (fn, fallback = null) => {
    try {
      return typeof fn === "function" ? fn() : fallback;
    } catch (error) {
      return fallback;
    }
  };
  const safeBoolean = (fn) => {
    try {
      return Boolean(fn());
    } catch (error) {
      return false;
    }
  };
  const safeClassPresent = (element, className) => {
    try {
      return Boolean(element?.classList?.contains?.(className));
    } catch (error) {
      return false;
    }
  };
  const routeLatLngs = safeCall(() => (typeof getRoutePolylineLatLngs === "function" ? getRoutePolylineLatLngs() : null), null);
  const activeRouteCoordinateCount = Array.isArray(routeLatLngs)
    ? routeLatLngs.filter((pt) => Number.isFinite(Number(pt?.lat)) && Number.isFinite(Number(pt?.lng))).length
    : 0;
  const activeRoutePresent = activeRouteCoordinateCount > 1;
  const selectedDestinationLabel = safeCall(() => (typeof getSelectedDestinationLabel === "function" ? getSelectedDestinationLabel() : null), null);
  const selectedLabel = String(selectedDestinationLabel || "").trim();
  const routeIsMonitoring = safeBoolean(() => routeWatchActivated || window.__gridlyRouteWatchActive);
  const awarenessPanelMode = true;

  let commandCardOwner = "unknown";
  if (awarenessPanelMode) commandCardOwner = "awareness";
  else if (routeIsMonitoring) commandCardOwner = "route";
  else if (selectedLabel) commandCardOwner = "destination";

  const selectedAwarenessArea = safeCall(() => {
    if (typeof getSelectedGridlyAwarenessArea === "function") return getSelectedGridlyAwarenessArea();
    if (typeof getGridlySelectedAwarenessArea === "function") return getGridlySelectedAwarenessArea();
    return null;
  }, null);
  const awarenessStorageValue = safeCall(() => {
    if (typeof gridlySafeLocalStorageGet === "function") return gridlySafeLocalStorageGet("gridlyHomeTown");
    if (typeof window !== "undefined" && window.localStorage) return window.localStorage.getItem("gridlyHomeTown");
    return null;
  }, null);

  const awarenessDiagnostics = safeCall(() => (
    typeof getGridlyAwarenessModeDiagnostics === "function"
      ? getGridlyAwarenessModeDiagnostics({ ...options, ownershipAuditReadOnly: true, routeLatLngs: Array.isArray(routeLatLngs) ? routeLatLngs : [] })
      : null
  ), null);
  const pulseModel = options?.includeFreshPulseModel === true
    ? safeCall(() => (typeof buildGridlyCommunityPulseModel === "function" ? buildGridlyCommunityPulseModel({ ...options, ownershipAuditReadOnly: true, routeLatLngs: Array.isArray(routeLatLngs) ? routeLatLngs : [] }) : null), null)
    : null;
  const pulseState = pulseModel || (typeof gridlyCommunityPulseAuditState === "object" && gridlyCommunityPulseAuditState ? gridlyCommunityPulseAuditState : null);
  const pulseSurface = safeCall(() => (typeof document !== "undefined" ? document.getElementById("gridlyCommunityPulseSurface") : null), null);
  const pulseVisible = safeBoolean(() => {
    if (pulseSurface) return !pulseSurface.hidden;
    return pulseState?.pulseVisible;
  });
  const pulseSuppressedReason = String(pulseState?.pulseSuppressedReason || (awarenessDiagnostics?.awarenessMode === "route" ? "route-priority suppression: active route intelligence is primary" : "") || "");

  const commandCard = safeCall(() => (typeof document !== "undefined" ? document.getElementById("mobileDestinationCommandTitle")?.closest?.(".mobile-destination-command") || document.querySelector(".mobile-destination-command") : null), null);
  const crossingsElement = safeCall(() => (typeof document !== "undefined" ? document.getElementById("mobileAwarenessPanelCrossings") : null), null);
  const issuesElement = safeCall(() => (typeof document !== "undefined" ? document.getElementById("mobileAwarenessPanelIssues") : null), null);
  const destinationPreview = safeCall(() => (typeof window !== "undefined" && window.GridlyDestinationRoutePreview ? window.GridlyDestinationRoutePreview : null), null);
  const selectedDestination = safeCall(() => {
    if (typeof ensureGridlySearchState !== "function" || typeof normalizeGridlySearchResult !== "function") return null;
    return normalizeGridlySearchResult(ensureGridlySearchState()?.selectedDestination);
  }, null);

  const routeTakingCommandCardOwnership = commandCardOwner === "route" || Boolean(routeIsMonitoring && !awarenessPanelMode);
  const destinationTakingCommandCardOwnership = commandCardOwner === "destination";
  const routeSuppressingCommunityPulse = Boolean(activeRoutePresent && (awarenessDiagnostics?.awarenessMode === "route" || /route-priority suppression/i.test(pulseSuppressedReason)) && !pulseVisible);
  const awarenessLanguagePattern = /awareness|community|county|area|crossing|hazard|quiet|nearby/i;
  const commandCardTextForConflict = [
    safeTextById("mobileAwarenessPanelKicker"),
    safeTextById("mobileDestinationCommandTitle"),
    safeTextById("mobileDestinationCommandMeta"),
    safeTextById("mobileAwarenessPanelCrossings"),
    safeTextById("mobileAwarenessPanelIssues")
  ].filter(Boolean).join(" ");
  const awarenessLanguageStillShowing = awarenessLanguagePattern.test(commandCardTextForConflict);
  const conflictingOwners = Boolean(
    ((commandCardOwner === "route" || commandCardOwner === "destination") && awarenessLanguageStillShowing)
    || (commandCardOwner === "awareness" && routeSuppressingCommunityPulse)
  );
  const awarenessPrimary = Boolean(
    commandCardOwner === "awareness"
    && (pulseVisible || !routeSuppressingCommunityPulse)
    && !routeTakingCommandCardOwnership
    && !destinationTakingCommandCardOwnership
  );
  let summary = "Awareness is primary; no route or destination is taking command-card ownership.";
  if (conflictingOwners) summary = "Potential ownership conflict detected between command card language and route/community pulse state.";
  else if (destinationTakingCommandCardOwnership) summary = "Destination state is taking command-card ownership under current behavior.";
  else if (routeTakingCommandCardOwnership || routeSuppressingCommunityPulse) summary = "Route state is taking priority under current behavior.";
  else if (!awarenessPrimary) summary = "Ownership is indeterminate from the current runtime state.";

  return {
    available: true,
    version: auditVersion,
    generatedAt: safeNow(),
    awarenessArea: {
      selectedName: selectedAwarenessArea?.label || selectedAwarenessArea?.storageValue || null,
      selectedKey: selectedAwarenessArea?.key || null,
      storageValue: selectedAwarenessArea?.storageValue || awarenessStorageValue || null
    },
    commandCard: {
      selectedLabel: selectedLabel || null,
      routeIsMonitoring,
      awarenessPanelMode,
      owner: commandCardOwner,
      kickerText: safeTextById("mobileAwarenessPanelKicker"),
      titleText: safeTextById("mobileDestinationCommandTitle"),
      metaText: safeTextById("mobileDestinationCommandMeta"),
      crossingsText: safeTextById("mobileAwarenessPanelCrossings"),
      issuesText: safeTextById("mobileAwarenessPanelIssues"),
      impactText: safeTextById("mobileDestinationCommandImpact"),
      buttonText: safeTextById("mobileDestinationCommandBtn"),
      awarenessLinesVisible: Boolean((crossingsElement && !crossingsElement.hidden) || (issuesElement && !issuesElement.hidden)),
      destinationPanelClassPresent: safeClassPresent(commandCard, "is-destination-panel") || safeClassPresent(commandCard, "destination-panel"),
      bodyDestinationPanelClassPresent: safeBoolean(() => document.body?.classList?.contains?.("is-destination-panel") || document.body?.classList?.contains?.("destination-panel"))
    },
    communityPulse: {
      awarenessMode: awarenessDiagnostics?.awarenessMode || pulseState?.awarenessMode || null,
      pulseVisible,
      pulseSuppressedReason: pulseSuppressedReason || null,
      activeRouteCoordinateCount,
      activeRoutePresent,
      headlineText: safeTextById("gridlyCommunityPulseHeadline") || pulseState?.renderedPulseHeadline || null,
      sublineText: safeTextById("gridlyCommunityPulseSubline") || pulseState?.renderedPulseSubline || null
    },
    routeState: {
      routeWatchActivated: safeBoolean(() => routeWatchActivated),
      windowRouteWatchActive: safeBoolean(() => window.__gridlyRouteWatchActive),
      activeRouteCoordinateCount,
      savedRouteLayerPresent: safeBoolean(() => savedRouteLayer && typeof savedRouteLayer.getLayers === "function" && savedRouteLayer.getLayers().length > 0),
      routePreviewLayerPresent: safeBoolean(() => window.__gridlyRoutePreviewLayer && typeof window.__gridlyRoutePreviewLayer.getLatLngs === "function" && window.__gridlyRoutePreviewLayer.getLatLngs().length > 0)
    },
    destinationState: {
      selectedDestinationPresent: Boolean(selectedDestination || selectedLabel),
      selectedDestinationLabel: selectedLabel || null,
      routePreviewActive: Boolean(destinationPreview?.active),
      routePreviewStatus: destinationPreview?.status || null
    },
    ownershipAssessment: {
      awarenessPrimary,
      routeTakingCommandCardOwnership,
      destinationTakingCommandCardOwnership,
      routeSuppressingCommunityPulse,
      conflictingOwners,
      summary
    }
  };
}

window.gridlyOwnershipStateAudit = function gridlyOwnershipStateAudit(options = {}) {
  try {
    return buildGridlyOwnershipStateAudit(options || {});
  } catch (error) {
    return {
      available: true,
      version: "V226.4",
      generatedAt: (() => {
        try { return new Date().toISOString(); } catch (dateError) { return ""; }
      })(),
      error: error?.message || "ownership audit unavailable",
      awarenessArea: { selectedName: null, selectedKey: null, storageValue: null },
      commandCard: {
        selectedLabel: null,
        routeIsMonitoring: null,
        awarenessPanelMode: null,
        owner: "unknown",
        kickerText: null,
        titleText: null,
        metaText: null,
        crossingsText: null,
        issuesText: null,
        impactText: null,
        buttonText: null,
        awarenessLinesVisible: false,
        destinationPanelClassPresent: false,
        bodyDestinationPanelClassPresent: false
      },
      communityPulse: {
        awarenessMode: null,
        pulseVisible: false,
        pulseSuppressedReason: null,
        activeRouteCoordinateCount: 0,
        activeRoutePresent: false,
        headlineText: null,
        sublineText: null
      },
      routeState: {
        routeWatchActivated: null,
        windowRouteWatchActive: null,
        activeRouteCoordinateCount: 0,
        savedRouteLayerPresent: false,
        routePreviewLayerPresent: false
      },
      destinationState: {
        selectedDestinationPresent: false,
        selectedDestinationLabel: null,
        routePreviewActive: false,
        routePreviewStatus: null
      },
      ownershipAssessment: {
        awarenessPrimary: false,
        routeTakingCommandCardOwnership: false,
        destinationTakingCommandCardOwnership: false,
        routeSuppressingCommunityPulse: false,
        conflictingOwners: false,
        summary: "Ownership audit caught an error and returned a safe fallback."
      }
    };
  }
};



function gridlyHistoricalIntelligenceTitleCaseLocation(value = "") {
  const preservedAbbreviations = new Set(["US", "TX", "FM", "SH", "IH", "I", "CR", "RR"]);
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/\b[a-z0-9]+\b/g, (word) => {
      const upper = word.toUpperCase();
      if (preservedAbbreviations.has(upper) || /^\d+[a-z]?$/.test(word)) return upper;
      return word.charAt(0).toUpperCase() + word.slice(1);
    })
    .replace(/\b(Mc)([a-z])/g, (_, prefix, letter) => `${prefix}${letter.toUpperCase()}`);
}

function gridlyHistoricalIntelligenceDisplayLocation(finding = {}) {
  return gridlyHistoricalIntelligenceTitleCaseLocation(finding.locationLabel || finding.nearbyLocationLabel || finding.referenceRoad || "Local Area") || "Local Area";
}

const GRIDLY_HISTORICAL_INTELLIGENCE_LANGUAGE = Object.freeze({
  most_blocked_crossing: Object.freeze({
    title: "Frequently Blocked Crossing",
    category: "Crossing",
    description: () => "Drivers have reported recurring train delays here."
  }),
  recurring_flooding_location: Object.freeze({
    title: "Recurring Flooding Location",
    category: "Flooding",
    description: () => "Drivers have frequently reported water on the road here."
  }),
  repeat_construction_zone: Object.freeze({
    title: "Recurring Construction Zone",
    category: "Construction",
    description: () => "Drivers have reported recurring road work in this area."
  }),
  high_delay_corridor: Object.freeze({
    title: "Common Delay Area",
    category: "Delay",
    description: () => "Community reports show delays here often take time to clear."
  }),
  community_confirmed_hotspot: Object.freeze({
    title: "Community Hotspot",
    category: "Hotspot",
    description: () => "Local drivers have repeatedly confirmed activity in this area."
  }),
  recurring_hazard: Object.freeze({
    title: "Recurring Road Hazard",
    category: "Road Hazard",
    description: (finding) => `Drivers have frequently reported ${finding.hazardLabel || "a road hazard"} here.`
  }),
  no_history: Object.freeze({
    title: "Not Enough History Yet",
    category: "History",
    description: () => "Gridly will show local patterns here after more cleared reports are collected."
  })
});

function getGridlyIntelligencePreviewLanguage(category = "no_history") {
  return GRIDLY_HISTORICAL_INTELLIGENCE_LANGUAGE[category] || GRIDLY_HISTORICAL_INTELLIGENCE_LANGUAGE.no_history;
}

function getGridlyIntelligencePreviewCategoryLabel(category = "no_history") {
  return getGridlyIntelligencePreviewLanguage(category).category;
}

function gridlyHistoricalIntelligenceConfirmationCount(record = {}) {
  const explicit = Number(record?.confirmationCount ?? record?.confirmations ?? record?.confirmation_count);
  return Number.isFinite(explicit) ? Math.max(0, Math.round(explicit)) : 0;
}

function gridlyHistoricalIntelligenceLatestTimestamp(records = []) {
  return records.reduce((latest, record) => {
    const ms = new Date(gridlyHistoricalAuditTimestamp(record) || record?.clearedAt || record?.cleared_at || 0).getTime();
    return Number.isFinite(ms) && ms > latest ? ms : latest;
  }, 0);
}

function gridlyHistoricalIntelligenceRecencyBoost(records = []) {
  const latest = gridlyHistoricalIntelligenceLatestTimestamp(records);
  if (!latest) return 0;
  const ageDays = Math.max(0, (Date.now() - latest) / 86400000);
  if (ageDays <= 7) return 20;
  if (ageDays <= 30) return 12;
  if (ageDays <= 90) return 6;
  return 0;
}

function gridlyHistoricalIntelligenceHazardLabel(record = {}) {
  const raw = gridlyHistoricalAuditHazardType(record);
  const normalized = typeof gridlyNormalizeHazardType === "function" ? gridlyNormalizeHazardType({ type: raw }) : raw;
  const copy = HAZARD_TYPES?.[normalized] || HAZARD_TYPES?.[raw] || null;
  return safeDisplayText(copy?.label || raw, "road hazard").toLowerCase();
}

function gridlyHistoricalIntelligenceGroupRecords(records = [], keyBuilder = () => "") {
  const groups = new Map();
  records.forEach((record) => {
    const key = String(keyBuilder(record) || "").trim().toLowerCase();
    if (!key) return;
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(record);
  });
  return groups;
}

function gridlyHistoricalIntelligenceNormalizeLocationToken(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/\b(state highway|state hwy|highway|hwy|texas|tx)\b/g, "tx")
    .replace(/\b(farm to market|farm road|fm road|f m)\b/g, "fm")
    .replace(/\b(road|rd)\b/g, "rd")
    .replace(/\b(street|st)\b/g, "st")
    .replace(/\b(avenue|ave)\b/g, "ave")
    .replace(/\b(boulevard|blvd)\b/g, "blvd")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function gridlyHistoricalIntelligenceReferenceRoad(record = {}) {
  return safeDisplayText(
    record?.referenceRoad
      || record?.reference_road
      || record?.crossStreet
      || record?.cross_street
      || record?.nearestCrossStreet
      || record?.nearest_cross_street
      || record?.intersection
      || record?.referenceLocation
      || record?.reference_location
      || "",
    ""
  );
}

function gridlyHistoricalIntelligenceRecordId(record = {}, index = 0) {
  const explicit = record?.id || record?.incidentId || record?.incident_id || record?.reportId || record?.report_id || record?.historicalRecordId || record?.historical_record_id || record?.eventId || record?.event_id || record?.uuid;
  if (explicit) return String(explicit);
  return [
    gridlyHistoricalAuditTimestamp(record),
    record?.clearedAt || record?.cleared_at || "",
    gridlyHistoricalAuditHazardType(record),
    gridlyHistoricalAuditRoad(record),
    gridlyHistoricalAuditCrossing(record),
    gridlyHistoricalIntelligenceReferenceRoad(record)
  ].map((part) => String(part || "").trim().toLowerCase()).join("|");
}

function gridlyHistoricalIntelligenceFindingSpecificity(category = "") {
  if (category === "community_confirmed_hotspot") return 0;
  if (category === "high_delay_corridor") return 1;
  if (category === "recurring_hazard") return 2;
  if (category === "most_blocked_crossing" || category === "recurring_flooding_location" || category === "repeat_construction_zone") return 3;
  return 1;
}

function gridlyHistoricalIntelligenceFindingFamily(finding = {}) {
  const category = String(finding.category || "");
  if (category === "community_confirmed_hotspot") return "hotspot";
  if (category === "recurring_flooding_location") return "flooding";
  if (category === "repeat_construction_zone") return "construction";
  if (category === "most_blocked_crossing") return "crossing";
  if (category === "high_delay_corridor") return "delay";
  return "road_hazard";
}

function gridlyHistoricalIntelligenceBuildFinding({ category, records, locationLabel = "", hazardLabel = "", baseScore = 0 } = {}) {
  const usableRecords = Array.isArray(records) ? records : [];
  const count = usableRecords.length;
  const averageDurationMinutes = gridlyHistoricalIntelligenceAverageDuration(usableRecords);
  const confirmationCount = usableRecords.reduce((sum, record) => sum + gridlyHistoricalIntelligenceConfirmationCount(record), 0);
  const durationScore = averageDurationMinutes ? Math.min(35, Math.round(averageDurationMinutes / 3)) : 0;
  const confirmationScore = Math.min(40, confirmationCount * 4);
  const significanceScore = Math.round(baseScore + count * 25 + durationScore + confirmationScore + gridlyHistoricalIntelligenceRecencyBoost(usableRecords));
  const normalizedRoadName = gridlyHistoricalIntelligenceNormalizeLocationToken(gridlyHistoricalAuditRoad(usableRecords[0] || {}) || locationLabel);
  const referenceRoad = usableRecords.map((record) => gridlyHistoricalIntelligenceReferenceRoad(record)).find(Boolean) || "";
  const normalizedReferenceRoad = gridlyHistoricalIntelligenceNormalizeLocationToken(referenceRoad);
  const normalizedLocationLabel = gridlyHistoricalIntelligenceNormalizeLocationToken(locationLabel);
  const sourceRecordIds = usableRecords.map((record, index) => gridlyHistoricalIntelligenceRecordId(record, index)).filter(Boolean);
  return {
    category,
    title: getGridlyIntelligencePreviewLanguage(category).title,
    categoryLabel: getGridlyIntelligencePreviewLanguage(category).category,
    locationLabel: safeDisplayText(locationLabel, ""),
    nearbyLocationLabel: safeDisplayText(locationLabel, ""),
    hazardLabel: safeDisplayText(hazardLabel, ""),
    count,
    averageDurationMinutes,
    confirmationCount,
    latestAt: gridlyHistoricalIntelligenceLatestTimestamp(usableRecords) ? new Date(gridlyHistoricalIntelligenceLatestTimestamp(usableRecords)).toISOString() : null,
    significanceScore,
    sourceRecordIds,
    normalizedRoadName,
    referenceRoad,
    normalizedReferenceRoad,
    normalizedLocationLabel,
    groupingKey: [normalizedRoadName, normalizedReferenceRoad, normalizedLocationLabel, gridlyHistoricalIntelligenceFindingFamily({ category })].filter(Boolean).join("|"),
    source: "real_historical_records"
  };
}

function gridlyHistoricalIntelligenceSharedRecordCount(a = {}, b = {}) {
  const left = new Set(Array.isArray(a.sourceRecordIds) ? a.sourceRecordIds : []);
  if (!left.size) return 0;
  return (Array.isArray(b.sourceRecordIds) ? b.sourceRecordIds : []).filter((id) => left.has(id)).length;
}

function gridlyHistoricalIntelligenceSameLocalPattern(a = {}, b = {}) {
  const sharedRecordCount = gridlyHistoricalIntelligenceSharedRecordCount(a, b);
  if (sharedRecordCount > 0) return { grouped: true, reason: "shared historical record ids" };

  const sameRoad = Boolean(a.normalizedRoadName && b.normalizedRoadName && a.normalizedRoadName === b.normalizedRoadName);
  const sameReference = Boolean(a.normalizedReferenceRoad && b.normalizedReferenceRoad && a.normalizedReferenceRoad === b.normalizedReferenceRoad);
  const sameLabel = Boolean(a.normalizedLocationLabel && b.normalizedLocationLabel && a.normalizedLocationLabel === b.normalizedLocationLabel);
  if (!sameRoad && !sameReference && !sameLabel) return { grouped: false, reason: "different local labels" };

  const aFamily = gridlyHistoricalIntelligenceFindingFamily(a);
  const bFamily = gridlyHistoricalIntelligenceFindingFamily(b);
  const genericOverlap = aFamily === "hotspot" || bFamily === "hotspot";
  if (genericOverlap) return { grouped: true, reason: "generic hotspot overlaps a category-specific local pattern" };
  if (aFamily === bFamily) return { grouped: true, reason: "same category and nearby road/corridor label" };
  if (sameReference && sameRoad) return { grouped: true, reason: "same road and reference road" };

  return { grouped: false, reason: "different category-specific patterns" };
}

function gridlyHistoricalIntelligencePreferFinding(a = {}, b = {}) {
  const specificityDelta = gridlyHistoricalIntelligenceFindingSpecificity(a.category) - gridlyHistoricalIntelligenceFindingSpecificity(b.category);
  if (specificityDelta !== 0) return specificityDelta > 0 ? a : b;
  const scoreDelta = Number(a.significanceScore || 0) - Number(b.significanceScore || 0);
  if (scoreDelta !== 0) return scoreDelta > 0 ? a : b;
  const countDelta = Number(a.count || 0) - Number(b.count || 0);
  if (countDelta !== 0) return countDelta > 0 ? a : b;
  const latestDelta = new Date(a.latestAt || 0).getTime() - new Date(b.latestAt || 0).getTime();
  if (latestDelta !== 0) return latestDelta > 0 ? a : b;
  return String(a.title || "").localeCompare(String(b.title || "")) <= 0 ? a : b;
}

function gridlyHistoricalIntelligenceMergeFindingGroup(keeper = {}, suppressed = {}, reason = "related local pattern") {
  const sourceRecordIds = Array.from(new Set([
    ...(Array.isArray(keeper.sourceRecordIds) ? keeper.sourceRecordIds : []),
    ...(Array.isArray(suppressed.sourceRecordIds) ? suppressed.sourceRecordIds : [])
  ].filter(Boolean)));
  const groupingReasons = Array.from(new Set([
    ...(Array.isArray(keeper.groupingReasons) ? keeper.groupingReasons : []),
    reason
  ].filter(Boolean)));
  const groupedFindingCount = Number(keeper.groupedFindingCount || 0) + 1 + Number(suppressed.groupedFindingCount || 0);
  const groupedRelatedReportCount = Math.max(Number(keeper.count || 0), sourceRecordIds.length, Number(suppressed.count || 0));
  return {
    ...keeper,
    sourceRecordIds,
    groupedFindingCount,
    groupedRelatedReportCount,
    groupingReasons,
    groupedFromCategories: Array.from(new Set([
      ...(Array.isArray(keeper.groupedFromCategories) ? keeper.groupedFromCategories : []),
      keeper.categoryLabel || getGridlyIntelligencePreviewCategoryLabel(keeper.category),
      suppressed.categoryLabel || getGridlyIntelligencePreviewCategoryLabel(suppressed.category)
    ].filter(Boolean)))
  };
}

function gridlyDeduplicateHistoricalIntelligenceFindings(rankedFindings = []) {
  const rawFindings = Array.isArray(rankedFindings) ? rankedFindings : [];
  if (rawFindings.length <= 1) {
    return {
      dedupedRankedFindings: rawFindings.map((finding, index) => ({ ...finding, rank: index + 1 })),
      suppressedFindings: [],
      suppressedFindingsSample: [],
      groupingReasons: [],
      groupedFindingCount: 0,
      suppressedFindingCount: 0
    };
  }

  const candidates = rawFindings
    .map((finding) => ({ ...finding }))
    .sort((a, b) => {
      const preferred = gridlyHistoricalIntelligencePreferFinding(a, b);
      if (preferred === a && preferred !== b) return -1;
      if (preferred === b && preferred !== a) return 1;
      return Number(a.rank || 0) - Number(b.rank || 0);
    });
  const keepers = [];
  const suppressedFindings = [];
  const groupingReasons = [];

  candidates.forEach((candidate) => {
    let grouped = false;
    for (let index = 0; index < keepers.length; index += 1) {
      const comparison = gridlyHistoricalIntelligenceSameLocalPattern(candidate, keepers[index]);
      if (!comparison.grouped) continue;
      const preferred = gridlyHistoricalIntelligencePreferFinding(candidate, keepers[index]);
      const suppressed = preferred === candidate ? keepers[index] : candidate;
      const keeper = preferred === candidate ? candidate : keepers[index];
      keepers[index] = gridlyHistoricalIntelligenceMergeFindingGroup(keeper, suppressed, comparison.reason);
      suppressedFindings.push({
        rank: suppressed.rank,
        title: suppressed.title,
        category: suppressed.category,
        categoryLabel: suppressed.categoryLabel,
        locationLabel: suppressed.locationLabel,
        count: suppressed.count,
        suppressedBy: keeper.title,
        reason: comparison.reason
      });
      groupingReasons.push(comparison.reason);
      grouped = true;
      break;
    }
    if (!grouped) keepers.push(candidate);
  });

  const dedupedRankedFindings = keepers
    .sort((a, b) => {
      const adjustedA = Number(a.significanceScore || 0) + gridlyHistoricalIntelligenceFindingSpecificity(a.category) * 10;
      const adjustedB = Number(b.significanceScore || 0) + gridlyHistoricalIntelligenceFindingSpecificity(b.category) * 10;
      return adjustedB - adjustedA || Number(b.count || 0) - Number(a.count || 0) || String(a.title || "").localeCompare(String(b.title || ""));
    })
    .map((finding, index) => ({ ...finding, rank: index + 1 }));

  return {
    dedupedRankedFindings,
    suppressedFindings,
    suppressedFindingsSample: suppressedFindings.slice(0, 6),
    groupingReasons: Array.from(new Set(groupingReasons)),
    groupedFindingCount: suppressedFindings.length,
    suppressedFindingCount: suppressedFindings.length
  };
}

function gridlyBuildHistoricalIntelligenceFindings() {
  const snapshot = gridlyReadHistoricalIntelligenceStorageSnapshot();
  const crossingEvents = Array.isArray(snapshot.state?.crossingEvents) ? snapshot.state.crossingEvents : [];
  const hazardEvents = Array.isArray(snapshot.state?.hazardEvents) ? snapshot.state.hazardEvents : [];
  const findings = [];

  const crossingGroups = gridlyHistoricalIntelligenceGroupRecords(crossingEvents, (record) => gridlyHistoricalAuditLocationKey(record, "crossing"));
  crossingGroups.forEach((records) => {
    if (records.length < 2) return;
    const sample = records[0] || {};
    findings.push(gridlyHistoricalIntelligenceBuildFinding({
      category: "most_blocked_crossing",
      records,
      locationLabel: gridlyHistoricalAuditCrossing(sample) || sample.crossingName || sample.crossingId || "this crossing",
      baseScore: 35
    }));
  });

  const floodEvents = hazardEvents.filter((record) => /flood|high_water|high water|water/.test(gridlyHistoricalAuditHazardType(record).toLowerCase()));
  const floodGroups = gridlyHistoricalIntelligenceGroupRecords(floodEvents, (record) => gridlyHistoricalAuditRoad(record));
  floodGroups.forEach((records) => {
    if (records.length < 2) return;
    findings.push(gridlyHistoricalIntelligenceBuildFinding({ category: "recurring_flooding_location", records, locationLabel: gridlyHistoricalAuditRoad(records[0]), baseScore: 45 }));
  });

  const constructionEvents = hazardEvents.filter((record) => /construction|roadwork|road_work|work_zone|work zone|lane_closure|closure/.test(gridlyHistoricalAuditHazardType(record).toLowerCase()));
  const constructionGroups = gridlyHistoricalIntelligenceGroupRecords(constructionEvents, (record) => gridlyHistoricalAuditRoad(record));
  constructionGroups.forEach((records) => {
    if (records.length < 2) return;
    findings.push(gridlyHistoricalIntelligenceBuildFinding({ category: "repeat_construction_zone", records, locationLabel: gridlyHistoricalAuditRoad(records[0]), baseScore: 30 }));
  });

  const hazardGroups = gridlyHistoricalIntelligenceGroupRecords(hazardEvents, (record) => gridlyHistoricalAuditLocationKey(record, "hazard"));
  hazardGroups.forEach((records) => {
    if (records.length < 2) return;
    const sample = records[0] || {};
    findings.push(gridlyHistoricalIntelligenceBuildFinding({
      category: "recurring_hazard",
      records,
      locationLabel: gridlyHistoricalAuditRoad(sample),
      hazardLabel: gridlyHistoricalIntelligenceHazardLabel(sample),
      baseScore: 20
    }));
  });

  const durationEvents = [...crossingEvents, ...hazardEvents].filter((record) => Boolean(gridlyHistoricalAuditRoad(record)) && gridlyHistoricalIntelligenceHasClearTime(record) && Number.isFinite(Number(gridlyHistoricalAuditDuration(record))));
  const durationGroups = gridlyHistoricalIntelligenceGroupRecords(durationEvents, (record) => gridlyHistoricalAuditRoad(record));
  durationGroups.forEach((records) => {
    if (records.length < 2) return;
    const averageDurationMinutes = gridlyHistoricalIntelligenceAverageDuration(records);
    if (!averageDurationMinutes) return;
    const finding = gridlyHistoricalIntelligenceBuildFinding({ category: "high_delay_corridor", records, locationLabel: gridlyHistoricalAuditRoad(records[0]), baseScore: 25 });
    findings.push({ ...finding, significanceScore: finding.significanceScore + Math.min(30, Math.round(averageDurationMinutes / 2)) });
  });

  const confirmedEvents = [...crossingEvents, ...hazardEvents].filter((record) => gridlyHistoricalIntelligenceConfirmationCount(record) > 0);
  const confirmedGroups = gridlyHistoricalIntelligenceGroupRecords(confirmedEvents, (record) => gridlyHistoricalAuditRoad(record) || gridlyHistoricalAuditLocationKey(record, record?.crossingId || record?.crossing_id ? "crossing" : "hazard"));
  confirmedGroups.forEach((records) => {
    const confirmationCount = records.reduce((sum, record) => sum + gridlyHistoricalIntelligenceConfirmationCount(record), 0);
    if (records.length < 2 && confirmationCount < 2) return;
    findings.push(gridlyHistoricalIntelligenceBuildFinding({ category: "community_confirmed_hotspot", records, locationLabel: gridlyHistoricalAuditRoad(records[0]) || gridlyHistoricalAuditCrossing(records[0]), baseScore: 15 }));
  });

  const rankedFindings = findings
    .filter((finding) => finding.count > 0 && Number.isFinite(Number(finding.significanceScore)))
    .sort((a, b) => Number(b.significanceScore) - Number(a.significanceScore) || Number(b.count) - Number(a.count) || String(a.title).localeCompare(String(b.title)))
    .map((finding, index) => ({ ...finding, rank: index + 1 }));
  const dedupe = gridlyDeduplicateHistoricalIntelligenceFindings(rankedFindings);
  const dedupedRankedFindings = dedupe.dedupedRankedFindings;

  return {
    rawFindingCount: rankedFindings.length,
    dedupedFindingCount: dedupedRankedFindings.length,
    groupedFindingCount: dedupe.groupedFindingCount,
    suppressedFindingCount: dedupe.suppressedFindingCount,
    rankedFindings,
    dedupedRankedFindings,
    suppressedFindingsSample: dedupe.suppressedFindingsSample,
    groupingReasons: dedupe.groupingReasons,
    strongestFinding: dedupedRankedFindings[0] || null,
    historicalRecordCount: crossingEvents.length + hazardEvents.length,
    crossingEventCount: crossingEvents.length,
    hazardEventCount: hazardEvents.length,
    storageFound: Boolean(snapshot.found),
    parseOk: Boolean(snapshot.parseOk),
    storageReadError: snapshot.storageReadError || null,
    readOnly: true,
    writesAnalytics: false,
    writesTelemetry: false,
    writesSupabase: false,
    changesRouting: false,
    changesAlerts: false
  };
}

function gridlyHistoricalIntelligenceHasClearTime(record = {}) {
  const explicit = Number(record?.durationMinutes ?? record?.duration ?? record?.duration_min ?? record?.durationMins);
  if (Number.isFinite(explicit) && explicit >= 0) return true;
  const clearedAt = record?.clearedAt || record?.cleared_at || null;
  return Boolean(clearedAt && gridlyHistoricalAuditTimestamp(record));
}

function gridlyHistoricalIntelligenceAverageDuration(records = []) {
  const durations = records
    .filter((record) => gridlyHistoricalIntelligenceHasClearTime(record))
    .map((record) => Number(gridlyHistoricalAuditDuration(record)))
    .filter((value) => Number.isFinite(value) && value >= 0);
  if (!durations.length) return null;
  return Math.max(1, Math.round(durations.reduce((sum, value) => sum + value, 0) / durations.length));
}

function formatGridlyHistoricalIntelligenceDate(value) {
  const ms = new Date(value || 0).getTime();
  if (!Number.isFinite(ms) || ms <= 0) return "";
  return new Date(ms).toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" });
}

function formatGridlyHistoricalIntelligenceDuration(minutes) {
  const value = Number(minutes);
  if (!Number.isFinite(value) || value <= 0) return "";
  if (value < 60) return `${Math.round(value)} min`;
  const hours = Math.floor(value / 60);
  const mins = Math.round(value % 60);
  return mins ? `${hours} hr ${mins} min` : `${hours} hr`;
}

function buildGridlyIntelligencePreviewCardModel(options = {}) {
  const historical = gridlyBuildHistoricalIntelligenceFindings(options);
  const strongest = historical.strongestFinding;
  const selectedCategory = strongest?.category || "no_history";
  const dedupedRankedFindings = Array.isArray(historical.dedupedRankedFindings) ? historical.dedupedRankedFindings : [];
  const findingCount = dedupedRankedFindings.length;
  const fallbackMode = Number(historical.historicalRecordCount || 0) === 0;
  return {
    cardAvailable: Boolean(document.getElementById("gridlyHistoryDockButton")),
    chipRendered: false,
    historyChipRemoved: true,
    historyDockButtonRendered: Boolean(document.getElementById("gridlyHistoryDockButton")),
    sheetAvailable: true,
    selectedCategory,
    selectedTitle: "History",
    selectedDescription: "Local patterns",
    supportingData: {
      ...historical,
      source: "Real historical records",
      selectedCommunityCount: 0,
      activeAwarenessCount: 0
    },
    findingCount,
    rawFindingCount: Number(historical.rawFindingCount || 0),
    dedupedFindingCount: findingCount,
    groupedFindingCount: Number(historical.groupedFindingCount || 0),
    suppressedFindingCount: Number(historical.suppressedFindingCount || 0),
    rankedFindings: historical.rankedFindings,
    dedupedRankedFindings,
    suppressedFindingsSample: historical.suppressedFindingsSample || [],
    groupingReasons: historical.groupingReasons || [],
    strongestFinding: strongest,
    previewMode: false,
    fallbackMode,
    noPreviewLanguage: true,
    supportText: String(findingCount),
    renderingLocation: "#gridlyPortraitV2 .gridly-v2-bottom-dock [data-v2-sheet='history']"
  };
}

function buildGridlyHistoricalIntelligenceSheetHtml(options = {}) {
  const state = buildGridlyIntelligencePreviewCardModel(options);
  const rankedFindings = Array.isArray(state.dedupedRankedFindings) ? state.dedupedRankedFindings : (Array.isArray(state.rankedFindings) ? state.rankedFindings : []);
  if (!rankedFindings.length) {
    return `<div class="gridly-historical-intelligence-sheet"><p class="gridly-v2-sheet-copy gridly-historical-intelligence-subtitle">Based on cleared community reports</p><div class="gridly-historical-intelligence-empty"><strong>Not Enough History Yet</strong><p>Gridly will show local patterns here after more cleared reports are collected.</p></div></div>`;
  }
  const rows = rankedFindings.map((finding) => {
    const language = getGridlyIntelligencePreviewLanguage(finding.category);
    const title = sanitizeText(finding.title || language.title || "Historical Pattern");
    const description = sanitizeText(language.description(finding));
    const category = sanitizeText(finding.categoryLabel || language.category || "Hotspot");
    const location = sanitizeText(gridlyHistoricalIntelligenceDisplayLocation(finding));
    const lastSeen = formatGridlyHistoricalIntelligenceDate(finding.latestAt);
    const duration = formatGridlyHistoricalIntelligenceDuration(finding.averageDurationMinutes);
    const count = Number(finding.count || 0);
    const durationLabel = finding.category === "most_blocked_crossing" || finding.category === "high_delay_corridor" ? "Average delay" : "Average clear time";
    const supportLines = [
      duration ? `<div class="gridly-historical-intelligence-stat"><span>${sanitizeText(durationLabel)}:</span><strong>${sanitizeText(duration)}</strong></div>` : "",
      `<div class="gridly-historical-intelligence-stat"><span>Based on</span><strong>${sanitizeText(`${count} community ${count === 1 ? "report" : "reports"}`)}</strong></div>`,
      lastSeen ? `<div class="gridly-historical-intelligence-stat gridly-historical-intelligence-stat-muted"><span>Last reported</span><strong>${sanitizeText(lastSeen)}</strong></div>` : ""
    ].filter(Boolean).join("");
    return `<article class="gridly-historical-intelligence-row"><div class="gridly-historical-intelligence-row-head"><span class="gridly-historical-intelligence-rank">${Number(finding.rank || 0)}</span><span class="gridly-historical-intelligence-category">${category}</span></div><strong>${title}</strong><div class="gridly-historical-intelligence-location">${location}</div><p>${description}</p><div class="gridly-historical-intelligence-stats">${supportLines}</div></article>`;
  }).join("");
  return `<div class="gridly-historical-intelligence-sheet"><p class="gridly-v2-sheet-copy gridly-historical-intelligence-subtitle">Based on cleared community reports</p><div class="gridly-historical-intelligence-list">${rows}</div></div>`;
}

function renderGridlyIntelligencePreviewCard(options = {}) {
  const chip = document.getElementById("gridlyIntelligencePreviewCard");
  const dockButton = document.getElementById("gridlyHistoryDockButton") || document.querySelector("#gridlyPortraitV2 .gridly-v2-bottom-dock [data-v2-sheet='history']");
  const mode = document.getElementById("gridlyIntelligencePreviewMode");
  const category = document.getElementById("gridlyIntelligencePreviewCategory");
  const title = document.getElementById("gridlyIntelligencePreviewTitle");
  const description = document.getElementById("gridlyIntelligencePreviewDescription");
  const support = document.getElementById("gridlyIntelligencePreviewSupport");
  const model = {
    ...buildGridlyIntelligencePreviewCardModel(options),
    cardAvailable: Boolean(dockButton),
    chipRendered: false,
    historyChipRemoved: !chip,
    historyDockButtonRendered: Boolean(dockButton),
    renderingLocation: "#gridlyPortraitV2 .gridly-v2-bottom-dock [data-v2-sheet='history']"
  };
  if (chip) chip.hidden = true;
  if (dockButton) {
    dockButton.dataset.gridlyPreviewMode = "false";
    dockButton.dataset.gridlySelectedCategory = model.selectedCategory;
    dockButton.dataset.gridlyFallbackMode = model.fallbackMode ? "true" : "false";
    dockButton.setAttribute("aria-label", `Open historical intelligence, ${model.findingCount} ${model.findingCount === 1 ? "finding" : "findings"}`);
  }
  if (mode) mode.textContent = "History";
  if (category) category.textContent = "Local patterns";
  if (title) title.textContent = "History";
  if (description) description.textContent = "Local patterns";
  if (support) support.textContent = String(model.findingCount || 0);
  window.gridlyIntelligencePreviewCardState = model;
  return model;
}

