function getGridlyLegacyTruthMatchedSelectors(element, selectors = []) {
  if (!element || !Array.isArray(selectors) || selectors.length === 0) return [];
  return selectors.filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector]));
}

function classifyGridlyLegacyTruthSurface(surface) {
  if (surface.retired) return "retired";
  if (!surface.loaded) return "deadSurface";
  if (surface.contributesVisibleContent || surface.contributesAlertContent || surface.contributesPulseContent || surface.contributesRouteContent || surface.contributesMapContent || surface.contributesReportContent) {
    return "trueDependency";
  }
  if (surface.receivesUpdates || surface.receivesEvents || surface.referencedByPortraitV2 || surface.referencedByCurrentUserFlow) {
    return "passiveDependency";
  }
  return "legacyReferenceOnly";
}

function gridlyLegacyTruthAudit() {
  try {
    const dashboardSuppressionAudit = getGridlyDashboardSectionPassiveUpdateSuppressionAudit();
    const remainingSurfaceNames = new Set(GRIDLY_LEGACY_TRUTH_AUDIT_SURFACE_NAMES);
    const legacyDefinitions = GRIDLY_PORTRAIT_OWNERSHIP_SYSTEMS.filter((definition) => remainingSurfaceNames.has(definition.name));
    const surfaces = legacyDefinitions.map((definition) => {
      const dependencyProfile = GRIDLY_LEGACY_SURFACE_DEPENDENCY_PROFILES[definition.name] || {};
      const retirement = GRIDLY_PORTRAIT_RETIRED_SURFACES[definition.name] || null;
      const contentProfile = GRIDLY_LEGACY_TRUTH_CONTENT_PROFILES[definition.name] || {};
      const state = getGridlyLegacySurfaceDependencyElementState(definition);
      const { element } = state;
      const updateSelectors = [
        ...(dependencyProfile.domUpdateSelectors || []),
        ...(dependencyProfile.dataUpdateSelectors || [])
      ];
      const eventSelectors = dependencyProfile.eventSelectors || [];
      const dashboardSectionPassiveUpdatesSuppressed = Boolean(definition.name === "dashboardSection" && dashboardSuppressionAudit.skippedBecausePortraitV2Owns);
      const rawReceivesUpdates = Boolean(
        state.loaded &&
        (gridlyLegacySurfaceHasAnySelector(element, updateSelectors) || element?.querySelector?.("[data-bind-text]"))
      );
      const rawReceivesEvents = Boolean(state.loaded && gridlyLegacySurfaceHasAnySelector(element, eventSelectors));
      const receivesUpdates = Boolean(rawReceivesUpdates && !dashboardSectionPassiveUpdatesSuppressed);
      const receivesEvents = Boolean(rawReceivesEvents && !dashboardSectionPassiveUpdatesSuppressed);
      const matchedVisibleSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.visibleSelectors);
      const matchedAlertSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.alertSelectors);
      const matchedPulseSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.pulseSelectors);
      const matchedRouteSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.routeSelectors);
      const matchedMapSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.mapSelectors);
      const matchedReportSelectors = getGridlyLegacyTruthMatchedSelectors(element, contentProfile.reportSelectors);
      const referencedByPortraitV2 = Boolean(dependencyProfile.referencedByPortraitV2);
      const rawReferencedByCurrentUserFlow = Boolean(
        dependencyProfile.referencedByAlerts ||
        dependencyProfile.referencedByPulse ||
        dependencyProfile.referencedByHeader ||
        dependencyProfile.referencedByMap ||
        dependencyProfile.referencedByRouteFlow ||
        dependencyProfile.referencedByReportFlow
      );
      const referencedByCurrentUserFlow = Boolean(rawReferencedByCurrentUserFlow && !dashboardSectionPassiveUpdatesSuppressed);
      const contributesVisibleContent = Boolean(state.visible && matchedVisibleSelectors.length > 0);
      const surface = {
        name: definition.name,
        selector: definition.selector,
        loaded: Boolean(state.loaded),
        visible: Boolean(state.visible),
        receivesUpdates,
        receivesEvents,
        dashboardSectionPassiveUpdatesSuppressed,
        suppressedUpdateTargets: dashboardSectionPassiveUpdatesSuppressed ? dashboardSuppressionAudit.suppressedUpdateTargets.slice() : [],
        skippedBecausePortraitV2Owns: Boolean(dashboardSectionPassiveUpdatesSuppressed),
        contributesVisibleContent,
        contributesAlertContent: Boolean(contributesVisibleContent && matchedAlertSelectors.length > 0),
        contributesPulseContent: Boolean(contributesVisibleContent && matchedPulseSelectors.length > 0),
        contributesRouteContent: Boolean(contributesVisibleContent && matchedRouteSelectors.length > 0),
        contributesMapContent: Boolean(contributesVisibleContent && matchedMapSelectors.length > 0),
        contributesReportContent: Boolean(contributesVisibleContent && matchedReportSelectors.length > 0),
        referencedByPortraitV2,
        referencedByCurrentUserFlow,
        retired: Boolean(retirement),
        retirement,
        dependencyReason: retirement?.reason || dependencyProfile.dependencyReason || "No explicit dependency profile is registered for this legacy surface.",
        evidence: {
          display: state.display || state.style?.display || null,
          visibility: state.visibility || state.style?.visibility || null,
          opacity: state.opacity || state.style?.opacity || null,
          inLayoutFlow: Boolean(state.inLayoutFlow),
          updateSelectorsFound: dashboardSectionPassiveUpdatesSuppressed ? [] : getGridlyLegacyTruthMatchedSelectors(element, updateSelectors),
          rawUpdateSelectorsFound: getGridlyLegacyTruthMatchedSelectors(element, updateSelectors),
          eventSelectorsFound: dashboardSectionPassiveUpdatesSuppressed ? [] : getGridlyLegacyTruthMatchedSelectors(element, eventSelectors),
          rawEventSelectorsFound: getGridlyLegacyTruthMatchedSelectors(element, eventSelectors),
          visibleContentSelectorsFound: matchedVisibleSelectors,
          alertContentSelectorsFound: matchedAlertSelectors,
          pulseContentSelectorsFound: matchedPulseSelectors,
          routeContentSelectorsFound: matchedRouteSelectors,
          mapContentSelectorsFound: matchedMapSelectors,
          reportContentSelectorsFound: matchedReportSelectors
        }
      };
      surface.classification = classifyGridlyLegacyTruthSurface(surface);
      return surface;
    });
    const namesForClassification = (classification) => surfaces.filter((surface) => surface.classification === classification).map((surface) => surface.name);
    const trueDependencies = namesForClassification("trueDependency");
    const passiveDependencies = namesForClassification("passiveDependency");
    const legacyReferenceOnly = namesForClassification("legacyReferenceOnly");
    const deadSurfaces = namesForClassification("deadSurface");
    const retiredSurfaces = namesForClassification("retired");

    return {
      loaded: true,
      version: GRIDLY_LEGACY_TRUTH_AUDIT_VERSION,
      auditOnly: true,
      surfaces,
      trueDependencies,
      passiveDependencies,
      legacyReferenceOnly,
      deadSurfaces,
      retiredSurfaces,
      dashboardSectionPassiveUpdatesSuppressed: dashboardSuppressionAudit.dashboardSectionPassiveUpdatesSuppressed,
      suppressedUpdateTargets: dashboardSuppressionAudit.suppressedUpdateTargets,
      skippedBecausePortraitV2Owns: dashboardSuppressionAudit.skippedBecausePortraitV2Owns,
      firstLikelyDeadSurface: deadSurfaces[0] || null,
      firstLikelyPassiveDependency: passiveDependencies[0] || null,
      answer: trueDependencies.length
        ? `Remaining legacy surfaces contributing visible active-product content today: ${trueDependencies.join(", ")}.`
        : "No remaining legacy surfaces are currently contributing visible active-product content.",
      notes: [
        "Audit only: this helper reads the current DOM, computed visibility, descendant update/event targets, and registered dependency profiles; it does not remove, hide, restyle, or deauthorize any surface.",
        "trueDependency means the surface is loaded, visible, and contains matched active content/functionality selectors for alerts, pulse, route, map, report, or other visible product content.",
        "passiveDependency means no visible active content was detected, but the surface still receives updates/events or remains referenced by registered active user-flow profiles.",
        "legacyReferenceOnly means the surface is loaded without detected visible contribution, updates/events, or current user-flow references; deadSurface means the surface is not loaded."
      ]
    };
  } catch (error) {
    return {
      loaded: false,
      version: GRIDLY_LEGACY_TRUTH_AUDIT_VERSION,
      auditOnly: true,
      surfaces: [],
      trueDependencies: [],
      passiveDependencies: [],
      legacyReferenceOnly: [],
      deadSurfaces: [],
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      dashboardSectionPassiveUpdatesSuppressed: false,
      suppressedUpdateTargets: [],
      skippedBecausePortraitV2Owns: false,
      firstLikelyDeadSurface: null,
      firstLikelyPassiveDependency: null,
      error: error?.message || "unknown error"
    };
  }
}

function gridlyLegacySurfaceDependencyAudit() {
  try {
    const dashboardSuppressionAudit = getGridlyDashboardSectionPassiveUpdateSuppressionAudit();
    const portraitInventory = typeof window.gridlyPortraitOwnershipInventory === "function" ? window.gridlyPortraitOwnershipInventory() : null;
    const containmentAudit = typeof window.gridlyPortraitContainmentAudit === "function" ? window.gridlyPortraitContainmentAudit() : null;
    const legacySurfaceAuditNames = new Set([
      ...GRIDLY_PORTRAIT_RECOMMENDED_DEAUTHORIZE,
      ...Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES)
    ]);
    const legacyDefinitions = GRIDLY_PORTRAIT_OWNERSHIP_SYSTEMS.filter((definition) => legacySurfaceAuditNames.has(definition.name));
    const surfaces = legacyDefinitions.map((definition) => {
      const profile = GRIDLY_LEGACY_SURFACE_DEPENDENCY_PROFILES[definition.name] || {};
      const retirement = GRIDLY_PORTRAIT_RETIRED_SURFACES[definition.name] || null;
      const state = getGridlyLegacySurfaceDependencyElementState(definition);
      const { element } = state;
      const dashboardSectionPassiveUpdatesSuppressed = Boolean(definition.name === "dashboardSection" && dashboardSuppressionAudit.skippedBecausePortraitV2Owns);
      const rawReceivesDomUpdates = Boolean(state.loaded && gridlyLegacySurfaceHasAnySelector(element, profile.domUpdateSelectors));
      const rawReceivesDataUpdates = Boolean(state.loaded && (gridlyLegacySurfaceHasAnySelector(element, profile.dataUpdateSelectors) || element?.querySelector?.("[data-bind-text]")));
      const rawReceivesEventBindings = Boolean(state.loaded && gridlyLegacySurfaceHasAnySelector(element, profile.eventSelectors));
      const receivesDomUpdates = Boolean(rawReceivesDomUpdates && !dashboardSectionPassiveUpdatesSuppressed);
      const receivesDataUpdates = Boolean(rawReceivesDataUpdates && !dashboardSectionPassiveUpdatesSuppressed);
      const receivesEventBindings = Boolean(rawReceivesEventBindings && !dashboardSectionPassiveUpdatesSuppressed);
      const affectsLayout = Boolean(state.loaded && (state.inLayoutFlow || (profile.affectsLayoutWhenLoaded && state.visible)));
      const referencedByPortraitV2 = Boolean(profile.referencedByPortraitV2 && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByAlerts = Boolean(profile.referencedByAlerts && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByPulse = Boolean(profile.referencedByPulse && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByHeader = Boolean(profile.referencedByHeader && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByMap = Boolean(profile.referencedByMap && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByRouteFlow = Boolean(profile.referencedByRouteFlow && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByReportFlow = Boolean(profile.referencedByReportFlow && !dashboardSectionPassiveUpdatesSuppressed);
      const referencedByActiveSystems = Boolean(
        referencedByPortraitV2 ||
        referencedByAlerts ||
        referencedByPulse ||
        referencedByHeader ||
        referencedByMap ||
        referencedByRouteFlow ||
        referencedByReportFlow
      );
      const surface = {
        name: definition.name,
        selector: definition.selector,
        loaded: Boolean(state.loaded),
        visible: Boolean(state.visible),
        receivesDomUpdates,
        receivesEventBindings,
        receivesDataUpdates,
        dashboardSectionPassiveUpdatesSuppressed,
        suppressedUpdateTargets: dashboardSectionPassiveUpdatesSuppressed ? dashboardSuppressionAudit.suppressedUpdateTargets.slice() : [],
        skippedBecausePortraitV2Owns: Boolean(dashboardSectionPassiveUpdatesSuppressed),
        affectsLayout,
        referencedByActiveSystems,
        referencedByPortraitV2,
        referencedByAlerts,
        referencedByPulse,
        referencedByHeader,
        referencedByMap,
        referencedByRouteFlow,
        referencedByReportFlow,
        retired: Boolean(retirement),
        retirement,
        dependencyReason: retirement?.reason || profile.dependencyReason || "No explicit dependency profile is registered for this legacy surface.",
        evidence: {
          display: state.display || state.style?.display || null,
          visibility: state.visibility || state.style?.visibility || null,
          opacity: state.opacity || state.style?.opacity || null,
          inLayoutFlow: Boolean(state.inLayoutFlow),
          domUpdateSelectorsFound: dashboardSectionPassiveUpdatesSuppressed ? [] : (profile.domUpdateSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector])),
          dataUpdateSelectorsFound: dashboardSectionPassiveUpdatesSuppressed ? [] : (profile.dataUpdateSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector])),
          eventSelectorsFound: dashboardSectionPassiveUpdatesSuppressed ? [] : (profile.eventSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector])),
          rawDomUpdateSelectorsFound: (profile.domUpdateSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector])),
          rawDataUpdateSelectorsFound: (profile.dataUpdateSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector])),
          rawEventSelectorsFound: (profile.eventSelectors || []).filter((selector) => gridlyLegacySurfaceHasAnySelector(element, [selector]))
        }
      };
      surface.classification = retirement ? "retired" : classifyGridlyLegacySurfaceDependency(surface);
      surface.safeToRetire = !retirement && surface.classification === "safeToRetire";
      surface.safeToContain = surface.classification === "safeToContain";
      surface.activeDependency = surface.classification === "activeDependency";
      surface.unknown = surface.classification === "unknown";
      surface.removalRiskScore = scoreGridlyLegacySurfaceRemovalRisk(surface);
      return surface;
    });
    const safeRetirementCandidates = surfaces.filter((surface) => surface.safeToRetire).map((surface) => surface.name);
    const containmentCandidates = surfaces.filter((surface) => surface.safeToContain).map((surface) => surface.name);
    const activeDependencyCandidates = surfaces.filter((surface) => surface.activeDependency).map((surface) => surface.name);
    const highestRiskRemovals = surfaces
      .filter((surface) => surface.removalRiskScore > 0)
      .slice()
      .sort((a, b) => b.removalRiskScore - a.removalRiskScore || a.name.localeCompare(b.name))
      .slice(0, 5)
      .map((surface) => ({ name: surface.name, removalRiskScore: surface.removalRiskScore, classification: surface.classification }));

    return {
      loaded: true,
      version: GRIDLY_LEGACY_SURFACE_DEPENDENCY_AUDIT_VERSION,
      auditOnly: true,
      portraitPrimaryOwner: portraitInventory?.portraitPrimaryOwner || containmentAudit?.portraitPrimaryOwner || GRIDLY_PORTRAIT_PRIMARY_OWNER,
      duplicateOwnershipWarnings: portraitInventory?.duplicateOwnershipWarnings || [],
      recommendedDeauthorize: GRIDLY_PORTRAIT_RECOMMENDED_DEAUTHORIZE.slice(),
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      dashboardSectionPassiveUpdatesSuppressed: dashboardSuppressionAudit.dashboardSectionPassiveUpdatesSuppressed,
      suppressedUpdateTargets: dashboardSuppressionAudit.suppressedUpdateTargets,
      skippedBecausePortraitV2Owns: dashboardSuppressionAudit.skippedBecausePortraitV2Owns,
      surfaces,
      safeRetirementCandidates,
      containmentCandidates,
      activeDependencyCandidates,
      highestRiskRemovals,
      firstSafeLegacySurfaceToRetire: safeRetirementCandidates[0] || null,
      notes: [
        "Audit only: this helper reads DOM visibility, descendant bindings, and registered dependency profiles; it does not remove, hide, restyle, or rebind any surface.",
        "safeToRetire means the loaded surface is hidden, has no detected DOM/data/event dependency, is not in layout flow, and is not referenced by a registered active system profile.",
        "activeDependency means removal risk was detected through visibility, updates, events, or active-system references."
      ]
    };
  } catch (error) {
    return {
      loaded: false,
      version: GRIDLY_LEGACY_SURFACE_DEPENDENCY_AUDIT_VERSION,
      auditOnly: true,
      surfaces: [],
      safeRetirementCandidates: [],
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      dashboardSectionPassiveUpdatesSuppressed: false,
      suppressedUpdateTargets: [],
      skippedBecausePortraitV2Owns: false,
      containmentCandidates: [],
      activeDependencyCandidates: [],
      highestRiskRemovals: [],
      firstSafeLegacySurfaceToRetire: null,
      error: error?.message || "unknown error"
    };
  }
}

window.gridlyPortraitContainmentAudit = gridlyPortraitContainmentAudit;
window.gridlyLegacySurfaceDependencyAudit = gridlyLegacySurfaceDependencyAudit;
window.gridlyLegacyTruthAudit = gridlyLegacyTruthAudit;

window.gridlyPortraitOwnershipInventory = function gridlyPortraitOwnershipInventory() {
  try {
    const layoutMode = document.body?.dataset?.layoutMode || "";
    const legacyLayoutMode = document.body?.dataset?.layoutModeLegacy || "";
    const portraitMedia = Boolean(window.matchMedia?.("(orientation: portrait)")?.matches);
    const cleanupGate = getGridlyPortraitCleanupGateState(layoutMode);
    const portraitModeActive = cleanupGate.portraitCleanupGateActive;
    const systems = GRIDLY_PORTRAIT_OWNERSHIP_SYSTEMS.map((definition) => {
      const state = getGridlyPortraitOwnershipElementState(definition);
      const element = state.loaded ? document.querySelector(definition.selector) : null;
      const portraitContainedStructuralWrapper = isGridlyPortraitContainedStructuralWrapper(state, element);
      return {
        name: state.name,
        selector: state.selector,
        ownershipRole: state.ownershipRole,
        ownerClass: state.ownerClass,
        visible: state.visible,
        loaded: state.loaded,
        active: Boolean(!GRIDLY_PORTRAIT_RETIRED_SURFACES[state.name] && state.active && !portraitContainedStructuralWrapper && (portraitModeActive || state.ownerClass === "shared_map" || state.ownerClass === "portrait_module")),
        portraitContainedStructuralWrapper,
        retirement: GRIDLY_PORTRAIT_RETIRED_SURFACES[state.name] || null
      };
    });
    const portraitVisibleSystems = systems.filter((system) => system.visible);
    const portraitLoadedSystems = systems.filter((system) => system.loaded);
    const portraitHiddenSystems = systems.filter((system) => system.loaded && !system.visible);
    const portraitDormantSystems = systems.filter((system) => !system.loaded || !system.active);
    const duplicateOwnershipWarnings = buildGridlyPortraitDuplicateOwnershipWarnings(systems, portraitModeActive);
    const activePrimary = systems.find((system) => system.name === GRIDLY_PORTRAIT_PRIMARY_OWNER && system.active);
    const firstVisibleOwner = portraitVisibleSystems.find((system) => system.name !== "map-card" && !system.portraitContainedStructuralWrapper) || portraitVisibleSystems[0] || null;
    return {
      loaded: true,
      version: GRIDLY_PORTRAIT_OWNERSHIP_INVENTORY_VERSION,
      layoutMode,
      legacyLayoutMode,
      portraitModeActive,
      viewportWidth: cleanupGate.viewportWidth,
      viewportHeight: cleanupGate.viewportHeight,
      isStrictPortraitMobile: cleanupGate.isStrictPortraitMobile,
      portraitCleanupGateActive: cleanupGate.portraitCleanupGateActive,
      desktopProtectedFromPortraitCleanup: cleanupGate.desktopProtectedFromPortraitCleanup,
      portraitCleanupGateReason: cleanupGate.portraitCleanupGateReason,
      portraitVisibleSystems,
      portraitLoadedSystems,
      portraitHiddenSystems,
      portraitDormantSystems,
      duplicateOwnershipWarnings,
      portraitPrimaryOwner: activePrimary ? GRIDLY_PORTRAIT_PRIMARY_OWNER : (firstVisibleOwner?.name || GRIDLY_PORTRAIT_PRIMARY_OWNER),
      recommendedKeep: GRIDLY_PORTRAIT_RECOMMENDED_KEEP,
      recommendedDeauthorize: GRIDLY_PORTRAIT_RECOMMENDED_DEAUTHORIZE,
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      containedStructuralWrappers: systems.filter((system) => system.portraitContainedStructuralWrapper).map((system) => system.name),
      portraitV2StartupActivationApplied: Boolean(gridlyPortraitV2StartupActivationState.applied),
      portraitV2StartupActivationReason: gridlyPortraitV2StartupActivationState.reason,
      portraitV2StartupActivation: { ...gridlyPortraitV2StartupActivationState },
      notes: [
        "Inventory only: this helper reads DOM/system visibility and does not mutate UI, rendering, or behavior.",
        "recommendedDeauthorize is an audit recommendation list only; no systems are removed or hidden by this helper."
      ]
    };
  } catch (error) {
    return {
      loaded: false,
      version: GRIDLY_PORTRAIT_OWNERSHIP_INVENTORY_VERSION,
      portraitVisibleSystems: [],
      portraitLoadedSystems: [],
      portraitHiddenSystems: [],
      portraitDormantSystems: [],
      duplicateOwnershipWarnings: [{
        type: "inventory_error",
        message: error?.message || "unknown error",
        systems: []
      }],
      portraitPrimaryOwner: GRIDLY_PORTRAIT_PRIMARY_OWNER,
      recommendedKeep: GRIDLY_PORTRAIT_RECOMMENDED_KEEP,
      recommendedDeauthorize: GRIDLY_PORTRAIT_RECOMMENDED_DEAUTHORIZE,
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      containedStructuralWrappers: [],
      portraitV2StartupActivationApplied: Boolean(gridlyPortraitV2StartupActivationState.applied),
      portraitV2StartupActivationReason: gridlyPortraitV2StartupActivationState.reason,
      portraitV2StartupActivation: { ...gridlyPortraitV2StartupActivationState }
    };
  }
};


function getGridlyPortraitActivationRectSnapshot(element) {
  if (!element || typeof element.getBoundingClientRect !== "function") return null;
  const rect = element.getBoundingClientRect();
  return {
    x: Math.round(Number(rect.x || 0) * 100) / 100,
    y: Math.round(Number(rect.y || 0) * 100) / 100,
    width: Math.round(Number(rect.width || 0) * 100) / 100,
    height: Math.round(Number(rect.height || 0) * 100) / 100,
    top: Math.round(Number(rect.top || 0) * 100) / 100,
    right: Math.round(Number(rect.right || 0) * 100) / 100,
    bottom: Math.round(Number(rect.bottom || 0) * 100) / 100,
    left: Math.round(Number(rect.left || 0) * 100) / 100
  };
}

function isGridlyPortraitActivationElementVisible(element) {
  if (!element) return false;
  const style = window.getComputedStyle(element);
  const rect = getGridlyPortraitActivationRectSnapshot(element);
  return Boolean(
    !element.hidden &&
    element.getAttribute("aria-hidden") !== "true" &&
    style.display !== "none" &&
    style.visibility !== "hidden" &&
    Number.parseFloat(style.opacity || "1") !== 0 &&
    rect &&
    rect.width > 0 &&
    rect.height > 0
  );
}

function getGridlyPortraitActivationParentChain(element) {
  const chain = [];
  let current = element;
  while (current && current.nodeType === 1) {
    const style = window.getComputedStyle(current);
    const rect = getGridlyPortraitActivationRectSnapshot(current);
    const hiddenAttribute = Boolean(current.hidden);
    const ariaHidden = current.getAttribute("aria-hidden");
    const visible = Boolean(
      !hiddenAttribute &&
      ariaHidden !== "true" &&
      style.display !== "none" &&
      style.visibility !== "hidden" &&
      Number.parseFloat(style.opacity || "1") !== 0 &&
      rect &&
      rect.width > 0 &&
      rect.height > 0
    );
    chain.push({
      tagName: current.tagName.toLowerCase(),
      id: current.id || "",
      className: typeof current.className === "string" ? current.className : "",
      hidden: hiddenAttribute,
      ariaHidden,
      display: style.display,
      visibility: style.visibility,
      opacity: style.opacity,
      pointerEvents: style.pointerEvents,
      rect,
      visible,
      blockers: [
        hiddenAttribute ? "hidden_attribute" : "",
        ariaHidden === "true" ? "aria_hidden_true" : "",
        style.display === "none" ? "display_none" : "",
        style.visibility === "hidden" ? "visibility_hidden" : "",
        Number.parseFloat(style.opacity || "1") === 0 ? "opacity_zero" : "",
        !rect || rect.width <= 0 || rect.height <= 0 ? "zero_or_missing_rect" : ""
      ].filter(Boolean)
    });
    current = current.parentElement;
  }
  return chain;
}

function getGridlyPortraitActivationCssClassAudit(shell) {
  const body = document.body;
  return {
    bodyClasses: Array.from(body?.classList || []),
    bodyDataset: {
      layoutMode: body?.dataset?.layoutMode || "",
      layoutModeLegacy: body?.dataset?.layoutModeLegacy || "",
      mobileMode: body?.dataset?.mobileMode || ""
    },
    shellClasses: Array.from(shell?.classList || []),
    shellHiddenAttribute: Boolean(shell?.hidden),
    shellAriaHidden: shell?.getAttribute?.("aria-hidden") || null,
    matchedVisibilitySelectors: [
      { selector: "#gridlyPortraitV2", effect: "base CSS sets display:none", matched: Boolean(shell) },
      { selector: 'body[data-layout-mode="portrait"] #gridlyPortraitV2', effect: "portrait CSS requests display:block, fixed inset shell", matched: Boolean(shell && body?.dataset?.layoutMode === "portrait") },
      { selector: 'body[data-layout-mode="portrait"].gridly-v2-surface-containment #gridlyPortraitV2', effect: "raises V2 z-index when JS marks shell visually active", matched: Boolean(shell && body?.dataset?.layoutMode === "portrait" && body.classList.contains("gridly-v2-surface-containment")) },
      { selector: 'body[data-layout-mode="portrait"].gridly-v2-surface-containment #gridlyPortraitV2::before', effect: "V181.3 top shield isolates the header/status/segments stack from underlying map-card or Community Pulse surfaces inside the strict portrait-mobile containment gate", matched: Boolean(shell && body?.dataset?.layoutMode === "portrait" && body.classList.contains("gridly-v2-surface-containment")) },
      { selector: 'body[data-layout-mode="portrait"].gridly-v2-surface-containment #gridlyPortraitV2 .gridly-v2-topbar, .gridly-v2-status-pill, .gridly-v2-segments', effect: "V181.3 applies opaque paint-contained backgrounds to prevent layer bleed inside the strict portrait-mobile containment gate", matched: Boolean(shell && body?.dataset?.layoutMode === "portrait" && body.classList.contains("gridly-v2-surface-containment")) },
      { selector: '[hidden]', effect: "HTML hidden attribute keeps the shell out of rendering until removed", matched: Boolean(shell?.hidden) }
    ],
    portraitV2StartupActivationApplied: Boolean(gridlyPortraitV2StartupActivationState.applied),
    portraitV2StartupActivationReason: gridlyPortraitV2StartupActivationState.reason,
    descendantVisibilityClasses: [
      ".gridly-v2-topbar",
      ".gridly-v2-status-pill",
      ".gridly-v2-segments",
      ".gridly-v2-control-rail",
      ".gridly-v2-bottom-dock",
      ".gridly-v2-sheet"
    ].map((selector) => {
      const element = shell?.querySelector?.(selector);
      const style = element ? window.getComputedStyle(element) : null;
      return {
        selector,
        exists: Boolean(element),
        display: style?.display || null,
        visibility: style?.visibility || null,
        opacity: style?.opacity || null,
        visible: isGridlyPortraitActivationElementVisible(element)
      };
    })
  };
}

function getGridlyPortraitActivationJsGateAudit(shell) {
  return [
    {
      gate: "index.html initial shell state",
      controlsVisibility: true,
      currentState: shell?.hidden ? "blocked_by_hidden_attribute" : "hidden_attribute_removed",
      notes: "#gridlyPortraitV2 ships with the hidden attribute; it is not active until a JS path removes that attribute."
    },
    {
      gate: "activateGridlyPortraitV2StartupOwner()",
      controlsVisibility: true,
      currentState: gridlyPortraitV2StartupActivationState.reason,
      notes: "When canonical layoutMode is 'portrait', this conservative startup/layout path removes only #gridlyPortraitV2 [hidden] and then lets containment run normally."
    },
    {
      gate: "openGridlyPortraitV2Sheet(sheetName)",
      controlsVisibility: true,
      currentState: typeof window.openGridlyPortraitV2Sheet === "function" ? "available" : "not_exposed_yet_or_missing",
      notes: "This sheet-open path still removes the shell hidden attribute as a fallback, but portrait startup no longer depends on opening a sheet."
    },
    {
      gate: "openPortraitV2Sheet(type)",
      controlsVisibility: true,
      currentState: typeof window.openPortraitV2Sheet === "function" ? "available" : "not_exposed_yet_or_missing",
      notes: "Wrapper around openGridlyPortraitV2Sheet; it remains a sheet fallback rather than the primary portrait startup activation path."
    },
    {
      gate: "isPortraitV2VisuallyActive()",
      controlsVisibility: false,
      currentState: typeof isPortraitV2VisuallyActive === "function" ? Boolean(isPortraitV2VisuallyActive()) : "missing",
      notes: "Reads body[data-layout-mode='portrait'] plus computed shell visibility; returns false while [hidden] forces display:none."
    },
    {
      gate: "applyPortraitV2SurfaceContainment()",
      controlsVisibility: false,
      currentState: typeof applyPortraitV2SurfaceContainment === "function" ? "available" : "missing",
      notes: "Toggles containment only after V2 is already visually active; it does not activate the shell."
    },
    {
      gate: "bindV2()",
      controlsVisibility: false,
      currentState: typeof bindV2 === "function" ? "available" : "missing",
      notes: "Binds dock/sheet controls and requests conservative portrait startup activation before containment."
    },
    {
      gate: "gridlyPortraitV2SheetState portrait mode check",
      controlsVisibility: false,
      currentState: "diagnostic_checks_body_data_layout_mode_portrait_v2",
      notes: "Existing sheet diagnostic checks for 'portrait-v2', while canonical portrait mode is 'portrait'; this can make diagnostics say detached even when portrait mode is active."
    }
  ];
}

function getGridlyPortraitActivationFunctionAudit() {
  return [
    { name: "openGridlyPortraitV2Sheet", role: "removes #gridlyPortraitV2 hidden and opens a V2 bottom sheet", available: typeof window.openGridlyPortraitV2Sheet === "function" },
    { name: "openPortraitV2Sheet", role: "public wrapper for opening V2 sheets", available: typeof window.openPortraitV2Sheet === "function" },
    { name: "activateGridlyPortraitV2StartupOwner", role: "conservative startup/layout activation that removes only #gridlyPortraitV2 [hidden] when canonical layoutMode is portrait", available: typeof activateGridlyPortraitV2StartupOwner === "function" },
    { name: "bindV2", role: "binds V2 buttons and applies portrait startup activation/containment without opening a sheet", available: typeof bindV2 === "function" },
    { name: "isPortraitV2VisuallyActive", role: "computed visibility gate used by containment", available: typeof isPortraitV2VisuallyActive === "function" },
    { name: "applyPortraitV2SurfaceContainment", role: "adds body.gridly-v2-surface-containment only after V2 is visible", available: typeof applyPortraitV2SurfaceContainment === "function" },
    { name: "setLayoutMode/getCurrentLayoutMode", role: "sets/reads canonical layout mode; portrait layout activation now requests the V2 shell startup owner", available: typeof getCurrentLayoutMode === "function" }
  ];
}

window.gridlyPortraitActivationAudit = function gridlyPortraitActivationAudit() {
  try {
    const body = document.body;
    const layoutMode = body?.dataset?.layoutMode || "";
    const legacyLayoutMode = body?.dataset?.layoutModeLegacy || "";
    const portraitMedia = Boolean(window.matchMedia?.("(orientation: portrait)")?.matches);
    const cleanupGate = getGridlyPortraitCleanupGateState(layoutMode);
    const portraitModeActive = cleanupGate.portraitCleanupGateActive;
    const shell = document.getElementById("gridlyPortraitV2");
    const shellStyle = shell ? window.getComputedStyle(shell) : null;
    const shellRect = getGridlyPortraitActivationRectSnapshot(shell);
    const gridlyPortraitV2Visible = isGridlyPortraitActivationElementVisible(shell);
    const gridlyPortraitV2Active = Boolean(portraitModeActive && gridlyPortraitV2Visible);
    const ownershipInventory = typeof window.gridlyPortraitOwnershipInventory === "function" ? window.gridlyPortraitOwnershipInventory() : null;
    const visibleSystems = Array.isArray(ownershipInventory?.portraitVisibleSystems) ? ownershipInventory.portraitVisibleSystems : [];
    const activeOwner = portraitModeActive && gridlyPortraitV2Visible
      ? "gridlyPortraitV2"
      : (visibleSystems.find((system) => system.name !== "map-card")?.name || visibleSystems[0]?.name || ownershipInventory?.portraitPrimaryOwner || null);
    const activationBlockers = [
      !shell ? "gridlyPortraitV2_missing" : "",
      shell?.hidden ? "gridlyPortraitV2_hidden_attribute_present" : "",
      shellStyle?.display === "none" ? "gridlyPortraitV2_computed_display_none" : "",
      shellStyle?.visibility === "hidden" ? "gridlyPortraitV2_computed_visibility_hidden" : "",
      shellStyle && Number.parseFloat(shellStyle.opacity || "1") === 0 ? "gridlyPortraitV2_computed_opacity_zero" : "",
      !shellRect || shellRect.width <= 0 || shellRect.height <= 0 ? "gridlyPortraitV2_zero_or_missing_bounds" : "",
      portraitModeActive && !body?.classList.contains("gridly-v2-surface-containment") ? "v2_surface_containment_not_active_because_shell_not_visually_active" : "",
      portraitModeActive && visibleSystems.some((system) => system.name !== "gridlyPortraitV2" && system.name !== "map-card") ? "legacy_or_module_portrait_owner_visible_before_v2" : ""
    ].filter(Boolean);
    const whyInactive = gridlyPortraitV2Active
      ? "gridlyPortraitV2 is active and visible inside the strict portrait mobile cleanup gate."
      : !portraitModeActive
        ? `Portrait cleanup gate is inactive: ${cleanupGate.portraitCleanupGateReason}.`
        : shell?.hidden
        ? "gridlyPortraitV2 is loaded, but the shell still has the hidden attribute. Portrait CSS targets the shell, but no portrait-startup activation path has removed [hidden]; only the V2 sheet-open path removes it."
        : shellStyle?.display === "none"
          ? "gridlyPortraitV2 is loaded, but computed display is none."
          : !shellRect || shellRect.width <= 0 || shellRect.height <= 0
            ? "gridlyPortraitV2 is loaded, but it has no visible bounds."
            : "gridlyPortraitV2 fails the visibility gate for computed style, attributes, or geometry.";
    return {
      loaded: true,
      auditVersion: "V180.13",
      portraitModeActive,
      viewportWidth: cleanupGate.viewportWidth,
      viewportHeight: cleanupGate.viewportHeight,
      isStrictPortraitMobile: cleanupGate.isStrictPortraitMobile,
      portraitCleanupGateActive: cleanupGate.portraitCleanupGateActive,
      desktopProtectedFromPortraitCleanup: cleanupGate.desktopProtectedFromPortraitCleanup,
      portraitCleanupGateReason: cleanupGate.portraitCleanupGateReason,
      layoutMode,
      legacyLayoutMode,
      portraitMedia,
      gridlyPortraitV2Exists: Boolean(shell),
      gridlyPortraitV2Loaded: Boolean(shell),
      gridlyPortraitV2Visible,
      gridlyPortraitV2Active,
      gridlyPortraitV2ComputedDisplay: shellStyle?.display || null,
      gridlyPortraitV2ComputedVisibility: shellStyle?.visibility || null,
      gridlyPortraitV2ComputedOpacity: shellStyle?.opacity || null,
      shellHiddenAttribute: Boolean(shell?.hidden),
      portraitV2StartupActivationApplied: Boolean(gridlyPortraitV2StartupActivationState.applied),
      portraitV2StartupActivationReason: gridlyPortraitV2StartupActivationState.reason,
      portraitV2StartupActivation: { ...gridlyPortraitV2StartupActivationState },
      gridlyPortraitV2BoundingRect: shellRect,
      parentChainVisibilityAudit: getGridlyPortraitActivationParentChain(shell),
      cssClassesAffectingVisibility: getGridlyPortraitActivationCssClassAudit(shell),
      jsGatesAffectingVisibility: getGridlyPortraitActivationJsGateAudit(shell),
      functionsControllingPortraitActivation: getGridlyPortraitActivationFunctionAudit(),
      currentActivePortraitOwner: activeOwner,
      visiblePortraitSystems: visibleSystems.map((system) => system.name),
      ownershipWarnings: ownershipInventory?.duplicateOwnershipWarnings || [],
      whyGridlyPortraitV2IsConsideredInactive: whyInactive,
      activationBlockers,
      recommendedActivationPath: [
        "Keep audit-only behavior for this helper; do not mutate UI from diagnostics.",
        "Portrait startup owner handoff is explicit in production code: when canonical layoutMode is 'portrait', remove #gridlyPortraitV2 [hidden] before visibility/containment checks.",
        "After the shell is visible, let applyPortraitV2SurfaceContainment mark body.gridly-v2-surface-containment so legacy surfaces are contained by existing CSS.",
        "Align diagnostics that check 'portrait-v2' with the canonical layoutMode value 'portrait' if V2 is meant to own portrait mode."
      ]
    };
  } catch (error) {
    return {
      loaded: false,
      auditVersion: "V180.13",
      error: error?.message || "unknown error",
      portraitModeActive: false,
      gridlyPortraitV2Exists: false,
      gridlyPortraitV2Loaded: false,
      gridlyPortraitV2Visible: false,
      shellHiddenAttribute: false,
      portraitV2StartupActivationApplied: Boolean(gridlyPortraitV2StartupActivationState.applied),
      portraitV2StartupActivationReason: gridlyPortraitV2StartupActivationState.reason,
      activationBlockers: ["audit_error"],
      whyGridlyPortraitV2IsConsideredInactive: "Activation audit failed before visibility could be evaluated."
    };
  }
};


function gridlyPortraitStabilitySmokeAudit() {
  const safeText = (selector) => String(document.querySelector(selector)?.textContent || "").replace(/\s+/g, " ").trim();
  const isVisible = (element) => {
    if (!element || element.hidden) return false;
    const style = typeof window.getComputedStyle === "function" ? window.getComputedStyle(element) : null;
    const rect = typeof element.getBoundingClientRect === "function" ? element.getBoundingClientRect() : null;
    return Boolean(
      (!style || (style.display !== "none" && style.visibility !== "hidden" && Number.parseFloat(style.opacity || "1") !== 0)) &&
      (!rect || (rect.width > 0 && rect.height > 0))
    );
  };
  const countSelector = (selector) => {
    try {
      return document.querySelectorAll(selector).length;
    } catch (_error) {
      return 0;
    }
  };
  const findVisibleSelector = (selectors) => selectors.find((selector) => {
    try {
      return Array.from(document.querySelectorAll(selector)).some(isVisible);
    } catch (_error) {
      return false;
    }
  }) || "";

  try {
    const layoutMode = getCanonicalGridlyPortraitLayoutMode();
    const cleanupGate = getGridlyPortraitCleanupGateState(layoutMode);
    const ownershipAudit = typeof window.gridlyPortraitOwnershipInventory === "function" ? window.gridlyPortraitOwnershipInventory() : null;
    const containmentAudit = typeof window.gridlyPortraitContainmentAudit === "function" ? window.gridlyPortraitContainmentAudit() : null;
    const legacyTruthAudit = typeof window.gridlyLegacyTruthAudit === "function" ? window.gridlyLegacyTruthAudit() : null;
    const visibleSystems = Array.isArray(ownershipAudit?.portraitVisibleSystems) ? ownershipAudit.portraitVisibleSystems : [];
    const duplicateOwnershipWarnings = Array.isArray(ownershipAudit?.duplicateOwnershipWarnings) ? ownershipAudit.duplicateOwnershipWarnings : [];
    const containedStructuralWrappers = Array.from(new Set([
      ...(Array.isArray(ownershipAudit?.containedStructuralWrappers) ? ownershipAudit.containedStructuralWrappers : []),
      ...(Array.isArray(containmentAudit?.containedStructuralWrappers) ? containmentAudit.containedStructuralWrappers : [])
    ]));
    const retiredSurfaceNames = Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES);
    const retiredSurfaces = retiredSurfaceNames.map((name) => {
      const system = visibleSystems.find((candidate) => candidate.name === name)
        || (Array.isArray(legacyTruthAudit?.surfaces) ? legacyTruthAudit.surfaces.find((candidate) => candidate.name === name) : null)
        || null;
      return {
        name,
        status: GRIDLY_PORTRAIT_RETIRED_SURFACES[name]?.status || "retired",
        retiredIn: GRIDLY_PORTRAIT_RETIRED_SURFACES[name]?.retiredIn || "",
        loaded: Boolean(system?.loaded),
        visible: Boolean(system?.visible)
      };
    });
    const protectedRuntimeFlags = {
      crossingRuntimeEnabled: GRIDLY_CROSSING_RUNTIME_ENABLED,
      crossingEnrichmentEnabled: GRIDLY_CROSSING_ENRICHMENT_ENABLED,
      sourceJoinRuntimeEnabled: GRIDLY_SOURCE_JOIN_RUNTIME_ENABLED,
      heavyCommunityRuntimeDisabled: GRIDLY_HEAVY_COMMUNITY_RUNTIME_DISABLED
    };

    const classifiedDockButtons = (typeof getBottomDockButtons === "function" ? getBottomDockButtons() : [])
      .map((button) => ({ button, intent: classifyBottomDockIntent(button) }));
    const buttonBound = (intent) => classifiedDockButtons.some((entry) => entry.intent === intent && entry.button.dataset.gridlyDockBound === "true");
    const bottomDockVisible = Boolean(findVisibleSelector([
      ".gridly-v2-bottom-dock",
      ".gridly-bottom-dock",
      ".tactical-dock",
      ".mobile-floating-action-dock",
      ".mobile-bottom-nav",
      ".mobile-bottom-dock",
      ".mobile-dock"
    ]));
    const mapVisible = isVisible(document.getElementById("map"));
    const alertsHeadingText = safeText("[data-gridly-alerts-panel-heading='true']")
      || safeText("#alertsSection h2, #alertsSection h3, .gridly-alerts-active h2, .gridly-alerts-active h3");
    const renderedAlertCount = Array.isArray(window.__gridlyLatestAlertsForRender)
      ? window.__gridlyLatestAlertsForRender.length
      : (Array.isArray(window.__gridlyAlertsForRenderSample) ? window.__gridlyAlertsForRenderSample.length : null);
    const unifiedIncidents = typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : null;
    const unifiedIncidentCount = Array.isArray(unifiedIncidents) ? unifiedIncidents.length : null;
    const localActiveAlertCount = (Array.isArray(activeReports) ? activeReports.length : 0) + (Array.isArray(activeHazards) ? activeHazards.length : 0);
    const activeAlertCount = Number.isFinite(renderedAlertCount)
      ? renderedAlertCount
      : (Number.isFinite(unifiedIncidentCount) ? unifiedIncidentCount : localActiveAlertCount);
    const isApprovedSupportingPortraitModule = (system) => {
      const containmentProfile = GRIDLY_PORTRAIT_CONTAINMENT_PROFILE[system.name] || {};
      return Boolean(
        system.ownerClass === "portrait_module" ||
        (containmentProfile.supportsPortraitV2 && !containmentProfile.competesWithPortraitOwnership && containmentProfile.recommendedAction === "keep")
      );
    };
    const leakedVisibleLegacyOwners = visibleSystems
      .filter((system) => system.name !== GRIDLY_PORTRAIT_PRIMARY_OWNER && system.name !== "map-card" && !system.portraitContainedStructuralWrapper && !system.retirement && !isApprovedSupportingPortraitModule(system))
      .map((system) => system.name);
    const leakedVisibleRetiredSurfaces = retiredSurfaces.filter((surface) => surface.visible).map((surface) => surface.name);
    const duplicateElementIds = {
      gridlyPortraitV2: countSelector("#gridlyPortraitV2"),
      gridlyPortraitV2Sheet: countSelector("#gridlyPortraitV2Sheet"),
      map: countSelector("#map"),
      alertsSection: countSelector("#alertsSection")
    };
    const objectLeakCheck = {
      ok: !Object.values(duplicateElementIds).some((count) => count > 1) && leakedVisibleLegacyOwners.length === 0 && leakedVisibleRetiredSurfaces.length === 0,
      duplicateElementIds,
      leakedVisibleLegacyOwners,
      leakedVisibleRetiredSurfaces,
      inspectedOnly: true
    };

    const majorProblems = [];
    if (cleanupGate.isStrictPortraitMobile && !cleanupGate.portraitCleanupGateActive) majorProblems.push("strict_portrait_mobile_cleanup_gate_inactive");
    if (cleanupGate.isStrictPortraitMobile && ownershipAudit?.portraitPrimaryOwner !== GRIDLY_PORTRAIT_PRIMARY_OWNER) majorProblems.push("portrait_primary_owner_not_gridlyPortraitV2");
    if (duplicateOwnershipWarnings.length) majorProblems.push("duplicate_portrait_ownership_warnings_present");
    if (cleanupGate.isStrictPortraitMobile && !mapVisible) majorProblems.push("map_not_visible_in_portrait");
    if (cleanupGate.isStrictPortraitMobile && !bottomDockVisible) majorProblems.push("bottom_dock_not_visible_in_portrait");
    if (!buttonBound("route")) majorProblems.push("route_button_not_bound");
    if (!buttonBound("report")) majorProblems.push("report_button_not_bound");
    if (!buttonBound("alerts")) majorProblems.push("alerts_button_not_bound");
    if (!buttonBound("settings")) majorProblems.push("settings_button_not_bound");
    if (!protectedRuntimeFlags.heavyCommunityRuntimeDisabled || protectedRuntimeFlags.crossingRuntimeEnabled || protectedRuntimeFlags.crossingEnrichmentEnabled || protectedRuntimeFlags.sourceJoinRuntimeEnabled) majorProblems.push("protected_runtime_flags_not_preserved");
    if (!objectLeakCheck.ok) majorProblems.push("portrait_object_or_surface_leak_detected");

    return {
      layoutMode,
      viewportWidth: cleanupGate.viewportWidth,
      viewportHeight: cleanupGate.viewportHeight,
      isStrictPortraitMobile: cleanupGate.isStrictPortraitMobile,
      portraitCleanupGateActive: cleanupGate.portraitCleanupGateActive,
      portraitPrimaryOwner: ownershipAudit?.portraitPrimaryOwner || GRIDLY_PORTRAIT_PRIMARY_OWNER,
      duplicateOwnershipWarnings,
      containedStructuralWrappers,
      retiredSurfaces,
      protectedRuntimeFlags,
      headerText: safeText("#gridlyV2TopStatusPrimary"),
      alertsHeadingText,
      activeAlertCount,
      mapVisible,
      bottomDockVisible,
      routeButtonBound: buttonBound("route"),
      reportButtonBound: buttonBound("report"),
      alertsButtonBound: buttonBound("alerts"),
      settingsButtonBound: buttonBound("settings"),
      objectLeakCheck,
      majorProblems
    };
  } catch (error) {
    return {
      layoutMode: document.body?.dataset?.layoutMode || "unknown",
      viewportWidth: Math.round(window.visualViewport?.width || window.innerWidth || 0),
      viewportHeight: Math.round(window.visualViewport?.height || window.innerHeight || 0),
      isStrictPortraitMobile: false,
      portraitCleanupGateActive: false,
      portraitPrimaryOwner: GRIDLY_PORTRAIT_PRIMARY_OWNER,
      duplicateOwnershipWarnings: [{ type: "audit_error", message: error?.message || "unknown error", systems: [] }],
      containedStructuralWrappers: [],
      retiredSurfaces: Object.keys(GRIDLY_PORTRAIT_RETIRED_SURFACES),
      protectedRuntimeFlags: {},
      headerText: "",
      alertsHeadingText: "",
      activeAlertCount: 0,
      mapVisible: false,
      bottomDockVisible: false,
      routeButtonBound: false,
      reportButtonBound: false,
      alertsButtonBound: false,
      settingsButtonBound: false,
      objectLeakCheck: { ok: false, auditError: error?.message || "unknown error", inspectedOnly: true },
      majorProblems: ["portrait_stability_smoke_audit_error"]
    };
  }
}

window.gridlyPortraitStabilitySmokeAudit = gridlyPortraitStabilitySmokeAudit;

