function getGridlyParallelBridgeDomSnapshot() {
  if (typeof document === "undefined") {
    return {
      markerPanePresent: false,
      routeNodes: [],
      communityNodes: [],
      allBridgeNodes: [],
      routePhraseNodes: [],
      communityPhraseNodes: []
    };
  }
  const markerPane = document.querySelector("#map .leaflet-marker-pane");
  const query = (selector) => markerPane ? Array.from(markerPane.querySelectorAll(selector)) : [];
  const routeNodes = Array.from(new Set(query('[data-gridly-route-impact="true"], [data-gridly-consequence], [data-gridly-confidence], [data-gridly-intelligence], [data-gridly-confidence-label], .gridly-marker-rail-route-impact, .gridly-marker-priority-route-impact')));
  const communityNodes = Array.from(new Set(query('[data-gridly-community-awareness="true"], [data-gridly-community-score], [data-gridly-community-corridor], [data-gridly-community-severity], [data-gridly-community-freshness], [data-gridly-community-bridge-source]')));
  const routePhraseNodes = routeNodes.filter((node) => Boolean(String(node?.dataset?.gridlyIntelligence || node?.getAttribute?.("data-gridly-intelligence") || "").trim()));
  const communityPhraseNodes = communityNodes.filter((node) => Boolean(String(node?.dataset?.gridlyCommunityCorridor || node?.getAttribute?.("data-gridly-community-corridor") || "").trim()));
  return {
    markerPanePresent: Boolean(markerPane),
    routeNodes,
    communityNodes,
    allBridgeNodes: Array.from(new Set([...routeNodes, ...communityNodes])),
    routePhraseNodes,
    communityPhraseNodes
  };
}

function countGridlyDuplicateBridgeKeys(nodes = []) {
  return Math.max(0, nodes.length - new Set(nodes).size);
}

function getGridlyBridgeOwnershipDiagnostics(options = {}) {
  const awarenessDiagnostics = getGridlyAwarenessModeDiagnostics(options);
  const routeGeometryAudit = typeof getGridlyActiveRouteCoordinatesForAudit === "function"
    ? getGridlyActiveRouteCoordinatesForAudit()
    : { activeRoutePresent: false, activeRouteCoordinateCount: 0 };
  const routeAudit = typeof window.gridlyRouteIntelligenceAudit === "function"
    ? window.gridlyRouteIntelligenceAudit(options)
    : { routeRelevantCount: 0, routeImpactPhraseCount: 0, selectedDomCount: 0 };
  const communityDataset = buildCommunityPresenceDataset(options);
  const domSnapshot = getGridlyParallelBridgeDomSnapshot();
  const routeBridgeApplied = domSnapshot.routeNodes.length > 0 || Number(routeAudit.selectedDomCount || 0) > 0;
  const communityBridgeApplied = domSnapshot.communityNodes.length > 0;
  const routeCommunitySourceConflicts = domSnapshot.routeNodes.filter((node) => String(node?.dataset?.gridlyCommunityBridgeSource || "") === GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE && String(node?.dataset?.gridlyRouteImpact || "").toLowerCase() === "true" && String(node?.dataset?.gridlyCommunityAwareness || "").toLowerCase() !== "true").length;
  const routeFieldsOnCommunityOnlyNodes = domSnapshot.communityNodes.filter((node) => !domSnapshot.routeNodes.includes(node) && (
    String(node?.dataset?.gridlyRouteImpact || "").toLowerCase() === "true"
    || Boolean(node?.dataset?.gridlyConsequence)
    || Boolean(node?.dataset?.gridlyConfidence)
    || Boolean(node?.dataset?.gridlyIntelligence)
  )).length;
  const communityFieldsOnRouteOnlyNodes = domSnapshot.routeNodes.filter((node) => !domSnapshot.communityNodes.includes(node) && (
    String(node?.dataset?.gridlyCommunityAwareness || "").toLowerCase() === "true"
    || Boolean(node?.dataset?.gridlyCommunityScore)
    || Boolean(node?.dataset?.gridlyCommunityBridgeSource)
  )).length;
  const duplicateBridgeTargets = countGridlyDuplicateBridgeKeys(domSnapshot.routeNodes) + countGridlyDuplicateBridgeKeys(domSnapshot.communityNodes);
  const duplicatePhraseTargets = countGridlyDuplicateBridgeKeys(domSnapshot.routePhraseNodes) + countGridlyDuplicateBridgeKeys(domSnapshot.communityPhraseNodes);
  const bridgeOwnershipConflicts = routeCommunitySourceConflicts + routeFieldsOnCommunityOnlyNodes + communityFieldsOnRouteOnlyNodes;
  return {
    loaded: true,
    version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
    awarenessMode: awarenessDiagnostics.awarenessMode,
    routeModeActive: awarenessDiagnostics.awarenessMode === "route",
    communityModeActive: communityDataset.selectedCommunityCount > 0,
    routeBridgeApplied,
    communityBridgeApplied,
    routePhraseCount: Number(routeAudit.routeImpactPhraseCount || routeAudit.routeRelevantPhraseCount || 0),
    communityPhraseCount: Number(communityDataset.communityPhraseCount || 0),
    bridgeOwnershipConflicts,
    duplicateBridgeTargets,
    duplicatePhraseTargets,
    activeRoutePresent: Boolean(routeGeometryAudit.activeRoutePresent || awarenessDiagnostics.activeRoutePresent),
    routeCoordinatesPresent: Number(routeGeometryAudit.activeRouteCoordinateCount || awarenessDiagnostics.activeRouteCoordinateCount || 0) > 1,
    activeRouteCoordinateCount: Number(routeGeometryAudit.activeRouteCoordinateCount || awarenessDiagnostics.activeRouteCoordinateCount || 0),
    routeRelevantCount: Number(routeAudit.routeRelevantCount || 0),
    selectedDomCount: Number(routeAudit.selectedDomCount || 0),
    communitySelectedDomCount: Number(awarenessDiagnostics.selectedDomCount || 0),
    routeBridgeDomCount: domSnapshot.routeNodes.length,
    communityBridgeDomCount: domSnapshot.communityNodes.length,
    bridgeOwnershipConflictBreakdown: {
      routeCommunitySourceConflicts,
      routeFieldsOnCommunityOnlyNodes,
      communityFieldsOnRouteOnlyNodes
    },
    notes: [
      "Route mode has awareness priority whenever active route coordinates are present.",
      "Community bridge metadata uses data-gridly-community-* fields only; route bridge metadata uses route/consequence/confidence fields only.",
      "Diagnostics are additive and do not rebuild markers, popups, or bridge DOM."
    ]
  };
}

window.gridlyIntelligenceModeStateAudit = function gridlyIntelligenceModeStateAudit(options = {}) {
  try {
    return getGridlyBridgeOwnershipDiagnostics(options);
  } catch (error) {
    return { loaded: false, version: GRIDLY_COMMUNITY_PRESENCE_VERSION, awarenessMode: "community", routeModeActive: false, communityModeActive: false, routeBridgeApplied: false, communityBridgeApplied: false, routePhraseCount: 0, communityPhraseCount: 0, bridgeOwnershipConflicts: 0, duplicateBridgeTargets: 0, duplicatePhraseTargets: 0, activeRoutePresent: false, routeCoordinatesPresent: false, notes: [`Intelligence mode state audit fallback: ${error?.message || "unknown error"}`] };
  }
};

window.gridlyBridgeOwnershipAudit = function gridlyBridgeOwnershipAudit(options = {}) {
  try {
    return getGridlyBridgeOwnershipDiagnostics(options);
  } catch (error) {
    return { loaded: false, version: GRIDLY_COMMUNITY_PRESENCE_VERSION, awarenessMode: "community", routeModeActive: false, communityModeActive: false, routeBridgeApplied: false, communityBridgeApplied: false, routePhraseCount: 0, communityPhraseCount: 0, bridgeOwnershipConflicts: 0, duplicateBridgeTargets: 0, duplicatePhraseTargets: 0, activeRoutePresent: false, routeCoordinatesPresent: false, notes: [`Bridge ownership audit fallback: ${error?.message || "unknown error"}`] };
  }
};

window.gridlyParallelModeAudit = function gridlyParallelModeAudit(options = {}) {
  try {
    const diagnostics = getGridlyBridgeOwnershipDiagnostics(options);
    return {
      ...diagnostics,
      parallelStable: diagnostics.bridgeOwnershipConflicts === 0 && diagnostics.duplicateBridgeTargets === 0,
      routePriorityConfirmed: diagnostics.activeRoutePresent ? diagnostics.awarenessMode === "route" : true,
      communityFallbackReady: !diagnostics.activeRoutePresent ? diagnostics.awarenessMode === "community" && diagnostics.communityPhraseCount > 0 : diagnostics.communityModeActive
    };
  } catch (error) {
    return { loaded: false, version: GRIDLY_COMMUNITY_PRESENCE_VERSION, awarenessMode: "community", routeModeActive: false, communityModeActive: false, routeBridgeApplied: false, communityBridgeApplied: false, routePhraseCount: 0, communityPhraseCount: 0, bridgeOwnershipConflicts: 0, duplicateBridgeTargets: 0, duplicatePhraseTargets: 0, activeRoutePresent: false, routeCoordinatesPresent: false, parallelStable: false, routePriorityConfirmed: false, communityFallbackReady: false, notes: [`Parallel mode audit fallback: ${error?.message || "unknown error"}`] };
  }
};

window.gridlyAwarenessModeDebug = {
  loaded: true,
  version: GRIDLY_COMMUNITY_PRESENCE_VERSION,
  bridgeSource: GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE
};


function applyRouteVisualEmphasis() {
  const primaryStyle = preferredRoute === "primary"
    ? { ...gridlyGetVisualSignatureRouteStyle("core"), weight: 8, opacity: 0.96 }
    : { ...gridlyGetVisualSignatureRouteStyle("core"), weight: 6, opacity: 0.58 };
  const alternateStyle = preferredRoute === "alternate"
    ? { ...gridlyGetVisualSignatureRouteStyle("alternate"), weight: 6, opacity: 0.9 }
    : { ...gridlyGetVisualSignatureRouteStyle("alternate"), weight: 4, opacity: 0.48 };
  if (window.__gridlyRoutePreviewLayer?.setStyle) window.__gridlyRoutePreviewLayer.setStyle(primaryStyle);
  if (alternateRouteLayer?.setStyle) alternateRouteLayer.setStyle(alternateStyle);
}



function getRerouteFoundation(routeHazard = {}) {
  const level = String(routeHazard?.level || "clear").toLowerCase();
  const rerouteRecommended = level === "blocked" || level === "heavy";
  const rerouteReason = level === "blocked"
    ? "Blocked crossing detected. Consider another route."
    : level === "heavy"
      ? "Heavy delay detected. Leave early or reroute."
      : "";
  const alternateRouteStatus = rerouteRecommended ? "needed" : "not_needed";
  return {
    rerouteRecommended,
    rerouteReason,
    rerouteTargetIssue: routeHazard?.nearestIssue || null,
    originalRouteGeometrySource: routeGeometrySource || "fallback",
    originalRouteVertexCount: Number.isFinite(Number(routePreviewPolylinePointCount)) ? Number(routePreviewPolylinePointCount) : 0,
    alternateRouteAvailable: rerouteRecommended ? alternateRouteAvailable : false,
    alternateRouteReason: rerouteRecommended ? (alternateRouteReason || "Alternate route check recommended.") : "",
    alternateRouteGeometrySource: rerouteRecommended ? (alternateRouteGeometrySource || "none") : "none",
    alternateRouteVertexCount: rerouteRecommended ? alternateRouteVertexCount : 0,
    alternateRouteStatus: rerouteRecommended ? (alternateRouteStatus || "unavailable") : alternateRouteStatus
  };
}

function isIncidentRouteRelevant(incident = {}, routeHazard = null) {
  if (!routeWatchActivated) return false;
  const routeLatLngs = getRoutePolylineLatLngs();
  if (routeLatLngs.length < 2) return false;
  const nearbyReports = Array.isArray(routeHazard?.nearbyReports) ? routeHazard.nearbyReports : getRouteHazardAssessment().nearbyReports;
  const nearbyCrossingIds = new Set(nearbyReports.map((report) => String(report.crossingId || "")));
  if (incident?.crossingId && nearbyCrossingIds.has(String(incident.crossingId))) return true;
  const incidentLat = Number(incident?.lat);
  const incidentLng = Number(incident?.lng);
  if (!Number.isFinite(incidentLat) || !Number.isFinite(incidentLng)) return false;
  const thresholdMiles = 0.8;
  const minDistance = routeLatLngs.reduce((minDist, pt) => Math.min(minDist, getDistanceMiles(incidentLat, incidentLng, pt.lat, pt.lng)), Number.POSITIVE_INFINITY);
  return Number.isFinite(minDistance) && minDistance <= thresholdMiles;
}

function getRouteStatusColor() {
  const routeReports = activeReports.filter((report) => savedRouteCrossingIds.has(String(report.crossingId)));
  const hasBlocked = routeReports.some(
    (report) => getIncidentLifecycleState(report) === "active" && String(report.type || "").toLowerCase() === "blocked"
  );
  if (hasBlocked) return "#e53935";
  const hasDelay = routeReports.some(
    (report) => getIncidentLifecycleState(report) === "active" && String(report.type || "").toLowerCase() === "heavy"
  );
  if (hasDelay) return "#ffb020";
  return "#1fbf68";
}

function inferSavedRouteCrossings() {
  const savedHome = String(localStorage.getItem("gridlyHome") || "").toLowerCase();
  const savedWork = String(localStorage.getItem("gridlyWork") || "").toLowerCase();
  if (!savedHome || !savedWork || !crossings.length) return [];
  const homeCandidates = crossings.filter((crossing) => savedHome.includes(String(crossing.city || "").toLowerCase()));
  const workCandidates = crossings.filter((crossing) => savedWork.includes(String(crossing.city || "").toLowerCase()));
  const from = (homeCandidates.length ? homeCandidates : crossings).slice(0, 80);
  const to = (workCandidates.length ? workCandidates : crossings).slice(0, 80);
  let bestPair = null;
  from.forEach((a) => {
    to.forEach((b) => {
      const d = getDistanceMiles(a.lat, a.lng, b.lat, b.lng);
      if (!bestPair || d < bestPair.distance) bestPair = { a, b, distance: d };
    });
  });
  if (!bestPair) return [];
  const corridor = crossings
    .map((crossing) => {
      const da = getDistanceMiles(crossing.lat, crossing.lng, bestPair.a.lat, bestPair.a.lng);
      const db = getDistanceMiles(crossing.lat, crossing.lng, bestPair.b.lat, bestPair.b.lng);
      return { crossing, metric: da + db };
    })
    .sort((x, y) => x.metric - y.metric)
    .slice(0, 12)
    .map((entry) => entry.crossing)
    .sort((x, y) => getDistanceMiles(x.lat, x.lng, bestPair.a.lat, bestPair.a.lng) - getDistanceMiles(y.lat, y.lng, bestPair.a.lat, bestPair.a.lng));
  return corridor;
}

async function fetchRoadRoutePreviewData(from, to, options = {}) {
  if (!Array.isArray(from) || !Array.isArray(to)) return null;
  const [fromLat, fromLng] = from.map(Number);
  const [toLat, toLng] = to.map(Number);
  if (![fromLat, fromLng, toLat, toLng].every((n) => Number.isFinite(n))) return null;

  const timeoutMs = Number.isFinite(Number(options.timeoutMs)) ? Number(options.timeoutMs) : 4500;
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const osrmFetchStartedAt = getGridlyDestinationPerfNow();
    const response = await fetch(
      `${OSRM_ROUTE_API}/${fromLng},${fromLat};${toLng},${toLat}?overview=full&geometries=geojson&alternatives=false&steps=false`,
      { signal: controller.signal }
    );
    setGridlyDestinationPerformanceTiming("osrmFetchMs", getGridlyDestinationPerfNow() - osrmFetchStartedAt);
    if (!response.ok) {
      addGridlyDestinationPerformanceNote(`OSRM response not ok: ${response.status}`);
      return null;
    }
    const parseStartedAt = getGridlyDestinationPerfNow();
    const data = await response.json();
    const route = data?.routes?.[0] || null;
    const coordinates = route?.geometry?.coordinates;
    if (!Array.isArray(coordinates) || coordinates.length < 2) {
      setGridlyDestinationPerformanceTiming("routeGeometryParseMs", getGridlyDestinationPerfNow() - parseStartedAt);
      addGridlyDestinationPerformanceNote("OSRM route geometry missing or too short");
      return null;
    }
    const latLngs = coordinates
      .map(([lng, lat]) => [Number(lat), Number(lng)])
      .filter((pt) => Number.isFinite(pt[0]) && Number.isFinite(pt[1]));
    setGridlyDestinationPerformanceTiming("routeGeometryParseMs", getGridlyDestinationPerfNow() - parseStartedAt);
    gridlyDestinationPerformanceAuditState.routeGeometryPointCount = latLngs.length;
    if (latLngs.length < 2) return null;
    const distanceMeters = Number(route?.distance);
    const durationSeconds = Number(route?.duration);
    return {
      geometry: latLngs,
      distanceMeters: Number.isFinite(distanceMeters) && distanceMeters > 0 ? distanceMeters : null,
      distanceMiles: Number.isFinite(distanceMeters) && distanceMeters > 0 ? distanceMeters / 1609.344 : null,
      durationSeconds: Number.isFinite(durationSeconds) && durationSeconds > 0 ? durationSeconds : null,
      etaMinutes: Number.isFinite(durationSeconds) && durationSeconds > 0 ? Math.max(1, Math.round(durationSeconds / 60)) : null,
      provider: "osrm"
    };
  } catch (error) {
    addGridlyDestinationPerformanceNote(`OSRM route preview fetch failed: ${String(error?.name || error?.message || error || "unknown")}`);
    return null;
  } finally {
    clearTimeout(timeout);
  }
}

async function fetchRoadRouteCoordinates(from, to) {
  const routePreview = await fetchRoadRoutePreviewData(from, to);
  return routePreview?.geometry || null;
}

async function fetchAlternateRouteCoordinates(from, to, primaryPoints = []) {
  if (!Array.isArray(from) || !Array.isArray(to)) return null;
  const [fromLat, fromLng] = from;
  const [toLat, toLng] = to;
  if (![fromLat, fromLng, toLat, toLng].every((value) => Number.isFinite(Number(value)))) return null;
  const primarySignature = Array.isArray(primaryPoints)
    ? primaryPoints.map((point) => `${Number(point?.[0]).toFixed(5)},${Number(point?.[1]).toFixed(5)}`).join("|")
    : "";
  const osrmUrl = `${OSRM_ROUTE_API}/${Number(fromLng)},${Number(fromLat)};${Number(toLng)},${Number(toLat)}?overview=full&geometries=geojson&alternatives=true&steps=false`;
  const response = await fetch(osrmUrl, { method: "GET" });
  if (!response.ok) return null;
  const payload = await response.json();
  const alternateCandidates = Array.isArray(payload?.routes) ? payload.routes.slice(1) : [];
  for (const route of alternateCandidates) {
    const routeCoordinates = route?.geometry?.coordinates;
    if (!Array.isArray(routeCoordinates) || routeCoordinates.length < 2) continue;
    const convertedPoints = routeCoordinates
      .map((point) => (Array.isArray(point) ? [Number(point[1]), Number(point[0])] : null))
      .filter((point) => Array.isArray(point) && Number.isFinite(point[0]) && Number.isFinite(point[1]));
    if (convertedPoints.length < 2) continue;
    const signature = convertedPoints.map((point) => `${point[0].toFixed(5)},${point[1].toFixed(5)}`).join("|");
    if (primarySignature && signature === primarySignature) continue;
    return convertedPoints;
  }
  return null;
}

function drawPremiumRouteLine(latLngs, color = getRouteStatusColor(), renderFunction = "drawPremiumRouteLine") {
  if (!savedRouteLayer || !Array.isArray(latLngs) || latLngs.length < 2) return;
  const activation = getLineActivationContext();
  if (!activation.hasActivation) {
    savedRouteLayer.clearLayers();
    return;
  }

  const glow = L.polyline(latLngs, {
    pane: "routePane",
    color: "#3cf2ff",
    weight: 10,
    opacity: 0.18,
    lineJoin: "round",
    lineCap: "round",
    interactive: false
  });

  const core = L.polyline(latLngs, {
    pane: "routePane",
    color,
    weight: 4,
    opacity: 0.88,
    lineJoin: "round",
    lineCap: "round",
    interactive: false
  });

  const accent = L.polyline(latLngs, {
    pane: "routePane",
    color: "#9efaff",
    weight: 2,
    opacity: 0.68,
    lineJoin: "round",
    lineCap: "round",
    interactive: false
  });

  savedRouteLayer.addLayer(glow);
  savedRouteLayer.addLayer(core);
  savedRouteLayer.addLayer(accent);
  logGridlyMapLineRendered({
    renderFunction,
    routeId: activation.selectedRouteId,
    activationReason: activation.selectedRouteId ? "selected-route-id" : activation.routeWatchActive ? "route-watch-active" : "selected-corridor-id",
    coordinates: latLngs
  });

  if (map && routeFocusArmed) {
    const bounds = L.latLngBounds(latLngs);
    if (bounds.isValid()) {
      map.fitBounds(bounds, { paddingTopLeft: [32, 240], paddingBottomRight: [32, 72], maxZoom: 13, animate: false });
      routeFocusArmed = false;
    }
  }
}

async function renderSavedRouteLine() {
  if (!savedRouteLayer) return;
  const activation = getLineActivationContext();
  if (!activation.hasActivation) {
    savedRouteLayer.clearLayers();
    lastRenderedRouteKey = "";
    return;
  }
  const routeCrossings = inferSavedRouteCrossings();
  savedRouteCrossingIds = new Set(routeCrossings.map((c) => String(c.id)));
  if (routeCrossings.length < 2) {
    lastRenderedRouteKey = "";
    routeFocusArmed = true;
    savedRouteLayer.clearLayers();
    return;
  }

  const from = [routeCrossings[0].lat, routeCrossings[0].lng];
  const to = [routeCrossings[routeCrossings.length - 1].lat, routeCrossings[routeCrossings.length - 1].lng];
  const routeKey = `${from.join(",")}|${to.join(",")}|${getRouteStatusColor()}`;
  if (routeKey === lastRenderedRouteKey) return;
  lastRenderedRouteKey = routeKey;

  savedRouteLayer.clearLayers();
  const osrmPath = await fetchRoadRouteCoordinates(from, to);
  const fallbackPath = routeCrossings.map((crossing) => [crossing.lat, crossing.lng]);
  drawPremiumRouteLine(osrmPath?.length > 1 ? osrmPath : fallbackPath, getRouteStatusColor(), "renderSavedRouteLine");
  recordGridlyActiveLocationLifecycleEvent("renderSavedRouteLine:complete", {
    routeKey,
    routeWatchActivated: Boolean(routeWatchActivated),
    pointCount: (osrmPath?.length > 1 ? osrmPath : fallbackPath).length,
    geometrySource: osrmPath?.length > 1 ? "osrm" : "fallback"
  });
}

function getMarkerLabel(report, markerStateClass, lifecycleState) {
  if (lifecycleState === "recently_cleared" || markerStateClass === "state-cleared") return "✅";
  if (markerStateClass === "state-blocked") return "🛑";
  if (markerStateClass === "state-delay") return "⏱";
  return "◦";
}

function buildSmartIncidentClusters(visibleCrossings = []) {
  const candidates = visibleCrossings
    .map((crossing) => {
      const report = getLatestReportForCrossing(crossing.id);
      const lifecycleState = getIncidentLifecycleState(report);
      if (!report || lifecycleState !== "active") return null;
      const reportType = String(report?.type || "").toLowerCase();
      const severity = reportType === "blocked" ? 2 : reportType === "heavy" ? 1 : 0;
      const candidate = { crossing, report, severity };
      return candidate;
    })
    .filter(Boolean);

  const hiddenIds = new Set();
  const leadCounts = new Map();
  const groupedIds = new Set();

  candidates.forEach((seed) => {
    const seedId = String(seed.crossing.id);
    if (groupedIds.has(seedId)) return;
    const group = candidates.filter((candidate) => {
      if (groupedIds.has(String(candidate.crossing.id))) return false;
      return getDistanceMiles(seed.crossing.lat, seed.crossing.lng, candidate.crossing.lat, candidate.crossing.lng) <= 0.34;
    });
    group.forEach((entry) => groupedIds.add(String(entry.crossing.id)));
    if (group.length <= 2) return;

    const leader = group.sort((a, b) => b.severity - a.severity || a.report.minutesAgo - b.report.minutesAgo)[0];
    leadCounts.set(String(leader.crossing.id), group.length);
    group.forEach((entry) => {
      const id = String(entry.crossing.id);
      if (id !== String(leader.crossing.id)) hiddenIds.add(id);
    });
  });

  return { leadCounts, hiddenIds };
}




function highlightNearestCrossingOnFirstLoad() {
  if (!map || !crossings.length) return;
  if (localStorage.getItem(MAP_FIRST_HINT_SEEN_KEY)) return;

  const center = getGridlyAwarenessAnchor();
  const nearest = findNearestCrossings(center.lat, center.lng, 1)[0];
  if (!nearest) return;

  const marker = crossingMarkers.get(String(nearest.id));
  if (!marker) return;

  const markerEl = marker.getElement?.();
  markerEl?.classList.add("pulse-nearest");

  marker.bindTooltip("Tap marker to report status", {
    direction: "top",
    offset: [0, -12],
    className: "gridly-map-hint",
    opacity: 0.96
  });

  marker.openTooltip();
  localStorage.setItem(MAP_FIRST_HINT_SEEN_KEY, "1");

  setTimeout(() => {
    marker.closeTooltip();
    markerEl?.classList.remove("pulse-nearest");
  }, 4200);
}

function getFilterFitPadding() {
  if (typeof getGridlyAwarenessFitPadding === "function") return getGridlyAwarenessFitPadding();
  const isMobile = window.matchMedia && window.matchMedia("(max-width: 768px)").matches;
  return isMobile ? { paddingTopLeft: [20, 112], paddingBottomRight: [20, 148] } : { paddingTopLeft: [24, 48], paddingBottomRight: [24, 96] };
}

function fitMapToCrossingsForActiveFilter(visibleCrossings = []) {
  if (!map) return;
  if (!Array.isArray(visibleCrossings) || !visibleCrossings.length) return;

  const latLngs = visibleCrossings
    .map((crossing) => [Number(crossing.lat), Number(crossing.lng)])
    .filter(([lat, lng]) => Number.isFinite(lat) && Number.isFinite(lng));

  if (!latLngs.length) return;

  const bounds = L.latLngBounds(latLngs);
  if (!bounds.isValid()) return;

  map.fitBounds(bounds, {
    ...getFilterFitPadding(),
    animate: true,
    duration: 0.55,
    maxZoom: window.matchMedia && window.matchMedia("(max-width: 768px)").matches ? 16 : 15
  });

  highlightNearestCrossingOnFirstLoad();
}

function updateGeoFilterStatus(visibleCrossings = []) {
  if (!els.geoFilterStatus) return;
  if (activeGeoFilter === "nearby" && userLocation) {
    updateNearestContext();
    return;
  }

  const count = visibleCrossings.length;
  const crossingLabel = count === 1 ? "crossing" : "crossings";
  let message = "All crossings visible: tap markers to confirm route status.";

  if (activeGeoFilter === "nearby") {
    message = count ? `Act now: review ${count} nearby ${crossingLabel} before departure.` : "Action needed: switch filters or zoom to find crossings.";
  } else if (activeGeoFilter === "town") {
    message = count ? `Route focus: check ${count} likely commute ${crossingLabel}.` : "No route crossings in view. Try My Town or Delays.";
  } else if (activeGeoFilter === "county") {
    message = count ? "Awareness area: scan crossings and tap any issue marker." : "No awareness area crossings visible. Reset map view.";
  } else if (activeGeoFilter === "active-delays") {
    const delayLabel = count === 1 ? "delay" : "delays";
    message = count ? `Priority: resolve ${count} active ${delayLabel} affecting routes.` : "Good news: no active delays in this view.";
  } else if (activeGeoFilter === "all") {
    message = "All crossings visible: tap markers to confirm route status.";
  }

  els.geoFilterStatus.textContent = message;
}

function getVisibleCrossingsForFilter(reason = "unknown") {
  const fallbackToAll = () => {
    debugGeoFilter(activeGeoFilter, crossings.length, reason);
    return crossings;
  };

  if (activeGeoFilter === "all") {
    const relevant = getDefaultRelevantCrossings();
    debugGeoFilter("All", relevant.length, reason);
    return relevant;
  }

  if (activeGeoFilter === "active-delays") {
    const filtered = crossings.filter((crossing) => {
      const report = getLatestReportForCrossing(crossing.id);
      return getIncidentLifecycleState(report) === "active";
    });
    debugGeoFilter("Active Delays", filtered.length, reason);
    return filtered;
  }

  if (activeGeoFilter === "county") {
    const filtered = crossings.filter(
      (crossing) => String(crossing.county || "").toLowerCase() === "liberty county"
    );
    debugGeoFilter("My County", filtered.length, reason);
    return filtered;
  }

  if (activeGeoFilter === "town") {
    const awarenessAnchor = typeof getGridlyHomeTownAwarenessAnchor === "function" ? getGridlyHomeTownAwarenessAnchor() : null;
    const filtered = awarenessAnchor ? getGridlyHomeTownCrossings(awarenessAnchor) : crossings.filter(
      (crossing) => String(crossing.city || "").toLowerCase() === getMyTownKey()
    );

    if (!filtered.length) {
      const center = awarenessAnchor || getGridlyAwarenessAnchor({ preferUserLocation: false });
      const nearest = center ? findNearestCrossings(center.lat, center.lng, 10) : crossings;
      debugGeoFilter("Awareness Area", nearest.length, reason);
      return nearest;
    }

    debugGeoFilter("Awareness Area", filtered.length, reason);
    return filtered;
  }

  if (activeGeoFilter === "nearby") {
    const center = getGridlyAwarenessAnchor();
    const nearest = findNearestCrossings(center.lat, center.lng, 10);
    debugGeoFilter("Nearby", nearest.length, reason);
    return nearest;
  }

  return fallbackToAll();
}

function debugGeoFilter(label, visibleCount, reason = "unknown") {
  gridlyCrossingRenderAuditState.filterApplyCallCount += 1;
  const signature = `${activeGeoFilter}|${label}|${visibleCount}`;
  const now = pushCrossingAuditCall("filter-apply", reason, { label, visibleCount, activeGeoFilter, signature });
  const lastApply = gridlyCrossingRenderAuditState.lastFilterApply;
  if (signature === lastApply.signature && now - lastApply.at <= GRIDLY_GEO_FILTER_DEDUPE_MS) return;
  gridlyCrossingRenderAuditState.lastFilterApply = { key: activeGeoFilter, visibleCount, signature, at: now };
  if (GRIDLY_CROSSING_RENDER_DEBUG) {
    console.debug(`Filter applied: ${label}`);
    console.debug(`Visible crossings: ${visibleCount}`);
  }
}

function ensureUnifiedIncidentLayerOnMap() {
  if (!map || typeof L === "undefined" || !L?.layerGroup) return false;
  if (!unifiedIncidentLayer) {
    unifiedIncidentLayer = L.layerGroup();
  }
  if (typeof map.hasLayer === "function" && !map.hasLayer(unifiedIncidentLayer)) {
    unifiedIncidentLayer.addTo(map);
  }
  return Boolean(unifiedIncidentLayer && typeof map.hasLayer === "function" ? map.hasLayer(unifiedIncidentLayer) : unifiedIncidentLayer);
}

function gridlyIncidentEligibleForMapMarker(incident = {}) {
  const type = String(incident?.report_type || incident?.type || "").trim().toLowerCase();
  const status = String(incident?.status || incident?.state || "").trim().toLowerCase();
  const lifecycleState = String(incident?.lifecycleState || incident?.lifecycle || incident?.lifecycle_state || "").trim().toLowerCase();
  if (type === "hazard_cleared") return false;
  if (status === "cleared" || status === "hazard_cleared") return false;
  if (["recently_cleared", "cleared", "hazard_cleared"].includes(lifecycleState)) return false;
  return true;
}

function renderUnifiedIncidents(reason = "auto") {
  const endRenderUnifiedTrace = timeGridlyReflowTrace("renderUnifiedIncidents");
  if (!ensureUnifiedIncidentLayerOnMap()) return;

  unifiedIncidentLayer.clearLayers();

  const unifiedIncidents = getUnifiedIncidents();
  const fallbackHazards = Array.isArray(activeHazards) ? activeHazards : [];
  const getIncidentCoordinate = (incident) => {
    const lat = incident?.lat ?? incident?.latitude ?? incident?.rawLat;
    const lng = incident?.lng ?? incident?.lon ?? incident?.longitude ?? incident?.rawLng;
    return { lat, lng };
  };
  const hasFiniteCoordinates = (incident) => {
    const { lat, lng } = getIncidentCoordinate(incident);
    return Number.isFinite(Number(lat)) && Number.isFinite(Number(lng));
  };
  const primaryIncidents = Array.isArray(unifiedIncidents) ? unifiedIncidents : [];
  const primaryCoordinateCount = primaryIncidents.filter(hasFiniteCoordinates).length;
  const fallbackCoordinateCount = fallbackHazards.filter(hasFiniteCoordinates).length;
  const shouldUseFallbackHazards = primaryCoordinateCount === 0 && fallbackCoordinateCount > 0;
  const incidents = shouldUseFallbackHazards ? fallbackHazards : primaryIncidents;
  const markerRenderSkipReasons = { missing_lat_lng: 0, invalid_lat_lng: 0, filtered_out: 0, cleared_or_recently_cleared: 0, missing_marker_layer: 0, render_exception: 0 };
  const markerSourceUsed = shouldUseFallbackHazards ? "activeHazards_fallback" : "unifiedIncidents";
  const sourceCounts = {
    primaryCount: primaryIncidents.length,
    primaryValidCount: primaryCoordinateCount,
    activeHazardsCount: fallbackHazards.length,
    activeHazardsValidCount: fallbackCoordinateCount,
    selectedSourceName: markerSourceUsed,
    selectedSourceCount: incidents.length
  };
  const routeHazard = routeWatchActivated ? getRouteHazardAssessment() : null;
  const dedupedMap = new Map();
  const duplicateCounts = new Map();

  incidents.forEach((incident) => {
    const renderKey = getUnifiedIncidentRenderKey(incident);
    incident._gridlyRenderKey = renderKey;
    if (!dedupedMap.has(renderKey)) {
      dedupedMap.set(renderKey, incident);
      duplicateCounts.set(renderKey, 1);
      return;
    }
    duplicateCounts.set(renderKey, (duplicateCounts.get(renderKey) || 1) + 1);
    dedupedMap.set(renderKey, choosePreferredIncidentCandidate(dedupedMap.get(renderKey), incident, routeHazard));
  });
  const dedupedIncidents = [...dedupedMap.values()];
  const markerEligibleIncidents = dedupedIncidents.filter((incident) => {
    const eligible = gridlyIncidentEligibleForMapMarker(incident);
    if (!eligible) markerRenderSkipReasons.cleared_or_recently_cleared += 1;
    return eligible;
  });

  const markersByCategory = {};
  const markerTypesRendered = new Set();
  const activeVisualStates = new Set();
  let markersAffectingRoute = 0;
  let routeHighlightedMarkers = 0;

  markerEligibleIncidents.forEach((incident) => {
    if (!unifiedIncidentLayer) { markerRenderSkipReasons.missing_marker_layer += 1; return; }
    const { lat: rawLat, lng: rawLng } = getIncidentCoordinate(incident);
    if (rawLat == null || rawLng == null) { markerRenderSkipReasons.missing_lat_lng += 1; return; }
    const lat = Number(rawLat);
    const lng = Number(rawLng);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) { markerRenderSkipReasons.invalid_lat_lng += 1; return; }

    const distanceFromUser = userLocation
      ? getDistanceMiles(userLocation.lat, userLocation.lng, lat, lng)
      : null;
    const isNearbyPriority = Number.isFinite(distanceFromUser) && distanceFromUser <= PRIORITY_NEARBY_MILES;
    const ageClass =
      incident.age_minutes <= 15 ? "fresh" : incident.age_minutes <= 60 ? "aging" : "old";
    const proximityClass = isNearbyPriority ? "nearby-priority" : "far-faded";
    const routeRelevanceClass = routeWatchActivated
      ? (isIncidentRouteRelevant(incident, routeHazard) ? "route-relevant" : "route-deemphasized")
      : "";
    const visualState = getGridlyIncidentVisualState(incident);
    const markerVisual = getGridlyMarkerVisualConfig(visualState.markerStyle);
    const hierarchyConfig = getGridlyMarkerHierarchyConfig(visualState.markerStyle);
    const markerVisualClass = markerVisual.className;
    const markerVisualClassSafe = sanitizeText(markerVisualClass);
    const hazardVisualClassSegment = markerVisualClassSafe ? ` ${markerVisualClassSafe}` : "";
    const priorityClassMap = {
      "route-impact": "gridly-marker-priority-route-impact",
      critical: "gridly-marker-priority-critical",
      high: "gridly-marker-priority-high",
      moderate: "gridly-marker-priority-moderate",
      low: "gridly-marker-priority-low",
      passive: "gridly-marker-priority-passive"
    };
    const hierarchyPriorityClass = priorityClassMap[hierarchyConfig.emphasisLevel] || "gridly-marker-priority-passive";
    const consequenceLevel = String(visualState?.consequenceLevel || "low").toLowerCase();
    const consequenceClass = `gridly-consequence-${consequenceLevel}`;
    const freshnessLevel = String(visualState?.freshnessLevel || evaluateGridlyIncidentFreshness(incident)?.freshnessLevel || "recent").toLowerCase();
    const freshnessClass = `gridly-freshness-${freshnessLevel}`;
    const confidenceEval = evaluateGridlyIncidentConfidence(incident, { visualState, freshnessOptions: { nowMs: Date.now() } });
    const confidenceLevel = String(confidenceEval?.confidenceLevel || "low").toLowerCase();
    const confidenceVisualClass = `gridly-confidence-${confidenceLevel.replace(/_/g, "-")}`;
    const hazardVisualOwner = gridlyResolveVisualHierarchyOwner({ visualStyle: visualState.markerStyle, markerNode: null, config: hierarchyConfig, incident });
    const markerState = incident?.status === "cleared" || incident?.report_type === "hazard_cleared" ? "cleared" : "active";
    const hazardVisualMetadata = gridlyBuildVisualPriorityMetadata({
      owner: hazardVisualOwner,
      visualState: markerState === "cleared" ? "recently_cleared" : (routeRelevanceClass === "route-relevant" ? "route_impact" : "active"),
      routeRelevant: routeRelevanceClass === "route-relevant",
      selected: false,
      impactLevel: hierarchyConfig.emphasisLevel,
      priorityRank: hierarchyConfig.priorityRank
    });
    const intelligence = generateGridlyIntelligencePhrase(incident, visualState);
    const communityPresence = typeof scoreCommunityPresenceIncident === "function"
      ? scoreCommunityPresenceIncident(incident, { allCandidates: dedupedIncidents })
      : null;
    const hazardVisualMetadataAttributes = `
          data-visual-style="${sanitizeText(visualState.markerStyle)}"
          data-visual-priority="${sanitizeText(String(markerVisual.priority))}"
          data-gridly-marker-priority="${sanitizeText(String(hierarchyConfig.priorityRank))}"
          data-gridly-marker-weight="${sanitizeText(String(hierarchyConfig.visualWeight))}"
          ${hazardVisualMetadata.attributes}
          data-gridly-consequence="${sanitizeText(consequenceLevel)}"
          data-gridly-freshness="${sanitizeText(freshnessLevel)}"
          data-gridly-confidence="${sanitizeText(confidenceLevel)}"
          data-gridly-intelligence="${sanitizeText(intelligence.shortPhrase)}"
          data-gridly-confidence-label="${sanitizeText(intelligence.confidencePhrase)}"
          data-incident-id="${sanitizeText(getGridlyCommunityIncidentId(incident))}"
          data-lat="${sanitizeText(String(lat))}"
          data-lng="${sanitizeText(String(lng))}"
          data-gridly-community-awareness="${communityPresence ? "true" : "false"}"
          data-gridly-community-score="${sanitizeText(String(communityPresence?.communityPresenceScore || 0))}"
          data-gridly-community-corridor="${sanitizeText(communityPresence?.corridor || "Local corridors")}"
          data-gridly-community-severity="${sanitizeText(String(communityPresence?.severity || "low"))}"
          data-gridly-community-freshness="${sanitizeText(String(communityPresence?.freshnessLevel || "unknown"))}"
          data-gridly-community-bridge-source="${sanitizeText(GRIDLY_COMMUNITY_AWARENESS_BRIDGE_SOURCE)}"
        `;
    const category = getHazardCategory(incident.report_type || incident.type || "other_hazard");
    const markerVariantClass = `marker-${category}`;
    const confidenceClass = String(incident.confidence || "").toLowerCase().includes("community") ? "confidence-community" : "confidence-high";
    markersByCategory[category] = (markersByCategory[category] || 0) + 1;
    markerTypesRendered.add(markerVariantClass);
    markerTypesRendered.add(getMapSeverityClass(incident));
    markerTypesRendered.add(confidenceClass);
    markerTypesRendered.add(markerVisualClass);
    activeVisualStates.add(ageClass);
    if (routeRelevanceClass) activeVisualStates.add(routeRelevanceClass);
    if (routeRelevanceClass === "route-relevant") {
      markersAffectingRoute += 1;
      routeHighlightedMarkers += 1;
    }

    const icon = L.divIcon({
      className: `${markerVisualClassSafe} ${sanitizeText(hazardVisualMetadata.className)}`,
      html: `
        <div class="gridly-hazard-marker ${sanitizeText(getMapSeverityClass(incident))} ${ageClass} ${proximityClass} ${routeRelevanceClass} ${sanitizeText(markerVariantClass)} ${sanitizeText(confidenceClass)} ${sanitizeText(hierarchyPriorityClass)} ${sanitizeText(consequenceClass)} ${sanitizeText(freshnessClass)} ${sanitizeText(confidenceVisualClass)} ${sanitizeText(hazardVisualMetadata.className)}${hazardVisualClassSegment}"
          data-category="${sanitizeText(category)}"
          ${hazardVisualMetadataAttributes}
          data-freshness="${sanitizeText(ageClass)}"
          data-confidence="${sanitizeText(confidenceClass.replace("confidence-", ""))}"
          data-route-relevance="${sanitizeText(routeRelevanceClass || "unscored")}"
          data-state="${sanitizeText(markerState)}">
          <span>${sanitizeText(getCategoryMarkerGlyph(category, incident))}</span>
          <small>${incident.age_minutes}m</small>
          ${incident.reports_count > 1 ? `<b>${incident.reports_count}</b>` : ""}
        </div>
      `,
      iconSize: [46, 46],
      iconAnchor: [23, 23]
    });

    try {
      L.marker([lat, lng], {
        icon,
        incidentId: String(incident?.id || incident?.report_id || incident?.key || ""),
        incidentSource: String(incident?.source || ""),
        gridlyPlacementAudit: {
          incidentId: String(incident?.id || incident?.report_id || incident?.key || ""),
          coordinateSourceUsed: incident?.coordinateSourceUsed || "unified_incident_lat_lng",
          rawTapCoordinate: incident?.rawTapCoordinate || incident?.reportCaptureCoordinate || null,
          snappedRoadCoordinate: incident?.snappedRoadCoordinate || null,
          finalPlacementCoordinate: incident?.finalPlacementCoordinate || { lat, lng },
          renderedMarkerCoordinate: { lat, lng },
          reportCaptureCoordinate: incident?.reportCaptureCoordinate || null,
          storedReportCoordinate: incident?.storedReportCoordinate || null,
          activeHazardCoordinate: incident?.activeHazardCoordinate || null,
          unifiedIncidentCoordinate: { lat, lng },
          tapToSnapDeltaMeters: incident?.tapToSnapDeltaMeters ?? null,
          tapToFinalDeltaMeters: incident?.tapToFinalDeltaMeters ?? null,
          snapToFinalDeltaMeters: incident?.snapToFinalDeltaMeters ?? null,
          placementMode: incident?.placementMode || null,
          placementRiskLevel: incident?.placementRiskLevel || null,
          roadCandidateCount: incident?.roadCandidateCount ?? null,
          nearestCandidateDistanceMeters: incident?.nearestCandidateDistanceMeters ?? null,
          representativeCoordinateReason: incident?.representativeCoordinateReason || null
        }
      })
        .bindPopup(buildUnifiedIncidentPopup(incident), { maxWidth: 340 })
        .addTo(unifiedIncidentLayer);
    } catch (error) {
      markerRenderSkipReasons.render_exception += 1;
    }
  });

  const duplicateEntries = [...duplicateCounts.entries()].filter(([, count]) => count > 1);
  const duplicateIncidentCount = duplicateEntries.reduce((sum, [, count]) => sum + (count - 1), 0);

  updateHazardCounter(markerEligibleIncidents);
  lastMarkerAuditDebug = {
    activeMarkerCount: markerEligibleIncidents.length,
    totalIncidentsInput: incidents.length,
    uniqueIncidentRenderCount: markerEligibleIncidents.length,
    markerEligibleIncidentCount: markerEligibleIncidents.length,
    markerSuppressedClearedOrRecentlyClearedCount: markerRenderSkipReasons.cleared_or_recently_cleared,
    duplicateIncidentCount,
    duplicateKeysPreview: duplicateEntries.slice(0, 8).map(([key, count]) => `${key}×${count}`),
    activeRenderedCount: markerEligibleIncidents.filter((item) => String(item?.status || "").toLowerCase() !== "cleared").length,
    clearedRenderedCount: markerEligibleIncidents.filter((item) => String(item?.status || "").toLowerCase() === "cleared").length,
    routeRelevantRenderedCount: markerEligibleIncidents.filter((item) => isIncidentRouteRelevant(item, routeHazard)).length,
    lastRenderAt: new Date().toISOString(),
    markerLayerCount: typeof unifiedIncidentLayer?.getLayers === "function" ? unifiedIncidentLayer.getLayers().length : null,
    markersByCategory,
    markersAffectingRoute,
    clusteredMarkerCount: getLiveHazardIncidents().length,
    markerTypesRendered: [...markerTypesRendered],
    routeHighlightedMarkers,
    activeVisualStates: [...activeVisualStates],
    markerRenderFunctionFound: typeof renderUnifiedIncidentMarkers === "function" || typeof renderUnifiedIncidents === "function",
    markerSourceCount: Array.isArray(incidents) ? incidents.length : 0,
    markerSourceSample: (Array.isArray(incidents) ? incidents : []).slice(0, 3).map((item) => ({
      id: item?.id || item?.report_id || item?.key || null,
      type: item?.report_type || item?.type || null,
      lat: getIncidentCoordinate(item).lat ?? null,
      lng: getIncidentCoordinate(item).lng ?? null
    })),
    markerRenderSkipReasons,
    markerSourceUsed,
    lastMarkerRenderAt: new Date().toISOString(),
    lastMarkerRenderSourceCounts: sourceCounts,
    lastMarkerRenderResult: {
      reason,
      selectedSourceName: markerSourceUsed,
      selectedSourceCount: incidents.length,
      renderedMarkerCount: typeof unifiedIncidentLayer?.getLayers === "function" ? unifiedIncidentLayer.getLayers().length : 0
    }
  };
  renderGridlyCommunityPulse({ reason: `renderUnifiedIncidents:${reason}` });
}

function renderUnifiedIncidentMarkers() {
  return renderUnifiedIncidents();
}


if (typeof window !== "undefined") {
  window.gridlyRenderUnifiedIncidentsNow = () => renderUnifiedIncidents("manual-debug");
}

function scheduleHazardMarkerAutoRender(source = "unspecified") {
  const renderFn = typeof renderUnifiedIncidents === "function"
    ? renderUnifiedIncidents
    : (typeof renderUnifiedIncidentMarkers === "function" ? renderUnifiedIncidentMarkers : null);
  if (typeof renderFn !== "function") return;
  renderFn();
  setTimeout(() => {
    if (typeof renderFn === "function") renderFn();
  }, 500);
  setTimeout(() => {
    if (typeof renderFn === "function") renderFn();
  }, 1500);
}

function getCategoryMarkerGlyph(category, incident) {
  if (incident?.status === "cleared" || incident?.report_type === "hazard_cleared") return "✓";
  const glyphMap = {
    rail_blockage_delay: "⟂",
    delay: "◔",
    flooding: "≈",
    crash: "✶",
    construction: "▧",
    road_closed: "⛔",
    disabled_vehicle: "◌",
    traffic_backup: "◍",
    other_hazard: "•"
  };
  return glyphMap[category] || "•";
}

function buildHazardPopup(incident) {
  const hazard = incident.latestReport;
  const isFresh = hazard.minutesAgo <= REPORT_EXPIRATION_MINUTES;
  const reportedAgo = humanizeMinutesAgo(hazard.minutesAgo);
  const driverLabel = `${incident.count} driver${incident.count === 1 ? "" : "s"}`;
  const reportStateLabel = isFresh ? "Live community report" : "Needs new confirmation";
  const reportedLabel = isFresh
    ? `Reported ${reportedAgo} by ${driverLabel}.`
    : `Last reported ${reportedAgo} by ${driverLabel}.`;
  const stateNote = isFresh
    ? "Drivers can confirm if this hazard is still active."
    : "This may no longer be active.";
  const actionButtons = isFresh
    ? `
        <button class="popup-report-btn warning" data-action="confirm-hazard" data-hazard-type="${sanitizeText(hazard.type)}" data-lat="${hazard.lat}" data-lng="${hazard.lng}">Still There</button>
        <button class="popup-report-btn blue" data-action="clear-hazard" data-hazard-type="${sanitizeText(hazard.type)}" data-lat="${hazard.lat}" data-lng="${hazard.lng}">Cleared</button>
      `
    : `
        <button class="popup-report-btn warning" data-action="confirm-hazard" data-hazard-type="${sanitizeText(hazard.type)}" data-lat="${hazard.lat}" data-lng="${hazard.lng}">Confirm Now</button>
      `
    ;

  return `
    <div class="gridly-popup">
      <strong>${sanitizeText(isFresh ? hazard.title : "Crash Report")}</strong>
      <span>${sanitizeText(reportStateLabel)}</span><br />
      <span>${sanitizeText(reportedLabel)}</span><br />
      <span>${sanitizeText(stateNote)}</span><br />

      <div class="popup-report-grid">
        ${actionButtons}
        <button class="popup-report-btn neutral" data-action="zoom-hazard" data-lat="${hazard.lat}" data-lng="${hazard.lng}">View Area</button>
      </div>
    </div>
  `;
}

function humanizeMinutesAgo(totalMinutes) {
  const minutes = Math.max(0, Number(totalMinutes) || 0);

  if (minutes <= 1) return "just now";
  if (minutes < 60) return `${minutes}m ago`;

  const roundedHours = Math.round(minutes / 60);
  if (roundedHours < 24) return `${roundedHours}h ago`;

  const roundedDays = Math.round(roundedHours / 24);
  return `${roundedDays}d ago`;
}
function gridlyRoadClearedCoordinateKey(hazard = {}) {
  const lat = Number(hazard?.lat ?? hazard?.latitude ?? hazard?.rawLat);
  const lng = Number(hazard?.lng ?? hazard?.lon ?? hazard?.longitude ?? hazard?.rawLng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  return `${lat.toFixed(3)}-${lng.toFixed(3)}`;
}

function gridlyIsRoadClearedHazardRecord(hazard = {}) {
  return String(hazard?.type || hazard?.report_type || "").toLowerCase() === "hazard_cleared";
}

function gridlyInferRoadClearedHazardType(hazard = {}) {
  const explicitType = String(hazard?.clearedHazardType || hazard?.originalHazardType || hazard?.hazardType || hazard?.hazard_type || "").trim().toLowerCase();
  if (explicitType && explicitType !== "hazard_cleared") return gridlyNormalizeHazardType({ type: explicitType });

  const recordType = String(hazard?.type || hazard?.report_type || "").trim().toLowerCase();
  if (recordType && recordType !== "hazard_cleared") return gridlyNormalizeHazardType({ type: recordType });

  const text = [hazard?.detail, hazard?.title, hazard?.crossingName, hazard?.crossing_name, hazard?.label]
    .map((value) => String(value || "").toLowerCase())
    .join(" ");
  const normalizedText = text.replace(/[^a-z0-9]+/g, " ").trim();
  for (const [type, copy] of Object.entries(HAZARD_TYPES || {})) {
    if (type === "rail_blockage_delay" || type === "rail_issue") continue;
    const typeText = String(type || "").replace(/_/g, " ");
    const labelText = String(copy?.label || "").toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
    const labelLead = labelText.split(" ")[0] || "";
    if ((typeText && normalizedText.includes(typeText)) || (labelText && normalizedText.includes(labelText)) || (labelLead && labelLead.length >= 4 && normalizedText.includes(labelLead))) {
      return gridlyNormalizeHazardType({ type });
    }
  }
  return "other_hazard";
}

function gridlyRoadHazardLifecycleMatchType(hazard = {}) {
  return gridlyIsRoadClearedHazardRecord(hazard) ? gridlyInferRoadClearedHazardType(hazard) : gridlyNormalizeHazardType(hazard);
}

function gridlyRoadHazardIncidentKey(hazard = {}) {
  const value = hazard?.incidentKey || hazard?.incident_key || hazard?.incidentId || hazard?.incident_id || hazard?.groupKey || hazard?.group_key || hazard?.clusterId || hazard?.cluster_id;
  const text = String(value || "").trim();
  return text ? `incident:${text.toLowerCase()}` : "";
}

function gridlyRoadHazardRoundedCoordinateKey(hazard = {}, decimals = GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS) {
  const coordinate = gridlyRoadClusterCoordinateFromRecord(hazard);
  const lat = Number(coordinate?.lat ?? hazard?.lat ?? hazard?.latitude ?? hazard?.rawLat);
  const lng = Number(coordinate?.lng ?? hazard?.lng ?? hazard?.lon ?? hazard?.longitude ?? hazard?.rawLng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return "";
  const safeDecimals = Number.isFinite(Number(decimals)) ? Number(decimals) : GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS;
  return `${lat.toFixed(safeDecimals)}-${lng.toFixed(safeDecimals)}`;
}

function gridlyRoadHazardLifecycleMatchKeys(hazard = {}) {
  const keys = new Set();
  const incidentKey = gridlyRoadHazardIncidentKey(hazard);
  if (incidentKey) keys.add(incidentKey);

  const sourceReportId = String(hazard?.sourceReportId || hazard?.source_report_id || hazard?.reportId || hazard?.report_id || hazard?.raw?.id || hazard?.raw?.report_id || hazard?.latestReport?.id || "").trim();
  if (sourceReportId) keys.add(`sourcereport:${sourceReportId.toLowerCase()}`);

  const id = String(hazard?.id || hazard?.raw?.id || "").trim();
  if (id) keys.add(`id:${id.toLowerCase()}`);

  const hazardType = gridlyRoadHazardLifecycleMatchType(hazard);
  const explicitRoadCluster = String(hazard?.roadClusterKey || hazard?.road_cluster_key || hazard?.clusterKey || hazard?.cluster_key || "").trim();
  if (explicitRoadCluster) keys.add(`roadcluster:${explicitRoadCluster.toLowerCase()}`);

  const coordinateKey = gridlyRoadHazardRoundedCoordinateKey(hazard, GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS);
  if (coordinateKey) {
    keys.add(`roadcluster:${hazardType}-${coordinateKey}`);
    keys.add(`coordtype:${hazardType}-${coordinateKey}`);
  }

  const previousCoordinateKey = gridlyRoadHazardRoundedCoordinateKey(hazard, GRIDLY_ROAD_CLUSTER_PREVIOUS_ROUNDING_DECIMALS);
  if (previousCoordinateKey) keys.add(`coordtype:${hazardType}-${previousCoordinateKey}`);

  return [...keys];
}

function gridlyBuildRoadHazardLifecycleIndex(hazards = activeHazards) {
  const index = new Map();
  gridlyDiagnosticArray(hazards).forEach((hazard) => {
    if (!hazard || hazard?.expired) return;
    const type = String(hazard?.type || hazard?.report_type || "").toLowerCase();
    const isRoadHazard = hazard?.reportKind === "hazard" || type === "hazard_cleared" || Object.prototype.hasOwnProperty.call(HAZARD_TYPES, type);
    if (!isRoadHazard) return;
    const eventTime = gridlyRoadClusterReportTimeMs(hazard);
    if (!Number.isFinite(eventTime) || eventTime <= 0) return;
    const state = gridlyIsRoadClearedHazardRecord(hazard) ? "cleared" : "active";
    gridlyRoadHazardLifecycleMatchKeys(hazard).forEach((key) => {
      const previous = index.get(key);
      const previousTime = Number(previous?.eventTime) || 0;
      if (!previous || eventTime > previousTime || (eventTime === previousTime && state === "cleared")) {
        index.set(key, { hazard, state, eventTime, key });
      }
    });
  });
  return index;
}

function gridlyFindNewestMatchingRoadHazardLifecycleEntry(hazard = {}, hazards = activeHazards, stateFilter = null) {
  const keys = gridlyRoadHazardLifecycleMatchKeys(hazard);
  if (!keys.length) return null;
  const lifecycleIndex = gridlyBuildRoadHazardLifecycleIndex(hazards);
  const states = Array.isArray(stateFilter)
    ? new Set(stateFilter.map((state) => String(state || "").toLowerCase()))
    : (stateFilter ? new Set([String(stateFilter).toLowerCase()]) : null);
  return keys
    .map((key) => lifecycleIndex.get(key))
    .filter((entry) => entry && (!states || states.has(String(entry.state || "").toLowerCase())))
    .sort((a, b) => Number(b.eventTime || 0) - Number(a.eventTime || 0))[0] || null;
}

function gridlyRoadHazardLatestLifecycleState(hazard = {}, hazards = activeHazards) {
  const eventTime = gridlyRoadClusterReportTimeMs(hazard);
  const isClear = gridlyIsRoadClearedHazardRecord(hazard);
  const latest = gridlyFindNewestMatchingRoadHazardLifecycleEntry(hazard, hazards);
  if (!latest) return isClear ? "cleared" : "active";
  if (isClear) {
    const newerActive = gridlyFindNewestMatchingRoadHazardLifecycleEntry(hazard, hazards, "active");
    const activeTime = Number(newerActive?.eventTime || 0);
    return Number.isFinite(eventTime) && eventTime > 0 && Number.isFinite(activeTime) && activeTime > eventTime ? "active" : "cleared";
  }
  const latestClear = gridlyFindNewestMatchingRoadHazardLifecycleEntry(hazard, hazards, "cleared");
  const clearTime = Number(latestClear?.eventTime || 0);
  return Number.isFinite(eventTime) && eventTime > 0 && Number.isFinite(clearTime) && clearTime > eventTime ? "cleared" : "active";
}

function gridlyRoadClearSupersededByNewerActive(hazard = {}, hazards = activeHazards) {
  if (!gridlyIsRoadClearedHazardRecord(hazard)) return false;
  const clearTime = gridlyRoadClusterReportTimeMs(hazard);
  const newerActive = gridlyFindNewestMatchingRoadHazardLifecycleEntry(hazard, hazards, "active");
  const activeTime = Number(newerActive?.eventTime || 0);
  return Number.isFinite(clearTime) && clearTime > 0 && Number.isFinite(activeTime) && activeTime > clearTime;
}

function gridlyRoadClearedAgeMinutes(hazard = {}, nowMs = Date.now()) {
  const submittedAtMs = new Date(hazard?.submittedAt || hazard?.created_at || hazard?.createdAt || hazard?.updated_at || 0).getTime();
  if (!Number.isFinite(submittedAtMs) || submittedAtMs <= 0 || submittedAtMs > nowMs) return null;
  return Math.max(0, Math.floor((nowMs - submittedAtMs) / 60000));
}

function gridlyIsRecentlyClearedRoadHazardRecord(hazard = {}, nowMs = Date.now()) {
  if (!gridlyIsRoadClearedHazardRecord(hazard)) return false;
  const ageMinutes = gridlyRoadClearedAgeMinutes(hazard, nowMs);
  return Number.isFinite(Number(ageMinutes)) && Number(ageMinutes) <= RECENTLY_CLEARED_WINDOW_MINUTES;
}

function gridlyBuildRecentRoadClearIndex(hazards = activeHazards, nowMs = Date.now()) {
  return gridlyDiagnosticArray(hazards).reduce((acc, hazard) => {
    if (!gridlyIsRecentlyClearedRoadHazardRecord(hazard, nowMs)) return acc;
    const hazardTime = gridlyRoadClusterReportTimeMs(hazard);
    gridlyRoadHazardLifecycleMatchKeys(hazard).forEach((key) => {
      const previous = acc.get(key);
      const previousTime = gridlyRoadClusterReportTimeMs(previous);
      if (!previous || hazardTime >= previousTime) acc.set(key, hazard);
    });
    return acc;
  }, new Map());
}

function gridlyRoadHazardClearMatchReason(hazard = {}, clear = {}) {
  const hazardKeys = new Set(gridlyRoadHazardLifecycleMatchKeys(hazard));
  const matchedKey = gridlyRoadHazardLifecycleMatchKeys(clear).find((key) => hazardKeys.has(key));
  if (matchedKey) return matchedKey;
  const hazardType = gridlyRoadHazardLifecycleMatchType(hazard);
  const clearType = gridlyRoadHazardLifecycleMatchType(clear);
  const hazardRoad = normalizeGridlyAwarenessAreaLookupText(gridlyRoadClusterRoadName(hazard));
  const clearRoad = normalizeGridlyAwarenessAreaLookupText(gridlyRoadClusterRoadName(clear));
  const hazardTime = gridlyRoadClusterReportTimeMs(hazard);
  const clearTime = gridlyRoadClusterReportTimeMs(clear);
  const proximityMs = Math.abs(Number(clearTime || 0) - Number(hazardTime || 0));
  if (hazardType === clearType && hazardRoad && clearRoad && hazardRoad === clearRoad && Number.isFinite(proximityMs) && proximityMs <= 12 * 60 * 60 * 1000) {
    return `roadtypeproximity:${hazardType}:${hazardRoad}`;
  }
  return "";
}

function gridlyFindRecentClearForRoadHazard(hazard = {}, hazards = activeHazards, recentClearIndex = gridlyBuildRecentRoadClearIndex(hazards), nowMs = Date.now()) {
  if (!hazard || gridlyIsRoadClearedHazardRecord(hazard)) return null;
  const directClear = gridlyRoadHazardLifecycleMatchKeys(hazard)
    .map((key) => recentClearIndex.get(key))
    .filter((clear) => clear && gridlyIsRecentlyClearedRoadHazardRecord(clear, nowMs))
    .sort((a, b) => gridlyRoadClusterReportTimeMs(b) - gridlyRoadClusterReportTimeMs(a))[0] || null;
  if (directClear) return directClear;
  return gridlyDiagnosticArray(hazards)
    .filter((clear) => gridlyIsRecentlyClearedRoadHazardRecord(clear, nowMs) && gridlyRoadHazardClearMatchReason(hazard, clear))
    .sort((a, b) => gridlyRoadClusterReportTimeMs(b) - gridlyRoadClusterReportTimeMs(a))[0] || null;
}

function gridlySummarizeRehydrationSuppression(hazard = {}, clear = {}, source = "activeHazards", nowMs = Date.now()) {
  const hazardCoord = gridlyCoordinateFromRecord(hazard);
  const clearCoord = gridlyCoordinateFromRecord(clear);
  return {
    source,
    id: hazard?.id || hazard?.report_id || hazard?.reportId || null,
    sourceReportId: hazard?.sourceReportId || hazard?.source_report_id || hazard?.reportId || hazard?.report_id || hazard?.raw?.id || null,
    type: hazard?.type || hazard?.report_type || null,
    matchedClearId: clear?.id || clear?.report_id || clear?.reportId || null,
    matchedClearType: clear?.clearedHazardType || clear?.hazardType || clear?.type || clear?.report_type || null,
    matchReason: gridlyRoadHazardClearMatchReason(hazard, clear),
    hazardCreatedAt: hazard?.submittedAt || hazard?.created_at || hazard?.createdAt || null,
    clearCreatedAt: clear?.submittedAt || clear?.created_at || clear?.createdAt || null,
    hazardAgeMinutes: gridlyRoadClusterReportAgeMinutes(hazard, nowMs),
    clearAgeMinutes: gridlyRoadClusterReportAgeMinutes(clear, nowMs),
    hazardCoordinate: hazardCoord ? { lat: Number(hazardCoord.lat), lng: Number(hazardCoord.lng) } : null,
    clearCoordinate: clearCoord ? { lat: Number(clearCoord.lat), lng: Number(clearCoord.lng) } : null,
    roadName: gridlyRoadClusterRoadName(hazard)
  };
}

function gridlyRoadHazardSuppressedByRecentClear(hazard = {}, recentClearIndex = gridlyBuildRecentRoadClearIndex(), nowMs = Date.now(), sourceHazards = activeHazards) {
  return Boolean(gridlyFindRecentClearForRoadHazard(hazard, sourceHazards, recentClearIndex, nowMs));
}

function gridlyHasRecentlyClearedLifecycleState(hazard = {}, nowMs = Date.now()) {
  const explicitState = String(hazard?.lifecycleState || hazard?.lifecycle || hazard?.status || hazard?.state || "").trim().toLowerCase();
  if (["recently_cleared", "cleared", "expired", "inactive", "historical", "stale"].includes(explicitState)) return true;
  return gridlyIsRecentlyClearedRoadHazardRecord(hazard, nowMs);
}

function gridlyIsActiveRoadHazardIncidentSource(hazard = {}, sourceHazards = activeHazards, recentClearIndex = gridlyBuildRecentRoadClearIndex(sourceHazards), nowMs = Date.now()) {
  if (!hazard || hazard?.expired) return false;
  if (gridlyIsRoadClearedHazardRecord(hazard) || gridlyHasRecentlyClearedLifecycleState(hazard, nowMs)) return false;
  if (getIncidentLifecycleState(hazard, nowMs) !== "active") return false;
  if (typeof gridlyClassifyHazardLifecycle === "function") {
    const resolved = gridlyClassifyHazardLifecycle(hazard, { nowMs });
    if (resolved?.lifecycleState && !["ACTIVE", "NEEDS_CONFIRMATION", "CONFIRMED"].includes(resolved.lifecycleState)) return false;
  }
  if (typeof gridlyRoadHazardLatestLifecycleState === "function" && gridlyRoadHazardLatestLifecycleState(hazard, sourceHazards) === "cleared") return false;
  return !gridlyRoadHazardSuppressedByRecentClear(hazard, recentClearIndex, nowMs, sourceHazards);
}

function gridlyFilterRecentlyClearedRoadHazardsForVisibility(hazards = activeHazards, nowMs = Date.now()) {
  const sourceHazards = gridlyDiagnosticArray(hazards);
  return sourceHazards.filter((hazard) => gridlyIsRecentlyClearedRoadHazardRecord(hazard, nowMs));
}

function gridlyFilterRoadHazardsByLatestLifecycle(hazards = activeHazards, nowMs = Date.now()) {
  const sourceHazards = gridlyDiagnosticArray(hazards);
  const recentClearIndex = gridlyBuildRecentRoadClearIndex(sourceHazards, nowMs);
  const suppressedRecords = [];
  const active = sourceHazards.filter((hazard) => {
    const matchingClear = gridlyFindRecentClearForRoadHazard(hazard, sourceHazards, recentClearIndex, nowMs);
    if (matchingClear && !gridlyIsRoadClearedHazardRecord(hazard)) {
      suppressedRecords.push(gridlySummarizeRehydrationSuppression(hazard, matchingClear, "gridlyFilterRoadHazardsByLatestLifecycle", nowMs));
      return false;
    }
    return gridlyIsActiveRoadHazardIncidentSource(hazard, sourceHazards, recentClearIndex, nowMs);
  });
  gridlyClearedHazardRehydrationGuardState = {
    suppressedRecords,
    lastUpdatedAt: new Date(nowMs).toISOString()
  };
  return active;
}

function gridlyBuildRoadHazardIncidentsFromReports(hazards = activeHazards, options = {}) {
  const grouped = new Map();
  const cleared = options?.cleared === true;
  const nowMs = Number.isFinite(Number(options?.nowMs)) ? Number(options.nowMs) : Date.now();
  const sourceHazards = gridlyDiagnosticArray(hazards);
  const recentClearIndex = gridlyBuildRecentRoadClearIndex(sourceHazards, nowMs);

  sourceHazards
    .filter((hazard) => cleared
      ? gridlyIsRecentlyClearedRoadHazardRecord(hazard, nowMs) && !gridlyRoadClearSupersededByNewerActive(hazard, sourceHazards)
      : gridlyIsActiveRoadHazardIncidentSource(hazard, sourceHazards, recentClearIndex, nowMs))
    .forEach((hazard) => {
      const key = cleared
        ? `hazard_cleared-${gridlyRoadHazardLifecycleMatchType(hazard)}-${gridlyRoadClearedCoordinateKey(hazard) || gridlyRoadHazardRoundedCoordinateKey(hazard) || getHazardClusterKey(hazard)}`
        : getHazardClusterKey(hazard);

      if (!grouped.has(key)) {
        grouped.set(key, {
          key,
          reports: []
        });
      }

      grouped.get(key).reports.push(hazard);
    });

  return [...grouped.values()]
    .map((incident) => {
      const sorted = incident.reports.sort(
        (a, b) => new Date(b.submittedAt) - new Date(a.submittedAt)
      );

      return {
        key: incident.key,
        count: sorted.length,
        latestReport: sorted[0],
        reports: sorted,
        representativeCoordinateReason: sorted.length > 1
          ? "latest_report_coordinate_within_tight_0.0001_degree_hazard_cluster"
          : "single_report_coordinate",
        oldestMinutes: Math.max(...sorted.map((r) => r.minutesAgo)),
        newestMinutes: Math.min(...sorted.map((r) => r.minutesAgo))
      };
    })
    .sort((a, b) => b.count - a.count || a.newestMinutes - b.newestMinutes);
}

function getRecentlyClearedRoadHazardIncidents() {
  return gridlyBuildRoadHazardIncidentsFromReports(recentlyClearedRoadHazards, { cleared: true });
}

function getLiveHazardIncidents() {
  return gridlyBuildRoadHazardIncidentsFromReports([...gridlyDiagnosticArray(activeHazards), ...gridlyDiagnosticArray(recentlyClearedRoadHazards)]);
}

const GRIDLY_ROAD_CLUSTER_PREVIOUS_ROUNDING_DECIMALS = 3;
const GRIDLY_ROAD_CLUSTER_PREVIOUS_PRECISION_DEGREES = 0.001;
const GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS = 4;
const GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES = 0.0001;
const GRIDLY_ROAD_CLUSTER_METHOD = "type_plus_tight_0.0001_degree_coordinate_bucket";

function getHazardClusterKey(hazard) {
  const rawLat = hazard?.lat ?? hazard?.latitude ?? hazard?.rawLat;
  const rawLng = hazard?.lng ?? hazard?.lon ?? hazard?.longitude ?? hazard?.rawLng;
  const latNum = Number(rawLat);
  const lngNum = Number(rawLng);
  const lat = Number.isFinite(latNum) ? latNum.toFixed(GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS) : "na";
  const lng = Number.isFinite(lngNum) ? lngNum.toFixed(GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS) : "na";
  return `${hazard?.type || "hazard"}-${lat}-${lng}`;
}

function gridlyRoadClusterCoordinateFromRecord(record = {}) {
  return gridlyCoordinateFromRecord(record)
    || gridlyCoordinateFromRecord(record?.finalPlacementCoordinate)
    || gridlyCoordinateFromRecord(record?.storedReportCoordinate)
    || gridlyCoordinateFromRecord(record?.activeHazardCoordinate)
    || null;
}

function gridlyRoadClusterRoundedCoordinateFromKey(clusterKey = "") {
  const match = String(clusterKey || "").match(/(-?\d+\.\d+)-(-?\d+\.\d+)$/);
  if (!match) return null;
  const lat = Number(match[1]);
  const lng = Number(match[2]);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  return { lat, lng };
}

function gridlyEstimateRoadClusterRadiusMeters(latitude = LOCATION_DEFAULTS?.center?.[0] || 30, precisionDegrees = GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES) {
  const lat = Number.isFinite(Number(latitude)) ? Number(latitude) : 30;
  const precision = Number.isFinite(Number(precisionDegrees)) ? Number(precisionDegrees) : GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES;
  const latMeters = precision * 111320;
  const lngMeters = precision * 111320 * Math.cos(lat * Math.PI / 180);
  return Math.round(Math.sqrt((latMeters ** 2) + (lngMeters ** 2)) * 10) / 10;
}

function gridlyRoadClusterReportId(record = {}) {
  return String(record?.id || record?.report_id || record?.reportId || record?.incidentId || "").trim();
}

function gridlyRoadClusterReportTimeMs(record = {}) {
  const value = record?.submittedAt || record?.created_at || record?.createdAt || record?.updated_at || record?.updatedAt || 0;
  const ms = new Date(value).getTime();
  return Number.isFinite(ms) ? ms : 0;
}

function gridlyRoadClusterReportAgeMinutes(record = {}, nowMs = Date.now()) {
  const ms = gridlyRoadClusterReportTimeMs(record);
  if (!ms || ms > nowMs) return null;
  return Math.max(0, Math.round((nowMs - ms) / 60000));
}

function gridlyRoadClusterRoadName(record = {}) {
  return String(record?.roadName || record?.road_name || record?.street || record?.nearest_road || record?.location_name || record?.area || "Unknown road").trim() || "Unknown road";
}

function gridlyRoadClusterRoadSide(record = {}) {
  const text = [
    record?.roadSide,
    record?.road_side,
    record?.direction,
    record?.bearing,
    record?.laneDirection,
    record?.lane_direction,
    record?.description,
    record?.detail,
    record?.title,
    record?.roadName,
    record?.road_name
  ].map((value) => String(value || "").toLowerCase()).join(" ");
  if (/\b(northbound|north bound|nb)\b/.test(text)) return "northbound";
  if (/\b(southbound|south bound|sb)\b/.test(text)) return "southbound";
  if (/\b(eastbound|east bound|eb)\b/.test(text)) return "eastbound";
  if (/\b(westbound|west bound|wb)\b/.test(text)) return "westbound";
  if (/\b(left shoulder|inside shoulder|median)\b/.test(text)) return "inside_or_median";
  if (/\b(right shoulder|outside shoulder)\b/.test(text)) return "outside_shoulder";
  return "unknown";
}

function gridlyRoadClusterConfidenceRank(record = {}) {
  const text = String(record?.confidence || record?.source || "").toLowerCase();
  if (/official|txdot|moderator|trusted|system/.test(text)) return 3;
  if (/community|verified|confirm/.test(text)) return 2;
  return 1;
}

function gridlyClassifyRoadClusterHighZoomRisk(details = {}) {
  const maxDistance = Number(details.maxClusterDistanceMeters || 0);
  if (details.containsClearedReports || details.containsMultipleRoadSides || details.containsDividedRoadName || maxDistance >= 75) return "high";
  if (details.containsMultipleRoadNames || details.containsMultipleReportTypes || maxDistance >= 25 || Number(details.clusterMemberCount || 0) > 1) return "medium";
  return "low";
}

function gridlyBuildRoadClusterAudit(options = {}) {
  const nowMs = Number.isFinite(Number(options?.nowMs)) ? Number(options.nowMs) : Date.now();
  const sampleLimit = Math.max(1, Math.min(50, Number(options?.sampleLimit) || 12));
  const sourceHazards = Array.isArray(options?.hazards) ? options.hazards : [...gridlyDiagnosticArray(activeHazards), ...gridlyDiagnosticArray(recentlyClearedRoadHazards)];
  const sourceReports = Array.isArray(options?.reports) ? options.reports : gridlyDiagnosticArray(activeReports);
  const unifiedIncidents = Array.isArray(options?.unifiedIncidents)
    ? options.unifiedIncidents
    : (typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : []);
  const liveHazardIncidents = Array.isArray(options?.liveHazardIncidents)
    ? options.liveHazardIncidents
    : (typeof getLiveHazardIncidents === "function" ? getLiveHazardIncidents() : []);
  const renderedAudits = typeof unifiedIncidentLayer?.getLayers === "function"
    ? unifiedIncidentLayer.getLayers().map((layer) => {
      const audit = layer?.options?.gridlyPlacementAudit || {};
      const latLng = typeof layer?.getLatLng === "function" ? layer.getLatLng() : null;
      return { ...audit, incidentId: audit?.incidentId || layer?.options?.incidentId || "", renderedMarkerCoordinate: gridlyCoordinateFromRecord(latLng) || audit?.renderedMarkerCoordinate || null };
    })
    : [];
  const reportById = new Map(sourceReports.map((report) => [gridlyRoadClusterReportId(report), report]).filter(([id]) => id));
  const latitudeForEstimate = sourceHazards.map((hazard) => Number(gridlyRoadClusterCoordinateFromRecord(hazard)?.lat)).find(Number.isFinite) || LOCATION_DEFAULTS?.center?.[0] || 30;
  const estimatedClusterRadiusMeters = gridlyEstimateRoadClusterRadiusMeters(latitudeForEstimate);
  const previousEstimatedClusterRadiusMeters = gridlyEstimateRoadClusterRadiusMeters(latitudeForEstimate, GRIDLY_ROAD_CLUSTER_PREVIOUS_PRECISION_DEGREES);

  const sampleClusters = liveHazardIncidents.slice(0, sampleLimit).map((incident) => {
    const reports = Array.isArray(incident?.reports) ? incident.reports : sourceHazards.filter((hazard) => getHazardClusterKey(hazard) === incident?.key);
    const sortedReports = [...reports].sort((a, b) => gridlyRoadClusterReportTimeMs(b) - gridlyRoadClusterReportTimeMs(a));
    const representative = incident?.latestReport || sortedReports[0] || null;
    const representativeCoordinate = gridlyRoadClusterCoordinateFromRecord(representative);
    const clusterCoordinate = gridlyRoadClusterRoundedCoordinateFromKey(incident?.key);
    const roadIncidentId = `road-${incident?.key || "unknown"}`;
    const unified = unifiedIncidents.find((item) => String(item?.id || "") === roadIncidentId) || null;
    const rendered = renderedAudits.find((audit) => String(audit?.incidentId || "") === roadIncidentId) || gridlyFindRenderedMarkerPlacementAudit(roadIncidentId);
    const reportTypes = [...new Set(reports.map((report) => String(report?.type || report?.report_type || "unknown").toLowerCase()))];
    const roadNames = [...new Set(reports.map(gridlyRoadClusterRoadName).filter(Boolean))];
    const roadSides = [...new Set(reports.map(gridlyRoadClusterRoadSide).filter((side) => side && side !== "unknown"))];
    const containsClearedReports = reports.some(gridlyIsRoadClearedHazardRecord);
    const containsMultipleRoadNames = roadNames.length > 1;
    const containsMultipleRoadSides = roadSides.length > 1;
    const containsMultipleReportTypes = reportTypes.length > 1;
    const containsDividedRoadName = roadNames.some((name) => /\b(us\s*90|u\.?s\.?\s*90|tx\s*146|sh\s*146|state\s*highway\s*146|highway\s*146)\b/i.test(name));
    const distancesToRepresentative = reports.map((report) => gridlyCoordinateDeltaMeters(gridlyRoadClusterCoordinateFromRecord(report), representativeCoordinate)).filter((distance) => Number.isFinite(Number(distance)));
    const maxClusterDistanceMeters = distancesToRepresentative.length ? Math.max(...distancesToRepresentative) : 0;
    const highestConfidenceRank = Math.max(...reports.map(gridlyRoadClusterConfidenceRank), 0);
    const representativeRank = gridlyRoadClusterConfidenceRank(representative);
    const newestReport = sortedReports[0] || null;
    const representativeReportId = gridlyRoadClusterReportId(representative);
    const highZoomPlacementRisk = gridlyClassifyRoadClusterHighZoomRisk({
      clusterMemberCount: reports.length,
      maxClusterDistanceMeters,
      maxMemberDistanceMeters: maxClusterDistanceMeters,
      dividedRoadRisk: containsDividedRoadName || containsMultipleRoadSides || maxClusterDistanceMeters >= previousEstimatedClusterRadiusMeters * 0.25 ? "elevated" : "reduced",
      carriagewayRisk: containsMultipleRoadSides || maxClusterDistanceMeters >= 25 ? "elevated" : "reduced",
      containsClearedReports,
      containsMultipleRoadSides,
      containsMultipleRoadNames,
      containsMultipleReportTypes,
      containsDividedRoadName
    });

    const clusterMembers = reports.map((report) => {
      const reportId = gridlyRoadClusterReportId(report);
      const originalReport = reportById.get(reportId) || null;
      const originalReportCoordinate = gridlyRoadClusterCoordinateFromRecord(originalReport) || gridlyCoordinateFromRecord(report?.rawTapCoordinate || report?.reportCaptureCoordinate) || gridlyRoadClusterCoordinateFromRecord(report);
      const activeHazardCoordinate = gridlyRoadClusterCoordinateFromRecord(report);
      const distanceToRepresentativeMeters = gridlyCoordinateDeltaMeters(activeHazardCoordinate, representativeCoordinate);
      return {
        reportId: reportId || null,
        reportType: report?.type || report?.report_type || null,
        source: report?.source || null,
        confidence: report?.confidence || null,
        ageMinutes: gridlyRoadClusterReportAgeMinutes(report, nowMs),
        isCleared: gridlyIsRoadClearedHazardRecord(report),
        roadName: gridlyRoadClusterRoadName(report),
        roadSide: gridlyRoadClusterRoadSide(report),
        originalReportCoordinate,
        activeHazardCoordinate,
        clusterCoordinate,
        representativeCoordinate,
        unifiedIncidentCoordinate: gridlyRoadClusterCoordinateFromRecord(unified),
        renderedCoordinate: gridlyRoadClusterCoordinateFromRecord(rendered?.renderedMarkerCoordinate),
        distanceToRepresentativeMeters,
        clusterKey: incident?.key || null,
        trace: {
          report: originalReportCoordinate,
          activeHazards: activeHazardCoordinate,
          roadClustering: clusterCoordinate,
          representativeSelection: representativeCoordinate,
          unifiedIncidents: gridlyRoadClusterCoordinateFromRecord(unified),
          renderedMarker: gridlyRoadClusterCoordinateFromRecord(rendered?.renderedMarkerCoordinate)
        }
      };
    });

    return {
      clusterKey: incident?.key || null,
      clusterMemberCount: reports.length,
      clusterCoordinate,
      clusterMembers,
      representativeCoordinate,
      representativeCoordinateReason: incident?.representativeCoordinateReason || (reports.length > 1 ? "latest_report_coordinate_within_tight_0.0001_degree_hazard_cluster" : "single_report_coordinate"),
      representativeReportId: representativeReportId || null,
      representativeReportAge: gridlyRoadClusterReportAgeMinutes(representative, nowMs),
      representativeReportType: representative?.type || representative?.report_type || null,
      representativeIsNewestReport: representativeReportId && newestReport ? representativeReportId === gridlyRoadClusterReportId(newestReport) : null,
      representativeIsHighestConfidenceReport: representative ? representativeRank >= highestConfidenceRank : null,
      distanceToRepresentativeMeters: clusterMembers.map((member) => ({ reportId: member.reportId, meters: member.distanceToRepresentativeMeters })),
      maxClusterDistanceMeters,
      maxMemberDistanceMeters: maxClusterDistanceMeters,
      dividedRoadRisk: containsDividedRoadName || containsMultipleRoadSides || maxClusterDistanceMeters >= previousEstimatedClusterRadiusMeters * 0.25 ? "elevated" : "reduced",
      carriagewayRisk: containsMultipleRoadSides || maxClusterDistanceMeters >= 25 ? "elevated" : "reduced",
      containsClearedReports,
      containsMultipleRoadSides,
      containsMultipleRoadNames,
      containsMultipleReportTypes,
      containsDividedRoadName,
      roadNames,
      roadSides,
      reportTypes,
      unifiedIncidentCoordinate: gridlyRoadClusterCoordinateFromRecord(unified),
      renderedCoordinate: gridlyRoadClusterCoordinateFromRecord(rendered?.renderedMarkerCoordinate),
      highZoomPlacementRisk,
      highZoomPlacementRiskReasons: [
        containsDividedRoadName ? "known_divided_highway_name" : "",
        containsMultipleRoadSides ? "multiple_detected_road_sides" : "",
        containsClearedReports ? "cleared_report_in_cluster" : "",
        maxClusterDistanceMeters >= 75 ? "representative_far_from_member" : "",
        containsMultipleRoadNames ? "multiple_road_names" : "",
        containsMultipleReportTypes ? "multiple_report_types" : ""
      ].filter(Boolean)
    };
  });

  const highRiskClusters = sampleClusters.filter((cluster) => cluster.highZoomPlacementRisk === "high").length;
  const mediumRiskClusters = sampleClusters.filter((cluster) => cluster.highZoomPlacementRisk === "medium").length;
  const clusteredSamples = sampleClusters.filter((cluster) => cluster.clusterMemberCount > 1);
  const largestClusterMemberCount = sampleClusters.reduce((max, cluster) => Math.max(max, Number(cluster.clusterMemberCount || 0)), 0);
  const largestMaxMemberDistanceMeters = sampleClusters.reduce((max, cluster) => Math.max(max, Number(cluster.maxMemberDistanceMeters || cluster.maxClusterDistanceMeters || 0)), 0);
  const dividedRoadRisk = sampleClusters.some((cluster) => cluster.dividedRoadRisk === "elevated") ? "elevated_in_sample" : "reduced_by_tight_coordinate_bucket";
  const carriagewayRisk = sampleClusters.some((cluster) => cluster.carriagewayRisk === "elevated") ? "elevated_in_sample" : "reduced_by_tight_coordinate_bucket";

  return {
    clusteringEnabled: true,
    clusterPrecision: GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES,
    clusterMethod: GRIDLY_ROAD_CLUSTER_METHOD,
    clusterRoundingPrecision: GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES,
    clusterRoundingDecimals: GRIDLY_ROAD_CLUSTER_ROUNDING_DECIMALS,
    estimatedClusterRadiusMeters,
    previousClusterPrecision: GRIDLY_ROAD_CLUSTER_PREVIOUS_PRECISION_DEGREES,
    previousEstimatedClusterRadiusMeters,
    preChangeClusterRisk: "high: the former 0.001-degree bucket could span roughly " + previousEstimatedClusterRadiusMeters + "m diagonally near the sampled latitude, so opposite sides of divided roads or separate carriageways could share one key.",
    postChangeClusterRisk: "lower: active road hazards now use a 0.0001-degree bucket with an estimated diagonal of roughly " + estimatedClusterRadiusMeters + "m; duplicate reports at the same spot can still merge, while broad cross-road merges are less likely.",
    clusterMemberCount: largestClusterMemberCount,
    maxMemberDistanceMeters: largestMaxMemberDistanceMeters,
    representativeCoordinateReason: clusteredSamples.length ? "latest_report_coordinate_within_tight_0.0001_degree_hazard_cluster" : "single_report_coordinate_or_no_clustered_samples",
    dividedRoadRisk,
    carriagewayRisk,
    clusterKeyGeneration: "`${type}-${lat.toFixed(4)}-${lng.toFixed(4)}` for active road hazards; recently cleared rows continue to use `hazard_cleared-${coordinateKey}` and remain separated from active clusters.",
    distanceGrouping: "Option A selected for beta: a tighter 0.0001-degree coordinate bucket. It avoids broad 0.001-degree merges without adding a new road-geometry dependency or changing rail behavior.",
    representativeSelectionRules: "Each tight cluster sorts reports by submittedAt descending; the latest report remains the representative because the tighter bucket bounds representative drift to a small duplicate-report area.",
    suppressionRules: "Expired hazards and non-recent hazard_cleared rows are excluded. Active hazards sharing a cleared coordinate key are suppressed only when a recent clear is actually newer than the hazard.",
    dedupeRules: "renderUnifiedIncidents dedupes by unified incident id first; road clusters normally render one marker per road-${clusterKey} incident.",
    clearedHazardInteraction: "Recently cleared road rows are included as separate cleared clusters keyed by cleared coordinate; they do not become representatives for active clusters unless their type/key is explicitly the cleared cluster.",
    reviewedOptions: {
      optionA: "Selected: 0.0001 precision is the smallest beta-ready change and directly fixes broad rounded-cell clustering.",
      optionB: "Deferred: distance-based clustering would improve bucket-boundary behavior but adds more membership logic and tuning risk.",
      optionC: "Deferred: road-aware clustering needs reliable carriageway/side geometry that is not currently part of the report payload.",
      optionD: "Deferred: hybrid road/distance logic is likely best long term, but it is more complex than needed for this precision fix."
    },
    primaryQuestions: {
      whenRoadClusteringOccurs: "getLiveHazardIncidents groups filtered activeHazards before getUnifiedIncidents creates road unified incidents and before renderUnifiedIncidents renders markers.",
      coordinateRoundingUsed: GRIDLY_ROAD_CLUSTER_ROUNDING_PRECISION_DEGREES,
      effectiveClusteringRadiusMeters: estimatedClusterRadiusMeters,
      oppositeSidesCanEnterSameCluster: "Less likely; active road hazards now need matching type and matching 0.0001-degree rounded lat/lng instead of the former broad 0.001-degree cell.",
      separateCarriagewaysCanEnterSameCluster: "Less likely for typical divided carriageway separation; exact same-location duplicates still merge.",
      newerReportCanMoveRepresentativeCoordinate: "Only within the tighter active road hazard bucket; newest remains the representative to preserve existing dedupe behavior.",
      clearedReportCanBecomeRepresentativeCoordinate: "Only for the separate recently-cleared cluster; active hazard clusters filter cleared rows out or suppress matching active rows.",
      representativeAlwaysNewestReport: clusteredSamples.length ? clusteredSamples.every((cluster) => cluster.representativeIsNewestReport === true) : null,
      representativeAlwaysHighestConfidenceReport: clusteredSamples.length ? clusteredSamples.every((cluster) => cluster.representativeIsHighestConfidenceReport === true) : null,
      shouldClusteringDetermineHighZoomPlacement: highRiskClusters > 0 || mediumRiskClusters > 0 ? "Review recommended for sampled elevated-risk clusters, but the active road hazard bucket is now much tighter than the pre-change 0.001-degree key." : "Current samples are low risk under the tighter key."
    },
    dividedRoadReview: {
      routesChecked: ["US 90", "TX 146", "other divided highways inferred from road-side/direction text"],
      sampleMatches: sampleClusters.filter((cluster) => cluster.containsDividedRoadName || cluster.containsMultipleRoadSides),
      conclusion: "The tighter active-road key reduces accidental divided-road and carriageway merges without changing rail clustering, reporting payloads, or historical record validity."
    },
    sampleClusters,
    highZoomRiskSummary: { low: sampleClusters.filter((cluster) => cluster.highZoomPlacementRisk === "low").length, medium: mediumRiskClusters, high: highRiskClusters },
    recommendations: [
      "Use this audit at high zoom on suspected divided roads to compare each member's originalReportCoordinate with the representativeCoordinate and renderedCoordinate.",
      "Expect same-location duplicate reports to merge, but reports on opposite sides of divided roads to split unless their final coordinates are extremely close.",
      "If a sampled cluster still shows elevated dividedRoadRisk or carriagewayRisk, review the report finalPlacementCoordinate values before considering a future distance-based or road-aware clustering pass.",
      "Keep rail reporting, rail markers, TxDOT, and Supabase payload shape out of this road-cluster precision path."
    ]
  };
}

function gridlyRoadClusterAudit(options = {}) {
  const audit = gridlyBuildRoadClusterAudit(options);
  console.info("gridlyRoadClusterAudit", audit);
  return audit;
}

if (typeof window !== "undefined") {
  window.gridlyRoadClusterAudit = gridlyRoadClusterAudit;
}
exposeGridlyAuditHelper("gridlyRoadClusterAudit", gridlyRoadClusterAudit);

function gridlyBuildRoadClearedLifecycleTrace(options = {}) {
  const nowMs = Number.isFinite(Number(options?.nowMs)) ? Number(options.nowMs) : Date.now();
  const sourceHazards = Array.isArray(options?.hazards) ? options.hazards : [...gridlyDiagnosticArray(activeHazards), ...gridlyDiagnosticArray(recentlyClearedRoadHazards)];
  const sourceReports = Array.isArray(options?.reports) ? options.reports : gridlyDiagnosticArray(activeReports);
  const unifiedIncidents = Array.isArray(options?.unifiedIncidents)
    ? options.unifiedIncidents
    : (typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : []);
  const liveHazardIncidents = Array.isArray(options?.liveHazardIncidents)
    ? options.liveHazardIncidents
    : (typeof getLiveHazardIncidents === "function" ? getLiveHazardIncidents() : []);
  const roadClearedRows = sourceHazards.filter(gridlyIsRoadClearedHazardRecord);
  const recentlyClearedRows = roadClearedRows.filter((row) => gridlyIsRecentlyClearedRoadHazardRecord(row, nowMs));
  const clearedUnifiedIncidents = unifiedIncidents.filter((incident) => {
    const status = String(incident?.status || "").toLowerCase();
    const type = String(incident?.report_type || incident?.type || "").toLowerCase();
    return status === "cleared" || type === "hazard_cleared";
  });
  const roadClearedUnifiedIncidents = clearedUnifiedIncidents.filter((incident) => {
    const id = String(incident?.id || "").toLowerCase();
    const source = String(incident?.source || "").toLowerCase();
    const reportType = String(incident?.report_type || "").toLowerCase();
    return reportType === "hazard_cleared" || (id.startsWith("road-") && !/rail|txdot/.test(source));
  });
  const alertEligibleRows = roadClearedUnifiedIncidents.filter((incident) => String(incident?.status || "").toLowerCase() === "active");
  const historicalEligibleRows = roadClearedRows.filter((row, index) => gridlyClassifyHazardLifecycleFrameworkRecord({
    record: row,
    sourceKind: "activeHazards",
    index,
    sourceHazards,
    sourceReports,
    nowMs
  }).historicalEligible);
  const recentClearIndex = gridlyBuildRecentRoadClearIndex(sourceHazards, nowMs);
  const suppressedActiveHazards = sourceHazards.filter((row) => gridlyRoadHazardSuppressedByRecentClear(row, recentClearIndex, nowMs));
  const scenarioTypes = ["flooding", "road_closed", "crash", "debris", "disabled_vehicle", "traffic_backup"];
  return {
    roadClearedLifecycleTrace: {
      sourcePath: [
        "recentlyClearedRoadHazards receives normalized hazard_cleared rows from loadSharedReports() recent-clear read",
        "getLiveHazardIncidents() excludes hazard_cleared and recently_cleared rows from active generated road incidents",
        "getUnifiedIncidents() emits cleared-only road incidents from recentlyClearedRoadHazards when the clear is the latest credible lifecycle event",
        "Alerts keep cleared unified incidents out of active eligibility; Recently Cleared may still read cleared rows by age_minutes",
        "gridlyHazardLifecycleFramework/gridlyHistoricalIntelligenceAudit mark cleared road rows historical-eligible without active treatment"
      ],
      sourceCounts: {
        activeHazards: sourceHazards.length,
        activeReports: sourceReports.length,
        roadClearedRows: roadClearedRows.length,
        recentlyClearedRows: recentlyClearedRows.length,
        liveHazardIncidents: liveHazardIncidents.length,
        roadClearedUnifiedIncidents: roadClearedUnifiedIncidents.length,
        suppressedActiveHazardsAtClearedLocations: suppressedActiveHazards.length
      },
      sampleTraces: scenarioTypes.map((type) => ({
        hazardType: type,
        lifecycle: ["Reported", "Cleared", `Recently Cleared <= ${RECENTLY_CLEARED_WINDOW_MINUTES} minutes`, "Historical Intelligence eligible"],
        activeHazardTreatment: "stops after a newer hazard_cleared row at the same rounded road location",
        routeImpactTreatment: "cleared unified incident is informational, not active route-impacting"
      })),
      detectedRows: roadClearedRows.slice(0, 6).map((row) => ({
        id: row?.id || null,
        type: row?.type || row?.report_type || null,
        ageMinutes: gridlyRoadClearedAgeMinutes(row, nowMs),
        recentlyCleared: gridlyIsRecentlyClearedRoadHazardRecord(row, nowMs),
        coordinateKey: gridlyRoadClearedCoordinateKey(row),
        historicalEligible: gridlyClassifyHazardLifecycleFrameworkRecord({ record: row, sourceKind: "activeHazards", sourceHazards, sourceReports, nowMs }).historicalEligible
      }))
    },
    roadClearedWriteDetected: roadClearedRows.length > 0,
    roadClearedUnifiedIncidentDetected: roadClearedUnifiedIncidents.length > 0,
    roadClearedAlertEligible: alertEligibleRows.length > 0,
    roadClearedHistoricalEligible: historicalEligibleRows.length > 0,
    recentlyClearedVisibilityWindow: RECENTLY_CLEARED_WINDOW_MINUTES,
    roadClearedFilteringFindings: [
      "Previous active-alert eligibility could count cleared unified road incidents inside the recent-clear window.",
      "Current getLiveHazardIncidents() only returns active lifecycle rows; latest recently cleared road rows are kept separately for Recently Cleared and suppress older active rows by incident key, road cluster, or rounded coordinate plus hazard type.",
      "Expired hazard_cleared rows can still be loaded by the recent-clear read path for the visibility window, without changing Supabase writes.",
      "Rail cleared paths are not modified by this road-only lifecycle trace."
    ],
    recommendedLifecyclePath: "Reported road hazard -> hazard_cleared row -> cleared unified road incident -> Recently Cleared for 90 minutes -> Historical Intelligence eligible; never active once cleared."
  };
}



function gridlyReadCachedTxdotRows() {
  if (typeof window === "undefined") return [];
  const serviceRows = typeof window.gridlyTxdot?.getRoadConditions === "function"
    ? window.gridlyTxdot.getRoadConditions()
    : null;
  if (Array.isArray(serviceRows)) return serviceRows;
  return Array.isArray(window.gridlyExternalRoadConditions) ? window.gridlyExternalRoadConditions : [];
}

function gridlyTxdotRowHasFiniteCoordinates(row = {}) {
  const lat = Number(row?.lat ?? row?.latitude ?? row?.rawLat);
  const lng = Number(row?.lng ?? row?.lon ?? row?.longitude ?? row?.rawLng);
  return Number.isFinite(lat) && Number.isFinite(lng);
}

function gridlyTxdotIsConstructionRow(row = {}) {
  const text = [
    row?.source,
    row?.sourceType,
    row?.type,
    row?.category,
    row?.condition,
    row?.title,
    row?.headline,
    row?.description,
    row?.summary
  ].map((value) => String(value || "").toLowerCase()).join(" ");
  return /construct|maintenance|lane closure|work zone|road work|utility work/.test(text);
}

function gridlyBuildTxdotUnifiedIncident(row = {}, options = {}) {
  const lat = Number(row?.lat ?? row?.latitude ?? row?.rawLat);
  const lng = Number(row?.lng ?? row?.lon ?? row?.longitude ?? row?.rawLng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;

  const isConstruction = Boolean(options.construction);
  const rawId = String(row?.id || row?.incidentId || row?.reportId || row?.GLOBALID || `${lat.toFixed(5)}-${lng.toFixed(5)}`).trim();
  const idPrefix = isConstruction ? "txdot-construction" : "txdot";
  const safeRawId = rawId.replace(/^txdot-construction-/i, "").replace(/^txdot-/i, "") || `${lat.toFixed(5)}-${lng.toFixed(5)}`;
  const roadName = safeDisplayText(row?.roadName || row?.routeNameDisplay || row?.routeName || row?.roadway, "Roadway");
  const rowTitle = safeDisplayText(row?.title || row?.headline, "");
  const condition = safeDisplayText(row?.type || row?.category || row?.condition, isConstruction ? "construction" : "incident");
  const category = isConstruction ? "construction" : normalizeGridlyTxdotVisualCategory(condition, { ...row, source: "txdot" });
  const title = rowTitle || `TxDOT ${condition} on ${roadName}`;
  const description = safeDisplayText(row?.description || row?.summary || row?.detail, title);
  const createdAt = row?.createdAt || row?.created_at || row?.startTime || row?.start_time || row?.reportedAt || null;
  const updatedAt = row?.updatedAt || row?.updated_at || row?.lastUpdated || row?.last_updated || createdAt || new Date(0).toISOString();
  const expiresAt = row?.expiresAt || row?.expires_at || row?.endTime || row?.end_time || null;

  return normalizeUnifiedIncident({
    id: `${idPrefix}-${safeRawId}`,
    source: "txdot",
    sourceType: "txdot",
    externalSource: "txdot",
    provider: "TxDOT",
    type: category,
    category,
    severity: getGridlyIncidentSeverity({ ...row, source: "txdot", description, title }, category),
    status: "active",
    title,
    headline: title,
    description,
    summary: description,
    lat,
    lng,
    latitude: lat,
    longitude: lng,
    roadName,
    area: roadName,
    routeName: row?.routeName || null,
    routeNameDisplay: row?.routeNameDisplay || null,
    direction: row?.direction || null,
    createdAt,
    updatedAt,
    expiresAt,
    endTime: row?.endTime || row?.end_time || expiresAt,
    created_at: createdAt || updatedAt,
    updated_at: updatedAt,
    expires_at: expiresAt,
    confidence: row?.confidence || "official",
    reports_count: 1,
    report_type: category,
    isExternal: true,
    isTxdot: true,
    rawTxdotId: row?.id || null
  });
}

function gridlyBuildTxdotUnifiedRows(options = {}) {
  const wantConstruction = Boolean(options.construction);
  return gridlyReadCachedTxdotRows()
    .filter((row) => row && String(row?.source || "").toLowerCase().includes("txdot"))
    .filter((row) => gridlyTxdotRowHasFiniteCoordinates(row))
    .filter((row) => gridlyTxdotIsConstructionRow(row) === wantConstruction)
    .map((row) => gridlyBuildTxdotUnifiedIncident(row, { construction: wantConstruction }))
    .filter(Boolean);
}

function futureTxdotIncidents() { return gridlyBuildTxdotUnifiedRows({ construction: false }); }
function futureTxdotConstruction() { return gridlyBuildTxdotUnifiedRows({ construction: true }); }
function futureFloodAlerts() { return []; }


function gridlyTxdotLayerAudit() {
  const toArray = (value) => Array.isArray(value) ? value : [];
  const toText = (value) => String(value || "").trim();
  const toLowerText = (value) => toText(value).toLowerCase();
  const numberOrNull = (value) => {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  };
  const getLatLng = (item = {}) => {
    const lat = numberOrNull(item?.lat ?? item?.latitude ?? item?.rawLat);
    const lng = numberOrNull(item?.lng ?? item?.lon ?? item?.longitude ?? item?.rawLng);
    return { lat, lng, hasCoordinates: Number.isFinite(lat) && Number.isFinite(lng) };
  };
  const getTxdotId = (item = {}) => toText(item?.rawTxdotId || item?.id || item?.incidentId || item?.reportId || item?.GLOBALID);
  const isTxdotLike = (item = {}) => {
    const haystack = [item?.source, item?.sourceType, item?.externalSource, item?.provider, item?.id, item?.rawTxdotId, item?.title, item?.headline]
      .map(toLowerText)
      .join(" ");
    return /txdot|drive texas|drivetexas/.test(haystack);
  };
  const getTypeText = (item = {}) => [item?.type, item?.category, item?.condition, item?.report_type, item?.title, item?.description]
    .map(toLowerText)
    .join(" ");
  const isConstruction = (item = {}) => gridlyTxdotIsConstructionRow(item) || /txdot_construction|\bconstruction\b|maintenance|lane closure|work zone|road work|utility work/.test(getTypeText(item));
  const getTimestampMs = (item = {}) => {
    const candidate = item?.updated_at || item?.updatedAt || item?.created_at || item?.createdAt || item?.startTime || item?.start_time || item?.reportedAt;
    const parsed = candidate ? new Date(candidate).getTime() : Number.NaN;
    return Number.isFinite(parsed) ? parsed : null;
  };
  const getEndTimestampMs = (item = {}) => {
    const candidate = item?.expires_at || item?.expiresAt || item?.endTime || item?.end_time;
    const parsed = candidate ? new Date(candidate).getTime() : Number.NaN;
    return Number.isFinite(parsed) ? parsed : null;
  };
  const isDateFiltered = (item = {}) => {
    const endMs = getEndTimestampMs(item);
    if (!Number.isFinite(endMs)) return false;
    return endMs < Date.now();
  };
  const mapBounds = map && typeof map.getBounds === "function" ? map.getBounds() : null;
  const isInBounds = (item = {}) => {
    const { lat, lng, hasCoordinates } = getLatLng(item);
    if (!hasCoordinates || !mapBounds || typeof mapBounds.contains !== "function") return null;
    return Boolean(mapBounds.contains([lat, lng]));
  };
  const getVisibleDomTxdotMarkers = () => {
    if (typeof document === "undefined") return [];
    const markerNodes = Array.from(document.querySelectorAll([
      "#map .leaflet-marker-pane .gridly-hazard-marker",
      "#map .leaflet-marker-pane [data-visual-style^='txdot_']",
      "#map .gridly-marker-txdot-single",
      "#map .gridly-marker-txdot-corridor",
      "#map .gridly-marker-txdot-route-impact"
    ].join(", ")));
    const seen = new Set();
    return markerNodes.filter((node) => {
      if (!node || seen.has(node)) return false;
      seen.add(node);
      const style = toLowerText(node.dataset?.visualStyle);
      const className = toLowerText(node.className);
      const source = toLowerText(node.dataset?.incidentSource || node.closest?.(".leaflet-marker-icon")?.dataset?.incidentSource);
      const id = toLowerText(node.dataset?.incidentId || node.dataset?.id || node.closest?.(".leaflet-marker-icon")?.dataset?.incidentId);
      return style.startsWith("txdot_") || className.includes("txdot") || source.includes("txdot") || id.includes("txdot");
    }).filter((node) => {
      const iconNode = node.closest?.(".leaflet-marker-icon") || node;
      const style = typeof window !== "undefined" && window.getComputedStyle ? window.getComputedStyle(iconNode) : null;
      const rect = iconNode.getBoundingClientRect?.();
      return !style || (style.display !== "none" && style.visibility !== "hidden" && Number(style.opacity || 1) !== 0 && (!rect || (rect.width > 0 && rect.height > 0)));
    });
  };
  const rawRows = typeof window !== "undefined" && typeof window.gridlyTxdot?.getRawRoadConditions === "function"
    ? window.gridlyTxdot.getRawRoadConditions()
    : toArray(window?.gridlyTxdotRawRoadConditions);
  const normalizedRows = gridlyReadCachedTxdotRows().filter(isTxdotLike);
  const unifiedRows = (typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : []).filter(isTxdotLike);
  const activeUnifiedRows = unifiedRows.filter((incident) => toLowerText(incident?.status || "active") === "active");
  const normalizedIds = new Set(normalizedRows.map(getTxdotId).filter(Boolean));
  const unifiedIds = new Set(unifiedRows.map(getTxdotId).filter(Boolean));
  const normalizedWithoutCoordinates = normalizedRows.filter((row) => !getLatLng(row).hasCoordinates);
  const normalizedOutsideBounds = normalizedRows.filter((row) => getLatLng(row).hasCoordinates && isInBounds(row) === false);
  const normalizedSourceFiltered = gridlyReadCachedTxdotRows().filter((row) => row && !isTxdotLike(row));
  const unifiedStatusFiltered = unifiedRows.filter((row) => toLowerText(row?.status || "active") !== "active");
  const unifiedDateFiltered = unifiedRows.filter(isDateFiltered);
  const unifiedVisualStates = unifiedRows.map((incident) => ({ incident, visualState: getGridlyIncidentVisualState(incident) }));
  const markerCandidates = unifiedVisualStates.filter(({ incident, visualState }) => {
    const { hasCoordinates } = getLatLng(incident);
    return hasCoordinates && toLowerText(incident?.status || "active") === "active" && !isDateFiltered(incident) && visualState?.shouldRender !== false;
  });
  const markerFilteredByVisualState = unifiedVisualStates.filter(({ incident, visualState }) => getLatLng(incident).hasCoordinates && visualState?.shouldRender === false);
  const renderedLayerMarkers = (unifiedIncidentLayer && typeof unifiedIncidentLayer.getLayers === "function")
    ? unifiedIncidentLayer.getLayers().filter((layer) => isTxdotLike({
        source: layer?.options?.incidentSource,
        id: layer?.options?.incidentId,
        rawTxdotId: layer?.options?.incidentId
      }))
    : [];
  const visibleDomTxdotMarkers = getVisibleDomTxdotMarkers();
  const latestAlerts = toArray(window?.__gridlyLatestAlertsForRender);
  const alertCandidates = activeUnifiedRows.filter((incident) => {
    const { hasCoordinates } = getLatLng(incident);
    return hasCoordinates && !isDateFiltered(incident);
  });
  const alertRendered = latestAlerts.filter(isTxdotLike);
  const skippedByFilterBreakdown = {
    source: normalizedSourceFiltered.length,
    type: normalizedRows.filter((row) => !GRIDLY_NORMALIZED_INCIDENT_CATEGORIES.has(normalizeGridlyIncidentCategory({ ...row, source: "txdot" }))).length,
    status: unifiedStatusFiltered.length,
    date: unifiedDateFiltered.length,
    visualShouldRenderFalse: markerFilteredByVisualState.length,
    notInUnified: normalizedRows.filter((row) => {
      const id = getTxdotId(row);
      return id && !unifiedIds.has(id) && !unifiedIds.has(`txdot-${id}`) && !unifiedIds.has(`txdot-construction-${id}`);
    }).length
  };
  const blockers = [];
  if (!rawRows.length) blockers.push("No TxDOT raw rows are cached. Run await window.gridlyTxdot?.fetchRoadConditions?.() first and confirm the API key/fetch succeeds.");
  if (rawRows.length && !normalizedRows.length) blockers.push("TxDOT rows were fetched but no cached normalized rows were found.");
  if (normalizedRows.length && !unifiedRows.length) blockers.push("TxDOT rows are normalized but are not present in getUnifiedIncidents().");
  if (normalizedWithoutCoordinates.length) blockers.push(`${normalizedWithoutCoordinates.length} normalized TxDOT row(s) have no finite coordinates.`);
  if (normalizedOutsideBounds.length) blockers.push(`${normalizedOutsideBounds.length} normalized TxDOT row(s) are outside the current map bounds.`);
  if (unifiedRows.length && !markerCandidates.length) blockers.push("TxDOT rows are unified, but current visual-state eligibility marks every TxDOT marker as non-renderable.");
  if (markerFilteredByVisualState.length) blockers.push(`${markerFilteredByVisualState.length} unified TxDOT row(s) have visualState.shouldRender === false.`);
  if (markerCandidates.length && !renderedLayerMarkers.length && !visibleDomTxdotMarkers.length) blockers.push("TxDOT marker candidates exist, but no TxDOT markers are currently rendered in the Leaflet layer/DOM. Manual fetch does not trigger marker rerender.");
  if (renderedLayerMarkers.length && !visibleDomTxdotMarkers.length) blockers.push("TxDOT markers exist in the Leaflet layer but are not visible in the marker DOM.");
  if (alertCandidates.length && !alertRendered.length) blockers.push("TxDOT alert candidates exist, but no TxDOT rows are present in __gridlyLatestAlertsForRender.");
  const nextPatchRecommendation = !rawRows.length
    ? "Run the manual TxDOT fetch, then rerun this audit."
    : (!normalizedRows.length
      ? "Patch TxDOT normalization/cache handoff before touching rendering."
      : (!unifiedRows.length
        ? "Patch getUnifiedIncidents()/futureTxdotIncidents handoff so cached TxDOT rows become unified incidents."
        : (!markerCandidates.length
          ? "Patch TxDOT marker eligibility deliberately; current visual-state policy sets TxDOT shouldRender=false."
          : (!renderedLayerMarkers.length && !visibleDomTxdotMarkers.length
            ? "Patch a manual, non-startup rerender path after explicit TxDOT fetch; do not add startup fetches, polling, or activeHazards forcing."
            : (alertCandidates.length && !alertRendered.length
              ? "Patch the alert candidate-to-render pipeline for TxDOT without changing startup fetch behavior."
              : "TxDOT reaches the current rendered marker path; inspect visibility, styling, and alert surface separately.")))));

  return {
    txdotFetchedRows: rawRows.length,
    txdotNormalizedRows: normalizedRows.length,
    txdotUnifiedIncidents: unifiedRows.length,
    txdotIncidentCount: unifiedRows.filter((row) => !isConstruction(row)).length,
    txdotConstructionCount: unifiedRows.filter(isConstruction).length,
    markerCandidates: markerCandidates.length,
    markerRenderedCount: Math.max(renderedLayerMarkers.length, visibleDomTxdotMarkers.length),
    alertCandidates: alertCandidates.length,
    alertRenderedCount: alertRendered.length,
    skippedNoCoordinates: normalizedWithoutCoordinates.length,
    skippedByBounds: normalizedOutsideBounds.length,
    skippedByFilters: skippedByFilterBreakdown.source + skippedByFilterBreakdown.type + skippedByFilterBreakdown.status + skippedByFilterBreakdown.date + skippedByFilterBreakdown.visualShouldRenderFalse + skippedByFilterBreakdown.notInUnified,
    visibleTxdotMarkerSamples: visibleDomTxdotMarkers.slice(0, 5).map((node) => ({
      incidentId: node.dataset?.incidentId || node.closest?.(".leaflet-marker-icon")?.dataset?.incidentId || "",
      visualStyle: node.dataset?.visualStyle || "",
      lat: numberOrNull(node.dataset?.lat),
      lng: numberOrNull(node.dataset?.lng),
      className: toText(node.className).slice(0, 160)
    })),
    unifiedTxdotSamples: unifiedRows.slice(0, 5).map((incident) => {
      const { lat, lng, hasCoordinates } = getLatLng(incident);
      const visualState = getGridlyIncidentVisualState(incident);
      return {
        id: incident?.id || null,
        rawTxdotId: incident?.rawTxdotId || null,
        type: incident?.type || incident?.category || null,
        status: incident?.status || null,
        lat,
        lng,
        hasCoordinates,
        inBounds: isInBounds(incident),
        shouldRender: visualState?.shouldRender,
        markerStyle: visualState?.markerStyle,
        updatedAt: incident?.updated_at || incident?.updatedAt || null,
        expiresAt: incident?.expires_at || incident?.expiresAt || incident?.endTime || null
      };
    }),
    blockers,
    nextPatchRecommendation,
    details: {
      skippedByFilterBreakdown,
      activeUnifiedTxdotCount: activeUnifiedRows.length,
      markerLayerTxdotCount: renderedLayerMarkers.length,
      visibleDomTxdotCount: visibleDomTxdotMarkers.length,
      mapBoundsAvailable: Boolean(mapBounds),
      normalizedTxdotIdsMissingFromUnified: normalizedRows.filter((row) => {
        const id = getTxdotId(row);
        return id && !unifiedIds.has(id) && !unifiedIds.has(`txdot-${id}`) && !unifiedIds.has(`txdot-construction-${id}`);
      }).slice(0, 10).map(getTxdotId),
      normalizedTxdotIdsPresent: normalizedRows.filter((row) => normalizedIds.has(getTxdotId(row))).slice(0, 10).map(getTxdotId)
    }
  };
}

function gridlyRunTxdotLayerAudit() {
  const target = typeof window !== "undefined" ? window : globalThis;
  console.log("Gridly TxDOT layer audit started");

  const auditPromise = Promise.resolve()
    .then(async () => {
      const txdotService = target?.gridlyTxdot || null;
      if (!txdotService || typeof txdotService.fetchRoadConditions !== "function") {
        throw new Error("Gridly TxDOT layer audit cannot run because window.gridlyTxdot.fetchRoadConditions is unavailable.");
      }

      await txdotService.fetchRoadConditions();

      const auditFn = typeof target?.gridlyTxdotLayerAudit === "function"
        ? target.gridlyTxdotLayerAudit
        : (typeof gridlyTxdotLayerAudit === "function" ? gridlyTxdotLayerAudit : null);
      if (typeof auditFn !== "function") {
        throw new Error("Gridly TxDOT layer audit cannot run because window.gridlyTxdotLayerAudit is unavailable.");
      }

      const auditResult = auditFn();
      target.gridlyLastTxdotLayerAudit = auditResult;
      console.log(auditResult);
      return auditResult;
    })
    .catch((error) => {
      const auditError = {
        error: true,
        message: error instanceof Error ? error.message : String(error),
        timestamp: new Date().toISOString()
      };
      target.gridlyLastTxdotLayerAudit = auditError;
      console.error("Gridly TxDOT layer audit failed", error);
      console.log(auditError);
      return auditError;
    });

  return auditPromise;
}

if (typeof window !== "undefined") {
  window.gridlyTxdotLayerAudit = gridlyTxdotLayerAudit;
  window.gridlyLastTxdotLayerAudit = window.gridlyLastTxdotLayerAudit || null;
  window.gridlyRunTxdotLayerAudit = gridlyRunTxdotLayerAudit;
}

exposeGridlyAuditHelper("gridlyTxdotLayerAudit", gridlyTxdotLayerAudit);
exposeGridlyAuditHelper("gridlyRunTxdotLayerAudit", gridlyRunTxdotLayerAudit);

function mapRailReportType(type) {
  if (type === "blocked") return "rail_blocked";
  if (type === "heavy") return "rail_delay";
  if (type === "cleared") return "rail_cleared";
  return "rail_delay";
}

function mapRoadHazardType(type) {
  const map = { crash: "wreck", flooding: "flooding",
  ice: "ice", construction: "construction", debris: "debris", road_closed: "closure", disabled_vehicle: "disabled_vehicle", traffic_backup: "traffic_backup", hazard_cleared: "cleared" };
  return map[type] || "debris";
}

function normalizeUnifiedIncident(base) {
  return { ...base, updated_at: base.updated_at || base.created_at, confidence: base.confidence || "community", reports_count: Number(base.reports_count || 1) };
}


function gridlyCoordinateFromRecord(record = {}) {
  const lat = Number(record?.lat ?? record?.latitude ?? record?.rawLat);
  const lng = Number(record?.lng ?? record?.lon ?? record?.longitude ?? record?.rawLng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  return { lat, lng };
}

function gridlyCoordinateDeltaMeters(a, b) {
  if (!a || !b) return null;
  const lat1 = Number(a.lat);
  const lng1 = Number(a.lng);
  const lat2 = Number(b.lat);
  const lng2 = Number(b.lng);
  if (![lat1, lng1, lat2, lng2].every(Number.isFinite)) return null;
  const earthRadiusMeters = 6371000;
  const toRad = (value) => value * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const h = Math.sin(dLat / 2) ** 2
    + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  return Math.round(earthRadiusMeters * 2 * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h)) * 10) / 10;
}

function gridlyCoordinatesWithinMeters(a, b, toleranceMeters = 0.5) {
  const deltaMeters = gridlyCoordinateDeltaMeters(a, b);
  return Number.isFinite(Number(deltaMeters)) && Number(deltaMeters) <= toleranceMeters;
}

function gridlyLatestRoadIncidentForPlacementTrace() {
  const roadIncidents = typeof getUnifiedIncidents === "function"
    ? getUnifiedIncidents().filter((incident) => String(incident?.id || "").startsWith("road-"))
    : [];
  return roadIncidents
    .slice()
    .sort((a, b) => new Date(b?.created_at || b?.updated_at || 0).getTime() - new Date(a?.created_at || a?.updated_at || 0).getTime())[0] || null;
}

function gridlyClassifyPlacementSource({ tapCoordinate, projectionCoordinate, snappedCoordinate, finalPlacementCoordinate, placementMode }) {
  if (projectionCoordinate && gridlyCoordinatesWithinMeters(finalPlacementCoordinate, projectionCoordinate)) return "projected_point";
  if (snappedCoordinate && gridlyCoordinatesWithinMeters(finalPlacementCoordinate, snappedCoordinate)) return "snapped_point";
  if (tapCoordinate && gridlyCoordinatesWithinMeters(finalPlacementCoordinate, tapCoordinate)) return "raw_tap";
  if (["raw_tap", "raw_tap_preserved_user_intent", "tap_preserved_near_road", "snap_rejected_divided_road_risk", "snap_rejected_too_far", "raw_tap_no_candidate", "raw_tap_projection_missing", "raw_tap_snap_too_far", "raw_tap_divided_road_ambiguous"].includes(placementMode)) return "raw_tap";
  if (placementMode === "projected_point_used") return "projected_point";
  if (placementMode === "road_snapped") return projectionCoordinate ? "projected_point" : "snapped_point";
  return "unknown";
}

function gridlyFindRenderedMarkerPlacementAudit(incidentId) {
  const layers = typeof unifiedIncidentLayer?.getLayers === "function" ? unifiedIncidentLayer.getLayers() : [];
  const targetId = String(incidentId || "");
  for (const layer of layers) {
    const audit = layer?.options?.gridlyPlacementAudit || null;
    const layerIncidentId = String(audit?.incidentId || layer?.options?.incidentId || "");
    if (targetId && layerIncidentId && layerIncidentId !== targetId) continue;
    const latLng = typeof layer?.getLatLng === "function" ? layer.getLatLng() : null;
    const renderedMarkerCoordinate = gridlyCoordinateFromRecord(latLng) || audit?.renderedMarkerCoordinate || null;
    return { ...(audit || {}), renderedMarkerCoordinate };
  }
  return null;
}


function gridlyRoadwayAuditNormalizeText(value) {
  return String(value ?? "").trim();
}

function gridlyRoadwayAuditLower(value) {
  return gridlyRoadwayAuditNormalizeText(value).toLowerCase();
}

function gridlyRoadwayAuditFeatureNameValues(feature) {
  const props = feature?.properties || {};
  return [
    props.name,
    props.ref,
    props.highway,
    props.route,
    props.route_name,
    props.routeName,
    props.alt_name,
    props.official_name,
    props["tiger:name_base"],
    props["tiger:name_base_1"],
    props["tiger:name_base_2"],
    props["tiger:name_base_3"]
  ].map(gridlyRoadwayAuditNormalizeText).filter(Boolean);
}

function gridlyRoadwayAuditFeatureText(feature) {
  const props = feature?.properties || {};
  return gridlyRoadwayAuditLower([...gridlyRoadwayAuditFeatureNameValues(feature), props["@id"]].join(" | "));
}

function gridlyRoadwayAuditMatchesCorridor(feature, corridorKey) {
  const text = gridlyRoadwayAuditFeatureText(feature);
  if (corridorKey === "us90") return /\b(us\s*90|us-90|u\.?s\.?\s*highway\s*90|united\s+states\s+highway\s+90|highway\s+90)\b/.test(text);
  if (corridorKey === "tx146") return /\b(tx\s*146|tx-146|sh\s*146|state\s+highway\s+146|highway\s+146)\b/.test(text);
  return false;
}

function gridlyRoadwayAuditToArray(value) {
  if (Array.isArray(value)) return value;
  if (value == null) return [];
  if (value?.type === "FeatureCollection" && Array.isArray(value.features)) return value.features;
  if (value && typeof value === "object" && value.type !== "Feature" && !value.geometry) {
    const values = Object.values(value);
    if (values.length && values.every((entry) => entry && typeof entry === "object")) return values;
  }
  return [];
}

function gridlyRoadwayAuditCountValues(values) {
  return values.reduce((counts, value) => {
    const key = gridlyRoadwayAuditNormalizeText(value);
    if (key) counts[key] = (counts[key] || 0) + 1;
    return counts;
  }, {});
}

function gridlyRoadwayAuditRound(value, digits = 3) {
  const number = Number(value);
  if (!Number.isFinite(number)) return null;
  const factor = 10 ** digits;
  return Math.round(number * factor) / factor;
}

function gridlyRoadwayAuditMilesToMeters(value) {
  const number = Number(value);
  return Number.isFinite(number) ? gridlyRoadwayAuditRound(number * 1609.344, 1) : null;
}

function gridlyRoadwayAuditFeatureCenter(feature) {
  const segments = flattenRoadGeometrySegments(feature?.geometry);
  if (!segments.length) return null;
  const points = [];
  segments.forEach((segment) => {
    points.push([segment.startLat, segment.startLng], [segment.endLat, segment.endLng]);
  });
  const totals = points.reduce((acc, point) => ({ lat: acc.lat + point[0], lng: acc.lng + point[1] }), { lat: 0, lng: 0 });
  return { lat: totals.lat / points.length, lng: totals.lng / points.length };
}

function gridlyRoadwayAuditFeatureBearing(feature) {
  const segments = flattenRoadGeometrySegments(feature?.geometry).filter((segment) => {
    return haversineDistance(segment.startLat, segment.startLng, segment.endLat, segment.endLng) > 0.0005;
  });
  if (!segments.length) return null;
  const middle = segments[Math.floor(segments.length / 2)];
  return gridlyRoadBearingDegrees(middle.startLat, middle.startLng, middle.endLat, middle.endLng);
}

function gridlyRoadwayAuditSampleFeature(feature) {
  const props = feature?.properties || {};
  const bearing = gridlyRoadwayAuditFeatureBearing(feature);
  const center = gridlyRoadwayAuditFeatureCenter(feature);
  return {
    id: props["@id"] || props.id || null,
    geometryType: feature?.geometry?.type || null,
    name: props.name || null,
    ref: props.ref || null,
    highway: props.highway || null,
    oneway: props.oneway || null,
    lanes: props.lanes || null,
    lanesForward: props["lanes:forward"] || null,
    lanesBackward: props["lanes:backward"] || null,
    tigerSeparated: props["tiger:separated"] || null,
    placement: props.placement || null,
    bearing,
    inferredDirection: gridlyInferCardinalRoadDirection(bearing),
    center: center ? { lat: gridlyRoadwayAuditRound(center.lat, 6), lng: gridlyRoadwayAuditRound(center.lng, 6) } : null
  };
}

function gridlyRoadwayAuditFieldCandidates(features, patterns) {
  const counts = {};
  features.forEach((feature) => {
    Object.keys(feature?.properties || {}).forEach((field) => {
      if (patterns.some((pattern) => pattern.test(field))) counts[field] = (counts[field] || 0) + 1;
    });
  });
  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .map(([field, count]) => ({ field, count }));
}

function gridlyRoadwayAuditFindParallelCandidates(features, maxPairs = 8) {
  const candidates = [];
  const sampled = features.slice(0, 220);
  for (let i = 0; i < sampled.length; i += 1) {
    const a = sampled[i];
    const centerA = gridlyRoadwayAuditFeatureCenter(a);
    const bearingA = gridlyRoadwayAuditFeatureBearing(a);
    const namesA = new Set(gridlyRoadwayAuditFeatureNameValues(a).map(gridlyRoadwayAuditLower));
    if (!centerA || !Number.isFinite(Number(bearingA)) || !namesA.size) continue;
    for (let j = i + 1; j < sampled.length; j += 1) {
      const b = sampled[j];
      const centerB = gridlyRoadwayAuditFeatureCenter(b);
      const bearingB = gridlyRoadwayAuditFeatureBearing(b);
      if (!centerB || !Number.isFinite(Number(bearingB))) continue;
      const sharedName = gridlyRoadwayAuditFeatureNameValues(b).map(gridlyRoadwayAuditLower).find((name) => namesA.has(name));
      if (!sharedName) continue;
      const distanceMeters = haversineDistance(centerA.lat, centerA.lng, centerB.lat, centerB.lng) * 1609.344;
      const bearingDifference = gridlyBearingDifferenceDegrees(bearingA, bearingB);
      if (distanceMeters >= 8 && distanceMeters <= 90 && Number.isFinite(bearingDifference) && bearingDifference <= 25) {
        candidates.push({
          sharedName,
          distanceMeters: gridlyRoadwayAuditRound(distanceMeters, 1),
          bearingDifferenceDegrees: gridlyRoadwayAuditRound(bearingDifference, 1),
          first: gridlyRoadwayAuditSampleFeature(a),
          second: gridlyRoadwayAuditSampleFeature(b)
        });
      }
    }
  }
  return candidates.sort((a, b) => a.distanceMeters - b.distanceMeters).slice(0, maxPairs);
}

function gridlyRoadwayAuditAssessCorridor(label, corridorKey) {
  const features = Array.isArray(roadwaySegmentFeatures) ? roadwaySegmentFeatures.filter((feature) => gridlyRoadwayAuditMatchesCorridor(feature, corridorKey)) : [];
  const geometryTypeCount = gridlyRoadwayAuditCountValues(features.map((feature) => feature?.geometry?.type));
  const roadNameVariants = gridlyRoadwayAuditCountValues(features.flatMap(gridlyRoadwayAuditFeatureNameValues));
  const bearingSamples = features.map(gridlyRoadwayAuditSampleFeature).filter((sample) => Number.isFinite(Number(sample.bearing))).slice(0, 12);
  const duplicateParallelSegmentCandidates = gridlyRoadwayAuditFindParallelCandidates(features, 8);
  const hasOneWayPairs = features.filter((feature) => gridlyRoadwayAuditLower(feature?.properties?.oneway) === "yes").length >= 2;
  const hasMultiLaneBidirectionalCenterline = features.some((feature) => {
    const props = feature?.properties || {};
    return gridlyRoadwayAuditLower(props.oneway) !== "yes" && (Number(props.lanes) >= 3 || props["lanes:forward"] || props["lanes:backward"] || props["lanes:both_ways"]);
  });
  const separateCarriagewaysAppearPresent = hasOneWayPairs || duplicateParallelSegmentCandidates.length > 0;
  const appearsCenterlineOnly = features.length > 0 && !separateCarriagewaysAppearPresent && hasMultiLaneBidirectionalCenterline;
  const bearingComputable = bearingSamples.length > 0;
  const confidenceLevel = !features.length ? "none" : (separateCarriagewaysAppearPresent && bearingComputable ? "medium" : (bearingComputable ? "low" : "none"));
  const directionalLabelsCanBeInferredSafely = Boolean(separateCarriagewaysAppearPresent && bearingComputable && confidenceLevel !== "low");
  const readiness = !features.length
    ? "no_geometry_loaded"
    : (directionalLabelsCanBeInferredSafely ? "usable_with_caution" : "insufficient_geometry");
  return {
    road: label,
    directionalReadiness: readiness,
    segmentCount: features.length,
    geometryTypeCount,
    roadNameVariants,
    bearingSamples,
    parallelCandidateDistanceMeters: duplicateParallelSegmentCandidates.map((candidate) => candidate.distanceMeters),
    duplicateParallelSegmentCandidates,
    appearsCenterlineOnly,
    separateCarriagewaysAppearPresent,
    directionalLabelsCanBeInferredSafely,
    confidenceLevel,
    assessment: !features.length
      ? "No matching local roadway geometry is loaded for this corridor."
      : (directionalLabelsCanBeInferredSafely
        ? "Local geometry includes computable bearings and probable separate carriageway/parallel candidates, but this remains audit-only without authoritative carriageway direction metadata."
        : "Local geometry can identify the corridor and usually compute bearings, but it is not sufficient to safely publish directional/carriageway labels by itself.")
  };
}

function gridlyRoadwayGeometryCapabilityAudit() {
  const features = Array.isArray(roadwaySegmentFeatures) ? roadwaySegmentFeatures : [];
  const loadedFeatures = roadwayDatasetLoaded ? features : [];
  const geometryTypes = gridlyRoadwayAuditCountValues(loadedFeatures.map((feature) => feature?.geometry?.type));
  const roadNameFieldCandidates = gridlyRoadwayAuditFieldCandidates(loadedFeatures, [/name/i, /^ref$/i, /route/i, /highway/i]);
  const directionFieldCandidates = gridlyRoadwayAuditFieldCandidates(loadedFeatures, [/direction/i, /bearing/i, /heading/i, /forward/i, /backward/i, /prefix/i, /suffix/i]);
  const oneWayFieldCandidates = gridlyRoadwayAuditFieldCandidates(loadedFeatures, [/oneway/i, /one_way/i]);
  const bearingFieldCandidates = gridlyRoadwayAuditFieldCandidates(loadedFeatures, [/bearing/i, /heading/i, /azimuth/i]);
  const carriagewayFieldCandidates = gridlyRoadwayAuditFieldCandidates(loadedFeatures, [/carriage/i, /separat/i, /divider/i, /median/i, /placement/i, /^lanes/i, /turn:lanes/i]);
  const bearingAvailable = bearingFieldCandidates.length > 0;
  const bearingComputable = loadedFeatures.some((feature) => Number.isFinite(Number(gridlyRoadwayAuditFeatureBearing(feature))));
  const carriagewayMetadataAvailable = carriagewayFieldCandidates.some((entry) => /carriage|separat|divider|median|placement/i.test(entry.field));
  const dividedRoadRepresentationAvailable = loadedFeatures.some((feature) => gridlyRoadwayAuditLower(feature?.properties?.oneway) === "yes") || carriagewayMetadataAvailable;
  const sampleRoadSegments = loadedFeatures.slice(0, 10).map(gridlyRoadwayAuditSampleFeature);
  const sampleUs90Segments = loadedFeatures.filter((feature) => gridlyRoadwayAuditMatchesCorridor(feature, "us90")).slice(0, 10).map(gridlyRoadwayAuditSampleFeature);
  const sampleTx146Segments = loadedFeatures.filter((feature) => gridlyRoadwayAuditMatchesCorridor(feature, "tx146")).slice(0, 10).map(gridlyRoadwayAuditSampleFeature);
  const estimatedBearingSamples = loadedFeatures.map(gridlyRoadwayAuditSampleFeature).filter((sample) => Number.isFinite(Number(sample.bearing))).slice(0, 20);
  const us90GeometryAssessment = gridlyRoadwayAuditAssessCorridor("US 90", "us90");
  const tx146GeometryAssessment = gridlyRoadwayAuditAssessCorridor("TX 146", "tx146");
  const duplicateParallelSegmentCandidates = gridlyRoadwayAuditFindParallelCandidates(loadedFeatures, 12);
  const target = typeof window !== "undefined" ? window : globalThis;
  const rawTxdotRows = typeof target?.gridlyTxdot?.getRawRoadConditions === "function" ? target.gridlyTxdot.getRawRoadConditions() : gridlyRoadwayAuditToArray(target?.gridlyTxdotRawRoadConditions);
  const normalizedTxdotRows = typeof gridlyReadCachedTxdotRows === "function" ? gridlyReadCachedTxdotRows() : [];
  const txdotRows = [...gridlyRoadwayAuditToArray(rawTxdotRows), ...gridlyRoadwayAuditToArray(normalizedTxdotRows)];
  const txdotHasGeometry = txdotRows.some((row) => row?.__geometry?.type || row?.geometry?.type);
  const txdotHasLineGeometry = txdotRows.some((row) => [row?.__geometry?.type, row?.geometry?.type].includes("LineString") || [row?.__geometry?.type, row?.geometry?.type].includes("MultiLineString"));
  const txdotHasDirection = txdotRows.some((row) => row?.travel_direction || row?.travelDirection || row?.direction);
  const routeLatLngs = typeof savedRouteLayer?.getLatLngs === "function" ? (savedRouteLayer.getLatLngs() || []) : [];
  const routeGeometryAvailable = Array.isArray(routeLatLngs) && routeLatLngs.length >= 2;
  const localLoaded = Boolean(roadwayDatasetLoaded && loadedFeatures.length);
  const missingData = [];
  if (!localLoaded) missingData.push("local roadway segment geometry not loaded");
  if (!bearingAvailable) missingData.push("authoritative bearing fields on local roadway segments");
  if (!carriagewayMetadataAvailable) missingData.push("explicit carriageway/side-of-road metadata");
  if (!directionFieldCandidates.some((entry) => /direction/i.test(entry.field))) missingData.push("explicit EB/WB/NB/SB direction metadata on local roadway segments");
  if (!txdotHasLineGeometry) missingData.push("retained TxDOT LineString/MultiLineString geometry in normalized incident cache");
  if (!txdotHasDirection) missingData.push("observed/current TxDOT travel_direction values for geometry validation");
  const sourceComparison = {
    localRoadwaySegments: {
      loaded: localLoaded,
      source: ROADWAY_SEGMENTS_URL,
      roadNameSupport: roadNameFieldCandidates.length ? "yes_name_ref_highway_fields" : "missing",
      bearingSupport: bearingComputable ? "computable_from_linestring_coordinates" : "missing",
      directionSupport: directionFieldCandidates.some((entry) => /direction/i.test(entry.field)) ? "limited_name_direction_fields" : "no_explicit_direction",
      carriagewaySupport: dividedRoadRepresentationAvailable ? "partial_oneway_or_separation_tags" : "missing",
      sideOfRoadSupport: carriagewayMetadataAvailable ? "partial_metadata_not_validated" : "insufficient",
      betaUsability: localLoaded && bearingComputable ? "usable_with_caution_for_audit_only" : "insufficient"
    },
    osrmNearestCandidates: {
      loaded: Boolean(lastRoadSnapDebug?.nearestCandidates?.length || lastRoadSnapDebug?.osrmNearestCandidates?.length),
      roadNameSupport: "yes_when_nearest_response_has_name",
      bearingSupport: "not_retained_in_current_nearest_debug_path",
      directionSupport: "missing",
      carriagewaySupport: "missing",
      sideOfRoadSupport: "insufficient_point_snap_only",
      betaUsability: "insufficient_for_directional_labels"
    },
    txdotCachedCurrentGeometry: {
      loaded: txdotRows.length > 0,
      roadNameSupport: txdotRows.some((row) => row?.roadway || row?.roadName || row?.routeName || row?.route_name) ? "yes_when_rows_present" : "unknown_or_missing",
      bearingSupport: txdotHasLineGeometry ? "potential_if_full_geometry_retained" : "discarded_or_midpoint_only_today",
      directionSupport: txdotHasDirection ? "official_direction_present_in_some_rows" : "not_observed_in_current_cache",
      carriagewaySupport: "not_structured_in_current_normalized_cache",
      sideOfRoadSupport: "insufficient_without_retained_line_and_carriageway_metadata",
      betaUsability: txdotHasDirection ? "usable_with_caution_for_official_event_direction_only" : "insufficient"
    },
    routeGeometry: {
      loaded: routeGeometryAvailable,
      roadNameSupport: "missing_route_polyline_has_shape_not_road_names",
      bearingSupport: routeGeometryAvailable ? "computable_for_active_route_path" : "missing_when_no_active_route",
      directionSupport: "route_travel_direction_only_not_road_carriageway_direction",
      carriagewaySupport: "missing",
      sideOfRoadSupport: "insufficient",
      betaUsability: "not_suitable_for_roadway_intelligence_labels"
    }
  };
  const scoreParts = {
    localGeometryLoaded: localLoaded ? 20 : 0,
    lineGeometryPresent: Object.keys(geometryTypes).some((type) => /LineString/.test(type)) ? 20 : 0,
    roadNamesPresent: roadNameFieldCandidates.length ? 15 : 0,
    bearingComputable: bearingComputable ? 20 : 0,
    dividedRepresentationPartial: dividedRoadRepresentationAvailable ? 10 : 0,
    explicitDirectionMetadata: directionFieldCandidates.some((entry) => /direction/i.test(entry.field)) ? 5 : 0,
    carriagewayMetadata: carriagewayMetadataAvailable ? 5 : 0,
    txdotRetainedGeometry: txdotHasLineGeometry ? 5 : 0
  };
  const directionalReadinessScore = Object.values(scoreParts).reduce((sum, value) => sum + value, 0);
  const directionalReadiness = !localLoaded
    ? "no_geometry_loaded"
    : (directionalReadinessScore >= 85 && us90GeometryAssessment.directionalReadiness !== "insufficient_geometry" && tx146GeometryAssessment.directionalReadiness !== "insufficient_geometry"
      ? "ready_high_confidence"
      : (directionalReadinessScore >= 55 ? "usable_with_caution" : "insufficient_geometry"));
  const recommendation = directionalReadiness === "ready_high_confidence"
    ? "Use local roadway geometry only behind conservative validation against explicit direction/carriageway metadata; keep audit-only until live incident labeling is designed."
    : "Do not claim US 90 EB/WB or TX 146 NB/SB production support yet. Next required data is authoritative carriageway-aware roadway geometry with explicit direction/one-way semantics, plus retained TxDOT LineString geometry and travel_direction for validation.";
  const audit = {
    auditVersion: "V206.12-roadway-geometry-capability-audit",
    auditOnly: true,
    destructiveActionsTaken: false,
    geometrySourcesFound: [
      { source: "localRoadwaySegments", url: ROADWAY_SEGMENTS_URL, found: true },
      { source: "osrmNearestCandidates", url: OSRM_NEAREST_API, found: true },
      { source: "txdotCachedCurrentGeometry", found: txdotRows.length > 0 || Boolean(target?.gridlyTxdot) },
      { source: "routeGeometry", found: true }
    ],
    geometrySourcesLoaded: {
      localRoadwaySegments: localLoaded,
      osrmNearestCandidates: Boolean(sourceComparison.osrmNearestCandidates.loaded),
      txdotCachedCurrentGeometry: txdotRows.length > 0,
      routeGeometry: routeGeometryAvailable
    },
    roadSegmentFeatureCount: loadedFeatures.length,
    roadSegmentGeometryTypes: geometryTypes,
    roadNameFieldCandidates,
    directionFieldCandidates,
    oneWayFieldCandidates,
    bearingAvailable,
    bearingComputable,
    carriagewayMetadataAvailable,
    dividedRoadRepresentationAvailable,
    us90GeometryAssessment,
    tx146GeometryAssessment,
    sampleRoadSegments,
    sampleUs90Segments,
    sampleTx146Segments,
    estimatedBearingSamples,
    duplicateParallelSegmentCandidates,
    missingData,
    directionalReadiness,
    directionalReadinessScore,
    scoreParts,
    dataSourceComparison: sourceComparison,
    recommendation,
    guardrailConclusion: "Current local geometry can support audit bearing calculations and corridor identification. It should not be treated as high-confidence directional/carriageway reporting unless explicit direction, selected-segment reliability, and separated same-name carriageway candidates are all validated."
  };
  console.info("gridlyRoadwayGeometryCapabilityAudit", audit);
  return audit;
}

if (typeof window !== "undefined") {
  window.gridlyRoadwayGeometryCapabilityAudit = gridlyRoadwayGeometryCapabilityAudit;
}
exposeGridlyAuditHelper("gridlyRoadwayGeometryCapabilityAudit", gridlyRoadwayGeometryCapabilityAudit);

function gridlyInferCardinalRoadDirection(bearing) {
  const value = Number(bearing);
  if (!Number.isFinite(value)) return null;
  const normalized = ((value % 360) + 360) % 360;
  if (normalized >= 315 || normalized < 45) return "NB";
  if (normalized >= 45 && normalized < 135) return "EB";
  if (normalized >= 135 && normalized < 225) return "SB";
  if (normalized >= 225 && normalized < 315) return "WB";
  return null;
}

function gridlyDirectionalRoadNameFromFeature(feature = {}) {
  const props = feature?.properties || {};
  const candidates = [props.name, props.ref, props.highway]
    .map((value) => typeof evaluateRoadNameCandidate === "function" ? evaluateRoadNameCandidate(value) : { valid: Boolean(value), normalized: String(value || "").trim() });
  return candidates.find((entry) => entry.valid)?.normalized || "Unknown road";
}

function gridlyBuildLocalDirectionalRoadCandidates(tapCoordinate, options = {}) {
  const tap = gridlyCoordinateFromRecord(tapCoordinate);
  if (!tap || !roadwayDatasetLoaded || !Array.isArray(roadwaySegmentFeatures) || !roadwaySegmentFeatures.length) return [];
  const maxDistanceMeters = Number.isFinite(Number(options.maxDistanceMeters)) ? Number(options.maxDistanceMeters) : 75;
  const maxDistanceMiles = maxDistanceMeters / 1609.344;
  const bestByFeature = new Map();
  roadwaySegmentFeatures.forEach((feature, featureIndex) => {
    const segments = flattenRoadGeometrySegments(feature?.geometry);
    for (const segment of segments) {
      const projection = projectPointToRoadSegment(tap.lat, tap.lng, segment.startLat, segment.startLng, segment.endLat, segment.endLng);
      if (!projection || !Number.isFinite(projection.distanceMiles) || projection.distanceMiles > maxDistanceMiles) continue;
      const current = bestByFeature.get(featureIndex);
      if (!current || projection.distanceMiles < current.distanceMiles) bestByFeature.set(featureIndex, { feature, featureIndex, projection });
    }
  });
  return Array.from(bestByFeature.values())
    .map((entry) => {
      const distanceMeters = entry.projection.distanceMiles * 1609.344;
      const roadName = gridlyDirectionalRoadNameFromFeature(entry.feature);
      const bearing = entry.projection.segmentBearing;
      const inferredDirection = gridlyInferCardinalRoadDirection(bearing);
      const props = entry.feature?.properties || {};
      return {
        source: "local_roadway_dataset_geometry",
        roadName,
        candidateCoordinate: entry.projection.coordinate,
        distanceFromTapMeters: Number(distanceMeters.toFixed(1)),
        bearing,
        inferredDirection,
        directionConfidence: Number.isFinite(Number(bearing)) ? "medium" : "low",
        featureId: props["@id"] || props.id || null,
        oneWay: props.oneway || null,
        highway: props.highway || null,
        segmentStart: entry.projection.segmentStart,
        segmentEnd: entry.projection.segmentEnd,
        geometryAvailable: true,
        rank: 0,
        selected: false,
        selectionReason: "pending_rank"
      };
    })
    .sort((a, b) => Number(a.distanceFromTapMeters || Infinity) - Number(b.distanceFromTapMeters || Infinity))
    .slice(0, 12)
    .map((candidate, index) => ({ ...candidate, rank: index + 1 }));
}


function gridlyRoadwaySegmentId(feature, featureIndex, segmentIndex) {
  const props = feature?.properties || {};
  const baseId = props["@id"] || props.id || props.osm_id || props.way_id || props.gid || `feature_${featureIndex}`;
  return `${baseId}::segment_${segmentIndex}`;
}

function gridlyRoadwayGeometryLengthMeters(startLat, startLng, endLat, endLng) {
  const miles = haversineDistance(startLat, startLng, endLat, endLng);
  return Number.isFinite(miles) ? gridlyRoadwayAuditRound(miles * 1609.344, 1) : null;
}

function gridlyRoadNameKey(value) {
  return gridlyRoadwayAuditNormalizeText(value).toLowerCase();
}

function gridlyBuildGeometryAwareRoadCandidates(tapCoordinate, options = {}) {
  const tap = gridlyCoordinateFromRecord(tapCoordinate);
  if (!tap || !roadwayDatasetLoaded || !Array.isArray(roadwaySegmentFeatures) || !roadwaySegmentFeatures.length) return [];
  const maxDistanceMeters = Number.isFinite(Number(options.maxDistanceMeters)) ? Number(options.maxDistanceMeters) : 75;
  const limit = Number.isFinite(Number(options.limit)) ? Math.max(1, Number(options.limit)) : 16;
  const maxDistanceMiles = maxDistanceMeters / 1609.344;
  const candidates = [];
  roadwaySegmentFeatures.forEach((feature, featureIndex) => {
    const segments = flattenRoadGeometrySegments(feature?.geometry);
    segments.forEach((segment, segmentIndex) => {
      const projection = projectPointToRoadSegment(tap.lat, tap.lng, segment.startLat, segment.startLng, segment.endLat, segment.endLng);
      if (!projection || !Number.isFinite(projection.distanceMiles) || projection.distanceMiles > maxDistanceMiles) return;
      const distanceMeters = projection.distanceMiles * 1609.344;
      const roadName = gridlyDirectionalRoadNameFromFeature(feature);
      const bearing = projection.segmentBearing;
      const segmentLengthMeters = gridlyRoadwayGeometryLengthMeters(segment.startLat, segment.startLng, segment.endLat, segment.endLng);
      const props = feature?.properties || {};
      candidates.push({
        source: "local_roadway_dataset_geometry",
        segmentId: gridlyRoadwaySegmentId(feature, featureIndex, segmentIndex),
        featureIndex,
        segmentIndex,
        featureId: props["@id"] || props.id || props.osm_id || props.way_id || props.gid || null,
        roadName,
        roadNameKey: gridlyRoadNameKey(roadName),
        distanceFromTapMeters: gridlyRoadwayAuditRound(distanceMeters, 1),
        candidateCoordinate: {
          lat: gridlyRoadwayAuditRound(projection.coordinate.lat, 7),
          lng: gridlyRoadwayAuditRound(projection.coordinate.lng, 7)
        },
        segmentStart: {
          lat: gridlyRoadwayAuditRound(segment.startLat, 7),
          lng: gridlyRoadwayAuditRound(segment.startLng, 7)
        },
        segmentEnd: {
          lat: gridlyRoadwayAuditRound(segment.endLat, 7),
          lng: gridlyRoadwayAuditRound(segment.endLng, 7)
        },
        segmentCenter: {
          lat: gridlyRoadwayAuditRound((segment.startLat + segment.endLat) / 2, 7),
          lng: gridlyRoadwayAuditRound((segment.startLng + segment.endLng) / 2, 7)
        },
        bearing: Number.isFinite(Number(bearing)) ? gridlyRoadwayAuditRound(bearing, 1) : null,
        geometryLengthMeters: segmentLengthMeters,
        oneWay: props.oneway || null,
        highway: props.highway || null,
        ref: props.ref || null,
        placement: props.placement || null,
        lanes: props.lanes || null,
        inferredDirection: gridlyInferCardinalRoadDirection(bearing),
        directionConfidence: Number.isFinite(Number(bearing)) ? "medium" : "low",
        rank: 0,
        selected: false,
        selectionReason: "pending_geometry_aware_rank"
      });
    });
  });
  return candidates
    .sort((a, b) => Number(a.distanceFromTapMeters || Infinity) - Number(b.distanceFromTapMeters || Infinity)
      || String(a.roadName || "").localeCompare(String(b.roadName || ""))
      || String(a.segmentId || "").localeCompare(String(b.segmentId || "")))
    .slice(0, limit)
    .map((candidate, index) => ({ ...candidate, rank: index + 1 }));
}

function gridlySelectGeometryAwareRoadSegment(candidates = []) {
  const sorted = (Array.isArray(candidates) ? candidates : [])
    .filter((candidate) => Number.isFinite(Number(candidate?.distanceFromTapMeters)))
    .sort((a, b) => Number(a.distanceFromTapMeters) - Number(b.distanceFromTapMeters));
  if (!sorted.length) {
    return {
      selectedSegment: null,
      selectedSegmentReason: "no_local_roadway_geometry_candidate_within_radius",
      sameRoadCandidateCount: 0,
      oppositeSideCandidateCount: 0,
      dividedRoadRisk: false,
      selectedSideConfidence: "low",
      canSupportFutureDirectionalLabels: false,
      recommendedDirection: null,
      directionConfidence: "low"
    };
  }
  const selected = sorted[0];
  const sameRoadCandidates = selected.roadNameKey
    ? sorted.filter((candidate) => candidate.roadNameKey === selected.roadNameKey)
    : [];
  const sameRoadParallelCandidates = sameRoadCandidates.filter((candidate) => {
    if (candidate.segmentId === selected.segmentId) return false;
    const bearingDifference = gridlyBearingDifferenceDegrees(selected.bearing, candidate.bearing);
    return Number(candidate.distanceFromTapMeters) <= 90
      && (bearingDifference === null || bearingDifference <= 30 || bearingDifference >= 150);
  });
  const nearestOpposite = sameRoadParallelCandidates[0] || null;
  const distanceGap = nearestOpposite && Number.isFinite(Number(nearestOpposite.distanceFromTapMeters))
    ? gridlyRoadwayAuditRound(Number(nearestOpposite.distanceFromTapMeters) - Number(selected.distanceFromTapMeters), 1)
    : null;
  const bearingDifferences = sameRoadParallelCandidates
    .map((candidate) => gridlyBearingDifferenceDegrees(selected.bearing, candidate.bearing))
    .filter(Number.isFinite);
  const bearingConsistent = !bearingDifferences.length || bearingDifferences.some((difference) => difference <= 30 || difference >= 150);
  const dividedRoadRisk = sameRoadParallelCandidates.length > 0 && Number.isFinite(Number(nearestOpposite?.distanceFromTapMeters)) && Number(nearestOpposite.distanceFromTapMeters) <= 35;
  const selectedDistance = Number(selected.distanceFromTapMeters);
  const selectedSideConfidence = !Number.isFinite(selectedDistance) ? "low"
    : (dividedRoadRisk && Number.isFinite(distanceGap) && distanceGap >= 10 && selectedDistance <= 12 && bearingConsistent) ? "high"
      : (dividedRoadRisk && Number.isFinite(distanceGap) && distanceGap >= 5 && selectedDistance <= 20) ? "medium"
        : dividedRoadRisk ? "low"
          : selectedDistance <= 12 ? "high"
            : selectedDistance <= 25 ? "medium" : "low";
  const directionConfidence = Number.isFinite(Number(selected.bearing))
    ? (selectedSideConfidence === "high" ? "medium" : selectedSideConfidence === "medium" ? "low" : "low")
    : "low";
  const canSupportFutureDirectionalLabels = Boolean(
    Number.isFinite(Number(selected.bearing))
    && selectedSideConfidence !== "low"
    && sameRoadCandidates.length > 0
  );
  return {
    selectedSegment: {
      ...selected,
      selected: true,
      selectionReason: "nearest_geometry_segment_selected; same-road continuity and divided-road separation checked before directional confidence is assigned"
    },
    selectedSegmentReason: "nearest_geometry_segment_selected_with_same_road_and_parallel_carriageway_diagnostics",
    sameRoadCandidateCount: sameRoadCandidates.length,
    oppositeSideCandidateCount: sameRoadParallelCandidates.length,
    dividedRoadRisk,
    selectedSideConfidence,
    canSupportFutureDirectionalLabels,
    recommendedDirection: gridlyInferCardinalRoadDirection(selected.bearing),
    directionConfidence,
    sameRoadParallelCandidates: sameRoadParallelCandidates.slice(0, 6).map((candidate) => ({
      segmentId: candidate.segmentId,
      roadName: candidate.roadName,
      distanceFromTapMeters: candidate.distanceFromTapMeters,
      bearing: candidate.bearing,
      bearingDifferenceFromSelected: gridlyBearingDifferenceDegrees(selected.bearing, candidate.bearing),
      segmentCenter: candidate.segmentCenter
    })),
    candidateDistanceGapMeters: distanceGap
  };
}

function gridlyGeometryAwarePlacementDecision(tapCoordinate, options = {}) {
  const tap = gridlyCoordinateFromRecord(tapCoordinate);
  const candidateSegments = gridlyBuildGeometryAwareRoadCandidates(tap, options);
  const selection = gridlySelectGeometryAwareRoadSegment(candidateSegments);
  const decoratedCandidates = candidateSegments.map((candidate) => ({
    ...candidate,
    selected: candidate.segmentId === selection.selectedSegment?.segmentId,
    selectionReason: candidate.segmentId === selection.selectedSegment?.segmentId
      ? selection.selectedSegmentReason
      : `rejected_by_geometry_distance_rank_${candidate.rank}`,
    bearingDifferenceFromSelected: candidate.segmentId === selection.selectedSegment?.segmentId ? 0 : gridlyBearingDifferenceDegrees(selection.selectedSegment?.bearing, candidate.bearing)
  }));
  return {
    tapCoordinate: tap,
    candidateSegments: decoratedCandidates,
    candidateCount: decoratedCandidates.length,
    ...selection
  };
}

function gridlyNormalizeOsrmDirectionalCandidates(candidates = []) {
  return (Array.isArray(candidates) ? candidates : [])
    .map((candidate, index) => {
      const coordinate = gridlyCoordinateFromRecord(candidate?.candidateCoordinate || candidate?.location || candidate);
      return {
        source: candidate?.source || "osrm_nearest_v1_driving",
        roadName: String(candidate?.roadName || candidate?.name || "unknown").trim() || "unknown",
        candidateCoordinate: coordinate,
        distanceFromTapMeters: Number.isFinite(Number(candidate?.distanceFromTapMeters ?? candidate?.distance)) ? Math.round(Number(candidate?.distanceFromTapMeters ?? candidate?.distance) * 10) / 10 : null,
        bearing: null,
        inferredDirection: null,
        directionConfidence: "low",
        rank: index + 1,
        selected: false,
        selectionReason: "OSRM nearest exposes snapped point/name/distance here, but not local segment geometry or carriageway bearing."
      };
    });
}

function gridlyBearingDifferenceDegrees(a, b) {
  const first = Number(a);
  const second = Number(b);
  if (!Number.isFinite(first) || !Number.isFinite(second)) return null;
  const diff = Math.abs(first - second) % 360;
  return Math.round(Math.min(diff, 360 - diff) * 10) / 10;
}

function gridlyLatestDirectionalTapCoordinate(options = {}) {
  return gridlyCoordinateFromRecord(options.tapCoordinate)
    || gridlyCoordinateFromRecord(lastMobileReportSubmitDebug.rawTapCoordinate || lastMobileReportSubmitDebug.originalTapCoords)
    || gridlyCoordinateFromRecord(lastRoadSnapDebug.rawTapCoordinate || lastRoadSnapDebug.originalTapCoords)
    || gridlyCoordinateFromRecord(lastMobileReportSubmitDebug.finalPlacementCoordinate)
    || gridlyCoordinateFromRecord(lastRoadSnapDebug.finalPlacementCoordinate);
}

function gridlyDirectionalSampleIncidents(limit = 6) {
  const unifiedIncidents = typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : [];
  return unifiedIncidents
    .filter((incident) => String(incident?.id || "").startsWith("road-"))
    .slice(0, limit)
    .map((incident) => ({
      id: incident.id,
      roadName: incident.roadName || incident.road_name || incident.nearestRoad || "Unknown road",
      coordinate: gridlyCoordinateFromRecord(incident),
      rawTapCoordinate: gridlyCoordinateFromRecord(incident.rawTapCoordinate || incident.reportCaptureCoordinate),
      finalPlacementCoordinate: gridlyCoordinateFromRecord(incident.finalPlacementCoordinate) || gridlyCoordinateFromRecord(incident),
      roadCandidateCount: incident.roadCandidateCount ?? null,
      nearestCandidateDistanceMeters: incident.nearestCandidateDistanceMeters ?? null,
      placementMode: incident.placementMode || "unknown"
    }));
}

function gridlyDirectionalRoadAudit(options = {}) {
  const includeConnectedAudits = gridlyShouldRunConnectedAuditSnapshots(options);
  const lastTapCoordinate = gridlyLatestDirectionalTapCoordinate(options);
  const localCandidates = gridlyBuildLocalDirectionalRoadCandidates(lastTapCoordinate, options);
  const osrmCandidates = gridlyNormalizeOsrmDirectionalCandidates(lastRoadSnapDebug?.nearestRoadCandidates || []);
  const nearestRoadCandidates = localCandidates.length ? localCandidates : osrmCandidates;
  const selectedRoadCandidate = nearestRoadCandidates[0] || null;
  const nearestDistance = Number(selectedRoadCandidate?.distanceFromTapMeters);
  const secondCandidate = nearestRoadCandidates[1] || null;
  const secondDistance = Number(secondCandidate?.distanceFromTapMeters);
  const candidateDistanceGapMeters = Number.isFinite(nearestDistance) && Number.isFinite(secondDistance)
    ? Math.round(Math.abs(secondDistance - nearestDistance) * 10) / 10
    : null;
  const selectedRoadNameKey = String(selectedRoadCandidate?.roadName || "").toLowerCase();
  const sameRoadNameCandidates = selectedRoadNameKey
    ? nearestRoadCandidates.filter((candidate) => String(candidate.roadName || "").toLowerCase() === selectedRoadNameKey)
    : [];
  const bearingDifferences = sameRoadNameCandidates.slice(1).map((candidate) => gridlyBearingDifferenceDegrees(selectedRoadCandidate?.bearing, candidate?.bearing)).filter(Number.isFinite);
  const parallelCandidateRisk = sameRoadNameCandidates.length > 1 && Number.isFinite(secondDistance) && secondDistance <= 35 && (candidateDistanceGapMeters === null || candidateDistanceGapMeters <= 12);
  const dividedRoadRisk = Boolean(lastRoadSnapDebug?.dividedRoadRisk) || parallelCandidateRisk;
  const selectedSideConfidence = !selectedRoadCandidate ? "low"
    : dividedRoadRisk ? "low"
      : Number.isFinite(candidateDistanceGapMeters) && candidateDistanceGapMeters >= 12 ? "high"
        : Number.isFinite(candidateDistanceGapMeters) && candidateDistanceGapMeters >= 5 ? "medium"
          : nearestRoadCandidates.length <= 1 ? "medium" : "low";
  const roadGeometryAvailable = localCandidates.length > 0;
  const roadBearing = Number.isFinite(Number(selectedRoadCandidate?.bearing)) ? Number(selectedRoadCandidate.bearing) : null;
  const inferredDirection = gridlyInferCardinalRoadDirection(roadBearing);
  const directionConfidence = roadGeometryAvailable && inferredDirection
    ? (selectedSideConfidence === "high" ? "high" : selectedSideConfidence === "medium" ? "medium" : "low")
    : "low";
  const roadName = selectedRoadCandidate?.roadName || (typeof resolveNearestRoadName === "function" && lastTapCoordinate ? resolveNearestRoadName(lastTapCoordinate.lat, lastTapCoordinate.lng) : "Unknown road") || "Unknown road";
  const directionLabel = inferredDirection ? `${roadName} ${inferredDirection}` : roadName;
  const safeDirectionalLabelAnswer = !roadGeometryAvailable ? "insufficient_geometry"
    : directionConfidence === "high" ? "yes_high_confidence"
      : directionConfidence === "medium" ? "yes_medium_confidence" : "no_low_confidence";
  const missingData = [];
  if (!lastTapCoordinate) missingData.push("last tap/report coordinate");
  if (!osrmCandidates.length) missingData.push("latest OSRM nearest candidate list (run tap-map report flow first)");
  if (!roadGeometryAvailable) missingData.push("nearby local roadway LineString/MultiLineString geometry within audit radius");
  if (!Number.isFinite(roadBearing)) missingData.push("candidate segment bearing");
  if (!selectedRoadCandidate?.oneWay) missingData.push("explicit one-way/carriageway direction metadata for high-confidence EB/WB/NB/SB labeling");
  if (parallelCandidateRisk) missingData.push("lane/carriageway-side disambiguation because multiple same-name candidates are similarly close");
  const recommendations = [
    "Use local roadway segment geometry for bearing diagnostics; OSRM nearest candidates alone expose point distance but not enough segment geometry for reliable directional labels.",
    "Treat EB/WB/NB/SB labels as audit-only until the selected candidate has both a stable bearing and enough separation from same-name parallel candidates.",
    "For divided roads such as US 90 and TX 146, compare nearest vs second-nearest same-name candidates and do not promote a directional label when the distance gap is small.",
    "Persist no new payload fields from this audit; keep Supabase, routing, Route Watch, rail markers, and rail reporting untouched."
  ];
  const decoratedCandidates = nearestRoadCandidates.map((candidate, index) => ({
    ...candidate,
    rank: index + 1,
    selected: index === 0,
    reasonSelectedRejected: index === 0
      ? (roadGeometryAvailable ? "nearest local geometry candidate selected for directional audit" : "nearest OSRM point candidate selected, but bearing is unavailable")
      : `rejected_by_rank_distance_${candidate.distanceFromTapMeters ?? "unknown"}m`,
    bearingDifferenceFromSelected: index === 0 ? 0 : gridlyBearingDifferenceDegrees(selectedRoadCandidate?.bearing, candidate?.bearing)
  }));
  const placementAuditSnapshot = includeConnectedAudits && typeof gridlyHazardPlacementAccuracyAudit === "function" ? gridlyHazardPlacementAccuracyAudit() : null;
  const roadClusterAuditSnapshot = includeConnectedAudits && typeof gridlyBuildRoadClusterAudit === "function" ? gridlyBuildRoadClusterAudit({ sampleLimit: 4 }) : null;
  const audit = {
    auditVersion: "V206.10.4-directional-road-placement-bearing-audit",
    auditOnly: true,
    destructiveActionsTaken: false,
    lastTapCoordinate,
    nearestRoadCandidates: decoratedCandidates,
    selectedRoadCandidate: decoratedCandidates[0] || null,
    roadName,
    roadBearing,
    inferredDirection,
    directionLabel,
    directionConfidence,
    safeDirectionalLabelAnswer,
    canSafelyLabelExamplesRightNow: safeDirectionalLabelAnswer,
    dividedRoadRisk,
    parallelCandidateRisk,
    candidateCount: decoratedCandidates.length,
    nearestCandidateDistanceMeters: Number.isFinite(nearestDistance) ? Math.round(nearestDistance * 10) / 10 : null,
    secondNearestCandidateDistanceMeters: Number.isFinite(secondDistance) ? Math.round(secondDistance * 10) / 10 : null,
    candidateDistanceGapMeters,
    sameRoadNameCandidateCount: sameRoadNameCandidates.length,
    bearingDifferences,
    selectedSideConfidence,
    roadGeometryAvailable,
    dataSourceAssessment: {
      localRoadwaySegments: roadGeometryAvailable ? "has nearby segment geometry and can provide audit bearing" : "unavailable_or_no_nearby_geometry",
      osrmNearestCandidates: osrmCandidates.length ? "has nearby point candidates, names, and distances; no bearing/shape in current snap response" : "not_available_in_latest_debug_state",
      leafletTapCoordinate: lastTapCoordinate ? "available" : "missing",
      routeGeometry: typeof savedRouteLayer?.getLatLngs === "function" && (savedRouteLayer.getLatLngs() || []).length ? "available_for_route_context_not_carriageway_selection" : "not_available_or_not_used",
      mapLayerGeometry: "not used for permanent UI; audit relies on loaded roadway dataset geometry when available"
    },
    missingData,
    recommendations,
    sampleIncidents: gridlyDirectionalSampleIncidents(),
    connectedAudits: {
      hazardPlacementAccuracyAuditAvailable: typeof gridlyHazardPlacementAccuracyAudit === "function",
      roadClusterAuditAvailable: typeof gridlyRoadClusterAudit === "function",
      nestedSnapshotsSkippedByDefault: !includeConnectedAudits,
      placementCoordinate: placementAuditSnapshot?.finalPlacementCoordinate || placementAuditSnapshot?.renderedMarkerCoordinate || null,
      placementMode: placementAuditSnapshot?.placementMode || null,
      clusteringApplied: placementAuditSnapshot?.clusteringApplied ?? null,
      clusterSampleCount: Array.isArray(roadClusterAuditSnapshot?.sampleClusters) ? roadClusterAuditSnapshot.sampleClusters.length : null
    },
    trace: [
      "Tap coordinate: last tap/report debug coordinate from lastMobileReportSubmitDebug or lastRoadSnapDebug.",
      "Nearest road candidates: local roadway geometry candidates are preferred for bearing; latest OSRM nearest debug candidates are used as a no-bearing fallback.",
      "Road name: selected candidate name, falling back to resolveNearestRoadName when needed.",
      "Candidate geometry: local LineString/MultiLineString projected segment when available; OSRM fallback has point only.",
      "Bearing: computed from selected local segment start/end when available.",
      "Inferred direction: NB/EB/SB/WB ranges are applied only when bearing is numeric.",
      "Selected candidate: nearest candidate by tap distance for this diagnostic-only audit.",
      "Marker coordinate and alert label: linked through gridlyHazardPlacementAccuracyAudit without changing reporting output."
    ],
    lastRoadSnapDebug: { ...lastRoadSnapDebug },
    lastMobileReportSubmitDebug: { ...lastMobileReportSubmitDebug }
  };
  console.info("gridlyDirectionalRoadAudit", audit);
  return audit;
}

if (typeof window !== "undefined") {
  window.gridlyDirectionalRoadAudit = gridlyDirectionalRoadAudit;
}
exposeGridlyAuditHelper("gridlyDirectionalRoadAudit", gridlyDirectionalRoadAudit);


function gridlyGeometryAwarePlacementSampleIncidents(limit = 8) {
  const unifiedIncidents = typeof getUnifiedIncidents === "function" ? getUnifiedIncidents() : [];
  return unifiedIncidents
    .filter((incident) => String(incident?.id || "").startsWith("road-"))
    .slice(0, limit)
    .map((incident) => ({
      id: incident.id,
      type: incident.report_type || incident.type,
      rawTapCoordinate: gridlyCoordinateFromRecord(incident.rawTapCoordinate || incident.reportCaptureCoordinate),
      finalPlacementCoordinate: gridlyCoordinateFromRecord(incident.finalPlacementCoordinate) || gridlyCoordinateFromRecord(incident),
      selectedRoadwaySegment: incident.selectedRoadwaySegment || null,
      selectedRoadName: incident.selectedRoadName || incident.roadName || incident.nearestRoad || "Unknown road",
      selectedSegmentDistanceMeters: incident.selectedSegmentDistanceMeters ?? null,
      selectedSideConfidence: incident.selectedSideConfidence || "unknown",
      placementMode: incident.placementMode || "unknown"
    }));
}

function gridlyGeometryAwarePlacementAudit(options = {}) {
  const includeConnectedAudits = gridlyShouldRunConnectedAuditSnapshots(options);
  const tapCoordinate = gridlyLatestDirectionalTapCoordinate(options);
  const geometryDecision = gridlyGeometryAwarePlacementDecision(tapCoordinate, { maxDistanceMeters: options.maxDistanceMeters || 75, limit: options.limit || 16 });
  const selectedSegment = geometryDecision.selectedSegment || lastRoadSnapDebug?.selectedRoadwaySegment || lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment || null;
  const selectedRoadName = selectedSegment?.roadName || lastRoadSnapDebug?.selectedRoadName || null;
  const placementAuditSnapshot = includeConnectedAudits && typeof gridlyHazardPlacementAccuracyAudit === "function" ? gridlyHazardPlacementAccuracyAudit() : null;
  const roadClusterAuditSnapshot = includeConnectedAudits && typeof gridlyBuildRoadClusterAudit === "function" ? gridlyBuildRoadClusterAudit({ sampleLimit: 4 }) : null;
  const directionalAuditSnapshot = includeConnectedAudits && typeof gridlyDirectionalRoadAudit === "function" ? gridlyDirectionalRoadAudit({ maxDistanceMeters: options.maxDistanceMeters || 75, includeConnectedAudits: false }) : null;
  const geometryCapabilitySnapshot = includeConnectedAudits && typeof gridlyRoadwayGeometryCapabilityAudit === "function" ? gridlyRoadwayGeometryCapabilityAudit() : null;
  const candidateCount = geometryDecision.candidateCount || 0;
  const selectedSegmentDistanceMeters = selectedSegment?.distanceFromTapMeters ?? lastRoadSnapDebug?.selectedSegmentDistanceMeters ?? null;
  const selectedSegmentBearing = selectedSegment?.bearing ?? lastRoadSnapDebug?.selectedSegmentBearing ?? null;
  const geometryAwarePlacementAvailable = Boolean(candidateCount && selectedSegment);
  const dividedRoadRisk = Boolean(geometryDecision.dividedRoadRisk || lastRoadSnapDebug?.dividedRoadRisk);
  const selectedSideConfidence = geometryDecision.selectedSideConfidence || lastRoadSnapDebug?.selectedSideConfidence || "low";
  const recommendedDirection = geometryDecision.recommendedDirection || lastRoadSnapDebug?.recommendedDirection || null;
  const directionConfidence = geometryDecision.directionConfidence || lastRoadSnapDebug?.directionConfidence || "low";
  const canSupportFutureDirectionalLabels = Boolean(geometryDecision.canSupportFutureDirectionalLabels || lastRoadSnapDebug?.canSupportFutureDirectionalLabels);
  const recommendations = [
    "Use the selected local roadway segment as the internal road-hazard attachment point before considering any future EB/WB/NB/SB display labels.",
    "Keep directional labels audit-only; require stable segment selection, sufficient same-road carriageway separation, and explicit metadata review before exposing labels to users.",
    "For US 90 and TX 146 validation, run two real taps on opposite carriageways and compare selectedSegment.segmentId plus selectedSegmentDistanceMeters in this audit.",
    "Do not alter rail reporting, crossing workflows, TxDOT startup fetch, Supabase schema, Route Watch, Alerts, or Historical Intelligence from this prototype."
  ];
  const audit = {
    auditVersion: "V206.13-geometry-aware-road-hazard-placement-prototype",
    auditOnly: true,
    destructiveActionsTaken: false,
    tapCoordinate,
    candidateCount,
    candidateSegments: geometryDecision.candidateSegments || [],
    selectedSegment,
    selectedRoadName,
    selectedSegmentDistanceMeters,
    selectedSegmentBearing,
    selectedSegmentReason: geometryDecision.selectedSegmentReason || lastRoadSnapDebug?.selectedSegmentReason || "no_geometry_aware_selection_available",
    sameRoadCandidateCount: geometryDecision.sameRoadCandidateCount || 0,
    oppositeSideCandidateCount: geometryDecision.oppositeSideCandidateCount || 0,
    dividedRoadRisk,
    selectedSideConfidence,
    geometryAwarePlacementAvailable,
    canSupportFutureDirectionalLabels,
    recommendedDirection,
    directionConfidence,
    sameRoadParallelCandidates: geometryDecision.sameRoadParallelCandidates || [],
    candidateDistanceGapMeters: geometryDecision.candidateDistanceGapMeters ?? null,
    sampleIncidents: gridlyGeometryAwarePlacementSampleIncidents(),
    recommendations,
    connectedAudits: {
      hazardPlacementAccuracyAuditAvailable: typeof gridlyHazardPlacementAccuracyAudit === "function",
      roadClusterAuditAvailable: typeof gridlyRoadClusterAudit === "function",
      directionalRoadAuditAvailable: typeof gridlyDirectionalRoadAudit === "function",
      roadwayGeometryCapabilityAuditAvailable: typeof gridlyRoadwayGeometryCapabilityAudit === "function",
      nestedSnapshotsSkippedByDefault: !includeConnectedAudits,
      placementMode: placementAuditSnapshot?.placementMode || null,
      finalPlacementCoordinate: placementAuditSnapshot?.finalPlacementCoordinate || null,
      renderedMarkerCoordinate: placementAuditSnapshot?.renderedMarkerCoordinate || null,
      clusterSampleCount: Array.isArray(roadClusterAuditSnapshot?.sampleClusters) ? roadClusterAuditSnapshot.sampleClusters.length : null,
      directionalSelectedRoadCandidate: directionalAuditSnapshot?.selectedRoadCandidate || null,
      directionalReadiness: geometryCapabilitySnapshot?.directionalReadiness || null,
      localRoadwayFeatureCount: geometryCapabilitySnapshot?.roadSegmentFeatureCount ?? null
    },
    validationGuide: {
      us90: "Zoom to US 90, tap one carriageway, record selectedSegment.segmentId, then tap the opposite carriageway and confirm the segmentId changes while selectedSegmentDistanceMeters stays small.",
      tx146: "Repeat the same opposite-carriageway check on TX 146 before promoting any future NB/SB diagnostic label confidence.",
      success: "Selected segments differ, selected distances remain small, and the rendered/final marker coordinate remains visually consistent with the user's tap."
    },
    trace: [
      "Tap Coordinate -> local LineString/MultiLineString segment candidates from the loaded roadway dataset.",
      "Each candidate records segment id, road name, projected tap distance, start/end, center, bearing, and geometry length.",
      "Selection is nearest-first, with same-road continuity, divided-road separation, and bearing consistency diagnostics layered on top.",
      "Selected segment is internal diagnostic state only; no EB/WB/NB/SB label is exposed to users."
    ],
    lastRoadSnapDebug: { ...lastRoadSnapDebug },
    lastMobileReportSubmitDebug: { ...lastMobileReportSubmitDebug }
  };
  console.info("gridlyGeometryAwarePlacementAudit", audit);
  return audit;
}

