    storedReportCoordinate,
    activeHazardCoordinate,
    unifiedIncidentCoordinate,
    coordinateDeltaMeters,
    coordinateSourceUsed,
    roundingApplied,
    snappingApplied,
    clusteringApplied,
    dedupeApplied,
    sampleIncidents,
