function gridlyAuditPerformanceReview() {
  const target = typeof window !== "undefined" ? window : globalThis;
  const recentAuditHelpers = gridlyRecentAuditPerformanceInventory();
  const helperNames = recentAuditHelpers.map((entry) => entry.helperName);
  const manualOnlyHelpers = recentAuditHelpers
    .filter((entry) => Array.isArray(entry.classification) && entry.classification.includes("manual-only") && !entry.calledDuringReportSubmit)
    .map((entry) => entry.helperName);
  const runtimeCalledHelpers = recentAuditHelpers
    .filter((entry) => entry.calledDuringNormalRuntime || entry.calledDuringRenderRefreshLoops || entry.calledDuringReportSubmit || entry.calledDuringMapMovement)
    .map((entry) => ({
      helperName: entry.helperName,
      duringReportSubmit: Boolean(entry.calledDuringReportSubmit),
      duringRenderRefreshLoops: Boolean(entry.calledDuringRenderRefreshLoops),
      duringMapMovement: Boolean(entry.calledDuringMapMovement),
      note: entry.notes
    }));
  const nestedAuditCalls = recentAuditHelpers
    .filter((entry) => Array.isArray(entry.callsOtherAudits) && entry.callsOtherAudits.length)
    .map((entry) => ({
      helperName: entry.helperName,
      callsOtherAudits: entry.callsOtherAudits,
      defaultBehavior: "skipped unless includeConnectedAudits/includeHeavyConnectedAudits/nestedAuditSnapshots is true"
    }));
  const loadedRoadwayFeatureCount = Array.isArray(roadwaySegmentFeatures) ? roadwaySegmentFeatures.length : 0;
  const loadedIncidentCounts = {
    activeHazards: Array.isArray(activeHazards) ? activeHazards.length : 0,
    activeReports: Array.isArray(activeReports) ? activeReports.length : 0,
    roadwaySegmentFeatures: loadedRoadwayFeatureCount,
    roadwayDatasetLoaded: Boolean(roadwayDatasetLoaded)
  };
  const heavyGeometryScans = recentAuditHelpers
    .filter((entry) => String(entry.geometryScanCount).toLowerCase().includes("full") || entry.estimatedCost === "high" || String(entry.estimatedCost).includes("high"))
    .map((entry) => ({
      helperName: entry.helperName,
      geometryScanCount: entry.geometryScanCount,
      estimatedCost: entry.estimatedCost,
      runsAutomatically: Boolean(entry.calledDuringNormalRuntime || entry.calledDuringRenderRefreshLoops || entry.calledDuringMapMovement),
      runsOnSubmit: Boolean(entry.calledDuringReportSubmit)
    }));
  const renderLoopRisks = {
    riskLevel: "low",
    auditHelpersInRenderLoop: recentAuditHelpers.filter((entry) => entry.calledDuringRenderRefreshLoops).map((entry) => entry.helperName),
    finding: "No recent audit helper is called from marker render or refresh loops. Marker diagnostics reuse stored render metadata and are inspected only by manual audits."
  };
  const reportSubmitRisks = {
    riskLevel: roadwayDatasetLoaded ? "medium" : "low",
    runtimeCalls: runtimeCalledHelpers.filter((entry) => entry.duringReportSubmit).map((entry) => entry.helperName),
    finding: "No audit helper runs on submit. The non-audit gridlyGeometryAwarePlacementDecision can scan local roadway geometry once during a road hazard submit after OSRM nearest succeeds."
  };
  const startupRisks = {
    riskLevel: "low",
    auditHelpersOnStartup: [],
    finding: "Audit helpers are exposed on window at startup, but exposing function references does not execute their diagnostic bodies."
  };
  const txdotNetworkRisk = {
    riskLevel: "low",
    fetchesStartedByTxdotDirectionalReadinessAudit: false,
    finding: "gridlyTxdotDirectionalReadinessAudit reads cached TxDOT arrays and getUnifiedIncidents; it does not call fetch or change the TxDOT startup fetch path."
  };
  const markerRenderDiagnosticCost = {
    riskLevel: "low",
    perMarkerAuditWorkAdded: false,
    finding: "Recent audit helpers do not add geometry, incident, DOM, network, localStorage, or Supabase work per marker render. Manual placement audits may inspect a bounded set of existing rendered marker diagnostics."
  };
  const recommendations = [
    "Keep roadway geometry capability and geometry-aware placement audits manual-only; they are the most expensive because they can scan all loaded LineString features.",
    "Use includeConnectedAudits: true only for deliberate deep investigations; default manual audit calls avoid nested heavy snapshots.",
    "Before beta, consider a lightweight roadway spatial index for the report-submit placement decision if field testing shows submit latency on lower-end devices.",
    "Do not attach audit helpers to map move, filter, render, Alerts, History, Route Watch, or startup fetch flows.",
    "Keep TxDOT readiness audits cache-only and avoid diagnostic fetches inside audits."
  ];
  const audit = {
    auditVersion: "V206.13.1-audit-weight-runtime-performance-review",
    auditOnly: true,
    destructiveActionsTaken: false,
    recentAuditHelpers,
    manualOnlyHelpers,
    runtimeCalledHelpers,
    nestedAuditCalls,
    heavyGeometryScans,
    renderLoopRisks,
    reportSubmitRisks,
    startupRisks,
    txdotNetworkRisk,
    markerRenderDiagnosticCost,
    loadedIncidentCounts,
    estimatedPerformanceRisk: {
      overall: roadwayDatasetLoaded ? "low_to_medium" : "low",
      answer: "Audits are not slowing normal app use because recent audit helpers are manual-only by default. The main runtime weight is the non-audit geometry-aware placement decision during actual road hazard submit.",
      expensiveAudits: heavyGeometryScans.map((entry) => entry.helperName),
      lazyAuditCalls: recentAuditHelpers.filter((entry) => entry.shouldBeLazy).map((entry) => entry.helperName)
    },
    recommendations,
    protectedSystemsChanged: false,
    exposedHelperTypes: helperNames.reduce((memo, helperName) => {
      memo[helperName] = typeof target?.[helperName];
      return memo;
    }, {})
  };
  target.gridlyLastAuditPerformanceReview = audit;
  return audit;
}

if (typeof window !== "undefined") {
  window.gridlyAuditPerformanceReview = gridlyAuditPerformanceReview;
  window.gridlyLastAuditPerformanceReview = window.gridlyLastAuditPerformanceReview || null;
}
exposeGridlyAuditHelper("gridlyAuditPerformanceReview", gridlyAuditPerformanceReview);


function getUnifiedIncidents() {
  const railIncidentSource = getConsolidatedIncidents();
  const railAreaFilter = typeof gridlyGetCrossingReportAreaFilter === "function"
    ? gridlyGetCrossingReportAreaFilter(railIncidentSource.map((incident) => incident.latestReport).filter(Boolean), "unifiedIncidents.rail")
    : null;
  const railReportsInSelectedArea = new Set((railAreaFilter?.inSelectedArea || []).filter(Boolean));
  const filteredRailIncidentSource = railAreaFilter?.applied
    ? railIncidentSource.filter((incident) => railReportsInSelectedArea.has(incident.latestReport))
    : railIncidentSource;
  const railIncidents = filteredRailIncidentSource.map((incident) => {
    const latest = incident.latestReport;
    return normalizeUnifiedIncident({
      id: `rail-${incident.crossingId}`,
      type: mapRailReportType(latest.type),
      source: "community",
      severity: latest.severity === "moderate" ? "medium" : latest.severity || "medium",
      status: getIncidentLifecycleState(latest) === "active" ? "active" : "cleared",
      title:
        getIncidentLifecycleState(latest) === "active"
          ? `${incident.crossingName} Rail Update`
          : `✅ ${incident.crossingName} Cleared`,
      description: latest.detail,
      lat: latest.lat ?? latest.latitude ?? latest.rawLat,
      lng: latest.lng ?? latest.lon ?? latest.longitude ?? latest.rawLng,
      area: incident.crossingName,
      created_at: latest.submittedAt,
      confidence: latest.confidence,
      reports_count: incident.count,
      age_minutes: latest.minutesAgo,
      report_type: latest.type,
      crossing_id: incident.crossingId
    });
  });

  function buildRoadUnifiedIncident(incident, status = "active") {
    const latest = incident.latestReport;
    const activeHazardCoordinate = gridlyCoordinateFromRecord(latest);
    const reportCaptureCoordinate = gridlyCoordinateFromRecord(latest?.reportCaptureCoordinate || latest?.rawTapCoordinate || latest?.originalTapCoords);
    const snappedRoadCoordinate = gridlyCoordinateFromRecord(latest?.snappedRoadCoordinate || latest?.snappedCoords);
    const finalPlacementCoordinate = gridlyCoordinateFromRecord(latest?.finalPlacementCoordinate) || activeHazardCoordinate;
    const storedReportCoordinate = activeHazardCoordinate;
    const isCleared = String(status || "").toLowerCase() === "cleared";
    return normalizeUnifiedIncident({
      id: `road-${incident.key}`,
      type: mapRoadHazardType(latest.type),
      source: latest.source || "community",
      severity: isCleared ? "low" : (latest.severity === "moderate" ? "medium" : latest.severity || "medium"),
      status: isCleared ? "cleared" : "active",
      title: latest.title,
      description: latest.detail,
      subtype: latest.subtype || latest.hazardSubtype || latest.otherHazardSubtype || null,
      hazardSubtype: latest.hazardSubtype || latest.subtype || latest.otherHazardSubtype || null,
      detail: latest.detail,
      raw: latest,
      lat: latest.lat ?? latest.latitude ?? latest.rawLat,
      lng: latest.lng ?? latest.lon ?? latest.longitude ?? latest.rawLng,
      reportCaptureCoordinate,
      storedReportCoordinate,
      activeHazardCoordinate,
      rawTapCoordinate: reportCaptureCoordinate,
      snappedRoadCoordinate,
      finalPlacementCoordinate,
      renderedMarkerCoordinate: finalPlacementCoordinate,
      coordinateSourceUsed: latest.coordinateSourceUsed || latest.placementMode || "stored_report_lat_lng",
      placementMode: latest.placementMode || (snappedRoadCoordinate ? "road_snapped" : "raw_tap"),
      placementRiskLevel: latest.placementRiskLevel || "medium",
      tapToSnapDeltaMeters: latest.tapToSnapDeltaMeters ?? gridlyCoordinateDeltaMeters(reportCaptureCoordinate, snappedRoadCoordinate),
      tapToFinalDeltaMeters: latest.tapToFinalDeltaMeters ?? gridlyCoordinateDeltaMeters(reportCaptureCoordinate, finalPlacementCoordinate),
      snapToFinalDeltaMeters: latest.snapToFinalDeltaMeters ?? gridlyCoordinateDeltaMeters(snappedRoadCoordinate, finalPlacementCoordinate),
      roadCandidateCount: latest.roadCandidateCount ?? null,
      nearestCandidateDistanceMeters: latest.nearestCandidateDistanceMeters ?? null,
      selectedRoadwaySegment: latest.selectedRoadwaySegment || latest.geometryAwarePlacement?.selectedSegment || null,
      selectedRoadName: latest.selectedRoadName || latest.geometryAwarePlacement?.selectedSegment?.roadName || null,
      selectedSegmentDistanceMeters: latest.selectedSegmentDistanceMeters ?? latest.geometryAwarePlacement?.selectedSegment?.distanceFromTapMeters ?? null,
      selectedSegmentBearing: latest.selectedSegmentBearing ?? latest.geometryAwarePlacement?.selectedSegment?.bearing ?? null,
      selectedSideConfidence: latest.selectedSideConfidence || latest.geometryAwarePlacement?.selectedSideConfidence || "low",
      geometryAwarePlacement: latest.geometryAwarePlacement || null,
      snappingApplied: Boolean(snappedRoadCoordinate),
      clusteringApplied: incident.count > 1,
      representativeCoordinateReason: latest.representativeCoordinateReason || incident.representativeCoordinateReason,
      area: latest.location_name || latest.area || latest.city || incident.location_name || incident.area || incident.city || "",
      created_at: latest.submittedAt,
      confidence: latest.confidence,
      reports_count: incident.count,
      age_minutes: latest.minutesAgo,
      report_type: latest.type,
      crossing_id: incident.crossingId
    });
  }

  const roadIncidents = getLiveHazardIncidents().map((incident) => buildRoadUnifiedIncident(incident, "active"));
  const recentlyClearedRoadIncidents = getRecentlyClearedRoadHazardIncidents().map((incident) => buildRoadUnifiedIncident(incident, "cleared"));

  return [...railIncidents, ...roadIncidents, ...recentlyClearedRoadIncidents, ...futureTxdotIncidents(), ...futureTxdotConstruction(), ...futureFloodAlerts()]
    .sort((a,b)=>new Date(b.updated_at)-new Date(a.updated_at));
}

function getActiveUnifiedIncidents() {
  return getUnifiedIncidents().filter((incident) => String(incident?.status || "").toLowerCase() === "active");
}


function getUnifiedIncidentRenderKey(incident = {}) {
  const explicitId = incident?.id ?? incident?.report_id ?? incident?.reportId;
  if (explicitId !== undefined && explicitId !== null && String(explicitId).trim()) return `id:${String(explicitId).trim()}`;

  const crossingId = incident?.crossing_id ?? incident?.crossingId;
  const reportType = String(incident?.report_type || incident?.type || "other_hazard").toLowerCase();
  const state = String(incident?.status || "").toLowerCase() === "cleared" || reportType === "hazard_cleared" ? "cleared" : "active";
  if (crossingId !== undefined && crossingId !== null && String(crossingId).trim()) {
    return `crossing:${String(crossingId).trim()}:${reportType}:${state}`;
  }

  const category = getHazardCategory(incident?.report_type || incident?.type || "other_hazard");
  const lat = Number(incident?.lat);
  const lng = Number(incident?.lng);
  const roundedLat = Number.isFinite(lat) ? lat.toFixed(4) : "na";
  const roundedLng = Number.isFinite(lng) ? lng.toFixed(4) : "na";
  const sourceTime = incident?.updated_at || incident?.created_at || incident?.submittedAt;
  const timeMs = sourceTime ? new Date(sourceTime).getTime() : Number.NaN;
  const bucketMinutes = Number.isFinite(timeMs) ? Math.floor(timeMs / (5 * 60 * 1000)) : "na";
  return `fallback:${category}:${roundedLat}:${roundedLng}:${bucketMinutes}:${state}`;
}

function choosePreferredIncidentCandidate(current, candidate, routeHazard) {
  if (!current) return candidate;

  const currentRelevant = isIncidentRouteRelevant(current, routeHazard);
  const candidateRelevant = isIncidentRouteRelevant(candidate, routeHazard);
  if (currentRelevant !== candidateRelevant) return candidateRelevant ? candidate : current;

  const currentStatus = String(current?.status || "").toLowerCase();
  const candidateStatus = String(candidate?.status || "").toLowerCase();
  const currentActive = currentStatus !== "cleared" && String(current?.report_type || "").toLowerCase() !== "hazard_cleared";
  const candidateActive = candidateStatus !== "cleared" && String(candidate?.report_type || "").toLowerCase() !== "hazard_cleared";

  const currentUpdated = new Date(current?.updated_at || current?.created_at || 0).getTime();
  const candidateUpdated = new Date(candidate?.updated_at || candidate?.created_at || 0).getTime();
  if (currentActive !== candidateActive) {
    if (!candidateActive && candidateUpdated > currentUpdated) return candidate;
    if (candidateActive) return candidate;
    return current;
  }

  const currentConfidence = String(current?.confidence || "").toLowerCase().includes("community") ? 1 : 2;
  const candidateConfidence = String(candidate?.confidence || "").toLowerCase().includes("community") ? 1 : 2;
  if (candidateConfidence !== currentConfidence) return candidateConfidence > currentConfidence ? candidate : current;
  if (candidateUpdated !== currentUpdated) return candidateUpdated > currentUpdated ? candidate : current;

  const currentReports = Number(current?.reports_count || 0);
  const candidateReports = Number(candidate?.reports_count || 0);
  if (candidateReports !== currentReports) return candidateReports > currentReports ? candidate : current;
  return current;
}

function getMapSeverityClass(incident){
  if (incident.status === "cleared") return "low";
  const normalizedType = String(incident?.type || incident?.report_type || "").toLowerCase();
  const metadataSeverity = HAZARD_TYPES[normalizedType]?.severity;
  if (metadataSeverity === "high") return "high";
  if (metadataSeverity === "moderate") return "moderate";
  if (["flooding", "rail_blocked", "wreck", "closure"].includes(normalizedType)) return "high";
  if (["rail_delay", "construction", "disabled_vehicle", "traffic_backup"].includes(normalizedType)) return "moderate";
  return "low";
}

function getUnifiedIncidentIcon(incident){
  if (incident.status === "cleared") return "✅";
  const m={rail_blocked:"⛔", rail_delay:"🚦", wreck:"🚗", flooding:"🌊", construction:"🚧", closure:"⛔", debris:"⚠️", disabled_vehicle:"🚙", traffic_backup:"🚦", cleared:"✅"};
  return m[incident.type]||"❗";
}

const GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN = /\b(?:other_hazard|emergency_response_activity|community_report|future_source|gridly\s+structured|gridly_structured|source\s*:|source\s+tag|source\s+tags|internal\s+(?:category|subtype|source)|report_type|hazard_subtype|confidence\s*(?:score|:|\d+%|percentage)|\d+\s*%)\b/i;
let lastGridlyHazardPopupConsumerState = null;
let lastGridlyCrossingPopupConsumerState = null;

function getGridlyHazardConsumerTitle(incident = {}) {
  const subtype = resolveOtherHazardSubtypeFromRecord(incident);
  if (subtype) return getOtherHazardSubtypeLabel(subtype);
  const category = getHazardCategory(incident?.report_type || incident?.type || "other_hazard");
  return (typeof formatRoadHazardCategoryLabel === "function" ? formatRoadHazardCategoryLabel(category) : HAZARD_TYPES?.[category]?.label) || "Other Hazard";
}

function getGridlyHazardPopupReportCount(incident = {}) {
  const candidates = [incident?.reports_count, incident?.count, Array.isArray(incident?.reports) ? incident.reports.length : null];
  const count = candidates.map((value) => Number(value)).find((value) => Number.isFinite(value) && value > 0);
  return Math.max(1, Math.round(count || 1));
}

function getGridlyHazardPopupMinutesAgo(incident = {}) {
  const numericAge = Number(incident?.age_minutes ?? incident?.minutesAgo ?? incident?.latestReport?.minutesAgo);
  if (Number.isFinite(numericAge)) return Math.max(0, Math.round(numericAge));
  const timestampCandidates = [
    incident?.updated_at, incident?.updatedAt, incident?.lastUpdatedAt, incident?.last_activity_at, incident?.lastActivityAt,
    incident?.latestReport?.updated_at, incident?.latestReport?.updatedAt, incident?.latestReport?.submittedAt,
    incident?.created_at, incident?.createdAt
  ];
  const newestMs = timestampCandidates
    .map((value) => new Date(value || 0).getTime())
    .filter((value) => Number.isFinite(value) && value > 0)
    .sort((a, b) => b - a)[0];
  if (!newestMs) return 0;
  return Math.max(0, Math.round((Date.now() - newestMs) / 60000));
}

function formatGridlyHazardPopupFreshnessLine(incident = {}) {
  const minutes = getGridlyHazardPopupMinutesAgo(incident);
  const verb = [incident?.updated_at, incident?.updatedAt, incident?.lastUpdatedAt, incident?.last_activity_at, incident?.lastActivityAt, incident?.age_minutes]
    .some((value) => value !== undefined && value !== null && String(value).trim() !== "") ? "Updated" : "Reported";
  if (minutes <= 1) return `${verb} just now`;
  if (minutes < 60) return `${verb} ${minutes} minutes ago`;
  const hours = Math.round(minutes / 60);
  if (hours < 24) return `${verb} ${hours} hour${hours === 1 ? "" : "s"} ago`;
  const days = Math.round(hours / 24);
  return `${verb} ${days} day${days === 1 ? "" : "s"} ago`;
}

function getGridlyHazardPopupConfidenceLine(reportCount = 1) {
  if (reportCount <= 1) return "Awaiting additional reports";
  if (reportCount === 2) return "Community confirmed";
  return "Multiple community reports";
}

function resolveGridlyHazardPopupRoadLabel(incident = {}) {
  const lookup = typeof getSharedResolvedRoadLookup === "function" ? getSharedResolvedRoadLookup(incident) : null;
  const lookupPhrase = lookup?.locationContext?.phrasing || lookup?.locationContext?.primary || "";
  const candidates = [
    lookupPhrase,
    incident?.road_name, incident?.roadName, incident?.resolvedRoadName, incident?.primaryRoad, incident?.corridor,
    incident?.street_name, incident?.nearest_road, incident?.snapped_road_name, incident?.location_name,
    incident?.latestReport?.road_name, incident?.latestReport?.roadName, incident?.latestReport?.resolvedRoadName, incident?.latestReport?.nearest_road
  ];
  const label = candidates
    .map((value) => normalizeGridlyUserFacingRoadText(value))
    .find((value) => value && !isOtherHazardGenericRoadLabel(value) && !/^liberty county$/i.test(value));
  return label || "this area";
}

function buildGridlyHazardPopupConsumerModel(incident = {}) {
  const headline = typeof standardizeGridlyAlertHeadline === "function" ? standardizeGridlyAlertHeadline(getGridlyHazardConsumerTitle(incident)) : getGridlyHazardConsumerTitle(incident);
  const title = normalizeGridlyUserFacingRoadText(headline);
  const category = getHazardCategory(incident?.report_type || incident?.type || "other_hazard");
  const roadLabel = resolveGridlyHazardPopupRoadLabel(incident);
  const locationPreposition = category === "other_hazard" ? "near" : "on";
  const locationLine = `Reported ${locationPreposition} ${roadLabel}`;
  const reportCount = getGridlyHazardPopupReportCount(incident);
  const reportCountLine = `${reportCount} active report${reportCount === 1 ? "" : "s"}`;
  const freshnessLine = formatGridlyHazardPopupFreshnessLine(incident);
  const confidenceLine = getGridlyHazardPopupConfidenceLine(reportCount);
  const visibleText = [title, locationLine, reportCountLine, freshnessLine, confidenceLine].join(" ");
  const containsTechnicalMetadata = GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN.test(visibleText);
  return {
    title,
    locationLine: normalizeGridlyUserFacingRoadText(locationLine),
    reportCountLine,
    freshnessLine,
    confidenceLine,
    containsTechnicalMetadata,
    consumerFriendlyPass: Boolean(title && locationLine && reportCountLine && freshnessLine && confidenceLine && !containsTechnicalMetadata)
  };
}


function getGridlyCrossingPopupTitle(incident = {}) {
  const statusText = String(incident?.status || incident?.state || "").toLowerCase();
  const typeText = String(incident?.report_type || incident?.reportType || incident?.type || incident?.eventType || incident?.title || "").toLowerCase();
  if (statusText === "cleared" || /\b(?:cleared|clear|rail_cleared)\b/.test(typeText)) return "Crossing Clear";
  if (/\b(?:blocked|blocking|rail_blocked|blocked_crossing|crossing_blocked)\b/.test(typeText)) return "Crossing Blocked";
  if (/\b(?:heavy|delay|delayed|rail_delay|train)\b/.test(typeText)) return "Train Blocking Crossing";
  return statusText === "active" ? "Crossing Blocked" : "Train Blocking Crossing";
}

function resolveGridlyCrossingPopupLocationLabel(incident = {}) {
  const candidates = [
    incident?.crossingName, incident?.crossing_name, incident?.crossingRoad, incident?.crossingLabel, incident?.resolvedCrossingName,
    incident?.area, incident?.location_name, incident?.locationName, incident?.name, incident?.title,
    incident?.latestReport?.crossingName, incident?.latestReport?.crossing_name, incident?.latestReport?.crossingRoad
  ];
  let label = candidates
    .map((value) => normalizeGridlyLightweightLocationLabelText(normalizeGridlyUserFacingRoadText(value)))
    .map((value) => value.replace(/\s+Rail Update$/i, "").replace(/^✅\s*/, "").replace(/\s+Cleared$/i, "").trim())
    .find((value) => value && !/^(?:this area|liberty county|unknown|undefined|null|live incident)$/i.test(value));
  if (!label) label = "this crossing";
  const displayLabel = typeof standardizeGridlyAlertHeadline === "function" ? standardizeGridlyAlertHeadline(label) : label;
  if (/^this crossing$/i.test(displayLabel) || /\bcrossing\b/i.test(displayLabel)) return displayLabel;
  return `${displayLabel} Crossing`;
}

function getGridlyCrossingPopupReportCount(incident = {}) {
  return getGridlyHazardPopupReportCount(incident);
}

function getGridlyCrossingPopupConfidenceLine(incident = {}, reportCount = 1) {
  const confidenceText = String(incident?.confidence || incident?.confidenceLine || incident?.confidence_label || "").toLowerCase();
  if (reportCount >= 3 || /multiple/.test(confidenceText)) return "Multiple community reports";
  if (reportCount >= 2 || /confirmed|verified/.test(confidenceText)) return "Community confirmed";
  return "Awaiting additional reports";
}

function buildGridlyCrossingPopupConsumerModel(incident = {}) {
  const title = getGridlyCrossingPopupTitle(incident);
  const locationLabel = resolveGridlyCrossingPopupLocationLabel(incident);
  const locationLine = normalizeGridlyUserFacingRoadText(`Reported at ${locationLabel}`);
  const reportCount = getGridlyCrossingPopupReportCount(incident);
  const reportCountLine = `${reportCount} active report${reportCount === 1 ? "" : "s"}`;
  const freshnessLine = formatGridlyHazardPopupFreshnessLine(incident);
  const confidenceLine = getGridlyCrossingPopupConfidenceLine(incident, reportCount);
  const visibleText = [title, locationLine, freshnessLine, reportCountLine, confidenceLine].join(" ");
  const technicalMetadataDetected = GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN.test(visibleText);
  return {
    title,
    locationLine,
    freshnessLine,
    reportCountLine,
    confidenceLine,
    technicalMetadataDetected,
    consumerFriendlyPass: Boolean(title && locationLine && freshnessLine && reportCountLine && confidenceLine && !technicalMetadataDetected)
  };
}

function isGridlyAlertCardCrossingRelated(alert = {}) {
  const textValue = [
    alert?.category, alert?.type, alert?.hazardType, alert?.hazard_type, alert?.reportType, alert?.report_type,
    alert?.title, alert?.headline, alert?.resolvedHeadline, alert?.localizedSummary, alert?.crossingId, alert?.crossing_id,
    alert?.crossingName, alert?.crossingRoad
  ].map((value) => String(value || "")).join(" ");
  if (typeof isGridlyAlertRailOrCrossingRelated === "function" && isGridlyAlertRailOrCrossingRelated(alert)) return true;
  return /\b(?:rail|train|crossing|blocked\s+crossing|rail_blockage|rail_blocked)\b/i.test(textValue);
}

function stripGridlyAlertCardLocationFromTitle(value = "") {
  const textValue = normalizeGridlyUserFacingRoadText(value);
  if (!textValue) return "";
  const protectedLabels = ["Debris in Road", "Livestock on Road", "Object in Road", "Water on Road", "Ice on Road"];
  const protectedMatch = protectedLabels.find((label) => textValue.toLowerCase().startsWith(label.toLowerCase()));
  if (protectedMatch) return protectedMatch;
  return textValue
    .replace(/\s+(?:on|near|at|in)\s+.+$/i, "")
    .replace(/\s+between\s+.+$/i, "")
    .replace(/\s+(?:eastbound|westbound|northbound|southbound)\b.*$/i, "")
    .trim();
}

function normalizeGridlyAlertCardTitleCandidate(alert = {}, fallbackTitle = "") {
  if (isGridlyAlertCardCrossingRelated(alert)) return "Crossing Blocked";
  const subtype = typeof resolveOtherHazardSubtypeFromRecord === "function" ? resolveOtherHazardSubtypeFromRecord(alert) : "";
  if (subtype && typeof getOtherHazardSubtypeLabel === "function") return getOtherHazardSubtypeLabel(subtype);
  const popupTitle = typeof getGridlyHazardConsumerTitle === "function" ? getGridlyHazardConsumerTitle({
    ...alert,
    report_type: alert?.report_type || alert?.reportType || alert?.type || alert?.category || alert?.hazardType || alert?.hazard_type
  }) : "";
  const metadataLabel = popupTitle && !/^other hazard$/i.test(popupTitle) ? popupTitle : "";
  const rawEvent = [alert?.hazardTypeLabel, alert?.typeLabel, alert?.label, alert?.reportType, alert?.report_type, alert?.hazardType, alert?.type, alert?.category, fallbackTitle, alert?.title, alert?.headline, alert?.resolvedHeadline, alert?.localizedSummary]
    .map((value) => normalizeGridlyUserFacingRoadText(value))
    .find(Boolean) || "";
  const normalized = String(rawEvent || "").toLowerCase();
  const eventMap = [
    { test: /downed\s+power|power\s+line/, label: "Downed Power Line" },
    { test: /livestock|animal/, label: "Livestock on Road" },
    { test: /road[_\s-]*(?:closed|closure)|\bclosure\b|\bclosed\b/, label: "Road Closed" },
    { test: /construction|work ?zone|lane ?work/, label: "Construction" },
    { test: /debris|object/, label: "Debris in Road" },
    { test: /traffic|backup|congestion|heavy delay/, label: "Traffic Backup" },
    { test: /flood|high water/, label: "Flooding" },
    { test: /crash|collision|wreck|accident/, label: "Crash / Wreck" },
    { test: /disabled\s+vehicle|stalled/, label: "Disabled Vehicle" }
  ];
  return eventMap.find((entry) => entry.test.test(normalized))?.label || stripGridlyAlertCardLocationFromTitle(metadataLabel || rawEvent) || "Road Hazard";
}

function normalizeGridlyAlertCardLocationLabel(alert = {}) {
  const isCrossing = isGridlyAlertCardCrossingRelated(alert);
  const popupRoad = typeof resolveGridlyHazardPopupRoadLabel === "function" ? resolveGridlyHazardPopupRoadLabel({
    ...alert,
    road_name: alert?.road_name || alert?.roadName || alert?.primaryRoad || alert?.corridor || alert?.route,
    nearest_road: alert?.nearest_road || alert?.nearestRoad || alert?.knownLocation || alert?.locationName
  }) : "";
  const crossingCandidates = [alert?.crossingName, alert?.crossingRoad, alert?.resolvedCrossingName, alert?.crossingLabel, alert?.nearestRoad, alert?.knownLocation, alert?.locationName, alert?.location, popupRoad];
  const roadCandidates = [popupRoad, alert?.knownLocation, alert?.locationName, alert?.location, alert?.nearestRoad, alert?.roadName, alert?.primaryRoad, alert?.corridor, alert?.route, alert?.titleRoad, alert?.raw?.knownLocation, alert?.raw?.nearestRoad, alert?.raw?.roadName, alert?.source?.knownLocation, alert?.source?.nearestRoad, alert?.source?.roadName];
  const candidates = (isCrossing ? crossingCandidates : roadCandidates)
    .map((value) => normalizeGridlyLightweightLocationLabelText(normalizeGridlyUserFacingRoadText(value)))
    .filter((value) => value && !/^(this area|liberty county|dayton area|unknown|undefined|null)$/i.test(value));
  const first = candidates.find((value, index) => candidates.findIndex((candidate) => candidate.toLowerCase() === value.toLowerCase()) === index) || "this area";
  return isCrossing && first && !/crossing/i.test(first) ? `${first} Crossing` : first;
}

function buildGridlyAlertCardConsumerModel(alert = {}, options = {}) {
  const rawTitle = options.fallbackTitle || alert?.resolvedHeadline || alert?.headline || alert?.title || alert?.localizedSummary || "";
  const title = standardizeGridlyAlertHeadline(normalizeGridlyAlertCardTitleCandidate(alert, rawTitle));
  const locationLabel = normalizeGridlyAlertCardLocationLabel(alert);
  const locationVerb = isGridlyAlertCardCrossingRelated(alert) ? "at" : "near";
  const locationLine = normalizeGridlyUserFacingRoadText(`Reported ${locationVerb} ${locationLabel}`);
  const reportCountCandidates = [alert?.reports_count, alert?.count, alert?.confirmations, alert?.users_count, Array.isArray(alert?.reports) ? alert.reports.length : null]
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value > 0);
  const reportCount = Math.max(1, Math.round(reportCountCandidates[0] || (typeof getGridlyHazardPopupReportCount === "function" ? getGridlyHazardPopupReportCount(alert) : 1)));
  const reportCountLine = `${reportCount} active report${reportCount === 1 ? "" : "s"}`;
  const freshnessLine = typeof formatGridlyHazardPopupFreshnessLine === "function" ? formatGridlyHazardPopupFreshnessLine(alert) : normalizeGridlyUserFacingRoadText(alert?.minutesText || alert?.timeAgo || "Updated just now");
  const freshnessCountLine = `${freshnessLine} • ${reportCountLine}`;
  const visibleText = [title, locationLine, freshnessCountLine].join(" ");
  const technicalMetadataDetected = GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN.test(visibleText);
  return {
    title,
    locationLabel,
    locationLine,
    reportCount,
    reportCountLine,
    freshnessLine,
    freshnessCountLine,
    technicalMetadataDetected,
    consumerFriendlyPass: Boolean(title && locationLine && freshnessCountLine && !technicalMetadataDetected)
  };
}

function buildUnifiedIncidentPopup(incident){
  const isActive = incident.status === "active";
  const typeCategory = incident.id?.startsWith("rail-") ? "rail" : "road";
  if (typeCategory === "rail") {
    const model = buildGridlyCrossingPopupConsumerModel(incident);
    lastGridlyCrossingPopupConsumerState = model;
    const popupLines = `
      <strong data-gridly-crossing-popup-field="title">${sanitizeText(model.title)}</strong>
      <span data-gridly-crossing-popup-field="locationLine">${sanitizeText(model.locationLine)}</span><br />
      <span data-gridly-crossing-popup-field="freshnessLine">${sanitizeText(model.freshnessLine)}</span> • <span data-gridly-crossing-popup-field="reportCountLine">${sanitizeText(model.reportCountLine)}</span><br />
      <span data-gridly-crossing-popup-field="confidenceLine">${sanitizeText(model.confidenceLine)}</span>
    `;
    if (!isActive) {
      return `<div class="gridly-popup" data-gridly-crossing-popup="consumer">${popupLines}</div>`;
    }
    return `<div class="gridly-popup" data-gridly-crossing-popup="consumer">${popupLines}<div class="popup-report-grid"><button class="popup-report-btn warning" type="button" data-unified-action="confirm" data-incident-id="${sanitizeText(incident.id)}" data-incident-category="${sanitizeText(typeCategory)}" data-report-type="${sanitizeText(incident.report_type || "")}" data-crossing-id="${sanitizeText(incident.crossing_id || "")}" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">Confirm Still Active</button><button class="popup-report-btn blue" type="button" data-unified-action="cleared" data-incident-id="${sanitizeText(incident.id)}" data-incident-category="${sanitizeText(typeCategory)}" data-report-type="${sanitizeText(incident.report_type || "")}" data-crossing-id="${sanitizeText(incident.crossing_id || "")}" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">Mark Cleared</button><button class="popup-report-btn neutral" type="button" data-unified-action="view-area" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">View Area</button></div></div>`;
  }

  const model = buildGridlyHazardPopupConsumerModel(incident);
  lastGridlyHazardPopupConsumerState = model;
  const popupLines = `
    <strong data-gridly-hazard-popup-field="title">${sanitizeText(model.title)}</strong>
    <span data-gridly-hazard-popup-field="locationLine">${sanitizeText(model.locationLine)}</span><br />
    <span data-gridly-hazard-popup-field="reportCountLine">${sanitizeText(model.reportCountLine)}</span><br />
    <span data-gridly-hazard-popup-field="freshnessLine">${sanitizeText(model.freshnessLine)}</span><br />
    <span data-gridly-hazard-popup-field="confidenceLine">${sanitizeText(model.confidenceLine)}</span>
  `;

  if (!isActive) {
    return `<div class="gridly-popup" data-gridly-hazard-popup="consumer">${popupLines}</div>`;
  }

  return `<div class="gridly-popup" data-gridly-hazard-popup="consumer">${popupLines}<div class="popup-report-grid"><button class="popup-report-btn warning" type="button" data-unified-action="confirm" data-incident-id="${sanitizeText(incident.id)}" data-incident-category="${sanitizeText(typeCategory)}" data-report-type="${sanitizeText(incident.report_type || "")}" data-crossing-id="${sanitizeText(incident.crossing_id || "")}" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">Confirm Still Active</button><button class="popup-report-btn blue" type="button" data-unified-action="cleared" data-incident-id="${sanitizeText(incident.id)}" data-incident-category="${sanitizeText(typeCategory)}" data-report-type="${sanitizeText(incident.report_type || "")}" data-crossing-id="${sanitizeText(incident.crossing_id || "")}" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">Mark Cleared</button><button class="popup-report-btn neutral" type="button" data-unified-action="view-area" data-lat="${sanitizeText(String(incident.lat))}" data-lng="${sanitizeText(String(incident.lng))}">View Area</button></div></div>`;
}

function gridlyHazardPopupAudit() {
  const popup = typeof document !== "undefined" ? document.querySelector("#map .leaflet-popup-content [data-gridly-hazard-popup='consumer'], [data-gridly-hazard-popup='consumer']") : null;
  const readField = (field) => popup?.querySelector?.(`[data-gridly-hazard-popup-field='${field}']`)?.textContent?.trim() || "";
  const domModel = popup ? {
    title: readField("title"),
    locationLine: readField("locationLine"),
    reportCountLine: readField("reportCountLine"),
    freshnessLine: readField("freshnessLine"),
    confidenceLine: readField("confidenceLine")
  } : null;
  const model = domModel || lastGridlyHazardPopupConsumerState || buildGridlyHazardPopupConsumerModel({
    report_type: "other_hazard",
    subtype: "emergency_response_activity",
    road_name: "CR 2418",
    reports_count: 1,
    age_minutes: 25,
    status: "active"
  });
  const visibleText = [model.title, model.locationLine, model.reportCountLine, model.freshnessLine, model.confidenceLine, popup?.textContent || ""].join(" ");
  const containsTechnicalMetadata = GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN.test(visibleText);
  return {
    title: model.title,
    locationLine: model.locationLine,
    reportCountLine: model.reportCountLine,
    freshnessLine: model.freshnessLine,
    confidenceLine: model.confidenceLine,
    containsTechnicalMetadata,
    consumerFriendlyPass: Boolean(model.title && model.locationLine && model.reportCountLine && model.freshnessLine && model.confidenceLine && !containsTechnicalMetadata)
  };
}
exposeGridlyAuditHelper("gridlyHazardPopupAudit", gridlyHazardPopupAudit);

