exposeGridlyAuditHelper("gridlyCrossingPopupConsumerAudit", gridlyCrossingPopupConsumerAudit);

const GRIDLY_LANGUAGE_CONSISTENCY_AUDIT_VERSION = "V241";


function gridlyNormalizeAlertCardAuditText(value = "") {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function gridlyAlertCardConsumerAudit(options = {}) {
  const samples = [];
  const maxSamples = Number(options.limit || 8);
  let clearedRowsIgnored = 0;
  let staleRowsIgnored = 0;
  let headerRowsIgnored = 0;
  const readNodeText = (node, selector) => gridlyNormalizeAlertCardAuditText(node?.querySelector?.(selector)?.textContent || "");
  const readNodeOwnText = (node) => gridlyNormalizeAlertCardAuditText(node?.textContent || node?.getAttribute?.("aria-label") || node?.getAttribute?.("title") || "");
  const isClearedAlertCardAuditRow = (node) => {
    const textValue = readNodeOwnText(node);
    const typeText = gridlyNormalizeAlertCardAuditText([
      node?.dataset?.gridlyAlertHazardType,
      node?.dataset?.alertType,
      node?.dataset?.reportType,
      node?.dataset?.status,
      node?.dataset?.state,
      node?.className,
      textValue
    ].join(" ")).toLowerCase();
    return /^cleared\b/i.test(textValue)
      || /\b(?:hazard_cleared|recently_cleared|recently-cleared|cleared)\b/i.test(typeText);
  };
  const isHeaderAlertCardAuditRow = (node) => {
    if (node?.hasAttribute?.("data-gridly-alerts-panel-heading") || node?.hasAttribute?.("data-gridly-alert-expand")) return true;
    const textValue = readNodeOwnText(node);
    return /^(?:community awareness|active movement alerts|no active alerts|road conditions appear calm|trending crossings are calm|\+\s*\d+\s+more)/i.test(textValue)
      || /\bactive community report(?:s)?\b/i.test(textValue);
  };
  const hasRequiredV240CardMarkers = (node) => Boolean(
    node?.getAttribute?.("data-gridly-alert-row") === "true"
    && node?.hasAttribute?.("data-gridly-alert-id")
    && node?.hasAttribute?.("data-gridly-alert-title")
    && node?.hasAttribute?.("data-gridly-alert-summary")
    && node?.hasAttribute?.("data-gridly-alert-location")
    && !node?.hasAttribute?.("data-gridly-alert-expand")
  );
  const isCardVisiblyRendered = (node) => {
    if (!node || !(node instanceof Element)) return false;
    if (node.hidden || node.getAttribute("aria-hidden") === "true" || node.dataset?.gridlyAlertHidden === "true") return false;
    if (typeof isElementVisiblyRendered === "function" && !isElementVisiblyRendered(node)) return false;
    let current = node;
    while (current && current instanceof Element) {
      if (current.hidden || current.getAttribute("aria-hidden") === "true") return false;
      const style = typeof window !== "undefined" && typeof window.getComputedStyle === "function" ? window.getComputedStyle(current) : null;
      if (style && (style.display === "none" || style.visibility === "hidden" || style.opacity === "0")) return false;
      current = current.parentElement;
    }
    return true;
  };
  const activeAlertsSheet = typeof document !== "undefined"
    ? document.querySelector?.("#gridlyPortraitV2Sheet[data-active-sheet='alerts']:not([hidden])")
    : null;
  const activeAlertsSurface = activeAlertsSheet?.querySelector?.("#gridlyPortraitV2SheetBody .gridly-alerts-active, .gridly-alerts-active") || null;
  const belongsToCurrentActiveSurface = (node) => {
    if (activeAlertsSurface) return activeAlertsSurface.contains(node);
    if (activeAlertsSheet) return activeAlertsSheet.contains(node);
    return Boolean(node?.closest?.(".gridly-alerts-active")) || !node?.closest?.("#gridlyPortraitV2Sheet");
  };
  const toDomSample = (node, index) => {
    const title = gridlyNormalizeAlertCardAuditText(node?.dataset?.gridlyAlertTitle || readNodeText(node, "strong, .gridly-alert-title, .gridly-alert-headline, [data-gridly-alert-title]"));
    const locationLine = gridlyNormalizeAlertCardAuditText(
      readNodeText(node, "[data-gridly-alert-location-line], .gridly-alert-subtitle, strong + div")
      || readNodeText(node, ".gridly-alert-title + div, .gridly-alert-headline + div")
    );
    const freshnessCountLine = gridlyNormalizeAlertCardAuditText(readNodeText(node, "small, [data-gridly-alert-freshness], [data-gridly-alert-count-line]"));
    const text = gridlyNormalizeAlertCardAuditText([title, locationLine, freshnessCountLine].filter(Boolean).join(" ") || node?.dataset?.gridlyAlertSummary || node?.textContent || "");
    return { index, source: "dom", title, locationLine, freshnessCountLine, text };
  };

  if (typeof document !== "undefined" && typeof document.querySelectorAll === "function") {
    const candidateNodes = Array.from(document.querySelectorAll([
      "[data-gridly-alert-row='true']",
      ".gridly-alert-row",
      ".alert-item",
      "[data-gridly-alerts-panel-heading='true']"
    ].join(",")));
    const activeCardNodes = [];
    candidateNodes.forEach((node) => {
      if (isHeaderAlertCardAuditRow(node)) {
        headerRowsIgnored += 1;
        return;
      }
      if (isClearedAlertCardAuditRow(node)) {
        clearedRowsIgnored += 1;
        return;
      }
      if (!hasRequiredV240CardMarkers(node) || !belongsToCurrentActiveSurface(node) || !isCardVisiblyRendered(node)) {
        staleRowsIgnored += 1;
        return;
      }
      activeCardNodes.push(node);
    });
    activeCardNodes.slice(0, maxSamples).forEach((node, index) => samples.push(toDomSample(node, index)));
  }
  if (!samples.length) {
    const latestAlerts = typeof window !== "undefined" && Array.isArray(window.__gridlyLatestAlertsForRender) ? window.__gridlyLatestAlertsForRender : [];
    latestAlerts.filter((alert) => !isClearedReportType(alert?.type || alert?.report_type || alert?.status || alert?.state)).slice(0, maxSamples).forEach((alert, index) => {
      const model = buildGridlyAlertCardConsumerModel(alert);
      samples.push({ index, source: "render-cache", title: model.title, locationLine: model.locationLine, freshnessCountLine: model.freshnessCountLine, text: [model.title, model.locationLine, model.freshnessCountLine].join(" "), model });
    });
  }
  if (!samples.length) {
    [
      { report_type: "other_hazard", subtype: "downed_power_line", road_name: "Bowie Street", reports_count: 1, age_minutes: 6 },
      { type: "rail_blocked", crossingName: "Alabama Street Crossing", reports_count: 1, age_minutes: 4 },
      { report_type: "other_hazard", subtype: "livestock_on_road", road_name: "CR 2414", reports_count: 1, age_minutes: 17 }
    ].forEach((alert, index) => {
      const model = buildGridlyAlertCardConsumerModel(alert);
      samples.push({ index, source: "fixture", title: model.title, locationLine: model.locationLine, freshnessCountLine: model.freshnessCountLine, text: [model.title, model.locationLine, model.freshnessCountLine].join(" "), model });
    });
  }

  const titleLooksLong = (title) => {
    const cleanTitle = gridlyNormalizeAlertCardAuditText(title);
    return cleanTitle.split(/\s+/).filter(Boolean).length > 8 || cleanTitle.length > 64 || /\b(?:on|near|at)\s+.+\s+in\s+/i.test(cleanTitle);
  };
  const duplicateLocationPattern = /\b(?:reported\s+)?(?:near|on|at)\s+(.{3,70}?)\s+(?:near|on|at|in)\s+\1\b/i;
  const duplicateLocationCount = samples.filter((sample) => {
    const text = gridlyNormalizeAlertCardAuditText(sample.text);
    const title = gridlyNormalizeAlertCardAuditText(sample.title);
    const locationLine = gridlyNormalizeAlertCardAuditText(sample.locationLine);
    const locationValue = locationLine.replace(/^reported\s+(?:near|at|on)\s+/i, "").trim();
    return duplicateLocationPattern.test(text)
      || /\bon\s+([^•,;]+?)\s+in\s+\1\b/i.test(text)
      || Boolean(locationValue && title && title.toLowerCase().includes(locationValue.toLowerCase()) && /\b(?:near|on|at|in)\b/i.test(title));
  }).length;
  const longTitleCount = samples.filter((sample) => titleLooksLong(sample.title)).length;
  const technicalMetadataDetected = samples.some((sample) => GRIDLY_HAZARD_POPUP_TECHNICAL_METADATA_PATTERN.test(gridlyNormalizeAlertCardAuditText(sample.text)));
  const cardsChecked = samples.length;
  return {
    cardsChecked,
    longTitleCount,
    duplicateLocationCount,
    technicalMetadataDetected,
    clearedRowsIgnored,
    staleRowsIgnored,
    headerRowsIgnored,
    consumerFriendlyPass: Boolean(cardsChecked && samples.every((sample) => sample.title && sample.locationLine && sample.freshnessCountLine) && longTitleCount === 0 && duplicateLocationCount === 0 && !technicalMetadataDetected),
    samples: samples.slice(0, maxSamples)
  };
}
exposeGridlyAuditHelper("gridlyAlertCardConsumerAudit", gridlyAlertCardConsumerAudit);

function gridlyLanguageConsistencyNormalizeText(value = "") {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function gridlyLanguageConsistencyTextFromNode(node) {
  return gridlyLanguageConsistencyNormalizeText(node?.textContent || node?.getAttribute?.("aria-label") || node?.getAttribute?.("title") || "");
}

function gridlyLanguageConsistencyReadSurface(label, selector, options = {}) {
  const samples = [];
  if (typeof document !== "undefined" && typeof document.querySelectorAll === "function") {
    const nodes = Array.from(document.querySelectorAll(selector || ""));
    nodes.slice(0, options.limit || 8).forEach((node, index) => {
      const text = gridlyLanguageConsistencyTextFromNode(node);
      if (!text && !options.includeEmpty) return;
      samples.push({
        index,
        selector,
        text,
        source: "dom",
        visible: typeof isElementVisiblyRendered === "function" ? isElementVisiblyRendered(node) : undefined
      });
    });
  }
  if (!samples.length && options.fallbackText) {
    samples.push({ index: 0, selector, text: gridlyLanguageConsistencyNormalizeText(options.fallbackText), source: options.fallbackSource || "model_fallback" });
  }
  return { label, selector, count: samples.length, samples };
}

function gridlyLanguageConsistencyDetectIssues(surface = {}) {
  const findings = [];
  const samples = Array.isArray(surface.samples) ? surface.samples : [];
  const rawInternalPattern = /\b(?:other_hazard|community_report|future_source|status_source|gridly_structured|gridly\s+structured|source\s+tag|source\s+tags|report_type|hazard_subtype)\b/i;
  const onRoadInRoadPattern = /\bon\s+([^•,;]+?)\s+in\s+([^•,;]+?)(?:$|[•,;.])/i;
  const duplicateNearPattern = /\b(?:near|on|at)\s+(.{3,60}?)\s+(?:near|on|at|in)\s+\1\b/i;
  samples.forEach((sample) => {
    const text = gridlyLanguageConsistencyNormalizeText(sample.text);
    if (!text) return;
    const lower = text.toLowerCase();
    const push = (type, severity, evidence, recommendation) => findings.push({
      surface: surface.label,
      selector: surface.selector,
      sampleIndex: sample.index,
      type,
      severity,
      evidence,
      recommendation
    });
    if (/\brail\s+delay\b/i.test(text)) {
      push("railDelayLanguageDetected", "high", text, "For blocked crossings, prefer popup-style language such as 'Train blocking crossing' plus a clear location and freshness line.");
    }
    if (/\bmobility\s+report\b/i.test(text)) {
      push("mobilityReportLanguageDetected", "medium", text, "Prefer 'community report' for source language or 'active report' for count/status language.");
    }
    if (rawInternalPattern.test(text)) {
      push("technicalMetadataDetected", "high", text, "Remove raw internal tokens from user-facing copy; translate them through consumer labels before rendering.");
    }
    const onInMatch = text.match(onRoadInRoadPattern);
    if (onInMatch) {
      const first = gridlyLanguageConsistencyNormalizeText(onInMatch[1]);
      const second = gridlyLanguageConsistencyNormalizeText(onInMatch[2]);
      const firstRoadLike = /\b(?:road|street|st\.?|avenue|ave\.?|highway|hwy|fm|cr|tx|us|i-)\b|\d/.test(first.toLowerCase());
      const secondRoadLike = /\b(?:road|street|st\.?|avenue|ave\.?|highway|hwy|fm|cr|tx|us|i-)\b|\d/.test(second.toLowerCase());
      if (firstRoadLike && secondRoadLike) {
        push("roadLikeAreaLanguageDetected", "high", text, "Avoid 'on <road> in <road>'; use popup-style location such as 'Reported near <area>' or a single road/intersection line.");
      }
    }
    if (duplicateNearPattern.test(text) || /\b(.{4,40})\b(?:\s*[•·,/]\s*|\s+near\s+)\1\b/i.test(text)) {
      push("duplicateLocationPhrasingDetected", "medium", text, "Deduplicate repeated location fragments before rendering the card or header.");
    }
    if (/alert card title/i.test(surface.label) || /alert card titles/i.test(surface.label)) {
      const wordCount = text.split(/\s+/).filter(Boolean).length;
      if (wordCount > 8 || text.length > 64) {
        push("alertTitleTooLong", "medium", text, "Use popup-style title length: short event label first, then move location/freshness into subtitle or metadata lines.");
      }
    }
    if (/\bactive hazards reported\b/i.test(text) || /\bmultiple\s+mobility\s+impacts\b/i.test(lower)) {
      push("genericHazardLanguage", "low", text, "Prefer the popup model's specific event + location + count + freshness hierarchy when data is available.");
    }
  });
  return findings;
}

function gridlyLanguageConsistencyPopupModelSample() {
  const hazardModel = typeof gridlyHazardPopupAudit === "function"
    ? gridlyHazardPopupAudit()
    : (typeof buildGridlyHazardPopupConsumerModel === "function" ? buildGridlyHazardPopupConsumerModel({ report_type: "other_hazard", subtype: "downed_power_line", road_name: "Bowie Street", reports_count: 1, age_minutes: 6, status: "active" }) : null);
  const unifiedRailPopupModel = typeof gridlyCrossingPopupConsumerAudit === "function"
    ? gridlyCrossingPopupConsumerAudit()
    : (typeof buildGridlyCrossingPopupConsumerModel === "function" ? buildGridlyCrossingPopupConsumerModel({ type: "rail_blocked", report_type: "blocked", status: "active", crossingName: "Louisiana Street", reports_count: 1, age_minutes: 0, confidence: "community" }) : null);
  let crossingModel = null;
  const crossingPopupNode = typeof document !== "undefined" ? document.querySelector("#map .leaflet-popup-content .gridly-popup:not([data-gridly-hazard-popup='consumer']):not([data-gridly-crossing-popup='consumer']), .gridly-popup:not([data-gridly-hazard-popup='consumer']):not([data-gridly-crossing-popup='consumer'])") : null;
  if (crossingPopupNode) {
    crossingModel = { source: "dom", text: gridlyLanguageConsistencyTextFromNode(crossingPopupNode) };
  } else if (typeof buildPopup === "function") {
    const sampleHtml = buildPopup({ id: "audit-crossing", name: "Sample crossing", railroad: "Railroad", risk: 50 }, { title: "Blocked", type: "blocked", minutesAgo: 6 });
    crossingModel = { source: "sample_buildPopup", text: gridlyLanguageConsistencyNormalizeText(sampleHtml.replace(/<[^>]+>/g, " ")) };
  }
  return { hazardPopupModel: hazardModel, unifiedRailPopupModel, crossingPopupModel: crossingModel };
}

function gridlyLanguageConsistencyAudit() {
  const generatedAt = new Date().toISOString();
  const popupModels = gridlyLanguageConsistencyPopupModelSample();
  const mobileAwareness = typeof getGridlyMobileAwarenessPanelSummary === "function" ? getGridlyMobileAwarenessPanelSummary() : null;
  const awarenessSummary = typeof buildGridlyCommunityAwarenessIntelligenceSummary === "function" ? buildGridlyCommunityAwarenessIntelligenceSummary() : null;
  const displaySummary = typeof summarizeGridlyAwarenessIntelligenceForDisplay === "function" && awarenessSummary ? summarizeGridlyAwarenessIntelligenceForDisplay(awarenessSummary) : null;
  const surfaces = [
    gridlyLanguageConsistencyReadSurface("top awareness/header headline", "#gridlyV2TopStatusPrimary", { fallbackText: displaySummary?.headline || awarenessSummary?.awarenessStatus || "", fallbackSource: "awareness_display_model" }),
    gridlyLanguageConsistencyReadSurface("top awareness/header subline", "#gridlyV2TopStatusSecondary, #gridlyTopAwarenessMicroline", { fallbackText: displaySummary?.subline || awarenessSummary?.awarenessStatusReason || "", fallbackSource: "awareness_display_model" }),
    gridlyLanguageConsistencyReadSurface("mobile awareness card headline", "#gridlyCommunityPulseHeadline, #gridlyMobileAwarenessPanel [data-gridly-awareness-headline]", { fallbackText: mobileAwareness?.status || "", fallbackSource: "mobile_awareness_model" }),
    gridlyLanguageConsistencyReadSurface("mobile awareness card metric line", "#gridlyCommunityPulseSubline, #gridlyCommunityPulseCopy, #gridlyMobileAwarenessPanel [data-gridly-awareness-metric-line]", { fallbackText: mobileAwareness?.crossingsLine || "", fallbackSource: "mobile_awareness_model" }),
    gridlyLanguageConsistencyReadSurface("alert panel header", "[data-gridly-alerts-panel-heading='true'], #alertsList h2, #alertsList h3, #roadHazardsList h2, #roadHazardsList h3", { fallbackText: "", includeEmpty: false }),
    gridlyLanguageConsistencyReadSurface("alert card titles", "[data-gridly-alert-row='true'] strong, .gridly-alert-row strong, .alert-item strong", { limit: 12 }),
    gridlyLanguageConsistencyReadSurface("alert card subtitles/summaries", "[data-gridly-alert-row='true'] small, [data-gridly-alert-row='true'] [data-gridly-alert-summary], .gridly-alert-row small, .alert-item small", { limit: 18 }),
    {
      label: "hazard popup model",
      selector: "gridlyHazardPopupAudit()/buildGridlyHazardPopupConsumerModel",
      count: popupModels.hazardPopupModel ? 1 : 0,
      samples: popupModels.hazardPopupModel ? [{
        index: 0,
        selector: "hazardPopupModel",
        source: "model",
        text: gridlyLanguageConsistencyNormalizeText([
          popupModels.hazardPopupModel.title,
          popupModels.hazardPopupModel.locationLine,
          popupModels.hazardPopupModel.reportCountLine,
          popupModels.hazardPopupModel.freshnessLine,
          popupModels.hazardPopupModel.confidenceLine
        ].filter(Boolean).join(" / ")),
        model: popupModels.hazardPopupModel
      }] : []
    },
    {
      label: "unified rail popup fixture",
      selector: "gridlyCrossingPopupConsumerAudit()/buildUnifiedIncidentPopup",
      count: popupModels.unifiedRailPopupModel ? 1 : 0,
      samples: popupModels.unifiedRailPopupModel ? [{
        index: 0,
        selector: "unifiedRailPopupModel",
        source: "model",
        text: gridlyLanguageConsistencyNormalizeText([
          popupModels.unifiedRailPopupModel.title,
          popupModels.unifiedRailPopupModel.locationLine,
          popupModels.unifiedRailPopupModel.freshnessLine,
          popupModels.unifiedRailPopupModel.reportCountLine,
          popupModels.unifiedRailPopupModel.confidenceLine
        ].filter(Boolean).join(" / ")),
        model: popupModels.unifiedRailPopupModel
      }] : []
    },
    {
      label: "crossing popup model",
      selector: "buildPopup()/visible crossing popup",
      count: popupModels.crossingPopupModel ? 1 : 0,
      samples: popupModels.crossingPopupModel ? [{ index: 0, selector: "crossingPopupModel", source: popupModels.crossingPopupModel.source, text: popupModels.crossingPopupModel.text }] : []
    }
  ];
  const inconsistencies = surfaces.flatMap(gridlyLanguageConsistencyDetectIssues);
  const hasType = (type) => inconsistencies.some((finding) => finding.type === type);
  const recommendedRewrites = inconsistencies.map((finding) => ({
    surface: finding.surface,
    issue: finding.type,
    currentText: finding.evidence,
    recommendedRewrite: finding.recommendation
  }));
  const surfacesChecked = surfaces.map((surface) => ({
    surface: surface.label,
    selector: surface.selector,
    sampleCount: surface.count,
    samples: surface.samples.map((sample) => ({ text: sample.text, source: sample.source }))
  }));
  return {
    version: GRIDLY_LANGUAGE_CONSISTENCY_AUDIT_VERSION,
    generatedAt,
    surfacesChecked,
    preferredLanguageModel: {
      source: "hazard popup consumer model",
      hierarchy: ["short specific event title", "reported near/on location", "active report count", "freshness", "confidence/community confirmation"],
      example: "Downed Power Line / Reported near Bowie Street / 1 active report / Updated 6 minutes ago",
      hazardPopupModel: popupModels.hazardPopupModel || null,
      unifiedRailPopupModel: popupModels.unifiedRailPopupModel || null
    },
    inconsistencies,
    railDelayLanguageDetected: hasType("railDelayLanguageDetected"),
    roadLikeAreaLanguageDetected: hasType("roadLikeAreaLanguageDetected"),
    technicalMetadataDetected: hasType("technicalMetadataDetected"),
    duplicateLocationPhrasingDetected: hasType("duplicateLocationPhrasingDetected"),
    recommendedRewrites,
    safeToProceedToCopyPatch: true
  };
}
exposeGridlyAuditHelper("gridlyLanguageConsistencyAudit", gridlyLanguageConsistencyAudit);

function mapUnifiedRailConfirmType(reportType) {
  if (reportType === "blocked" || reportType === "heavy" || reportType === "other") return reportType;
  if (reportType === "cleared") return "heavy";
  return "heavy";
}

async function handleUnifiedIncidentAction(button) {
  const action = button?.dataset?.unifiedAction;
  const incidentId = button?.dataset?.incidentId || "";
  const incident = getUnifiedIncidents().find((item) => String(item.id) === String(incidentId));
  const category = button?.dataset?.incidentCategory || (incidentId.startsWith("rail-") ? "rail" : "road");
  const reportType = button?.dataset?.reportType || incident?.report_type || "";
  const crossingId = button?.dataset?.crossingId || incident?.crossing_id || (incidentId.startsWith("rail-") ? incidentId.replace("rail-", "") : "");
  const lat = Number(button?.dataset?.lat ?? incident?.lat);
  const lng = Number(button?.dataset?.lng ?? incident?.lng);

  if (action === "view-area") {
    if (Number.isFinite(lat) && Number.isFinite(lng)) {
      window.zoomToHazard?.(lat, lng);
    }
    return;
  }

  if (action === "confirm") {
    console.debug("Unified confirm action", { category, reportType, crossingId, incidentId });
    if (category === "rail") {
      const crossing = crossings.find((item) => String(item.id) === String(crossingId));
      if (!crossing) {
        setConfirmation("Crossing not found for this incident.", "error");
        return;
      }
      await createSharedReport(crossing, mapUnifiedRailConfirmType(reportType), "unified incident confirm");
      return;
    }

    await createSharedHazardReport(reportType || "other_hazard", lat, lng, "unified incident confirm still active");
    return;
  }

  if (action === "cleared") {
    console.debug("Unified cleared action", { category, reportType, crossingId, incidentId });
    if (category === "rail") {
      const crossing = crossings.find((item) => String(item.id) === String(crossingId));
      if (!crossing) {
        setConfirmation("Crossing not found for this incident.", "error");
        return;
      }
      await createSharedReport(crossing, "cleared", "unified incident cleared");
      return;
    }

    if (typeof window.clearHazard === "function") {
      await window.clearHazard(reportType || "other_hazard", lat, lng);
      return;
    }

    setConfirmation("Hazard clear is not supported yet for this incident.", "success");
  }
}

function getHazardConfidenceLabel(count) {
  if (count >= 4) return "Community verified";
  if (count >= 2) return "Likely active";
  return "Single live report";
}

function updateHazardCounter(liveHazards) {
  const existing = document.getElementById("gridlyHazardCounter");

  if (!existing) return;

  const count = liveHazards.length;
  const confirmed = liveHazards.filter((hazard) => (hazard.count || hazard.reports_count || 0) >= 2).length;

  existing.textContent =
    count === 0
      ? "No live incidents"
      : `${count} live incident${count === 1 ? "" : "s"} · ${confirmed} confirmed`;
}
window.zoomToHazard = function (lat, lng) {
  if (!map) return;
  map.setView([lat, lng], 16);
};

