function openMobileRouteQuickPanel() {
  routeLauncherSource = routeLauncherSource || "unknown";
  injectMobileQuickActionOverlays();
  const panel = document.getElementById("gridlyMobileRouteQuickPanel");
  if (!panel) return;
  document.getElementById("gridlyHazardPanel")?.classList.remove("visible");
  const startSelect = document.getElementById("mobileRouteQuickStart");
  const destinationSelect = document.getElementById("mobileRouteQuickDestination");
  if (startSelect && els.routeWatchStartSelect) {
    startSelect.innerHTML = els.routeWatchStartSelect.innerHTML;
    startSelect.value = els.routeWatchStartSelect.value || "";
  }
  if (destinationSelect && els.routeWatchDestinationSelect) {
    destinationSelect.innerHTML = els.routeWatchDestinationSelect.innerHTML;
    destinationSelect.value = els.routeWatchDestinationSelect.value || "";
  }
  const meta = document.getElementById("mobileRouteQuickMeta");
  if (meta) {
    meta.textContent = `${els.routeStatus?.textContent || "Choose route"} • ${els.routeEta?.textContent || "ETA pending"} • ${els.routeRecommendation?.textContent || "Leave now for best commute"}`;
  }
  if (startSelect && !startSelect.dataset.gridlyRouteQuickBound) {
    startSelect.addEventListener("change", () => {
      console.info("Gridly route panel selection change", { control: "start", value: startSelect.value || "" });
    });
    startSelect.dataset.gridlyRouteQuickBound = "1";
  }
  if (destinationSelect && !destinationSelect.dataset.gridlyRouteQuickBound) {
    destinationSelect.addEventListener("change", () => {
      console.info("Gridly route panel selection change", { control: "destination", value: destinationSelect.value || "" });
    });
    destinationSelect.dataset.gridlyRouteQuickBound = "1";
  }
  bindDirectRouteQuickPanelButtonListeners();
  panel.classList.add("visible");
  syncRouteQuickPanelUiState();
  if (isMobileLayoutMode()) setMobileUiMode("route", { silent: true });
  traceMobileModeMutation("route quick panel opened", { intendedSurfaceSelector: "#gridlyMobileRouteQuickPanel", surfaceState: readSurfaceComputedState("#gridlyMobileRouteQuickPanel") });
}

async function debugEnterRoutePipeline(args = {}) {
  routeDebugError("DEBUG ROUTE PIPELINE ENTER");
  debugPipelineWrapperEntered = true;
  lastRoutePipelineStep = "pipeline-entered";
  routeDebugError("DEBUG ROUTE PIPELINE TRACE", {
    typeOfStartInlineRouteWatch: typeof startInlineRouteWatch,
    args
  });
  try {
    routeDebugError("DEBUG ROUTE PIPELINE BEFORE AWAIT", { args });
    const result = await startInlineRouteWatch(args);
    routeDebugError("DEBUG ROUTE PIPELINE AFTER AWAIT", { args });
    return finalizeNearbyPairResult(result);
  } catch (error) {
    routeDebugError("DEBUG ROUTE PIPELINE CATCH ERROR", { error, args });
    throw error;
  }
}

function bindDirectRouteQuickPanelButtonListeners() {
  const panel = document.getElementById("gridlyMobileRouteQuickPanel");
  const viewRouteButton = panel?.querySelector?.('.route-quick-actions button[data-action="view-route-quick"]');
  const startRouteWatchButton = panel?.querySelector?.('.route-quick-actions button[data-action="start-route-watch-quick"]');
  if (!viewRouteButton || !startRouteWatchButton) return;
  if (viewRouteButton.dataset.gridlyDirectRouteListenerAttached === "1" && startRouteWatchButton.dataset.gridlyDirectRouteListenerAttached === "1") {
    routeQuickDirectListenerAttached = true;
    return;
  }

  const attachDirectListener = (button, action) => {
    if (!button || button.dataset.gridlyDirectRouteListenerAttached === "1") return;
    button.addEventListener("click", async (event) => {
      const startSelect = document.getElementById("mobileRouteQuickStart");
      const destinationSelect = document.getElementById("mobileRouteQuickDestination");
      const selectedStart = startSelect?.value || "";
      const selectedDestination = destinationSelect?.value || "";
      routeDebugError("DIRECT ROUTE BUTTON CLICK", {
        action,
        button,
        selectedStart,
        selectedDestination
      });
      lastRoutePipelineStep = "direct-listener-hit";
      lastDirectRouteClick = {
        action,
        buttonAction: button?.dataset?.action || "",
        selectedStart,
        selectedDestination,
        at: new Date().toISOString()
      };
      if (els.routeWatchStartSelect && startSelect) els.routeWatchStartSelect.value = selectedStart;
      if (els.routeWatchDestinationSelect && destinationSelect) els.routeWatchDestinationSelect.value = selectedDestination;
      updateRouteWatchStartButtonState();
      event.preventDefault();
      event.stopPropagation();
      if (typeof event.stopImmediatePropagation === "function") event.stopImmediatePropagation();
      const panelWasVisible = panel?.classList?.contains("visible") ?? false;
      await debugEnterRoutePipeline({
        activateWatch: action === "start-route-watch-quick",
        source: action === "start-route-watch-quick" ? "mobile_quick_panel_start_watch_direct" : "mobile_quick_panel_view_route_direct"
      });
      const routePreviewWasSuccessful = Boolean(routeRenderSucceeded && !lastRouteEarlyReturnReason);
      if (action === "view-route-quick" && routePreviewWasSuccessful) {
        closeMobileRouteQuickPanel("view_route_success");
      }
      if (action === "start-route-watch-quick" && routePreviewWasSuccessful) {
        closeMobileRouteQuickPanel("start_route_watch_success");
      }
      const panelIsVisible = panel?.classList?.contains("visible") ?? false;
      if (panelWasVisible && !panelIsVisible && routeRenderSucceeded && !lastRouteEarlyReturnReason) {
        lastRoutePanelCloseReason = action === "start-route-watch-quick" ? "start_route_watch_success" : "view_route_success";
      }
    }, true);
    button.dataset.gridlyDirectRouteListenerAttached = "1";
  };

  attachDirectListener(startRouteWatchButton, "start-route-watch-quick");
  attachDirectListener(viewRouteButton, "view-route-quick");
  routeQuickDirectListenerAttached = true;
}

// Compatibility wrapper: legacy callers still invoke this name after route CTA helper split.
function updateRouteWatchStartButtonState() {
  if (typeof loadSavedRoute === "function") {
    loadSavedRoute();
    return;
  }
  if (typeof updateRouteWatchStartButtonLabel === "function") updateRouteWatchStartButtonLabel();
}

async function handleRouteQuickPanelAction(action, event, actionEl) {
  const startSelect = document.getElementById("mobileRouteQuickStart");
  const destinationSelect = document.getElementById("mobileRouteQuickDestination");
  const selectedStartValue = startSelect?.value || "";
  const selectedDestinationValue = destinationSelect?.value || "";

  if (action === "view-route-quick") {
    pushGridlyReflowTrace("Route Watch open/view route", "start", { source: "view-route-quick" });
    routeDebugLog("ROUTE QUICK VIEW CLICK HIT", {
      eventTarget: event?.target || null,
      eventCurrentTarget: event?.currentTarget || null,
      selectedStartValue,
      selectedDestinationValue
    });
  } else if (action === "start-route-watch-quick") {
    pushGridlyReflowTrace("Route Watch open/view route", "start", { source: "start-route-watch-quick" });
    routeDebugLog("ROUTE QUICK START CLICK HIT", {
      eventTarget: event?.target || null,
      eventCurrentTarget: event?.currentTarget || null,
      selectedStartValue,
      selectedDestinationValue
    });
  }

  lastRouteButtonClickSource = actionEl?.dataset?.action || action || "";
  lastRouteButtonClickAt = new Date().toISOString();
  routeRequestTriggered = true;
  lastRouteError = null;

  if (els.routeWatchStartSelect && startSelect) els.routeWatchStartSelect.value = startSelect.value;
  if (els.routeWatchDestinationSelect && destinationSelect) els.routeWatchDestinationSelect.value = destinationSelect.value;
  const places = getSavedPlaces();
  const resolvedStartPlace = places.find((place) => place.id === (els.routeWatchStartSelect?.value || "")) || null;
  const resolvedDestinationPlace = places.find((place) => place.id === (els.routeWatchDestinationSelect?.value || "")) || null;
  routeDebugLog("Gridly quick panel place resolution result", { resolvedStartPlace, resolvedDestinationPlace });
  updateRouteWatchStartButtonState();

  const routePipelineArgs = {
    activateWatch: action === "start-route-watch-quick",
    source: action === "start-route-watch-quick" ? "mobile_quick_panel_start_watch" : "mobile_quick_panel_view_route"
  };

  try {
    routeDebugLog("ABOUT TO CALL startInlineRouteWatch", {
      typeOfStartInlineRouteWatch: typeof startInlineRouteWatch,
      routePipelineArgs
    });
    if (typeof startInlineRouteWatch !== "function") {
      lastRouteEarlyReturnReason = "start_inline_route_watch_unavailable";
      lastRouteError = "Route pipeline function startInlineRouteWatch is unavailable";
      throw new Error(lastRouteError);
    }
    await startInlineRouteWatch(routePipelineArgs);
    routeDebugLog("RETURNED FROM startInlineRouteWatch", { routePipelineArgs });
  } catch (error) {
    lastRouteError = String(error?.message || error || "Route pipeline invocation failed");
    if (!lastRouteEarlyReturnReason) {
      lastRouteEarlyReturnReason = "route_pipeline_invocation_failed";
    }
    console.error("Gridly quick panel route pipeline call failed", {
      error,
      message: lastRouteError,
      routePipelineArgs
    });
    return;
  }

  const routePreviewWasSuccessful = Boolean(routeRenderSucceeded && !lastRouteEarlyReturnReason);
  if (action === "view-route-quick") {
    routeNavSection("map");
    if (routePreviewWasSuccessful) {
      closeMobileRouteQuickPanel("view_route_success");
    }
    return;
  }

  if (action === "start-route-watch-quick" && routePreviewWasSuccessful) {
    closeMobileRouteQuickPanel("start_route_watch_success");
  }
}

function attachRouteQuickPanelDelegatedClickHandlers() {
  if (routeQuickButtonDelegatedBindingActive) return;
  routeQuickButtonDelegatedBindingActive = true;
  document.addEventListener("click", async (event) => {
    const actionEl = event?.target?.closest?.(
      '#gridlyMobileRouteQuickPanel .route-quick-actions button[data-action="view-route-quick"], #gridlyMobileRouteQuickPanel .route-quick-actions button[data-action="start-route-watch-quick"]'
    );
    if (!actionEl) return;
    if (actionEl.dataset.gridlyDirectRouteListenerAttached === "1") return;
    const action = actionEl.dataset.action || "";
    if (!action) return;
    event.preventDefault();
    await handleRouteQuickPanelAction(action, event, actionEl);
  }, true);
}

function resetQuickHazardReportState() {
  if (reportingState.placementModeActive) return;
  pendingHazardPlacement = null;
  selectedQuickHazardType = null;
  selectedOtherHazardSubtype = "";
  updateReportingState({ selectedHazardType: null, placementModeActive: false, reportModeActive: false });
  document.querySelectorAll("#gridlyHazardPanel .hazard-choice-grid button").forEach((btn) => {
    btn.classList.remove("selected");
  });
  document.querySelectorAll("#gridlyHazardPanel [data-other-hazard-subtype]").forEach((btn) => {
    btn.classList.remove("selected");
    btn.removeAttribute("aria-pressed");
  });
  const useMyLocationBtn = document.querySelector('#gridlyHazardPanel [data-action="submit-hazard"]');
  useMyLocationBtn?.classList.remove("selected", "active", "armed");
  useMyLocationBtn?.removeAttribute("aria-pressed");
  syncHazardPickerUiState();
}

function closeVisiblePortraitV2ReportSurfaceAfterSubmit() {
  const safeTrace = (stage, details = {}) => {
    try {
      if (typeof pushTapMapTrace === "function") pushTapMapTrace(stage, details);
    } catch (error) {
      console.warn("Gridly report surface close trace failed", error);
    }
  };
  const safeIsVisible = (el) => {
    try {
      if (!el) return false;
      const style = getComputedStyle(el);
      if (el.hidden || style.display === "none" || style.visibility === "hidden" || Number(style.opacity || "1") === 0) return false;
      const rect = el.getBoundingClientRect();
      return rect.width > 0 && rect.height > 0;
    } catch (error) {
      return false;
    }
  };
  const sheet = document.getElementById("gridlyPortraitV2Sheet");
  const sheetBody = document.getElementById("gridlyPortraitV2SheetBody");
  const backdrop = document.getElementById("gridlyPortraitV2SheetBackdrop");
  const legacyHazardPanel = document.getElementById("gridlyHazardPanel");

  safeTrace("portrait-v2-use-location-success-close-start", {
    source: "use-my-location-post-submit",
    sheetVisible: safeIsVisible(sheet),
    backdropVisible: safeIsVisible(backdrop),
    hazardPanelVisible: Boolean(legacyHazardPanel?.classList.contains("visible")) && safeIsVisible(legacyHazardPanel)
  });

  const fallbackClose = () => {
    if (sheet) {
      sheet.hidden = true;
      sheet.removeAttribute("data-active-sheet");
      sheet.style.display = "none";
      sheet.style.pointerEvents = "none";
      sheet.style.transform = "translate3d(0, 100%, 0)";
      sheet.style.translate = "0 100%";
      sheet.classList.remove("visible", "is-open", "active", "open");
      sheet.classList.add("is-closing", "is-closed");
    }
    if (sheetBody) {
      sheetBody.hidden = true;
      sheetBody.classList.remove("visible", "is-open", "active", "open");
    }
    if (backdrop) {
      backdrop.hidden = true;
      backdrop.style.display = "none";
      backdrop.style.pointerEvents = "none";
      backdrop.classList.remove("visible", "is-open", "active", "open");
    }
    document.body.classList.remove("modal-open", "report-pulse", "portrait-alerts-open");
    if (typeof updateReportingState === "function") {
      updateReportingState({ reportModeActive: false, placementModeActive: false });
    }
  };

  if (typeof window.closePortraitV2Sheet === "function") {
    try {
      window.closePortraitV2Sheet();
    } catch (error) {
      console.warn("Gridly Portrait V2 sheet close helper failed; applying fallback close", error);
      fallbackClose();
    }
  } else {
    fallbackClose();
  }

  if (legacyHazardPanel?.classList.contains("visible")) legacyHazardPanel.classList.remove("visible");
  safeTrace("portrait-v2-use-location-success-close-complete", {
    source: "use-my-location-post-submit",
    sheetVisible: safeIsVisible(sheet),
    backdropVisible: safeIsVisible(backdrop),
    hazardPanelVisible: Boolean(legacyHazardPanel?.classList.contains("visible")) && safeIsVisible(legacyHazardPanel)
  });
}

window.submitHazardNearMe = function (hazardType) {
  lastMobileReportSubmitDebug.lastSubmitAttempt = "use_my_location_clicked";
  markReportActionCompletionAudit({
    reportUseLocationAttempted: true,
    reportUseLocationSubmitted: false,
    reportUseLocationError: "",
    lastReportAction: "report-use-location",
    lastReportActionCompleted: false
  });
  const resolved = resolveRoadHazardReportTypeForAction(
    hazardType || reportingState.selectedHazardType || selectedQuickHazardType || pendingHazardPlacement,
    { announceDefault: true }
  );
  const selectedType = resolved.type;
  selectedQuickHazardType = selectedType;
  pendingHazardPlacement = null;

  if (reportingState.submissionInProgress || reportingState.locationLookupInProgress) return;

  if (!navigator.geolocation) {
    const message = "Location is unavailable. Select a spot on the map to submit this hazard.";
    markReportActionCompletionAudit({ reportUseLocationError: message, lastReportActionCompleted: false });
    updateReportingState({ lastReportError: message, lastReportMessage: "" });
    setConfirmation(message, "error");
    return;
  }

  const hazardCopy = HAZARD_TYPES[selectedType] || HAZARD_TYPES.other_hazard;

  updateReportingState({
    activeReportEntryPoint: "hazard_use_my_location",
    locationLookupInProgress: true,
    lastReportError: "",
    lastReportMessage: "Getting your location..."
  });
  setConfirmation("Getting your location...", "info");

  recordGridlyGeolocationRequest("hazard_use_my_location");
  navigator.geolocation.getCurrentPosition(
    async (position) => {
      try {
        const lat = Number(position?.coords?.latitude);
        const lng = Number(position?.coords?.longitude);
        if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
          throw new Error("invalid_geolocation_coordinates");
        }

        const snapped = await snapHazardToRoad(lat, lng, { source: "use_my_location" });
        if (snapped.invalid) {
          const message = "No nearby roadway found. Move closer to a road or tap a road on the map.";
          lastRoadSnapDebug.rawHazardCoordinatesBlockedWhenInvalid = true;
          markReportActionCompletionAudit({ reportUseLocationError: message, lastReportActionCompleted: false });
          setConfirmation("We couldn't place that hazard on a nearby road. Move closer to a roadway or tap a road on the map.", "error");
          updateReportingState({ locationLookupInProgress: false, lastReportError: message, lastReportMessage: "" });
          return;
        }
        const finalPlacement = gridlyCoordinateFromRecord(snapped.finalPlacementCoordinate) || { lat: snapped.lat, lng: snapped.lng };
        lastMobileReportSubmitDebug.rawTapCoordinate = snapped.rawTapCoordinate || { lat, lng };
        lastMobileReportSubmitDebug.originalTapCoords = snapped.rawTapCoordinate || { lat, lng };
        lastMobileReportSubmitDebug.snappedCoords = snapped.snappedRoadCoordinate || { lat: snapped.lat, lng: snapped.lng };
        lastMobileReportSubmitDebug.snappedRoadCoordinate = snapped.snappedRoadCoordinate || { lat: snapped.lat, lng: snapped.lng };
        lastMobileReportSubmitDebug.finalPlacementCoordinate = finalPlacement;
        lastMobileReportSubmitDebug.renderedMarkerCoordinate = finalPlacement;
        lastMobileReportSubmitDebug.activeSubmitCoords = finalPlacement;
        lastMobileReportSubmitDebug.coordinateSourceUsed = snapped.placementMode || "road_aware_use_my_location";
        lastMobileReportSubmitDebug.placementMode = snapped.placementMode || "road_snapped";
        lastMobileReportSubmitDebug.placementRiskLevel = snapped.placementRiskLevel || "medium";
        lastMobileReportSubmitDebug.tapToSnapDeltaMeters = snapped.tapToSnapDeltaMeters ?? null;
        lastMobileReportSubmitDebug.tapToFinalDeltaMeters = snapped.tapToFinalDeltaMeters ?? null;
        lastMobileReportSubmitDebug.snapToFinalDeltaMeters = snapped.snapToFinalDeltaMeters ?? null;
        lastMobileReportSubmitDebug.roadCandidateCount = snapped.roadCandidateCount ?? null;
        lastMobileReportSubmitDebug.nearestCandidateDistanceMeters = snapped.nearestCandidateDistanceMeters ?? null;
        lastMobileReportSubmitDebug.placementCoordinateReason = snapped.representativeCoordinateReason || "Road-aware placement selected the final hazard marker coordinate from GPS and nearest road candidate.";
        const submitted = await createSharedHazardReport(selectedType, finalPlacement.lat, finalPlacement.lng, "gps hazard report", "", snapped.originalTapCoords);
        if (!submitted) {
          markReportActionCompletionAudit({
            reportUseLocationError: reportingState.lastReportError || lastMobileReportSubmitDebug.lastSubmitError || "Hazard report was not submitted.",
            lastReportActionCompleted: false
          });
          return;
        }
        markReportActionCompletionAudit({
          reportUseLocationSubmitted: true,
          reportUseLocationCompleted: true,
          reportUseLocationError: "",
          lastReportAction: "report-use-location",
          lastReportActionCompleted: true,
          lastReportCompletionState: "success"
        });

        try {
          if (map) {
            map.setView([finalPlacement.lat, finalPlacement.lng], 16);
          }

          resetQuickHazardReportState();
          closeVisiblePortraitV2ReportSurfaceAfterSubmit();
          closeHazardPanel({ preserveLastReportMessage: true });
          setConfirmation("Report accepted and shared.", "success");
          updateReportingState({
            locationLookupInProgress: false,
            submissionInProgress: false,
            lastReportError: "",
            lastReportMessage: "Report added"
          });
        } catch (cleanupError) {
          console.warn("Gridly Use My Location post-submit cleanup warning", cleanupError);
          lastMobileReportSubmitDebug.postSubmitUiResetSucceeded = false;
          lastMobileReportSubmitDebug.lastSubmitAttempt = "use_my_location_cleanup_warning";
          lastMobileReportSubmitDebug.lastSubmitError = "";
          markReportActionCompletionAudit({
            reportUseLocationSubmitted: true,
            reportUseLocationCompleted: true,
            reportUseLocationError: "",
            lastReportAction: "report-use-location",
            lastReportActionCompleted: true,
            lastReportCompletionState: "success"
          });
          updateReportingState({
            locationLookupInProgress: false,
            submissionInProgress: false,
            lastReportError: "",
            lastReportMessage: "Report added"
          });
          setConfirmation("Report accepted and shared.", "success");
        }
      } catch (error) {
        const message = error?.message || "Hazard report was not submitted.";
        markReportActionCompletionAudit({ reportUseLocationError: message, lastReportActionCompleted: false });
        updateReportingState({ locationLookupInProgress: false, submissionInProgress: false, lastReportError: message, lastReportMessage: "" });
        setConfirmation(`Hazard report failed: ${message}`, "error");
      }
    },
    () => {
      const message = "We couldn't access your location. Allow GPS or tap the map to place this hazard.";
      markReportActionCompletionAudit({ reportUseLocationError: message, lastReportActionCompleted: false });
      updateReportingState({
        locationLookupInProgress: false,
        lastReportError: message,
        lastReportMessage: ""
      });
      setConfirmation(message, "error");
    },
    {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 15000
    }
  );
};

function beginRoadHazardMapPlacement(hazardType, options = {}) {
  const source = options.source || "unknown";
  markReportActionCompletionAudit({
    reportTapMapAttempted: true,
    reportTapMapPlacementArmed: false,
    reportTapMapError: "",
    lastReportAction: "report-tap-map",
    lastReportActionCompleted: false
  });
  pushTapMapTrace("placement_requested", { source, hazardType: hazardType || null });
  const resolved = resolveRoadHazardReportTypeForAction(
    hazardType || selectedV2HazardType || reportingState.selectedHazardType || selectedQuickHazardType || pendingHazardPlacement,
    { announceDefault: true }
  );
  const resolvedHazardType = resolved.type;
  if (!resolvedHazardType || !HAZARD_TYPES[resolvedHazardType]) {
    const err = "Choose a hazard first, then tap map location.";
    lastRoadHazardPlacementError = err;
    markReportActionCompletionAudit({ reportTapMapError: err, lastReportActionCompleted: false });
    pushTapMapTrace("hazard_type_validation_failed", { source, hazardType: resolvedHazardType || null, reason: "invalid_hazard_type" });
    updateReportingState({ lastReportError: err, lastReportMessage: "" });
    setConfirmation(err, "error");
    return false;
  }
  pushTapMapTrace("hazard_type_validated", { source, hazardType: resolvedHazardType });
  lastRoadHazardPlacementSource = source;
  lastRoadHazardPlacementError = null;
  pendingHazardPlacement = resolvedHazardType;
  selectedQuickHazardType = resolvedHazardType;
  pushTapMapTrace("surface_teardown_started", { source });
  const v2Backdrop = document.getElementById("gridlyPortraitV2SheetBackdrop");
  if (v2Backdrop) {
    v2Backdrop.hidden = true;
    v2Backdrop.style.pointerEvents = "none";
  }
  const v2Sheet = document.getElementById("gridlyPortraitV2Sheet");
  if (v2Sheet) {
    v2Sheet.hidden = true;
    v2Sheet.style.pointerEvents = "none";
  }
  document.getElementById("gridlyHazardPanel")?.classList.remove("visible");
  document.getElementById("gridlyMobileRouteQuickPanel")?.classList.remove("visible");
  document.body.classList.remove("modal-open", "report-pulse", "portrait-alerts-open");
  pushTapMapTrace("surface_teardown_completed", { source, v2SheetHidden: Boolean(v2Sheet?.hidden), v2BackdropHidden: Boolean(v2Backdrop?.hidden) });
  lastMobileReportSubmitDebug.lastSubmitAttempt = "tap_map_mode_selected";
  setReportMode(REPORT_MODES.roadHazard);
  updateReportingState({
    selectedHazardType: resolvedHazardType,
    placementModeActive: true,
    reportModeActive: true,
    activeReportEntryPoint: "hazard_tap_map"
  });
  if (typeof suppressGlobalMapPopupsUntil === "number") suppressGlobalMapPopupsUntil = Date.now() + 2500;
  updateReportingState({
    lastReportError: "",
    lastReportMessage: "Tap a road to place this hazard."
  });
  setConfirmation("Tap a road to place this hazard.", "info");
  markReportActionCompletionAudit({
    reportTapMapPlacementArmed: true,
    reportTapMapCompleted: true,
    reportTapMapError: "",
    lastReportAction: "report-tap-map",
    lastReportActionCompleted: true,
    lastReportCompletionState: "armed"
  });
  pushTapMapTrace("placement_armed", { source, hazardType: pendingHazardPlacement });
  return true;
}

function openHazardPlacement(hazardType, options = {}) {
  return beginRoadHazardMapPlacement(hazardType, options.source ? options : { ...options, source: "openHazardPlacement" });
}
