window.gridlyPortraitV2HitboxAudit = function gridlyPortraitV2HitboxAudit() {
  const actions = ["report-use-location", "report-tap-map"];
  const selectedHazardButtons = Array.from(document.querySelectorAll('#gridlyPortraitV2SheetBody [data-v2-action="report-select-hazard"].is-selected'));
  const selectedHazardButtonText = selectedHazardButtons.map((button) => (button.textContent || "").trim()).filter(Boolean);
  const reportingStateSelectedHazardType = (typeof reportingState === "object" && reportingState ? reportingState.selectedHazardType : null) || null;
  const ctaDisabledReason = reportingStateSelectedHazardType ? "" : "hazard_type_not_selected";
  const summarizeNode = (node) => {
    if (!(node instanceof Element)) return null;
    return {
      tag: node.tagName.toLowerCase(),
      class: node.className || null,
      id: node.id || null,
      text: (node.textContent || "").trim().slice(0, 140) || null
    };
  };
  const auditRows = actions.map((action) => {
    const button = document.querySelector(`#gridlyPortraitV2SheetBody [data-v2-action="${action}"]`);
    if (!(button instanceof HTMLButtonElement)) return { action, found: false };
    const style = getComputedStyle(button);
    const rect = button.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const topNode = rect.width > 0 && rect.height > 0 ? document.elementFromPoint(centerX, centerY) : null;
    const centerTargetsButton = Boolean(topNode && (topNode === button || button.contains(topNode)));
    return {
      text: (button.textContent || "").trim(),
      dataV2Action: button.getAttribute("data-v2-action") || null,
      visible: style.display !== "none" && style.visibility !== "hidden" && Number(style.opacity || "1") > 0 && rect.width > 0 && rect.height > 0,
      disabled: Boolean(button.disabled || button.getAttribute("aria-disabled") === "true"),
      rect: {
        top: Math.round(rect.top),
        left: Math.round(rect.left),
        width: Math.round(rect.width),
        height: Math.round(rect.height),
        right: Math.round(rect.right),
        bottom: Math.round(rect.bottom)
      },
      pointerEvents: style.pointerEvents,
      zIndex: style.zIndex,
      elementFromPoint: summarizeNode(topNode),
      elementFromPointIsButtonOrInside: centerTargetsButton,
      blockingElement: centerTargetsButton ? null : summarizeNode(topNode)
    };
  });
  return {
    sheetHidden: Boolean(document.getElementById("gridlyPortraitV2Sheet")?.hidden),
    ctaDisabledReason,
    reportingStateSelectedHazardType,
    selectedHazardButtonCount: selectedHazardButtons.length,
    selectedHazardButtonText,
    auditRows
  };
};

async function handleHazardPlacementMapClick(event) {
  if (!reportingState.placementModeActive) return;
  if (!pendingHazardPlacement && !reportingState.selectedHazardType) return;
  const clickReceivedAtPerformance = gridlyNowMs();
  const rawLeafletLatLng = gridlyCloneCoordinate(event?.latlng);
  const fallbackPointerClient = gridlyReadPointerClientFromEvent(event);
  const fallbackContainerPointLatLng = gridlyCloneCoordinate(gridlyConvertClientPointToMapLatLng(fallbackPointerClient));
  const pointerCaptureAgeMs = latestTapMapPointerCapture?.capturedAtPerformance
    ? clickReceivedAtPerformance - latestTapMapPointerCapture.capturedAtPerformance
    : Infinity;
  const pointerCapture = latestTapMapPointerCapture
    && Number.isFinite(pointerCaptureAgeMs)
    && pointerCaptureAgeMs >= -25
    && pointerCaptureAgeMs <= 1500
    ? latestTapMapPointerCapture
    : null;
  const immediateCoordinate = gridlyCloneCoordinate(pointerCapture?.containerPointLatLng) || fallbackContainerPointLatLng;
  const leafletCoordinate = rawLeafletLatLng;
  const selectedCoordinate = immediateCoordinate || leafletCoordinate;
  if (!selectedCoordinate) return;
  const selectedType = pendingHazardPlacement || reportingState.selectedHazardType;
  const rawTapCoordinate = gridlyStartTapMapPlacementAccuracyCapture(selectedCoordinate, selectedType, {
    pointerCapture,
    rawPointerClient: pointerCapture?.rawPointerClient || fallbackPointerClient,
    containerPointLatLng: immediateCoordinate,
    rawLeafletLatLng,
    clickReceivedAtPerformance
  }) || selectedCoordinate;
  pushTapMapTrace("map_click_received", {
    lat: rawTapCoordinate.lat,
    lng: rawTapCoordinate.lng,
    hazardType: selectedType,
    source: lastRoadHazardPlacementSource,
    coordinateSourceUsed: tapMapPlacementAccuracyState.coordinateSourceUsed,
    rawPointerClient: tapMapPlacementAccuracyState.rawPointerClient,
    rawLeafletLatLng: tapMapPlacementAccuracyState.rawLeafletLatLng,
    containerPointLatLng: tapMapPlacementAccuracyState.containerPointLatLng,
    pointerCaptureAgeMs: tapMapPlacementAccuracyState.pointerCaptureAgeMs
  });
  lastMobileReportSubmitDebug.originalTapCoords = { ...rawTapCoordinate };
  lastMobileReportSubmitDebug.rawTapCoordinate = { ...rawTapCoordinate };
  lastMobileReportSubmitDebug.lastSubmitAttempt = "tap_captured";
  lastMobileReportSubmitDebug.coordinateSourceUsed = "raw_tap_coordinate";
  pushTapMapTrace("snap_started", { lat: rawTapCoordinate.lat, lng: rawTapCoordinate.lng, coordinatePreservedForSubmission: true });
  const snapped = await snapHazardToRoad(rawTapCoordinate.lat, rawTapCoordinate.lng, { source: "tap_map" });
  if (snapped.invalid) {
    const message = "Tap closer to a road to place this hazard.";
    updateReportingState({ placementModeActive: true });
    lastRoadSnapDebug.rawHazardCoordinatesBlockedWhenInvalid = true;
    markReportActionCompletionAudit({ reportTapMapError: message, lastReportActionCompleted: false });
    setConfirmation("Hazard location must be near a road. Tap closer to a roadway.", "error");
    updateReportingState({ lastReportError: message, lastReportMessage: "" });
    pushTapMapTrace("snap_failed", { reason: "no_nearby_road" });
    return;
  }
  const resolvedRoadCoordinate = gridlyCoordinateFromRecord(snapped.snappedRoadCoordinate) || gridlyCoordinateFromRecord(snapped.projectionCoordinate) || { lat: snapped.lat, lng: snapped.lng };
  const submittedReportCoordinate = { ...rawTapCoordinate };
  const finalPlacement = submittedReportCoordinate;
  pushTapMapTrace("snap_succeeded", { lat: resolvedRoadCoordinate?.lat ?? snapped.lat, lng: resolvedRoadCoordinate?.lng ?? snapped.lng, placementMode: snapped.placementMode, placementRiskLevel: snapped.placementRiskLevel, submittedLat: submittedReportCoordinate.lat, submittedLng: submittedReportCoordinate.lng, coordinateSourceUsed: "raw_tap_coordinate" });
  lastMobileReportSubmitDebug.rawTapCoordinate = { ...rawTapCoordinate };
  lastMobileReportSubmitDebug.originalTapCoords = { ...rawTapCoordinate };
  lastMobileReportSubmitDebug.snappedCoords = resolvedRoadCoordinate ? { ...resolvedRoadCoordinate } : null;
  lastMobileReportSubmitDebug.snappedRoadCoordinate = resolvedRoadCoordinate ? { ...resolvedRoadCoordinate } : null;
  lastMobileReportSubmitDebug.roadResolverDiagnosticCoordinate = resolvedRoadCoordinate ? { ...resolvedRoadCoordinate } : null;
  lastMobileReportSubmitDebug.finalPlacementCoordinate = { ...submittedReportCoordinate };
  lastMobileReportSubmitDebug.renderedMarkerCoordinate = { ...submittedReportCoordinate };
  lastMobileReportSubmitDebug.activeSubmitCoords = { ...submittedReportCoordinate };
  lastMobileReportSubmitDebug.snapComplete = true;
  lastMobileReportSubmitDebug.coordinateSourceUsed = "raw_tap_coordinate";
  lastMobileReportSubmitDebug.placementMode = snapped.placementMode || "raw_tap_preserved_user_intent";
  lastMobileReportSubmitDebug.placementRiskLevel = snapped.placementRiskLevel || "medium";
  lastMobileReportSubmitDebug.tapToSnapDeltaMeters = snapped.tapToSnapDeltaMeters ?? gridlyCoordinateDeltaMeters(rawTapCoordinate, resolvedRoadCoordinate);
  lastMobileReportSubmitDebug.tapToFinalDeltaMeters = gridlyCoordinateDeltaMeters(rawTapCoordinate, submittedReportCoordinate);
  lastMobileReportSubmitDebug.snapToFinalDeltaMeters = gridlyCoordinateDeltaMeters(resolvedRoadCoordinate, submittedReportCoordinate);
  lastMobileReportSubmitDebug.resolverAttemptedReplacementDeltaMeters = lastMobileReportSubmitDebug.snapToFinalDeltaMeters;
  lastMobileReportSubmitDebug.resolverAttemptedCoordinateReplacement = Boolean(Number.isFinite(lastMobileReportSubmitDebug.snapToFinalDeltaMeters) && lastMobileReportSubmitDebug.snapToFinalDeltaMeters > 0.5);
  lastMobileReportSubmitDebug.roadCandidateCount = snapped.roadCandidateCount ?? null;
  lastMobileReportSubmitDebug.nearestCandidateDistanceMeters = snapped.nearestCandidateDistanceMeters ?? null;
  lastMobileReportSubmitDebug.projectionCoordinate = snapped.projectionCoordinate || null;
  lastMobileReportSubmitDebug.selectedRoadName = snapped.selectedRoadName || null;
  lastMobileReportSubmitDebug.selectedSegmentDistanceMeters = snapped.selectedSegmentDistanceMeters ?? null;
  lastMobileReportSubmitDebug.recommendedDirection = snapped.recommendedDirection || null;
  lastMobileReportSubmitDebug.selectedSideConfidence = snapped.selectedSideConfidence || "low";
  lastMobileReportSubmitDebug.geometryAwarePlacementAvailable = Boolean(snapped.geometryAwarePlacementAvailable);
  lastMobileReportSubmitDebug.placementCoordinateReason = lastMobileReportSubmitDebug.resolverAttemptedCoordinateReplacement
    ? "Tap Map placement blocked a road resolver coordinate replacement; final submitted coordinate remains the raw tap coordinate."
    : "Tap Map placement submits the raw tap coordinate; road resolution is retained as diagnostic context only.";
  lastMobileReportSubmitDebug.lastSubmitAttempt = "snap_completed";
  gridlyFinishTapMapPlacementAccuracyCapture({
    submittedReportCoordinate,
    renderedMarkerCoordinate: submittedReportCoordinate,
    resolvedRoadCoordinate,
    finding: "road resolver completed without replacing the report coordinate",
    coordinateRendered: false
  });
  pushTapMapTrace("submit_started", { hazardType: selectedType, coordinateSourceUsed: lastMobileReportSubmitDebug.coordinateSourceUsed });
  const submitted = await createSharedHazardReport(selectedType, finalPlacement.lat, finalPlacement.lng, "tap map placement", "", rawTapCoordinate, {
    deferPostSubmitUiReset: true,
    tapMapUserSelectedCoordinate: finalPlacement,
    resolvedRoadCoordinate
  });
  if (!submitted) {
    const message = reportingState.lastReportError || lastMobileReportSubmitDebug.lastSubmitError || "Hazard report was not submitted.";
    updateReportingState({ placementModeActive: true });
    markReportActionCompletionAudit({ reportTapMapError: message, lastReportActionCompleted: false });
    pushTapMapTrace("submit_failed", { hazardType: selectedType, reason: "create_report_failed" });
    return;
  }
  markReportActionCompletionAudit({
    reportTapMapSubmitted: true,
    reportTapMapCompleted: true,
    reportTapMapError: "",
    lastReportAction: "report-tap-map",
    lastReportActionCompleted: true,
    lastReportCompletionState: "submitted"
  });
  pushTapMapTrace("submit_succeeded", { hazardType: selectedType });
  if (map) {
    L.circleMarker([finalPlacement.lat, finalPlacement.lng], { radius: 4, color: "#8fb6ff", weight: 1, fillOpacity: 0.3, opacity: 0.8 })
      .addTo(unifiedIncidentLayer)
      .bindTooltip("Tap", { permanent: false, direction: "top" });
  }
  gridlyFinishTapMapPlacementAccuracyCapture({
    submittedReportCoordinate: finalPlacement,
    renderedMarkerCoordinate: finalPlacement,
    resolvedRoadCoordinate,
    finding: "submitted and rendered coordinates remained locked to the raw tap coordinate",
    monitoringComplete: true
  });
  setConfirmation("Hazard placed at the intended roadway location", "success");
  updateReportingState({ placementModeActive: false, reportModeActive: false, selectedHazardType: null });
  selectedOtherHazardSubtype = "";
  resetQuickHazardReportState();
  closeHazardPanel({ preserveLastReportMessage: true });
  returnMobileToLiveMode("submit_hazard_success");
  lastMobileReportSubmitDebug.postSubmitUiResetSucceeded = true;
  lastMobileReportSubmitDebug.lastSubmitAttempt = "ui_reset_complete_after_tap_map_coordinate_lock";
  gridlyFinishTapMapPlacementAccuracyCapture({
    submittedReportCoordinate: finalPlacement,
    renderedMarkerCoordinate: finalPlacement,
    resolvedRoadCoordinate,
    finding: "post-submit sheet and map container state recorded after coordinate lock",
    monitoringComplete: true,
    afterCoordinateLockCleanup: true
  });
  pushTapMapTrace("placement_mode_cleared_restored", { outcome: "success" });
}

function gridlyRoundAuditMeters(value) {
  return Number.isFinite(Number(value)) ? Math.round(Number(value) * 10) / 10 : null;
}

function gridlyBuildRoadAwareHazardPlacement(rawCoordinate, snappedCoordinate, options = {}) {
  const raw = gridlyCoordinateFromRecord(rawCoordinate);
  const snapped = gridlyCoordinateFromRecord(snappedCoordinate);
  const rawFallback = raw || snapped || null;
  const SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS = 75;
  const CLEARLY_UNREASONABLE_SNAP_DISTANCE_METERS = 90;
  const LOW_CONFIDENCE_DISTANCE_LIMIT_METERS = 35;
  const AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS = 35;
  const geometryDecision = raw && typeof gridlyGeometryAwarePlacementDecision === "function"
    ? gridlyGeometryAwarePlacementDecision(raw, { maxDistanceMeters: options.maxDistanceMeters || SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS, limit: options.limit || 16 })
    : null;
  const selectedSegment = options.selectedRoadwaySegment
    || options.selectedSegment
    || options.geometryAwarePlacement?.selectedSegment
    || geometryDecision?.selectedSegment
    || null;
  const projected = gridlyCoordinateFromRecord(options.projectedCoordinate)
    || gridlyCoordinateFromRecord(options.projectionCoordinate)
    || gridlyCoordinateFromRecord(selectedSegment?.candidateCoordinate)
    || null;
  const selectedRoadNameRaw = String(options.selectedRoadName || selectedSegment?.roadName || "").trim();
  const selectedRoadName = /^(unknown|unknown road)$/i.test(selectedRoadNameRaw) ? "" : selectedRoadNameRaw;
  const projectionSource = String(options.projectionSource || selectedSegment?.source || (projected ? "local_roadway_dataset_geometry" : snapped ? "existing_road_aware_snap_logic" : "")).trim();
  const projectionFromTrustedRoadLogic = projectionSource === "local_roadway_dataset_geometry"
    || projectionSource === "existing_road_aware_snap_logic"
    || /road_aware|geometry|snap/i.test(projectionSource);
  const candidateDistance = Number.isFinite(Number(options.nearestCandidateDistanceMeters))
    ? Number(options.nearestCandidateDistanceMeters)
    : Number.isFinite(Number(selectedSegment?.distanceFromTapMeters))
      ? Number(selectedSegment.distanceFromTapMeters)
      : gridlyCoordinateDeltaMeters(raw, projected || snapped);
  const roadCandidateCount = Number.isFinite(Number(options.roadCandidateCount))
    ? Number(options.roadCandidateCount)
    : Number.isFinite(Number(geometryDecision?.candidateCount)) ? Number(geometryDecision.candidateCount) : 0;
  const geometryCandidateDistances = Array.isArray(geometryDecision?.candidateSegments)
    ? geometryDecision.candidateSegments.map((candidate) => Number(candidate?.distanceFromTapMeters)).filter(Number.isFinite)
    : [];
  const closeCandidateDistances = (Array.isArray(options.candidateDistancesMeters) && options.candidateDistancesMeters.length
    ? options.candidateDistancesMeters
    : geometryCandidateDistances)
    .map((distance) => Number(distance)).filter(Number.isFinite).sort((a, b) => a - b);
  const closestDistance = Number.isFinite(candidateDistance) ? candidateDistance : (Number.isFinite(closeCandidateDistances[0]) ? closeCandidateDistances[0] : null);
  const secondDistance = closeCandidateDistances.find((distance, index) => index > 0 && Number.isFinite(distance));
  const candidateDistanceGapMeters = Number.isFinite(closestDistance) && Number.isFinite(secondDistance)
    ? Math.abs(secondDistance - closestDistance)
    : (Number.isFinite(Number(options.candidateDistanceGapMeters)) ? Number(options.candidateDistanceGapMeters) : Number.isFinite(Number(geometryDecision?.candidateDistanceGapMeters)) ? Number(geometryDecision.candidateDistanceGapMeters) : null);
  const selectedSideConfidence = options.selectedSideConfidence || options.geometryAwarePlacement?.selectedSideConfidence || geometryDecision?.selectedSideConfidence || "low";
  const parallelRoadRisk = Boolean(options.parallelRoadRisk)
    || roadCandidateCount > 1
      && Number.isFinite(closestDistance)
      && Number.isFinite(secondDistance)
      && secondDistance <= AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS
      && Number.isFinite(candidateDistanceGapMeters)
      && candidateDistanceGapMeters <= 4;
  const dividedRoadRisk = Boolean(options.dividedRoadRisk || options.geometryAwarePlacement?.dividedRoadRisk || geometryDecision?.dividedRoadRisk || parallelRoadRisk);
  const decisionRulesEvaluated = [];
  const decisionTrace = [];
  const recordDecisionRule = (rule, passed, details = {}) => {
    const entry = { rule, passed: Boolean(passed), ...details };
    decisionRulesEvaluated.push(entry);
    decisionTrace.push(`${rule}: ${entry.passed ? "passed" : "failed"}${details.reason ? ` (${details.reason})` : ""}`);
    return entry.passed;
  };

  const placementSource = String(options.source || options.placementSource || "").trim();
  const preserveTapMapUserIntent = placementSource === "tap_map";

  let finalCoordinate = rawFallback;
  let placementMode = preserveTapMapUserIntent ? "raw_tap_preserved_user_intent" : "raw_tap_no_candidate";
  let placementRiskLevel = "medium";
  let representativeCoordinateReason = preserveTapMapUserIntent
    ? "Tap Map placement preserves the user's raw tap coordinate; roadway projection is retained only as diagnostic context."
    : "No usable roadway candidate was available, so Gridly preserved the original tap coordinate.";
  let finalDecisionOwner = preserveTapMapUserIntent
    ? "gridlyBuildRoadAwareHazardPlacement:raw_tap_preserved_user_intent"
    : "gridlyBuildRoadAwareHazardPlacement:default_raw_fallback";
  let rejectionReason = preserveTapMapUserIntent ? "tap_map_user_intent_preserved" : null;

  const hasSelectedRoadwaySegment = recordDecisionRule("selected_roadway_segment_exists", Boolean(selectedSegment), {
    reason: selectedSegment ? "local roadway dataset selected a segment for this tap" : "no selected roadway segment is available"
  });
  const hasProjectedCoordinate = recordDecisionRule("projected_coordinate_exists", Boolean(projected), {
    reason: projected ? "geometry-derived projection coordinate is available" : "projection coordinate is missing"
  });
  const hasSelectedRoadName = recordDecisionRule("selected_road_name_exists", Boolean(selectedRoadName), {
    selectedRoadName: selectedRoadName || null,
    reason: selectedRoadName ? "selected segment has a road name" : "selected segment road name is missing"
  });
  const hasFiniteDistance = recordDecisionRule("nearest_candidate_distance_available", Number.isFinite(closestDistance), {
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    reason: Number.isFinite(closestDistance) ? "nearest candidate distance is finite" : "nearest candidate distance is unavailable"
  });
  const trustedProjectionSource = recordDecisionRule("trusted_projection_source", projectionFromTrustedRoadLogic, {
    projectionSource: projectionSource || null,
    reason: projectionFromTrustedRoadLogic ? "projection came from local roadway geometry or existing road-aware snap logic" : "projection source is not a trusted roadway snap/projection source"
  });
  const withinExpandedThreshold = recordDecisionRule("snap_distance_within_expanded_roadway_threshold", Number.isFinite(closestDistance) && closestDistance <= SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS, {
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    distanceThreshold: SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS,
    reason: Number.isFinite(closestDistance)
      ? `candidate is ${gridlyRoundAuditMeters(closestDistance)}m from tap; expanded roadway threshold is ${SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS}m`
      : "candidate distance is unavailable"
  });
  const clearlyUnreasonableDistance = recordDecisionRule("reject_when_snap_distance_clearly_unreasonable", Number.isFinite(closestDistance) && closestDistance > CLEARLY_UNREASONABLE_SNAP_DISTANCE_METERS, {
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    distanceThreshold: CLEARLY_UNREASONABLE_SNAP_DISTANCE_METERS,
    reason: Number.isFinite(closestDistance)
      ? `candidate is ${gridlyRoundAuditMeters(closestDistance)}m from tap; clearly unreasonable threshold is ${CLEARLY_UNREASONABLE_SNAP_DISTANCE_METERS}m`
      : "candidate distance is unavailable"
  });
  const lowConfidenceTooLarge = recordDecisionRule("reject_when_geometry_confidence_low_and_distance_too_large", selectedSideConfidence === "low" && Number.isFinite(closestDistance) && closestDistance > LOW_CONFIDENCE_DISTANCE_LIMIT_METERS, {
    selectedSideConfidence,
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    distanceThreshold: LOW_CONFIDENCE_DISTANCE_LIMIT_METERS,
    reason: selectedSideConfidence === "low" && Number.isFinite(closestDistance)
      ? `low geometry confidence with candidate ${gridlyRoundAuditMeters(closestDistance)}m from tap; low-confidence threshold is ${LOW_CONFIDENCE_DISTANCE_LIMIT_METERS}m`
      : "low-confidence distance rejection did not apply"
  });
  const ambiguousBeyondSafeThreshold = recordDecisionRule("reject_when_divided_road_ambiguous_beyond_safe_threshold", dividedRoadRisk && selectedSideConfidence === "low" && Number.isFinite(closestDistance) && closestDistance > AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS, {
    dividedRoadRisk,
    selectedSideConfidence,
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    distanceThreshold: AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS,
    candidateDistanceGapMeters: gridlyRoundAuditMeters(candidateDistanceGapMeters),
    reason: dividedRoadRisk && selectedSideConfidence === "low" && Number.isFinite(closestDistance)
      ? `divided-road candidate remains ambiguous ${gridlyRoundAuditMeters(closestDistance)}m from tap; ambiguity threshold is ${AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS}m`
      : "divided-road ambiguity rejection did not apply"
  });

  if (preserveTapMapUserIntent) {
    finalCoordinate = raw || rawFallback;
  } else if (!hasSelectedRoadwaySegment) {
    finalCoordinate = rawFallback;
    placementMode = "raw_tap_no_candidate";
    placementRiskLevel = "high";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:raw_tap_no_candidate";
    rejectionReason = "no_roadway_candidate";
  } else if (!hasProjectedCoordinate || !hasSelectedRoadName || !trustedProjectionSource || !hasFiniteDistance) {
    finalCoordinate = rawFallback;
    placementMode = "raw_tap_projection_missing";
    placementRiskLevel = "high";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:raw_tap_projection_missing";
    rejectionReason = !hasProjectedCoordinate ? "projection_missing" : !hasSelectedRoadName ? "selected_road_name_missing" : !trustedProjectionSource ? "untrusted_projection_source" : "candidate_distance_missing";
    representativeCoordinateReason = "A roadway segment was found, but the projection could not be safely validated, so Gridly preserved the tap coordinate.";
  } else if (clearlyUnreasonableDistance || !withinExpandedThreshold) {
    finalCoordinate = raw || rawFallback;
    placementMode = "raw_tap_snap_too_far";
    placementRiskLevel = "high";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:raw_tap_snap_too_far";
    rejectionReason = "candidate_too_far";
    representativeCoordinateReason = "The roadway projection was too far from the tap for a safe road-aware placement, so Gridly preserved the tap coordinate.";
  } else if (ambiguousBeyondSafeThreshold) {
    finalCoordinate = raw || rawFallback;
    placementMode = "raw_tap_divided_road_ambiguous";
    placementRiskLevel = "medium";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:raw_tap_divided_road_ambiguous";
    rejectionReason = "divided_road_ambiguous";
    representativeCoordinateReason = "Nearby divided-road geometry was still ambiguous beyond the safe threshold, so Gridly preserved the tap coordinate.";
  } else if (lowConfidenceTooLarge) {
    finalCoordinate = raw || rawFallback;
    placementMode = "raw_tap_snap_too_far";
    placementRiskLevel = "high";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:raw_tap_snap_too_far";
    rejectionReason = "low_confidence_distance_too_large";
    representativeCoordinateReason = "Geometry confidence was too low for a projection this far from the tap, so Gridly preserved the tap coordinate.";
  } else {
    finalCoordinate = projected;
    placementMode = "projected_point_used";
    placementRiskLevel = dividedRoadRisk ? "medium" : "low";
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:projected_point_used";
    representativeCoordinateReason = "Gridly used the geometry-derived roadway projection because the selected segment, road name, projection source, and snap distance were all safely validated.";
  }

  const resolverCandidateFinalCoordinate = preserveTapMapUserIntent ? (projected || snapped || finalCoordinate) : finalCoordinate;
  const resolverAttemptedReplacementDeltaMeters = gridlyCoordinateDeltaMeters(raw, resolverCandidateFinalCoordinate);
  const resolverAttemptedCoordinateReplacement = Boolean(preserveTapMapUserIntent && raw && resolverCandidateFinalCoordinate && Number.isFinite(resolverAttemptedReplacementDeltaMeters) && resolverAttemptedReplacementDeltaMeters > 0.5);
  if (preserveTapMapUserIntent) {
    finalCoordinate = raw || rawFallback;
    placementMode = "raw_tap_preserved_user_intent";
    placementRiskLevel = resolverAttemptedCoordinateReplacement ? "medium" : placementRiskLevel;
    finalDecisionOwner = "gridlyBuildRoadAwareHazardPlacement:tap_map_coordinate_lock";
    rejectionReason = "tap_map_user_intent_preserved";
    representativeCoordinateReason = resolverAttemptedCoordinateReplacement
      ? "Tap Map coordinate lock blocked the road resolver coordinate from replacing the user's selected coordinate; resolver coordinate is retained only as diagnostics."
      : "Tap Map placement preserves the user's raw tap coordinate; roadway projection is retained only as diagnostic context.";
  }

  const snapAccepted = !preserveTapMapUserIntent && placementMode === "projected_point_used";
  const snapRejected = placementMode.startsWith("raw_tap_") && placementMode !== "raw_tap_no_candidate";
  const snapRejectionDecisionAudit = {
    snapAccepted,
    snapRejected,
    projectionUsed: snapAccepted,
    resolverCandidateFinalCoordinate,
    resolverAttemptedCoordinateReplacement,
    resolverAttemptedReplacementDeltaMeters: gridlyRoundAuditMeters(resolverAttemptedReplacementDeltaMeters),
    rejectionReason,
    placementMode,
    decisionRulesEvaluated,
    decisionTrace,
    distanceThreshold: {
      expandedRoadwaySafeMeters: SAFE_EXPANDED_ROADWAY_THRESHOLD_METERS,
      clearlyUnreasonableSnapMeters: CLEARLY_UNREASONABLE_SNAP_DISTANCE_METERS,
      lowConfidenceDistanceLimitMeters: LOW_CONFIDENCE_DISTANCE_LIMIT_METERS,
      dividedRoadAmbiguousMeters: AMBIGUOUS_DIVIDED_ROAD_LIMIT_METERS,
      dividedRoadCandidateDistanceGapMaxMeters: 4
    },
    distanceActual: gridlyRoundAuditMeters(closestDistance),
    sameRoadCandidateCount: geometryDecision?.sameRoadCandidateCount ?? null,
    oppositeSideCandidateCount: geometryDecision?.oppositeSideCandidateCount ?? null,
    parallelRoadRisk,
    dividedRoadRisk,
    selectedSideConfidence,
    selectedRoadName: selectedRoadName || null,
    selectedSegmentDistanceMeters: selectedSegment?.distanceFromTapMeters ?? null,
    candidateDistanceGapMeters: gridlyRoundAuditMeters(candidateDistanceGapMeters),
    minimumConfidenceRequired: "low_allowed_with_distance_guardrails",
    confidenceMet: selectedSideConfidence !== "low" || !(Number.isFinite(closestDistance) && closestDistance > LOW_CONFIDENCE_DISTANCE_LIMIT_METERS),
    finalDecisionOwner
  };

  return {
    rawTapCoordinate: raw,
    snappedRoadCoordinate: snapped,
    projectedRoadCoordinate: projected,
    projectionCoordinate: projected,
    selectedRoadwaySegment: selectedSegment,
    selectedRoadName: selectedRoadName || null,
    selectedSideConfidence,
    selectedSegmentDistanceMeters: selectedSegment?.distanceFromTapMeters ?? null,
    recommendedDirection: options.recommendedDirection || options.geometryAwarePlacement?.recommendedDirection || geometryDecision?.recommendedDirection || null,
    geometryAwarePlacementAvailable: Boolean(selectedSegment),
    finalPlacementCoordinate: finalCoordinate,
    renderedMarkerCoordinate: finalCoordinate,
    tapToSnapDeltaMeters: gridlyCoordinateDeltaMeters(raw, snapped),
    tapToProjectionDeltaMeters: gridlyCoordinateDeltaMeters(raw, projected),
    tapToFinalDeltaMeters: gridlyCoordinateDeltaMeters(raw, finalCoordinate),
    snapToFinalDeltaMeters: gridlyCoordinateDeltaMeters(snapped, finalCoordinate),
    projectionToFinalDeltaMeters: gridlyCoordinateDeltaMeters(projected, finalCoordinate),
    placementMode,
    placementRiskLevel,
    roadCandidateCount,
    nearestCandidateDistanceMeters: gridlyRoundAuditMeters(closestDistance),
    representativeCoordinateReason,
    candidateDistancesMeters: closeCandidateDistances.map((distance) => gridlyRoundAuditMeters(distance)),
    candidateDistanceGapMeters: gridlyRoundAuditMeters(candidateDistanceGapMeters),
    parallelRoadRisk,
    dividedRoadRisk,
    projectionUsed: snapAccepted,
    snapAccepted,
    snapRejected,
    resolverCandidateFinalCoordinate,
    resolverAttemptedCoordinateReplacement,
    resolverAttemptedReplacementDeltaMeters: gridlyRoundAuditMeters(resolverAttemptedReplacementDeltaMeters),
    rejectionReason,
    decisionRulesEvaluated,
    decisionTrace,
    finalDecisionOwner,
    snapRejectionDecisionAudit
  };
}

async function snapHazardToRoad(lat, lng, options = {}) {
  const regionContext = { ...LOCATION_DEFAULTS };
  const snapAttemptRadii = [75, 150];
  const candidateRequestCount = 3;
  const debug = {
    originalTapCoords: { lat, lng },
    rawTapCoordinate: { lat, lng },
    snappedCoords: { lat, lng },
    snappedRoadCoordinate: null,
    finalPlacementCoordinate: { lat, lng },
    placementMode: "raw_tap",
    placementRiskLevel: "medium",
    representativeCoordinateReason: "Road snap has not completed yet.",
    roadCandidateCount: 0,
    nearestCandidateDistanceMeters: null,
    tapToSnapDeltaMeters: null,
    tapToFinalDeltaMeters: 0,
    snapToFinalDeltaMeters: null,
    snapAttemptRadii: [...snapAttemptRadii],
    finalSnapRadiusUsed: null,
    snapDistanceMeters: 0,
    candidateDistancesMeters: [],
    nearestRoadCandidates: [],
    nearestRoadFound: false,
    snapMethodUsed: "fallback_original_tap",
    fallbackUsed: true,
    fallbackReason: "nearest_no_result",
    osrmNearestUrl: "",
    osrmNearestStatus: null,
    regionContext,
    routeImpactDetected: false,
    hazardPlacementUsesCanonicalSnap: false,
    hazardPlacementUsesTapCoordinate: true,
    lastHazardPlacementSource: options?.source || "unknown",
    lastHazardSnapResult: "pending",
    rawHazardCoordinatesBlockedWhenInvalid: false
  };
  for (const radiusMeters of snapAttemptRadii) {
    try {
      pushAuditCall(gridlyNetworkAuditState.osrmNearest, options?.source || "hazard_snap", { radiusMeters, candidateRequestCount });
      gridlyNetworkAuditState.osrmNearest.inFlight += 1;
      const nearestUrl = `${OSRM_NEAREST_API}/${lng},${lat}?number=${candidateRequestCount}&radiuses=${radiusMeters}`;
      debug.osrmNearestUrl = nearestUrl;
      const response = await fetch(nearestUrl);
      debug.osrmNearestStatus = response.status;
      if (!response.ok) throw new Error(`nearest_failed_${response.status}`);
      const payload = await response.json();
      const candidates = Array.isArray(payload?.waypoints)
        ? payload.waypoints
          .filter((waypoint) => Array.isArray(waypoint?.location) && Number.isFinite(Number(waypoint.location[1])) && Number.isFinite(Number(waypoint.location[0])))
          .sort((a, b) => Number(a?.distance || 0) - Number(b?.distance || 0))
        : [];
      const diagnosticCandidates = candidates.map((candidate, index) => ({
        rank: index + 1,
        roadName: String(candidate?.name || candidate?.hint || "").trim() || "unknown",
        candidateCoordinate: { lat: Number(candidate?.location?.[1]), lng: Number(candidate?.location?.[0]) },
        distanceFromTapMeters: Number.isFinite(Number(candidate?.distance)) ? Math.round(Number(candidate.distance) * 10) / 10 : null,
        source: "osrm_nearest_v1_driving",
        bearing: null,
        inferredDirection: null,
        directionConfidence: "low"
      }));
      const nearest = candidates[0];
      const snappedLat = Number(nearest?.location?.[1]);
      const snappedLng = Number(nearest?.location?.[0]);
      if (!Number.isFinite(snappedLat) || !Number.isFinite(snappedLng)) throw new Error("nearest_no_geometry");
      const snapDistanceMeters = Number(nearest?.distance || 0);
      const geometryAwareSelection = gridlyGeometryAwarePlacementDecision({ lat, lng }, { maxDistanceMeters: radiusMeters, limit: 16 });
      const geometrySelectedCoordinate = gridlyCoordinateFromRecord(geometryAwareSelection?.selectedSegment?.candidateCoordinate);
      const geometryCandidateDistancesMeters = Array.isArray(geometryAwareSelection?.candidateSegments)
        ? geometryAwareSelection.candidateSegments.map((candidate) => Number(candidate?.distanceFromTapMeters)).filter(Number.isFinite).sort((a, b) => a - b)
        : [];
      const candidateDistancesMeters = geometryCandidateDistancesMeters.length
        ? geometryCandidateDistancesMeters
        : candidates.map((candidate) => Number(candidate?.distance)).filter(Number.isFinite).sort((a, b) => a - b);
      const geometryNearestDistanceMeters = Number(geometryAwareSelection?.selectedSegment?.distanceFromTapMeters);
      const placementDecision = gridlyBuildRoadAwareHazardPlacement(
        { lat, lng },
        geometrySelectedCoordinate || { lat: snappedLat, lng: snappedLng },
        {
          nearestCandidateDistanceMeters: Number.isFinite(geometryNearestDistanceMeters) ? geometryNearestDistanceMeters : snapDistanceMeters,
          roadCandidateCount: geometryAwareSelection?.candidateCount || candidates.length,
          candidateDistancesMeters,
          source: options?.source || "hazard_snap",
          geometryAwarePlacement: geometryAwareSelection,
          selectedRoadwaySegment: geometryAwareSelection?.selectedSegment || null,
          projectionCoordinate: geometrySelectedCoordinate || null,
          selectedRoadName: geometryAwareSelection?.selectedSegment?.roadName || null,
          selectedSideConfidence: geometryAwareSelection?.selectedSideConfidence || "low",
          recommendedDirection: geometryAwareSelection?.recommendedDirection || null
        }
      );
      const selectedSideConfidence = geometryAwareSelection?.selectedSideConfidence || "low";
      const confidenceRank = { low: 0, medium: 1, high: 2 };
      const minimumConfidenceRequired = "none_current_rule_set_uses_distance_thresholds_and_divided_road_risk_only";
      const confidenceMet = null;
      const snapRejectionDecisionAudit = {
        ...(placementDecision.snapRejectionDecisionAudit || {}),
        sameRoadCandidateCount: geometryAwareSelection?.sameRoadCandidateCount ?? 0,
        oppositeSideCandidateCount: geometryAwareSelection?.oppositeSideCandidateCount ?? 0,
        parallelRoadRisk: Boolean(placementDecision.parallelRoadRisk || geometryAwareSelection?.sameRoadParallelCandidates?.length || geometryAwareSelection?.dividedRoadRisk),
        dividedRoadRisk: Boolean(placementDecision.dividedRoadRisk || geometryAwareSelection?.dividedRoadRisk),
        selectedSideConfidence,
        selectedRoadName: geometryAwareSelection?.selectedSegment?.roadName || null,
        selectedSegmentDistanceMeters: geometryAwareSelection?.selectedSegment?.distanceFromTapMeters ?? null,
        candidateDistanceGapMeters: geometryAwareSelection?.candidateDistanceGapMeters ?? placementDecision.candidateDistanceGapMeters ?? null,
        minimumConfidenceRequired,
        confidenceMet,
        confidenceAuditNote: `selectedSideConfidence=${selectedSideConfidence}; current final placement decision does not compare side confidence against a minimum (${confidenceRank[selectedSideConfidence] ?? 0} recorded for diagnostics only)`,
        finalDecisionOwner: placementDecision.finalDecisionOwner || "gridlyBuildRoadAwareHazardPlacement"
      };
      debug.snappedCoords = { lat: snappedLat, lng: snappedLng };
      debug.snappedRoadCoordinate = { lat: snappedLat, lng: snappedLng };
      debug.finalPlacementCoordinate = placementDecision.finalPlacementCoordinate;
      debug.projectionCoordinate = placementDecision.projectionCoordinate || placementDecision.projectedRoadCoordinate || null;
      debug.placementMode = placementDecision.placementMode;
      debug.placementRiskLevel = placementDecision.placementRiskLevel;
      debug.representativeCoordinateReason = placementDecision.representativeCoordinateReason;
      debug.roadCandidateCount = placementDecision.roadCandidateCount;
      debug.nearestCandidateDistanceMeters = placementDecision.nearestCandidateDistanceMeters;
      debug.tapToSnapDeltaMeters = placementDecision.tapToSnapDeltaMeters;
      debug.tapToFinalDeltaMeters = placementDecision.tapToFinalDeltaMeters;
      debug.snapToFinalDeltaMeters = placementDecision.snapToFinalDeltaMeters;
      debug.candidateDistancesMeters = placementDecision.candidateDistancesMeters;
      debug.snapAccepted = placementDecision.snapAccepted;
      debug.snapRejected = placementDecision.snapRejected;
      debug.resolverCandidateFinalCoordinate = placementDecision.resolverCandidateFinalCoordinate || null;
      debug.resolverAttemptedCoordinateReplacement = Boolean(placementDecision.resolverAttemptedCoordinateReplacement);
      debug.resolverAttemptedReplacementDeltaMeters = placementDecision.resolverAttemptedReplacementDeltaMeters ?? null;
      debug.rejectionReason = placementDecision.rejectionReason;
      debug.decisionRulesEvaluated = placementDecision.decisionRulesEvaluated;
      debug.decisionTrace = placementDecision.decisionTrace;
      debug.finalDecisionOwner = placementDecision.finalDecisionOwner;
      debug.parallelRoadRisk = snapRejectionDecisionAudit.parallelRoadRisk;
      debug.candidateDistanceGapMeters = snapRejectionDecisionAudit.candidateDistanceGapMeters;
      debug.snapRejectionDecisionAudit = snapRejectionDecisionAudit;
      debug.nearestRoadCandidates = geometryAwareSelection?.candidateSegments?.length ? geometryAwareSelection.candidateSegments : diagnosticCandidates;
      debug.osrmNearestCandidates = diagnosticCandidates;
      debug.geometryAwarePlacement = geometryAwareSelection;
      debug.selectedRoadwaySegment = geometryAwareSelection?.selectedSegment || null;
      debug.selectedRoadName = geometryAwareSelection?.selectedSegment?.roadName || null;
      debug.selectedSegmentDistanceMeters = geometryAwareSelection?.selectedSegment?.distanceFromTapMeters ?? null;
      debug.selectedSegmentBearing = geometryAwareSelection?.selectedSegment?.bearing ?? null;
      debug.selectedSegmentReason = geometryAwareSelection?.selectedSegmentReason || null;
      debug.sameRoadCandidateCount = geometryAwareSelection?.sameRoadCandidateCount ?? 0;
      debug.oppositeSideCandidateCount = geometryAwareSelection?.oppositeSideCandidateCount ?? 0;
      debug.selectedSideConfidence = geometryAwareSelection?.selectedSideConfidence || "low";
      debug.canSupportFutureDirectionalLabels = Boolean(geometryAwareSelection?.canSupportFutureDirectionalLabels);
      debug.geometryAwarePlacementAvailable = Boolean(placementDecision.geometryAwarePlacementAvailable || geometryAwareSelection?.selectedSegment);
      debug.recommendedDirection = geometryAwareSelection?.recommendedDirection || null;
      debug.directionConfidence = geometryAwareSelection?.directionConfidence || "low";
      debug.dividedRoadRisk = Boolean(placementDecision.dividedRoadRisk || geometryAwareSelection?.dividedRoadRisk);
      debug.snapDistanceMeters = snapDistanceMeters;
      debug.finalSnapRadiusUsed = radiusMeters;
      debug.nearestRoadFound = true;
      debug.snapMethodUsed = "osrm_nearest_v1_driving_candidates";
      debug.fallbackUsed = !placementDecision.snapAccepted;
      debug.fallbackReason = placementDecision.snapAccepted ? "" : placementDecision.placementMode;
      debug.routeImpactDetected = routeWatchActivated && isPointNearActiveRoute(placementDecision.finalPlacementCoordinate?.lat, placementDecision.finalPlacementCoordinate?.lng);
      debug.lastHazardSnapResult = placementDecision.placementMode;
      debug.hazardPlacementUsesCanonicalSnap = Boolean(placementDecision.snapAccepted);
      debug.hazardPlacementUsesTapCoordinate = !placementDecision.snapAccepted;
      lastRoadSnapDebug = debug;
      return {
        lat: placementDecision.finalPlacementCoordinate?.lat ?? lat,
        lng: placementDecision.finalPlacementCoordinate?.lng ?? lng,
        fallbackUsed: debug.fallbackUsed,
        originalTapCoords: debug.originalTapCoords,
        rawTapCoordinate: placementDecision.rawTapCoordinate,
        snappedRoadCoordinate: placementDecision.snappedRoadCoordinate,
        finalPlacementCoordinate: placementDecision.finalPlacementCoordinate,
        renderedMarkerCoordinate: placementDecision.renderedMarkerCoordinate,
        projectionCoordinate: placementDecision.projectionCoordinate || placementDecision.projectedRoadCoordinate || null,
        tapToSnapDeltaMeters: placementDecision.tapToSnapDeltaMeters,
        tapToFinalDeltaMeters: placementDecision.tapToFinalDeltaMeters,
        snapToFinalDeltaMeters: placementDecision.snapToFinalDeltaMeters,
        resolverCandidateFinalCoordinate: placementDecision.resolverCandidateFinalCoordinate || null,
        resolverAttemptedCoordinateReplacement: Boolean(placementDecision.resolverAttemptedCoordinateReplacement),
        resolverAttemptedReplacementDeltaMeters: placementDecision.resolverAttemptedReplacementDeltaMeters ?? null,
        placementMode: placementDecision.placementMode,
        placementRiskLevel: placementDecision.placementRiskLevel,
        roadCandidateCount: placementDecision.roadCandidateCount,
        nearestCandidateDistanceMeters: placementDecision.nearestCandidateDistanceMeters,
        representativeCoordinateReason: placementDecision.representativeCoordinateReason,
        snapRejectionDecisionAudit,
        geometryAwarePlacement: geometryAwareSelection,
        selectedRoadwaySegment: geometryAwareSelection?.selectedSegment || null,
        selectedRoadName: geometryAwareSelection?.selectedSegment?.roadName || null,
        selectedSegmentDistanceMeters: geometryAwareSelection?.selectedSegment?.distanceFromTapMeters ?? null,
        selectedSegmentBearing: geometryAwareSelection?.selectedSegment?.bearing ?? null,
        selectedSegmentReason: geometryAwareSelection?.selectedSegmentReason || null,
        selectedSideConfidence: geometryAwareSelection?.selectedSideConfidence || "low",
        geometryAwarePlacementAvailable: Boolean(placementDecision.geometryAwarePlacementAvailable || geometryAwareSelection?.selectedSegment),
        canSupportFutureDirectionalLabels: Boolean(geometryAwareSelection?.canSupportFutureDirectionalLabels),
        recommendedDirection: geometryAwareSelection?.recommendedDirection || null,
        directionConfidence: geometryAwareSelection?.directionConfidence || "low"
      };
    } catch (error) {
      debug.fallbackReason = String(error?.message || error || "nearest_unknown_failure");
    } finally {
      gridlyNetworkAuditState.osrmNearest.inFlight = Math.max(0, gridlyNetworkAuditState.osrmNearest.inFlight - 1);
    }
  }
  debug.lastHazardSnapResult = "blocked_no_nearby_road";
  debug.snapDistanceMeters = null;
  debug.rawHazardCoordinatesBlockedWhenInvalid = true;
  debug.placementMode = "raw_tap";
  debug.placementRiskLevel = "high";
  debug.representativeCoordinateReason = "No nearby road candidate was found by OSRM nearest; tap-map hazard submission remains blocked for road proximity validation.";
  lastRoadSnapDebug = debug;
  return { lat, lng, fallbackUsed: true, invalid: true, originalTapCoords: debug.originalTapCoords };
}

function isPointNearActiveRoute(lat, lng) {
  const points = savedRouteLayer?.getLatLngs?.() || [];
  if (!Array.isArray(points) || !points.length) return false;
  return points.some((p) => getDistanceMiles(lat, lng, p.lat, p.lng) <= 0.08);
}

async function createSharedHazardReport(hazardType, lat, lng, confidence, locationName = "", originalTapCoords = null, options = {}) {
  const submitAudit = {
    startedAt: Date.now(),
    startedIso: new Date().toISOString(),
    hazardType,
    stages: []
  };
  const markSubmitStage = (name, extra = {}) => {
    submitAudit.stages.push({ name, timestamp: Date.now(), ...extra });
  };
  markSubmitStage("enter");
  const deferPostSubmitUiReset = Boolean(options?.deferPostSubmitUiReset);
  const tapMapUserSelectedCoordinate = confidence === "tap map placement"
    ? gridlyCoordinateFromRecord(options?.tapMapUserSelectedCoordinate || options?.preservedTapMapCoordinate || originalTapCoords)
    : null;
  const tapMapResolverDiagnosticCoordinate = confidence === "tap map placement"
    ? gridlyCoordinateFromRecord(options?.resolvedRoadCoordinate || lastMobileReportSubmitDebug.snappedRoadCoordinate || lastMobileReportSubmitDebug.snappedCoords)
    : null;
  if (tapMapUserSelectedCoordinate) {
    lat = tapMapUserSelectedCoordinate.lat;
    lng = tapMapUserSelectedCoordinate.lng;
    lastMobileReportSubmitDebug.finalPlacementCoordinate = { ...tapMapUserSelectedCoordinate };
    lastMobileReportSubmitDebug.activeSubmitCoords = { ...tapMapUserSelectedCoordinate };
    lastMobileReportSubmitDebug.renderedMarkerCoordinate = { ...tapMapUserSelectedCoordinate };
    lastMobileReportSubmitDebug.placementCoordinateReason = "Tap Map payload lat/lng are locked to the original user-selected coordinate; resolver coordinate is diagnostic only.";
  }
  lastMobileReportSubmitDebug.lastSubmitAttempt = "final_submit_handler_entered";
  if (reportingState.submissionInProgress) return false;

  if (!supabaseClient) {
    const message = "Live hazard sync is unavailable.";
    lastMobileReportSubmitDebug.lastSubmitError = message;
    updateReportingState({ submissionInProgress: false, locationLookupInProgress: false, lastReportError: message, lastReportMessage: "" });
    setConfirmation(message, "error");
    return false;
  }

  const normalizedOtherSubtype = hazardType === "other_hazard"
    ? normalizeOtherHazardSubtype(options?.subtype || selectedOtherHazardSubtype)
    : "";
  const copy = HAZARD_TYPES[hazardType] || HAZARD_TYPES.other_hazard;
  const subtypeLabel = normalizedOtherSubtype ? getOtherHazardSubtypeLabel(normalizedOtherSubtype) : "";
  const sourceTag = ROAD_HAZARD_SOURCE_MAP[hazardType] || "community_report";
  const expiresAt = new Date(Date.now() + HAZARD_REPORT_EXPIRATION_MINUTES * 60000).toISOString();
  const baseDetail = normalizedOtherSubtype
    ? `Shared report: ${subtypeLabel.toLowerCase()} may affect travel. (future_source: ${sourceTag})`
    : `${copy.detail} (future_source: ${sourceTag})`;

  lastOtherHazardReportPayloadSubtype = normalizedOtherSubtype;

  const row = {
    crossing_id: `hazard-${deviceId}-${Date.now()}`,
    crossing_name: locationName
      ? `${subtypeLabel || copy.label} · ${locationName}`
      : (subtypeLabel || copy.label),
    railroad: "Road hazard",
    lat,
    lng,
    report_type: hazardType,
    severity: copy.severity,
    detail: appendOtherHazardStructuredMetadata(baseDetail, normalizedOtherSubtype),
    source: "user",
    confidence,
    device_id: deviceId,
    expires_at: expiresAt
  };
  const localRow = normalizedOtherSubtype
    ? { ...row, category: "other_hazard", subtype: normalizedOtherSubtype, hazardSubtype: normalizedOtherSubtype }
    : row;

  try {
    lastMobileReportSubmitDebug.activeSubmitCoords = { lat, lng };
    if (originalTapCoords) lastMobileReportSubmitDebug.originalTapCoords = { ...originalTapCoords };
    lastMobileReportSubmitDebug.insertPayloadPreview = normalizedOtherSubtype ? { ...row, subtype: normalizedOtherSubtype } : { ...row };
    lastMobileReportSubmitDebug.lastReportPayloadSubtype = normalizedOtherSubtype;
    lastMobileReportSubmitDebug.supabaseInsertStarted = false;
    lastMobileReportSubmitDebug.supabaseInsertSucceeded = false;
    lastMobileReportSubmitDebug.supabaseInsertError = "";
    lastMobileReportSubmitDebug.lastSubmitError = "";
    updateReportingState({ submissionInProgress: true, locationLookupInProgress: false });
    setSync("Sending hazard report...");
    updateReportingState({ lastReportError: "", lastReportMessage: `Sending ${copy.label} hazard report...` });
    setConfirmation(`Sending ${copy.label} hazard report...`, "success");

    lastMobileReportSubmitDebug.lastSubmitAttempt = "supabase_insert_started";
    markSubmitStage("supabase_insert_started");
    lastMobileReportSubmitDebug.supabaseInsertStarted = true;
    const { error } = await supabaseClient.from("reports").insert(row);

    if (error) throw error;

    lastMobileReportSubmitDebug.lastSubmitAttempt = "supabase_insert_succeeded";
    markSubmitStage("supabase_insert_succeeded");
    lastMobileReportSubmitDebug.supabaseInsertSucceeded = true;
    const localHazardRows = normalizeReports([{ ...localRow, created_at: new Date().toISOString() }]);
    const localHazardEntry = localHazardRows[0] || null;
    if (localHazardEntry && originalTapCoords) {
      const finalPlacementCoordinate = gridlyCoordinateFromRecord(lastMobileReportSubmitDebug.finalPlacementCoordinate) || gridlyCoordinateFromRecord(localHazardEntry);
      localHazardEntry.originalTapCoords = { ...originalTapCoords };
      localHazardEntry.rawTapCoordinate = { ...originalTapCoords };
      localHazardEntry.reportCaptureCoordinate = { ...originalTapCoords };
      localHazardEntry.coordinateSourceUsed = lastMobileReportSubmitDebug.coordinateSourceUsed || "road_aware_placement";
      localHazardEntry.placementMode = lastMobileReportSubmitDebug.placementMode || lastRoadSnapDebug?.placementMode || "raw_tap";
      localHazardEntry.placementRiskLevel = lastMobileReportSubmitDebug.placementRiskLevel || lastRoadSnapDebug?.placementRiskLevel || "medium";
      localHazardEntry.snappedRoadCoordinate = tapMapResolverDiagnosticCoordinate
        ? { ...tapMapResolverDiagnosticCoordinate }
        : lastMobileReportSubmitDebug.snappedRoadCoordinate
          ? { ...lastMobileReportSubmitDebug.snappedRoadCoordinate }
          : (lastMobileReportSubmitDebug.snappedCoords ? { ...lastMobileReportSubmitDebug.snappedCoords } : null);
      localHazardEntry.roadResolverDiagnosticCoordinate = localHazardEntry.snappedRoadCoordinate ? { ...localHazardEntry.snappedRoadCoordinate } : null;
      localHazardEntry.resolverAttemptedCoordinateReplacement = Boolean(tapMapUserSelectedCoordinate && localHazardEntry.roadResolverDiagnosticCoordinate && gridlyCoordinateDeltaMeters(tapMapUserSelectedCoordinate, localHazardEntry.roadResolverDiagnosticCoordinate) > 0.5);
      localHazardEntry.finalPlacementCoordinate = tapMapUserSelectedCoordinate ? { ...tapMapUserSelectedCoordinate } : finalPlacementCoordinate;
      localHazardEntry.renderedMarkerCoordinate = tapMapUserSelectedCoordinate ? { ...tapMapUserSelectedCoordinate } : finalPlacementCoordinate;
      localHazardEntry.tapToSnapDeltaMeters = lastMobileReportSubmitDebug.tapToSnapDeltaMeters ?? lastRoadSnapDebug?.tapToSnapDeltaMeters ?? null;
      localHazardEntry.tapToFinalDeltaMeters = lastMobileReportSubmitDebug.tapToFinalDeltaMeters ?? lastRoadSnapDebug?.tapToFinalDeltaMeters ?? null;
      localHazardEntry.snapToFinalDeltaMeters = lastMobileReportSubmitDebug.snapToFinalDeltaMeters ?? lastRoadSnapDebug?.snapToFinalDeltaMeters ?? null;
      localHazardEntry.roadCandidateCount = lastMobileReportSubmitDebug.roadCandidateCount ?? lastRoadSnapDebug?.roadCandidateCount ?? null;
      localHazardEntry.nearestCandidateDistanceMeters = lastMobileReportSubmitDebug.nearestCandidateDistanceMeters ?? lastRoadSnapDebug?.nearestCandidateDistanceMeters ?? null;
      localHazardEntry.selectedRoadwaySegment = lastRoadSnapDebug?.selectedRoadwaySegment || lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment || null;
      localHazardEntry.selectedRoadName = lastRoadSnapDebug?.selectedRoadName || lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment?.roadName || null;
      localHazardEntry.selectedSegmentDistanceMeters = lastRoadSnapDebug?.selectedSegmentDistanceMeters ?? lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment?.distanceFromTapMeters ?? null;
      localHazardEntry.selectedSegmentBearing = lastRoadSnapDebug?.selectedSegmentBearing ?? lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment?.bearing ?? null;
      localHazardEntry.geometryAwarePlacement = lastRoadSnapDebug?.geometryAwarePlacement || null;
      localHazardEntry.projectionCoordinate = lastRoadSnapDebug?.projectionCoordinate || lastMobileReportSubmitDebug.projectionCoordinate || null;
      localHazardEntry.selectedSideConfidence = lastRoadSnapDebug?.selectedSideConfidence || lastRoadSnapDebug?.geometryAwarePlacement?.selectedSideConfidence || "low";
      localHazardEntry.geometryAwarePlacementAvailable = Boolean(lastRoadSnapDebug?.geometryAwarePlacementAvailable || lastRoadSnapDebug?.geometryAwarePlacement?.selectedSegment);
      localHazardEntry.recommendedDirection = lastRoadSnapDebug?.recommendedDirection || null;
      localHazardEntry.representativeCoordinateReason = lastMobileReportSubmitDebug.placementCoordinateReason || lastRoadSnapDebug?.representativeCoordinateReason || "Road-aware placement coordinate selected during hazard submission.";
    }
    if (localHazardEntry) {
      gridlyCaptureHazardHistoryEvent(localHazardEntry, { sourceHazards: [localHazardEntry, ...(Array.isArray(activeHazards) ? activeHazards : [])] });
      activeHazards = [localHazardEntry, ...activeHazards.filter((hazard) => hazard.crossingId !== localHazardEntry.crossingId)];
      if (activeGeoFilter !== "all" && activeGeoFilter !== "active-delays" && typeof applyGeoFilterFromPill === "function") {
        applyGeoFilterFromPill("all", "post_hazard_submit_visibility");
      }
      if (unifiedIncidentLayer && map && typeof map.hasLayer === "function" && !map.hasLayer(unifiedIncidentLayer)) {
        unifiedIncidentLayer.addTo(map);
      }
      refreshReportHazardViews("createSharedHazardReport:local_immediate");
      if (typeof renderUnifiedIncidents === "function") renderUnifiedIncidents();
      scheduleHazardMarkerAutoRender("createSharedHazardReport:local_immediate");
    }
    const submitLifecycleId = row.crossing_id;
    if (!beginSubmitLifecycleGuard(submitLifecycleId)) {
      markSubmitStage("duplicate_success_lifecycle_suppressed", { submitLifecycleId });
      updateReportingState({ submissionInProgress: false, locationLookupInProgress: false });
      submitAudit.suppressedDuplicateLifecycle = true;
      submitAudit.submitLifecycleId = submitLifecycleId;
      submitAudit.completedAt = Date.now();
      submitAudit.durationMs = submitAudit.completedAt - submitAudit.startedAt;
      gridlyNetworkAuditState.hazardSubmit.lastLifecycle = submitAudit;
      return false;
    }

    try {
      if (deferPostSubmitUiReset) {
        updateReportingState({
          submissionInProgress: false,
          locationLookupInProgress: false,
          lastReportError: "",
          lastReportMessage: "Report added"
        });
        setSync("Hazard report shared");
        lastMobileReportSubmitDebug.postSubmitUiResetSucceeded = false;
        lastMobileReportSubmitDebug.lastSubmitAttempt = "ui_reset_deferred_until_tap_map_coordinate_lock";
        markSubmitStage("ui_reset_deferred_until_tap_map_coordinate_lock");
        runPostSubmitRefreshInBackground(submitAudit, markSubmitStage, "createSharedHazardReport_success_deferred_ui_reset");
      } else {
        updateReportingState({ lastReportError: "", lastReportMessage: "Report added" });
        runUnifiedReportSuccessLifecycle({
          flow: "hazard",
          successType: hazardType,
          successMessage: "Report accepted and shared."
        });
        setSync("Hazard report shared");

        updateReportingState({
          submissionInProgress: false,
          locationLookupInProgress: false,
          reportModeActive: false,
          placementModeActive: false,
          selectedHazardType: null
        });
        selectedOtherHazardSubtype = "";
        closeHazardPanel({ preserveLastReportMessage: true });
        returnMobileToLiveMode("submit_hazard_success");
        lastMobileReportSubmitDebug.postSubmitUiResetSucceeded = true;
        lastMobileReportSubmitDebug.lastSubmitAttempt = "ui_reset_complete";
        markSubmitStage("ui_reset_complete");
        runPostSubmitRefreshInBackground(submitAudit, markSubmitStage);
      }
    } finally {
      endSubmitLifecycleGuard(submitLifecycleId);
    }
    submitAudit.completedAt = Date.now();
    submitAudit.durationMs = submitAudit.completedAt - submitAudit.startedAt;
    gridlyNetworkAuditState.hazardSubmit.lastLifecycle = submitAudit;
    return true;
  } catch (error) {
    const message = error?.message || "unknown_error";
    const insertSucceeded = Boolean(lastMobileReportSubmitDebug.supabaseInsertSucceeded);
    if (insertSucceeded) {
      console.warn("Gridly hazard post-submit completion warning:", error);
      lastMobileReportSubmitDebug.lastSubmitAttempt = "post_insert_completion_warning";
      lastMobileReportSubmitDebug.lastSubmitError = "";
      updateReportingState(deferPostSubmitUiReset ? {
        submissionInProgress: false,
        locationLookupInProgress: false,
        lastReportError: "",
        lastReportMessage: "Report added"
      } : {
        submissionInProgress: false,
        locationLookupInProgress: false,
        reportModeActive: false,
        placementModeActive: false,
        selectedHazardType: null,
        lastReportError: "",
        lastReportMessage: "Report added"
      });
      if (!deferPostSubmitUiReset) selectedOtherHazardSubtype = "";
      setConfirmation("Report accepted and shared.", "success");
      setSync("Hazard report shared");
      markSubmitStage("post_insert_completion_warning", { message });
      submitAudit.completedAt = Date.now();
      submitAudit.durationMs = submitAudit.completedAt - submitAudit.startedAt;
      submitAudit.warning = message;
      gridlyNetworkAuditState.hazardSubmit.lastLifecycle = submitAudit;
      return true;
    }
    console.error("Gridly hazard insert failed:", error);
    lastMobileReportSubmitDebug.lastSubmitAttempt = "supabase_insert_failed";
    lastMobileReportSubmitDebug.supabaseInsertError = message;
    lastMobileReportSubmitDebug.lastSubmitError = message;
    updateReportingState({ lastReportError: `Hazard report failed: ${message || "permission denied"}` });
    setConfirmation(`Hazard report failed: ${message || "permission denied"}`, "error");
    setSync("Hazard report failed");
    updateReportingState({ submissionInProgress: false, locationLookupInProgress: false });
    markSubmitStage("failed", { message });
    submitAudit.completedAt = Date.now();
    submitAudit.durationMs = submitAudit.completedAt - submitAudit.startedAt;
    submitAudit.error = message;
    gridlyNetworkAuditState.hazardSubmit.lastLifecycle = submitAudit;
    return false;
  }
}
window.confirmHazardStillThere = async function (hazardType, lat, lng) {
  await createSharedHazardReport(hazardType, lat, lng, "hazard confirmed still there");
};

window.clearHazard = async function (hazardType, lat, lng) {
  if (!supabaseClient) {
    setConfirmation("Live hazard sync is unavailable.", "error");
    return;
  }

  const copy = HAZARD_TYPES[hazardType] || HAZARD_TYPES.other_hazard;
  const expiresAt = new Date(Date.now() + 30 * 60000).toISOString();

  const row = {
    crossing_id: `hazard-cleared-${deviceId}-${Date.now()}`,
    crossing_name: `${copy.label} Cleared`,
    railroad: "Road hazard",
    lat,
    lng,
    report_type: "hazard_cleared",
    severity: "low",
    detail: `Shared report: ${copy.label} appears cleared.`,
    source: "user",
    confidence: "hazard cleared by user",
    device_id: deviceId,
    expires_at: expiresAt
  };

  try {
    setSync("Sending hazard clear report...");
    setConfirmation(`Clearing ${copy.label} hazard...`, "success");

    lastMobileReportSubmitDebug.lastSubmitAttempt = "supabase_insert_started";
    lastMobileReportSubmitDebug.supabaseInsertStarted = true;
    const { error } = await supabaseClient.from("reports").insert(row);

    if (error) throw error;

    const localClearRows = normalizeReports([{ ...row, created_at: new Date().toISOString() }]);
    if (localClearRows[0]) {
      gridlyCaptureHazardHistoryEvent(localClearRows[0], { hazardType, sourceHazards: Array.isArray(activeHazards) ? activeHazards : [] });
    }

    setConfirmation(`${copy.label} marked cleared.`, "success");
    setSync("Hazard cleared");

    await runPostSubmitRefresh();
  } catch (error) {
    console.error("Gridly hazard clear failed:", error);
    setConfirmation(`Clear failed: ${error.message || "permission denied"}`, "error");
    setSync("Hazard clear failed");
  }
};
