async function renderDestinationRoute(target) {
  if (!savedRouteLayer || !target) return;
  window.__gridlyRouteWatchActive = true;
  window.__gridlySelectedRouteId = String(target.type || target.label || "saved-route").toLowerCase();
  savedRouteLayer.clearLayers();
  const fromCandidate = userLocation ? [userLocation.lat, userLocation.lng] : [defaultCenter[0], defaultCenter[1]];
  const fromCoords = normalizeCoordinatePair(fromCandidate[0], fromCandidate[1]);
  const toCoords = normalizeCoordinatePair(target.lat, target.lng);
  if (!fromCoords || !toCoords) {
    setConfirmation("Add exact Home and Work locations to show route.", "error");
    savedRouteCrossingIds = new Set();
    window.__gridlyRouteWatchActive = false;
    window.__gridlySelectedRouteId = "";
    scheduleRenderCrossings("state-change");
    return;
  }
  const from = [fromCoords.lat, fromCoords.lng];
  const to = [toCoords.lat, toCoords.lng];
  const osrmPath = await fetchRoadRouteCoordinates(from, to);
  if (osrmPath?.length > 1) {
    drawPremiumRouteLine(osrmPath, "#66e8ff", "renderDestinationRoute");
    setConfirmation(`Route Watch set: ${target.label}.`, "success");
  } else {
    savedRouteLayer.clearLayers();
    setConfirmation(`Route Watch set: ${target.label}. Precise route line unavailable.`, "success");
    if (els.routeWatchSetupHint) els.routeWatchSetupHint.textContent = `Monitoring Home → ${target.label}. Precise route line unavailable.`;
  }
  savedRouteCrossingIds = new Set(crossings.filter((c) => getDistanceMiles(c.lat, c.lng, target.lat, target.lng) <= 3.5).map((c) => String(c.id)));
  scheduleRenderCrossings("state-change");
  updateRouteWatchBadge(target.label);
}

function updateRouteWatchBadge(routeLabel = "Route") {
  const activation = getLineActivationContext();
  if (!activation.hasActivation || !buildRouteWatchLabelParts().configured || !routeWatchActivated) {
    if (els.routeWatchLivePill) {
      els.routeWatchLivePill.textContent = "Monitoring OFF";
      els.routeWatchLivePill.classList.remove("is-on");
    }
    return;
  }
  if (els.routeWatchLivePill) {
    els.routeWatchLivePill.textContent = "Monitoring ON";
    els.routeWatchLivePill.classList.add("is-on");
  }
}

function loadSavedRoute() {
  scrubInvalidSavedPlacesState();
  routeFocusArmed = true;
  const routeLabelParts = buildRouteWatchLabelParts();
  const home = routeLabelParts.hasHome ? "Home" : "No active route";
  const work = routeLabelParts.destination || "";
  renderSavedPlacesSelectOptions();
  updateRouteWatchSetupUI();

  if (home) {
    safeText("savedHome", home);
    safeText("desktopRouteHome", home);
  }

  if (work) {
    safeText("savedWork", work);
    safeText("desktopRouteWork", work);
  }
  const savedPlaceCount = getSavedPlaces().length;
  const startId = els.routeWatchStartSelect?.value || "";
  const destinationId = els.routeWatchDestinationSelect?.value || "";
  const state = normalizeSavedPlaces();
  const startPlace = startId === "home" ? state.home : startId === "work" ? state.work : state.custom.find((place) => place.id === startId);
  const destinationPlace = destinationId === "home" ? state.home : destinationId === "work" ? state.work : state.custom.find((place) => place.id === destinationId);
  const startCoordinates = normalizeCoordinatePair(startPlace?.lat, startPlace?.lng);
  const destinationCoordinates = normalizeCoordinatePair(destinationPlace?.lat, destinationPlace?.lng);
  if (startId && destinationId && (!startCoordinates || !destinationCoordinates)) {
    savedRouteLayer?.clearLayers?.();
    setRoutePreviewState(false, "Missing start or destination coordinates", { layerExists: false, mapHasLayer: false, pointCount: 0 });
  }
  if (els.routeWatchStartBtn) {
    els.routeWatchStartBtn.disabled = savedPlaceCount < 2 || !startId || !destinationId || !startCoordinates || !destinationCoordinates;
  }
  updateRouteWatchStartButtonLabel();
  if (savedPlaceCount === 0) {
    safeText("desktopRouteStatus", "Save at least two places to start Route Watch.");
    safeText("routeWatchSetupHint", "Add Home and Work to start Route Watch.");
  } else if (savedPlaceCount < 2) {
    safeText("desktopRouteStatus", "Save at least two places to start Route Watch.");
    safeText("routeWatchSetupHint", "Choose a start and destination to begin monitoring.");
  } else if (!startId || !destinationId) {
    safeText("desktopRouteStatus", "Choose a start and destination to begin monitoring.");
  }
  safeText("routeCardLabel", routeWatchActivated && routeLabelParts.activeLabel
    ? `Home → ${routeLabelParts.activeLabel}`
    : routeLabelParts.hasHome && routeLabelParts.destination
      ? `Home → ${routeLabelParts.destination}`
      : "No active route");

  if (!routeLabelParts.configured) {
    routeWatchActivated = false;
    savedRouteCrossingIds = new Set();
    savedRouteLayer?.clearLayers?.();
    updateRouteWatchBadge();
    if (els.routeWatchSetupHint) {
      els.routeWatchSetupHint.hidden = false;
      els.routeWatchSetupHint.textContent = routeLabelParts.hasHome
        ? "Choose a saved destination to start Route Watch."
        : "Set Home and one destination to start Route Watch.";
    }
    if (els.sideRouteWatchHint) {
      els.sideRouteWatchHint.textContent = "1. Save Home and Work · 2. Open Manage Route · 3. Start Route Watch";
    }
  } else if (!routeWatchActivated && els.routeWatchSetupHint) {
    els.routeWatchSetupHint.hidden = false;
    els.routeWatchSetupHint.textContent = "Choose a saved destination to start Route Watch.";
  } else if (routeWatchActivated && els.routeWatchSetupHint) {
    els.routeWatchSetupHint.hidden = false;
    els.routeWatchSetupHint.textContent = `Monitoring Home → ${routeLabelParts.activeLabel || "Saved destination"}.`;
  }
  if (!routeLabelParts.hasHome && routeLabelParts.hasWork && els.routeWatchSetupHint) {
    els.routeWatchSetupHint.textContent = "Work saved. Add Home to start Route Watch.";
  } else if (routeLabelParts.hasHome && !routeLabelParts.hasWork && els.routeWatchSetupHint) {
    els.routeWatchSetupHint.textContent = "Home saved. Add Work to start Route Watch.";
  }
}

async function startInlineRouteWatch(options = {}) {
  const endInlineRouteTrace = timeGridlyReflowTrace("Route Watch open/view route", String(options?.source || "startInlineRouteWatch"));
  lastRoutePipelineStep = "entered";
  lastRouteEarlyReturnReason = null;
  const { activateWatch = true, source = "route_watch_cta" } = options;
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, source, activateWatch });

  lastRoutePipelineStep = "received_source_action";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, source, activateWatch });

  const startId = els.routeWatchStartSelect?.value || "";
  lastRoutePipelineStep = "start_selector_read";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, startId });

  const destinationId = els.routeWatchDestinationSelect?.value || "";
  lastRoutePipelineStep = "destination_selector_read";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, destinationId });

  const places = getSavedPlaces();
  const start = places.find((place) => place.id === startId);
  lastRoutePipelineStep = "resolved_start_place";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, start });

  const destination = places.find((place) => place.id === destinationId);
  lastRoutePipelineStep = "resolved_destination_place";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, destination });

  const startCoords = normalizeCoordinatePair(start?.lat, start?.lng);
  const destinationCoords = normalizeCoordinatePair(destination?.lat, destination?.lng);
  captureRouteAttempt({
    source,
    selectedStart: start?.name || startId || "",
    selectedDestination: destination?.name || destinationId || "",
    startCoords: startCoords || null,
    destinationCoords: destinationCoords || null,
    validationPassed: false,
    osrmCallStarted: false,
    osrmCallSucceeded: false,
    polylineRendered: false
  });
  lastRoutePipelineStep = "lat_lng_validated";
  routeDebugLog("Gridly route pipeline step", {
    step: lastRoutePipelineStep,
    startHasLatLng: Boolean(startCoords),
    destinationHasLatLng: Boolean(destinationCoords)
  });

  if (!start || !destination) {
    lastRouteEarlyReturnReason = "missing_start_or_destination_selection";
    lastRoutePipelineStep = "early_return";
    routeDebugLog("Gridly route pipeline early return", { reason: lastRouteEarlyReturnReason, startId, destinationId });
    setRoutePreviewState(false, "Start or destination was not selected.", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation("Choose a start and destination to begin monitoring.", "error");
    captureRouteAttempt({ finalFailureReason: "Missing start or destination selection" });
    return { success: false, reason: lastRouteEarlyReturnReason };
  }

  const samePlace = start.id === destination.id;
  lastRoutePipelineStep = "same_place_checked";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, samePlace });
  if (samePlace) {
    lastRouteEarlyReturnReason = "same_place_selected";
    lastRoutePipelineStep = "early_return";
    routeDebugLog("Gridly route pipeline early return", { reason: lastRouteEarlyReturnReason, startId, destinationId });
    savedRouteLayer?.clearLayers?.();
    setRoutePreviewState(false, "Start and destination are the same place.", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation("Choose a different destination.", "error");
    captureRouteAttempt({ finalFailureReason: "Start and destination are the same" });
    return { success: false, reason: lastRouteEarlyReturnReason };
  }

  routeWatchActivated = false;
  safeText("desktopRouteHome", start.name);
  safeText("desktopRouteWork", destination.name);
  safeText("routeCardLabel", `${start.name} → ${destination.name}`);
  safeText("desktopRouteStatus", activateWatch ? `Monitoring ${start.name} → ${destination.name}.` : `Viewing ${start.name} → ${destination.name}.`);
  safeText("routeWatchSetupHint", activateWatch ? `Monitoring ${start.name} → ${destination.name}.` : `Viewing ${start.name} → ${destination.name}.`);

  if (!startCoords || !destinationCoords) {
    lastRouteEarlyReturnReason = "missing_start_or_destination_coordinates";
    lastRoutePipelineStep = "early_return";
    routeDebugLog("Gridly route pipeline early return", { reason: lastRouteEarlyReturnReason, start, destination });
    savedRouteLayer?.clearLayers?.();
    setRoutePreviewState(false, "Missing start or destination coordinates", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation("Route preview unavailable until precise locations are saved.", "error");
    captureRouteAttempt({ finalFailureReason: !startCoords ? "Missing Home coordinates" : "Missing Destination coordinates" });
    safeText("routeWatchSetupHint", "Route preview unavailable until precise locations are saved.");
    updateRouteIntelligence();
    updateRouteWatchStartButtonLabel();
    return { success: false, reason: lastRouteEarlyReturnReason };
  }
  if (startCoords.lat === destinationCoords.lat && startCoords.lng === destinationCoords.lng) {
    lastRouteEarlyReturnReason = "same_coordinates";
    lastRoutePipelineStep = "early_return";
    routeDebugLog("Gridly route pipeline early return", { reason: lastRouteEarlyReturnReason, startCoords, destinationCoords });
    savedRouteLayer?.clearLayers?.();
    setRoutePreviewState(false, "Start and destination coordinates are the same", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation("Update one saved place location to view a route preview.", "error");
    safeText("routeWatchSetupHint", "Update one saved place location to view a route preview.");
    updateRouteIntelligence();
    updateRouteWatchStartButtonLabel();
    return { success: false, reason: lastRouteEarlyReturnReason };
  }
  if (getDistanceMiles(startCoords.lat, startCoords.lng, destinationCoords.lat, destinationCoords.lng) > 80) {
    lastRouteEarlyReturnReason = "distance_exceeds_local_preview_limit";
    lastRoutePipelineStep = "early_return";
    routeDebugLog("Gridly route pipeline early return", { reason: lastRouteEarlyReturnReason, startCoords, destinationCoords });
    savedRouteLayer?.clearLayers?.();
    setRoutePreviewState(false, "Route preview skipped because points are too far apart for local preview.", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation("Route preview unavailable for this selection.", "error");
    safeText("routeWatchSetupHint", "Route preview unavailable for this selection.");
    updateRouteIntelligence();
    updateRouteWatchStartButtonLabel();
    return { success: false, reason: lastRouteEarlyReturnReason };
  }

  lastRoutePipelineStep = "route_engine_availability_checked";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, mapReady: Boolean(map), osrmApi: OSRM_ROUTE_API });

  savedRouteLayer?.clearLayers?.();
  window.__gridlyRouteWatchActive = false;
  window.__gridlySelectedRouteId = `${start.id}->${destination.id}`;

  lastRoutePipelineStep = "osrm_payload_build_start";
  routeDebugLog("Gridly route pipeline step", { step: lastRoutePipelineStep, startCoords, destinationCoords });

  const routePreviewShown = await renderRoutePreviewLine(startCoords, destinationCoords, {
    start: start.name,
    destination: destination.name
  });
  if (!routePreviewShown) {
    lastRouteEarlyReturnReason = "route_preview_renderer_returned_false";
    setRoutePreviewState(false, "Missing start or destination coordinates", { layerExists: false, mapHasLayer: false, pointCount: 0 });
    setConfirmation(lastRouteError || "Route could not be drawn", "error");
    safeText("routeWatchSetupHint", "Route preview unavailable until precise locations are saved.");
  } else {
    const layerExists = Boolean(window.__gridlyRoutePreviewLayer);
    const mapHasLayer = Boolean(map && window.__gridlyRoutePreviewLayer && typeof map.hasLayer === "function" && map.hasLayer(window.__gridlyRoutePreviewLayer));
    setRoutePreviewState(Boolean(layerExists && mapHasLayer), "Route preview layer was not added to map", {
      layerExists,
      mapHasLayer,
      pointCount: routePreviewPolylinePointCount
    });
    if (routePreviewRendered) {
      setConfirmation("Route preview active.", "success");
      safeText("routeWatchSetupHint", "Route preview active.");
    } else {
      setConfirmation("Route preview unavailable until precise locations are saved.", "error");
      safeText("routeWatchSetupHint", "Route preview unavailable until precise locations are saved.");
    }
  }
  routeWatchActivated = Boolean(activateWatch && routePreviewRendered);
  window.__gridlyRouteWatchActive = routeWatchActivated;
  if (!routePreviewRendered) {
    setConfirmation(lastRouteError || "Route could not be drawn", "error");
  }
  captureRouteAttempt({
    validationPassed: true,
    osrmCallStarted: osrmRequestStarted,
    osrmCallSucceeded: osrmRouteSuccess,
    polylineRendered: routePreviewRendered,
    finalFailureReason: routePreviewRendered ? "" : (lastRouteError || "Route could not be drawn")
  });
  lastRoutePipelineStep = "route_pipeline_completed";
  activeDestinationPlace = destination;
  lastRouteWatchSelection = { startId: start.id, destinationId: destination.id };
  updateRouteWatchBadge(destination.name);
  updateRouteIntelligence();
  updateRouteWatchStartButtonLabel();
  return {
    success: Boolean(routePreviewRendered),
    reason: routePreviewRendered ? "" : (lastRouteEarlyReturnReason || "route_preview_unavailable"),
    activateWatch: Boolean(routeWatchActivated),
    startId: start.id,
    destinationId: destination.id
  };
}
window.gridlyStartInlineRouteWatch = startInlineRouteWatch;


function resetSavedPlaces() {
  localStorage.removeItem(SAVED_PLACES_STORAGE_KEY);
  localStorage.removeItem(SELECTED_PLACE_STORAGE_KEY);
  localStorage.removeItem("gridlyHome");
  localStorage.removeItem("gridlyWork");
  activeDestinationPlace = null;
  routeWatchActivated = false;
  setRoutePreviewState(false, "Saved places were reset.", { layerExists: false, mapHasLayer: false });
  savedRouteCrossingIds = new Set();
  savedRouteLayer?.clearLayers?.();
  corridorIntelLayer?.clearLayers?.();
  window.__gridlyRouteWatchActive = false;
  window.__gridlySelectedRouteId = "";
  loadSavedRoute();
  scheduleRenderCrossings("state-change");
  setConfirmation("Saved places reset on this device.", "success");
}


const GRIDLY_SETTINGS_DEFAULTS = Object.freeze({
  notifications: Object.freeze({
    routeAlerts: true,
    railAlerts: true,
    hazardAlerts: true,
    communityAlerts: false
  }),
  display: Object.freeze({
    mapStyle: "standard",
    theme: "system",
    textSize: "standard"
  }),
  personalization: Object.freeze({
    preferredName: ""
  })
});

const GRIDLY_SETTINGS_MAP_STYLE_LABELS = {
  standard: "Standard",
  dark: "Dark",
  satellite: "Satellite"
};

const GRIDLY_SETTINGS_VALID_THEMES = new Set(["system", "light", "dark"]);
const GRIDLY_SETTINGS_VALID_TEXT_SIZES = new Set(["standard", "large", "compact", "extra-large"]);
let gridlyLastSettingsAction = "";

function gridlyStorageAvailable() {
  try {
    if (typeof localStorage === "undefined") return false;
    const probeKey = "__gridly_settings_probe__";
    localStorage.setItem(probeKey, "1");
    localStorage.removeItem(probeKey);
    return true;
  } catch (error) {
    return false;
  }
}

function normalizeGridlySettings(raw = null) {
  const base = {
    notifications: { ...GRIDLY_SETTINGS_DEFAULTS.notifications },
    display: { ...GRIDLY_SETTINGS_DEFAULTS.display },
    personalization: { ...GRIDLY_SETTINGS_DEFAULTS.personalization },
    community: { homeTown: "", awarenessArea: "", awarenessAreaKey: "" }
  };
  const source = raw && typeof raw === "object" ? raw : {};
  const notifications = source.notifications && typeof source.notifications === "object" ? source.notifications : {};
  const display = source.display && typeof source.display === "object" ? source.display : {};
  const personalization = source.personalization && typeof source.personalization === "object" ? source.personalization : {};
  const community = source.community && typeof source.community === "object" ? source.community : {};
  Object.keys(base.notifications).forEach((key) => {
    if (typeof notifications[key] === "boolean") base.notifications[key] = notifications[key];
  });
  const normalizedStyle = String(display.mapStyle || "").trim().toLowerCase();
  if (GRIDLY_SETTINGS_MAP_STYLE_LABELS[normalizedStyle]) base.display.mapStyle = normalizedStyle;
  const normalizedTheme = String(display.theme || "").trim().toLowerCase();
  if (GRIDLY_SETTINGS_VALID_THEMES.has(normalizedTheme)) base.display.theme = normalizedTheme;
  const normalizedTextSize = String(display.textSize || "").trim().toLowerCase();
  if (normalizedTextSize === "extra-large") base.display.textSize = "large";
  else if (GRIDLY_SETTINGS_VALID_TEXT_SIZES.has(normalizedTextSize)) base.display.textSize = normalizedTextSize;
  base.personalization.preferredName = normalizeGridlyPreferredName(personalization.preferredName);
  const resolvedAwarenessArea = resolveGridlyAwarenessArea(community.awarenessArea || community.homeTown);
  base.community.homeTown = resolvedAwarenessArea?.storageValue || "";
  base.community.awarenessArea = resolvedAwarenessArea?.storageValue || "";
  base.community.awarenessAreaKey = resolvedAwarenessArea?.key || "";
  return base;
}

function getGridlySettingsPreferences() {
  try {
    const parsed = JSON.parse(localStorage.getItem(GRIDLY_SETTINGS_STORAGE_KEY) || "null");
    return normalizeGridlySettings(parsed);
  } catch (error) {
    return normalizeGridlySettings();
  }
}

function saveGridlySettingsPreferences(nextSettings, { applyDisplay = true, render = false, source = "settings" } = {}) {
  const normalized = normalizeGridlySettings(nextSettings);
  localStorage.setItem(GRIDLY_SETTINGS_STORAGE_KEY, JSON.stringify(normalized));
  if (applyDisplay) applyGridlySettingsDisplayPreferences(normalized.display, source);
  if (render) renderGridlySettingsPanel(normalized);
  return normalized;
}

function loadGridlySettingsPreferences({ render = false, applyDisplay = false } = {}) {
  const settings = getGridlySettingsPreferences();
  try {
    if (!localStorage.getItem(GRIDLY_SETTINGS_STORAGE_KEY)) {
      localStorage.setItem(GRIDLY_SETTINGS_STORAGE_KEY, JSON.stringify(settings));
    }
  } catch (error) {
    // Settings remain usable in-memory if local storage is blocked.
  }
  if (applyDisplay) applyGridlySettingsDisplayPreferences(settings.display, "settings_load");
  if (render) renderGridlySettingsPanel(settings);
  return settings;
}

function applyGridlySettingsDisplayPreferences(display = {}, source = "settings") {
  const normalized = normalizeGridlySettings({ display }).display;
  const layerName = GRIDLY_SETTINGS_MAP_STYLE_LABELS[normalized.mapStyle] || "Standard";
  const body = typeof document !== "undefined" ? document.body : null;
  const root = typeof document !== "undefined" ? document.documentElement : null;
  const themeClass = `gridly-theme-${normalized.theme}`;
  const textSizeClass = `gridly-text-${normalized.textSize}`;
  if (body) {
    ["gridly-theme-system", "gridly-theme-light", "gridly-theme-dark"].forEach((className) => body.classList.remove(className));
    ["gridly-text-standard", "gridly-text-large", "gridly-text-compact", "gridly-text-extra-large"].forEach((className) => body.classList.remove(className));
    body.classList.add(themeClass, textSizeClass);
    body.dataset.gridlyTheme = normalized.theme;
    body.dataset.gridlyTextSize = normalized.textSize;
  }
  if (root) {
    root.dataset.gridlyTheme = normalized.theme;
    root.dataset.gridlyTextSize = normalized.textSize;
  }
  try {
    localStorage.setItem(MAP_STYLE_STORAGE_KEY, layerName);
  } catch (error) {
    // Existing map style storage may be unavailable; keep the in-memory UI preference.
  }
  if (!map || !mapBaseLayersByName?.[layerName]) return false;
  Object.entries(mapBaseLayersByName).forEach(([, layer]) => {
    if (map.hasLayer(layer)) map.removeLayer(layer);
  });
  map.addLayer(mapBaseLayersByName[layerName]);
  if (!map.hasLayer(mapBaseLayersByName[layerName])) return false;
  currentMapStyle = layerName;
  activeBaseLayerName = layerName;
  if (mapStyleClassByName[layerName]) {
    Object.values(mapStyleClassByName).forEach((className) => map.getContainer().classList.remove(className));
    map.getContainer().classList.add(mapStyleClassByName[layerName]);
  }
  map.fire("baselayerchange", { name: layerName, layer: mapBaseLayersByName[layerName], source });
  return true;
}

function gridlyIsZipOnlyValue(value = "") {
  return /^\d{5}(?:-\d{4})?$/.test(String(value || "").trim());
}

function gridlyJoinCityState(city = "", state = "") {
  return [city, state].map((value) => String(value || "").trim()).filter(Boolean).join(", ");
}

function resolveGridlySettingsAddressObjectDisplay(addressObject = null) {
  if (!addressObject || typeof addressObject !== "object" || Array.isArray(addressObject)) return "";
  const street = [addressObject.house_number, addressObject.road || addressObject.street].map((value) => String(value || "").trim()).filter(Boolean).join(" ");
  const city = addressObject.city || addressObject.town || addressObject.village || addressObject.hamlet || addressObject.municipality || "";
  const state = addressObject.state || addressObject.region || "";
  return [street, gridlyJoinCityState(city, state)].map((value) => String(value || "").trim()).filter(Boolean).join(", ");
}

function resolveGridlySettingsPlaceDisplay(place, fallbackLabel = "Saved Place") {
  if (!isConfiguredPlace(place)) {
    return { value: "Not saved", source: "not_saved", zipUsedAsPrimary: false };
  }
  const rawAddress = place?.address;
  const addressObject = rawAddress && typeof rawAddress === "object" && !Array.isArray(rawAddress) ? rawAddress : null;
  const rawPayload = place?.raw && typeof place.raw === "object" ? place.raw : {};
  const rawPayloadAddress = rawPayload.address && typeof rawPayload.address === "object" && !Array.isArray(rawPayload.address) ? rawPayload.address : null;
  const genericLabels = new Set([String(fallbackLabel || "").trim().toLowerCase(), "home", "work", "saved place", "favorite place"].filter(Boolean));
  const isGenericLabel = (value = "") => genericLabels.has(String(value || "").trim().toLowerCase());
  const candidates = [
    ["address", typeof rawAddress === "string" ? rawAddress : ""],
    ["formattedAddress", place?.formattedAddress],
    ["fullAddress", place?.fullAddress],
    ["displayName", place?.displayName || place?.display_name || rawPayload.display_name],
    ["addressObject", resolveGridlySettingsAddressObjectDisplay(addressObject)],
    ["rawAddressObject", resolveGridlySettingsAddressObjectDisplay(rawPayloadAddress)],
    ["placeName", place?.placeName],
    ["city/state", gridlyJoinCityState(place?.city || addressObject?.city || addressObject?.town || rawPayloadAddress?.city || rawPayloadAddress?.town, place?.state || addressObject?.state || rawPayloadAddress?.state)],
    ["label", place?.label],
    ["name", place?.name]
  ];
  for (const [source, candidate] of candidates) {
    const value = String(candidate || "").trim();
    if (!value || gridlyIsZipOnlyValue(value)) continue;
    if ((source === "label" || source === "name" || source === "placeName") && isGenericLabel(value)) continue;
    return { value, source, zipUsedAsPrimary: false };
  }
  const zipCandidate = [place?.zip, place?.zipCode, place?.postalCode, addressObject?.postcode, rawPayloadAddress?.postcode, rawAddress].find((value) => gridlyIsZipOnlyValue(value));
  if (zipCandidate) return { value: String(zipCandidate).trim(), source: "zip", zipUsedAsPrimary: true };
  const coordinates = normalizeCoordinatePair(place?.lat ?? place?.coordinates?.lat, place?.lng ?? place?.coordinates?.lng);
  if (coordinates) return { value: `${coordinates.lat.toFixed(5)}, ${coordinates.lng.toFixed(5)}`, source: "coordinates", zipUsedAsPrimary: false };
  return { value: String(place?.label || place?.name || fallbackLabel).trim() || fallbackLabel, source: "fallback", zipUsedAsPrimary: false };
}

function describeGridlySettingsPlace(place, fallbackLabel) {
  if (!isConfiguredPlace(place)) {
    return { label: "Not saved", meta: `Save ${fallbackLabel} to enable Route Watch context.`, source: "not_saved", zipUsedAsPrimary: false };
  }
  const display = resolveGridlySettingsPlaceDisplay(place, fallbackLabel);
  const source = String(place.coordinateSource || "saved").trim();
  return {
    label: display.value,
    meta: display.source === "coordinates" ? `Coordinates saved (${source}).` : `Saved ${fallbackLabel}.`,
    source: display.source,
    zipUsedAsPrimary: display.zipUsedAsPrimary
  };
}

function renderGridlySettingsSavedPlaces() {
  const state = getSavedPlacesState();
  const home = describeGridlySettingsPlace(state.home, "Home");
  const work = describeGridlySettingsPlace(state.work, "Work");
  safeText("settingsHomeValue", home.label);
  safeText("settingsHomeMeta", home.meta);
  safeText("settingsWorkValue", work.label);
  safeText("settingsWorkMeta", work.meta);

  if (!els.settingsSavedPlacesList) return;
  els.settingsSavedPlacesList.innerHTML = "";
  els.settingsSavedPlacesList.hidden = true;
}

function renderGridlySettingsPanel(settings = getGridlySettingsPreferences()) {
  const normalized = normalizeGridlySettings(settings);
  renderGridlySettingsSavedPlaces();
  if (els.settingsRouteAlertsToggle) els.settingsRouteAlertsToggle.checked = Boolean(normalized.notifications.routeAlerts);
  if (els.settingsRailAlertsToggle) els.settingsRailAlertsToggle.checked = Boolean(normalized.notifications.railAlerts);
  if (els.settingsHazardAlertsToggle) els.settingsHazardAlertsToggle.checked = Boolean(normalized.notifications.hazardAlerts);
  if (els.settingsCommunityAlertsToggle) els.settingsCommunityAlertsToggle.checked = Boolean(normalized.notifications.communityAlerts);
  if (els.settingsMapStyleSelect) els.settingsMapStyleSelect.value = normalized.display.mapStyle;
  if (els.settingsThemeSelect) els.settingsThemeSelect.value = normalized.display.theme;
  if (els.settingsTextSizeSelect) els.settingsTextSizeSelect.value = normalized.display.textSize;
  if (els.settingsPreferredNameInput) els.settingsPreferredNameInput.value = normalized.personalization.preferredName;
  safeText("settingsBuildValue", GRIDLY_APP_BUILD_LABEL);
}

function collectGridlySettingsFromUi() {
  const current = getGridlySettingsPreferences();
  return normalizeGridlySettings({
    notifications: {
      routeAlerts: Boolean(els.settingsRouteAlertsToggle?.checked),
      railAlerts: Boolean(els.settingsRailAlertsToggle?.checked),
      hazardAlerts: Boolean(els.settingsHazardAlertsToggle?.checked),
      communityAlerts: Boolean(els.settingsCommunityAlertsToggle?.checked)
    },
    display: {
      mapStyle: els.settingsMapStyleSelect?.value || current.display.mapStyle,
      theme: els.settingsThemeSelect?.value || current.display.theme,
      textSize: els.settingsTextSizeSelect?.value || current.display.textSize
    },
    personalization: {
      preferredName: els.settingsPreferredNameInput?.value ?? current.personalization.preferredName
    },
    community: current.community
  });
}

function persistGridlySettingsFromUi(event) {
  try {
    const saved = saveGridlySettingsPreferences(collectGridlySettingsFromUi(), { applyDisplay: true, source: event?.target?.id || "settings_ui" });
    safeText("settingsSaveStatus", "Settings saved on this device.");
    return saved;
  } catch (error) {
    safeText("settingsSaveStatus", "Settings could not be saved on this device.");
    return collectGridlySettingsFromUi();
  }
}

function prepareGridlySettingsRouteSetupVisibility(source = "legacy_settings") {
  const portraitSheet = typeof document !== "undefined" ? document.getElementById("gridlyPortraitV2Sheet") : null;
  const portraitBackdrop = typeof document !== "undefined" ? document.getElementById("gridlyPortraitV2SheetBackdrop") : null;
  const portraitBody = typeof document !== "undefined" ? document.getElementById("gridlyPortraitV2SheetBody") : null;
  const portraitSettingsOpen = Boolean(portraitSheet && !portraitSheet.hidden && portraitSheet.dataset?.activeSheet === "settings");
  if (source === "portrait_v2_settings" || portraitSettingsOpen) {
    if (typeof window.closePortraitV2Sheet === "function") window.closePortraitV2Sheet();
    else {
      if (portraitSheet) {
        portraitSheet.hidden = true;
        portraitSheet.style.display = "none";
        portraitSheet.style.pointerEvents = "none";
        portraitSheet.setAttribute("aria-hidden", "true");
        portraitSheet.classList.remove("visible", "is-open", "active", "open");
      }
      if (portraitBody) portraitBody.hidden = true;
      if (portraitBackdrop) {
        portraitBackdrop.hidden = true;
        portraitBackdrop.style.display = "none";
        portraitBackdrop.style.pointerEvents = "none";
      }
    }
  }
  document.body?.classList?.remove?.("gridly-v2-surface-containment");
}

function openGridlySettingsSavedPlaceAction(action = "", type = "manage", source = "legacy_settings") {
  const normalizedType = type === "home" || type === "work" ? type : "manage";
  gridlyLastSettingsAction = action || (normalizedType === "home" ? "edit_home" : normalizedType === "work" ? "edit_work" : "manage_saved_places");
  const openHandler = () => {
    prepareGridlySettingsRouteSetupVisibility(source);
    if (normalizedType === "home" || normalizedType === "work") {
      if (typeof openRouteSetupModal === "function") openRouteSetupModal();
      if (typeof configureRouteSetupModal === "function") configureRouteSetupModal({ mode: "manage", prefillType: normalizedType });
      return;
    }
    if (typeof openRouteSetupModal === "function") openRouteSetupModal();
    if (typeof configureRouteSetupModal === "function") configureRouteSetupModal({ mode: "manage", prefillType: "custom" });
  };
  if (typeof openGridlySurface === "function") openGridlySurface("route", openHandler);
  else openHandler();
  return true;
}

function gridlyWelcomeOnboardingAudit() {
  const hasDocument = typeof document !== "undefined";
  const overlay = hasDocument ? document.getElementById("gridlyWelcomeOnboarding") : null;
  const currentStepNode = hasDocument ? document.querySelector("[data-gridly-welcome-step].is-active") : null;
  const stepNodes = hasDocument ? Array.from(document.querySelectorAll("[data-gridly-welcome-step]")) : [];
  const replaySetupFound = hasDocument ? Boolean(
    document.getElementById("settingsReplaySetupBtn") ||
    document.querySelector('[data-v2-action="settings-replay-setup"]')
  ) : false;
  const controlSelectors = [
    "#gridlyWelcomeBackBtn",
    "#gridlyWelcomeNextBtn",
    "#gridlyWelcomeSkipBtn",
    "#gridlyWelcomeFinishBtn"
  ];
  const controlsFound = hasDocument ? controlSelectors.every((selector) => Boolean(document.querySelector(selector))) : false;
  const rawSettings = gridlySafeLocalStorageGet(GRIDLY_SETTINGS_STORAGE_KEY);
  let preferredNamePersisted = false;
  try {
    const parsedSettings = rawSettings ? JSON.parse(rawSettings) : null;
    preferredNamePersisted = typeof parsedSettings?.personalization?.preferredName === "string";
  } catch (error) {
    preferredNamePersisted = false;
  }
  return {
    onboardingDomFound: Boolean(overlay),
    preferredNameInputFound: hasDocument ? Boolean(document.getElementById("gridlyWelcomePreferredNameInput")) : false,
    preferredNamePersisted,
    previewCardFound: hasDocument ? Boolean(document.getElementById("gridlyWelcomePreviewCard")) : false,
    themeControlsFound: hasDocument ? Boolean(document.getElementById("gridlyWelcomeThemeSelect")) : false,
    textSizeControlsFound: hasDocument ? Boolean(document.getElementById("gridlyWelcomeTextSizeSelect")) : false,
    personalizationStepFound: hasDocument ? Boolean(document.querySelector('[data-gridly-welcome-step="1"] #gridlyWelcomePreferredNameInput')) : false,
    homeTownSelectionFound: hasDocument ? document.querySelectorAll("[data-gridly-town]").length >= GRIDLY_HOME_TOWN_OPTIONS.length : false,
    welcomeSeen: gridlySafeLocalStorageGet(GRIDLY_WELCOME_SEEN_STORAGE_KEY) === "yes",
    currentStep: currentStepNode ? Number(currentStepNode.dataset.gridlyWelcomeStep) + 1 : gridlyWelcomeCurrentStep + 1,
    totalSteps: stepNodes.length || GRIDLY_WELCOME_TOTAL_STEPS,
    replaySetupFound,
    controlsFound,
    canOpen: typeof openGridlyWelcomeOnboarding === "function" && Boolean(overlay),
    canClose: typeof closeGridlyWelcomeOnboarding === "function" && Boolean(overlay),
    persistenceKey: GRIDLY_WELCOME_SEEN_STORAGE_KEY,
    protectedSystemsChanged: false
  };
}

if (typeof window !== "undefined") {
  window.gridlyWelcomeOnboardingAudit = gridlyWelcomeOnboardingAudit;
}


function gridlySettingsPanelAudit() {
  const hasDocument = typeof document !== "undefined";
  const settings = getGridlySettingsPreferences();
  const body = hasDocument ? document.body : null;
  const root = hasDocument ? document.documentElement : null;
  const legacyPanel = hasDocument ? document.getElementById("settingsModal") : null;
  const v2Panel = hasDocument ? document.querySelector("[data-gridly-settings-v2]") : null;
  const mapStyleSelect = hasDocument ? (document.getElementById("settingsMapStyleSelect") || document.querySelector('[data-v2-settings-field="display.mapStyle"]')) : null;
  const themeSelect = hasDocument ? (document.getElementById("settingsThemeSelect") || document.querySelector('[data-v2-settings-field="display.theme"]')) : null;
  const textSizeSelect = hasDocument ? (document.getElementById("settingsTextSizeSelect") || document.querySelector('[data-v2-settings-field="display.textSize"]')) : null;
  const preferredNameControl = hasDocument ? (document.getElementById("settingsPreferredNameInput") || document.querySelector('[data-v2-settings-field="personalization.preferredName"]')) : null;
  const notificationToggles = hasDocument ? Array.from(document.querySelectorAll('#settingsRouteAlertsToggle, #settingsRailAlertsToggle, #settingsHazardAlertsToggle, #settingsCommunityAlertsToggle, [data-v2-settings-field^="notifications."]')) : [];
  const rawSettings = gridlySafeLocalStorageGet(GRIDLY_SETTINGS_STORAGE_KEY);
  const appliedThemeClass = body ? ["gridly-theme-system", "gridly-theme-light", "gridly-theme-dark"].find((className) => body.classList.contains(className)) || "" : "";
  const appliedTextSizeClass = body ? ["gridly-text-standard", "gridly-text-large", "gridly-text-compact", "gridly-text-extra-large"].find((className) => body.classList.contains(className)) || "" : "";
  const visualIssuesDetected = [];
  if (hasDocument) {
    document.querySelectorAll(".settings-toggle-row").forEach((row, index) => {
      const input = row.querySelector('input[type="checkbox"]');
      const labelText = row.querySelector("span");
      if (!input) visualIssuesDetected.push(`notification_row_${index}_missing_checkbox`);
      if (!labelText || !String(labelText.textContent || "").trim()) visualIssuesDetected.push(`notification_row_${index}_missing_label`);
      if (input && input.getBoundingClientRect && row.getBoundingClientRect) {
        const inputRect = input.getBoundingClientRect();
        const rowRect = row.getBoundingClientRect();
        if (inputRect.width > 34 || inputRect.height > 34) visualIssuesDetected.push(`notification_row_${index}_oversized_checkbox`);
        if (rowRect.height > 72) visualIssuesDetected.push(`notification_row_${index}_oversized_row`);
      }
    });
  }
  const controlsFunctional = Boolean(
    mapStyleSelect &&
    themeSelect &&
    textSizeSelect &&
    preferredNameControl &&
    notificationToggles.length >= 4 &&
    rawSettings &&
    appliedThemeClass === `gridly-theme-${settings.display.theme}` &&
    appliedTextSizeClass === `gridly-text-${settings.display.textSize}`
  );
  return {
    settingsPanelFound: Boolean(legacyPanel || v2Panel),
    mapStyleSelectFound: Boolean(mapStyleSelect),
    themeSelectFound: Boolean(themeSelect),
    textSizeSelectFound: Boolean(textSizeSelect),
    preferredNameControlFound: Boolean(preferredNameControl),
    notificationTogglesFound: notificationToggles.length,
    currentSettings: settings,
    appliedThemeClass,
    appliedTextSizeClass,
    persistedSettingsFound: Boolean(rawSettings),
    visualIssuesDetected,
    controlsFunctional,
    appliedRootTheme: root?.dataset?.gridlyTheme || "",
    appliedRootTextSize: root?.dataset?.gridlyTextSize || ""
  };
}

if (typeof window !== "undefined") {
  window.gridlySettingsPanelAudit = gridlySettingsPanelAudit;
}

function bindGridlySettingsPreferences() {
  const controls = [
    els.settingsRouteAlertsToggle,
    els.settingsRailAlertsToggle,
    els.settingsHazardAlertsToggle,
    els.settingsCommunityAlertsToggle,
    els.settingsMapStyleSelect,
    els.settingsThemeSelect,
    els.settingsTextSizeSelect,
    els.settingsPreferredNameInput
  ].filter(Boolean);
  controls.forEach((control) => {
    if (control.dataset.gridlySettingsBound === "1") return;
    control.dataset.gridlySettingsBound = "1";
    control.addEventListener("change", persistGridlySettingsFromUi);
    if (control === els.settingsPreferredNameInput) control.addEventListener("input", persistGridlySettingsFromUi);
  });
  [[els.settingsEditHomeBtn, "home"], [els.settingsEditWorkBtn, "work"]].forEach(([button, type]) => {
    if (!button || button.dataset.gridlySettingsBound === "1") return;
    button.dataset.gridlySettingsBound = "1";
    button.addEventListener("click", () => {
      openGridlySettingsSavedPlaceAction(type === "home" ? "edit_home" : "edit_work", type, "legacy_settings");
    });
  });
  if (els.settingsManageSavedPlacesBtn && els.settingsManageSavedPlacesBtn.dataset.gridlySettingsBound !== "1") {
    els.settingsManageSavedPlacesBtn.dataset.gridlySettingsBound = "1";
    els.settingsManageSavedPlacesBtn.addEventListener("click", () => {
      openGridlySettingsSavedPlaceAction("manage_saved_places", "manage", "legacy_settings");
    });
  }
  if (els.settingsFeedbackBtn && els.settingsFeedbackBtn.dataset.gridlySettingsBound !== "1") {
    els.settingsFeedbackBtn.dataset.gridlySettingsBound = "1";
    els.settingsFeedbackBtn.addEventListener("click", () => {
      safeText("settingsFeedbackStatus", "Feedback placeholder acknowledged. No message was sent.");
    });
  }
}

function gridlySettingsCompleteness(settings = getGridlySettingsPreferences()) {
  const normalized = normalizeGridlySettings(settings);
  return {
    notificationsComplete: ["routeAlerts", "railAlerts", "hazardAlerts", "communityAlerts"].every((key) => typeof normalized.notifications[key] === "boolean"),
    displayComplete: Boolean(GRIDLY_SETTINGS_MAP_STYLE_LABELS[normalized.display.mapStyle] && GRIDLY_SETTINGS_VALID_THEMES.has(normalized.display.theme) && GRIDLY_SETTINGS_VALID_TEXT_SIZES.has(normalized.display.textSize)),
    routeWatchPlacesComplete: true,
    aboutComplete: true
  };
}

function buildGridlySettingsAudit(section = "all") {
  const storageAvailable = gridlyStorageAvailable();
  const settings = loadGridlySettingsPreferences({ render: false, applyDisplay: false });
  const rawSettings = gridlySafeLocalStorageGet(GRIDLY_SETTINGS_STORAGE_KEY);
  const places = gridlyGetSavedPlacesReadiness();
  const savedPlacesState = getSavedPlacesState();
  const homeDisplay = resolveGridlySettingsPlaceDisplay(savedPlacesState.home, "Home");
  const workDisplay = resolveGridlySettingsPlaceDisplay(savedPlacesState.work, "Work");
  const duplicateRouteWatchRowsFound = typeof document !== "undefined"
    ? Boolean(document.querySelector("#settingsSavedPlacesSection #settingsSavedPlacesList:not([hidden]) .settings-saved-place-row"))
    : false;
  const settingsEditHomeButton = typeof document !== "undefined" ? document.getElementById("settingsEditHomeBtn") : null;
  const settingsEditWorkButton = typeof document !== "undefined" ? document.getElementById("settingsEditWorkBtn") : null;
  const settingsManageSavedPlacesButton = typeof document !== "undefined" ? document.getElementById("settingsManageSavedPlacesBtn") : null;
  const portraitSettingsBody = typeof document !== "undefined" ? document.getElementById("gridlyPortraitV2SheetBody") : null;
  const portraitSettingsEditHomeButton = portraitSettingsBody?.querySelector?.('[data-v2-action="route-edit-home-open"]') || null;
  const portraitSettingsEditWorkButton = portraitSettingsBody?.querySelector?.('[data-v2-action="route-edit-work-open"]') || null;
  const portraitSettingsManageSavedPlacesButton = portraitSettingsBody?.querySelector?.('[data-v2-action="route-manage-places-open"]') || null;
  const portraitSettingsDelegatedBound = Boolean(portraitSettingsBody?.dataset?.v2DelegatedClickBound === "1");
  const completeness = gridlySettingsCompleteness(settings);
  return {
    loaded: true,
    storageAvailable,
    settingsDetected: Boolean(rawSettings) || Boolean(settings),
    diagnosticOnly: true,
    section,
    storageKeys: {
      settings: GRIDLY_SETTINGS_STORAGE_KEY,
      savedPlaces: SAVED_PLACES_STORAGE_KEY,
      mapStyle: MAP_STYLE_STORAGE_KEY
    },
    persistenceStatus: {
      settingsKeyPresent: Boolean(rawSettings),
      canPersistSettings: storageAvailable,
      mapStyleMirrorPresent: gridlySafeLocalStorageHas(MAP_STYLE_STORAGE_KEY)
    },
    settingsCompleteness: completeness,
    complete: Object.values(completeness).every(Boolean),
    routeWatchSettings: {
      homeVisible: Boolean(places.hasHome || typeof places.hasHome === "boolean"),
      workVisible: Boolean(places.hasWork || typeof places.hasWork === "boolean"),
      savedPlacesVisible: true,
      homeConfigured: Boolean(places.hasHome),
      workConfigured: Boolean(places.hasWork),
      savedPlaceCount: Number(places.savedPlaceCount || places.routablePlaceCount || 0),
      existingStorageReused: true,
      storageKey: SAVED_PLACES_STORAGE_KEY
    },
    homeDisplayValue: homeDisplay.value,
    workDisplayValue: workDisplay.value,
    homeDisplaySource: homeDisplay.source,
    workDisplaySource: workDisplay.source,
    zipUsedAsPrimary: Boolean(homeDisplay.zipUsedAsPrimary || workDisplay.zipUsedAsPrimary),
    duplicateRouteWatchRowsFound,
    settingsEditHomeButtonFound: Boolean(settingsEditHomeButton),
    settingsEditHomeButtonBound: Boolean(settingsEditHomeButton?.dataset?.gridlySettingsBound === "1"),
    settingsEditWorkButtonFound: Boolean(settingsEditWorkButton),
    settingsEditWorkButtonBound: Boolean(settingsEditWorkButton?.dataset?.gridlySettingsBound === "1"),
    settingsManageSavedPlacesButtonFound: Boolean(settingsManageSavedPlacesButton),
    settingsManageSavedPlacesButtonBound: Boolean(settingsManageSavedPlacesButton?.dataset?.gridlySettingsBound === "1"),
    portraitSettingsEditHomeButtonFound: Boolean(portraitSettingsEditHomeButton),
    portraitSettingsEditHomeButtonBound: Boolean(portraitSettingsEditHomeButton?.dataset?.gridlySettingsBound === "1" || (portraitSettingsEditHomeButton && portraitSettingsDelegatedBound)),
    portraitSettingsEditWorkButtonFound: Boolean(portraitSettingsEditWorkButton),
    portraitSettingsEditWorkButtonBound: Boolean(portraitSettingsEditWorkButton?.dataset?.gridlySettingsBound === "1" || (portraitSettingsEditWorkButton && portraitSettingsDelegatedBound)),
    portraitSettingsManageSavedPlacesButtonFound: Boolean(portraitSettingsManageSavedPlacesButton),
    portraitSettingsManageSavedPlacesButtonBound: Boolean(portraitSettingsManageSavedPlacesButton?.dataset?.gridlySettingsBound === "1" || (portraitSettingsManageSavedPlacesButton && portraitSettingsDelegatedBound)),
    lastSettingsAction: gridlyLastSettingsAction || null,
    textSizePreferenceAvailable: Boolean(GRIDLY_SETTINGS_VALID_TEXT_SIZES.has(settings.display.textSize)),
    textSizePreferencePersisted: rawSettings ? Boolean(GRIDLY_SETTINGS_VALID_TEXT_SIZES.has(settings.display.textSize)) : false,
    preferences: settings,
    notificationDeliveryEnabled: false,
    runtimeLoopsAdded: false,
    geolocationPromptRequested: false
  };
}

window.gridlySettingsAudit = function gridlySettingsAudit() {
  return buildGridlySettingsAudit("all");
};

window.gridlyNotificationPreferenceAudit = function gridlyNotificationPreferenceAudit() {
  return buildGridlySettingsAudit("notifications");
};

window.gridlyDisplayPreferenceAudit = function gridlyDisplayPreferenceAudit() {
  return buildGridlySettingsAudit("display");
};


const GRIDLY_NOTIFICATION_ARCHITECTURE_VERSION = "V199";
const GRIDLY_NOTIFICATION_FRESHNESS_WINDOWS_MINUTES = Object.freeze({
  route: 90,
  rail: 90,
  hazard: 180,
  community: 75,
  cleared: RECENTLY_CLEARED_WINDOW_MINUTES
});
const GRIDLY_NOTIFICATION_ROUTE_DISTANCE_MILES = 0.8;
const GRIDLY_NOTIFICATION_COMMUNITY_DISTANCE_MILES = 1.25;

function gridlyNotificationStableIssueKey(type = "unknown", issue = {}) {
  const explicitId = issue?.id || issue?.reportId || issue?.report_id || issue?.crossingId || issue?.crossing_id || "";
  if (String(explicitId || "").trim()) return `${type}:${String(explicitId).trim()}`;
  const lat = Number(issue?.lat ?? issue?.latitude ?? issue?.rawLat);
  const lng = Number(issue?.lng ?? issue?.lon ?? issue?.longitude ?? issue?.rawLng);
  const category = getHazardCategory(issue?.report_type || issue?.type || issue?.category || type);
  if (Number.isFinite(lat) && Number.isFinite(lng)) return `${type}:${category}:${lat.toFixed(3)}:${lng.toFixed(3)}`;
  return `${type}:${category}:${String(issue?.title || issue?.description || "unknown").slice(0, 60).toLowerCase()}`;
}

function gridlyNotificationIssueAgeMinutes(issue = {}, nowMs = Date.now()) {
  const direct = Number(issue?.minutesAgo ?? issue?.age_minutes ?? issue?.ageMinutes);
  if (Number.isFinite(direct) && direct >= 0) return direct;
  const timestamp = issue?.submittedAt || issue?.created_at || issue?.updated_at || issue?.timestamp || issue?.reportedAt;
  const parsed = timestamp ? Date.parse(timestamp) : NaN;
  if (!Number.isFinite(parsed) || parsed <= 0) return null;
  return Math.max(0, Math.round((nowMs - parsed) / 60000));
}

function gridlyNotificationCoordinates(issue = {}) {
  if (typeof getGridlyIncidentCoordinate === "function") {
    const resolved = getGridlyIncidentCoordinate(issue);
    if (resolved && Number.isFinite(Number(resolved.lat)) && Number.isFinite(Number(resolved.lng))) {
      return { lat: Number(resolved.lat), lng: Number(resolved.lng) };
    }
  }
  const lat = Number(issue?.lat ?? issue?.latitude ?? issue?.rawLat);
  const lng = Number(issue?.lng ?? issue?.lon ?? issue?.longitude ?? issue?.rawLng);
  return Number.isFinite(lat) && Number.isFinite(lng) ? { lat, lng } : null;
}

function gridlyNotificationDistanceToRoute(issue = {}, routeLatLngs = []) {
  const coords = gridlyNotificationCoordinates(issue);
  if (!coords || !Array.isArray(routeLatLngs) || routeLatLngs.length < 2) return null;
  const minDistance = routeLatLngs.reduce((min, pt) => {
    const lat = Number(pt?.lat);
    const lng = Number(pt?.lng);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) return min;
    return Math.min(min, getDistanceMiles(coords.lat, coords.lng, lat, lng));
  }, Number.POSITIVE_INFINITY);
  return Number.isFinite(minDistance) ? Number(minDistance.toFixed(2)) : null;
}

function gridlyNotificationIsNearRoute(issue = {}, routeLatLngs = [], maxMiles = GRIDLY_NOTIFICATION_ROUTE_DISTANCE_MILES) {
  const distanceMiles = gridlyNotificationDistanceToRoute(issue, routeLatLngs);
  return distanceMiles !== null && distanceMiles <= maxMiles;
}

function gridlyNotificationAddCandidate(collection, type, subtype, issue = {}, reasons = [], context = {}) {
  const key = gridlyNotificationStableIssueKey(type, issue);
  if (collection.seenKeys.has(key)) {
    collection.suppressedReasons.push(`${type}:${subtype}:duplicate_issue_suppressed`);
    return false;
  }
  collection.seenKeys.add(key);
  collection.candidates.push({
    type,
    subtype,
    key,
    eligible: true,
    reasons,
    issueSummary: {
      id: issue?.id || issue?.reportId || issue?.report_id || issue?.crossingId || issue?.crossing_id || null,
      title: safeDisplayText(issue?.title || issue?.crossingName || issue?.area || issue?.description || subtype, subtype),
      category: getHazardCategory(issue?.report_type || issue?.type || issue?.category || subtype),
      status: issue?.status || issue?.lifecycleState || null,
      ageMinutes: gridlyNotificationIssueAgeMinutes(issue, context.nowMs),
      distanceMiles: context.distanceMiles ?? null
    }
  });
  return true;
}

function gridlyNotificationBuildCollection() {
  return { candidates: [], suppressedReasons: [], seenKeys: new Set() };
}

function gridlyNotificationFinalizeType(collection, enabled, readinessReasons = []) {
  const typeSuppressed = [...collection.suppressedReasons, ...readinessReasons];
  return {
    preferenceEnabled: Boolean(enabled),
    eligible: Boolean(enabled && collection.candidates.length > 0 && readinessReasons.length === 0),
    candidateCount: collection.candidates.length,
    candidates: collection.candidates,
    suppressedReasons: typeSuppressed
  };
}

function buildGridlyNotificationArchitectureAudit() {
  const nowMs = Date.now();
  const settings = typeof getGridlySettingsPreferences === "function" ? getGridlySettingsPreferences() : normalizeGridlySettings();
  const preferencesLoaded = Boolean(settings?.notifications && ["routeAlerts", "railAlerts", "hazardAlerts", "communityAlerts"].every((key) => typeof settings.notifications[key] === "boolean"));
  const places = typeof gridlyGetSavedPlacesReadiness === "function" ? gridlyGetSavedPlacesReadiness() : { hasHome: false, hasWork: false, routablePlaceCount: 0, state: {} };
  const routeGeometry = typeof gridlyGetRouteGeometryDiagnostics === "function" ? gridlyGetRouteGeometryDiagnostics() : { currentRouteAvailable: false, routeGeometryAvailable: false, routePointCount: 0 };
  const routeLatLngs = typeof getRoutePolylineLatLngs === "function" ? getRoutePolylineLatLngs() : [];
  const savedRouteContextAvailable = Boolean(places.hasHome && places.hasWork);
  const routeContextAvailable = Boolean(routeGeometry.currentRouteAvailable || savedRouteContextAvailable);
  const routeHazard = typeof getRouteHazardAssessment === "function" ? getRouteHazardAssessment() : { level: "clear", score: 0, nearbyReports: [] };
  const commuteDelta = typeof window.gridlyCommuteDeltaSnapshot === "function" ? window.gridlyCommuteDeltaSnapshot() : { deltaAvailable: false };
  const unifiedIncidents = Array.isArray(getUnifiedIncidents?.()) ? getUnifiedIncidents() : [];
  const railReports = Array.isArray(activeReports) ? activeReports : [];
  const roadHazards = Array.isArray(activeHazards) ? activeHazards : [];
  const routeCollection = gridlyNotificationBuildCollection();
  const railCollection = gridlyNotificationBuildCollection();
  const hazardCollection = gridlyNotificationBuildCollection();
  const communityCollection = gridlyNotificationBuildCollection();

  const routeReadinessReasons = [];
  if (!settings.notifications.routeAlerts) routeReadinessReasons.push("preference_disabled:notifications.routeAlerts");
  if (!routeContextAvailable) routeReadinessReasons.push("route_context_unavailable");
  if (routeContextAvailable) {
    if (commuteDelta?.deltaAvailable && commuteDelta.deltaDirection === "slower" && Number(commuteDelta.deltaMinutes) >= 5) {
      gridlyNotificationAddCandidate(routeCollection, "route", "route_delay_increased", { id: commuteDelta.routeKey || "route-delay", type: "delay", title: "Route delay increased", status: commuteDelta.deltaStatus, age_minutes: 0 }, ["current commute is at least 5 minutes slower than normal"], { nowMs });
    }
    if (routeHazard?.level === "blocked" || (Array.isArray(routeHazard?.nearbyReports) && routeHazard.nearbyReports.some((report) => report.reportType === "blocked" && report.lifecycleState === "active"))) {
      gridlyNotificationAddCandidate(routeCollection, "route", "route_blocked", routeHazard.nearestIssue || { id: "route-blocked", type: "blocked", title: "Route blocked" }, ["active blocking issue intersects saved route"], { nowMs, distanceMiles: routeHazard.nearestIssue?.distanceMiles });
    }
    if (routeComparisonStatus === "alternate_safer" && alternateRouteAvailable && Number(primaryRouteScore) > Number(alternateRouteScore)) {
      gridlyNotificationAddCandidate(routeCollection, "route", "better_alternate_route_found", { id: "alternate-route", type: "alternate", title: "Better alternate route found", status: routeComparisonStatus, age_minutes: 0 }, ["alternate route has lower route pressure than primary route"], { nowMs });
    }
    if (["slower_than_normal", "normal"].includes(String(commuteDelta?.deltaStatus || "")) || ["blocked", "heavy", "caution", "clear"].includes(String(routeHazard?.level || ""))) {
      const changed = Boolean(commuteDelta?.deltaAvailable && Math.abs(Number(commuteDelta.deltaMinutes || 0)) >= 3) || ["blocked", "heavy", "caution"].includes(String(routeHazard?.level || ""));
      if (changed) gridlyNotificationAddCandidate(routeCollection, "route", "commute_condition_changed", { id: `commute-${commuteDelta.routeKey || routeHazard?.level || "route"}`, type: routeHazard?.level || "commute", title: "Commute condition changed", status: commuteDelta?.deltaStatus || routeHazard?.level, age_minutes: 0 }, ["route status changed enough to explain to the user"], { nowMs });
    }
  }

  const railReadinessReasons = [];
  if (!settings.notifications.railAlerts) railReadinessReasons.push("preference_disabled:notifications.railAlerts");
  if (!routeContextAvailable) railReadinessReasons.push("route_context_unavailable");
  railReports.forEach((report) => {
    const age = gridlyNotificationIssueAgeMinutes(report, nowMs);
    const crossing = (Array.isArray(crossings) ? crossings : []).find((item) => String(item?.id) === String(report?.crossingId));
    const issue = { ...crossing, ...report, id: report?.id || report?.crossingId, lat: report?.lat ?? crossing?.lat, lng: report?.lng ?? crossing?.lng };
    const nearRoute = routeGeometry.routeGeometryAvailable ? gridlyNotificationIsNearRoute(issue, routeLatLngs) : savedRouteContextAvailable;
    if (!nearRoute) return;
    if (age !== null && age > GRIDLY_NOTIFICATION_FRESHNESS_WINDOWS_MINUTES.rail && !isClearedReportType(report?.type)) {
      railCollection.suppressedReasons.push("rail:stale_report_suppressed");
      return;
    }
    const distanceMiles = routeGeometry.routeGeometryAvailable ? gridlyNotificationDistanceToRoute(issue, routeLatLngs) : null;
    if (isActiveReportType(report?.type) && /blocked|delay|delayed|heavy/.test(String(report?.type || ""))) {
      gridlyNotificationAddCandidate(railCollection, "rail", "crossing_blocked_near_saved_route", issue, ["rail crossing blockage is near saved route"], { nowMs, distanceMiles });
    }
    if (isClearedReportType(report?.type) && (age === null || age <= GRIDLY_NOTIFICATION_FRESHNESS_WINDOWS_MINUTES.cleared)) {
      gridlyNotificationAddCandidate(railCollection, "rail", "crossing_cleared_near_saved_route", issue, ["recent clearance is near saved route"], { nowMs, distanceMiles });
    }
    if (Number(report?.reports_count || report?.count || 0) >= 2 || Number(report?.confirmations || 0) >= 2) {
      gridlyNotificationAddCandidate(railCollection, "rail", "repeated_blockage_pattern", issue, ["multiple rail reports indicate a repeated pattern"], { nowMs, distanceMiles });
    }
  });

  const hazardReadinessReasons = [];
  if (!settings.notifications.hazardAlerts) hazardReadinessReasons.push("preference_disabled:notifications.hazardAlerts");
  if (!routeContextAvailable) hazardReadinessReasons.push("route_context_unavailable");
  roadHazards.forEach((hazard) => {
    const lifecycle = typeof gridlyClassifyHazardLifecycle === "function" ? gridlyClassifyHazardLifecycle(hazard, { nowMs }) : { lifecycleStage: "active", lifecycleRecommendedAction: "keep_active" };
    const age = gridlyNotificationIssueAgeMinutes(hazard, nowMs);
    const nearRoute = routeGeometry.routeGeometryAvailable ? gridlyNotificationIsNearRoute(hazard, routeLatLngs) : savedRouteContextAvailable;
    if (!nearRoute) return;
    if (lifecycle.lifecycleStage === "expired_candidate") {
      hazardCollection.suppressedReasons.push("hazard:expired_candidate_suppressed");
      return;
    }
    if (age !== null && age > GRIDLY_NOTIFICATION_FRESHNESS_WINDOWS_MINUTES.hazard && lifecycle.lifecycleStage !== "aging") {
      hazardCollection.suppressedReasons.push("hazard:stale_hazard_suppressed");
      return;
    }
    const distanceMiles = routeGeometry.routeGeometryAvailable ? gridlyNotificationDistanceToRoute(hazard, routeLatLngs) : null;
    const category = getHazardCategory(hazard?.type || hazard?.report_type || hazard?.category);
    const highImpact = ["road_closed", "flooding", "crash", "rail_blockage_delay"].includes(category) || ["high", "critical"].includes(String(hazard?.severity || "").toLowerCase());
    if (highImpact && gridlyIsActiveHazardRecord(hazard)) {
      gridlyNotificationAddCandidate(hazardCollection, "hazard", "new_high_impact_hazard_near_user_route", hazard, ["high-impact active hazard is near user route"], { nowMs, distanceMiles });
    }
    if (isClearedReportType(hazard?.type || hazard?.report_type) || String(hazard?.status || "").toLowerCase() === "cleared") {
      gridlyNotificationAddCandidate(hazardCollection, "hazard", "hazard_cleared", hazard, ["hazard lifecycle indicates cleared"], { nowMs, distanceMiles });
    }
    if (["aging", "verified"].includes(lifecycle.lifecycleStage) || ["request_confirmation", "reduce_confidence"].includes(lifecycle.lifecycleRecommendedAction)) {
      gridlyNotificationAddCandidate(hazardCollection, "hazard", "hazard_aging_confirmation_changed", hazard, [lifecycle.lifecycleReason || "hazard lifecycle changed"], { nowMs, distanceMiles });
    }
  });

  const communityReadinessReasons = [];
  if (!settings.notifications.communityAlerts) communityReadinessReasons.push("preference_disabled:notifications.communityAlerts");
  if (!routeContextAvailable) communityReadinessReasons.push("route_context_unavailable");
  const communityNearRoute = unifiedIncidents.filter((incident) => {
    const age = gridlyNotificationIssueAgeMinutes(incident, nowMs);
    if (age !== null && age > GRIDLY_NOTIFICATION_FRESHNESS_WINDOWS_MINUTES.community) return false;
    return routeGeometry.routeGeometryAvailable ? gridlyNotificationIsNearRoute(incident, routeLatLngs, GRIDLY_NOTIFICATION_COMMUNITY_DISTANCE_MILES) : savedRouteContextAvailable;
  });
  if (communityNearRoute.length >= 2) {
    gridlyNotificationAddCandidate(communityCollection, "community", "multiple_nearby_reports", { id: "community-multiple-near-route", type: "community_activity", title: `${communityNearRoute.length} nearby reports`, reports_count: communityNearRoute.length, age_minutes: 0 }, ["multiple fresh reports near saved route"], { nowMs });
  }
  const buildingActivity = communityNearRoute.find((incident) => Number(incident?.reports_count || incident?.count || 0) >= 2);
  if (buildingActivity) {
    gridlyNotificationAddCandidate(communityCollection, "community", "activity_building", buildingActivity, ["report count is increasing around a local issue"], { nowMs, distanceMiles: routeGeometry.routeGeometryAvailable ? gridlyNotificationDistanceToRoute(buildingActivity, routeLatLngs) : null });
  }
  const highConfidence = communityNearRoute.find((incident) => ["high", "confirmed", "verified"].includes(String(incident?.confidence || incident?.confidenceLevel || "").toLowerCase()) || Number(incident?.reports_count || 0) >= 3);
  if (highConfidence) {
    gridlyNotificationAddCandidate(communityCollection, "community", "high_confidence_local_issue", highConfidence, ["high-confidence local issue is near saved route"], { nowMs, distanceMiles: routeGeometry.routeGeometryAvailable ? gridlyNotificationDistanceToRoute(highConfidence, routeLatLngs) : null });
  }

  const routeType = gridlyNotificationFinalizeType(routeCollection, settings.notifications.routeAlerts, routeReadinessReasons);
  const railType = gridlyNotificationFinalizeType(railCollection, settings.notifications.railAlerts, railReadinessReasons);
  const hazardType = gridlyNotificationFinalizeType(hazardCollection, settings.notifications.hazardAlerts, hazardReadinessReasons);
  const communityType = gridlyNotificationFinalizeType(communityCollection, settings.notifications.communityAlerts, communityReadinessReasons);
  const notificationTypes = { route: routeType, rail: railType, hazard: hazardType, community: communityType };
  const nextEligible = ["route", "rail", "hazard", "community"].find((type) => notificationTypes[type].eligible) || null;
  const suppressedReasons = [...new Set(Object.values(notificationTypes).flatMap((type) => type.suppressedReasons))];

  return {
    loaded: true,
    version: GRIDLY_NOTIFICATION_ARCHITECTURE_VERSION,
    diagnosticOnly: true,
    deliveryEnabled: false,
    runtimeLoopsAdded: false,
    schedulerAdded: false,
    preferencesLoaded,
    notificationTypes,
    routeAlertEligible: routeType.eligible,
    railAlertEligible: railType.eligible,
    hazardAlertEligible: hazardType.eligible,
    communityAlertEligible: communityType.eligible,
    suppressedReasons,
    nextEligibleNotificationType: nextEligible,
    routeContext: {
      currentRouteAvailable: Boolean(routeGeometry.currentRouteAvailable),
      routeGeometryAvailable: Boolean(routeGeometry.routeGeometryAvailable),
      routePointCount: Number(routeGeometry.routePointCount || 0),
      savedHomeAvailable: Boolean(places.hasHome),
      savedWorkAvailable: Boolean(places.hasWork),
      routeContextAvailable
    },
    betaSafe: true
  };
}

window.gridlyNotificationArchitectureAudit = function gridlyNotificationArchitectureAudit() {
  return buildGridlyNotificationArchitectureAudit();
};

function getDefaultSmartAlertsPreferences() {
  return { enabled: false, nearbyBlocked: false, routeDelay: false, us90Clear: false, needsConfirm: false };
}

function getSmartAlertsPreferences() {
  try {
    return { ...getDefaultSmartAlertsPreferences(), ...JSON.parse(localStorage.getItem(SMART_ALERTS_STORAGE_KEY) || "{}") };
  } catch (error) {
    return getDefaultSmartAlertsPreferences();
  }
}

function loadSmartAlertsPreferences() {
  const prefs = getSmartAlertsPreferences();
  if (els.smartAlertNearbyBlocked) els.smartAlertNearbyBlocked.checked = Boolean(prefs.nearbyBlocked);
  if (els.smartAlertRouteDelay) els.smartAlertRouteDelay.checked = Boolean(prefs.routeDelay);
  if (els.smartAlertUs90Clear) els.smartAlertUs90Clear.checked = Boolean(prefs.us90Clear);
  if (els.smartAlertNeedsConfirm) els.smartAlertNeedsConfirm.checked = Boolean(prefs.needsConfirm);
  markSmartAlertsSeenOnFirstVisit();
  updateSmartAlertsStatus(prefs);
}

function markSmartAlertsSeenOnFirstVisit() {
  const hasSeen = localStorage.getItem(SMART_ALERTS_DRAWER_SEEN_KEY) === "1";
  if (!hasSeen) localStorage.setItem(SMART_ALERTS_DRAWER_SEEN_KEY, "1");
}

function saveSmartAlertsPreferences() {
  const prefs = {
    nearbyBlocked: Boolean(els.smartAlertNearbyBlocked?.checked),
    routeDelay: Boolean(els.smartAlertRouteDelay?.checked),
    us90Clear: Boolean(els.smartAlertUs90Clear?.checked),
    needsConfirm: Boolean(els.smartAlertNeedsConfirm?.checked)
  };
  prefs.enabled = prefs.nearbyBlocked || prefs.routeDelay || prefs.us90Clear || prefs.needsConfirm;

  try {
    localStorage.setItem(SMART_ALERTS_STORAGE_KEY, JSON.stringify(prefs));
  } catch (error) {
    updateSmartAlertsStatus(prefs);
    evaluateSmartAlertsBanner(prefs);
    safeText("smartAlertsConfirmation", "⚠️ Could not save alert preferences on this device.");
    return;
  }

  updateSmartAlertsStatus(prefs);
  evaluateSmartAlertsBanner(prefs);
  const savedAt = new Date().toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
  safeText("smartAlertsConfirmation", `✅ Alert preferences are saved on this device at ${savedAt}.`);
}

function updateSmartAlertsStatus(prefs = getSmartAlertsPreferences()) {
  safeText("smartAlertsStatus", prefs.enabled ? "Premium Smart Alerts: On" : "Premium Smart Alerts: Off");
}

function evaluateSmartAlertsBanner(prefs = getSmartAlertsPreferences()) {
  if (!els.smartAlertsBanner) return;
  if (!prefs.enabled) {
    els.smartAlertsBanner.hidden = true;
    els.smartAlertsBanner.textContent = "";
    return;
  }

  const latestByCrossing = getLatestReportsByCrossing().filter((report) => !report.expired);
  const nearest = userLocation ? findNearestCrossings(userLocation.lat, userLocation.lng, 10) : [];
  const nearbyCrossingIds = new Set(nearest.map((crossing) => String(crossing.id)));
  const hasNearbyBlocked = latestByCrossing.some(
    (report) => nearbyCrossingIds.has(String(report.crossingId)) && report.type === "blocked"
  );
  const hasRouteDelay =
    Boolean(localStorage.getItem("gridlyHome") && localStorage.getItem("gridlyWork")) &&
    latestByCrossing.some((report) => getIncidentLifecycleState(report) === "active");
  const hasUs90Cleared = activeReports.some(
    (report) =>
      (getIncidentLifecycleState(report) === "recently_cleared" || getIncidentLifecycleState(report) === "cleared") &&
      String(report.crossingName || "").toLowerCase().includes("us 90")
  );
  const needsConfirmation = activeReports.some((report) => report.minutesAgo >= 75);

  const matches = [];
  if (prefs.nearbyBlocked && hasNearbyBlocked) matches.push("Nearby blocked crossing reported.");
  if (prefs.routeDelay && hasRouteDelay) matches.push("Saved-route delay is active.");
  if (prefs.us90Clear && hasUs90Cleared) matches.push("US 90 has a recent cleared report.");
  if (prefs.needsConfirm && needsConfirmation) matches.push("Reports need confirmation or are near expiry.");

  if (!matches.length) {
    els.smartAlertsBanner.hidden = true;
    els.smartAlertsBanner.textContent = "";
    return;
  }

  els.smartAlertsBanner.hidden = false;
  els.smartAlertsBanner.textContent = matches.slice(0, 3).join(" ");
}


function getUrgentBlockedCount(activeIssues = []) {
  return activeIssues.filter((issue) => String(issue.type || "") === "rail_blocked" && Number(issue.age_minutes ?? issue.minutesAgo ?? 999) <= 10).length;
}

function getFreshnessTier(minutesAgo) {
  if (typeof minutesAgo !== "number" || Number.isNaN(minutesAgo)) return "Unknown";
  if (minutesAgo <= 15) return "Fresh";
  if (minutesAgo <= 45) return "Aging";
  return "Stale";
}

function getRouteWatchIntelligence(activeIssues = []) {
  const blocked = activeIssues.filter((issue) => String(issue.type || "").includes("blocked"));
  const delayed = activeIssues.filter((issue) => String(issue.type || "").includes("delay"));
  const blockedCount = blocked.length;
  const estimatedDelayMinutes = Math.max(0, blockedCount * 7 + delayed.length * 4);
  const confidence = blockedCount >= 2 ? "High" : blockedCount === 1 || delayed.length >= 2 ? "Medium" : "Low";
  const urgentBlockedCount = getUrgentBlockedCount(activeIssues);
  const reroute = urgentBlockedCount > 0
    ? "Immediate reroute recommended: blocked report is within 10 minutes."
    : blockedCount > 0
      ? "Use your backup route and avoid the blocked crossings."
      : delayed.length > 0
        ? "Keep your route, but leave a few minutes early."
        : "Stay on your normal route.";
  const advice = urgentBlockedCount > 0
    ? "Avoid the crossing nearest your Home→Work midpoint and reroute now."
    : blockedCount > 0
      ? "Take your backup route and confirm crossings before departure."
      : delayed.length > 0
        ? "Leave 5–8 minutes early and monitor Route Watch."
        : "Stay on your normal route and check again before leaving.";
  return { blockedCount, urgentBlockedCount, estimatedDelayMinutes, confidence, reroute, advice };
}

function getCorridorHealthFromScore(score = 0) {
  const normalized = Math.max(0, Number(score) || 0);
  if (normalized <= 10) return "Clear";
  if (normalized <= 30) return "Moderate";
  if (normalized <= 60) return "Heavy";
  return "Severe";
}

function getEstimatedDelayImpact(corridorHealth = "Clear", routeStatus = "") {
  const normalizedHealth = String(corridorHealth || "").toLowerCase();
  const normalizedStatus = String(routeStatus || "").toLowerCase();
  if (normalizedStatus === "blocked" || normalizedHealth === "severe") return "High delay risk.";
  if (normalizedHealth === "heavy") return "Likely meaningful delay.";
  if (normalizedHealth === "moderate") return "Possible short delay.";
  return "No meaningful delay expected.";
}

function getSystemConfidence(routeIsMonitoring = false) {
  const checks = [
    Boolean(map),
    Boolean(routePreviewRendered),
    Number(routePreviewPolylinePointCount) >= 2,
    Boolean(map && savedRouteLayer && typeof map.hasLayer === "function" && map.hasLayer(savedRouteLayer)),
    !routeIsMonitoring || Boolean(osrmRouteSuccess)
  ];
  const score = checks.filter(Boolean).length;
  if (score >= 5) return "High";
  if (score >= 3) return "Medium";
  return "Low";
}

function getRecommendationConfidence({ alternateAvailable = false, hazardsAvoided = 0, primaryScore = 0, alternateScore = 0, routeIsMonitoring = false } = {}) {
  if (!routeIsMonitoring || !alternateAvailable) return "Low";
  const delta = Math.max(0, Number(primaryScore) - Number(alternateScore));
  if (hazardsAvoided > 0 && delta >= 10) return "High";
  if (delta <= 4) return "Medium";
  return "Medium";
}

