  const counts = {};
  const buildAuditExclusionDetails = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditInputSource = "getUnifiedIncidents()->getActiveUnifiedIncidents(status=active)";
  gridlyCommuteIntelligenceAuditState.commuteAuditUnifiedIncidentCountBeforeBuild = unifiedIncidentsBeforeBuildCount;
  gridlyCommuteIntelligenceAuditState.commuteAuditUnifiedIncidentCountAfterBuild = unifiedIncidentsBeforeBuildCount;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawUnifiedIncidentCount = unifiedIncidentsBeforeBuildCount;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawUnifiedIncidentIds = (unifiedIncidentsForAudit || []).map((incident) => String(incident?.id || ""));
  gridlyCommuteIntelligenceAuditState.commuteAuditRawCountSource = Array.isArray(unifiedIncidentsForAudit)
    ? "getUnifiedIncidents_array_length"
    : "getUnifiedIncidents_non_array_fallback_zero";
  gridlyCommuteIntelligenceAuditState.commuteAuditRawIdsSource = Array.isArray(unifiedIncidentsForAudit)
    ? "getUnifiedIncidents_array_map_id"
    : "getUnifiedIncidents_non_array_fallback_empty";
  gridlyCommuteIntelligenceAuditState.commuteAuditRawObjectSource = "bootstrap_pending_raw_array_evaluation";
  gridlyCommuteIntelligenceAuditState.commuteAuditRawObjectUnavailableReason = "bootstrap_pending_raw_array_evaluation";
  gridlyCommuteIntelligenceAuditState.commuteAuditUnifiedSnapshotShape = Array.isArray(unifiedIncidentsForAudit)
    ? "array"
    : (unifiedIncidentsForAudit === null ? "null" : typeof unifiedIncidentsForAudit);
  gridlyCommuteIntelligenceAuditState.commuteAuditUnifiedSnapshotIsArray = Array.isArray(unifiedIncidentsForAudit);
  gridlyCommuteIntelligenceAuditState.commuteAuditUnifiedSnapshotKeys = !Array.isArray(unifiedIncidentsForAudit) && unifiedIncidentsForAudit && typeof unifiedIncidentsForAudit === "object"
    ? Object.keys(unifiedIncidentsForAudit).slice(0, 12)
    : [];
  gridlyCommuteIntelligenceAuditState.commuteAuditRawArrayPublicationStage = "bootstrap_defaults_before_raw_publication";
  gridlyCommuteIntelligenceAuditState.commuteAuditRawUnifiedIncidentObjectAvailable = false;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawUnifiedIncidentObjectSample = null;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveCandidateCount = 0;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveCandidateIds = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveBuildAttempted = false;
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveBuildReason = "not_evaluated";
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveDiffRawIds = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveDiffActiveIds = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveDiffMissingIds = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditRawMinusActiveDiffMethod = "not_evaluated";
  gridlyCommuteIntelligenceAuditState.commuteAuditActiveFilterExclusionBuildCount = 0;
  gridlyCommuteIntelligenceAuditState.commuteAuditActiveIncidentCount = 0;
  gridlyCommuteIntelligenceAuditState.commuteAuditActiveIncidentIds = [];
  gridlyCommuteIntelligenceAuditState.commuteAuditModelInputCount = 0;
